const TAB_TARGETS = [
  "market",
  "overview",
  "screener",
  "report",
  "revenue",
  "technical",
  "discovery",
  "disposition",
  "ex-dividend",
  "active-etf",
  "catalyst",
  "macro",
  "risk",
  "podcast",
  "help"
];

function normalizeTabTarget(target) {
  const requested = target === "risk" ? "macro" : String(target || "");
  if (requested === "comparison") return "discovery";
  if (["valuation", "snapshots"].includes(requested)) return "overview";
  return TAB_TARGETS.includes(requested) ? requested : "market";
}

