// 所有 ETF 代碼集合（用於 isEtfCode 判斷與 NAV 查詢）
const ALL_ETF_CODES = new Set([
  ...TW_ACTIVE_ETF_CODES,
  ...TW_PASSIVE_ETF_CODES,
  ...US_TREASURY_ETF_CODES,
  ...US_STOCK_ETF_CODES,
  ...JAPAN_ETF_CODES,
  ...OVERSEAS_ACTIVE_ETF_CODES,
]);

function isEtfCode(code) {
  if (ALL_ETF_CODES.has(code)) return true;
  const sector = (STOCK_UNIVERSE[code] || {}).sector || "";
  return sector.startsWith("ETF") || sector.startsWith("主動式 ETF");
}

function isFinancialStock(stockOrCode) {
  const code = typeof stockOrCode === "string" ? stockOrCode : stockOrCode?.code;
  const stock = typeof stockOrCode === "object" ? stockOrCode : STOCK_MAP.get(code) || STOCK_UNIVERSE[code] || null;
  const sector = String(stock?.sector || "");
  return FINANCIAL_STOCK_CODES.includes(code)
    || (stock?.themes || []).includes("financials")
    || /金融|金控|銀行|保險|壽險|產險|證券/.test(sector)
    || String(stock?.officialIndustry || "") === "17";
}

function isTripleMarginEligibleStock(stockOrCode) {
  const code = typeof stockOrCode === "string" ? stockOrCode : stockOrCode?.code;
  return Boolean(code) && !isEtfCode(code) && !isFinancialStock(stockOrCode);
}

