function uniqueList(values) {
  return [...new Set(values.filter(Boolean))];
}

function isEtfTrackingThemeFilter(filterKey) {
  return filterKey === "activeetf" || filterKey === "usetf";
}

function ensureEtfTrackingFilterForTab() {
  if (state.activeTab === "active-etf" && !isEtfTrackingThemeFilter(state.filter)) {
    state.filter = "activeetf";
  }
}

