function applyPassiveComponentExpansion() {
  for (const [code, meta] of Object.entries(PASSIVE_COMPONENT_STOCKS)) {
    const existing = STOCK_UNIVERSE[code] || {};
    STOCK_UNIVERSE[code] = {
      ...meta,
      ...existing,
      sector: existing.sector || meta.sector,
      suffix: existing.suffix || meta.suffix,
      name: existing.name || meta.name
    };
  }
}

function applyAiSupplyChainExpansion() {
  for (const [code, meta] of Object.entries(AI_SUPPLY_CHAIN_STOCKS)) {
    const existing = STOCK_UNIVERSE[code] || {};
    STOCK_UNIVERSE[code] = {
      ...meta,
      ...existing,
      sector: existing.sector || meta.sector,
      suffix: existing.suffix || meta.suffix,
      name: existing.name || meta.name
    };
  }
  for (const [themeKey, codes] of Object.entries(AI_SUPPLY_CHAIN_THEME_CODES)) {
    const theme = THEME_MEMBERS.find((item) => item.key === themeKey);
    if (theme) theme.codes = uniqueList([...(theme.codes || []), ...codes]);
  }
}

