function ensureStockUniverse() {
  const existing = new Map(WATCHLIST.map((stock) => [stock.code, stock]));
  for (const [code, meta] of Object.entries(STOCK_UNIVERSE)) {
    const current = existing.get(code);
    if (current) {
      Object.assign(current, {
        name: meta.name || current.name,
        suffix: meta.suffix || current.suffix,
        officialIndustry: meta.officialIndustry || current.officialIndustry,
        market: meta.market || current.market || (meta.suffix === "TWO" ? "上櫃" : "上市"),
        sector: current.sector || meta.sector,
        themes: current.themes || [],
        themeSectors: current.themeSectors || {},
        labels: current.labels || [],
        searchAliases: current.searchAliases || []
      });
      continue;
    }
    WATCHLIST.push({
      code,
      suffix: meta.suffix,
      name: meta.name,
      group: "expand",
      sector: meta.sector,
      ref: null,
      pe: null,
      eps25: null,
      eps26e: null,
      target: null,
      order: "待追蹤",
      overlap: null,
      theme: null,
      stop: null,
      buy: "",
      catalyst: meta.sector,
      risk: "待建立研究假設",
      officialIndustry: meta.officialIndustry,
      market: meta.market || (meta.suffix === "TWO" ? "上櫃" : "上市"),
      themes: [],
      themeSectors: {},
      labels: [],
      searchAliases: []
    });
  }

  const metaByCode = new Map(WATCHLIST.map((stock) => [stock.code, stock]));
  for (const theme of THEME_MEMBERS) {
    for (const code of theme.codes) {
      const stock = metaByCode.get(code);
      if (!stock) continue;
      if (!stock.themes.includes(theme.key)) stock.themes.push(theme.key);
      stock.themeSectors[theme.key] = theme.title;
      if (!stock.primaryTheme) stock.primaryTheme = theme.key;
    }
  }
  for (const stock of WATCHLIST) {
    if (!stock.themes || !stock.themes.length) stock.themes = ["terafab"];
    if (!stock.themeSectors) stock.themeSectors = {};
  }
}

applyPassiveComponentExpansion();
applyAiSupplyChainExpansion();
ensureStockUniverse();

