function stockSubcategoryLabel(code, theme) {
  if (!theme || theme === "all" || theme === HOLDINGS_THEME_KEY) return "";
  const subs = THEME_SUBCATEGORIES[theme];
  if (!subs) return "";
  for (const [label, codes] of Object.entries(subs)) {
    if (codes.includes(code)) return label;
  }
  return "";
}

function stockSubcategoryBadgeHtml(code, theme) {
  const label = stockSubcategoryLabel(code, theme);
  return label ? `<span class="subcategory-badge">${escapeHtml(label)}</span>` : "";
}

// ─── 使用者自選股池（加入內建主題） ────────────────────────────────────────────
function applyUserThemeAdditions() {
  const additions = state.userThemeAdditions || {};
  for (const [themeKey, entries] of Object.entries(additions)) {
    if (!Array.isArray(entries) || !entries.length) continue;
    const themeMember = THEME_MEMBERS.find((t) => t.key === themeKey);
    for (const entry of entries) {
      const code = String(entry.code || "").trim();
      if (!code) continue;
      const suffix = entry.suffix || (code.startsWith("00") ? "TW" : "TW");
      const name = entry.name || STOCK_UNIVERSE[code]?.name || `股票 ${code}`;
      // Ensure stock is in WATCHLIST
      if (!STOCK_MAP.has(code)) {
        const known = STOCK_UNIVERSE[code] || {};
        const newStock = {
          code,
          suffix: known.suffix || suffix,
          name: known.name || name,
          group: "expand",
          sector: known.sector || entry.sector || "自訂觀察",
          ref: null, pe: null, eps25: null, eps26e: null, target: null,
          order: "自選", overlap: null, theme: null, stop: null, buy: "",
          catalyst: known.sector || "自選股", risk: "待建立研究假設",
          officialIndustry: known.officialIndustry,
          market: known.market || (suffix === "TWO" ? "上櫃" : "上市"),
          themes: [], themeSectors: {}, labels: [], searchAliases: [],
          userDefined: true
        };
        WATCHLIST.push(newStock);
        STOCK_MAP.set(code, newStock);
      }
      const stock = STOCK_MAP.get(code);
      // Assign theme
      if (!stock.themes.includes(themeKey)) stock.themes.push(themeKey);
      if (themeMember) {
        stock.themeSectors[themeKey] = stock.themeSectors[themeKey] || themeMember.title;
        if (!stock.primaryTheme) stock.primaryTheme = themeKey;
        if (!themeMember.codes.includes(code)) themeMember.codes.push(code);
      }
    }
  }
}

function addStockToPool(rawCode, themeKey) {
  if (!rawCode || !themeKey) { setStatus("請輸入股號並選擇主題。", "error"); return; }
  if (themeKey === HOLDINGS_THEME_KEY) {
    addCurrentHolding(rawCode);
    return;
  }
  const parsed = normalizeTickerInput(rawCode);
  if (!parsed) { setStatus("請輸入有效股號，例如 2330、6146.TWO。", "error"); return; }
  state.userThemeAdditions = state.userThemeAdditions || {};
  const existing = state.userThemeAdditions[themeKey] || [];
  const found = existing.find((e) => e.code === parsed.code);
  if (!found) {
    const known = STOCK_UNIVERSE[parsed.code] || {};
    state.userThemeAdditions[themeKey] = [
      ...existing,
      { code: parsed.code, suffix: parsed.suffix || known.suffix || "TW", name: known.name || `股票 ${parsed.code}`, sector: known.sector || "自訂觀察" }
    ];
  }
  applyUserThemeAdditions();
  applyResearchLabels();
  invalidateStockSearchIndex();
  persistStateSilently("股池新增");
  render();
  const label = THEME_LABELS[themeKey] || themeKey;
  setStatus(`已將 ${parsed.code} 加入「${label}」主題。`, "good");
}

function removeStockFromPool(code, themeKey) {
  state.userThemeAdditions = state.userThemeAdditions || {};
  const existing = state.userThemeAdditions[themeKey] || [];
  state.userThemeAdditions[themeKey] = existing.filter((e) => e.code !== code);
  // Remove theme from stock.themes
  const stock = STOCK_MAP.get(code);
  if (stock) stock.themes = stock.themes.filter((t) => t !== themeKey);
  const themeMember = THEME_MEMBERS.find((t) => t.key === themeKey);
  if (themeMember) themeMember.codes = themeMember.codes.filter((c) => c !== code);
  invalidateStockSearchIndex();
  persistStateSilently("股池移除");
  render();
  setStatus(`已從「${THEME_LABELS[themeKey] || themeKey}」移除 ${code}。`, "good");
}

function renderPoolThemeOptions() {
  const builtinThemes = THEME_ORDER.filter((k) => k !== "all" && k !== HOLDINGS_THEME_KEY && THEME_LABELS[k]);
  const options = builtinThemes.map((k) => `<option value="${escapeHtml(k)}">${escapeHtml(THEME_LABELS[k])}</option>`).join("");
  return options;
}

function researchLabelRule(key) {
  return RESEARCH_LABEL_LOOKUP[key] || null;
}

function stockResearchLabels(stock) {
  return (stock.labels || []).map((key) => {
    const rule = researchLabelRule(key);
    return rule ? rule.label : key;
  }).filter(Boolean);
}

function stockAllLabels(stock) {
  const scale = stockScaleInfo(stock);
  return uniqueList([
    scale && scale.searchLabel ? scale.searchLabel : "",
    ...stockResearchLabels(stock),
    ...stockThemeLabels(stock)
  ]);
}

function addResearchLabel(stock, key) {
  const rule = researchLabelRule(key);
  if (!rule) return;
  stock.labels = stock.labels || [];
  stock.searchAliases = stock.searchAliases || [];
  if (!stock.labels.includes(key)) stock.labels.push(key);
  for (const token of [rule.label, ...(rule.aliases || [])]) {
    if (token && !stock.searchAliases.includes(token)) stock.searchAliases.push(token);
  }
}

function applyResearchLabels() {
  for (const stock of WATCHLIST) {
    stock.labels = [];
    stock.searchAliases = [];
  }

  for (const rule of RESEARCH_LABEL_RULES) {
    if (Array.isArray(rule.codes)) {
      for (const code of rule.codes) {
        const stock = STOCK_MAP.get(code);
        if (!stock) continue;
        addResearchLabel(stock, rule.key);
      }
    }
    if (typeof rule.when === "function") {
      for (const stock of WATCHLIST) {
        if (rule.when(stock)) addResearchLabel(stock, rule.key);
      }
    }
  }
}

