// ─────────────────────────────────────────────────────────────────────────────
// 海外 ETF 規模 / 流動性（⚠️ unverified — please cross-check）
// AUM 與日均量為近似值，會隨市場波動；實際以投信月報、TWSE / TPEx 公告為準
// 規模量級分類：
//   ─ 巨型 (>1,000 億)：流動性極佳、買賣價差小
//   ─ 大型 (300-1,000 億)：流動性佳
//   ─ 中型 (100-300 億)：流動性中等，大單需注意衝擊成本
//   ─ 小型 (30-100 億)：流動性偏低，大單衝擊明顯
//   ─ 過小 (<30 億)：流動性差、易出現折溢價，避免大筆持有
// avgDailyVolume：日均成交量（張）；price × volume × 1000 即為日均成交金額
// ─────────────────────────────────────────────────────────────────────────────
const LIQUIDITY_TIER_META = {
  giant:    { label: "巨型 (>1,000億)", tone: "up",   note: "流動性極佳" },
  large:    { label: "大型 (300-1000億)", tone: "up",   note: "流動性佳" },
  mid:      { label: "中型 (100-300億)", tone: "flat", note: "流動性中等" },
  small:    { label: "小型 (30-100億)",   tone: "warn", note: "流動性偏低，大單衝擊明顯" },
  micro:    { label: "過小 (<30億)",       tone: "down", note: "流動性差，避免大筆持有" },
  unknown:  { label: "資料待更新",          tone: "flat", note: "規模 / 日均量待人工核對" }
};

function classifyLiquidityTier(aumBillion) {
  if (aumBillion == null) return "unknown";
  if (aumBillion >= 1000) return "giant";
  if (aumBillion >= 300) return "large";
  if (aumBillion >= 100) return "mid";
  if (aumBillion >= 30) return "small";
  return "micro";
}

