function etfLiquidityFor(code) {
  const liquidity = OVERSEAS_ETF_LIQUIDITY[code];
  if (!liquidity) return { tier: "unknown", aum: null, avgDailyVolume: null, asOf: "-" };
  return { ...liquidity, tier: classifyLiquidityTier(liquidity.aum) };
}

function liquidityChipHtml(code) {
  const l = etfLiquidityFor(code);
  const meta = LIQUIDITY_TIER_META[l.tier] || LIQUIDITY_TIER_META.unknown;
  const aumText = l.aum != null ? `${formatNumber(l.aum, 0)} 億` : "-";
  const advText = l.avgDailyVolume != null ? `${formatNumber(l.avgDailyVolume, 0)} 張/日` : "-";
  const tip = `${meta.label} · 規模 ${aumText} · 日均 ${advText}${l.note ? "｜" + l.note : ""}（${l.asOf || "-"}）⚠️ 以投信公告為準`;
  return `<span class="chip ${meta.tone}" title="${escapeHtml(tip)}">${escapeHtml(meta.label.split(" ")[0])} ${aumText}</span>`;
}

