const $ = (id) => document.getElementById(id);

function performanceDiagnosticsApi() {
  if (typeof window !== "undefined" && window.TwStockPerformanceDiagnostics) {
    return window.TwStockPerformanceDiagnostics;
  }
  return null;
}

function performanceDiagnosticsNow() {
  const api = performanceDiagnosticsApi();
  if (api && typeof api.nowMs === "function") return api.nowMs();
  if (typeof performance !== "undefined" && typeof performance.now === "function") return performance.now();
  return Date.now();
}

function performanceDiagnosticsDuration(startedAt) {
  const api = performanceDiagnosticsApi();
  if (api && typeof api.durationSince === "function") return api.durationSince(startedAt);
  const start = Number(startedAt);
  return Number.isFinite(start) ? Math.max(0, performanceDiagnosticsNow() - start) : null;
}

function ensurePerformanceDiagnostics() {
  const api = performanceDiagnosticsApi();
  if (api && typeof api.ensure === "function") {
    state.performance = api.ensure(state.performance || {});
  } else {
    state.performance = state.performance && typeof state.performance === "object" ? state.performance : {};
  }
  return state.performance;
}

function recordPerformanceCache(name, outcome) {
  const api = performanceDiagnosticsApi();
  if (!api || typeof api.recordCache !== "function") return;
  state.performance = api.recordCache(ensurePerformanceDiagnostics(), name, outcome);
}

function recordPerformanceSeedLoad(startedAt) {
  const api = performanceDiagnosticsApi();
  if (!api || typeof api.recordSeedLoad !== "function") return;
  state.performance = api.recordSeedLoad(ensurePerformanceDiagnostics(), {
    source: _cacheLoadInfo?.source || "",
    seedLabel: _cacheLoadInfo?.seedLabel || "",
    seedApplied: _cacheLoadInfo?.seedApplied === true,
    durationMs: performanceDiagnosticsDuration(startedAt),
    quoteCount: Object.keys(state.quotes || {}).length,
    klineCount: Object.keys(state.klines || {}).length,
    heavyCacheMode: state.heavyCacheStorage?.mode || ""
  });
}

function recordPerformanceRenderBlock(name, startedAt, details = {}) {
  const api = performanceDiagnosticsApi();
  if (!api || typeof api.recordRenderBlock !== "function") return;
  state.performance = api.recordRenderBlock(ensurePerformanceDiagnostics(), {
    name,
    tab: details.tab || state.activeTab || "",
    fallbackId: details.fallbackId || "",
    ok: details.ok !== false,
    durationMs: performanceDiagnosticsDuration(startedAt)
  });
}

function recordPerformanceActiveTab(tab, startedAt, details = {}) {
  const api = performanceDiagnosticsApi();
  if (!api || typeof api.recordActiveTabRender !== "function") return;
  state.performance = api.recordActiveTabRender(ensurePerformanceDiagnostics(), {
    tab,
    scope: details.scope || "",
    durationMs: performanceDiagnosticsDuration(startedAt)
  });
}

function performanceDiagnosticsSummary() {
  const api = performanceDiagnosticsApi();
  if (api && typeof api.summarize === "function") return api.summarize(ensurePerformanceDiagnostics());
  return {
    version: "unavailable",
    updatedAt: "",
    seedLoad: {},
    activeTab: {},
    cacheRows: [],
    slowRenderBlocks: []
  };
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

const MARKET_UP_WORDS = ["漲停", "買漲", "買超", "連買", "大買", "買進", "買盤", "做多", "多頭", "偏多", "上漲", "價漲", "漲"];
const MARKET_DOWN_WORDS = ["跌停", "賣超", "連賣", "大賣", "賣出", "賣壓", "做空", "放空", "空頭", "空方", "空單", "偏空", "下跌", "價跌", "跌"];
const MARKET_KEYWORD_PATTERN = new RegExp(`(${[...MARKET_UP_WORDS, ...MARKET_DOWN_WORDS].sort((a, b) => b.length - a.length).map((word) => word.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).join("|")})`, "g");
const MARKET_ISOLATED_SHORT_PATTERN = /(^|[\s:：;；,，、/()（）\[\]「」『』<>《》↑↓])空(?=$|[\s:：;；,，、/()（）\[\]「」『』<>《》↑↓])/g;

function marketKeywordHtml(value) {
  const html = escapeHtml(value);
  return html.replace(MARKET_KEYWORD_PATTERN, (word) => {
    if (MARKET_UP_WORDS.includes(word)) return `<span class="market-word-up">${word}</span>`;
    if (MARKET_DOWN_WORDS.includes(word)) return `<span class="market-word-down">${word}</span>`;
    return word;
  }).replace(MARKET_ISOLATED_SHORT_PATTERN, (match, prefix) => `${prefix}<span class="market-word-down">空</span>`);
}

function toNumber(value) {
  if (value === null || value === undefined) return null;
  const text = String(value).replace(/,/g, "").trim();
  if (!text || text === "-" || text.toLowerCase() === "null") return null;
  const number = Number(text);
  return Number.isFinite(number) ? number : null;
}

function normalizeSnapshotTrendWindow(value) {
  const number = Number(value);
  return SNAPSHOT_TREND_WINDOW_OPTIONS.includes(number)
    ? number
    : SNAPSHOT_TREND_WINDOW_OPTIONS[0];
}

function firstNumeric(value) {
  if (value === null || value === undefined) return null;
  const parts = String(value).split("_");
  for (const part of parts) {
    const number = toNumber(part);
    if (number !== null) return number;
  }
  return null;
}

function numericList(value, options = {}) {
  if (value === null || value === undefined) return [];
  const min = options.min ?? null;
  return String(value)
    .split("_")
    .map(toNumber)
    .filter((number) => number !== null && (min === null || number >= min));
}

function priceEquals(left, right, tolerance = 0.01) {
  const a = toNumber(left);
  const b = toNumber(right);
  if (a === null || b === null) return false;
  return Math.abs(a - b) <= tolerance;
}

function taiwanStockTickSize(price) {
  const number = Math.abs(toNumber(price) || 0);
  const row = TAIWAN_STOCK_TICK_TABLE.find((item) => number >= item.min && number < item.max);
  return row ? row.tick : 0.01;
}

function tickDecimalPlaces(tick) {
  const text = String(tick);
  return text.includes(".") ? text.split(".")[1].length : 0;
}

function roundTaiwanStockPrice(value, mode) {
  const number = toNumber(value);
  if (number === null || number <= 0) return null;
  const tick = taiwanStockTickSize(number);
  const scaled = number / tick;
  const rounded = mode === "ceil"
    ? Math.ceil(scaled - 1e-8)
    : Math.floor(scaled + 1e-8);
  return Number((rounded * tick).toFixed(tickDecimalPlaces(tick)));
}

function taiwanPriceText(value, tick = null) {
  const number = toNumber(value);
  if (number === null) return "-";
  const decimals = tick !== null ? tickDecimalPlaces(tick) : tickDecimalPlaces(taiwanStockTickSize(number));
  return number.toLocaleString("zh-TW", {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals
  });
}

function taiwanPriceLimitFromBase(basePrice) {
  const base = toNumber(basePrice);
  if (base === null || base <= 0) {
    return { available: false, base: null };
  }
  const theoreticalUp = base * (1 + TAIWAN_STOCK_PRICE_LIMIT_PCT / 100);
  const theoreticalDown = base * (1 - TAIWAN_STOCK_PRICE_LIMIT_PCT / 100);
  const limitUp = roundTaiwanStockPrice(theoreticalUp, "floor");
  const limitDown = roundTaiwanStockPrice(theoreticalDown, "ceil");
  return {
    available: limitUp !== null && limitDown !== null,
    base,
    theoreticalUp,
    theoreticalDown,
    limitUp,
    limitDown,
    baseTick: taiwanStockTickSize(base),
    upTick: taiwanStockTickSize(theoreticalUp),
    downTick: taiwanStockTickSize(theoreticalDown)
  };
}

function formatNumber(value, digits = 2) {
  const number = toNumber(value);
  if (number === null) return "-";
  return number.toLocaleString("zh-TW", {
    minimumFractionDigits: Number.isInteger(number) ? 0 : digits,
    maximumFractionDigits: digits
  });
}

function formatPct(value) {
  const number = toNumber(value);
  if (number === null) return "-";
  return `${number >= 0 ? "+" : ""}${number.toFixed(2)}%`;
}

function formatSignedMetric(value, digits = 1, suffix = "") {
  const number = toNumber(value);
  if (number === null) return "-";
  const displaySuffix = suffix === "pp" ? "百分點" : suffix;
  return `${number > 0 ? "+" : ""}${number.toFixed(digits)}${displaySuffix}`;
}

function formatPercentMetric(value, digits = 2) {
  const number = toNumber(value);
  if (number === null) return "-";
  return `${number.toFixed(digits)}%`;
}

function formatDateTime(value, options = {}) {
  if (!value) return "尚未更新";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toLocaleString("zh-TW", {
    timeZone: options.timeZone || TAIPEI_TIME_ZONE,
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  });
}

function formatDateOnly(value) {
  if (!value) return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toLocaleDateString("zh-TW", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  });
}

function todayKey(date = new Date()) {
  return date.toISOString().slice(0, 10);
}

function dateKeyInTaipei(date = new Date()) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: TAIPEI_TIME_ZONE,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(date).reduce((acc, part) => {
    acc[part.type] = part.value;
    return acc;
  }, {});
  return `${parts.year}-${parts.month}-${parts.day}`;
}

function timeKeyInTaipei(date = new Date()) {
  return new Intl.DateTimeFormat("zh-TW", {
    timeZone: TAIPEI_TIME_ZONE,
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).format(date);
}

function previousWeekday(date) {
  const d = new Date(date);
  do {
    d.setDate(d.getDate() - 1);
  } while (d.getDay() === 0 || d.getDay() === 6);
  return d;
}

function expectedLatestTradingDateKey(now = new Date()) {
  const taipeiHour = Number(new Intl.DateTimeFormat("en-US", {
    timeZone: TAIPEI_TIME_ZONE,
    hour: "numeric",
    hour12: false
  }).format(now));
  const key = dateKeyInTaipei(now);
  const local = new Date(`${key}T12:00:00+08:00`);
  if (local.getDay() === 0 || local.getDay() === 6 || taipeiHour < 8) {
    return dateKeyInTaipei(previousWeekday(local));
  }
  return key;
}

function dateKeyDiffDays(a, b) {
  if (!a || !b) return null;
  const da = Date.parse(`${a}T00:00:00+08:00`);
  const db = Date.parse(`${b}T00:00:00+08:00`);
  if (!Number.isFinite(da) || !Number.isFinite(db)) return null;
  return Math.round((db - da) / ONE_DAY_MS);
}

function dateKeyFromParts(year, month, day) {
  return `${year}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

function thirdWednesdayDateKey(year, month) {
  const firstDay = new Date(Date.UTC(year, month - 1, 1, 12));
  const firstWeekday = firstDay.getUTCDay();
  const day = 1 + ((3 - firstWeekday + 7) % 7) + 14;
  return dateKeyFromParts(year, month, day);
}

function nextMonthParts(year, month) {
  return month === 12 ? { year: year + 1, month: 1 } : { year, month: month + 1 };
}

function previousMonthParts(year, month) {
  return month === 1 ? { year: year - 1, month: 12 } : { year, month: month - 1 };
}

function taiexFuturesSettlementInfo(now = new Date()) {
  const today = dateKeyInTaipei(now);
  const [year, month] = today.split("-").map((part) => Number(part));
  const currentSettlement = thirdWednesdayDateKey(year, month);
  let targetYear = year;
  let targetMonth = month;
  let nextSettlement = currentSettlement;
  if (dateKeyDiffDays(today, currentSettlement) < 0) {
    const next = nextMonthParts(year, month);
    targetYear = next.year;
    targetMonth = next.month;
    nextSettlement = thirdWednesdayDateKey(targetYear, targetMonth);
  }
  const prev = previousMonthParts(targetYear, targetMonth);
  const previousSettlement = thirdWednesdayDateKey(prev.year, prev.month);
  const daysUntil = dateKeyDiffDays(today, nextSettlement);
  const level = daysUntil === 0 ? "danger" : daysUntil !== null && daysUntil <= 3 ? "warn" : "flat";
  const title = daysUntil === 0
    ? "今日台指期結算"
    : daysUntil === 1
      ? "明日台指期結算"
      : daysUntil !== null && daysUntil <= 3
        ? `台指期結算 T-${daysUntil}`
        : "下次台指期結算";
  return {
    today,
    year: targetYear,
    month: targetMonth,
    dateKey: nextSettlement,
    previousDateKey: previousSettlement,
    daysUntil,
    level,
    title,
    lastTradeTime: "13:30",
    settlementWindow: "收盤前 30 分鐘",
    source: "TAIFEX 臺股期貨契約規格",
    sourceTier: "Tier 1 官方",
    fallbackUsed: false,
    confidence: "rule-estimated",
    note: "以 TAIFEX 契約規格推算：各交割月份第三個星期三；遇休市或交易所公告調整時需以 TAIFEX 公告為準。"
  };
}

function taiexFuturesSettlementChipHtml() {
  const info = taiexFuturesSettlementInfo();
  const cls = info.level === "danger" ? "down" : info.level === "warn" ? "warn" : "flat";
  const dayText = info.daysUntil === 0 ? "今日" : info.daysUntil === 1 ? "明日" : `T-${info.daysUntil}`;
  return `<span class="chip ${cls}" title="${escapeHtml(info.note)}">台指期結算 ${escapeHtml(info.dateKey)} ${escapeHtml(dayText)}</span>`;
}

function renderTaiexFuturesSettlementReminder() {
  const info = taiexFuturesSettlementInfo();
  const bannerClass = info.level === "danger" ? "danger" : info.level === "warn" ? "warn" : "good";
  const isNear = info.daysUntil !== null && info.daysUntil <= 3;
  return `
    <div class="chip-alert-banner ${bannerClass}" style="margin-bottom:14px;">
      <div>
        <strong>${escapeHtml(info.title)}</strong>
        <div style="font-size:0.82rem;line-height:1.5;margin-top:4px;">
          下次日期：${escapeHtml(info.dateKey)}；到期月契約一般交易至 ${escapeHtml(info.lastTradeTime)}；最後結算價參考 ${escapeHtml(info.settlementWindow)} 指數均價。${isNear ? " 結算日前後請檢查期貨、選擇權、ETF 與現股部位曝險。" : " 目前尚未進入 T-3 視覺警示區。"}
        </div>
        <div style="font-size:0.76rem;color:var(--muted);margin-top:4px;">${escapeHtml(info.note)}</div>
      </div>
      <div class="link-row" style="margin-top:0;">
        ${TAIFEX_SETTLEMENT_SOURCE_LINKS.map((link) => `<a class="link-chip" href="${escapeHtml(link.url)}" target="_blank" rel="noopener">${escapeHtml(link.label)}</a>`).join("")}
      </div>
    </div>
  `;
}

function maybeTriggerFuturesSettlementReminder() {
  const info = taiexFuturesSettlementInfo();
  if (info.daysUntil === null || info.daysUntil > 1) return;
  const key = `${info.dateKey}:T-${info.daysUntil}`;
  if (state.futuresSettlementReminderLast === key) return;
  state.futuresSettlementReminderLast = key;
  persistStateSilently("台指期結算提醒");
  triggerAlert(`${info.title}（${info.dateKey}）。到期月契約一般交易至 ${info.lastTradeTime}，請檢查期貨、選擇權與現股曝險。`, info.daysUntil === 0 ? "stop" : "target");
}

function normalizeQuoteSourceDate(value) {
  const text = String(value || "").trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(text)) return text;
  if (/^\d{8}$/.test(text)) return `${text.slice(0, 4)}-${text.slice(4, 6)}-${text.slice(6, 8)}`;
  return "";
}

function quoteFreshnessInfo(quote, now = new Date()) {
  if (!quote) {
    return { level: "missing", label: "尚未更新", detail: "尚無報價，請按個股報價", expectedDate: expectedLatestTradingDateKey(now) };
  }
  const expectedDate = expectedLatestTradingDateKey(now);
  const sourceDate = normalizeQuoteSourceDate(quote.sourceDate);
  const lagDays = sourceDate ? dateKeyDiffDays(sourceDate, expectedDate) : null;
  const fallback = quote.sourceKind === "fallback" || quote.fallbackUsed;
  if (!sourceDate) {
    return { level: "warn", label: "報價日期缺失", detail: `${quote.source || "來源"} 未提供可核對日期`, expectedDate, sourceDate, lagDays, fallback };
  }
  if (lagDays !== null && lagDays > QUOTE_STALE_GRACE_DAYS) {
    return { level: "stale", label: `落後 ${lagDays} 天`, detail: `${quote.source || "來源"} 日期 ${sourceDate}，預期至少 ${expectedDate}`, expectedDate, sourceDate, lagDays, fallback };
  }
  if (fallback) {
    const sourceName = quote.source || (quote.sourceKind === "fallback" ? "Yahoo" : "備援來源");
    return { level: "fallback", label: `${sourceName} ${sourceDate}`, detail: `官方 MIS 失敗時才使用；已保留實際來源日期供核對`, expectedDate, sourceDate, lagDays, fallback };
  }
  return { level: "fresh", label: `最新 ${sourceDate}`, detail: `${quote.source || "官方"} ${quote.sourceTime || ""}`.trim(), expectedDate, sourceDate, lagDays, fallback };
}

function quoteFreshnessChipHtml(quote) {
  const info = quoteFreshnessInfo(quote);
  const cls = info.level === "fresh" ? "up" : info.level === "stale" || info.level === "missing" ? "down" : "flat";
  return `<span class="chip ${cls}" title="${escapeHtml(info.detail)}">${escapeHtml(info.label)}</span>`;
}

function parseCompactDay(value) {
  const match = String(value || "").match(/^(\d{4})(\d{2})(\d{2})$/);
  if (!match) return "";
  return `${match[1]}-${match[2]}-${match[3]}`;
}

function officialTextValue(value) {
  const text = String(value ?? "").replace(/\u3000/g, " ").trim();
  if (!text || text === "-" || /^N\/A$/i.test(text) || /^null$/i.test(text)) return "";
  return text;
}

function officialNumberValue(value) {
  const text = officialTextValue(value);
  return text ? toNumber(text) : null;
}

function themeButtonLabel(key) {
  const index = THEME_ORDER.indexOf(key);
  const prefix = index >= 0 ? `${String(index + 1).padStart(2, "0")}. ` : "";
  return `${prefix}${THEME_LABELS[key] || key}`;
}

function normalizeTickerInput(raw) {
  const text = String(raw || "").trim().toUpperCase().replace(/\s+/g, "");
  const match = text.match(/^([0-9A-Z]+)(?:\.(TW|TWO))?$/);
  if (!match) return null;
  const code = match[1];
  const known = STOCK_UNIVERSE[code] || {};
  return {
    code,
    suffix: match[2] || known.suffix || "TW"
  };
}

function normalizeHoldingEntry(entry) {
  if (!entry) return null;
  const parsed = normalizeTickerInput(entry.ticker || entry.symbol || entry.raw || `${entry.code || ""}${entry.suffix ? `.${entry.suffix}` : ""}`);
  if (!parsed) return null;
  const known = (state.userStocks && state.userStocks[parsed.code]) || STOCK_UNIVERSE[parsed.code] || {};
  return {
    code: parsed.code,
    suffix: parsed.suffix || known.suffix || "TW",
    name: String(entry.name || known.name || `自訂股 ${parsed.code}`).trim()
  };
}

function currentHoldingsSeedCopy() {
  return CURRENT_HOLDINGS_SEED.map((entry) => ({ ...entry }));
}

function applyCurrentHoldingsPresetIfNeeded() {
  if (state.holdingsPresetVersion === CURRENT_HOLDINGS_PRESET_VERSION) return false;
  if (Array.isArray(state.holdings) && state.holdings.length) {
    // 使用者持股屬本機資料；版本更新只升級標記，不覆寫既有非空清單。
    state.holdingsPresetVersion = CURRENT_HOLDINGS_PRESET_VERSION;
    return false;
  }
  state.holdings = currentHoldingsSeedCopy();
  state.holdingsPresetVersion = CURRENT_HOLDINGS_PRESET_VERSION;
  if (!state.selectedCode || !state.holdings.some((entry) => entry.code === state.selectedCode)) {
    state.selectedCode = state.holdings[0]?.code || WATCHLIST[0]?.code || "";
  }
  return true;
}

function buildStockRecord(meta) {
  return {
    code: meta.code,
    suffix: meta.suffix || "TW",
    name: meta.name || `自訂股 ${meta.code}`,
    group: meta.group || "expand",
    sector: meta.sector || "自訂觀察",
    ref: null,
    pe: null,
    eps25: null,
    eps26e: null,
    target: null,
    order: "待追蹤",
    overlap: null,
    theme: null,
    stop: null,
    buy: "",
    catalyst: meta.catalyst || meta.sector || "自訂觀察名單",
    risk: meta.risk || "待建立研究假設",
    officialIndustry: meta.officialIndustry || null,
    market: meta.market || (meta.suffix === "TWO" ? "上櫃" : "上市"),
    themes: [],
    themeSectors: {},
    labels: [],
    searchAliases: [],
    primaryTheme: null,
    userDefined: Boolean(meta.userDefined)
  };
}

function ensureStockRecord(meta) {
  let stock = STOCK_MAP.get(meta.code);
  if (!stock) {
    stock = buildStockRecord(meta);
    WATCHLIST.push(stock);
    STOCK_MAP.set(meta.code, stock);
    return stock;
  }

  if (meta.name) stock.name = meta.name;
  if (meta.suffix) stock.suffix = meta.suffix;
  if (meta.sector && (!stock.sector || stock.sector === "自訂觀察")) stock.sector = meta.sector;
  if (meta.market) stock.market = meta.market;
  if (meta.officialIndustry && !stock.officialIndustry) stock.officialIndustry = meta.officialIndustry;
  if (meta.userDefined) stock.userDefined = true;
  stock.themes = stock.themes || [];
  stock.themeSectors = stock.themeSectors || {};
  stock.labels = stock.labels || [];
  stock.searchAliases = stock.searchAliases || [];
  return stock;
}

function addThemeMembership(stock, themeKey, themeTitle) {
  stock.themes = stock.themes || [];
  stock.themeSectors = stock.themeSectors || {};
  if (!stock.themes.includes(themeKey)) stock.themes.push(themeKey);
  stock.themeSectors[themeKey] = themeTitle;
  if (!stock.primaryTheme) stock.primaryTheme = themeKey;
}

function removeThemeMembership(stock, themeKey) {
  stock.themes = (stock.themes || []).filter((key) => key !== themeKey);
  if (stock.themeSectors) delete stock.themeSectors[themeKey];
  if (stock.primaryTheme === themeKey) {
    stock.primaryTheme = stock.themes.find((key) => key !== HOLDINGS_THEME_KEY) || stock.themes[0] || null;
  }
}

function removeStockRecord(code) {
  const index = WATCHLIST.findIndex((stock) => stock.code === code);
  if (index >= 0) WATCHLIST.splice(index, 1);
  STOCK_MAP.delete(code);
}

function syncCurrentHoldingsTheme() {
  const theme = THEME_MEMBERS.find((item) => item.key === HOLDINGS_THEME_KEY);
  const seed = Array.isArray(state.holdings) && state.holdings.length ? state.holdings : currentHoldingsSeedCopy();
  const normalized = [];
  const codes = new Set();

  state.userStocks = state.userStocks || {};

  for (const entry of seed) {
    const holding = normalizeHoldingEntry(entry);
    if (!holding || codes.has(holding.code)) continue;
    codes.add(holding.code);
    normalized.push(holding);
  }

  state.holdings = normalized;
  if (theme) theme.codes = normalized.map((entry) => entry.code);

  for (const entry of normalized) {
    const userMeta = state.userStocks[entry.code] || {};
    const known = STOCK_UNIVERSE[entry.code] || {};
    const stock = ensureStockRecord({
      code: entry.code,
      suffix: entry.suffix || userMeta.suffix || known.suffix || "TW",
      name: entry.name || userMeta.name || known.name || `自訂股 ${entry.code}`,
      sector: userMeta.sector || known.sector || "自訂觀察",
      officialIndustry: userMeta.officialIndustry || known.officialIndustry || null,
      market: userMeta.market || known.market || ((entry.suffix || known.suffix) === "TWO" ? "上櫃" : "上市"),
      userDefined: Boolean(state.userStocks[entry.code])
    });
    addThemeMembership(stock, HOLDINGS_THEME_KEY, theme ? theme.title : THEME_LABELS[HOLDINGS_THEME_KEY]);
    if (!STOCK_UNIVERSE[entry.code]) {
      state.userStocks[entry.code] = {
        name: stock.name,
        suffix: stock.suffix,
        sector: stock.sector,
        market: stock.market,
        officialIndustry: stock.officialIndustry || null
      };
    }
  }

  for (const stock of [...WATCHLIST]) {
    if (!(stock.themes || []).includes(HOLDINGS_THEME_KEY)) continue;
    if (codes.has(stock.code)) continue;
    removeThemeMembership(stock, HOLDINGS_THEME_KEY);
    if (stock.userDefined && !(stock.themes || []).length) {
      removeStockRecord(stock.code);
    }
  }

  applyResearchLabels();
}

async function addCurrentHolding(rawTicker, rawName = "") {
  state.userStocks = state.userStocks || {};
  state.holdings = Array.isArray(state.holdings) ? state.holdings : [];
  const nameText = String(rawName || "").trim();
  const holding = normalizeHoldingEntry({
    ticker: rawTicker,
    name: nameText
  });
  if (!holding) {
    setStatus("請輸入有效股號，例如 2301、2301.TW、6146.TWO、00981A.TW。", "error");
    return;
  }

  const existing = (state.holdings || []).find((entry) => entry.code === holding.code);
  if (existing) {
    if (nameText) existing.name = nameText;
    existing.suffix = holding.suffix;
  } else {
    state.holdings.unshift(holding);
  }

  if (nameText && !STOCK_UNIVERSE[holding.code]) {
    state.userStocks[holding.code] = {
      ...(state.userStocks[holding.code] || {}),
      name: nameText,
      suffix: holding.suffix,
      sector: (state.userStocks[holding.code] && state.userStocks[holding.code].sector) || "自訂觀察",
      market: holding.suffix === "TWO" ? "上櫃" : "上市"
    };
  }

  syncCurrentHoldingsTheme();
  invalidateStockSearchIndex();
  state.filter = HOLDINGS_THEME_KEY;
  state.selectedCode = holding.code;
  await saveState();
  render();
  const codeInput = $("holdingCodeInput");
  const nameInput = $("holdingNameInput");
  if (codeInput) codeInput.value = "";
  if (nameInput) nameInput.value = "";
  const savedHolding = normalizeHoldingEntry((state.holdings || []).find((entry) => entry.code === holding.code)) || holding;
  setStatus(`${existing ? "已切換到目前持股" : "已加入目前持股"}：${savedHolding.name} ${savedHolding.code}.${savedHolding.suffix}`, "good");
}

async function removeCurrentHolding(code) {
  state.holdings = (state.holdings || []).filter((entry) => entry.code !== code);
  syncCurrentHoldingsTheme();
  invalidateStockSearchIndex();
  if (!STOCK_MAP.has(state.selectedCode)) {
    state.selectedCode = (state.holdings[0] && state.holdings[0].code) || WATCHLIST[0].code;
  }
  if (state.filter === HOLDINGS_THEME_KEY && !filteredStocks().length) {
    state.filter = "all";
  }
  await saveState();
  render();
  setStatus(`已從目前持股移除 ${code}。`, "good");
}

function changeClass(value) {
  const number = toNumber(value);
  if (number === null || number === 0) return "flat";
  return number > 0 ? "up" : "down";
}

function statusToneClass(tone) {
  if (tone === "up") return "good";
  if (tone === "down") return "bad";
  return tone || "flat";
}

function quoteFor(code) {
  try {
    const quotes = state && state.quotes && typeof state.quotes === "object" ? state.quotes : {};
    return quotes[code] || null;
  } catch (_) {
    return null;
  }
}

function valuationFor(code) {
  try {
    const valuations = state && state.valuations && typeof state.valuations === "object" ? state.valuations : {};
    return valuations[code] || null;
  } catch (_) {
    return null;
  }
}

function institutionalFor(code) {
  try {
    const institutional = state && state.institutional && typeof state.institutional === "object" ? state.institutional : {};
    const record = institutional[code] || null;
    return record ? normalizeInstitutionalRecord(record) : null;
  } catch (_) {
    return null;
  }
}

function latestValue(stock) {
  const quote = quoteFor(stock.code);
  const valuation = valuationFor(stock.code);
  if (quote && quote.price !== null) return quote.price;
  if (valuation && valuation.close !== null) return valuation.close;
  return stock.ref;
}

function effectivePe(stock) {
  const valuation = valuationFor(stock.code);
  return valuation && valuation.pe !== null ? valuation.pe : stock.pe;
}

// ─────────────────────────────────────────────────────────────────────────────
// 個股流動性評估（適用所有股票，包含 ETF 與個股）
//
// 採複合分級：日均成交張數（主要）+ 日均交易金額（輔助），取較嚴格者
//
// 主要分級依「日均成交張數」（lookback 20 日）：
//   ─ 巨型 ≥ 5,000 張/日：藍籌大型股級別
//   ─ 大型 1,000-5,000 張/日
//   ─ 中型 500-1,000 張/日（**500 張為實務分水嶺**）
//   ─ 小型 100-500 張/日
//   ─ 過小 < 100 張/日（建議避開或小額）
//
// 輔助分級依「日均交易金額」（避免高價股因張數低被誤判）：
//   ─ 巨型 ≥ 5 億元/日 ；大型 1-5 億 ；中型 3000萬-1億 ；小型 1000-3000萬 ；過小 < 1000 萬
//
// 採用「兩者較嚴格的等級」作為最終分級，例如：
//   ─ 新鼎 5209（價 ~80 元、量 ~100 張）→ 張數小型 / 金額過小 → 採過小（與用戶直覺一致）
//   ─ 台積電 2330（價 ~1,300 元、量 ~30,000 張）→ 巨型 / 巨型 → 採巨型
//
// 文獻 / 實務來源（⚠️ unverified — please cross-check）：
//   1. TWSE 「公布注意交易資訊辦法」與「公布處置作業要點」：低成交筆數的個股會被列為流動量偏低
//      https://twse-regulation.twse.com.tw/
//   2. 證交所「上市股票流動量檢視標準」：每月成交筆數低於約 200 筆視為偏低
//      https://www.twse.com.tw/zh/page/products/securities/list-low.html
//   3. 實務常見「500 張日均成交量」作為個股投資者的最低流動性水位
//      （參考：MoneyDJ、財報狗、CMoney 等實務分析常見門檻）
// ─────────────────────────────────────────────────────────────────────────────
const STOCK_LIQUIDITY_TIERS = {
  giant:    { label: "巨型流動性 (≥ 5,000 張/日)", short: "巨型", tone: "up",   note: "藍籌股級別，自由進出，幾乎無衝擊成本" },
  large:    { label: "大型流動性 (1,000-5,000 張/日)", short: "大型", tone: "up",   note: "流動性佳，一般大單可消化" },
  mid:      { label: "中型流動性 (500-1,000 張/日)", short: "中型", tone: "flat", note: "實務 500 張分水嶺以上，可進可出" },
  small:    { label: "小型流動性 (100-500 張/日)", short: "小型", tone: "warn", note: "低於 500 張實務水位，大單易拉開買賣價差" },
  micro:    { label: "過小流動性 (< 100 張/日)", short: "過小", tone: "down", note: "TWSE 流動量偏低區間，建議避開或小額試水溫" },
  unknown:  { label: "待累積",      short: "待累積", tone: "flat", note: "缺日線資料，請先更新日線" }
};

// 主要：依張數
function classifyLiquidityByVolumeLots(avgVolumeLots) {
  if (avgVolumeLots == null || !Number.isFinite(avgVolumeLots)) return "unknown";
  if (avgVolumeLots >= 5_000) return "giant";
  if (avgVolumeLots >= 1_000) return "large";
  if (avgVolumeLots >= 500) return "mid";
  if (avgVolumeLots >= 100) return "small";
  return "micro";
}

// 輔助：依金額（避免高價股因張數少誤判）
function classifyLiquidityByTurnoverNTD(avgTurnoverNTD) {
  if (avgTurnoverNTD == null || !Number.isFinite(avgTurnoverNTD)) return "unknown";
  if (avgTurnoverNTD >= 500_000_000) return "giant";
  if (avgTurnoverNTD >= 100_000_000) return "large";
  if (avgTurnoverNTD >= 30_000_000) return "mid";
  if (avgTurnoverNTD >= 10_000_000) return "small";
  return "micro";
}

const LIQUIDITY_TIER_ORDER = ["unknown", "giant", "large", "mid", "small", "micro"];

// 兩者取較嚴格（後段者更嚴格 → index 大者勝）；若任一為 unknown 而另一非 unknown，採用非 unknown 的
function classifyStockLiquidityTier(avgVolumeLots, avgTurnoverNTD) {
  const byVol = classifyLiquidityByVolumeLots(avgVolumeLots);
  const byNtd = classifyLiquidityByTurnoverNTD(avgTurnoverNTD);
  if (byVol === "unknown" && byNtd === "unknown") return "unknown";
  if (byVol === "unknown") return byNtd;
  if (byNtd === "unknown") return byVol;
  // 取「較嚴格」(index 較大) 的等級
  return LIQUIDITY_TIER_ORDER.indexOf(byVol) >= LIQUIDITY_TIER_ORDER.indexOf(byNtd) ? byVol : byNtd;
}

function stockLiquidityInfo(code, lookback = 20) {
  // 海外 / 美債 ETF 採已知 AUM 級距，避免被本機日均量低估
  if (OVERSEAS_ETF_LIQUIDITY[code]) {
    const e = etfLiquidityFor(code);
    const meta = LIQUIDITY_TIER_META[e.tier] || LIQUIDITY_TIER_META.unknown;
    return {
      tier: e.tier,
      tierMeta: meta,
      avgVolume: e.avgDailyVolume,
      avgTurnoverNTD: null,
      latestVolume: null,
      coverage: 0,
      asOf: e.asOf,
      note: e.note || meta.note,
      mode: "etf-aum"
    };
  }
  const klines = latestKlines(code);
  if (!Array.isArray(klines) || !klines.length) {
    return { tier: "unknown", tierMeta: STOCK_LIQUIDITY_TIERS.unknown, avgVolume: null, avgTurnoverNTD: null, latestVolume: null, coverage: 0, mode: "kline" };
  }
  const recent = klines.slice(-lookback);
  const volumes = recent.map((row) => Number(row.volume)).filter((v) => Number.isFinite(v) && v >= 0);
  if (!volumes.length) {
    return { tier: "unknown", tierMeta: STOCK_LIQUIDITY_TIERS.unknown, avgVolume: null, avgTurnoverNTD: null, latestVolume: null, coverage: 0, mode: "kline" };
  }
  const avgVolume = volumes.reduce((a, b) => a + b, 0) / volumes.length;
  const turnovers = recent.map((row) => {
    const vol = Number(row.volume);
    const close = Number(row.close);
    if (!Number.isFinite(vol) || !Number.isFinite(close)) return null;
    // 1 張 = 1000 股；turnover = vol(張) × close(元) × 1000
    return vol * close * 1000;
  }).filter((v) => Number.isFinite(v));
  const avgTurnoverNTD = turnovers.length ? turnovers.reduce((a, b) => a + b, 0) / turnovers.length : null;
  const tier = classifyStockLiquidityTier(avgVolume, avgTurnoverNTD);
  const latestVolume = volumes[volumes.length - 1] ?? null;
  return {
    tier,
    tierMeta: STOCK_LIQUIDITY_TIERS[tier] || STOCK_LIQUIDITY_TIERS.unknown,
    avgVolume,
    avgTurnoverNTD,
    latestVolume,
    coverage: recent.length,
    mode: "kline",
    tierByVolume: classifyLiquidityByVolumeLots(avgVolume),
    tierByTurnover: classifyLiquidityByTurnoverNTD(avgTurnoverNTD)
  };
}

function formatLiquidityTurnover(value) {
  if (value == null || !Number.isFinite(value)) return "-";
  if (value >= 100_000_000) return `${(value / 100_000_000).toFixed(1)} 億`;
  if (value >= 10_000) return `${(value / 10_000).toFixed(0)} 萬`;
  return formatNumber(value, 0);
}

function formatLiquidityVolume(value) {
  if (value == null || !Number.isFinite(value)) return "-";
  if (value >= 10_000) return `${(value / 10_000).toFixed(1)} 萬張`;
  if (value >= 1_000) return `${(value / 1_000).toFixed(1)} 千張`;
  return `${formatNumber(value, 0)} 張`;
}

// 流動性趨勢：用最近 N 日量的前後半段斜率比較
// 輸出 trend: "rising" | "stable" | "falling" | "unknown"
function stockLiquidityTrend(code, lookback = 20) {
  const klines = latestKlines(code);
  if (!Array.isArray(klines) || klines.length < 8) return { trend: "unknown", slope: null };
  const recent = klines.slice(-lookback);
  const vols = recent.map((r) => Number(r.volume)).filter((v) => Number.isFinite(v) && v >= 0);
  if (vols.length < 8) return { trend: "unknown", slope: null };
  const half = Math.floor(vols.length / 2);
  const firstHalfAvg = vols.slice(0, half).reduce((a, b) => a + b, 0) / half;
  const secondHalfAvg = vols.slice(half).reduce((a, b) => a + b, 0) / (vols.length - half);
  if (firstHalfAvg === 0) return { trend: "unknown", slope: null };
  const changePct = (secondHalfAvg - firstHalfAvg) / firstHalfAvg * 100;
  let trend;
  if (changePct >= 20) trend = "rising";
  else if (changePct <= -20) trend = "falling";
  else trend = "stable";
  return { trend, slope: changePct };
}

const LIQUIDITY_TREND_DISPLAY = {
  rising:  { arrow: "↑", tone: "up",   label: "量能上升" },
  stable:  { arrow: "→", tone: "flat", label: "量能穩定" },
  falling: { arrow: "↓", tone: "down", label: "量能下滑" },
  unknown: { arrow: "-", tone: "flat", label: "待更新"  }
};

function stockLiquidityChipHtml(code) {
  const info = stockLiquidityInfo(code);
  const meta = info.tierMeta || STOCK_LIQUIDITY_TIERS.unknown;
  const trendInfo = stockLiquidityTrend(code);
  const trendDisplay = LIQUIDITY_TREND_DISPLAY[trendInfo.trend] || LIQUIDITY_TREND_DISPLAY.unknown;
  // 張數優先（個股投資者直覺）；金額 / AUM 列在 tooltip
  let primaryText;
  if (info.avgVolume != null) {
    primaryText = formatLiquidityVolume(info.avgVolume);
  } else {
    primaryText = "待累積";
  }
  const turnoverText = info.avgTurnoverNTD != null ? `${formatLiquidityTurnover(info.avgTurnoverNTD)} 元/日` : "-";
  const trendText = trendInfo.slope != null ? `${trendDisplay.arrow} ${trendDisplay.label}（近${info.coverage || 20}日${trendInfo.slope > 0 ? "+" : ""}${trendInfo.slope.toFixed(0)}%）` : `${trendDisplay.arrow} ${trendDisplay.label}`;
  const tipParts = [
    meta.label,
    meta.note,
    info.avgVolume != null ? `日均 ${formatLiquidityVolume(info.avgVolume)}` : null,
    info.avgTurnoverNTD != null ? `≈ ${turnoverText}` : null,
    trendText,
    info.coverage ? `覆蓋 ${info.coverage} 日` : null
  ].filter(Boolean);
  const tip = tipParts.join(" · ");
  // 過小流動性以更明顯的⚠️提示；下滑趨勢加 ↓
  const warn = (info.tier === "micro" || info.tier === "small") ? "⚠ " : "";
  const trendArrow = trendInfo.trend !== "unknown" ? ` ${trendDisplay.arrow}` : "";
  return `<span class="chip ${meta.tone}" title="${escapeHtml(tip)}">${warn}${escapeHtml(meta.short)} ${escapeHtml(primaryText)}${trendArrow}</span>`;
}

function compactDayFromDateLabel(value) {
  const text = String(value || "").replace(/\D/g, "");
  return text.length === 8 ? text : "";
}

function marketCapFor(code) {
  try {
    const records = state && state.marketCaps && typeof state.marketCaps === "object" ? state.marketCaps : {};
    return records[code] || null;
  } catch (_) {
    return null;
  }
}

function marketCapBenchmark() {
  const meta = state && state.marketCapMeta && typeof state.marketCapMeta === "object" ? state.marketCapMeta : {};
  return meta.twseBenchmark || null;
}

function marketCapHundredMillion(price, sharesIssued) {
  const p = toNumber(price);
  const shares = toNumber(sharesIssued);
  if (p === null || shares === null || p <= 0 || shares <= 0) return null;
  return p * shares / 100000000;
}

function marketCapTierFromRank(rank) {
  const n = toNumber(rank);
  if (n === null || n <= 0) return null;
  if (n <= MARKET_CAP_TOP_LARGE) return { key: "large", label: "大型股", searchLabel: "大型股" };
  if (n <= MARKET_CAP_TOP_MID) return { key: "mid", label: "中型股", searchLabel: "中型股" };
  if (n <= MARKET_CAP_TOP_SMALL) return { key: "small", label: "小型股", searchLabel: "小型股" };
  return { key: "micro", label: "小型以下", searchLabel: "小型以下" };
}

function marketCapTierFromValue(marketCap100m, benchmark = marketCapBenchmark()) {
  const value = toNumber(marketCap100m);
  const thresholds = benchmark && benchmark.thresholds ? benchmark.thresholds : null;
  if (value === null || !thresholds) return null;
  const largeFloor = toNumber(thresholds.largeFloor100m);
  const midFloor = toNumber(thresholds.midFloor100m);
  const smallFloor = toNumber(thresholds.smallFloor100m);
  if (largeFloor !== null && value >= largeFloor) return { key: "large", label: "大型股", searchLabel: "大型股" };
  if (midFloor !== null && value >= midFloor) return { key: "mid", label: "中型股", searchLabel: "中型股" };
  if (smallFloor !== null && value >= smallFloor) return { key: "small", label: "小型股", searchLabel: "小型股" };
  return { key: "micro", label: "小型以下", searchLabel: "小型以下" };
}

function stockPriceForMarketCap(stock) {
  const quote = quoteFor(stock.code);
  const valuation = valuationFor(stock.code);
  return quote?.price ?? valuation?.close ?? latestValue(stock);
}

function stockSharesIssued(stock) {
  const foreignOwn = (state.foreignOwnership || {})[stock.code];
  const marketCap = (state.marketCaps || {})[stock.code];
  const tdccData = (state.tdcc || {})[stock.code];
  return toNumber(foreignOwn?.sharesIssued) ?? toNumber(marketCap?.sharesIssued) ?? toNumber(tdccData?.totalShares) ?? null;
}

// v7.8 Feature 3：成分股名單以「自動同步覆寫」為優先，回退到內建常數
function effectiveTWSE50Set() {
  return Array.isArray(state.customTWSE50) && state.customTWSE50.length
    ? new Set(state.customTWSE50)
    : TWSE50_CODES;
}
function effectiveMID100Set() {
  return Array.isArray(state.customMID100) && state.customMID100.length
    ? new Set(state.customMID100)
    : TWSE_MID100_CODES;
}

function stockScaleInfo(stock) {
  if (!stock) return { key: "pending", label: "市值待更新", searchLabel: "", tone: "pending", sortScore: -1 };
  const code = String(stock.code || "");

  // ETF 判斷：代號以 "00" 開頭（0050, 00662, 00981A 等）
  if (code.startsWith("00") || code === "0050") {
    return { key: "etf", label: "ETF", searchLabel: "ETF", tone: "etf", sortScore: -1, marketCapText: "-", rankText: "ETF 不納入市值級距" };
  }

  // 先計算本機市值（股價 × 股數）
  const shares = stockSharesIssued(stock);
  const price = stockPriceForMarketCap(stock);
  const marketCap100m = marketCapHundredMillion(price, shares);
  const marketCapText = marketCap100m !== null ? `${formatNumber(marketCap100m, 0)} 億` : "-";

  // 先取市值（後續各分支都需要）
  const record = marketCapFor(code);
  const effectiveCap = toNumber(record?.marketCap100m) ?? marketCap100m;

  // 1. 0050 成分股 → 大型股（市值有資料時加防呆：< 300億不強制大型）
  if (effectiveTWSE50Set().has(code)) {
    if (effectiveCap !== null && effectiveCap < 300) {
      // 市值明顯偏低，可能已被調出指數，回落到值域分類
    } else {
      return {
        key: "large", label: "大型股", searchLabel: "大型股", tone: "large",
        sortScore: effectiveCap ?? 9999,
        marketCap100m: effectiveCap ?? marketCap100m, marketCapText,
        rankText: effectiveCap !== null ? `0050 成分股，市值 ${formatNumber(effectiveCap, 0)} 億` : "0050 成分股"
      };
    }
  }

  // 2. 台灣中型100 成分股 → 中型股（市值有資料時加防呆：< 50億不強制中型）
  if (effectiveMID100Set().has(code)) {
    if (effectiveCap !== null && effectiveCap < 50) {
      // 市值偏低，回落到值域分類
    } else {
      return {
        key: "mid", label: "中型股", searchLabel: "中型股", tone: "mid",
        sortScore: effectiveCap ?? 999,
        marketCap100m: effectiveCap ?? marketCap100m, marketCapText,
        rankText: effectiveCap !== null ? `中型100 成分股，市值 ${formatNumber(effectiveCap, 0)} 億` : "中型100 成分股"
      };
    }
  }

  // 3. 用市值值域 fallback（TWSE API 資料補充 or 本機推估）
  if (effectiveCap === null) {
    return {
      key: "pending", label: "市值待更新", searchLabel: "", tone: "pending", sortScore: -1,
      marketCapText, rankText: "需更新報價"
    };
  }

  // 門檻：大型 ≥ 3000億、中型 500-3000億、小型 50-500億、微型 < 50億
  if (effectiveCap >= 3000) {
    return { key: "large", label: "大型股", searchLabel: "大型股", tone: "large", sortScore: effectiveCap, marketCap100m: effectiveCap, marketCapText, rankText: "市值 ≥ 3,000億推估" };
  }
  if (effectiveCap >= 500) {
    return { key: "mid", label: "中型股", searchLabel: "中型股", tone: "mid", sortScore: effectiveCap, marketCap100m: effectiveCap, marketCapText, rankText: "市值 500-3,000億推估" };
  }
  if (effectiveCap >= 50) {
    return { key: "small", label: "小型股", searchLabel: "小型股", tone: "small", sortScore: effectiveCap, marketCap100m: effectiveCap, marketCapText, rankText: "市值 50-500億推估" };
  }
  return { key: "micro", label: "微型股", searchLabel: "微型股", tone: "micro", sortScore: effectiveCap, marketCap100m: effectiveCap, marketCapText, rankText: "市值 < 50億" };
}

function stockScaleBadgeHtml(stock) {
  const scale = stockScaleInfo(stock);
  const titleParts = [scale.marketCapText, scale.rankText, scale.sourceDate].filter(Boolean);
  return `<span class="stock-scale-pill ${escapeHtml(scale.tone || scale.key)}" title="${escapeHtml(titleParts.join(" / "))}">${escapeHtml(scale.label)}</span>`;
}

function valuationPeriodLabel(valuation) {
  if (!valuation) return "-";
  const report = valuation.reportPeriod || "";
  const dividend = valuation.dividendYear ? `股利${valuation.dividendYear}` : "";
  return [report, dividend].filter(Boolean).join(" / ") || "-";
}

function derivedTrailingEps(valuation) {
  if (!valuation || valuation.close === null || valuation.pe === null || valuation.pe <= 0) return null;
  return valuation.close / valuation.pe;
}

function marketLabelFromSuffix(suffix) {
  return suffix === "TWO" ? "上櫃" : "上市";
}

function valuationRefreshSummaryText(summary) {
  if (!summary || !Array.isArray(summary.results) || !summary.results.length) return "";
  return summary.results
    .map((result) => `${marketLabelFromSuffix(result.market)} ${result.sourceDate || "最新資料"}`)
    .join(" / ");
}

function parseBuyRange(value) {
  const match = String(value || "").match(/(\d+(?:\.\d+)?)\s*[-~～]\s*(\d+(?:\.\d+)?)/);
  if (!match) return null;
  return {
    low: Number(match[1]),
    high: Number(match[2])
  };
}

function buyRangeStatus(stock, price) {
  const range = parseBuyRange(stock.buy);
  const number = toNumber(price);
  if (!range || number === null) return { label: stock.buy || "未設定", distance: Number.POSITIVE_INFINITY };
  if (number >= range.low && number <= range.high) {
    return { label: "買點區間內", distance: 0 };
  }
  if (number < range.low) {
    return { label: `低於買點 ${formatPct((number - range.low) / range.low * 100)}`, distance: Math.abs((number - range.low) / range.low * 100) };
  }
  return { label: `高於買點 ${formatPct((number - range.high) / range.high * 100)}`, distance: Math.abs((number - range.high) / range.high * 100) };
}

function midpoint(low, high) {
  const a = toNumber(low);
  const b = toNumber(high);
  if (a === null && b === null) return null;
  if (a === null) return b;
  if (b === null) return a;
  return (a + b) / 2;
}

function priceGapPct(base, target) {
  const b = toNumber(base);
  const t = toNumber(target);
  if (b === null || t === null || Math.abs(b) < 1e-9) return null;
  return (t - b) / b * 100;
}

function setupToneClass(score) {
  if (score >= 8) return "up";
  if (score >= 6) return "flat";
  return "down";
}

function setupGrade(score) {
  if (score >= 8) return "A";
  if (score >= 6) return "B";
  if (score >= 4) return "C";
  return "D";
}

function buildTradePlan(stock, technical, price, quote, rsMulti, rev) {
  const currentPrice = toNumber(price);
  const buyRange = parseBuyRange(stock.buy);
  const buyStatus = buyRangeStatus(stock, currentPrice);
  const playbook = technical && technical.ready ? technical.playbook : null;
  const levels = playbook?.levels || null;
  const technicalEntry = levels?.primaryEntry || null;
  const chipSignal = stockChipSignal(stock.code);
  const manualStop = toNumber(stock.stop);
  const manualTarget = toNumber(stock.target);
  const year252 = technical && technical.ready ? technical.rows.slice(-252) : [];
  const high52w = year252.length ? Math.max(...year252.map((row) => row.high)) : null;
  const breakoutTrigger = technical && technical.ready ? (technical.previous?.high ?? technical.resistance ?? null) : null;

  let entryLow = technicalEntry?.low ?? (technicalEntry?.trigger ?? null);
  let entryHigh = technicalEntry?.high ?? (technicalEntry?.trigger ?? null);
  let entrySource = technicalEntry ? `${technicalEntry.label}：${technicalEntry.source}` : "";
  let entryConfirmation = technicalEntry?.confirmation || "";

  if (!technicalEntry && buyRange) {
    entryLow = buyRange.low;
    entryHigh = buyRange.high;
    entrySource = "研究買點";
  }

  if (!technicalEntry && !buyRange && technical && technical.ready) {
    if (playbook?.positionLabel === "盤整突破候選") {
      entryLow = breakoutTrigger;
      entryHigh = breakoutTrigger;
      entrySource = "前高突破";
      entryConfirmation = "收盤站上且量價配合";
    } else if (playbook?.trendLabel === "多頭趨勢" && technical.ma10 !== null && technical.ma20 !== null) {
      entryLow = Math.min(technical.ma10, technical.ma20);
      entryHigh = Math.max(technical.ma10, technical.ma20);
      entrySource = "MA10~MA20 回測";
      entryConfirmation = "收盤不破操作線";
    } else if (technical.ma20 !== null) {
      entryLow = technical.ma20;
      entryHigh = technical.ma10 ?? technical.ma20;
      entrySource = "均線回測";
      entryConfirmation = "收盤確認";
    }
  }

  let stopPrice = levels?.stop?.price ?? manualStop;
  let stopSource = levels?.stop ? levels.stop.source : (manualStop !== null ? "研究停損" : "");
  if (stopPrice === null && technical && technical.ready) {
    if (technical.support !== null) {
      stopPrice = +(technical.support * 0.985).toFixed(2);
      stopSource = "20日支撐下 1.5%";
    } else if (technical.ma20 !== null) {
      stopPrice = +(technical.ma20 * 0.985).toFixed(2);
      stopSource = "MA20 下 1.5%";
    }
  }

  let targetPrice = levels?.target1?.price ?? manualTarget;
  let targetSource = levels?.target1 ? levels.target1.source : (manualTarget !== null ? "研究目標" : "");
  if (targetPrice === null && technical && technical.ready) {
    if (technical.resistance !== null && currentPrice !== null && technical.resistance > currentPrice) {
      targetPrice = technical.resistance;
      targetSource = "20日壓力";
    } else if (high52w !== null && currentPrice !== null && high52w > currentPrice) {
      targetPrice = high52w;
      targetSource = "52W 高點";
    }
  }

  const plannedEntryRef = technicalEntry?.trigger ?? midpoint(entryLow, entryHigh);
  let entryRef = plannedEntryRef ?? currentPrice;
  const entryLower = Math.min(...[entryLow, entryHigh].map(toNumber).filter((value) => value !== null));
  const entryUpper = Math.max(...[entryLow, entryHigh].map(toNumber).filter((value) => value !== null));
  const hasEntryRange = Number.isFinite(entryLower) && Number.isFinite(entryUpper);
  if (hasEntryRange && currentPrice !== null && currentPrice >= entryLower * 0.995 && currentPrice <= entryUpper * 1.005) {
    entryRef = currentPrice;
  } else if (!technicalEntry && buyRange && currentPrice !== null && currentPrice < buyRange.low) {
    entryRef = buyRange.low;
  }

  const riskPct = stopPrice !== null && entryRef !== null && stopPrice < entryRef
    ? (entryRef - stopPrice) / entryRef * 100
    : null;
  const rewardPct = targetPrice !== null && entryRef !== null && targetPrice > entryRef
    ? (targetPrice - entryRef) / entryRef * 100
    : null;
  const rr = riskPct !== null && rewardPct !== null && riskPct > 0 ? rewardPct / riskPct : null;
  const riskPerShare = stopPrice !== null && entryRef !== null && entryRef > stopPrice
    ? entryRef - stopPrice
    : null;

  const volumeHot = ["攻擊量", "爆大量 / 換手候選"].includes(playbook?.volumeLabel);
  const weakVolume = ["高檔出貨疑慮", "下跌大量"].includes(playbook?.volumeLabel);
  const inBuyZone = hasEntryRange && currentPrice !== null
    ? currentPrice >= entryLower * 0.995 && currentPrice <= entryUpper * 1.005
    : buyStatus.distance === 0;
  const entryDistancePct = hasEntryRange && currentPrice !== null
    ? currentPrice > entryUpper
      ? (currentPrice - entryUpper) / entryUpper * 100
      : currentPrice < entryLower
        ? (currentPrice - entryLower) / entryLower * 100
        : 0
    : null;
  const aboveBuy = entryDistancePct !== null ? entryDistancePct > 0 : String(buyStatus.label || "").startsWith("高於買點");
  const aboveBuyFar = aboveBuy && (entryDistancePct !== null ? entryDistancePct > 6 : buyStatus.distance > 6);
  const belowBuy = entryDistancePct !== null ? entryDistancePct < 0 : String(buyStatus.label || "").startsWith("低於買點");

  let setupScore = 0;
  if (playbook?.trendLabel === "多頭趨勢") setupScore += 3;
  else if (playbook?.positionLabel === "盤整突破候選") setupScore += 2;
  else if (playbook?.trendLabel === "盤整趨勢") setupScore += 1;
  if (playbook) setupScore += Math.min(playbook.checklistPasses, 3);
  if (volumeHot) setupScore += 2;
  else if (weakVolume) setupScore -= 1;
  const rs21 = toNumber(rsMulti?.r21);
  const rs65 = toNumber(rsMulti?.r65);
  const revYoy = toNumber(rev?.yoyPct);
  if (rs21 !== null && rs21 > 0) setupScore += 1;
  if (rs65 !== null && rs65 > 0) setupScore += 1;
  if (revYoy !== null && revYoy > 20) setupScore += 1;
  else if (revYoy !== null && revYoy < 0) setupScore -= 1;
  if (inBuyZone) setupScore += 1;
  else if (aboveBuyFar) setupScore -= 1;
  if (chipSignal?.level === "danger") setupScore -= 2;
  else if (chipSignal?.level === "warn") setupScore -= 1;
  else if (chipSignal?.level === "good") setupScore += 1;
  setupScore = Math.max(0, Math.min(10, setupScore));

  let action = "先觀察";
  let actionNote = "條件尚未完全共振，先等價格與量價訊號再決定。";
  if (!technical || !technical.ready || !playbook) {
    action = "待更新日線";
    actionNote = "先補日線後再看趨勢、位置與量價。";
  } else if (playbook.trendLabel === "空頭趨勢" || playbook.positionLabel === "盤整跌破候選") {
    action = "先避開";
    actionNote = "目前不是做多主戰場，除非你是明確做反彈策略。";
  } else if (playbook.positionLabel === "回後買上漲 / 攻擊段" && volumeHot && !aboveBuyFar) {
    action = "可列攻擊清單";
    actionNote = "帶量轉強且未明顯脫離買點，適合列入當日優先追蹤。";
  } else if (inBuyZone && playbook.trendLabel === "多頭趨勢") {
    action = "可分批布局";
    actionNote = "結構仍偏多，且價格就在原設定買點帶附近。";
  } else if (playbook.positionLabel === "盤整突破候選") {
    action = "等突破確認";
    actionNote = "優先等前高或壓力位帶量突破，再決定是否追價。";
  } else if (aboveBuyFar || playbook.positionLabel === "多頭高檔 / 壓力前") {
    action = "等回檔，不追價";
    actionNote = "已脫離舒服買點或接近壓力，先等回測。";
  } else if (belowBuy && technicalEntry && technicalEntry.trigger !== null) {
    action = "等突破確認";
    actionNote = "還沒收盤站上講義價位，先等突破價與量價條件一起完成。";
  } else if (belowBuy) {
    action = "等重新站回買點帶";
    actionNote = "價格比原設定買點更低，不一定是便宜，先看是否轉強。";
  }

  const entryText = entryLow !== null && entryHigh !== null
    ? (Math.abs(entryHigh - entryLow) < 0.01 ? formatNumber(entryLow) : `${formatNumber(entryLow)} – ${formatNumber(entryHigh)}`)
    : "-";
  const entryHint = entrySource ? `${entryText} (${entrySource})` : entryText;
  const rrNote = rr === null
    ? "目標 / 停損未齊，無法估風報比"
    : rr >= 2
      ? "風報比尚可，值得等訊號完成"
      : rr >= 1
        ? "風報比普通，需靠勝率與紀律補強"
        : "風報比偏差，除非勝率極高，否則不宜硬做";
  const invalidation = stopPrice !== null
    ? `跌破 ${formatNumber(stopPrice)} 視為 setup 失效`
    : "尚未定義明確停損，先不要加大部位";
  const researchEntryText = buyRange
    ? (Math.abs(buyRange.high - buyRange.low) < 0.01 ? formatNumber(buyRange.low) : `${formatNumber(buyRange.low)} – ${formatNumber(buyRange.high)}`)
    : "-";

  return {
    grade: setupGrade(setupScore),
    setupScore,
    action,
    actionNote,
    entryLow,
    entryHigh,
    entryText,
    entryHint,
    entrySource,
    entryConfirmation,
    researchEntryText,
    entryRef,
    stopPrice,
    stopSource,
    targetPrice,
    targetSource,
    riskPct,
    rewardPct,
    rr,
    rrNote,
    riskPerShare,
    invalidation,
    inBuyZone,
    aboveBuyFar,
    volumeHot,
    weakVolume,
    levels
  };
}

function buildValuationPriceModel(stock, valuation, quote, technical, tradePlan, activeEtfSignal = null) {
  const price = quote?.price ?? latestValue(stock);
  const trailingEps = derivedTrailingEps(valuation);
  const eps26e = toNumber(stock.eps26e);
  const eps25 = toNumber(stock.eps25);
  const epsBase = eps26e ?? eps25 ?? trailingEps;
  const peOfficial = valuation ? toNumber(valuation.pe) : null;
  const peResearch = toNumber(stock.pe);
  const peBase = peOfficial ?? peResearch;
  const epsSource = eps26e !== null ? "研究欄位 EPS 2026E" : eps25 !== null ? "研究欄位 EPS 2025" : trailingEps !== null ? "交易所 PE 與收盤價回推近四季 EPS" : "";
  const peSource = peOfficial !== null ? "交易所 PE" : peResearch !== null ? "研究欄位 PE" : "";
  if (epsBase === null || epsBase <= 0 || peBase === null || peBase <= 0) {
    return {
      ready: false,
      reason: "缺 EPS 或 PE，無法建立估值情境",
      price,
      source: valuation ? "交易所估值資料不足，且研究欄位未補 EPS / PE" : "尚未更新交易所估值或研究欄位"
    };
  }
  const chipSignal = stockChipSignal(stock.code);
  const bearPe = Math.max(4, peBase * 0.75);
  const basePe = peBase;
  const bullPe = peBase * 1.25;
  const fairLow = epsBase * bearPe;
  const fairMid = epsBase * basePe;
  const fairHigh = epsBase * bullPe;
  const technicalEntry = midpoint(tradePlan?.entryLow, tradePlan?.entryHigh);
  const buyLow = fairMid * 0.85;
  const buyHighRaw = fairMid * 0.92;
  const buyHigh = technicalEntry !== null ? Math.min(buyHighRaw, technicalEntry * 1.03) : buyHighRaw;
  const sellLow = Math.max(fairMid * 1.08, fairHigh * 0.96);
  const sellHigh = fairHigh * 1.12;
  const warnings = [];
  if (peOfficial === null) warnings.push("PE 使用研究欄位，非交易所當日欄位");
  if (eps26e !== null || eps25 !== null) warnings.push("EPS 使用研究欄位，需回法說 / 財報交叉核對");
  if (trailingEps !== null && eps26e === null && eps25 === null) warnings.push("EPS 由交易所 PE 回推，只能當近四季粗估");
  if (chipSignal.level === "danger") warnings.push("籌碼偏弱，估值帶不應直接當買點");
  if (activeEtfSignal?.net7 !== null && activeEtfSignal?.net7 <= -1) warnings.push("主動式 ETF 近 7 日有減碼 / 移除訊號");
  let action = "等待資料補齊";
  let tone = "flat";
  if (price !== null) {
    if (price <= buyHigh && chipSignal.level !== "danger") {
      action = "進入情境買進帶；仍需技術、籌碼與來源確認";
      tone = "up";
    } else if (price >= sellLow) {
      action = "接近情境減碼帶；優先檢查成長假設是否仍成立";
      tone = "down";
    } else if (chipSignal.level === "danger") {
      action = "估值中性但籌碼偏弱，先等止跌與法人回補";
      tone = "down";
    } else {
      action = "估值在中性區，依技術、籌碼與營收等待";
    }
  }
  const confidence = [
    peOfficial !== null ? 1 : 0,
    epsBase !== null ? 1 : 0,
    quote && quoteFreshnessInfo(quote).level !== "stale" ? 1 : 0,
    technical?.ready ? 1 : 0,
    chipSignal.level !== "neutral" ? 1 : 0
  ].reduce((sum, value) => sum + value, 0);
  return {
    ready: true,
    price,
    epsBase,
    epsSource,
    peBase,
    peSource,
    bearPe,
    basePe,
    bullPe,
    fairLow,
    fairMid,
    fairHigh,
    buyLow,
    buyHigh,
    sellLow,
    sellHigh,
    action,
    tone,
    chipSignal,
    confidence,
    warnings,
    source: `${epsSource || "EPS缺值"} × ${peSource || "PE缺值"}；低 / 中 / 高情境 = PE × 0.75 / 1.00 / 1.25；買進帶 = 中性價 × 0.85–0.92，若技術入場帶存在則上緣不高於技術入場 +3%`,
    method: "情境估值只用 EPS × PE，不再用籌碼或 ETF 賣壓任意調整合理 PE；籌碼只列為風險警示與信心分。"
  };
}

function renderValuationInferenceCard(model) {
  if (!model.ready) {
    return `
      <div class="report-card">
        <h3>估值情境 / 進出價</h3>
        <div class="empty" style="margin-top:8px;">${escapeHtml(model.reason || "資料不足")}</div>
        <div class="kv-row"><span>來源</span><strong style="font-size:0.78rem;">${escapeHtml(model.source || "-")}</strong></div>
      </div>
    `;
  }
  return `
    <div class="report-card">
      <h3>估值情境 / 進出價</h3>
      <div class="kv-row"><span>低 / 中 / 高</span><strong>${formatNumber(model.fairLow)} / ${formatNumber(model.fairMid)} / ${formatNumber(model.fairHigh)}</strong></div>
      <div class="kv-row"><span>買進帶</span><strong class="up">${formatNumber(model.buyLow)} – ${formatNumber(model.buyHigh)}</strong></div>
      <div class="kv-row"><span>賣出/減碼帶</span><strong class="down">${formatNumber(model.sellLow)} – ${formatNumber(model.sellHigh)}</strong></div>
      <div class="kv-row"><span>EPS / PE</span><strong>${formatNumber(model.epsBase)} / ${formatNumber(model.peBase)}</strong></div>
      <div class="kv-row"><span>情境 PE</span><strong>${formatNumber(model.bearPe)} / ${formatNumber(model.basePe)} / ${formatNumber(model.bullPe)}</strong></div>
      <div class="kv-row"><span>推論</span><strong class="${model.tone}" style="font-size:0.8rem;">${escapeHtml(model.action)}</strong></div>
      <div class="kv-row"><span>可信度</span><strong>${model.confidence}/5</strong></div>
      <div class="kv-row"><span>來源</span><strong style="font-size:0.74rem;color:var(--muted);">${escapeHtml(model.source)}</strong></div>
      <div class="kv-row"><span>方法</span><strong style="font-size:0.74rem;color:var(--muted);">${escapeHtml(model.method)}</strong></div>
      ${model.warnings?.length ? `<div class="note-box" style="margin-top:8px;font-size:0.76rem;color:var(--muted);">待複核：${model.warnings.map(escapeHtml).join("；")}</div>` : ""}
    </div>
  `;
}

function dividendFor(code) {
  return normalizeDividendState(state.dividends).records?.[code] || null;
}

function formatTwdAmount(value) {
  const number = toNumber(value);
  if (number === null) return "-";
  const abs = Math.abs(number);
  if (abs >= 100000000) return `${formatNumber(number / 100000000, 2)} 億`;
  if (abs >= 1000000) return `${formatNumber(number / 1000000, 1)} 百萬`;
  return `${formatNumber(number, 0)} 元`;
}

function renderDividendHistoryPanel(stock, valuation) {
  const record = dividendFor(stock.code);
  const latest = record?.latest || null;
  const history = Array.isArray(record?.history) ? record.history.slice(0, 5) : [];
  const sourceFresh = state.dividends?.fetchedAt ? `MOPS 最後更新 ${formatDateTime(state.dividends.fetchedAt)}` : "尚未更新 MOPS 股利";
  const yahooDividendUrl = yahooQuotePath(stock, "dividend");

  // 用交易所估值做 fallback（t187ap45 只有本年度「已決議」的分派案，很多公司尚未召開董事會）
  const valDivPerShare = valuation?.dividendPerShare ?? null;
  const valDivYear = valuation?.dividendYear || "";
  const trailingEps = (() => {
    const pe = valuation?.pe;
    const close = valuation?.close ?? latestValue(stock);
    if (pe && pe > 0 && close) return +(close / pe).toFixed(2);
    return null;
  })();

  const mopsNote = latest
    ? `MOPS 最新分派案（${escapeHtml(latest.dividendYear || latest.period || "-")}）`
    : `t187ap45 本年度尚無決議記錄 → 以交易所估值（上年度股利）補充`;

  return `
    <div class="report-card">
      <h3>配股配息 / 盈餘</h3>

      ${latest ? `
        <div class="kv-row"><span>股利年度</span><strong>${escapeHtml(latest.dividendYear || latest.period || "-")}</strong></div>
        <div class="kv-row"><span>本期淨利</span><strong>${formatTwdAmount(latest.netIncome)}</strong></div>
        <div class="kv-row"><span>現金股利</span><strong class="up">${formatNumber(latest.cashDividend)} 元/股</strong></div>
        <div class="kv-row"><span>股票股利</span><strong>${formatNumber(latest.stockDividend)} 元/股</strong></div>
        <div class="kv-row"><span>董事會</span><strong>${escapeHtml(latest.boardDate || "-")}</strong></div>
        <div class="kv-row"><span>股東會</span><strong>${escapeHtml(latest.shareholderMeetingDate || "-")}</strong></div>
        <div class="kv-row"><span>決議狀態</span><strong>${escapeHtml(latest.status || "-")}</strong></div>
      ` : `
        <div class="note-box" style="margin:6px 0;font-size:0.78rem;">
          MOPS t187ap45 本年度尚無決議記錄（多數公司 Q2/Q3 才召開董事會）。<br>
          下方顯示交易所上年度股利資料作為參考。
        </div>
      `}

      ${!latest && valDivPerShare !== null ? `
        <div class="kv-row"><span>現金股利（上年度）</span><strong class="up">${formatNumber(valDivPerShare)} 元/股 <span style="font-size:0.72rem;color:var(--muted);">交易所</span></strong></div>
        ${valDivYear ? `<div class="kv-row"><span>股利年度</span><strong>${escapeHtml(valDivYear)}</strong></div>` : ""}
      ` : ""}
      ${valuation?.dividendYield ? `<div class="kv-row"><span>殖利率（交易所）</span><strong class="${valuation.dividendYield >= 5 ? "up" : ""}">${formatPercentMetric(valuation.dividendYield)}</strong></div>` : ""}
      ${trailingEps !== null ? `<div class="kv-row"><span>回推近四季 EPS</span><strong title="= 收盤 ÷ PE，為估算值">${formatNumber(trailingEps)} 元<span style="font-size:0.7rem;color:var(--muted);">（回推）</span></strong></div>` : ""}

      <div class="kv-row"><span>資料</span><strong style="font-size:0.76rem;">${escapeHtml(mopsNote)}</strong></div>

      ${history.length ? `
        <div class="table-wrap" style="margin-top:10px;">
          <table style="min-width:480px;">
            <thead><tr><th>年度</th><th class="num">現金(元)</th><th class="num">股票(元)</th><th class="num">本期淨利</th><th>狀態</th></tr></thead>
            <tbody>
              ${history.map((row) => `
                <tr>
                  <td>${escapeHtml(row.dividendYear || row.period || "-")}</td>
                  <td class="num ${row.cashDividend > 0 ? "up" : ""}">${formatNumber(row.cashDividend)}</td>
                  <td class="num">${formatNumber(row.stockDividend)}</td>
                  <td class="num">${formatTwdAmount(row.netIncome)}</td>
                  <td style="font-size:0.76rem;">${escapeHtml(row.status || "-")}</td>
                </tr>
              `).join("")}
            </tbody>
          </table>
        </div>
      ` : ""}
      ${(() => {
        const yahooDivs = (state.customResearch?.[stock.code]?.yahooDividends || []).slice(-10).reverse();
        const yahooEps = state.customResearch?.[stock.code]?.yahooEps;
        const epsRows = [...(yahooEps?.quarterly || []), ...(yahooEps?.annual || [])]
          .filter((r, i, arr) => arr.findIndex((x) => x.endDate === r.endDate) === i)
          .sort((a, b) => b.endDate.localeCompare(a.endDate)).slice(0, 8);
        if (!yahooDivs.length && !epsRows.length) return "";
        return `
          <div style="margin-top:10px;">
            ${yahooDivs.length ? `
            <div class="table-wrap" style="margin-bottom:8px;">
              <div style="font-size:0.78rem;font-weight:700;margin-bottom:4px;">Yahoo Finance 歷史配息（近${yahooDivs.length}筆）</div>
              <table style="min-width:280px;">
                <thead><tr><th>除息日</th><th class="num">配息（元）</th></tr></thead>
                <tbody>${yahooDivs.map((r) => `<tr><td>${escapeHtml(r.date)}</td><td class="num up">${formatNumber(r.amount, 3)}</td></tr>`).join("")}</tbody>
              </table>
            </div>` : ""}
            ${epsRows.length ? `
            <div class="table-wrap">
              <div style="font-size:0.78rem;font-weight:700;margin-bottom:4px;">Yahoo Finance 財報（淨利）</div>
              <table style="min-width:280px;">
                <thead><tr><th>期間</th><th class="num">淨利（元）</th></tr></thead>
                <tbody>${epsRows.map((r) => `<tr><td>${escapeHtml(r.endDate)}</td><td class="num ${changeClass(r.netIncome)}">${formatTwdAmount(r.netIncome)}</td></tr>`).join("")}</tbody>
              </table>
            </div>` : ""}
          </div>`;
      })()}
      <div class="link-row" style="margin-top:10px;">
        <button id="yahooEnrichBtn" class="ghost-btn" type="button" style="font-size:0.8rem;min-height:28px;" data-enrich-code="${escapeHtml(stock.code)}">從 Yahoo 補充配息/財報</button>
        <a class="link-chip" href="${escapeHtml(latest?.sourceUrl || (stock.suffix === "TWO" ? DIVIDEND_SOURCE_LINKS.otc : DIVIDEND_SOURCE_LINKS.listed))}" target="_blank" rel="noopener">MOPS 股利 CSV</a>
        <a class="link-chip" href="${escapeHtml(stock.suffix === "TWO" ? DIVIDEND_SOURCE_LINKS.tpexExDividend : DIVIDEND_SOURCE_LINKS.twseExDividend)}" target="_blank" rel="noopener">除權息公告</a>
        <a class="link-chip" href="${escapeHtml(yahooDividendUrl)}" target="_blank" rel="noopener">Yahoo 歷年股利</a>
        <a class="link-chip" href="${escapeHtml(`https://goodinfo.tw/tw/StockDividend.asp?STOCK_ID=${stock.code}`)}" target="_blank" rel="noopener">Goodinfo 五年股利</a>
        <a class="link-chip" href="${escapeHtml(`https://statementdog.com/analysis/${stock.code}`)}" target="_blank" rel="noopener">財報狗 EPS 趨勢</a>
      </div>
      <div class="note-box" style="margin-top:6px;font-size:0.76rem;color:var(--muted);">
        MOPS t187ap45 只含本年度已決議分派案，大多數公司在 Q2–Q3 召開股東會後才出現。歷史股利由每次按「股利」更新後累積（最多 5 筆）。
      </div>
    </div>
  `;
}

function renderResearchDataQualityCard(stock, quote, valuation, rev, technical, activeEtfSignal) {
  const quoteInfo = quoteFreshnessInfo(quote);
  const instRows = normalizeInstitutionalHistoryRows((state.institutional || {})[stock.code]?.history || []);
  const inst7 = institutionalWindowSummary(instRows, 7);
  const inst14 = institutionalWindowSummary(instRows, 14);
  const inst30 = institutionalWindowSummary(instRows, 30);
  const dividend = dividendFor(stock.code);
  const valuationSource = valuation?.sourceLabel || (valuation ? "交易所估值" : "待更新");
  return `
    <div class="report-card">
      <h3>資料品質 / 來源</h3>
      <div class="kv-row"><span>報價</span><strong class="${quoteInfo.level === "fresh" ? "up" : quoteInfo.level === "stale" ? "down" : "flat"}">${escapeHtml(quoteInfo.label)}</strong></div>
      <div class="kv-row"><span>估值</span><strong style="font-size:0.78rem;">${escapeHtml(valuationSource)} ${valuation?.sourceDate ? `(${escapeHtml(valuation.sourceDate)})` : ""}</strong></div>
      <div class="kv-row"><span>月營收</span><strong>${rev ? `${escapeHtml(rev.yearMonth || "-")} YoY ${formatSignedMetric(rev.yoyPct, 1, "%")}` : "待更新"}</strong></div>
      <div class="kv-row"><span>三大法人</span><strong>${inst7.availableDays}/7；${inst14.isComplete ? "14日OK" : `14日不足${inst14.availableDays}/14`}；${inst30.isComplete ? "30日OK" : `30日不足${inst30.availableDays}/30`}</strong></div>
      <div class="kv-row"><span>日線</span><strong>${technical?.ready ? `${escapeHtml(technical.latest.date)} / ${escapeHtml(technical.source || "")}` : "待更新"}</strong></div>
      <div class="kv-row"><span>ETF 訊號</span><strong style="font-size:0.78rem;">${escapeHtml(activeEtfSignal?.detail || activeEtfSignal?.label || "尚無")}</strong></div>
      <div class="kv-row"><span>股利</span><strong>${dividend?.latest ? `${escapeHtml(dividend.latest.distributionYear || "-")} ${formatNumber(dividend.latest.cashDividend)}` : "待更新或待累積"}</strong></div>
    </div>
  `;
}

function renderResearchMethodCard(stock, valuationModel, rev, rsMulti, betaVal, volInfo) {
  const gaps = [];
  if (!valuationModel.ready) gaps.push("估值缺 EPS / PE");
  if (!rev) gaps.push("月營收待更新");
  if (rsMulti.r65 === null) gaps.push("RS 需大盤與個股日線");
  if (betaVal === null) gaps.push("Beta 需 60 日日報酬");
  if (!volInfo) gaps.push("量能 Z-score 需 21 根以上日線");
  return `
    <div class="report-card">
      <h3>研究方法 / 缺口</h3>
      <div class="kv-row"><span>估值公式</span><strong style="font-size:0.76rem;">EPS × PE；低/中/高 = PE × 0.75/1.00/1.25</strong></div>
      <div class="kv-row"><span>買進帶</span><strong style="font-size:0.76rem;">中性價 × 0.85–0.92，並受技術入場上緣限制</strong></div>
      <div class="kv-row"><span>相對強弱</span><strong style="font-size:0.76rem;">個股報酬 - TAIEX 報酬，單位為百分點</strong></div>
      <div class="kv-row"><span>Beta</span><strong style="font-size:0.76rem;">60 日日報酬對 TAIEX 報酬的線性敏感度</strong></div>
      <div class="kv-row"><span>缺口</span><strong style="font-size:0.76rem;">${escapeHtml(gaps.join("；") || "核心資料已可計算")}</strong></div>
      <div class="link-row" style="margin-top:10px;">
        <a class="link-chip" href="${escapeHtml(`https://goodinfo.tw/tw/StockFinDetail.asp?RPT_CAT=IS&STOCK_ID=${stock.code}`)}" target="_blank" rel="noopener">損益表核對</a>
        <a class="link-chip" href="${escapeHtml(`https://goodinfo.tw/tw/StockBzPerformance.asp?STOCK_ID=${stock.code}`)}" target="_blank" rel="noopener">月營收核對</a>
        <a class="link-chip" href="${escapeHtml(`https://goodinfo.tw/tw/StockDividend.asp?STOCK_ID=${stock.code}`)}" target="_blank" rel="noopener">股利核對</a>
      </div>
    </div>
  `;
}

function buildAnalystLens(stock, valuation, rev, rsMulti) {
  const notes = [];
  let score = 0;
  const pe = valuation ? toNumber(valuation.pe) : null;
  const researchPe = toNumber(stock.pe);
  const dividendYield = valuation ? valuation.dividendYield : null;

  if ((stock.theme ?? 0) >= 80) {
    score += 2;
    notes.push(`主題純度 ${stock.theme}%`);
  } else if ((stock.theme ?? 0) >= 60) {
    score += 1;
    notes.push(`主題純度 ${stock.theme}%`);
  }

  if ((stock.overlap ?? 0) >= 80) {
    score += 2;
    notes.push(`重疊度 ${stock.overlap}%`);
  } else if ((stock.overlap ?? 0) >= 60) {
    score += 1;
    notes.push(`重疊度 ${stock.overlap}%`);
  }

  const revYoy = toNumber(rev?.yoyPct);
  const rs65 = toNumber(rsMulti?.r65);
  if (revYoy !== null) {
    if (revYoy > 20) score += 2;
    else if (revYoy > 0) score += 1;
    notes.push(`月營收 YoY ${formatSignedMetric(revYoy, 1, "%")}`);
  }

  if (rs65 !== null) {
    if (rs65 > 0) score += 1;
    notes.push(`3M RS ${formatSignedMetric(rs65, 1, "pp")}`);
  }

  if (pe !== null && pe > 0 && pe <= 20) score += 1;
  if (pe !== null) notes.push(`交易所 PE ${formatNumber(pe)}`);
  else if (researchPe !== null) notes.push(`研究 PE ${formatNumber(researchPe)}（待核對）`);
  if (dividendYield !== null && dividendYield >= 4) notes.push(`殖利率 ${formatPercentMetric(dividendYield)}`);

  const stance = score >= 6
    ? "研究敘事與價格動能相對同向"
    : score >= 4
      ? "研究邏輯可追，但仍需價格驗證"
      : "題材存在，但基本面與價格證據仍不夠齊";

  return {
    score,
    stance,
    notes: notes.slice(0, 5)
  };
}

function radarToneClass(score) {
  if (score >= 75) return "up";
  if (score >= 55) return "flat";
  return "down";
}

function normalizeTradingRadarMode(value) {
  const key = String(value || "").trim();
  return Object.prototype.hasOwnProperty.call(TRADING_RADAR_MODES, key) ? key : DEFAULT_TRADING_RADAR_MODE;
}

function tradingRadarModeConfig(value = state.tradingRadarMode) {
  return TRADING_RADAR_MODES[normalizeTradingRadarMode(value)];
}

function tradingRadarModeButtonsHtml() {
  const activeKey = normalizeTradingRadarMode(state.tradingRadarMode);
  return Object.values(TRADING_RADAR_MODES).map((mode) => `
    <button class="radar-mode-btn${mode.key === activeKey ? " active" : ""}" type="button" data-radar-mode="${escapeHtml(mode.key)}">
      ${escapeHtml(mode.label)}
    </button>
  `).join("");
}

function weightedRadarValue(weight, rating) {
  return (toNumber(weight) || 0) * clamp(toNumber(rating) || 0, -1, 1);
}

function valuationRadarRating(stock, valuation) {
  const pe = effectivePe(stock);
  const dividendYield = valuation ? toNumber(valuation.dividendYield) : null;
  const pbr = valuation ? toNumber(valuation.pbr) : null;
  let rating = 0;
  const notes = [];

  if (pe !== null && pe > 0) {
    if (pe <= 15) rating += 0.35;
    else if (pe <= 22) rating += 0.22;
    else if (pe <= 35) rating += 0.08;
    else if (pe >= 60) rating -= 0.25;
  }
  if (dividendYield !== null) {
    if (dividendYield >= 5) rating += 0.35;
    else if (dividendYield >= 3) rating += 0.22;
    else if (dividendYield < 1) rating -= 0.08;
  }
  if (pbr !== null && pbr > 0) {
    if (pbr <= 1.5) rating += 0.2;
    else if (pbr <= 2.5) rating += 0.1;
    else if (pbr >= 6) rating -= 0.18;
  }

  if (rating >= 0.45) notes.push("估值 / 殖利率有支撐");
  else if (rating <= -0.2) notes.push("估值偏貴");

  return { rating: clamp(rating, -0.5, 1), notes };
}

function stockScaleRadarAdjustment(scale, modeKey) {
  const key = scale?.key || "pending";
  if (modeKey === "defensive") {
    if (key === "large") return { value: 4, note: "大型股適合防守模式" };
    if (key === "mid") return { value: 2, note: "中型股防守模式小幅加分" };
    if (key === "small") return { value: -6, note: "小型股防守模式降權" };
    if (key === "micro") return { value: -10, note: "小型以下不適合防守主倉" };
  }
  if (modeKey === "swing") {
    if (key === "mid") return { value: 3, note: "中型股適合波段主攻" };
    if (key === "large") return { value: 1, note: "大型股波段穩定度較高" };
    if (key === "small") return { value: 1, note: "小型股波段需控倉" };
    if (key === "micro") return { value: -4, note: "小型以下波動風險較高" };
  }
  if (modeKey === "attack") {
    if (key === "small") return { value: 2, note: "小型股攻擊性較高但需控倉" };
    if (key === "mid") return { value: 1, note: "中型股攻擊 / 流動性較均衡" };
    if (key === "large") return { value: -1, note: "大型股短線彈性通常較低" };
    if (key === "micro") return { value: -2, note: "小型以下流動性風險較高" };
  }
  return { value: 0, note: "" };
}

function buildTradingRadarScore(row) {
  const stock = row?.stock || {};
  const mode = tradingRadarModeConfig(row?.mode);
  const weights = mode.weights || TRADING_RADAR_MODES[DEFAULT_TRADING_RADAR_MODE].weights;
  const penalties = mode.penalties || TRADING_RADAR_MODES[DEFAULT_TRADING_RADAR_MODE].penalties;
  const technical = row?.technical || null;
  const tradePlan = row?.tradePlan || null;
  const total = toNumber(row?.total);
  const rsMulti = row?.rsMulti || null;
  const beta = toNumber(row?.beta);
  const vol = row?.vol || null;
  const rev = row?.rev || null;
  const quote = row?.quote || null;
  const valuation = row?.valuation || valuationFor(stock.code);
  const analystLens = row?.analystLens || null;
  const chipSignal = stockChipSignal(stock.code);
  const activeEtfSignal = row?.activeEtfSignal || activeEtfStockSignal(stock.code);
  const dispositionRisk = row?.dispositionRisk || dispositionRiskSignal(stock.code, { vol, quote });
  const scale = row?.scale || stockScaleInfo(stock);
  const notes = [];
  const scoreParts = [];

  let score = 0;
  function addPart(label, weight, rating, note) {
    const value = weightedRadarValue(weight, rating);
    score += value;
    scoreParts.push({ label, value });
    if (note && Math.abs(value) >= 1.5) notes.push(note);
    return value;
  }
  function addPenalty(amount, note) {
    const value = toNumber(amount) || 0;
    if (!value) return;
    score -= value;
    scoreParts.push({ label: note, value: -value });
    notes.push(note);
  }

  const setupScore = toNumber(tradePlan?.setupScore);
  if (setupScore !== null) addPart("Setup", weights.setup, setupScore / 10);

  if (total !== null) addPart("綜合分", weights.composite, total / 14);

  const rr = toNumber(tradePlan?.rr);
  if (rr !== null) {
    if (rr >= 2) {
      addPart("R:R", weights.rr, 1, `R:R ${rr.toFixed(2)}R`);
    } else if (rr >= 1.5) {
      addPart("R:R", weights.rr, 0.75, `R:R ${rr.toFixed(2)}R`);
    } else if (rr >= 1) {
      addPart("R:R", weights.rr, 0.4, `R:R ${rr.toFixed(2)}R`);
    } else {
      addPart("R:R", weights.rr, -0.35, `R:R ${rr.toFixed(2)}R 偏低`);
      addPenalty(penalties.rrLow, `R:R ${rr.toFixed(2)}R 偏低`);
      notes.push(`R:R ${rr.toFixed(2)}R 偏低`);
    }
  }

  const rs21 = toNumber(rsMulti?.r21);
  const rs65 = toNumber(rsMulti?.r65);
  if (rs21 !== null || rs65 !== null) {
    if ((rs21 ?? -999) > 0 && (rs65 ?? -999) > 0) {
      addPart("RS", weights.rs, 1, "1M / 3M RS 同向轉強");
    } else if ((rs21 ?? -999) > 0 || (rs65 ?? -999) > 0) {
      addPart("RS", weights.rs, 0.5, "RS 部分轉強");
    } else {
      addPart("RS", weights.rs, -0.4, "RS 落後大盤");
    }
  }

  const revYoy = toNumber(rev?.yoyPct);
  if (revYoy !== null) {
    if (revYoy > 20) addPart("月營收", weights.revenue, 1, `月營收 YoY ${formatSignedMetric(revYoy, 1, "%")}`);
    else if (revYoy > 5) addPart("月營收", weights.revenue, 0.62, `月營收 YoY ${formatSignedMetric(revYoy, 1, "%")}`);
    else if (revYoy > 0) addPart("月營收", weights.revenue, 0.25, `月營收 YoY ${formatSignedMetric(revYoy, 1, "%")}`);
    else addPart("月營收", weights.revenue, -0.45, `月營收 YoY ${formatSignedMetric(revYoy, 1, "%")}`);
  }

  const chipScore = toNumber(chipSignal?.score);
  if (chipScore !== null && chipScore !== 0) {
    addPart("籌碼", weights.chip, chipScore / 2, `籌碼 ${chipSignal.text}`);
  }

  if (activeEtfSignal?.hasData) {
    const etfScore = toNumber(activeEtfSignal.score) || 0;
    addPart("ETF", weights.etf, etfScore >= 0 ? etfScore / 6 : etfScore / 2, `ETF ${activeEtfSignal.label}`);
  }

  if (vol) {
    if (vol.zScore > 2 && vol.bullish) addPart("量能", weights.volume, 1, "攻擊量放大");
    else if (vol.zScore > 1 && vol.bullish) addPart("量能", weights.volume, 0.55, "量能轉強");
    else if (vol.zScore > 1 && !vol.bullish) addPart("量能", weights.volume, -0.7, "下跌量放大");
  }

  if (analystLens?.score !== null && analystLens?.score !== undefined) {
    addPart("研究", weights.analyst, clamp(toNumber(analystLens.score) / 8, 0, 1));
  }

  const valuationScore = valuationRadarRating(stock, valuation);
  addPart("估值", weights.valuation, valuationScore.rating, valuationScore.notes[0]);

  const scaleAdjustment = stockScaleRadarAdjustment(scale, mode.key);
  if (scaleAdjustment.value) {
    score += scaleAdjustment.value;
    scoreParts.push({ label: "市值級距", value: scaleAdjustment.value });
    if (scaleAdjustment.note) notes.push(scaleAdjustment.note);
  }

  if (!technical || !technical.ready) {
    addPenalty(penalties.noTechnical, "日線待更新");
  }
  if (tradePlan?.action === "先避開") {
    addPenalty(penalties.avoid, "結構不在做多主場");
  }
  if (tradePlan?.aboveBuyFar) {
    addPenalty(penalties.aboveBuy, "離買點過遠");
  }
  if (beta !== null && beta > 1.8) {
    addPenalty(penalties.betaHigh, `Beta ${beta.toFixed(2)} 偏高`);
  }
  if (quote?.pct !== null && quote?.pct !== undefined && quote.pct > 7) {
    addPenalty(penalties.chase, "單日漲幅過大，避免追高");
  }
  // 流動性扣分（v5.3 新增）：避免雷達分高但實際買不到 / 賣不掉
  // 日均 < 100 張：過小流動性，扣 8 分；日均 100-500 張：小型流動性，扣 4 分
  const liquidity = stockLiquidityInfo(stock.code);
  if (liquidity.tier === "micro") {
    addPenalty(8, `流動性過小（日均 ${liquidity.avgVolume != null ? Math.round(liquidity.avgVolume) : "?"} 張，建議避開）`);
  } else if (liquidity.tier === "small") {
    addPenalty(4, `流動性偏低（日均 ${liquidity.avgVolume != null ? Math.round(liquidity.avgVolume) : "?"} 張，需控倉）`);
  }
  if (dispositionRisk?.available) {
    if (dispositionRisk.level === "active") {
      addPenalty(30, "官方處置中，短線流動性與交易限制風險高");
    } else if (dispositionRisk.level === "officialCumulative") {
      addPenalty(24, "官方注意累計異常：次日再注意可能處置");
    } else if (dispositionRisk.level === "attention") {
      addPenalty(10, "今日公告注意交易，留意處置風險");
    } else if (dispositionRisk.level === "proxyHigh") {
      addPenalty(8, "量價處置 proxy 偏高，需回官方注意資訊複核");
    }
  }

  score = clamp(Math.round(score), 0, 100);
  const thresholds = mode.thresholds || TRADING_RADAR_MODES[DEFAULT_TRADING_RADAR_MODE].thresholds;

  let stage = "觀察";
  if (!technical || !technical.ready) stage = "資料待補";
  else if (dispositionRisk?.level === "active" || dispositionRisk?.level === "officialCumulative" || tradePlan?.action === "先避開" || score < thresholds.avoid) stage = "先避開";
  else if (tradePlan?.aboveBuyFar || (rr !== null && rr < 1)) stage = "等回測";
  else if (score >= thresholds.attack && (rr === null || rr >= 1.2)) stage = "攻擊觀察";
  else if (score >= thresholds.candidate) stage = "候選追蹤";

  return {
    score,
    stage,
    modeKey: mode.key,
    modeLabel: mode.label,
    level: radarToneClass(score),
    notes: [...new Set(notes)].slice(0, 5),
    scoreParts,
    activeEtfSignal,
    dispositionRisk
  };
}

function executionToneClass(status) {
  if (status === "可執行") return "up";
  if (["等回測", "等突破", "觀察"].includes(status)) return "flat";
  return "down";
}

function executionSortScore(status) {
  if (status === "可執行") return 6;
  if (status === "等回測") return 5;
  if (status === "等突破") return 4;
  if (status === "觀察") return 3;
  if (status === "風報比不足") return 2;
  if (status === "資料不足") return 1;
  return 0;
}

function buildExecutionInfo(stock, tradePlan, radar, technical, quote) {
  const mode = tradingRadarModeConfig(radar?.modeKey);
  const thresholds = mode.thresholds || TRADING_RADAR_MODES[DEFAULT_TRADING_RADAR_MODE].thresholds;
  const rr = toNumber(tradePlan?.rr);
  const riskPerShare = toNumber(tradePlan?.riskPerShare);
  const hasCore = tradePlan
    && tradePlan.entryRef !== null
    && tradePlan.stopPrice !== null
    && riskPerShare !== null
    && riskPerShare > 0;
  let status = "觀察";
  let blocker = tradePlan?.actionNote || radar?.notes?.[0] || "";

  if (!technical || !technical.ready) {
    status = "資料不足";
    blocker = "日線尚未更新，不能定義有效停損";
  } else if (!hasCore) {
    status = "資料不足";
    blocker = "入場、停損或每股風險不足";
  } else if (tradePlan.action === "先避開" || radar?.stage === "先避開") {
    status = "先避開";
    blocker = tradePlan.actionNote || "結構不在做多主場";
  } else if (rr !== null && rr < 1) {
    status = "風報比不足";
    blocker = `R:R ${rr.toFixed(2)}R 偏低`;
  } else if (tradePlan.aboveBuyFar) {
    status = "等回測";
    blocker = "離買點過遠，不追價";
  } else if (tradePlan.action === "等突破確認") {
    status = "等突破";
    blocker = "等突破關鍵均線或壓力後再執行";
  } else if (tradePlan.inBuyZone && (rr === null || rr >= 1.2) && (radar?.score ?? 0) >= thresholds.candidate) {
    status = "可執行";
    blocker = "價格在可控入場帶，停損與風報比已定義";
  } else if (["攻擊觀察", "候選追蹤"].includes(radar?.stage) && (rr === null || rr >= 1.2)) {
    status = "可執行";
    blocker = tradePlan.actionNote || "雷達與交易計畫同向";
  } else if (tradePlan.action === "等回檔，不追價") {
    status = "等回測";
    blocker = tradePlan.actionNote || "等回到入場帶";
  }

  const conclusion = status === "可執行"
    ? "可列入今日候選，但仍需盤中價格與量價確認"
    : status === "等回測"
      ? "只等價格回到入場帶，不在延伸段追價"
      : status === "等突破"
        ? "等突破確認後再重新評估"
        : status === "風報比不足"
          ? "目標與停損距離不划算，先不硬做"
          : status === "先避開"
            ? "結構或風險條件不合，先保留現金"
            : "資料或條件未齊，先放觀察清單";

  return {
    status,
    tone: executionToneClass(status),
    sortScore: executionSortScore(status),
    price: quote?.price ?? latestValue(stock),
    entry: tradePlan?.entryHint || tradePlan?.entryText || "-",
    stopPrice: tradePlan?.stopPrice ?? null,
    targetPrice: tradePlan?.targetPrice ?? null,
    riskPerShare,
    rr,
    blocker,
    conclusion
  };
}

function operationToneClass(level) {
  if (level === "low") return "up";
  if (level === "high" || level === "extreme") return "down";
  return "flat";
}

function buildOperationProfile(row) {
  const stock = row?.stock || {};
  const scale = row?.scale || stockScaleInfo(stock);
  const radar = row?.radar || null;
  const tradePlan = row?.tradePlan || null;
  const execution = row?.execution || null;
  const valuation = row?.valuation || valuationFor(stock.code);
  const beta = toNumber(row?.beta);
  const revYoy = toNumber(row?.rev?.yoyPct);
  const rs65 = toNumber(row?.rsMulti?.r65);
  const dispositionRisk = row?.dispositionRisk || dispositionRiskSignal(stock.code);
  const dividendYield = valuation ? toNumber(valuation.dividendYield) : null;
  const setupScore = toNumber(tradePlan?.setupScore);
  const volHot = row?.vol && row.vol.zScore > 1 && row.vol.bullish;
  const executable = execution?.status === "可執行";
  const avoid = radar?.stage === "先避開" || tradePlan?.action === "先避開";
  const strong = (radar?.score || 0) >= 70 && (setupScore === null || setupScore >= 6);
  const notes = [];

  let role = "觀察";
  let style = "觀察名單";
  let risk = "medium";
  let riskLabel = "中";
  let sizing = "一般觀察";
  let action = executable ? "可列候選" : (execution?.status || "先觀察");

  if (scale.key === "large") {
    role = dividendYield !== null && dividendYield >= 3.5 ? "核心防守" : "趨勢核心";
    style = "核心 / 續抱";
    risk = beta !== null && beta > 1.4 ? "medium" : "low";
    riskLabel = risk === "low" ? "低" : "中";
    sizing = "可作核心倉觀察";
    notes.push("大型股優先看趨勢延續、估值與籌碼穩定度");
  } else if (scale.key === "mid") {
    role = revYoy !== null && revYoy > 20 && rs65 !== null && rs65 > 0 ? "成長加速" : "波段主攻";
    style = "波段主倉";
    risk = beta !== null && beta > 1.6 ? "high" : "medium";
    riskLabel = risk === "high" ? "高" : "中";
    sizing = "可作波段主攻候選";
    notes.push("中型股重點是成長動能、RS 與可控停損");
  } else if (scale.key === "small") {
    role = strong && volHot ? "事件攻擊" : "題材控倉";
    style = "衛星 / 短波段";
    risk = "high";
    riskLabel = "高";
    sizing = "半倉以下、嚴控停損";
    notes.push("小型股彈性高，但不能用核心倉邏輯處理");
  } else if (scale.key === "micro") {
    role = "高波動觀察";
    style = "試單 / 事件";
    risk = "extreme";
    riskLabel = "極高";
    sizing = "迷你倉或只觀察";
    notes.push("小型以下以流動性與隔日風險優先");
  } else if (scale.key === "etf") {
    role = "ETF配置";
    style = "配置 / 分散";
    risk = "medium";
    riskLabel = "中";
    sizing = "依資產配置處理";
    notes.push("ETF 不納入個股市值級距");
  } else {
    role = "資料待補";
    style = "先補資料";
    risk = "medium";
    riskLabel = "待判斷";
    sizing = "先不放大部位";
    notes.push("需先更新報價、估值與籌碼股數");
  }
  if (dispositionRisk?.available && (dispositionRisk.riskScore || 0) >= 80) {
    role = "處置風險控管";
    style = "先避開 / 等公告解除";
    risk = "extreme";
    riskLabel = "極高";
    sizing = "不放大部位";
    action = "先複核官方公告";
    notes.push(`處置風險：${dispositionRisk.label}`);
  } else if (dispositionRisk?.available && (dispositionRisk.riskScore || 0) >= 55) {
    risk = risk === "low" ? "medium" : "high";
    riskLabel = risk === "high" ? "高" : "中";
    notes.push(`注意交易：${dispositionRisk.label}`);
  }

  if (avoid && !(dispositionRisk?.available && (dispositionRisk.riskScore || 0) >= 80)) {
    role = "暫避重評";
    action = "先避開";
    sizing = "不加碼";
    notes.unshift("結構不合，先保留現金");
  } else if (!executable && execution?.status === "等回測") {
    action = "等回測";
    notes.unshift("只等回到入場帶，不追延伸段");
  } else if (executable) {
    action = "可執行候選";
  }

  return {
    role,
    style,
    risk,
    riskLabel,
    sizing,
    action,
    tone: operationToneClass(risk),
    sortScore: (executable ? 100 : 0) + (radar?.score || 0) - (risk === "extreme" ? 28 : risk === "high" ? 14 : risk === "low" ? -4 : 0),
    notes: uniqueList(notes).slice(0, 4)
  };
}

function officialMarketCode(stock) {
  return stock.suffix === "TWO" ? "otc" : "tse";
}

function twseMisUrl(stock) {
  const exchange = officialMarketCode(stock);
  return `https://mis.twse.com.tw/stock/api/getStockInfo.jsp?ex_ch=${exchange}_${stock.code}.tw&json=1&delay=0&_=${Date.now()}`;
}

// TWSE MIS 支援 pipe-separated 批次查詢：?ex_ch=tse_2330.tw|otc_6640.tw|...
function twseMisBatchUrl(stocks) {
  const codes = stocks.map((s) => `${officialMarketCode(s)}_${s.code}.tw`).join("|");
  return `https://mis.twse.com.tw/stock/api/getStockInfo.jsp?ex_ch=${codes}&json=1&delay=0&_=${Date.now()}`;
}

function misOrderBookFields(row) {
  const bidPrices = numericList(row?.b, { min: 0.0001 });
  const askPrices = numericList(row?.a, { min: 0.0001 });
  const bidVols = numericList(row?.g, { min: 0.0001 });
  const askVols = numericList(row?.f, { min: 0.0001 });
  const totalBid = bidVols.reduce((sum, value) => sum + value, 0);
  const totalAsk = askVols.reduce((sum, value) => sum + value, 0);
  const bidAskRatio = (totalBid + totalAsk) > 0 ? totalBid / (totalBid + totalAsk) : null;
  return {
    bidPrices,
    askPrices,
    bidVols,
    askVols,
    bestBid: bidPrices[0] ?? null,
    bestAsk: askPrices[0] ?? null,
    bestBidVol: bidVols[0] ?? null,
    bestAskVol: askVols[0] ?? null,
    totalBid,
    totalAsk,
    bidAskRatio,
    limitUpPrice: firstNumeric(row?.u),
    limitDownPrice: firstNumeric(row?.w)
  };
}

// 解析 MIS batch 回應；回傳 Map<code, quote | null>
function parseTwseBatchQuotes(text, stocks) {
  const stockMap = new Map(stocks.map((s) => [s.code, s]));
  const results = new Map();
  try {
    const json = JSON.parse(String(text).trim());
    const rows = Array.isArray(json.msgArray) ? json.msgArray : [];
    for (const row of rows) {
      const code = String(row.c || "").trim();
      const stock = stockMap.get(code);
      if (!stock) continue;
      const price = firstNumeric(row.z) ?? firstNumeric(row.a) ?? firstNumeric(row.b) ?? toNumber(row.y);
      const previousClose = toNumber(row.y);
      if (price === null || previousClose === null) continue;
      const change = +(price - previousClose).toFixed(2);
      const pct = previousClose ? +(change / previousClose * 100).toFixed(2) : null;
      const date = row.d && String(row.d).length === 8
        ? `${String(row.d).slice(0, 4)}-${String(row.d).slice(4, 6)}-${String(row.d).slice(6, 8)}`
        : dateKeyInTaipei();
      const orderBook = misOrderBookFields(row);
      results.set(code, {
        code, name: row.n || stock.name, price, change, pct, previousClose,
        open: firstNumeric(row.o), high: firstNumeric(row.h), low: firstNumeric(row.l),
        volume: toNumber(row.v), averagePrice: firstNumeric(row.p), turnover: toNumber(row.m),
        ...orderBook,
        source: "證交所 MIS", sourceKind: "official",
        sourceDate: date, sourceTime: row.t || "", fallbackUsed: false,
        marketTime: row.t ? `${date} ${row.t}` : date,
        capturedAt: new Date().toISOString()
      });
    }
  } catch (_) {}
  return results;
}

// 並行限流器：最多 concurrency 個 worker 同時執行，全部完成才 resolve
async function runConcurrent(items, worker, concurrency) {
  const queue = items.map((item, idx) => ({ item, idx }));
  const results = new Array(items.length);
  async function drain() {
    let task;
    while ((task = queue.shift())) {
      const { item, idx } = task;
      try {
        results[idx] = { ok: true, value: await worker(item, idx) };
      } catch (err) {
        results[idx] = { ok: false, error: err };
      }
    }
  }
  await Promise.all(Array.from({ length: Math.min(concurrency, items.length) }, drain));
  return results;
}

function yahooUrls(stock) {
  return [
    `https://query2.finance.yahoo.com/v8/finance/chart/${stock.code}.${stock.suffix}?interval=1d&range=1d`,
    `https://query1.finance.yahoo.com/v8/finance/chart/${stock.code}.${stock.suffix}?interval=1d&range=1d`
  ];
}

function fetchText(url, { method = "GET", body = null, timeoutMs = null, encoding = "", contentType = "" } = {}) {
  if (typeof chrome !== "undefined" && chrome.runtime && chrome.runtime.sendMessage) {
    return new Promise((resolve, reject) => {
      const msg = { type: "fetch-text", url, method, body, timeoutMs, encoding, contentType };
      chrome.runtime.sendMessage(msg, (response) => {
        const runtimeError = chrome.runtime.lastError;
        if (runtimeError) {
          reject(new Error(runtimeError.message));
          return;
        }
        if (!response || !response.ok) {
          reject(new Error(response && response.error ? response.error : "fetch failed"));
          return;
        }
        resolve(response.text);
      });
    });
  }

  const opts = { cache: "no-store", method };
  if (body) { opts.body = body; opts.headers = { "Content-Type": contentType || "application/x-www-form-urlencoded" }; }
  let timeout = null;
  if (timeoutMs && typeof AbortController !== "undefined") {
    const controller = new AbortController();
    opts.signal = controller.signal;
    timeout = setTimeout(() => controller.abort(), timeoutMs);
  }
  return fetch(url, opts).then(async (response) => {
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    if (encoding && typeof TextDecoder !== "undefined") {
      const buffer = await response.arrayBuffer();
      return new TextDecoder(encoding).decode(buffer);
    }
    return response.text();
  }).finally(() => {
    if (timeout) clearTimeout(timeout);
  });
}

function requestBrowserDownload(url, filename) {
  const safeUrl = normalizeDownloadUrl(url);
  if (!safeUrl) return Promise.reject(new Error("下載網址格式或通訊協定不安全"));
  if (typeof chrome !== "undefined" && chrome.runtime && chrome.runtime.sendMessage) {
    return new Promise((resolve, reject) => {
      chrome.runtime.sendMessage({ type: "download-file", url: safeUrl, filename }, (response) => {
        const runtimeError = chrome.runtime.lastError;
        if (runtimeError) {
          reject(new Error(runtimeError.message));
          return;
        }
        if (!response || !response.ok) {
          reject(new Error(response && response.error ? response.error : "download failed"));
          return;
        }
        resolve(response);
      });
    });
  }

  return new Promise((resolve, reject) => {
    try {
      const anchor = document.createElement("a");
      anchor.href = safeUrl;
      anchor.download = String(filename || "").split("/").pop() || "podcast_audio.mp3";
      anchor.rel = "noopener noreferrer";
      document.body.appendChild(anchor);
      anchor.click();
      anchor.remove();
      resolve({ ok: true });
    } catch (error) {
      reject(error);
    }
  });
}

function normalizeExternalLinkUrl(url) {
  try {
    const parsed = new URL(String(url || ""), window.location.href);
    if (parsed.username || parsed.password) return "";
    if (parsed.protocol === "http:" || parsed.protocol === "https:") return parsed.href;
  } catch (_) {}
  return "";
}

function normalizeDownloadUrl(url) {
  try {
    const parsed = new URL(String(url || ""), window.location.href);
    if (parsed.username || parsed.password) return "";
    if (parsed.protocol === "https:") return parsed.href;
    if (parsed.protocol === "http:" && parsed.origin === window.location.origin) return parsed.href;
    if (parsed.protocol === "blob:") return parsed.href;
  } catch (_) {}
  return "";
}

function isPublishedWebRuntime() {
  return typeof document !== "undefined" && document.documentElement?.dataset?.runtime === "web";
}

function openExternalLink(url) {
  const safeUrl = normalizeExternalLinkUrl(url);
  if (!safeUrl) {
    setStatus("外部連結格式錯誤，未開啟。", "error");
    return false;
  }
  try {
    if (typeof chrome !== "undefined" && chrome.tabs && typeof chrome.tabs.create === "function") {
      chrome.tabs.create({ url: safeUrl }, () => {
        const runtimeError = chrome.runtime?.lastError;
        if (runtimeError && typeof window !== "undefined" && typeof window.open === "function") {
          const opened = window.open(safeUrl, "_blank", "noopener");
          if (opened) opened.opener = null;
        }
      });
      return true;
    }
  } catch (_) {}
  if (typeof window !== "undefined" && typeof window.open === "function") {
    const opened = window.open(safeUrl, "_blank", "noopener");
    if (opened) opened.opener = null;
    return true;
  }
  return false;
}

function shouldHandleExternalLinkClick(link) {
  if (!link) return false;
  return Boolean(
    link.classList?.contains("link-chip") ||
    link.closest?.("[data-market-card-inline-links]") ||
    link.closest?.("[data-external-source-links]") ||
    link.closest?.("#topFuturesStrip")
  );
}

function bundledAssetUrl(path) {
  if (typeof chrome !== "undefined" && chrome.runtime && chrome.runtime.getURL) {
    return chrome.runtime.getURL(path);
  }
  return path;
}

async function readLimitedJsonResponse(response, maxBytes = 2 * 1024 * 1024) {
  const announcedBytes = Number(response.headers.get("content-length") || 0);
  if (announcedBytes > maxBytes) throw new Error("行情快照超過 2 MB 安全上限");
  const buffer = await response.arrayBuffer();
  if (buffer.byteLength > maxBytes) throw new Error("行情快照超過 2 MB 安全上限");
  return JSON.parse(new TextDecoder("utf-8").decode(buffer));
}

async function loadPublishedMarketSnapshot() {
  if (!isPublishedWebRuntime()) throw new Error("延遲快照僅供公開網站模式使用");
  const snapshotUrl = new URL(bundledAssetUrl("data/live_market.json"), window.location.href);
  if (snapshotUrl.origin !== window.location.origin) throw new Error("行情快照必須來自目前網站");
  snapshotUrl.searchParams.set("app", APP_VERSION);
  snapshotUrl.searchParams.set("ts", String(Date.now()));
  const response = await fetch(snapshotUrl.href, {
    method: "GET",
    cache: "no-store",
    credentials: "same-origin",
    redirect: "error",
    headers: { Accept: "application/json" }
  });
  if (!response.ok) throw new Error(`HTTP ${response.status}`);
  const payload = await readLimitedJsonResponse(response);
  if (payload?.schemaVersion !== 1 || !payload.marketDashboardCache || typeof payload.marketDashboardCache !== "object") {
    throw new Error("行情快照格式不相容");
  }
  return normalizeMarketDashboardCache({
    ...payload.marketDashboardCache,
    delivery: payload.marketDashboardCache.delivery || payload.delivery
  });
}

async function fetchJson(url) {
  const response = await fetch(url, { cache: "no-store" });
  if (!response.ok) throw new Error(`HTTP ${response.status}`);
  return response.json();
}

function stripHtml(raw) {
  const source = String(raw || "");
  const parsed = typeof DOMParser !== "undefined"
    ? new DOMParser().parseFromString(source, "text/html")
    : null;
  const text = parsed?.body?.textContent || source.replace(/<[^>]*>/g, " ");
  return text
    .replace(/\r/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .replace(/[ \t]{2,}/g, " ")
    .trim();
}

function podcastHeadline(title) {
  return String(title || "")
    .replace(/^\s*EP\s*\d+\s*[｜|:：-]?\s*/i, "")
    .trim()
    .replace(/^[｜|:：\s-]+|[｜|:：\s-]+$/g, "");
}

function sanitizeDownloadSegment(value, fallback = "") {
  const cleaned = String(value || "")
    .replace(/[<>:"/\\|?*\u0000-\u001f]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/^\.+|\.+$/g, "");
  return cleaned || fallback;
}

function normalizePodcastDownloadDir(value) {
  const normalized = String(value || "")
    .split(/[\\/]+/)
    .map((part) => sanitizeDownloadSegment(part))
    .filter(Boolean)
    .join("/");
  return normalized || DEFAULT_PODCAST_DOWNLOAD_DIR;
}

function podcastDownloadFolder() {
  return normalizePodcastDownloadDir(state.podcastDownloadDir);
}

function podcastAudioExtension(audioUrl) {
  try {
    const pathname = new URL(audioUrl).pathname;
    const match = pathname.match(/\.([A-Za-z0-9]{2,5})$/);
    return match ? `.${match[1].toLowerCase()}` : ".mp3";
  } catch (error) {
    return ".mp3";
  }
}

function podcastDownloadFilename(show, episode) {
  const root = podcastDownloadFolder();
  const showSegment = sanitizeDownloadSegment(show.name || show.slug || "podcast", show.slug || "podcast");
  const datePart = sanitizeDownloadSegment(podcastEpisodeDate(episode) || "unknown-date", "unknown-date");
  const episodePart = sanitizeDownloadSegment(episode.episodeNo ? `EP${episode.episodeNo}` : "latest", "latest");
  const titlePart = sanitizeDownloadSegment(podcastHeadline(episode.title || "") || "audio", "audio").slice(0, 64);
  const ext = podcastAudioExtension(episode.audioUrl || "");
  return [root, showSegment, `${datePart}_${episodePart}_${titlePart}${ext}`].filter(Boolean).join("/");
}

function podcastDownloadHint(show) {
  const showSegment = sanitizeDownloadSegment((show && (show.name || show.slug)) || "podcast", "podcast");
  return `Downloads/${podcastDownloadFolder()}/${showSegment}/`;
}

function podcastIdentity(episode) {
  return episode.guid || episode.audioUrl || `${episode.title || ""}_${episode.publishedAt || ""}`;
}

function podcastTopicTags(title, description) {
  const haystack = `${title || ""}\n${description || ""}`.toLowerCase();
  return PODCAST_TOPIC_RULES
    .filter((rule) => rule.keywords.some((keyword) => haystack.includes(String(keyword).toLowerCase())))
    .map((rule) => rule.label)
    .slice(0, 6);
}

function podcastSummaryBullets(title, description) {
  const tags = podcastTopicTags(title, description);
  const sponsorScore = PODCAST_SPONSOR_MARKERS.filter((marker) => String(description || "").includes(marker)).length;
  const headline = podcastHeadline(title);
  const shortHeadline = headline.replace(/[\W_]+/g, "").length < 4;
  if (!tags.length && sponsorScore >= 2 && shortHeadline) {
    return [
      "RSS 節目說明以贊助或活動文案為主，無法可靠還原本集產業趨勢。",
      "若要判讀本集重點，建議直接開啟原始音檔或回 RSS 原節目頁確認。"
    ];
  }

  const source = description || podcastHeadline(title) || "";
  const normalized = String(source || "")
    .replace(/https?:\/\/\S+/g, " ")
    .replace(/-------/g, "\n")
    .replace(/[◎•▪✅☑🏆★▲●]/g, "\n");
  const parts = [
    podcastHeadline(title),
    ...normalized.split(/\n+|(?<=[。！？?])\s+/)
  ]
    .map((part) => part.replace(/\s+/g, " ").trim())
    .filter(Boolean);

  const bullets = [];
  const seen = new Set();
  for (const part of parts) {
    const lower = part.toLowerCase();
    if (part.length < 8) continue;
    if (lower.startsWith("本集節目由") || lower.startsWith("hosting provided by") || lower.startsWith("節目內容純屬")) continue;
    if (seen.has(part)) continue;
    seen.add(part);
    bullets.push(part);
    if (bullets.length >= 5) break;
  }
  return bullets;
}

function xmlNodeText(node, tagNames) {
  for (const tagName of tagNames) {
    const match = node.getElementsByTagName(tagName)[0];
    if (match && match.textContent) return match.textContent.trim();
  }
  return "";
}

function parsePodcastPubDate(value) {
  if (!value) return "";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toISOString();
}

function normalizePodcastEpisode(episode = {}) {
  const description = stripHtml(episode.description || "");
  const transcriptPreview = String(episode.transcriptPreview || description || "").trim();
  const trendTags = Array.isArray(episode.trendTags) && episode.trendTags.length
    ? episode.trendTags
    : podcastTopicTags(episode.title, description);
  const summaryBullets = Array.isArray(episode.summaryBullets) && episode.summaryBullets.length
    ? episode.summaryBullets
    : podcastSummaryBullets(episode.title, description);
  return {
    guid: episode.guid || episode.audioUrl || episode.title || "",
    episodeNo: episode.episodeNo || "",
    title: episode.title || "未命名單集",
    headline: episode.headline || podcastHeadline(episode.title),
    publishedAt: episode.publishedAt || "",
    duration: episode.duration || "",
    audioUrl: episode.audioUrl || "",
    description,
    trendTags,
    summaryBullets,
    summary500: episode.summary500 || "",
    transcriptStatus: episode.transcriptStatus || "rss_description",
    transcriptNote: episode.transcriptNote || "目前先以 RSS 節目說明建立摘要，完整逐字稿需另跑本地轉錄流程。",
    transcriptPreview,
    transcriptPath: episode.transcriptPath || "",
    summaryPath: episode.summaryPath || ""
  };
}

function mergePodcastDigest(existing, incoming) {
  const currentShows = new Map(((existing && existing.shows) || []).map((show) => [show.slug || show.name, show]));
  const shows = ((incoming && incoming.shows) || []).map((show) => {
    const previous = currentShows.get(show.slug || show.name) || {};
    const previousEpisodes = new Map(((previous.episodes) || []).map((episode) => [podcastIdentity(episode), episode]));
    const episodes = ((show.episodes) || []).map((episode) => {
      const normalized = normalizePodcastEpisode(episode);
      const earlier = previousEpisodes.get(podcastIdentity(normalized));
      if (!earlier) return normalized;
      return normalizePodcastEpisode({
        ...earlier,
        ...normalized,
        transcriptPath: earlier.transcriptPath || normalized.transcriptPath,
        summaryPath: earlier.summaryPath || normalized.summaryPath,
        transcriptPreview: earlier.transcriptPreview || normalized.transcriptPreview,
        transcriptStatus: earlier.transcriptStatus && earlier.transcriptStatus !== "rss_description"
          ? earlier.transcriptStatus
          : normalized.transcriptStatus,
        transcriptNote: earlier.transcriptStatus && earlier.transcriptStatus !== "rss_description"
          ? earlier.transcriptNote
          : normalized.transcriptNote
      });
    });
    return {
      slug: show.slug || previous.slug || show.name,
      name: show.name || previous.name || "未命名節目",
      cadence: show.cadence || previous.cadence || "",
      rss: show.rss || previous.rss || "",
      episodes
    };
  });

  return {
    generatedAt: (incoming && incoming.generatedAt) || (existing && existing.generatedAt) || null,
    source: (incoming && incoming.source) || (existing && existing.source) || "Podcast RSS",
    shows
  };
}

function normalizeYoutubeMarketLesson(lesson = {}) {
  const usableSignals = Array.isArray(lesson.usableSignals) && lesson.usableSignals.length
    ? lesson.usableSignals
    : (Array.isArray(lesson.summarySignals) ? lesson.summarySignals : []);
  const limits = Array.isArray(lesson.limits) && lesson.limits.length
    ? lesson.limits
    : [
      "未完成逐字稿或二次交叉比對前，不應把影片內容視為交易結論。",
      "若要升級信心，需回查 TWSE / TAIFEX / 法人 / 總經資料。"
    ];
  return {
    id: String(lesson.id || lesson.videoId || "").trim(),
    videoId: String(lesson.videoId || lesson.id || "").trim(),
    displayTitle: lesson.displayTitle || lesson.title || "YouTube 股市心得",
    title: lesson.title || lesson.displayTitle || "YouTube 股市心得",
    channel: lesson.channel || "",
    url: lesson.url || "",
    startSeconds: Number.isFinite(Number(lesson.startSeconds)) ? Number(lesson.startSeconds) : null,
    duration: lesson.duration || "",
    fetchedAt: lesson.fetchedAt || "",
    updatedAt: lesson.updatedAt || "",
    sourceTier: lesson.sourceTier || "Tier 3 影片 / 摘要來源",
    transcriptStatus: lesson.transcriptStatus || "待轉錄",
    confidence: lesson.confidence || "low",
    usableSignals: usableSignals.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 8),
    limits: limits.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 6),
    crossChecks: Array.isArray(lesson.crossChecks)
      ? lesson.crossChecks.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 8)
      : [],
    tags: Array.isArray(lesson.tags)
      ? lesson.tags.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 10)
      : [],
    transcriptMeta: lesson.transcriptMeta && typeof lesson.transcriptMeta === "object" ? lesson.transcriptMeta : null
  };
}

function normalizeYoutubeMarketLessonsPayload(payload) {
  if (!payload || typeof payload !== "object" || Array.isArray(payload)) return null;
  const lessons = Array.isArray(payload.lessons)
    ? payload.lessons.map(normalizeYoutubeMarketLesson).filter((lesson) => lesson.id && lesson.url)
    : [];
  if (!lessons.length) return null;
  const channels = Array.isArray(payload.channels) && payload.channels.length
    ? payload.channels.map((channel) => ({
      label: channel.label || channel.name || "YouTube",
      url: channel.url || "",
      sourceTier: channel.sourceTier || "Tier 3 影音來源"
    })).filter((channel) => channel.url)
    : YOUTUBE_MARKET_CHANNELS;
  return {
    version: Number(payload.version) || 1,
    generatedAt: payload.generatedAt || null,
    source: payload.source || "data/youtube_market_lessons.json",
    pipelineStatus: payload.pipelineStatus || "metadata-only",
    transcriptPolicy: payload.transcriptPolicy || "Full transcripts are read locally but not bundled in the extension.",
    channels,
    lessons
  };
}

function youtubeMarketLessonsPayload() {
  return normalizeYoutubeMarketLessonsPayload(state.youtubeMarketLessons) || {
    version: 1,
    generatedAt: null,
    source: "inline fallback",
    pipelineStatus: "metadata-only",
    transcriptPolicy: "Full transcripts are read locally but not bundled in the extension.",
    channels: YOUTUBE_MARKET_CHANNELS,
    lessons: YOUTUBE_MARKET_LESSONS_FALLBACK.map(normalizeYoutubeMarketLesson)
  };
}

function parsePodcastFeed(text, feed) {
  const parser = new DOMParser();
  const xml = parser.parseFromString(String(text || ""), "text/xml");
  if (xml.querySelector("parsererror")) {
    throw new Error(`${feed.name} RSS XML parse 失敗`);
  }
  const channel = xml.getElementsByTagName("channel")[0];
  if (!channel) throw new Error(`${feed.name} RSS 缺少 channel`);
  const items = [...channel.getElementsByTagName("item")].slice(0, 3);
  return {
    slug: feed.slug,
    name: feed.name,
    cadence: feed.cadence,
    rss: feed.rss,
    episodes: items.map((item) => {
      const enclosure = item.getElementsByTagName("enclosure")[0];
      const title = xmlNodeText(item, ["title"]);
      const description = stripHtml(xmlNodeText(item, ["description"]));
      return normalizePodcastEpisode({
        guid: xmlNodeText(item, ["guid"]) || (enclosure && enclosure.getAttribute("url")) || title,
        episodeNo: (title.match(/\bEP\s*(\d+)\b/i) || [null, ""])[1],
        title,
        headline: podcastHeadline(title),
        publishedAt: parsePodcastPubDate(xmlNodeText(item, ["pubDate"])),
        duration: xmlNodeText(item, ["itunes:duration", "duration"]),
        audioUrl: enclosure ? enclosure.getAttribute("url") || "" : "",
        description,
        trendTags: podcastTopicTags(title, description),
        summaryBullets: podcastSummaryBullets(title, description),
        summary500: podcastSummaryBullets(title, description).join(" ").slice(0, 520),
        transcriptStatus: "rss_description",
        transcriptNote: "這次由瀏覽器直接更新 RSS metadata。",
        transcriptPreview: description.slice(0, 700)
      });
    })
  };
}

function parseTwseQuote(text, stock) {
  const json = JSON.parse(String(text).trim());
  const row = json && Array.isArray(json.msgArray) ? json.msgArray[0] : null;
  if (!row) throw new Error("TWSE MIS 無報價列");

  const price = firstNumeric(row.z) ?? firstNumeric(row.a) ?? firstNumeric(row.b) ?? toNumber(row.y);
  const previousClose = toNumber(row.y);
  if (price === null || previousClose === null) {
    throw new Error("TWSE MIS 報價缺價格或昨收");
  }
  const change = +(price - previousClose).toFixed(2);
  const pct = previousClose ? +(change / previousClose * 100).toFixed(2) : null;
  const date = row.d && String(row.d).length === 8
    ? `${String(row.d).slice(0, 4)}-${String(row.d).slice(4, 6)}-${String(row.d).slice(6, 8)}`
    : dateKeyInTaipei();
  const orderBook = misOrderBookFields(row);

  return {
    code: stock.code,
    name: row.n || stock.name,
    price,
    change,
    pct,
    previousClose,
    open: firstNumeric(row.o),
    high: firstNumeric(row.h),
    low: firstNumeric(row.l),
    volume: toNumber(row.v),
    averagePrice: firstNumeric(row.p),
    turnover: toNumber(row.m),
    ...orderBook,
    source: "證交所 MIS",
    sourceKind: "official",
    sourceDate: date,
    sourceTime: row.t || "",
    fallbackUsed: false,
    marketTime: row.t ? `${date} ${row.t}` : date,
    capturedAt: new Date().toISOString()
  };
}

function parseYahooQuote(text, stock) {
  const json = JSON.parse(String(text).trim());
  const result = json && json.chart && Array.isArray(json.chart.result) ? json.chart.result[0] : null;
  const meta = result && result.meta ? result.meta : null;
  if (!meta) throw new Error("Yahoo 無報價資料");

  const price = toNumber(meta.regularMarketPrice);
  const previousClose = toNumber(meta.chartPreviousClose) ?? toNumber(meta.previousClose);
  if (price === null || previousClose === null) {
    throw new Error("Yahoo 報價缺價格或昨收");
  }
  const change = +(price - previousClose).toFixed(2);
  const pct = previousClose ? +(change / previousClose * 100).toFixed(2) : null;
  const marketTimestamp = toNumber(meta.regularMarketTime) || toNumber(result.timestamp?.at?.(-1));
  const marketDate = marketTimestamp ? new Date(marketTimestamp * 1000) : null;
  const sourceDate = marketDate && !Number.isNaN(marketDate.getTime()) ? dateKeyInTaipei(marketDate) : dateKeyInTaipei();
  const sourceTime = marketDate && !Number.isNaN(marketDate.getTime()) ? timeKeyInTaipei(marketDate) : "";

  const navPrice = toNumber(meta.navPrice);
  // 若有 navPrice（ETF 類型），順手存入 etfNavCache
  if (navPrice !== null && navPrice > 0 && isEtfCode(stock.code)) {
    state.etfNavCache = state.etfNavCache || {};
    state.etfNavCache[stock.code] = { nav: navPrice, date: dateKeyInTaipei(), fetchedAt: new Date().toISOString() };
  }
  return {
    code: stock.code,
    name: stock.name,
    price,
    change,
    pct,
    previousClose,
    open: toNumber(meta.regularMarketOpen),
    high: toNumber(meta.regularMarketDayHigh),
    low: toNumber(meta.regularMarketDayLow),
    volume: toNumber(meta.regularMarketVolume),
    averagePrice: null,
    turnover: null,
    navPrice,
    source: "Yahoo Finance fallback",
    sourceKind: "fallback",
    fallbackUsed: true,
    sourceDate,
    sourceTime,
    marketTime: marketDate ? marketDate.toISOString() : "",
    exchangeTimezoneName: meta.exchangeTimezoneName || meta.timezone || "",
    capturedAt: new Date().toISOString()
  };
}

let _officialDailyQuoteMapsPromise = null;

function parseOfficialDailyQuoteRow(row, stock, market) {
  if (!row || !stock) return null;
  const isTpex = market === "TPEX";
  const price = toNumber(isTpex ? row.Close : row.ClosingPrice);
  if (price === null) return null;
  const change = toNumber(row.Change);
  const previousClose = change !== null ? +(price - change).toFixed(2) : price;
  const pct = previousClose ? +(change / previousClose * 100).toFixed(2) : null;
  const code = String(isTpex ? row.SecuritiesCompanyCode : row.Code || stock.code).trim();
  const name = String(isTpex ? row.CompanyName : row.Name || stock.name).trim();
  return {
    code: stock.code || code,
    name: name || stock.name,
    price,
    change,
    pct,
    previousClose,
    open: toNumber(isTpex ? row.Open : row.OpeningPrice),
    high: toNumber(isTpex ? row.High : row.HighestPrice),
    low: toNumber(isTpex ? row.Low : row.LowestPrice),
    volume: toNumber(isTpex ? row.TradingShares : row.TradeVolume),
    averagePrice: null,
    turnover: toNumber(isTpex ? row.TransactionAmount : row.TradeValue),
    source: isTpex ? "TPEx 官方即時行情備援" : "TWSE 官方收盤表備援",
    sourceKind: "official",
    sourceDate: parseRocCompactDate(row.Date),
    sourceTime: "",
    fallbackUsed: true,
    marketTime: parseRocCompactDate(row.Date),
    capturedAt: new Date().toISOString()
  };
}

async function officialDailyQuoteMaps() {
  if (_officialDailyQuoteMapsPromise) return _officialDailyQuoteMapsPromise;
  _officialDailyQuoteMapsPromise = (async () => {
    const [twseResult, tpexResult] = await Promise.allSettled([
      fetchText("https://openapi.twse.com.tw/v1/exchangeReport/STOCK_DAY_ALL", { timeoutMs: 15000 }),
      fetchText("https://www.tpex.org.tw/openapi/v1/tpex_mainboard_quotes", { timeoutMs: 15000 })
    ]);
    const twseRows = twseResult.status === "fulfilled" ? JSON.parse(twseResult.value) : [];
    const tpexRows = tpexResult.status === "fulfilled" ? JSON.parse(tpexResult.value) : [];
    return {
      twse: new Map((Array.isArray(twseRows) ? twseRows : []).map((row) => [String(row.Code || "").trim(), row])),
      tpex: new Map((Array.isArray(tpexRows) ? tpexRows : []).map((row) => [String(row.SecuritiesCompanyCode || "").trim(), row])),
      errors: [
        twseResult.status === "rejected" ? `TWSE STOCK_DAY_ALL: ${twseResult.reason?.message || String(twseResult.reason)}` : "",
        tpexResult.status === "rejected" ? `TPEx mainboard quotes: ${tpexResult.reason?.message || String(tpexResult.reason)}` : ""
      ].filter(Boolean)
    };
  })();
  return _officialDailyQuoteMapsPromise;
}

async function officialDailyQuoteFallback(stock) {
  const maps = await officialDailyQuoteMaps();
  const twseRow = maps.twse.get(stock.code);
  if (twseRow) {
    const quote = parseOfficialDailyQuoteRow(twseRow, stock, "TWSE");
    if (quote) return quote;
  }
  const tpexRow = maps.tpex.get(stock.code);
  if (tpexRow) {
    const quote = parseOfficialDailyQuoteRow(tpexRow, stock, "TPEX");
    if (quote) return quote;
  }
  throw new Error(`官方收盤表備援無 ${stock.code}${maps.errors.length ? `；${maps.errors.join("；")}` : ""}`);
}

async function officialDailyQuoteFallbackMap(stocks) {
  if (!Array.isArray(stocks) || !stocks.length) return new Map();
  const result = new Map();
  await officialDailyQuoteMaps();
  for (const stock of stocks) {
    try {
      result.set(stock.code, await officialDailyQuoteFallback(stock));
    } catch (_) {}
  }
  return result;
}

async function fetchQuote(stock) {
  try {
    const text = await fetchText(twseMisUrl(stock));
    return parseTwseQuote(text, stock);
  } catch (officialError) {
    let lastError = officialError;
    for (const url of yahooUrls(stock)) {
      try {
        const text = await fetchText(url);
        return parseYahooQuote(text, stock);
      } catch (fallbackError) {
        lastError = fallbackError;
      }
    }
    try {
      return await officialDailyQuoteFallback(stock);
    } catch (officialDailyError) {
      lastError = officialDailyError || lastError;
    }
    throw lastError;
  }
}

function pad2(value) {
  return String(value).padStart(2, "0");
}

function compactDate(date) {
  return `${date.getFullYear()}${pad2(date.getMonth() + 1)}01`;
}

function compactDayDate(date) {
  return `${date.getFullYear()}${pad2(date.getMonth() + 1)}${pad2(date.getDate())}`;
}

function slashDate(date) {
  return `${date.getFullYear()}/${pad2(date.getMonth() + 1)}/01`;
}

function rocSlashDayDate(date) {
  return `${date.getFullYear() - 1911}/${pad2(date.getMonth() + 1)}/${pad2(date.getDate())}`;
}

function monthAnchors(monthCount = KLINE_HISTORY_MONTHS) {
  const anchors = [];
  const now = new Date();
  for (let offset = monthCount - 1; offset >= 0; offset -= 1) {
    anchors.push(new Date(now.getFullYear(), now.getMonth() - offset, 1));
  }
  return anchors;
}

function parseRocDate(value) {
  const match = String(value || "").match(/(\d{2,4})[/-](\d{1,2})[/-](\d{1,2})/);
  if (!match) return "";
  const rawYear = Number(match[1]);
  const year = rawYear < 1911 ? rawYear + 1911 : rawYear;
  return `${year}-${pad2(match[2])}-${pad2(match[3])}`;
}

function twseStockDayUrl(stock, date) {
  return `https://www.twse.com.tw/rwd/zh/afterTrading/STOCK_DAY?date=${compactDate(date)}&stockNo=${stock.code}&response=json`;
}

function tpexTradingStockUrl(stock, date) {
  return `https://www.tpex.org.tw/www/zh-tw/afterTrading/tradingStock?code=${stock.code}&date=${encodeURIComponent(slashDate(date))}&id=&response=json&type=Monthly`;
}

function twseValuationUrl(date) {
  return `https://www.twse.com.tw/exchangeReport/BWIBBU_d?response=json&date=${compactDayDate(date)}&selectType=ALL`;
}

function tpexValuationUrl(date) {
  return `https://www.tpex.org.tw/web/stock/aftertrading/peratio_analysis/pera_result.php?l=zh-tw&o=json&d=${encodeURIComponent(rocSlashDayDate(date))}`;
}

function yahooHistoryUrl(stock) {
  return `https://query1.finance.yahoo.com/v8/finance/chart/${stock.code}.${stock.suffix}?interval=1d&range=18mo`;
}

function normalizeKline(row) {
  if (!row || !row.date || row.close === null || row.close === undefined) return null;
  const open = toNumber(row.open);
  const high = toNumber(row.high);
  const low = toNumber(row.low);
  const close = toNumber(row.close);
  if (close === null) return null;
  return {
    date: row.date,
    open: open ?? close,
    high: high ?? close,
    low: low ?? close,
    close,
    volume: toNumber(row.volume) ?? 0,
    turnover: toNumber(row.turnover) ?? toNumber(row.amount) ?? null,
    source: row.source || "unknown"
  };
}

function parseTwseKlines(text, stock) {
  const json = JSON.parse(String(text).trim());
  const rows = Array.isArray(json.data) ? json.data : [];
  if (!rows.length) return [];
  return rows.map((row) => normalizeKline({
    date: parseRocDate(row[0]),
    volume: row[1],
    turnover: row[2],
    open: row[3],
    high: row[4],
    low: row[5],
    close: row[6],
    source: `TWSE STOCK_DAY ${stock.code}`
  })).filter(Boolean);
}

function parseTpexKlines(text, stock) {
  const json = JSON.parse(String(text).trim());
  const table = json && Array.isArray(json.tables) ? json.tables[0] : null;
  const rows = table && Array.isArray(table.data) ? table.data : [];
  if (!rows.length) return [];
  return rows.map((row) => normalizeKline({
    date: parseRocDate(row[0]),
    volume: toNumber(row[1]) !== null ? toNumber(row[1]) * 1000 : null,
    turnover: row[2],
    open: row[3],
    high: row[4],
    low: row[5],
    close: row[6],
    source: `TPEx tradingStock ${stock.code}`
  })).filter(Boolean);
}

function parseYahooKlines(text, stock) {
  const json = JSON.parse(String(text).trim());
  const result = json && json.chart && Array.isArray(json.chart.result) ? json.chart.result[0] : null;
  const timestamps = result && Array.isArray(result.timestamp) ? result.timestamp : [];
  const quote = result && result.indicators && Array.isArray(result.indicators.quote)
    ? result.indicators.quote[0]
    : null;
  if (!timestamps.length || !quote) return [];
  return timestamps.map((timestamp, index) => normalizeKline({
    date: new Date(timestamp * 1000).toISOString().slice(0, 10),
    open: quote.open ? quote.open[index] : null,
    high: quote.high ? quote.high[index] : null,
    low: quote.low ? quote.low[index] : null,
    close: quote.close ? quote.close[index] : null,
    volume: quote.volume ? quote.volume[index] : null,
    turnover: null,
    source: `Yahoo history fallback ${stock.code}.${stock.suffix}`
  })).filter(Boolean);
}

function normalizeValuationRecord(record) {
  return {
    code: record.code,
    name: record.name,
    market: record.market,
    close: record.close ?? null,
    pe: record.pe ?? null,
    dividendYield: record.dividendYield ?? null,
    dividendPerShare: record.dividendPerShare ?? null,
    dividendYear: record.dividendYear || "",
    pbr: record.pbr ?? null,
    reportPeriod: record.reportPeriod || "",
    sourceDate: record.sourceDate || "",
    sourceLabel: record.sourceLabel || "",
    fetchedAt: new Date().toISOString()
  };
}

function parseTwseValuations(text) {
  const json = JSON.parse(String(text).trim());
  const rows = Array.isArray(json.data) ? json.data : [];
  if (!rows.length) throw new Error("TWSE 官方估值無資料");
  const sourceDate = parseCompactDay(json.date);
  const records = {};
  const universeRecords = {};
  for (const row of rows) {
    const code = String(row[0] || "").trim();
    if (!code || !/^\d{4}$/.test(code)) continue;
    const normalized = normalizeValuationRecord({
      code,
      name: officialTextValue(row[1]),
      market: "TW",
      close: officialNumberValue(row[2]),
      dividendYield: officialNumberValue(row[3]),
      dividendYear: officialTextValue(row[4]),
      pe: officialNumberValue(row[5]),
      pbr: officialNumberValue(row[6]),
      reportPeriod: officialTextValue(row[7]),
      sourceDate,
      sourceLabel: "TWSE 官方估值"
    });
    universeRecords[code] = normalized;
    if (!STOCK_MAP.has(code)) continue;
    records[code] = normalized;
  }
  if (!Object.keys(records).length) throw new Error("TWSE 估值資料未涵蓋追蹤名單");
  return {
    market: "TW",
    title: json.title || "",
    sourceDate,
    sourceLabel: "TWSE 官方估值",
    records,
    universeRecords
  };
}

function parseTpexValuations(text) {
  const json = JSON.parse(String(text).trim());
  const table = json && Array.isArray(json.tables) ? json.tables[0] : null;
  const rows = table && Array.isArray(table.data) ? table.data : [];
  if (!rows.length) throw new Error("TPEx 官方估值無資料");
  const sourceDate = parseRocDate((table && table.date) || json.date);
  const records = {};
  for (const row of rows) {
    const code = String(row[0] || "").trim();
    if (!code || !STOCK_MAP.has(code)) continue;
    records[code] = normalizeValuationRecord({
      code,
      name: officialTextValue(row[1]),
      market: "TWO",
      close: null,
      pe: officialNumberValue(row[2]),
      dividendPerShare: officialNumberValue(row[3]),
      dividendYear: officialTextValue(row[4]),
      dividendYield: officialNumberValue(row[5]),
      pbr: officialNumberValue(row[6]),
      reportPeriod: officialTextValue(row[7]),
      sourceDate,
      sourceLabel: "TPEx 官方估值"
    });
  }
  if (!Object.keys(records).length) throw new Error("TPEx 估值資料未涵蓋追蹤名單");
  return {
    market: "TWO",
    title: (table && table.title) || "",
    sourceDate,
    sourceLabel: "TPEx 官方估值",
    records
  };
}

function storeValuationMarket(result) {
  if (!result || !result.records) return;
  for (const [code, record] of Object.entries(result.records)) {
    state.valuations[code] = {
      ...(state.valuations[code] || {}),
      ...record
    };
  }
  state.valuationMeta[result.market] = {
    title: result.title || "",
    sourceLabel: result.sourceLabel || "",
    sourceDate: result.sourceDate || "",
    count: Object.keys(result.records).length,
    fetchedAt: new Date().toISOString()
  };
  applyResearchLabels();
}

async function fetchOfficialValuationsForMarket(market, lookbackDays = 10) {
  let lastError = null;
  for (let offset = 0; offset <= lookbackDays; offset += 1) {
    const date = new Date();
    date.setDate(date.getDate() - offset);
    const url = market === "TWO" ? tpexValuationUrl(date) : twseValuationUrl(date);
    try {
      const text = await fetchText(url);
      return market === "TWO" ? parseTpexValuations(text) : parseTwseValuations(text);
    } catch (error) {
      lastError = error;
    }
    await wait(80);
  }
  throw lastError || new Error(`${marketLabelFromSuffix(market)}官方估值抓取失敗`);
}

async function refreshOfficialValuations(stocks = WATCHLIST, options = {}) {
  const force = options.force === true;
  const markets = [...new Set((stocks || WATCHLIST).map((stock) => (stock.suffix === "TWO" ? "TWO" : "TW")))];
  const today = localDateKey(); // "2026-05-12"
  const needsFetch = force ? markets : markets.filter((market) => {
    const meta = state.valuationMeta?.[market];
    if (!meta?.sourceDate) return true;
    const metaDate = meta.sourceDate.replace(/\//g, "-"); // normalize slash/dash
    return !metaDate.startsWith(today);
  });
  if (!needsFetch.length) {
    return { results: [], failures: [], skipped: markets };
  }
  // 並行抓取 TWSE + TPEx（不再串列）
  const settled = await Promise.allSettled(needsFetch.map((market) =>
    fetchOfficialValuationsForMarket(market)
  ));
  const results = [];
  const failures = [];
  settled.forEach((item, i) => {
    const market = needsFetch[i];
    if (item.status === "fulfilled") {
      storeValuationMarket(item.value);
      delete state.errors[`valuation_${market}`];
      results.push(item.value);
    } else {
      const message = item.reason?.message || String(item.reason);
      state.errors[`valuation_${market}`] = message;
      failures.push({ market, message });
    }
  });
  return { results, failures, skipped: [] };
}

function parseTwseSharesIssuedUniverse(data) {
  if (!data || !Array.isArray(data.data)) return {};
  const records = {};
  for (const row of data.data) {
    const code = String(row[0] || "").replace(/\s/g, "");
    if (!/^\d{4}$/.test(code)) continue;
    const sharesIssued = cellNumber(row[3]);
    if (sharesIssued === null || sharesIssued <= 0) continue;
    records[code] = {
      code,
      name: officialTextValue(row[1]),
      sharesIssued
    };
  }
  return records;
}

async function fetchTwseSharesIssuedUniverse(sourceDate = "", lookbackDays = 14) {
  const candidates = [];
  const compact = compactDayFromDateLabel(sourceDate);
  if (compact) candidates.push(compact);
  for (const { dateStr } of recentTradingDates(lookbackDays, 0)) {
    if (!candidates.includes(dateStr)) candidates.push(dateStr);
  }
  let lastError = null;
  for (const dateStr of candidates) {
    try {
      const url = `https://www.twse.com.tw/rwd/zh/fund/MI_QFIIS?response=json&date=${dateStr}&selectType=ALLBUT0999`;
      const data = JSON.parse(await fetchText(url));
      const shares = parseTwseSharesIssuedUniverse(data);
      if (Object.keys(shares).length) {
        return {
          sourceDate: parseCompactDay(data.date || dateStr) || parseCompactDay(dateStr),
          sourceLabel: "TWSE MI_QFIIS 發行股數",
          records: shares
        };
      }
    } catch (error) {
      lastError = error;
    }
    await wait(80);
  }
  throw lastError || new Error("TWSE 發行股數資料抓取失敗");
}

async function fetchTwseMarketCapBenchmark(twseValuationResult = null) {
  const valuationResult = twseValuationResult && twseValuationResult.universeRecords
    ? twseValuationResult
    : await fetchOfficialValuationsForMarket("TW");
  const sharesResult = await fetchTwseSharesIssuedUniverse(valuationResult.sourceDate);
  const rows = [];
  for (const [code, valuation] of Object.entries(valuationResult.universeRecords || {})) {
    const price = toNumber(valuation.close);
    const shares = sharesResult.records[code]?.sharesIssued;
    const marketCap100m = marketCapHundredMillion(price, shares);
    if (marketCap100m === null) continue;
    rows.push({
      code,
      name: valuation.name || sharesResult.records[code]?.name || "",
      price,
      sharesIssued: shares,
      marketCap100m
    });
  }
  rows.sort((a, b) => b.marketCap100m - a.marketCap100m);
  rows.forEach((row, index) => {
    row.rank = index + 1;
    const tier = marketCapTierFromRank(row.rank);
    row.tier = tier ? tier.key : "pending";
    row.tierLabel = tier ? tier.label : "市值待更新";
  });
  const atRank = (rank) => rows[rank - 1] || null;
  const benchmark = {
    sourceDate: valuationResult.sourceDate || sharesResult.sourceDate || "",
    sourceLabel: "TWSE 官方估值 + MI_QFIIS 發行股數",
    count: rows.length,
    thresholds: {
      largeTop: MARKET_CAP_TOP_LARGE,
      midTop: MARKET_CAP_TOP_MID,
      smallTop: MARKET_CAP_TOP_SMALL,
      largeFloor100m: atRank(MARKET_CAP_TOP_LARGE)?.marketCap100m ?? null,
      midFloor100m: atRank(MARKET_CAP_TOP_MID)?.marketCap100m ?? null,
      smallFloor100m: atRank(MARKET_CAP_TOP_SMALL)?.marketCap100m ?? null
    },
    recordsByCode: Object.fromEntries(rows.map((row) => [row.code, row])),
    fetchedAt: new Date().toISOString()
  };
  state.marketCapMeta = normalizeRecordMap(state.marketCapMeta);
  state.marketCapMeta.twseBenchmark = {
    sourceDate: benchmark.sourceDate,
    sourceLabel: benchmark.sourceLabel,
    count: benchmark.count,
    thresholds: benchmark.thresholds,
    fetchedAt: benchmark.fetchedAt
  };
  delete state.errors.marketCapBenchmark;
  return benchmark;
}

function normalizeMarketCapRecord(stock, data, benchmark = marketCapBenchmark()) {
  const marketCap100m = toNumber(data.marketCap100m);
  const rank = toNumber(data.rank);
  const rankTier = marketCapTierFromRank(rank);
  const valueTier = marketCapTierFromValue(marketCap100m, benchmark);
  const tier = rankTier || valueTier;
  return {
    code: stock.code,
    name: stock.name,
    market: stock.suffix === "TWO" ? "TWO" : "TW",
    price: toNumber(data.price),
    sharesIssued: toNumber(data.sharesIssued),
    marketCap100m,
    rank,
    tier: tier ? tier.key : "pending",
    tierLabel: tier ? tier.label : "市值待更新",
    tierRule: rankTier ? `集中市場市值第 ${rank} 名` : (tier ? "依 TWSE 集中市場 50/150/450 名門檻推估" : "資料不足"),
    sourceDate: data.sourceDate || benchmark?.sourceDate || "",
    sourceLabel: data.sourceLabel || benchmark?.sourceLabel || "本機市值推算",
    fetchedAt: new Date().toISOString()
  };
}

function updateMarketCapForStock(stock, options = {}) {
  if (!stock || String(stock.code || "").startsWith("00")) {
    if (stock) {
      state.marketCaps = normalizeRecordMap(state.marketCaps);
      state.marketCaps[stock.code] = {
        code: stock.code,
        name: stock.name,
        market: stock.suffix,
        tier: "etf",
        tierLabel: "ETF",
        tierRule: "ETF 不納入大型 / 中型 / 小型股分類",
        sourceDate: "",
        sourceLabel: "ETF",
        fetchedAt: new Date().toISOString()
      };
    }
    return null;
  }
  const benchmark = options.benchmark || marketCapBenchmark();
  const benchmarkRecord = options.benchmarkRecord || (options.benchmark?.recordsByCode || {})[stock.code] || null;
  state.marketCaps = normalizeRecordMap(state.marketCaps);
  if (benchmarkRecord) {
    const record = normalizeMarketCapRecord(stock, {
      ...benchmarkRecord,
      sourceDate: benchmark.sourceDate,
      sourceLabel: benchmark.sourceLabel
    }, benchmark);
    state.marketCaps[stock.code] = record;
    return record;
  }
  const price = stockPriceForMarketCap(stock);
  const sharesIssued = stockSharesIssued(stock);
  const marketCap100m = marketCapHundredMillion(price, sharesIssued);
  if (marketCap100m === null) return null;
  const record = normalizeMarketCapRecord(stock, {
    price,
    sharesIssued,
    marketCap100m,
    sourceDate: (state.foreignOwnership || {})[stock.code]?.date || "",
    sourceLabel: stock.suffix === "TWO" ? "TPEx 外資持股發行股數 + 最新報價" : "外資持股發行股數 + 最新報價"
  }, benchmark);
  state.marketCaps[stock.code] = record;
  return record;
}

async function refreshMarketCapProfile(stocks = WATCHLIST, options = {}) {
  state.marketCaps = normalizeRecordMap(state.marketCaps);
  state.marketCapMeta = normalizeRecordMap(state.marketCapMeta);
  const valuationSummary = options.valuationSummary || null;
  const twseValuationResult = (valuationSummary?.results || []).find((result) => result.market === "TW" && result.universeRecords) || null;
  let benchmark = null;
  try {
    benchmark = await fetchTwseMarketCapBenchmark(twseValuationResult);
  } catch (error) {
    const message = error && error.message ? error.message : String(error);
    state.errors.marketCapBenchmark = message;
    benchmark = marketCapBenchmark();
  }

  let tpexForeignData = null;
  if ((stocks || []).some((stock) => stock.suffix === "TWO")) {
    try {
      tpexForeignData = JSON.parse(await fetchText("https://www.tpex.org.tw/openapi/v1/tpex_3insti_qfii"));
    } catch (_) {
      tpexForeignData = null;
    }
  }

  let updated = 0;
  for (const stock of stocks || []) {
    if (stock.suffix === "TWO" && tpexForeignData) {
      const foreignOwn = parseForeignOwnershipTPEx(tpexForeignData, stock.code);
      if (foreignOwn) {
        state.foreignOwnership[stock.code] = foreignOwn;
        recordForeignOwnershipHistory(stock.code, foreignOwn);
      }
    }
    const record = updateMarketCapForStock(stock, {
      benchmark,
      benchmarkRecord: benchmark?.recordsByCode ? benchmark.recordsByCode[stock.code] : null
    });
    if (record) updated += 1;
  }
  return {
    updated,
    benchmarkSourceDate: benchmark?.sourceDate || state.marketCapMeta?.twseBenchmark?.sourceDate || "",
    benchmarkCount: benchmark?.count || state.marketCapMeta?.twseBenchmark?.count || 0,
    failed: Boolean(state.errors.marketCapBenchmark)
  };
}

function mergeKlines(existing, incoming) {
  const map = new Map();
  for (const row of [...(existing || []), ...(incoming || [])]) {
    const normalized = normalizeKline(row);
    if (normalized) map.set(normalized.date, normalized);
  }
  return [...map.values()]
    .sort((a, b) => a.date.localeCompare(b.date))
    .slice(-KLINE_RETENTION_BARS);
}

async function fetchOfficialKlines(stock) {
  const rows = [];
  for (const anchor of monthAnchors()) {
    const url = stock.suffix === "TWO" ? tpexTradingStockUrl(stock, anchor) : twseStockDayUrl(stock, anchor);
    const text = await fetchText(url);
    const parsed = stock.suffix === "TWO" ? parseTpexKlines(text, stock) : parseTwseKlines(text, stock);
    rows.push(...parsed);
    await wait(60);
  }
  if (!rows.length) throw new Error("官方日線無資料");
  return {
    rows: mergeKlines([], rows),
    source: stock.suffix === "TWO" ? "TPEx 官方日成交資訊" : "TWSE STOCK_DAY 官方日成交資訊",
    sourceKind: "official"
  };
}

async function fetchKlineHistory(stock) {
  try {
    return await fetchOfficialKlines(stock);
  } catch (officialError) {
    try {
      const text = await fetchText(yahooHistoryUrl(stock));
      const rows = parseYahooKlines(text, stock);
      if (!rows.length) throw new Error("Yahoo K 線無資料");
      return {
        rows,
        source: "Yahoo Finance history fallback",
        sourceKind: "fallback",
        officialError: officialError && officialError.message ? officialError.message : String(officialError)
      };
    } catch (fallbackError) {
      throw new Error(`日線抓取失敗：${fallbackError && fallbackError.message ? fallbackError.message : fallbackError}`);
    }
  }
}

async function fetchKlineHistoryFast(stock) {
  try {
    const text = await fetchText(yahooHistoryUrl(stock));
    const rows = parseYahooKlines(text, stock);
    if (!rows.length) throw new Error("Yahoo K 線無資料");
    return {
      rows,
      source: "Yahoo Finance history fast mode",
      sourceKind: "fast-yahoo"
    };
  } catch (fastError) {
    const official = await fetchOfficialKlines(stock);
    return {
      ...official,
      fastError: fastError && fastError.message ? fastError.message : String(fastError)
    };
  }
}

function storeKlines(stock, result) {
  const rows = mergeKlines(state.klines[stock.code] || [], result.rows || []);
  state.klines[stock.code] = compactKlineRows(rows.map((row) => ({
    ...row,
    source: row.source || result.source
  })));
  persistKlinesToIdb(stock.code, state.klines[stock.code]);
  state.klineUpdatedAt = new Date().toISOString();
}

function injectQuoteAsKline(stock, quote) {
  if (!quote || !quote.price || !quote.sourceDate || !stock) return;
  const existing = latestKlines(stock.code);
  if (existing.find((r) => r.date === quote.sourceDate)) return; // already have today
  const row = normalizeKline({
    date: quote.sourceDate,
    open:   quote.open   ?? quote.price,
    high:   quote.high   ?? quote.price,
    low:    quote.low    ?? quote.price,
    close:  quote.price,
    volume: quote.volume ?? 0,
    source: "MIS 盤中注入"
  });
  if (row) storeKlines(stock, { rows: [row], source: "MIS 盤中注入" });
}

function latestKlines(code) {
  const rows = Array.isArray(state.klines[code]) ? state.klines[code] : [];
  if (!rows.length) queueKlineHydration([code], "latestKlines");
  return rows;
}

const _technicalDerivedCache = new Map();

function klineMemoSignature(code, rows) {
  if (!Array.isArray(rows)) return `${code}|none`;
  const first = rows[0] || {};
  const anchor20 = rows[Math.max(0, rows.length - 20)] || {};
  const anchor60 = rows[Math.max(0, rows.length - 60)] || {};
  const previous = rows.at(-2) || {};
  const latest = rows.at(-1) || {};
  return [
    code,
    rows.length,
    first.date || "",
    anchor60.date || "",
    anchor60.close ?? "",
    anchor20.date || "",
    anchor20.close ?? "",
    previous.date || "",
    previous.close ?? "",
    latest.date || "",
    latest.open ?? "",
    latest.high ?? "",
    latest.low ?? "",
    latest.close ?? "",
    latest.volume ?? ""
  ].join("|");
}

function rememberTechnicalDerived(key, value) {
  if (!key) return value;
  _technicalDerivedCache.set(key, value);
  if (_technicalDerivedCache.size > TECHNICAL_DERIVED_CACHE_LIMIT) {
    const overflow = _technicalDerivedCache.size - TECHNICAL_DERIVED_CACHE_LIMIT;
    let removed = 0;
    for (const cacheKey of _technicalDerivedCache.keys()) {
      _technicalDerivedCache.delete(cacheKey);
      removed += 1;
      if (removed >= overflow) break;
    }
  }
  return value;
}

function average(values) {
  const usable = values.filter((value) => Number.isFinite(value));
  if (!usable.length) return null;
  return usable.reduce((sum, value) => sum + value, 0) / usable.length;
}

function sma(values, period) {
  if (!Array.isArray(values) || values.length < period) return null;
  return average(values.slice(-period));
}

function smaSeries(values, period) {
  return values.map((_, index) => {
    if (index + 1 < period) return null;
    return average(values.slice(index + 1 - period, index + 1));
  });
}

function emaSeries(values, period) {
  if (!Array.isArray(values) || !values.length) return [];
  const smoothing = 2 / (period + 1);
  const series = [];
  let previous = values[0];
  for (const value of values) {
    previous = value * smoothing + previous * (1 - smoothing);
    series.push(previous);
  }
  return series;
}

function rsi(values, period = 14) {
  if (!Array.isArray(values) || values.length <= period) return null;
  const changes = [];
  for (let index = 1; index < values.length; index += 1) {
    changes.push(values[index] - values[index - 1]);
  }
  const recent = changes.slice(-period);
  const gains = recent.map((value) => Math.max(value, 0));
  const losses = recent.map((value) => Math.max(-value, 0));
  const avgGain = average(gains) ?? 0;
  const avgLoss = average(losses) ?? 0;
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - (100 / (1 + rs));
}

// ─── ATR (Average True Range, Wilder's smoothing) ─────────────────────────
// 用於波動率衡量與停損設置（2 ATR 為常見值）
function atrSeries(rows, period = 14) {
  if (!Array.isArray(rows) || rows.length < period + 1) return [];
  const trs = [];
  for (let i = 0; i < rows.length; i++) {
    if (i === 0) {
      trs.push(rows[i].high - rows[i].low);
      continue;
    }
    const prev = rows[i - 1];
    const curr = rows[i];
    trs.push(Math.max(
      curr.high - curr.low,
      Math.abs(curr.high - prev.close),
      Math.abs(curr.low - prev.close)
    ));
  }
  const out = new Array(rows.length).fill(null);
  // Wilder seed: simple average of first `period` TRs
  let prevAtr = trs.slice(0, period).reduce((a, b) => a + b, 0) / period;
  out[period - 1] = prevAtr;
  for (let i = period; i < trs.length; i++) {
    prevAtr = (prevAtr * (period - 1) + trs[i]) / period;
    out[i] = prevAtr;
  }
  return out;
}

function atr(rows, period = 14) {
  const s = atrSeries(rows, period);
  return s.length ? s[s.length - 1] : null;
}

// ─── Divergence Detection (price vs indicator) ─────────────────────────────
// 偵測局部極值並比對價格與指標序列的背離關係
function findLocalPivots(values, window = 5) {
  const highs = [];
  const lows = [];
  if (!Array.isArray(values)) return { highs, lows };
  for (let i = window; i < values.length - window; i++) {
    const v = values[i];
    if (v === null || !Number.isFinite(v)) continue;
    let isHigh = true;
    let isLow = true;
    for (let j = i - window; j <= i + window; j++) {
      if (j === i) continue;
      const vj = values[j];
      if (vj === null || !Number.isFinite(vj)) {
        isHigh = false;
        isLow = false;
        break;
      }
      if (vj >= v) isHigh = false;
      if (vj <= v) isLow = false;
    }
    if (isHigh) highs.push({ index: i, value: v });
    if (isLow) lows.push({ index: i, value: v });
  }
  return { highs, lows };
}

function detectDivergence(rows, indicatorSeries, lookback = 60) {
  if (!Array.isArray(rows) || rows.length < lookback || !Array.isArray(indicatorSeries)) return null;
  const sliceStart = rows.length - lookback;
  const priceCloses = rows.slice(sliceStart).map((r) => r.close);
  const indicator = indicatorSeries.slice(sliceStart);
  const pricePivots = findLocalPivots(priceCloses, 4);
  const indPivots = findLocalPivots(indicator, 4);
  const bullish = (() => {
    if (pricePivots.lows.length < 2 || indPivots.lows.length < 2) return null;
    const p1 = pricePivots.lows.at(-2);
    const p2 = pricePivots.lows.at(-1);
    const i1 = indPivots.lows.find((x) => Math.abs(x.index - p1.index) <= 3);
    const i2 = indPivots.lows.find((x) => Math.abs(x.index - p2.index) <= 3);
    if (!i1 || !i2) return null;
    return p2.value < p1.value && i2.value > i1.value ? { type: "bullish", p1, p2, i1, i2 } : null;
  })();
  const bearish = (() => {
    if (pricePivots.highs.length < 2 || indPivots.highs.length < 2) return null;
    const p1 = pricePivots.highs.at(-2);
    const p2 = pricePivots.highs.at(-1);
    const i1 = indPivots.highs.find((x) => Math.abs(x.index - p1.index) <= 3);
    const i2 = indPivots.highs.find((x) => Math.abs(x.index - p2.index) <= 3);
    if (!i1 || !i2) return null;
    return p2.value > p1.value && i2.value < i1.value ? { type: "bearish", p1, p2, i1, i2 } : null;
  })();
  return { bullish, bearish };
}

// ─── Candlestick Patterns ──────────────────────────────────────────────────
// 簡易型態偵測：十字星、錘子線、流星、多空頭吞噬
function detectCandlePatterns(rows) {
  if (!Array.isArray(rows) || rows.length < 3) return [];
  const out = [];
  const latest = rows.at(-1);
  const prev = rows.at(-2);
  if (!latest || typeof latest.open !== "number" || typeof latest.close !== "number") return [];
  const body = Math.abs(latest.close - latest.open);
  const range = latest.high - latest.low;
  if (!Number.isFinite(range) || range <= 0) return [];
  const upperShadow = latest.high - Math.max(latest.open, latest.close);
  const lowerShadow = Math.min(latest.open, latest.close) - latest.low;
  // 5-day prior trend (excluding latest)
  const trendCloses = rows.slice(-7, -1).map((r) => r.close).filter((v) => Number.isFinite(v));
  const priorTrend = trendCloses.length >= 4 && trendCloses[0]
    ? (trendCloses.at(-1) - trendCloses[0]) / trendCloses[0]
    : 0;
  // 十字星
  if (body < range * 0.1) {
    out.push({ name: "十字星", type: "indecision", note: "多空力道接近，待方向選擇" });
  }
  // 錘子線
  if (lowerShadow > body * 2 && upperShadow < body * 0.5 && body > 0) {
    if (priorTrend < -0.03) {
      out.push({ name: "錘子線", type: "bullish", note: "下跌段末見錘子，可能止跌" });
    } else {
      out.push({ name: "錘子線", type: "neutral", note: "錘子線型態（趨勢不明顯）" });
    }
  }
  // 流星
  if (upperShadow > body * 2 && lowerShadow < body * 0.5 && body > 0) {
    if (priorTrend > 0.03) {
      out.push({ name: "流星", type: "bearish", note: "高檔流星，留意反轉" });
    } else {
      out.push({ name: "流星", type: "neutral", note: "流星線型態（趨勢不明顯）" });
    }
  }
  // 多頭吞噬
  if (prev && latest.close > latest.open && prev.close < prev.open) {
    if (latest.open <= prev.close && latest.close >= prev.open) {
      out.push({ name: "多頭吞噬", type: "bullish", note: "陽包陰，強烈反轉訊號" });
    }
  }
  // 空頭吞噬
  if (prev && latest.close < latest.open && prev.close > prev.open) {
    if (latest.open >= prev.close && latest.close <= prev.open) {
      out.push({ name: "空頭吞噬", type: "bearish", note: "陰包陽，強烈反轉訊號" });
    }
  }
  return out;
}

// v7.8 Feature 2：歷史 K 棒型態檢測（逐日 slice 後重跑 detectCandlePatterns）
// 回傳格式：[{ name, type, note, index, date, price, high, low }, ...]
function detectCandlePatternsHistory(rows, lookback = 60) {
  if (!Array.isArray(rows) || rows.length < 10) return [];
  const start = Math.max(2, rows.length - lookback);
  const out = [];
  for (let i = start; i < rows.length; i++) {
    const partial = rows.slice(0, i + 1);
    let patterns = [];
    try { patterns = detectCandlePatterns(partial); } catch (_) { patterns = []; }
    if (patterns.length) {
      for (const p of patterns) {
        out.push({
          ...p,
          index: i,
          date: rows[i].date,
          price: rows[i].close,
          high: rows[i].high,
          low: rows[i].low
        });
      }
    }
  }
  return out;
}

// ─── Ichimoku Cloud (一目均衡表) ────────────────────────────────────────────
function calculateIchimoku(rows) {
  if (!Array.isArray(rows) || rows.length < 52) return null;
  const periodHL = (i, period) => {
    const slice = rows.slice(Math.max(0, i - period + 1), i + 1);
    return (Math.max(...slice.map((r) => r.high)) + Math.min(...slice.map((r) => r.low))) / 2;
  };
  const last = rows.length - 1;
  const tenkan = periodHL(last, 9);
  const kijun = periodHL(last, 26);
  const senkouA = (tenkan + kijun) / 2;
  const senkouB = periodHL(last, 52);
  const chikou = rows[last].close;
  const cloudTop = Math.max(senkouA, senkouB);
  const cloudBottom = Math.min(senkouA, senkouB);
  const close = rows[last].close;
  const priceVsCloud = close > cloudTop
    ? "雲上(多頭)"
    : close < cloudBottom
      ? "雲下(空頭)"
      : "雲中(盤整)";
  return { tenkan, kijun, senkouA, senkouB, chikou, cloudTop, cloudBottom, priceVsCloud };
}

// ─── Ichimoku Series (v7.7 一目均衡表逐根序列，供雲層繪製) ───────────────────
function calculateIchimokuSeries(rows) {
  if (!Array.isArray(rows) || rows.length < 52) return null;
  const periodHL = (i, period) => {
    if (i < period - 1) return null;
    const slice = rows.slice(i - period + 1, i + 1);
    const highs = slice.map((r) => r.high).filter(Number.isFinite);
    const lows = slice.map((r) => r.low).filter(Number.isFinite);
    if (!highs.length || !lows.length) return null;
    return (Math.max(...highs) + Math.min(...lows)) / 2;
  };
  const tenkan = rows.map((_, i) => periodHL(i, 9));
  const kijun = rows.map((_, i) => periodHL(i, 26));
  const senkouB = rows.map((_, i) => periodHL(i, 52));
  // SenkouA = (tenkan + kijun) / 2，視覺上需向前位移 26 根；序列保留「當日」值，
  // 由繪圖時用 i-26 來取得「shifted forward to i」的雲層。
  const senkouA = tenkan.map((t, i) => (t != null && kijun[i] != null) ? (t + kijun[i]) / 2 : null);
  return { tenkan, kijun, senkouA, senkouB };
}

// ─── Fibonacci Retracement ─────────────────────────────────────────────────
function calculateFibonacci(rows, lookback = 60) {
  if (!Array.isArray(rows) || rows.length < lookback) return null;
  const slice = rows.slice(-lookback);
  const high = Math.max(...slice.map((r) => r.high));
  const low = Math.min(...slice.map((r) => r.low));
  const diff = high - low;
  if (!Number.isFinite(diff) || diff <= 0) return null;
  return {
    high,
    low,
    range: diff,
    levels: [
      { name: "0.000 (最低)", value: low },
      { name: "0.236", value: low + diff * 0.236 },
      { name: "0.382", value: low + diff * 0.382 },
      { name: "0.500", value: low + diff * 0.5 },
      { name: "0.618 (黃金)", value: low + diff * 0.618 },
      { name: "0.786", value: low + diff * 0.786 },
      { name: "1.000 (最高)", value: high }
    ]
  };
}

// ─── Volume Profile (價量分佈) ─────────────────────────────────────────────
function calculateVolumeProfile(rows, buckets = 12) {
  if (!Array.isArray(rows) || rows.length < 10) return null;
  const lows = rows.map((r) => r.low).filter((v) => Number.isFinite(v));
  const highs = rows.map((r) => r.high).filter((v) => Number.isFinite(v));
  if (!lows.length || !highs.length) return null;
  const min = Math.min(...lows);
  const max = Math.max(...highs);
  if (max <= min) return null;
  const bucketSize = (max - min) / buckets;
  const profile = Array.from({ length: buckets }, (_, i) => ({
    priceLow: min + i * bucketSize,
    priceHigh: min + (i + 1) * bucketSize,
    volume: 0
  }));
  for (const row of rows) {
    const mid = (row.high + row.low) / 2;
    if (!Number.isFinite(mid)) continue;
    const idx = Math.min(buckets - 1, Math.max(0, Math.floor((mid - min) / bucketSize)));
    profile[idx].volume += row.volume || 0;
  }
  const maxVol = Math.max(...profile.map((b) => b.volume), 1);
  const poc = profile.reduce((m, b) => (b.volume > m.volume ? b : m));
  return { profile, maxVol, poc, priceMin: min, priceMax: max };
}

function standardDeviation(values) {
  const mean = average(values);
  if (mean === null) return null;
  const variance = average(values.map((value) => (value - mean) ** 2));
  return variance === null ? null : Math.sqrt(variance);
}

// ─── 大盤指數 (TAIEX ^TWII) ────────────────────────────────────────────────

function taiexKlines() {
  return Array.isArray(state.klines["^TWII"]) ? state.klines["^TWII"] : [];
}

async function fetchTaiexKlines() {
  const url = "https://query1.finance.yahoo.com/v8/finance/chart/%5ETWII?interval=1d&range=6mo";
  const text = await fetchText(url);
  const json = JSON.parse(text);
  const result = json?.chart?.result?.[0];
  const timestamps = result?.timestamp || [];
  const quote = result?.indicators?.quote?.[0];
  if (!timestamps.length || !quote) return [];
  return timestamps.map((ts, i) => normalizeKline({
    date: new Date(ts * 1000).toISOString().slice(0, 10),
    open: quote.open?.[i],
    high: quote.high?.[i],
    low: quote.low?.[i],
    close: quote.close?.[i],
    volume: quote.volume?.[i],
    source: "Yahoo ^TWII"
  })).filter(Boolean);
}

// ─── 月營收（MOPS t187ap05 CSV canonical，OpenAPI fallback） ───────────────

function revenueFor(code) {
  return (state.revenue || {})[code] || null;
}

function parseNum(s) {
  return toNumber(String(s || "").replace(/,/g, "")) ?? null;
}

function monthKeyFromRevenueRow(row, fallbackDate = new Date()) {
  const keys = ["資料年月", "營收年月", "年月", "出表年月", "出表日期", "Date", "RevenueMonth", "YearMonth"];
  for (const key of keys) {
    const raw = String(row?.[key] || "").trim();
    const monthKey = normalizeMonthKey(raw);
    if (monthKey) return monthKey;
    const rocMatch = raw.match(/^(\d{2,3})\D+(\d{1,2})/);
    if (rocMatch) {
      const rocYear = Number(rocMatch[1]);
      const rocMonth = Number(rocMatch[2]);
      if (rocYear > 0 && rocMonth >= 1 && rocMonth <= 12) {
        return `${rocYear + 1911}-${String(rocMonth).padStart(2, "0")}`;
      }
    }
  }
  const year = toNumber(row?.["年度"] || row?.["年"] || row?.["Year"]);
  const month = toNumber(row?.["月份"] || row?.["月"] || row?.["Month"]);
  if (year !== null && month !== null && month >= 1 && month <= 12) {
    const fullYear = year < 1911 ? year + 1911 : year;
    return `${fullYear}-${String(Math.round(month)).padStart(2, "0")}`;
  }
  const fallback = fallbackDate instanceof Date ? fallbackDate : new Date(fallbackDate || Date.now());
  if (Number.isNaN(fallback.getTime())) return "";
  return shiftMonthKey(fallback.getUTCFullYear(), fallback.getUTCMonth() + 1, -1);
}

function rowFirstValue(row, keys) {
  for (const key of keys) {
    const value = row?.[key];
    const text = officialTextValue(value);
    if (text) return value;
  }
  return "";
}

function monthlyRevenueSourceLabel(market, fallbackUsed = false) {
  if (fallbackUsed) {
    return market === "listed" ? "TWSE monthlyRevenue OpenAPI" : "TPEx mtp_aabc_otc OpenAPI";
  }
  return market === "listed" ? "MOPS t187ap05_L 月營收 CSV" : "MOPS t187ap05_O 月營收 CSV";
}

function monthlyRevenueSourceUrl(market, fallbackUsed = false) {
  if (fallbackUsed) {
    return market === "listed" ? MONTHLY_REVENUE_SOURCE_LINKS.twseOpenApi : MONTHLY_REVENUE_SOURCE_LINKS.tpexOpenApi;
  }
  return market === "listed" ? MONTHLY_REVENUE_SOURCE_LINKS.listed : MONTHLY_REVENUE_SOURCE_LINKS.otc;
}

function normalizeMonthlyRevenueRow(row, fetchedAt, market, options = {}) {
  const yearMonth = monthKeyFromRevenueRow(row, fetchedAt);
  const fallbackUsed = options.fallbackUsed === true;
  return {
    current: parseNum(rowFirstValue(row, ["營業收入-當月營收", "當月營收", "Revenue"])),
    prevMonth: parseNum(rowFirstValue(row, ["營業收入-上月營收", "上月營收"])),
    prevYear: parseNum(rowFirstValue(row, ["營業收入-去年當月營收", "去年當月營收"])),
    momPct: parseNum(rowFirstValue(row, ["營業收入-上月比較增減(%)", "上月比較增減(%)", "MoM(%)"])),
    yoyPct: parseNum(rowFirstValue(row, ["營業收入-去年同月增減(%)", "去年同月增減(%)", "YoY(%)"])),
    cumulative: parseNum(rowFirstValue(row, ["累計營業收入-當月累計營收", "當月累計營收"])),
    cumulativePrevYear: parseNum(rowFirstValue(row, ["累計營業收入-去年累計營收", "去年累計營收"])),
    cumYoyPct: parseNum(rowFirstValue(row, ["累計營業收入-前期比較增減(%)", "前期比較增減(%)"])),
    yearMonth,
    sourceDate: parseRocCompactDate(row["出表日期"]),
    companyName: String(row["公司名稱"] || row["Name"] || "").trim(),
    industry: String(row["產業別"] || row["Industry"] || "").trim(),
    note: String(row["備註"] || row["Note"] || "").trim(),
    source: options.source || monthlyRevenueSourceLabel(market, fallbackUsed),
    sourceUrl: options.sourceUrl || monthlyRevenueSourceUrl(market, fallbackUsed),
    sourceTier: "Tier 1 官方",
    fallbackUsed,
    fetchedAt
  };
}

function monthlyRevenueRowsFromCsv(text, source, fetchedAt) {
  return parseCsvTable(text).map((row) => {
    const code = String(row["公司代號"] || "").trim().toUpperCase();
    if (!code || !STOCK_MAP.has(code)) return null;
    return {
      code,
      row: normalizeMonthlyRevenueRow(row, fetchedAt, source.market, {
        source: source.label,
        sourceUrl: source.url,
        fallbackUsed: false
      })
    };
  }).filter(Boolean);
}

function monthlyRevenueRowsFromJson(text, source, fetchedAt) {
  const rows = JSON.parse(text);
  if (!Array.isArray(rows)) throw new Error("回傳不是 JSON array");
  return rows.map((row) => {
    const code = String(row["公司代號"] || row["CompanyID"] || "").trim().toUpperCase();
    if (!code || !STOCK_MAP.has(code)) return null;
    return {
      code,
      row: normalizeMonthlyRevenueRow(row, fetchedAt, source.market, {
        source: source.label,
        sourceUrl: source.url,
        fallbackUsed: true
      })
    };
  }).filter(Boolean);
}

function monthlyRevenueMissingHoldings(nextRevenue) {
  const missingByCode = {};
  const missingHoldings = (state.holdings || [])
    .map((entry) => normalizeHoldingEntry(entry))
    .filter((holding) => holding && !isEtfCode(holding.code) && !nextRevenue[holding.code])
    .map((holding) => {
      const reason = "MOPS t187ap05 未含此代號；可能尚未公告、非普通股、公司代號 / 市場別需複核，或本機尚未成功更新。";
      missingByCode[holding.code] = reason;
      return { code: holding.code, name: holding.name, reason };
    });
  return { missingHoldings, missingByCode };
}

function latestMonthlyRevenuePeriod(revenueMap = state.revenue) {
  return Object.values(normalizeRecordMap(revenueMap))
    .map((row) => normalizeMonthKey(row?.yearMonth || row?.period || row?.date))
    .filter(Boolean)
    .sort()
    .at(-1) || "";
}

function monthlyRevenueRefreshDecision(options = {}) {
  const force = options.force === true;
  const latest = latestMonthlyRevenuePeriod();
  const expected = expectedRevenueMonthKey();
  const fetchedAtMs = Date.parse(state.revenueMeta?.fetchedAt || "");
  const recentlyChecked = Number.isFinite(fetchedAtMs) && Date.now() - fetchedAtMs < MONTHLY_REVENUE_RECHECK_TTL_MS;
  if (force) return { shouldFetch: true, reason: "manual-force", latest, expected };
  if (latest && expected && latest >= expected) {
    return { shouldFetch: false, reason: "current-period-ready", latest, expected };
  }
  if (recentlyChecked) {
    return { shouldFetch: false, reason: "recently-checked", latest, expected };
  }
  return { shouldFetch: true, reason: latest ? "period-missing" : "no-data", latest, expected };
}

async function fetchMonthlyRevenue() {
  syncCurrentHoldingsTheme();
  const fetchedAt = new Date().toISOString();
  const nextRevenue = { ...(state.revenue || {}) };
  const errors = [];
  const sources = [];
  const marketCounts = { listed: 0, otc: 0 };
  const primarySources = [
    { market: "listed", label: "MOPS t187ap05_L 月營收 CSV", url: MONTHLY_REVENUE_SOURCE_LINKS.listed, parser: monthlyRevenueRowsFromCsv },
    { market: "otc", label: "MOPS t187ap05_O 月營收 CSV", url: MONTHLY_REVENUE_SOURCE_LINKS.otc, parser: monthlyRevenueRowsFromCsv }
  ];
  const fallbackSources = [
    { market: "listed", label: "TWSE monthlyRevenue OpenAPI", url: MONTHLY_REVENUE_SOURCE_LINKS.twseOpenApi, parser: monthlyRevenueRowsFromJson },
    { market: "otc", label: "TPEx mtp_aabc_otc OpenAPI", url: MONTHLY_REVENUE_SOURCE_LINKS.tpexOpenApi, parser: monthlyRevenueRowsFromJson }
  ];

  for (const source of primarySources) {
    try {
      const text = await fetchText(source.url, { timeoutMs: 15000 });
      const rows = source.parser(text, source, fetchedAt);
      for (const item of rows) nextRevenue[item.code] = item.row;
      marketCounts[source.market] += rows.length;
      sources.push({ label: source.label, market: source.market, url: source.url, count: rows.length, fallbackUsed: false });
    } catch (error) {
      errors.push(`${source.label}: ${error?.message || String(error)}`);
      sources.push({ label: source.label, market: source.market, url: source.url, count: 0, fallbackUsed: false, error: error?.message || String(error) });
    }
  }

  for (const source of fallbackSources.filter((item) => marketCounts[item.market] === 0)) {
    try {
      const text = await fetchText(source.url, { timeoutMs: 12000 });
      const rows = source.parser(text, source, fetchedAt);
      for (const item of rows) nextRevenue[item.code] = item.row;
      marketCounts[source.market] += rows.length;
      sources.push({ label: source.label, market: source.market, url: source.url, count: rows.length, fallbackUsed: true });
    } catch (error) {
      errors.push(`${source.label}: ${error?.message || String(error)}`);
      sources.push({ label: source.label, market: source.market, url: source.url, count: 0, fallbackUsed: true, error: error?.message || String(error) });
    }
  }

  const count = marketCounts.listed + marketCounts.otc;
  const { missingHoldings, missingByCode } = monthlyRevenueMissingHoldings(nextRevenue);
  state.revenue = nextRevenue;
  state.revenueMeta = {
    fetchedAt,
    sourceSummary: `MOPS 月營收 t187ap05：上市 ${formatNumber(marketCounts.listed, 0)} 檔、上櫃 ${formatNumber(marketCounts.otc, 0)} 檔追蹤資料；持股缺 ${formatNumber(missingHoldings.length, 0)} 檔。`,
    sources,
    errors,
    missingHoldings,
    missingByCode
  };
  if (!count) throw new Error(errors.length ? errors.join("；") : "MOPS / OpenAPI 月營收皆未取得追蹤股票");

  // 累積月營收歷史；長期資料層保留最多 36 個月。
  state.revenueHistory = state.revenueHistory || {};
  for (const [code, rev] of Object.entries(state.revenue)) {
    if (!rev || typeof rev !== "object" || Array.isArray(rev)) continue;
    const yearMonth = normalizeMonthKey(rev.yearMonth || rev.period || rev.date) || fetchedAt.slice(0, 7);
    const hist = Array.isArray(state.revenueHistory[code]) ? state.revenueHistory[code] : [];
    const nextRow = {
      yearMonth,
      yoyPct: toNumber(rev.yoyPct),
      momPct: toNumber(rev.momPct),
      current: toNumber(rev.current),
      source: rev.source || "MOPS t187ap05 月營收",
      sourceUrl: rev.sourceUrl || "",
      sourceTier: rev.sourceTier || "Tier 1 官方",
      fallbackUsed: rev.fallbackUsed === true,
      fetchedAt: rev.fetchedAt || fetchedAt
    };
    const existingIndex = hist.findIndex((row) => normalizeMonthKey(row?.yearMonth) === yearMonth);
    if (existingIndex >= 0) hist[existingIndex] = { ...hist[existingIndex], ...nextRow };
    else hist.push(nextRow);
    hist.sort((a, b) => String(a.yearMonth).localeCompare(String(b.yearMonth)));
    state.revenueHistory[code] = hist.slice(-REVENUE_HISTORY_MONTH_LIMIT);
  }
  return { count, marketCounts, errors, missingHoldings };
}

function revenueHistorySparkHtml(code) {
  const hist = (state.revenueHistory || {})[code];
  if (!Array.isArray(hist) || hist.length < 3) return "";
  const rows = hist.map((r) => ({ close: r.yoyPct ?? 0 }));
  const latestYoy = rows.at(-1)?.close ?? 0;
  const path = sparklinePath(rows, 120, 28);
  if (!path) return "";
  return `<svg viewBox="0 0 120 28" preserveAspectRatio="none" style="width:80px;height:18px;vertical-align:middle;margin-left:4px;" aria-label="月收 YoY 趨勢">
    <path d="${path}" fill="none" stroke="${latestYoy > 0 ? "var(--bad)" : "var(--good)"}" stroke-width="1.5" />
  </svg>`;
}

async function updateMonthlyRevenue(options = {}) {
  const normalizedOptions = options && typeof options === "object" && !("type" in options) ? options : {};
  const decision = monthlyRevenueRefreshDecision({ force: normalizedOptions.force !== false });
  if (!decision.shouldFetch) {
    const reason = decision.reason === "current-period-ready"
      ? `已有預期公告月份 ${decision.latest}`
      : `最近 ${MONTHLY_REVENUE_RECHECK_TTL_MS / 60 / 60 / 1000} 小時已檢查`;
    setStatus(`月營收沿用長期快取：${reason}，本次不重複下載。`, "good");
    return { count: Object.keys(state.revenue || {}).length, skipped: true, decision };
  }
  setBusy(true, "更新月營收資料...");
  try {
    const result = await fetchMonthlyRevenue();
    await saveState();
    await persistResearchDataLayer("monthly-revenue");
    render();
    const missingText = result.missingHoldings.length ? `；目前持股缺 ${result.missingHoldings.length} 檔` : "";
    setStatus(`月營收更新完成：${result.count} 檔追蹤股有資料${missingText}。`, result.missingHoldings.length ? "warn" : "good");
  } catch (e) {
    setStatus(`月營收更新失敗：${e.message || e}`, "error");
  } finally {
    setBusy(false);
  }
}

function quarterlyMarginMissingHoldings(nextRatios = state.financialRatios) {
  const missingByCode = {};
  const missingHoldings = (state.holdings || [])
    .map((entry) => normalizeHoldingEntry(entry))
    .filter((holding) => holding && isTripleMarginEligibleStock(STOCK_MAP.get(holding.code) || holding))
    .filter((holding) => {
      const raw = nextRatios?.[holding.code];
      const rows = Array.isArray(raw) ? raw : Array.isArray(raw?.rows) ? raw.rows : Array.isArray(raw?.history) ? raw.history : [];
      return rows.length < 2;
    })
    .map((holding) => {
      const reason = "缺至少兩季毛利率 / 營益率 / 淨利率；請匯入 MOPS 季損益表或已整理三率 CSV。";
      missingByCode[holding.code] = reason;
      return { code: holding.code, name: holding.name, reason };
    });
  return { missingHoldings, missingByCode };
}

function applyQuarterlyMarginRows(rows, source = {}) {
  const fetchedAt = source.fetchedAt || new Date().toISOString();
  const grouped = {};
  for (const row of rows || []) {
    if (!row?.code || !row.period) continue;
    grouped[row.code] = grouped[row.code] || [];
    grouped[row.code].push({ ...row, fetchedAt: row.fetchedAt || fetchedAt });
  }
  const nextRatios = { ...(state.financialRatios || {}) };
  for (const [code, incomingRows] of Object.entries(grouped)) {
    const existingRaw = nextRatios[code];
    const existingRows = Array.isArray(existingRaw) ? existingRaw : Array.isArray(existingRaw?.rows) ? existingRaw.rows : Array.isArray(existingRaw?.history) ? existingRaw.history : [];
    const byPeriod = new Map();
    for (const row of existingRows) {
      const period = normalizeQuarterKey(row.period || row.quarter || row.yearQuarter || row.date);
      if (period) byPeriod.set(period, { ...row, period });
    }
    for (const row of incomingRows) byPeriod.set(row.period, row);
    const mergedRows = [...byPeriod.values()]
      .sort((a, b) => String(a.period).localeCompare(String(b.period)))
      .slice(-QUARTERLY_MARGIN_RETENTION_QUARTERS);
    nextRatios[code] = {
      source: source.label || incomingRows.at(-1)?.source || "MOPS 季損益表匯入",
      sourceTier: source.sourceTier || incomingRows.at(-1)?.sourceTier || "Tier 1 官方 / 本機匯入",
      sourceUrl: source.url || incomingRows.at(-1)?.sourceUrl || FINANCIAL_MARGIN_SOURCE_LINKS.mopsFinancials,
      fetchedAt,
      rows: mergedRows
    };
  }
  const { missingHoldings, missingByCode } = quarterlyMarginMissingHoldings(nextRatios);
  const importedCount = Object.values(grouped).reduce((sum, list) => sum + list.length, 0);
  state.financialRatios = nextRatios;
  state.financialRatioMeta = {
    fetchedAt,
    sourceSummary: `季財報三率：匯入 ${formatNumber(Object.keys(grouped).length, 0)} 檔 / ${formatNumber(importedCount, 0)} 筆；持股待補 ${formatNumber(missingHoldings.length, 0)} 檔。`,
    sources: [{ label: source.label || "MOPS 季損益表匯入", url: source.url || FINANCIAL_MARGIN_SOURCE_LINKS.mopsFinancials, count: importedCount, fallbackUsed: source.fallbackUsed === true }],
    errors: [],
    missingHoldings,
    missingByCode
  };
  return { codeCount: Object.keys(grouped).length, rowCount: importedCount, missingHoldings };
}

async function importQuarterlyMarginsFromFile(file) {
  if (!file) return null;
  const fetchedAt = new Date().toISOString();
  const text = await file.text();
  const rows = quarterlyMarginRowsFromCsv(text, {
    label: `MOPS 季損益表匯入：${file.name || "local CSV"}`,
    url: FINANCIAL_MARGIN_SOURCE_LINKS.mopsFinancials,
    sourceTier: "Tier 1 官方 / 本機匯入"
  }, fetchedAt);
  if (!rows.length) throw new Error("CSV 未解析到公司代號、期間與三率 / 損益表欄位");
  const result = applyQuarterlyMarginRows(rows, {
    label: `MOPS 季損益表匯入：${file.name || "local CSV"}`,
    url: FINANCIAL_MARGIN_SOURCE_LINKS.mopsFinancials,
    sourceTier: "Tier 1 官方 / 本機匯入",
    fetchedAt
  });
  await saveState();
  await persistResearchDataLayer("quarterly-margins");
  render();
  const missingText = result.missingHoldings.length ? `；持股待補 ${result.missingHoldings.length} 檔` : "";
  setStatus(`三率匯入完成：${result.codeCount} 檔 / ${result.rowCount} 筆${missingText}。`, result.missingHoldings.length ? "warn" : "good");
  return result;
}

function promptQuarterlyMarginImport() {
  const input = document.createElement("input");
  input.type = "file";
  input.accept = ".csv,text/csv";
  input.style.display = "none";
  input.addEventListener("change", () => {
    const file = input.files && input.files[0];
    importQuarterlyMarginsFromFile(file)
      .catch((error) => setStatus(`三率匯入失敗：${error?.message || String(error)}`, "error"))
      .finally(() => input.remove());
  }, { once: true });
  document.body.appendChild(input);
  input.click();
}

function twseExDividendApiUrl(startDate = localDateKey(), endDate = addMonthsToDateKey(startDate, 2)) {
  return `${EX_DIVIDEND_SOURCE_LINKS.twseApi}?startDate=${compactDateKey(startDate)}&endDate=${compactDateKey(endDate)}&response=json`;
}

function parseTwseExDividendPayload(payload, fetchedAt = new Date().toISOString()) {
  const data = Array.isArray(payload?.data) ? payload.data : [];
  return data.map((cells) => {
    if (!Array.isArray(cells) || cells.length < 8) return null;
    // v16.9 全市場：不再過濾追蹤股（使用者要找新標的），追蹤與否由 normalize 的 tracked 欄位標示
    const code = String(cells[1] || "").trim().toUpperCase();
    if (!/^\d{4,6}[A-Z]?$/.test(code)) return null;
    const cashText = stripHtml(cells[7]).trim();
    return normalizeExDividendEvent({
      date: cells[0],
      code,
      name: cells[2],
      market: "listed",
      type: cells[3],
      stockDividendRatio: cells[4],
      subscriptionRatio: cells[5],
      subscriptionPrice: cells[6],
      cashDividend: cashText,
      cashDividendText: toNumber(cashText) === null ? cashText : "",
      source: "TWSE TWT48U 除權除息預告表",
      sourceUrl: EX_DIVIDEND_SOURCE_LINKS.twsePage,
      fetchedAt
    });
  }).filter(Boolean);
}

function parseTpexExDividendPayload(payload, fetchedAt = new Date().toISOString()) {
  return (Array.isArray(payload) ? payload : []).map((row) => {
    // v16.9 全市場：不再過濾追蹤股；tracked 欄位由 normalize 標示
    const code = String(row?.SecuritiesCompanyCode || "").trim().toUpperCase();
    if (!/^\d{4,6}[A-Z]?$/.test(code)) return null;
    return normalizeExDividendEvent({
      date: row.ExRrightsExDividendDate,
      code,
      name: row.CompanyName,
      market: "otc",
      type: row.ExRrightsExDividend,
      stockDividendRatio: row.StockDividendRatio,
      subscriptionRatio: row.SubscriptionRatioToNewSharesIssued,
      subscriptionPrice: row.SubscriptionPricePerShare,
      cashDividend: row.CashDividend,
      source: "TPEx tpex_exright_prepost 除權除息預告表",
      sourceUrl: EX_DIVIDEND_SOURCE_LINKS.tpexApi,
      fetchedAt
    });
  }).filter(Boolean);
}

function exDividendRowsInWindow(rows, startDate = localDateKey(), endDate = addMonthsToDateKey(startDate, 2)) {
  return normalizeExDividendRows(rows).filter((row) => row.date >= startDate && row.date <= endDate);
}

async function fetchExDividendCalendarData() {
  const fetchedAt = new Date().toISOString();
  const startDate = localDateKey();
  const endDate = addMonthsToDateKey(startDate, 2);
  const definitions = [
    {
      label: "TWSE",
      url: twseExDividendApiUrl(startDate, endDate),
      parse: parseTwseExDividendPayload
    },
    {
      label: "TPEx",
      url: EX_DIVIDEND_SOURCE_LINKS.tpexApi,
      parse: parseTpexExDividendPayload
    }
  ];
  const results = await Promise.all(definitions.map(async (definition) => {
    const startedAt = Date.now();
    try {
      const text = await fetchText(definition.url, { timeoutMs: 15000 });
      const rows = definition.parse(JSON.parse(text), fetchedAt);
      return {
        ok: true,
        rows,
        bytes: String(text || "").length,
        durationMs: Date.now() - startedAt,
        error: ""
      };
    } catch (error) {
      return {
        ok: false,
        rows: [],
        bytes: 0,
        durationMs: Date.now() - startedAt,
        error: error?.message || String(error)
      };
    }
  }));
  const errors = [];
  const sources = [];
  const rows = [];
  results.forEach((result, index) => {
    const definition = definitions[index];
    if (result.ok) {
      rows.push(...result.rows);
      sources.push({
        label: definition.label,
        url: definition.url,
        status: "success",
        count: result.rows.length,
        bytes: result.bytes,
        durationMs: result.durationMs,
        sourceTier: "Tier 1 官方",
        fallbackUsed: false,
        error: ""
      });
    } else {
      errors.push(`${definition.label}: ${result.error}`);
      sources.push({
        label: definition.label,
        url: definition.url,
        status: "error",
        count: 0,
        bytes: result.bytes,
        durationMs: result.durationMs,
        sourceTier: "Tier 1 官方",
        fallbackUsed: false,
        error: result.error
      });
    }
  });
  const windowRows = exDividendRowsInWindow(rows, startDate, endDate);
  if (!windowRows.length && errors.length === definitions.length) throw new Error(errors.join("；"));
  state.exDividendCalendar = normalizeExDividendCalendarState({
    rows: windowRows,
    fetchedAt,
    errors,
    sources,
    sourceSummary: `近兩個月官方除權息預告：追蹤股 / ETF ${windowRows.length} 筆；TWSE / TPEx 皆以除權息交易日為準。`
  });
  return { rows: windowRows, count: windowRows.length, errors, sources, startDate, endDate };
}

async function updateExDividendCalendar(silent = false) {
  if (!silent) setBusy(true, "正在更新 TWSE / TPEx 除權息日曆...");
  try {
    const result = await fetchExDividendCalendarData();
    await saveState();
    if (state.activeTab === "ex-dividend") renderExDividendTab();
    if (!silent) {
      const suffix = result.errors.length ? `；部分來源失敗：${result.errors.join("；")}` : "";
      setStatus(`除權息日曆已更新：近兩個月 ${formatNumber(result.count, 0)} 筆${suffix}`, result.errors.length ? "warn" : "good");
    }
    return result;
  } catch (error) {
    if (!silent) setStatus(`除權息日曆更新失敗：${error?.message || String(error)}`, "error");
    throw error;
  } finally {
    if (!silent) setBusy(false);
  }
}

async function fetchDividendData() {
  const errors = [];
  const fetchedAt = new Date().toISOString();
  const nextRecords = { ...normalizeDividendState(state.dividends).records };
  const sources = [
    { market: "listed", label: "上市", url: DIVIDEND_SOURCE_LINKS.listed },
    { market: "otc", label: "上櫃", url: DIVIDEND_SOURCE_LINKS.otc }
  ];
  let count = 0;
  for (const source of sources) {
    try {
      const text = await fetchText(source.url, { timeoutMs: 15000 });
      const rows = parseMopsDividendCsv(text, source.market);
      for (const row of rows) {
        nextRecords[row.code] = mergeDividendRecord(nextRecords[row.code], { ...row, fetchedAt });
        count += 1;
      }
    } catch (error) {
      errors.push(`${source.label}: ${error?.message || String(error)}`);
    }
  }
  if (!count && errors.length) throw new Error(errors.join("；"));
  state.dividends = {
    records: nextRecords,
    fetchedAt,
    errors,
    sourceSummary: `MOPS 股利分派 opendata：${count} 筆追蹤股資料`
  };
  return { count, errors };
}

async function updateDividendData(silent = false) {
  if (!silent) setBusy(true, "更新 MOPS 配股配息與本期淨利...");
  try {
    const result = await fetchDividendData();
    await saveState();
    render();
    if (!silent) {
      const suffix = result.errors.length ? `；部分來源失敗：${result.errors.join("；")}` : "";
      setStatus(`股利更新完成：${formatNumber(result.count, 0)} 筆追蹤股資料${suffix}`, result.count ? "good" : "warn");
    }
    return result;
  } catch (error) {
    if (!silent) setStatus(`股利更新失敗：${error?.message || String(error)}`, "error");
    throw error;
  } finally {
    if (!silent) setBusy(false);
  }
}

// ─── Q1 相對強度（RS vs TAIEX） ────────────────────────────────────────────
// 回傳 { stockReturn, taiexReturn, excessReturn, rs, nDays } 或 null
function calculateRS(code, nDays = 65) {
  const rows = latestKlines(code);
  const taiex = taiexKlines();
  if (rows.length < 10 || taiex.length < nDays) return null;

  // 以 TAIEX 最近 nDays 筆的起始日作為基準日
  const taiexRecent = taiex.slice(-nDays);
  const startDate = taiexRecent[0].date;
  const endTaiex = taiexRecent[taiexRecent.length - 1].close;
  const startTaiex = taiexRecent[0].close;

  // 找個股對應的起始價（第一個 >= startDate 的收盤）
  const stockInRange = rows.filter((r) => r.date >= startDate);
  if (!stockInRange.length) return null;
  const startStock = stockInRange[0].close;
  const endStock = rows[rows.length - 1].close;

  if (!startTaiex || !endTaiex || !startStock || !endStock) return null;

  const stockReturn = (endStock - startStock) / startStock * 100;
  const taiexReturn = (endTaiex - startTaiex) / startTaiex * 100;
  const excessReturn = stockReturn - taiexReturn;
  const rs = Math.abs(taiexReturn) > 0.01 ? stockReturn / taiexReturn : null;

  return { stockReturn, taiexReturn, excessReturn, rs, nDays };
}

// ─── Q2 成交量 Z-score 異常偵測 ────────────────────────────────────────────
// 回傳 { zScore, ratio, bullish, date } 或 null
function volumeAnomalyInfo(code) {
  const rows = latestKlines(code);
  if (rows.length < 22) return null;
  const recent21 = rows.slice(-21);
  const latest = recent21[recent21.length - 1];
  const hist = recent21.slice(0, -1).map((r) => r.volume).filter((v) => v > 0);
  if (hist.length < 5) return null;
  const avgVol = average(hist);
  const stdVol = standardDeviation(hist);
  if (!avgVol || !stdVol || stdVol < 1) return null;
  const zScore = (latest.volume - avgVol) / stdVol;
  const ratio = latest.volume / avgVol;
  const bullish = latest.close >= latest.open;
  return { zScore, ratio, bullish, date: latest.date, volume: latest.volume, avgVol };
}

// ─── Q3 Beta（60 日對齊日報酬） ─────────────────────────────────────────────
// 回傳 beta（數值）或 null
function calculateBeta(code, nDays = 60) {
  const rows = latestKlines(code);
  const taiex = taiexKlines();
  if (rows.length < nDays + 1 || taiex.length < nDays + 1) return null;

  const taiexMap = new Map(taiex.map((r) => [r.date, r.close]));
  const recentStock = rows.slice(-(nDays + 1));

  const stockR = [];
  const taiexR = [];
  for (let i = 1; i < recentStock.length; i++) {
    const t1 = taiexMap.get(recentStock[i - 1].date);
    const t2 = taiexMap.get(recentStock[i].date);
    if (!t1 || !t2) continue;
    stockR.push((recentStock[i].close - recentStock[i - 1].close) / recentStock[i - 1].close);
    taiexR.push((t2 - t1) / t1);
  }

  if (stockR.length < 20) return null;

  const meanS = average(stockR);
  const meanT = average(taiexR);
  let cov = 0;
  let varT = 0;
  for (let i = 0; i < stockR.length; i++) {
    cov += (stockR[i] - meanS) * (taiexR[i] - meanT);
    varT += (taiexR[i] - meanT) ** 2;
  }
  cov /= stockR.length;
  varT /= stockR.length;

  return varT > 1e-10 ? cov / varT : null;
}

// 多時間窗口 RS：{ r21, r65, r130 }（excess return percentage points，null 代表資料不足）
function calculateRSMulti(code) {
  return {
    r21: calculateRS(code, 21)?.excessReturn ?? null,
    r65: calculateRS(code, 65)?.excessReturn ?? null,
    r130: calculateRS(code, 130)?.excessReturn ?? null
  };
}

// 個股的 MA 得分（0–4）
function maScoreValue(technical) {
  if (!technical || !technical.ready) return 1;
  const { latest, ma5, ma20, ma60, ma240 } = technical;
  const p = latest.close;
  if (ma5 && p > ma5) return 4;
  if (ma20 && p > ma20) {
    if (ma5) {
      const pos = (ma5 - ma20) > 0 ? (p - ma20) / (ma5 - ma20) : 0.5;
      return pos >= 0.5 ? 3 : 2.5;
    }
    return 2.5;
  }
  if (ma60 && p > ma60) {
    if (ma20) {
      const pos = (ma20 - ma60) > 0 ? (p - ma60) / (ma20 - ma60) : 0.5;
      return pos >= 0.5 ? 2 : 1.5;
    }
    return 1.5;
  }
  if (ma240 && Math.abs((p - ma240) / ma240) <= 0.05) return 1;
  if (ma240 && p < ma240) return 0;
  return 1;
}

// 個股的月營收 YoY 得分（0–3）
function revScoreValue(code) {
  const rev = revenueFor(code);
  if (!rev || rev.yoyPct === null) return 1; // 無資料視為中性
  if (rev.yoyPct > 20) return 3;
  if (rev.yoyPct > 5)  return 2;
  if (rev.yoyPct > 0)  return 1;
  return 0;
}

// 量能得分（-2 ~ +2）
function volScoreValue(code) {
  const vol = volumeAnomalyInfo(code);
  if (!vol) return 0;
  if (vol.zScore > 2) return vol.bullish ? 2 : -1;
  if (vol.zScore > 1) return vol.bullish ? 1 : 0;
  return 0;
}

// 籌碼得分（-2 ~ +2）
function chipScoreValue(code) {
  return stockChipSignal(code).score;
}

// 複合評分：最高 4+3+2+2+3 = 14
// rsRankFn(code) → 0-3，由 renderScreener 傳入（需先算全局分位）
function compositeScore(code, rsRankFn) {
  try {
    const t = calculateTechnical(code);
    return {
      ma: maScoreValue(t),
      rs: rsRankFn ? rsRankFn(code) : 1,
      vol: volScoreValue(code),
      chip: chipScoreValue(code),
      rev: revScoreValue(code)
    };
  } catch (_) {
    return { ma: 1, rs: 1, vol: 0, chip: 0, rev: 1 };
  }
}

function macd(values) {
  if (!Array.isArray(values) || values.length < 35) {
    return { macdLine: null, signalLine: null, histogram: null, previousHistogram: null };
  }
  const ema12 = emaSeries(values, 12);
  const ema26 = emaSeries(values, 26);
  const macdLineSeries = values.map((_, index) => ema12[index] - ema26[index]);
  const signalSeries = emaSeries(macdLineSeries, 9);
  const macdLine = macdLineSeries.at(-1);
  const signalLine = signalSeries.at(-1);
  const previousMacdLine = macdLineSeries.at(-2);
  const previousSignalLine = signalSeries.at(-2);
  return {
    macdLine,
    signalLine,
    histogram: macdLine !== null && signalLine !== null ? macdLine - signalLine : null,
    previousHistogram: previousMacdLine !== undefined && previousMacdLine !== null && previousSignalLine !== undefined && previousSignalLine !== null
      ? previousMacdLine - previousSignalLine
      : null
  };
}

// ─── 完整指標序列（供子圖使用） ─────────────────────────────────────────────

function macdFullSeries(values) {
  const empty = { macdLines: [], signalLines: [], histograms: [] };
  if (!Array.isArray(values) || values.length < 35) return empty;
  const ema12 = emaSeries(values, 12);
  const ema26 = emaSeries(values, 26);
  const macdLines = values.map((_, i) => ema12[i] - ema26[i]);
  const signalLines = emaSeries(macdLines, 9);
  const histograms = macdLines.map((m, i) => m - signalLines[i]);
  return { macdLines, signalLines, histograms };
}

function kdSeries(rows, kPeriod = 9, smooth = 3) {
  const empty = { k: Array(rows?.length || 0).fill(null), d: Array(rows?.length || 0).fill(null) };
  if (!Array.isArray(rows) || rows.length < kPeriod) return empty;
  const k = [];
  const d = [];
  let prevK = 50;
  let prevD = 50;
  for (let i = 0; i < rows.length; i++) {
    if (i + 1 < kPeriod) { k.push(null); d.push(null); continue; }
    const win = rows.slice(i + 1 - kPeriod, i + 1);
    const highest = Math.max(...win.map((r) => r.high));
    const lowest = Math.min(...win.map((r) => r.low));
    const range = highest - lowest || 0.001;
    const rsv = (rows[i].close - lowest) / range * 100;
    const kv = ((smooth - 1) * prevK + rsv) / smooth;
    const dv = ((smooth - 1) * prevD + kv) / smooth;
    k.push(kv);
    d.push(dv);
    prevK = kv;
    prevD = dv;
  }
  return { k, d };
}

function rsiSeries(values, period = 14) {
  if (!Array.isArray(values) || values.length <= period) return Array(values?.length || 0).fill(null);
  return values.map((_, i) => {
    if (i < period) return null;
    const changes = values.slice(i - period, i + 1).map((v, j, a) => j > 0 ? v - a[j - 1] : 0).slice(1);
    const gains = changes.filter((c) => c > 0).reduce((a, b) => a + b, 0) / period;
    const losses = changes.filter((c) => c < 0).reduce((a, b) => a + Math.abs(b), 0) / period;
    if (losses === 0) return 100;
    return 100 - 100 / (1 + gains / losses);
  });
}

function aggregateWeeklyBars(dailyRows) {
  if (!Array.isArray(dailyRows) || !dailyRows.length) return [];
  const weekly = [];
  for (const row of dailyRows) {
    if (!row.date) continue;
    const date = new Date(row.date + "T00:00:00");
    const dow = date.getDay();
    const daysToMonday = dow === 0 ? 6 : dow - 1;
    const monday = new Date(date);
    monday.setDate(date.getDate() - daysToMonday);
    const weekKey = monday.toISOString().slice(0, 10);
    const last = weekly[weekly.length - 1];
    if (last && last._wk === weekKey) {
      last.high = Math.max(last.high, row.high);
      last.low = Math.min(last.low, row.low);
      last.close = row.close;
      last.volume = (last.volume || 0) + (row.volume || 0);
      last.date = row.date;
    } else {
      weekly.push({ _wk: weekKey, date: row.date, open: row.open, high: row.high, low: row.low, close: row.close, volume: row.volume || 0, source: row.source });
    }
  }
  return weekly;
}

// ─── MACD / KD 子圖 SVG ───────────────────────────────────────────────────

function renderMacdSubChart(rows, left, width) {
  if (!rows || rows.length < 35) return "";
  const closes = rows.map((r) => r.close);
  const { macdLines, signalLines, histograms } = macdFullSeries(closes);
  const validH = histograms.filter(Number.isFinite);
  if (!validH.length) return "";
  // 15% headroom so bars never touch the very edge
  const maxAbs = Math.max(...validH.map(Math.abs), 0.001) * 1.15;
  const viewH = 110;
  const pad = 12;
  const chartH = (viewH - pad * 2) / 2;  // half-height for bars on each side
  const zero = pad + chartH;              // y-coordinate of zero line = 12 + 43 = 55

  const histBars = rows.map((_, i) => {
    const h = histograms[i];
    if (!Number.isFinite(h)) return "";
    const x = scalePoint(i, rows.length, left, width);
    const bw = Math.max(1.5, (width / rows.length) * 0.7);
    const bh = Math.min(Math.abs(h) / maxAbs * chartH, chartH);
    const y = h >= 0 ? zero - bh : zero;
    const cls = h >= 0 ? "candle-bull" : "candle-bear";
    return `<rect class="${cls}" opacity="0.55" x="${(x - bw / 2).toFixed(1)}" y="${y.toFixed(1)}" width="${bw.toFixed(1)}" height="${Math.max(1, bh).toFixed(1)}"></rect>`;
  }).join("");

  const mkPath = (series) => {
    let started = false;
    return series.map((v, i) => {
      if (!Number.isFinite(v)) { started = false; return ""; }
      const x = scalePoint(i, rows.length, left, width);
      const y = Math.min(Math.max(zero - (v / maxAbs) * chartH, pad - 2), viewH - pad + 2);
      const cmd = started ? "L" : "M";
      started = true;
      return `${cmd}${x.toFixed(1)},${y.toFixed(1)}`;
    }).filter(Boolean).join(" ");
  };

  const latestHist = validH.at(-1);
  const latestMacd = macdLines.filter(Number.isFinite).at(-1);
  const latestSig = signalLines.filter(Number.isFinite).at(-1);
  const histColor = Number.isFinite(latestHist) && latestHist >= 0 ? "var(--bad)" : "var(--good)";

  return `<div style="margin-top:4px;border:1px solid var(--line);border-radius:14px;background:rgba(255,255,255,0.72);overflow:visible;">
    <div style="padding:6px 18px;border-bottom:1px solid var(--line);background:rgba(239,232,222,0.3);border-radius:14px 14px 0 0;display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
      <span style="font-size:0.78rem;font-weight:900;color:var(--muted);">MACD(12,26,9)</span>
      <span class="chip legend-chip legend-ma5" style="min-height:20px;padding:2px 7px;font-size:0.72rem;">DIF ${Number.isFinite(latestMacd) ? latestMacd.toFixed(2) : "-"}</span>
      <span class="chip legend-chip legend-ma10" style="min-height:20px;padding:2px 7px;font-size:0.72rem;">DEA ${Number.isFinite(latestSig) ? latestSig.toFixed(2) : "-"}</span>
      <span class="chip" style="min-height:20px;padding:2px 7px;font-size:0.72rem;color:${histColor};">柱 ${Number.isFinite(latestHist) ? latestHist.toFixed(2) : "-"}</span>
    </div>
    <svg viewBox="0 0 1000 ${viewH}" preserveAspectRatio="none" style="width:100%;height:${viewH}px;display:block;overflow:visible;">
      <rect x="0" y="0" width="1000" height="${viewH}" fill="rgba(255,255,255,0)"></rect>
      <line stroke="rgba(91,76,61,0.22)" stroke-width="1" stroke-dasharray="4 4" x1="${left}" y1="${zero}" x2="${left + width}" y2="${zero}"></line>
      ${histBars}
      <path fill="none" stroke="var(--ma5-color)" stroke-width="1.3" stroke-linecap="round" stroke-linejoin="round" d="${mkPath(macdLines)}"></path>
      <path fill="none" stroke="var(--ma10-color)" stroke-width="1.1" stroke-linecap="round" stroke-linejoin="round" stroke-dasharray="4 3" d="${mkPath(signalLines)}"></path>
    </svg>
  </div>`;
}

function renderKdSubChart(rows, left, width) {
  if (!rows || rows.length < 9) return "";
  const { k, d } = kdSeries(rows, 9, 3);
  const viewH = 110;
  const pad = 12;
  const chartH = viewH - pad * 2;  // 86px usable

  const yAt = (pct) => pad + (1 - Math.max(0, Math.min(100, pct)) / 100) * chartH;

  const mkPath = (series) => {
    let started = false;
    return series.map((v, i) => {
      if (!Number.isFinite(v)) { started = false; return ""; }
      const x = scalePoint(i, rows.length, left, width);
      const y = yAt(v);
      const cmd = started ? "L" : "M";
      started = true;
      return `${cmd}${x.toFixed(1)},${y.toFixed(1)}`;
    }).filter(Boolean).join(" ");
  };

  const lastK = k.filter(Number.isFinite).at(-1);
  const lastD = d.filter(Number.isFinite).at(-1);
  const overbought = Number.isFinite(lastK) && lastK >= 80;
  const oversold = Number.isFinite(lastK) && lastK <= 20;

  return `<div style="margin-top:4px;border:1px solid var(--line);border-radius:14px;background:rgba(255,255,255,0.72);overflow:visible;">
    <div style="padding:6px 18px;border-bottom:1px solid var(--line);background:rgba(239,232,222,0.3);border-radius:14px 14px 0 0;display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
      <span style="font-size:0.78rem;font-weight:900;color:var(--muted);">KD(9,3,3)</span>
      <span class="chip legend-chip legend-ma20" style="min-height:20px;padding:2px 7px;font-size:0.72rem;">K ${Number.isFinite(lastK) ? lastK.toFixed(1) : "-"}</span>
      <span class="chip legend-chip legend-ma60" style="min-height:20px;padding:2px 7px;font-size:0.72rem;">D ${Number.isFinite(lastD) ? lastD.toFixed(1) : "-"}</span>
      ${overbought ? `<span style="font-size:0.72rem;font-weight:900;color:var(--bad);">超買 K≥80</span>` : ""}
      ${oversold ? `<span style="font-size:0.72rem;font-weight:900;color:var(--good);">超賣 K≤20</span>` : ""}
    </div>
    <svg viewBox="0 0 1000 ${viewH}" preserveAspectRatio="none" style="width:100%;height:${viewH}px;display:block;overflow:visible;">
      <rect x="0" y="0" width="1000" height="${viewH}" fill="rgba(255,255,255,0)"></rect>
      <line stroke="rgba(179,39,65,0.2)" stroke-width="1" stroke-dasharray="3 3" x1="${left}" y1="${yAt(80).toFixed(1)}" x2="${left + width}" y2="${yAt(80).toFixed(1)}"></line>
      <line stroke="rgba(91,76,61,0.15)" stroke-width="1" stroke-dasharray="3 3" x1="${left}" y1="${yAt(50).toFixed(1)}" x2="${left + width}" y2="${yAt(50).toFixed(1)}"></line>
      <line stroke="rgba(12,138,87,0.2)" stroke-width="1" stroke-dasharray="3 3" x1="${left}" y1="${yAt(20).toFixed(1)}" x2="${left + width}" y2="${yAt(20).toFixed(1)}"></line>
      <text fill="var(--muted)" font-size="10" x="${left - 4}" y="${(yAt(80) + 3).toFixed(1)}" text-anchor="end">80</text>
      <text fill="var(--muted)" font-size="10" x="${left - 4}" y="${(yAt(50) + 3).toFixed(1)}" text-anchor="end">50</text>
      <text fill="var(--muted)" font-size="10" x="${left - 4}" y="${(yAt(20) + 3).toFixed(1)}" text-anchor="end">20</text>
      <path fill="none" stroke="var(--ma20-color)" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round" d="${mkPath(k)}"></path>
      <path fill="none" stroke="var(--ma60-color)" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round" stroke-dasharray="4 3" d="${mkPath(d)}"></path>
    </svg>
  </div>`;
}

function recentSwingPoints(rows, span = 2) {
  const highs = [];
  const lows = [];
  if (!Array.isArray(rows) || rows.length < span * 2 + 1) {
    return { highs, lows };
  }

  for (let index = span; index < rows.length - span; index += 1) {
    const row = rows[index];
    const before = rows.slice(index - span, index);
    const after = rows.slice(index + 1, index + span + 1);
    const isHigh = before.every((entry) => row.high > entry.high) && after.every((entry) => row.high >= entry.high);
    const isLow = before.every((entry) => row.low < entry.low) && after.every((entry) => row.low <= entry.low);
    if (isHigh) highs.push({ index, date: row.date, value: row.high });
    if (isLow) lows.push({ index, date: row.date, value: row.low });
  }

  return { highs, lows };
}

function movingDeductionSignal(rows, period, slope = null) {
  if (!Array.isArray(rows) || rows.length < period + 1) return null;
  const incoming = rows.at(-1);
  const outgoing = rows.at(-(period + 1));
  if (!incoming || !outgoing) return null;
  const delta = incoming.close - outgoing.close;
  const relation = delta > 0 ? "抵高於扣" : delta < 0 ? "抵低於扣" : "抵扣相等";
  const direction = delta > 0 ? "偏上彎" : delta < 0 ? "偏下彎" : "易走平";
  let slopeNote = "";
  if (slope !== null) {
    if (slope > 0) slopeNote = "，目前均線方向仍上彎";
    else if (slope < 0) slopeNote = "，目前均線方向仍下彎";
    else slopeNote = "，目前均線近乎走平";
  }
  return {
    period,
    label: `MA${period}`,
    delta,
    summary: `${relation} ${formatNumber(Math.abs(delta))}，${direction}${slopeNote}`
  };
}

function maStackLabel(ma10, ma20, ma60, ma240) {
  if ([ma10, ma20, ma60].every((value) => value !== null) && ma10 > ma20 && ma20 > ma60) {
    if (ma240 !== null && ma60 > ma240) return "4 線多排";
    return "3 線多排";
  }
  if ([ma10, ma20, ma60].every((value) => value !== null) && ma10 < ma20 && ma20 < ma60) {
    if (ma240 !== null && ma60 < ma240) return "4 線空排";
    return "3 線空排";
  }
  return "均線交錯";
}

function consecutiveCloseDirection(rows, direction = "up", limit = 6) {
  if (!Array.isArray(rows) || rows.length < 2) return 0;
  let count = 0;
  for (let index = rows.length - 1; index > 0 && count < limit; index -= 1) {
    const current = rows[index];
    const previous = rows[index - 1];
    const passes = direction === "up"
      ? current.close > previous.close
      : current.close < previous.close;
    if (!passes) break;
    count += 1;
  }
  return count;
}

function roundPriceLevel(value) {
  const number = toNumber(value);
  if (number === null) return null;
  const digits = number >= 1000 ? 0 : number >= 100 ? 1 : 2;
  return Number(number.toFixed(digits));
}

function priceLevelCandidate(price, label, note = "", source = "") {
  const number = roundPriceLevel(price);
  if (number === null || number <= 0) return null;
  return { price: number, label, note, source };
}

function selectNearestBelow(candidates, currentPrice) {
  const price = toNumber(currentPrice);
  if (price === null) return null;
  return candidates
    .filter(Boolean)
    .filter((candidate) => candidate.price <= price * 1.01)
    .sort((left, right) => right.price - left.price)[0] || null;
}

function selectNearestAbove(candidates, currentPrice) {
  const price = toNumber(currentPrice);
  if (price === null) return null;
  return candidates
    .filter(Boolean)
    .filter((candidate) => candidate.price >= price * 0.99)
    .sort((left, right) => left.price - right.price)[0] || null;
}

function projectedTrendLine(points, targetIndex, label) {
  if (!Array.isArray(points) || points.length < 2 || !Number.isFinite(targetIndex)) return null;
  const p2 = points.at(-1);
  const p1 = points.at(-2);
  if (!p1 || !p2 || p2.index === p1.index) return null;
  const slope = (p2.value - p1.value) / (p2.index - p1.index);
  const price = roundPriceLevel(p2.value + slope * (targetIndex - p2.index));
  if (price === null || price <= 0) return null;
  return {
    price,
    label,
    slope,
    from: `${p1.date} ${formatNumber(p1.value)}`,
    to: `${p2.date} ${formatNumber(p2.value)}`
  };
}

function candleRangePct(row) {
  if (!row || !row.low || row.low <= 0) return null;
  return (row.high - row.low) / row.low * 100;
}

function candleBodyPct(row) {
  if (!row || !row.open || row.open <= 0) return null;
  return Math.abs(row.close - row.open) / row.open * 100;
}

function recentLargeCandles(rows, lookback = 45) {
  const result = { bullish: null, bearish: null };
  if (!Array.isArray(rows) || rows.length < 6) return result;
  const start = Math.max(1, rows.length - lookback);
  for (let index = start; index < rows.length; index += 1) {
    const row = rows[index];
    const prevVolumes = rows.slice(Math.max(0, index - 5), index).map((entry) => entry.volume || 0);
    const volumeBase = prevVolumes.length ? sma(prevVolumes, Math.min(5, prevVolumes.length)) : null;
    const volumeRatio = volumeBase ? row.volume / volumeBase : null;
    const rangePct = candleRangePct(row);
    const bodyPct = candleBodyPct(row);
    const isLargeRange = rangePct !== null && rangePct >= 6.5;
    const isLargeBody = bodyPct !== null && bodyPct >= 4.5;
    const isVolumeUseful = volumeRatio === null || volumeRatio >= 1.15;
    if (!(isLargeRange || isLargeBody) || !isVolumeUseful) continue;
    const candle = {
      index,
      date: row.date,
      high: row.high,
      low: row.low,
      half: roundPriceLevel((row.high + row.low) / 2),
      rangePct,
      bodyPct,
      volumeRatio,
      row
    };
    if (row.close > row.open) result.bullish = candle;
    if (row.close < row.open) result.bearish = candle;
  }
  return result;
}

function largeVolumeBarCandidates(rows, lookback = 60) {
  if (!Array.isArray(rows) || rows.length < 22) return [];
  const latestIndex = rows.length - 1;
  const start = Math.max(20, rows.length - lookback - 1);
  const candidates = [];
  for (let index = start; index < latestIndex; index += 1) {
    const row = rows[index];
    const prev = rows[index - 1] || null;
    const prevVolumes = rows.slice(Math.max(0, index - 20), index).map((entry) => entry.volume || 0).filter(Number.isFinite);
    const volumeBase20 = prevVolumes.length ? sma(prevVolumes, Math.min(20, prevVolumes.length)) : null;
    const volumeRatio20 = volumeBase20 ? (row.volume || 0) / volumeBase20 : null;
    const changePct = prev?.close ? (row.close - prev.close) / prev.close * 100 : null;
    const bodyPct = candleBodyPct(row);
    const rangePct = candleRangePct(row);
    const isLargeVolume = volumeRatio20 !== null && volumeRatio20 >= 1.5;
    const hasMeaningfulMove = Math.abs(changePct ?? 0) >= 0.8 || (bodyPct !== null && bodyPct >= 1) || (rangePct !== null && rangePct >= 2.5);
    if (!isLargeVolume || !hasMeaningfulMove) continue;
    const direction = row.close >= row.open && (changePct === null || changePct >= 0) ? "up"
      : row.close < row.open || (changePct !== null && changePct < 0) ? "down"
        : "flat";
    candidates.push({
      index,
      date: row.date,
      open: row.open,
      high: row.high,
      low: row.low,
      close: row.close,
      half: roundPriceLevel((row.high + row.low) / 2),
      volume: row.volume || 0,
      volumeBase20,
      volumeRatio20,
      changePct,
      bodyPct,
      rangePct,
      direction,
      row
    });
  }
  return candidates;
}

function fallbackLargeVolumeBar(rows, lookback = 60) {
  if (!Array.isArray(rows) || rows.length < 3) return null;
  const latestIndex = rows.length - 1;
  const start = Math.max(1, rows.length - lookback - 1);
  const candidates = rows
    .slice(start, latestIndex)
    .map((row, offset) => {
      const index = start + offset;
      const prev = rows[index - 1] || null;
      const prevVolumes = rows.slice(Math.max(0, index - 20), index).map((entry) => entry.volume || 0).filter(Number.isFinite);
      const volumeBase20 = prevVolumes.length ? sma(prevVolumes, Math.min(20, prevVolumes.length)) : null;
      const volumeRatio20 = volumeBase20 ? (row.volume || 0) / volumeBase20 : null;
      const changePct = prev?.close ? (row.close - prev.close) / prev.close * 100 : null;
      return {
        index,
        date: row.date,
        open: row.open,
        high: row.high,
        low: row.low,
        close: row.close,
        half: roundPriceLevel((row.high + row.low) / 2),
        volume: row.volume || 0,
        volumeBase20,
        volumeRatio20,
        changePct,
        bodyPct: candleBodyPct(row),
        rangePct: candleRangePct(row),
        direction: row.close >= row.open ? "up" : "down",
        fallbackUsed: true,
        row
      };
    })
    .filter((item) => Number.isFinite(item.volume) && item.volume > 0)
    .sort((left, right) => right.volume - left.volume);
  return candidates[0] || null;
}

function largeVolumePriceCheck(latest, anchor, side = "high") {
  if (!latest || !anchor) return null;
  const level = side === "high" ? toNumber(anchor.high) : toNumber(anchor.low);
  if (level === null || level <= 0) return null;
  const distancePct = latest.close ? (latest.close - level) / level * 100 : null;
  if (side === "high") {
    if (latest.close > level) {
      return {
        status: "breakout",
        label: "收盤站上大量高",
        tone: "up",
        score: 2,
        level,
        distancePct,
        detail: `收盤 ${formatNumber(latest.close)} 已站上 ${anchor.date} 大量高 ${formatNumber(level)}`
      };
    }
    if (latest.high >= level) {
      return {
        status: "test",
        label: "盤中碰大量高未收上",
        tone: "warn",
        score: 0,
        level,
        distancePct,
        detail: `最高 ${formatNumber(latest.high)} 曾碰大量高，但收盤仍未確認突破`
      };
    }
    return {
      status: "below",
      label: "尚未突破大量高",
      tone: "flat",
      score: 0,
      level,
      distancePct,
      detail: `距 ${anchor.date} 大量高 ${distancePct !== null ? formatSignedMetric(distancePct, 2, "%") : "-"}`
    };
  }
  if (latest.close < level) {
    return {
      status: "breakdown",
      label: "收盤跌破大量低",
      tone: "down",
      score: -2,
      level,
      distancePct,
      detail: `收盤 ${formatNumber(latest.close)} 已跌破 ${anchor.date} 大量低 ${formatNumber(level)}`
    };
  }
  if (latest.low <= level) {
    return {
      status: "test",
      label: "盤中測大量低守住",
      tone: "warn",
      score: 1,
      level,
      distancePct,
      detail: `最低 ${formatNumber(latest.low)} 曾測大量低，但收盤仍守住`
    };
  }
  return {
    status: "above",
    label: "尚未跌破大量低",
    tone: "up",
    score: 1,
    level,
    distancePct,
    detail: `收盤仍在 ${anchor.date} 大量低上方 ${distancePct !== null ? formatSignedMetric(distancePct, 2, "%") : "-"}`
  };
}

function analyzeLargeVolumeDefense(rows, lookback = 60, options = {}) {
  const periodLabel = options.periodLabel || "日線";
  const volumeBaseLabel = options.volumeBaseLabel || "前 20 日均量";
  if (!Array.isArray(rows) || rows.length < 22) {
    return {
      available: false,
      label: `${periodLabel}不足`,
      note: `至少需要 22 根${periodLabel}才能用${volumeBaseLabel}判斷大量 K 攻防。`
    };
  }
  const latest = rows.at(-1);
  const candidates = largeVolumeBarCandidates(rows, lookback);
  const fallback = candidates.length ? null : fallbackLargeVolumeBar(rows, lookback);
  const effective = candidates.length ? candidates : (fallback ? [fallback] : []);
  if (!effective.length) {
    return {
      available: false,
      label: "缺大量 K",
      note: `最近 ${lookback} 根${periodLabel}內沒有可用成交量錨點。`
    };
  }
  const latestAnchor = [...effective].sort((left, right) => right.index - left.index)[0];
  const maxVolumeAnchor = [...effective].sort((left, right) => right.volume - left.volume)[0];
  const bullishAnchor = [...effective].filter((item) => item.direction === "up").sort((left, right) => right.index - left.index)[0] || null;
  const bearishAnchor = [...effective].filter((item) => item.direction === "down").sort((left, right) => right.index - left.index)[0] || null;
  const highAnchor = latestAnchor || bearishAnchor || bullishAnchor || maxVolumeAnchor;
  const lowAnchor = latestAnchor || bullishAnchor || bearishAnchor || maxVolumeAnchor;
  const highCheck = largeVolumePriceCheck(latest, highAnchor, "high");
  const lowCheck = largeVolumePriceCheck(latest, lowAnchor, "low");
  const score = (highCheck?.score || 0) + (lowCheck?.score || 0);
  const tone = lowCheck?.status === "breakdown" ? "down"
    : highCheck?.status === "breakout" ? "up"
      : highCheck?.status === "test" || lowCheck?.status === "test" ? "warn"
        : "flat";
  const summary = lowCheck?.status === "breakdown"
    ? "大量低失守，先控風險"
    : highCheck?.status === "breakout"
      ? "大量高收復，攻擊確認"
      : highCheck?.status === "test"
        ? "測大量高未收上"
        : lowCheck?.status === "test"
          ? "測大量低後守住"
          : "大量區間內整理";
  return {
    available: true,
    lookback,
    latest,
    candidates,
    fallbackUsed: Boolean(fallback),
    latestAnchor,
    maxVolumeAnchor,
    bullishAnchor,
    bearishAnchor,
    highAnchor,
    lowAnchor,
    highCheck,
    lowCheck,
    score,
    tone,
    summary,
    note: fallback ? `最近${periodLabel}未達大量門檻，暫用區間最大量 K 作參考。` : `大量 K 門檻：相對${volumeBaseLabel} ≥ 1.5 倍，且該根 K 有明顯價格波動。`
  };
}

function analyzeWeeklyLargeVolumeDefense(rows) {
  const weeklyRows = aggregateWeeklyBars(rows);
  const defense = analyzeLargeVolumeDefense(weeklyRows, 52, {
    periodLabel: "週線",
    volumeBaseLabel: "前 20 週均量"
  });
  return {
    ...defense,
    timeframe: "weekly",
    rows: weeklyRows,
    rowCount: weeklyRows.length
  };
}

function analyzeLargeVolumeRecovery(rows, defense) {
  const anchor = defense?.lowAnchor || null;
  const latest = Array.isArray(rows) && rows.length ? rows.at(-1) : null;
  const close = toNumber(latest?.close);
  if (!Array.isArray(rows) || rows.length < 22 || !anchor || close === null) {
    return {
      available: false,
      label: "修復資料不足",
      note: "需先累積日線與大量 K 低點，才能判斷失守後是否修復。"
    };
  }
  const low = toNumber(anchor.low);
  const high = toNumber(anchor.high);
  const half = toNumber(anchor.half) ?? (low !== null && high !== null ? roundPriceLevel((low + high) / 2) : null);
  if (low === null || high === null || half === null || low <= 0 || high <= low) {
    return {
      available: false,
      label: "修復區間無效",
      note: "大量 K 高低點不足，暫不納入修復判讀。"
    };
  }
  const anchorIndex = Number.isFinite(anchor.index)
    ? anchor.index
    : rows.findIndex((row) => row.date === anchor.date && row.high === anchor.high && row.low === anchor.low);
  const startIndex = Math.max(0, anchorIndex + 1);
  const afterAnchor = rows.slice(startIndex);
  const brokenRows = afterAnchor.filter((row) => toNumber(row.close) !== null && row.close < low);
  const broken = brokenRows.length > 0;
  const latestHigh = toNumber(latest.high);
  const latestLow = toNumber(latest.low);
  const distanceToLowPct = (close - low) / low * 100;
  const distanceToHalfPct = (close - half) / half * 100;
  const brokenDate = brokenRows[0]?.date || "";
  const lowestAfterBreak = brokenRows.length
    ? brokenRows.reduce((best, row) => {
      const rowLow = toNumber(row.low);
      return rowLow !== null && (best === null || rowLow < best) ? rowLow : best;
    }, null)
    : null;
  const failedRetest = broken && close < low && latestHigh !== null && latestHigh >= low;
  let status = "intact";
  let label = "大量低尚未失守";
  let tone = "up";
  let score = 1;
  let stage = "防線仍在";
  let detail = `收盤仍在 ${anchor.date} 大量低 ${formatNumber(low)} 上方 ${formatSignedMetric(distanceToLowPct, 2, "%")}`;

  if (broken && close >= high) {
    status = "reclaimedHigh";
    label = "失守後收復大量高";
    tone = "up";
    score = 4;
    stage = "強修復";
    detail = `曾於 ${brokenDate} 失守大量低，現在收盤站回大量高 ${formatNumber(high)}，代表原大量 K 區間完整收復`;
  } else if (broken && close >= half) {
    status = "reclaimedHalf";
    label = "失守後站回半價";
    tone = "up";
    score = 3;
    stage = "修復確認";
    detail = `曾於 ${brokenDate} 失守，現在收盤站回大量 K 半價 ${formatNumber(half)}，可列再進場觀察`;
  } else if (broken && close >= low) {
    status = "reclaimedLow";
    label = "失守後站回大量低";
    tone = "flat";
    score = 2;
    stage = "初步修復";
    detail = `曾於 ${brokenDate} 失守，現在收盤重新站回大量低 ${formatNumber(low)}，仍需半價 / POC / 均線確認`;
  } else if (failedRetest) {
    status = "failedRetest";
    label = "反彈測低未收復";
    tone = "down";
    score = -3;
    stage = "假修復";
    detail = `盤中碰回大量低 ${formatNumber(low)}，但收盤仍在下方 ${formatSignedMetric(distanceToLowPct, 2, "%")}；反彈先視為壓力測試`;
  } else if (broken) {
    status = "unrecovered";
    label = "大量低失守未修復";
    tone = "down";
    score = -4;
    stage = "未修復";
    detail = `自 ${brokenDate} 失守後，收盤仍在大量低下方 ${formatSignedMetric(distanceToLowPct, 2, "%")}`;
  } else if (latestLow !== null && latestLow <= low) {
    status = "testedHeld";
    label = "測大量低後守住";
    tone = "flat";
    score = 1;
    stage = "防線測試";
    detail = `盤中測到大量低 ${formatNumber(low)}，收盤守在上方，仍需後續量價確認`;
  }

  return {
    available: true,
    status,
    label,
    tone,
    score,
    stage,
    anchor,
    broken,
    brokenDate,
    lowestAfterBreak,
    distanceToLowPct,
    distanceToHalfPct,
    levels: { low, half, high },
    latest,
    detail,
    note: "修復判讀以收盤價為主：先站回大量低，再看半價與大量高是否陸續收復。"
  };
}

function analyzeOscillatorChecklist(rows, rsiDivergence, macdDivergence, macdValue, rsi14) {
  if (!Array.isArray(rows) || rows.length < 35) {
    return {
      available: false,
      label: "KD / 背離資料不足",
      note: "至少需要 35 根日線才能同時檢查 MACD 與 KD。"
    };
  }
  const kd = kdSeries(rows, 9, 3);
  const kValues = kd.k.filter(Number.isFinite);
  const dValues = kd.d.filter(Number.isFinite);
  const k = kValues.at(-1);
  const d = dValues.at(-1);
  const previousK = kValues.at(-2);
  const previousD = dValues.at(-2);
  const goldenCross = Number.isFinite(previousK) && Number.isFinite(previousD) && Number.isFinite(k) && Number.isFinite(d)
    && previousK <= previousD && k > d;
  const deathCross = Number.isFinite(previousK) && Number.isFinite(previousD) && Number.isFinite(k) && Number.isFinite(d)
    && previousK >= previousD && k < d;
  const kRising = Number.isFinite(previousK) && Number.isFinite(k) && k > previousK;
  const kFalling = Number.isFinite(previousK) && Number.isFinite(k) && k < previousK;
  const oversoldTurn = Number.isFinite(k) && k <= 30 && kRising;
  const overboughtTurn = Number.isFinite(k) && k >= 80 && kFalling;
  const macdImproving = Number.isFinite(macdValue?.histogram) && (
    macdValue.histogram > 0
    || (Number.isFinite(macdValue.previousHistogram) && macdValue.histogram > macdValue.previousHistogram)
  );
  const macdWeakening = Number.isFinite(macdValue?.histogram) && Number.isFinite(macdValue?.previousHistogram)
    && macdValue.histogram < macdValue.previousHistogram;
  const bullishDivergence = Boolean(rsiDivergence?.bullish || macdDivergence?.bullish);
  const bearishDivergence = Boolean(rsiDivergence?.bearish || macdDivergence?.bearish);
  const confirmations = [
    goldenCross ? "KD 黃金交叉" : "",
    oversoldTurn ? "KD 低檔翻揚" : "",
    bullishDivergence ? "RSI / MACD 底背離" : "",
    macdImproving ? "MACD 柱狀體改善" : ""
  ].filter(Boolean);
  const blockers = [
    deathCross ? "KD 死亡交叉" : "",
    overboughtTurn ? "KD 高檔轉弱" : "",
    bearishDivergence ? "RSI / MACD 頂背離" : "",
    macdWeakening ? "MACD 柱狀體轉弱" : ""
  ].filter(Boolean);
  const score = (goldenCross ? 1 : 0)
    + (oversoldTurn ? 1 : 0)
    + (bullishDivergence ? 2 : 0)
    + (macdImproving ? 1 : 0)
    - (deathCross ? 1 : 0)
    - (overboughtTurn ? 1 : 0)
    - (bearishDivergence ? 2 : 0)
    - (macdWeakening ? 1 : 0);
  const tone = bearishDivergence || (deathCross && overboughtTurn) ? "down"
    : bullishDivergence || goldenCross || oversoldTurn ? "up"
      : "flat";
  const summary = tone === "up" ? "動能轉強 / 修復輔助"
    : tone === "down" ? "動能轉弱 / 背離警示"
      : "動能中性";
  const kdLabel = Number.isFinite(k) && Number.isFinite(d)
    ? `K ${formatNumber(k, 1)} / D ${formatNumber(d, 1)}`
    : "KD 資料不足";
  const items = [
    { label: "KD 黃金交叉或低檔翻揚", pass: goldenCross || oversoldTurn, tone: goldenCross || oversoldTurn ? "up" : "flat" },
    { label: "RSI / MACD 底背離", pass: bullishDivergence, tone: bullishDivergence ? "up" : "flat" },
    { label: "MACD 柱狀體改善", pass: macdImproving, tone: macdImproving ? "up" : "flat" },
    { label: "避免 KD 高檔轉弱", pass: !overboughtTurn && !deathCross, tone: overboughtTurn || deathCross ? "down" : "up" },
    { label: "避免 RSI / MACD 頂背離", pass: !bearishDivergence, tone: bearishDivergence ? "down" : "up" }
  ];

  return {
    available: true,
    label: summary,
    summary,
    tone,
    score,
    kd: { k, d, previousK, previousD, goldenCross, deathCross, oversoldTurn, overboughtTurn },
    rsi14,
    macdImproving,
    macdWeakening,
    bullishDivergence,
    bearishDivergence,
    confirmations,
    blockers,
    items,
    detail: `${kdLabel}；${confirmations.length ? `確認：${confirmations.join("、")}` : "暫無明確多方動能確認"}${blockers.length ? `；警示：${blockers.join("、")}` : ""}`,
    note: "KD / 背離只作輔助確認；仍以價格是否收復關鍵線與停損是否有效為主。"
  };
}

function pocMidpoint(poc) {
  if (!poc || !Number.isFinite(poc.priceLow) || !Number.isFinite(poc.priceHigh)) return null;
  return (poc.priceLow + poc.priceHigh) / 2;
}

function analyzePocPosition(latest, volumeProfile) {
  const poc = volumeProfile?.poc || null;
  const close = toNumber(latest?.close);
  if (!poc || close === null) {
    return {
      available: false,
      label: "POC 資料不足",
      note: "需先累積足夠日線與成交量。"
    };
  }
  const low = toNumber(poc.priceLow);
  const high = toNumber(poc.priceHigh);
  const mid = pocMidpoint(poc);
  if (low === null || high === null || mid === null || high <= low) {
    return {
      available: false,
      label: "POC 區間無效",
      note: "價量分布區間不足，暫不納入決策。"
    };
  }
  const distancePct = (close - mid) / mid * 100;
  if (close > high) {
    return {
      available: true,
      status: "above",
      label: "收盤站上 POC 成本區",
      tone: "up",
      score: 1,
      low,
      high,
      mid,
      volume: poc.volume || 0,
      distancePct,
      detail: `收盤 ${formatNumber(close)} 在 POC ${formatNumber(low)} – ${formatNumber(high)} 上方`
    };
  }
  if (close < low) {
    return {
      available: true,
      status: "below",
      label: "收盤仍在 POC 下方",
      tone: "down",
      score: -1,
      low,
      high,
      mid,
      volume: poc.volume || 0,
      distancePct,
      detail: `POC ${formatNumber(low)} – ${formatNumber(high)} 仍是上方成本壓力`
    };
  }
  return {
    available: true,
    status: "inside",
    label: "收盤在 POC 成本區內",
    tone: "flat",
    score: 0,
    low,
    high,
    mid,
    volume: poc.volume || 0,
    distancePct,
    detail: `收盤位於 POC ${formatNumber(low)} – ${formatNumber(high)}，多空成本仍在拉扯`
  };
}

function analyzeAtrRisk(rows, latest, atr14) {
  const close = toNumber(latest?.close);
  const atrValue = toNumber(atr14);
  if (!Array.isArray(rows) || !rows.length || close === null || atrValue === null || atrValue <= 0) {
    return {
      available: false,
      label: "ATR 資料不足",
      note: "需至少 15 根日線才能計算 ATR 風控。"
    };
  }
  const recentRows = rows.slice(-20);
  const recentHigh = Math.max(...recentRows.map((row) => row.high).filter(Number.isFinite));
  const recentLow = Math.min(...recentRows.map((row) => row.low).filter(Number.isFinite));
  const initialStop = roundPriceLevel(close - atrValue * 2);
  const tightStop = roundPriceLevel(close - atrValue * 1.5);
  const trailingStop = Number.isFinite(recentHigh) ? roundPriceLevel(recentHigh - atrValue * 2) : initialStop;
  const volatilityPct = atrValue / close * 100;
  const distanceToTrailingPct = trailingStop !== null ? (close - trailingStop) / close * 100 : null;
  const status = trailingStop !== null && close < trailingStop ? "trailBreak"
    : distanceToTrailingPct !== null && distanceToTrailingPct <= Math.max(2, volatilityPct * 0.5) ? "near"
      : "safe";
  const tone = status === "trailBreak" ? "down" : status === "near" ? "flat" : "up";
  const label = status === "trailBreak" ? "跌破 ATR 追蹤停損"
    : status === "near" ? "貼近 ATR 追蹤停損"
      : "ATR 風險距離尚可";
  const score = status === "trailBreak" ? -2 : status === "near" ? -1 : 1;
  return {
    available: true,
    atr: atrValue,
    initialStop,
    tightStop,
    trailingStop,
    recentHigh: Number.isFinite(recentHigh) ? recentHigh : null,
    recentLow: Number.isFinite(recentLow) ? recentLow : null,
    volatilityPct,
    distanceToTrailingPct,
    status,
    tone,
    label,
    score,
    detail: trailingStop !== null
      ? `追蹤停損 ${formatNumber(trailingStop)}，距收盤 ${distanceToTrailingPct !== null ? formatSignedMetric(distanceToTrailingPct, 2, "%") : "-"}`
      : "ATR 追蹤停損無法計算"
  };
}

function buildTechnicalDecisionLayer({ rows, latest, atr14, volumeProfile, dailyDefense, weeklyDefense, recoverySignal, oscillatorChecklist }) {
  const atrRisk = analyzeAtrRisk(rows, latest, atr14);
  const pocCheck = analyzePocPosition(latest, volumeProfile);
  const daily = dailyDefense || analyzeLargeVolumeDefense(rows, 60);
  const weekly = weeklyDefense || analyzeWeeklyLargeVolumeDefense(rows);
  const recovery = recoverySignal || analyzeLargeVolumeRecovery(rows, daily);
  const oscillator = oscillatorChecklist || null;
  const dailyLowBreak = daily?.available && daily.lowCheck?.status === "breakdown";
  const dailyHighBreak = daily?.available && daily.highCheck?.status === "breakout";
  const weeklyLowBreak = weekly?.available && weekly.lowCheck?.status === "breakdown";
  const weeklyHighBreak = weekly?.available && weekly.highCheck?.status === "breakout";
  const atrBreak = atrRisk?.available && atrRisk.status === "trailBreak";
  const atrNear = atrRisk?.available && atrRisk.status === "near";
  const pocBelow = pocCheck?.available && pocCheck.status === "below";
  const pocAbove = pocCheck?.available && pocCheck.status === "above";
  const recoveryPositive = recovery?.available && ["reclaimedLow", "reclaimedHalf", "reclaimedHigh"].includes(recovery.status);
  const recoveryStrong = recovery?.available && ["reclaimedHalf", "reclaimedHigh"].includes(recovery.status);
  const recoveryWeak = recovery?.available && ["failedRetest", "unrecovered"].includes(recovery.status);
  const oscillatorBull = oscillator?.available && oscillator.tone === "up";
  const oscillatorBear = oscillator?.available && oscillator.tone === "down";
  const score = (daily?.score || 0)
    + (weekly?.score || 0)
    + (atrRisk?.score || 0)
    + (pocCheck?.score || 0)
    + (recovery?.score || 0)
    + (oscillator?.score || 0);

  let summary = "技術決策層：等待確認";
  let action = "維持觀察，等趨勢、成本區與風控線同向。";
  let tone = "flat";
  if (weeklyLowBreak) {
    summary = "週線大量低失守，波段先控風險";
    action = "先檢查部位與停損；未持有者等週線重新站回大量低或 POC 後再評估。";
    tone = "down";
  } else if (dailyLowBreak || atrBreak || recoveryWeak) {
    summary = "日線風控觸發，優先守停損";
    action = "跌破大量低或 ATR 追蹤停損時，不把反彈直接視為買點。";
    tone = "down";
  } else if (recoveryStrong && !pocBelow && !atrNear && !oscillatorBear) {
    summary = "失守後修復，可列再進場觀察";
    action = "已站回大量低後的半價 / 高點修復區，若 R:R 與法人籌碼同向，可用較小部位重新評估。";
    tone = "up";
  } else if (recoveryPositive && !pocBelow) {
    summary = "初步修復，等半價與動能確認";
    action = "先把大量低當成再進場防線；尚未站回半價前，不宜放大部位。";
    tone = "flat";
  } else if (dailyHighBreak && pocAbove && (weeklyHighBreak || !weekly?.available)) {
    summary = "短波攻擊條件較完整";
    action = "若 R:R 與法人籌碼同向，可列入攻擊候選；仍以收盤與停損執行。";
    tone = "up";
  } else if (dailyHighBreak && !pocBelow) {
    summary = "短線突破，等週線或成本區確認";
    action = "可列入候選，但避免追價；等待週線大量高或 POC 上方站穩。";
    tone = "up";
  } else if (pocBelow) {
    summary = "尚未收復成本密集區";
    action = "POC 仍在上方時，反彈先當壓力測試，不急著放大部位。";
    tone = "flat";
  } else if (atrNear) {
    summary = "接近 ATR 風控線";
    action = "可觀察，但部位需縮小或等拉開停損距離。";
    tone = "flat";
  }

  const confirmations = [
    dailyHighBreak ? "日線收復大量高" : "",
    weeklyHighBreak ? "週線收復大量高" : "",
    recoveryPositive ? recovery.label : "",
    pocAbove ? "收盤站上 POC 成本區" : "",
    atrRisk?.status === "safe" ? "ATR 追蹤停損未觸發" : "",
    oscillatorBull ? oscillator.summary : ""
  ].filter(Boolean);
  const blockers = [
    dailyLowBreak ? "日線大量低失守" : "",
    weeklyLowBreak ? "週線大量低失守" : "",
    atrBreak ? "跌破 ATR 追蹤停損" : "",
    pocBelow ? "仍在 POC 成本區下方" : "",
    recoveryWeak ? recovery.label : "",
    oscillatorBear ? oscillator.summary : ""
  ].filter(Boolean);

  return {
    available: true,
    score,
    tone,
    summary,
    action,
    atrRisk,
    pocCheck,
    dailyDefense: daily,
    weeklyDefense: weekly,
    recoverySignal: recovery,
    oscillatorChecklist: oscillator,
    confirmations,
    blockers
  };
}

function buildTechnicalEvent({ key, label, tone = "flat", severity = 1, group = "技術", detail = "", date = "", level = null, rank = 0 }) {
  return { key, label, tone, severity, group, detail, date, level, rank };
}

function buildTechnicalEvents(technical) {
  if (!technical || !technical.ready) return [];
  const events = [];
  const latestDate = technical.latest?.date || "";
  const daily = technical.largeVolumeDefense || technical.decisionLayer?.dailyDefense || null;
  const weekly = technical.weeklyLargeVolumeDefense || technical.decisionLayer?.weeklyDefense || null;
  const decision = technical.decisionLayer || {};
  const atrRisk = decision.atrRisk || null;
  const pocCheck = decision.pocCheck || null;
  const recovery = technical.recoverySignal || decision.recoverySignal || null;
  const oscillator = technical.oscillatorChecklist || decision.oscillatorChecklist || null;
  const close = toNumber(technical.latest?.close);

  const push = (event) => {
    if (!event || !event.key) return;
    events.push(buildTechnicalEvent({ date: latestDate, ...event }));
  };

  if (daily?.available) {
    const highLevel = toNumber(daily.highAnchor?.high);
    const lowLevel = toNumber(daily.lowAnchor?.low);
    if (daily.highCheck?.status === "breakout") {
      push({
        key: "daily-large-high-breakout",
        label: "站上日線大量高",
        tone: "up",
        severity: 7,
        group: "大量K",
        detail: `${daily.highCheck.label}；錨點 ${daily.highAnchor?.date || "-"} 高 ${formatNumber(highLevel)}`,
        level: highLevel,
        rank: 110 + Math.max(0, daily.highCheck.distancePct || 0)
      });
    } else if (daily.highCheck?.status === "test") {
      push({
        key: "daily-large-high-test",
        label: "測大量高未確認",
        tone: "flat",
        severity: 4,
        group: "大量K",
        detail: `${daily.highCheck.label}；仍需收盤站上 ${formatNumber(highLevel)}`,
        level: highLevel,
        rank: 45 - Math.abs(daily.highCheck.distancePct || 0)
      });
    }
    if (daily.lowCheck?.status === "breakdown") {
      push({
        key: "daily-large-low-breakdown",
        label: "跌破日線大量低",
        tone: "down",
        severity: 9,
        group: "大量K",
        detail: `${daily.lowCheck.label}；錨點 ${daily.lowAnchor?.date || "-"} 低 ${formatNumber(lowLevel)}`,
        level: lowLevel,
        rank: 125 + Math.abs(daily.lowCheck.distancePct || 0)
      });
    } else if (daily.lowCheck?.status === "test") {
      push({
        key: "daily-large-low-test-held",
        label: "測大量低後守住",
        tone: "flat",
        severity: 5,
        group: "大量K",
        detail: `${daily.lowCheck.label}；防線 ${formatNumber(lowLevel)}`,
        level: lowLevel,
        rank: 60 - Math.abs(daily.lowCheck.distancePct || 0)
      });
    }
  }

  if (weekly?.available) {
    const weeklyLow = toNumber(weekly.lowAnchor?.low);
    const weeklyHigh = toNumber(weekly.highAnchor?.high);
    if (weekly.lowCheck?.status === "breakdown") {
      push({
        key: "weekly-large-low-breakdown",
        label: "週線大量低失守",
        tone: "down",
        severity: 10,
        group: "週線",
        detail: `${weekly.lowCheck.label}；週線錨點 ${weekly.lowAnchor?.date || "-"} 低 ${formatNumber(weeklyLow)}`,
        level: weeklyLow,
        rank: 140 + Math.abs(weekly.lowCheck.distancePct || 0)
      });
    }
    if (weekly.highCheck?.status === "breakout") {
      push({
        key: "weekly-large-high-breakout",
        label: "週線大量高收復",
        tone: "up",
        severity: 8,
        group: "週線",
        detail: `${weekly.highCheck.label}；週線錨點 ${weekly.highAnchor?.date || "-"} 高 ${formatNumber(weeklyHigh)}`,
        level: weeklyHigh,
        rank: 115 + Math.max(0, weekly.highCheck.distancePct || 0)
      });
    }
  }

  if (recovery?.available) {
    const recoveryEvents = {
      failedRetest: {
        label: "反彈測低未收復",
        tone: "down",
        severity: 9,
        rank: 128,
        detail: recovery.detail
      },
      unrecovered: {
        label: "大量低失守未修復",
        tone: "down",
        severity: 8,
        rank: 116,
        detail: recovery.detail
      },
      reclaimedLow: {
        label: "重新站回大量低",
        tone: "flat",
        severity: 6,
        rank: 76,
        detail: recovery.detail
      },
      reclaimedHalf: {
        label: "站回大量半價",
        tone: "up",
        severity: 7,
        rank: 104,
        detail: recovery.detail
      },
      reclaimedHigh: {
        label: "站上大量高 / 強修復",
        tone: "up",
        severity: 8,
        rank: 118,
        detail: recovery.detail
      },
      testedHeld: {
        label: "大量低防線測試",
        tone: "flat",
        severity: 5,
        rank: 62,
        detail: recovery.detail
      }
    };
    const event = recoveryEvents[recovery.status];
    if (event) {
      push({
        key: `recovery-${recovery.status}`,
        group: "修復",
        level: recovery.levels?.low ?? null,
        ...event
      });
    }
  }

  if (atrRisk?.available) {
    if (atrRisk.status === "trailBreak") {
      push({
        key: "atr-trailing-break",
        label: "跌破 ATR 追蹤停損",
        tone: "down",
        severity: 10,
        group: "風控",
        detail: atrRisk.detail,
        level: atrRisk.trailingStop,
        rank: 138 + Math.abs(atrRisk.distanceToTrailingPct || 0)
      });
    } else if (atrRisk.status === "near") {
      push({
        key: "atr-trailing-near",
        label: "貼近 ATR 追蹤停損",
        tone: "flat",
        severity: 6,
        group: "風控",
        detail: atrRisk.detail,
        level: atrRisk.trailingStop,
        rank: 70 - Math.max(0, atrRisk.distanceToTrailingPct || 0)
      });
    }
  }

  if (pocCheck?.available) {
    if (pocCheck.status === "above") {
      push({
        key: "poc-above",
        label: "站上 POC 成本區",
        tone: "up",
        severity: 5,
        group: "成本區",
        detail: pocCheck.detail,
        level: pocCheck.mid,
        rank: 72 + Math.max(0, pocCheck.distancePct || 0)
      });
    } else if (pocCheck.status === "below") {
      push({
        key: "poc-below",
        label: "仍在 POC 下方",
        tone: "down",
        severity: 6,
        group: "成本區",
        detail: pocCheck.detail,
        level: pocCheck.mid,
        rank: 82 + Math.abs(pocCheck.distancePct || 0)
      });
    }
  }

  if (oscillator?.available) {
    const kd = oscillator.kd || {};
    if (kd.goldenCross) {
      push({
        key: "kd-golden-cross",
        label: "KD 黃金交叉",
        tone: "up",
        severity: 4,
        group: "動能",
        detail: `K ${formatNumber(kd.k, 1)} / D ${formatNumber(kd.d, 1)}`,
        rank: 58 + (oscillator.score || 0)
      });
    }
    if (kd.deathCross) {
      push({
        key: "kd-death-cross",
        label: "KD 死亡交叉",
        tone: "down",
        severity: 5,
        group: "動能",
        detail: `K ${formatNumber(kd.k, 1)} / D ${formatNumber(kd.d, 1)}`,
        rank: 68 + Math.abs(oscillator.score || 0)
      });
    }
    if (kd.oversoldTurn) {
      push({
        key: "kd-oversold-turn",
        label: "KD 低檔翻揚",
        tone: "up",
        severity: 4,
        group: "動能",
        detail: oscillator.detail,
        rank: 60 + (oscillator.score || 0)
      });
    }
    if (kd.overboughtTurn) {
      push({
        key: "kd-overbought-turn",
        label: "KD 高檔轉弱",
        tone: "down",
        severity: 5,
        group: "動能",
        detail: oscillator.detail,
        rank: 72 + Math.abs(oscillator.score || 0)
      });
    }
    if (oscillator.bullishDivergence) {
      push({
        key: "bullish-divergence",
        label: "RSI / MACD 底背離",
        tone: "up",
        severity: 6,
        group: "背離",
        detail: oscillator.detail,
        rank: 86 + (oscillator.score || 0)
      });
    }
    if (oscillator.bearishDivergence) {
      push({
        key: "bearish-divergence",
        label: "RSI / MACD 頂背離",
        tone: "down",
        severity: 7,
        group: "背離",
        detail: oscillator.detail,
        rank: 102 + Math.abs(oscillator.score || 0)
      });
    }
  }

  if (close !== null && technical.rsi14 !== null) {
    if (technical.rsi14 >= 75) {
      push({
        key: "rsi-overheat",
        label: "RSI 過熱",
        tone: "down",
        severity: 5,
        group: "動能",
        detail: `RSI14 ${formatNumber(technical.rsi14, 1)}；持倉者留意停利或回檔`,
        rank: 66 + Math.max(0, technical.rsi14 - 75)
      });
    } else if (technical.rsi14 <= 30) {
      push({
        key: "rsi-oversold",
        label: "RSI 超賣",
        tone: "up",
        severity: 4,
        group: "動能",
        detail: `RSI14 ${formatNumber(technical.rsi14, 1)}；仍需價格收復確認`,
        rank: 52 + Math.max(0, 30 - technical.rsi14)
      });
    }
  }

  return events
    .sort((left, right) => right.severity - left.severity || right.rank - left.rank || String(left.label).localeCompare(String(right.label)));
}

function technicalEventFreshness(daysAgo) {
  if (!Number.isFinite(daysAgo)) return "待判斷";
  if (daysAgo === 0) return "今日";
  if (daysAgo <= 2) return "近3日";
  if (daysAgo <= 5) return "近5日";
  return "延續";
}

function technicalEventAgeText(daysAgo) {
  if (!Number.isFinite(daysAgo)) return "-";
  return daysAgo === 0 ? "今日" : `${daysAgo} 交易日前`;
}

function technicalEventFreshnessBonus(daysAgo) {
  if (!Number.isFinite(daysAgo)) return 0;
  if (daysAgo === 0) return 45;
  if (daysAgo <= 2) return 32;
  if (daysAgo <= 5) return 18;
  return Math.max(0, 12 - daysAgo);
}

function buildTechnicalEventTimeline(technical, lookback = 20) {
  const rows = Array.isArray(technical?.rows) ? technical.rows : [];
  if (!technical?.ready || rows.length < 22) {
    return {
      available: false,
      lookback,
      events: [],
      freshEvents: [],
      activeEvents: [],
      riskEvents: [],
      opportunityEvents: [],
      latestEvent: null,
      tone: "flat",
      score: 0,
      priority: 0,
      summary: rows.length ? "日線根數不足，暫無事件新鮮度。" : "尚無日線資料。",
      note: "需至少 22 根日線才能回看最近事件。"
    };
  }

  const latest = rows.at(-1);
  const latestClose = toNumber(latest?.close);
  const startIndex = Math.max(1, rows.length - lookback);
  const events = [];
  const closes = rows.map((row) => row.close);
  const ma20Series = smaSeries(closes, 20);
  const atr14Series = atrSeries(rows, 14);
  const latestMa20 = ma20Series.at(-1);
  const latestAtr = atr14Series.at(-1);
  const daily = technical.largeVolumeDefense || technical.decisionLayer?.dailyDefense || null;
  const weekly = technical.weeklyLargeVolumeDefense || technical.decisionLayer?.weeklyDefense || null;
  const poc = technical.decisionLayer?.pocCheck || analyzePocPosition(latest, technical.volumeProfile);

  const firstIndexAfterAnchor = (anchor, fallbackIndex = startIndex) => {
    if (!anchor) return fallbackIndex;
    if (anchor.date) {
      const dateIndex = rows.findIndex((row) => String(row.date || "") > String(anchor.date));
      if (dateIndex >= 1) return Math.max(fallbackIndex, dateIndex);
      return rows.length;
    }
    if (Number.isFinite(anchor.index)) return Math.max(fallbackIndex, Math.min(rows.length - 1, anchor.index + 1));
    return fallbackIndex;
  };

  const crossedAbove = (prev, row, level) => {
    const l = toNumber(level);
    return prev && row && l !== null && toNumber(prev.close) !== null && toNumber(row.close) !== null && prev.close <= l && row.close > l;
  };
  const crossedBelow = (prev, row, level) => {
    const l = toNumber(level);
    return prev && row && l !== null && toNumber(prev.close) !== null && toNumber(row.close) !== null && prev.close >= l && row.close < l;
  };

  const addEvent = ({ key, label, tone, group, severity, level = null, date, index, detail = "", active = false, rank = 0 }) => {
    if (!key || !date || !Number.isFinite(index)) return;
    const daysAgo = rows.length - 1 - index;
    const freshness = technicalEventFreshness(daysAgo);
    const priority = (severity || 1) * 20 + technicalEventFreshnessBonus(daysAgo) + (active ? 15 : 0) + (rank || 0) * 0.05;
    events.push({
      key,
      label,
      tone,
      group,
      severity,
      level,
      date,
      index,
      daysAgo,
      freshness,
      active: Boolean(active),
      rank,
      priority,
      close: rows[index]?.close ?? null,
      detail
    });
  };

  const scanCross = ({ key, label, tone, group, severity, level, minIndex = startIndex, activeWhen = () => false, detail = "", rank = 0 }) => {
    const l = toNumber(level);
    if (l === null || l <= 0) return;
    const begin = Math.max(1, minIndex, startIndex);
    for (let index = begin; index < rows.length; index += 1) {
      const prev = rows[index - 1];
      const row = rows[index];
      const hit = tone === "down" ? crossedBelow(prev, row, l) : crossedAbove(prev, row, l);
      if (!hit) continue;
      addEvent({
        key,
        label,
        tone,
        group,
        severity,
        level: l,
        date: row.date,
        index,
        detail,
        active: activeWhen(l),
        rank
      });
    }
  };

  if (daily?.available) {
    const highLevel = toNumber(daily.highAnchor?.high);
    const lowLevel = toNumber(daily.lowAnchor?.low);
    const halfLevel = toNumber(daily.lowAnchor?.half ?? daily.latestAnchor?.half);
    const dailyStart = firstIndexAfterAnchor(daily.latestAnchor || daily.highAnchor || daily.lowAnchor);
    scanCross({
      key: "fresh-daily-large-high-breakout",
      label: "過日線大量高",
      tone: "up",
      group: "大量K",
      severity: 8,
      level: highLevel,
      minIndex: dailyStart,
      activeWhen: (level) => latestClose !== null && latestClose > level,
      detail: `收盤穿越 ${daily.highAnchor?.date || "-"} 大量高 ${formatNumber(highLevel)}`,
      rank: 112
    });
    scanCross({
      key: "fresh-daily-large-low-breakdown",
      label: "破日線大量低",
      tone: "down",
      group: "大量K",
      severity: 10,
      level: lowLevel,
      minIndex: dailyStart,
      activeWhen: (level) => latestClose !== null && latestClose < level,
      detail: `收盤跌破 ${daily.lowAnchor?.date || "-"} 大量低 ${formatNumber(lowLevel)}`,
      rank: 135
    });
    scanCross({
      key: "fresh-daily-large-low-reclaim",
      label: "收復日線大量低",
      tone: "up",
      group: "修復",
      severity: 7,
      level: lowLevel,
      minIndex: dailyStart,
      activeWhen: (level) => latestClose !== null && latestClose >= level,
      detail: `失守後重新站回大量低 ${formatNumber(lowLevel)}`,
      rank: 92
    });
    scanCross({
      key: "fresh-daily-large-half-reclaim",
      label: "站回大量半價",
      tone: "up",
      group: "修復",
      severity: 7,
      level: halfLevel,
      minIndex: dailyStart,
      activeWhen: (level) => latestClose !== null && latestClose >= level,
      detail: `收盤站回大量 K 半價 ${formatNumber(halfLevel)}`,
      rank: 102
    });
  }

  if (weekly?.available) {
    const weeklyHigh = toNumber(weekly.highAnchor?.high);
    const weeklyLow = toNumber(weekly.lowAnchor?.low);
    scanCross({
      key: "fresh-weekly-large-high-breakout",
      label: "過週線大量高",
      tone: "up",
      group: "週線",
      severity: 9,
      level: weeklyHigh,
      minIndex: firstIndexAfterAnchor(weekly.highAnchor),
      activeWhen: (level) => latestClose !== null && latestClose > level,
      detail: `收盤穿越週線大量高 ${formatNumber(weeklyHigh)}`,
      rank: 126
    });
    scanCross({
      key: "fresh-weekly-large-low-breakdown",
      label: "破週線大量低",
      tone: "down",
      group: "週線",
      severity: 10,
      level: weeklyLow,
      minIndex: firstIndexAfterAnchor(weekly.lowAnchor),
      activeWhen: (level) => latestClose !== null && latestClose < level,
      detail: `收盤跌破週線大量低 ${formatNumber(weeklyLow)}`,
      rank: 145
    });
  }

  if (poc?.available) {
    scanCross({
      key: "fresh-poc-reclaim",
      label: "站上 POC 成本區",
      tone: "up",
      group: "成本區",
      severity: 6,
      level: poc.high,
      activeWhen: (level) => latestClose !== null && latestClose > level,
      detail: `收盤站上 POC 區間上緣 ${formatNumber(poc.high)}`,
      rank: 78
    });
    scanCross({
      key: "fresh-poc-break",
      label: "跌破 POC 成本區",
      tone: "down",
      group: "成本區",
      severity: 7,
      level: poc.low,
      activeWhen: (level) => latestClose !== null && latestClose < level,
      detail: `收盤跌破 POC 區間下緣 ${formatNumber(poc.low)}`,
      rank: 90
    });
  }

  for (let index = Math.max(20, startIndex); index < rows.length; index += 1) {
    const prev = rows[index - 1];
    const row = rows[index];
    const prevMa20 = ma20Series[index - 1];
    const rowMa20 = ma20Series[index];
    if (prevMa20 !== null && rowMa20 !== null) {
      if (prev.close <= prevMa20 && row.close > rowMa20) {
        addEvent({
          key: "fresh-ma20-reclaim",
          label: "收復 MA20",
          tone: "up",
          group: "均線",
          severity: 5,
          level: rowMa20,
          date: row.date,
          index,
          detail: `收盤 ${formatNumber(row.close)} 重新站上 MA20 ${formatNumber(rowMa20)}`,
          active: latestClose !== null && latestMa20 !== null && latestClose > latestMa20,
          rank: 68
        });
      }
      if (prev.close >= prevMa20 && row.close < rowMa20) {
        addEvent({
          key: "fresh-ma20-loss",
          label: "跌破 MA20",
          tone: "down",
          group: "均線",
          severity: 6,
          level: rowMa20,
          date: row.date,
          index,
          detail: `收盤 ${formatNumber(row.close)} 跌破 MA20 ${formatNumber(rowMa20)}`,
          active: latestClose !== null && latestMa20 !== null && latestClose < latestMa20,
          rank: 82
        });
      }
    }
    const prevAtr = atr14Series[index - 1];
    const rowAtr = atr14Series[index];
    if (prevAtr !== null && rowAtr !== null) {
      const prevHigh = Math.max(...rows.slice(Math.max(0, index - 20), index).map((entry) => entry.high).filter(Number.isFinite));
      const rowHigh = Math.max(...rows.slice(Math.max(0, index - 19), index + 1).map((entry) => entry.high).filter(Number.isFinite));
      const prevTrail = Number.isFinite(prevHigh) ? roundPriceLevel(prevHigh - prevAtr * 2) : null;
      const rowTrail = Number.isFinite(rowHigh) ? roundPriceLevel(rowHigh - rowAtr * 2) : null;
      if (prevTrail !== null && rowTrail !== null && prev.close >= prevTrail && row.close < rowTrail) {
        const currentTrail = latestAtr !== null
          ? roundPriceLevel(Math.max(...rows.slice(-20).map((entry) => entry.high).filter(Number.isFinite)) - latestAtr * 2)
          : null;
        addEvent({
          key: "fresh-atr-trailing-break",
          label: "跌破 ATR 追蹤停損",
          tone: "down",
          group: "風控",
          severity: 10,
          level: rowTrail,
          date: row.date,
          index,
          detail: `收盤 ${formatNumber(row.close)} 跌破 ATR 追蹤線 ${formatNumber(rowTrail)}`,
          active: latestClose !== null && currentTrail !== null && latestClose < currentTrail,
          rank: 142
        });
      }
    }
  }

  const deduped = [...events]
    .sort((left, right) => right.index - left.index || right.priority - left.priority)
    .filter((event, index, array) => index === array.findIndex((other) => other.key === event.key && other.index === event.index));
  const freshEvents = deduped.filter((event) => event.daysAgo <= 5);
  const activeEvents = deduped.filter((event) => event.active);
  const riskEvents = deduped.filter((event) => event.tone === "down");
  const opportunityEvents = deduped.filter((event) => event.tone === "up");
  const freshRisk = freshEvents.filter((event) => event.tone === "down").sort((left, right) => right.priority - left.priority)[0] || null;
  const freshOpportunity = freshEvents.filter((event) => event.tone === "up").sort((left, right) => right.priority - left.priority)[0] || null;
  const activeRisk = activeEvents.filter((event) => event.tone === "down").sort((left, right) => right.priority - left.priority)[0] || null;
  const activeOpportunity = activeEvents.filter((event) => event.tone === "up").sort((left, right) => right.priority - left.priority)[0] || null;
  const latestEvent = deduped[0] || null;
  const score = Math.round(deduped.reduce((sum, event) => {
    const recencyWeight = event.daysAgo === 0 ? 1.2 : event.daysAgo <= 2 ? 1 : event.daysAgo <= 5 ? 0.75 : 0.35;
    const activeWeight = event.active ? 1 : 0.55;
    const value = (event.severity || 1) * recencyWeight * activeWeight;
    if (event.tone === "down") return sum - value;
    if (event.tone === "up") return sum + value;
    return sum;
  }, 0));
  const priority = deduped.length ? Math.max(...deduped.map((event) => event.priority || 0)) : 0;
  const tone = freshRisk ? "down"
    : freshOpportunity ? "up"
      : activeRisk ? "down"
        : activeOpportunity ? "up"
          : score < 0 ? "down"
            : score > 0 ? "up"
              : "flat";
  const summary = freshRisk
    ? `${freshRisk.freshness}風險事件：${freshRisk.label}（${technicalEventAgeText(freshRisk.daysAgo)}，${freshRisk.active ? "仍有效" : "已失效"}）`
    : freshOpportunity
      ? `${freshOpportunity.freshness}攻擊 / 修復事件：${freshOpportunity.label}（${technicalEventAgeText(freshOpportunity.daysAgo)}，${freshOpportunity.active ? "仍有效" : "已失效"}）`
      : activeRisk
        ? `風險事件延續：${activeRisk.label}（${technicalEventAgeText(activeRisk.daysAgo)}）`
        : activeOpportunity
          ? `攻擊 / 修復事件延續：${activeOpportunity.label}（${technicalEventAgeText(activeOpportunity.daysAgo)}）`
          : latestEvent
            ? `近 ${lookback} 根日線最後事件：${latestEvent.label}（${technicalEventAgeText(latestEvent.daysAgo)}，${latestEvent.active ? "仍有效" : "已失效"}）`
            : `近 ${lookback} 根日線未偵測到收盤穿越事件`;

  return {
    available: true,
    lookback,
    events: deduped,
    freshEvents,
    activeEvents,
    riskEvents,
    opportunityEvents,
    latestEvent,
    freshRisk,
    freshOpportunity,
    activeRisk,
    activeOpportunity,
    tone,
    score,
    priority,
    summary,
    note: `事件新鮮度以最近 ${lookback} 根日線的收盤穿越大量 K 高低 / 半價、週線大量 K、POC、MA20 與 ATR 追蹤停損回推；舊事件若最新收盤已回到關卡另一側會標示已失效。`
  };
}

const EVENT_BACKTEST_HORIZONS = [1, 3, 5, 10];

function normalizeTechnicalEventType(event) {
  const key = String(event?.key || "");
  const label = String(event?.label || "");
  if (key.includes("daily-large-high-breakout") || label.includes("日線大量高") || label.includes("大量高")) return "dailyHighBreakout";
  if (key.includes("daily-large-low-breakdown") || label.includes("破日線大量低") || label.includes("跌破日線大量低")) return "dailyLowBreakdown";
  if (key.includes("daily-large-low-reclaim") || key.includes("recovery-reclaimedLow") || label.includes("收復日線大量低") || label.includes("重新站回大量低")) return "dailyLowReclaim";
  if (key.includes("daily-large-half-reclaim") || key.includes("recovery-reclaimedHalf") || label.includes("站回大量半價")) return "dailyHalfReclaim";
  if (key.includes("weekly-large-high-breakout") || label.includes("週線大量高")) return "weeklyHighBreakout";
  if (key.includes("weekly-large-low-breakdown") || label.includes("週線大量低")) return "weeklyLowBreakdown";
  if (key.includes("poc-reclaim") || key.includes("poc-above") || label.includes("站上 POC")) return "pocReclaim";
  if (key.includes("poc-break") || key.includes("poc-below") || label.includes("跌破 POC") || label.includes("仍在 POC 下方")) return "pocBreak";
  if (key.includes("ma20-reclaim") || label.includes("收復 MA20")) return "ma20Reclaim";
  if (key.includes("ma20-loss") || label.includes("跌破 MA20")) return "ma20Loss";
  if (key.includes("atr-trailing-break") || label.includes("ATR 追蹤停損")) return "atrBreak";
  return null;
}

function technicalEventTypeMeta(type) {
  const map = {
    dailyHighBreakout: { label: "過日線大量高", tone: "up", direction: 1, group: "大量K" },
    dailyLowBreakdown: { label: "破日線大量低", tone: "down", direction: -1, group: "大量K" },
    dailyLowReclaim: { label: "收復日線大量低", tone: "up", direction: 1, group: "修復" },
    dailyHalfReclaim: { label: "站回大量半價", tone: "up", direction: 1, group: "修復" },
    weeklyHighBreakout: { label: "過週線大量高", tone: "up", direction: 1, group: "週線" },
    weeklyLowBreakdown: { label: "破週線大量低", tone: "down", direction: -1, group: "週線" },
    pocReclaim: { label: "站上 POC 成本區", tone: "up", direction: 1, group: "成本區" },
    pocBreak: { label: "跌破 POC 成本區", tone: "down", direction: -1, group: "成本區" },
    ma20Reclaim: { label: "收復 MA20", tone: "up", direction: 1, group: "均線" },
    ma20Loss: { label: "跌破 MA20", tone: "down", direction: -1, group: "均線" },
    atrBreak: { label: "跌破 ATR 追蹤停損", tone: "down", direction: -1, group: "風控" }
  };
  return map[type] || null;
}

function detectHistoricalEventType(rows, index, type, ma20Series, atr14Series) {
  if (!Array.isArray(rows) || index < 1 || index >= rows.length) return false;
  const prev = rows[index - 1];
  const row = rows[index];
  if (!prev || !row || toNumber(prev.close) === null || toNumber(row.close) === null) return false;
  const crossedAboveLevel = (level) => {
    const l = toNumber(level);
    return l !== null && l > 0 && prev.close <= l && row.close > l;
  };
  const crossedBelowLevel = (level) => {
    const l = toNumber(level);
    return l !== null && l > 0 && prev.close >= l && row.close < l;
  };

  if (type === "ma20Reclaim" || type === "ma20Loss") {
    const prevMa20 = ma20Series[index - 1];
    const rowMa20 = ma20Series[index];
    if (prevMa20 === null || rowMa20 === null) return false;
    return type === "ma20Reclaim"
      ? prev.close <= prevMa20 && row.close > rowMa20
      : prev.close >= prevMa20 && row.close < rowMa20;
  }

  if (type === "atrBreak") {
    const prevAtr = atr14Series[index - 1];
    const rowAtr = atr14Series[index];
    if (prevAtr === null || rowAtr === null) return false;
    const prevHigh = Math.max(...rows.slice(Math.max(0, index - 20), index).map((entry) => entry.high).filter(Number.isFinite));
    const rowHigh = Math.max(...rows.slice(Math.max(0, index - 19), index + 1).map((entry) => entry.high).filter(Number.isFinite));
    const prevTrail = Number.isFinite(prevHigh) ? roundPriceLevel(prevHigh - prevAtr * 2) : null;
    const rowTrail = Number.isFinite(rowHigh) ? roundPriceLevel(rowHigh - rowAtr * 2) : null;
    return prevTrail !== null && rowTrail !== null && prev.close >= prevTrail && row.close < rowTrail;
  }

  const history = rows.slice(0, index);
  if (["dailyHighBreakout", "dailyLowBreakdown", "dailyLowReclaim", "dailyHalfReclaim"].includes(type)) {
    const daily = analyzeLargeVolumeDefense(history, 60);
    if (!daily?.available) return false;
    const highLevel = daily.highAnchor?.high;
    const lowLevel = daily.lowAnchor?.low;
    const halfLevel = daily.lowAnchor?.half ?? daily.latestAnchor?.half;
    if (type === "dailyHighBreakout") return crossedAboveLevel(highLevel);
    if (type === "dailyLowBreakdown") return crossedBelowLevel(lowLevel);
    if (type === "dailyLowReclaim") {
      const level = toNumber(lowLevel);
      return level !== null && prev.close < level && row.close >= level;
    }
    if (type === "dailyHalfReclaim") {
      const level = toNumber(halfLevel);
      return level !== null && prev.close < level && row.close >= level;
    }
  }

  if (type === "weeklyHighBreakout" || type === "weeklyLowBreakdown") {
    const weekly = analyzeWeeklyLargeVolumeDefense(history);
    if (!weekly?.available) return false;
    return type === "weeklyHighBreakout"
      ? crossedAboveLevel(weekly.highAnchor?.high)
      : crossedBelowLevel(weekly.lowAnchor?.low);
  }

  if (type === "pocReclaim" || type === "pocBreak") {
    const profile = calculateVolumeProfile(rows.slice(Math.max(0, index - 60), index), 12);
    const poc = analyzePocPosition(prev, profile);
    if (!poc?.available) return false;
    return type === "pocReclaim"
      ? crossedAboveLevel(poc.high)
      : crossedBelowLevel(poc.low);
  }

  return false;
}

function eventOutcomeStats(rows, index, horizon, direction = 1) {
  const entry = rows[index];
  const future = rows[index + horizon];
  const entryClose = toNumber(entry?.close);
  const futureClose = toNumber(future?.close);
  if (entryClose === null || futureClose === null || entryClose <= 0) return null;
  const windowRows = rows.slice(index + 1, index + horizon + 1);
  const returnPct = (futureClose - entryClose) / entryClose * 100;
  const continuation = direction >= 0 ? returnPct > 0 : returnPct < 0;
  const lows = windowRows.map((row) => row.low).filter(Number.isFinite);
  const highs = windowRows.map((row) => row.high).filter(Number.isFinite);
  const adversePct = direction >= 0
    ? (lows.length ? (Math.min(...lows) - entryClose) / entryClose * 100 : null)
    : (highs.length ? (Math.max(...highs) - entryClose) / entryClose * 100 : null);
  const favorablePct = direction >= 0
    ? (highs.length ? (Math.max(...highs) - entryClose) / entryClose * 100 : null)
    : (lows.length ? (entryClose - Math.min(...lows)) / entryClose * 100 : null);
  return {
    horizon,
    returnPct,
    continuation,
    adversePct,
    favorablePct,
    date: future.date
  };
}

function summarizeEventBacktestMatches(rows, matches, direction = 1) {
  return EVENT_BACKTEST_HORIZONS.map((horizon) => {
    const outcomes = matches
      .map((match) => eventOutcomeStats(rows, match.index, horizon, direction))
      .filter(Boolean);
    const n = outcomes.length;
    if (!n) {
      return { horizon, n: 0, continuationRate: null, avgReturnPct: null, avgAdversePct: null, avgFavorablePct: null };
    }
    const continuationRate = outcomes.filter((item) => item.continuation).length / n * 100;
    const avgReturnPct = average(outcomes.map((item) => item.returnPct));
    const avgAdversePct = average(outcomes.map((item) => item.adversePct).filter((value) => value !== null));
    const avgFavorablePct = average(outcomes.map((item) => item.favorablePct).filter((value) => value !== null));
    return {
      horizon,
      n,
      continuationRate,
      avgReturnPct,
      avgAdversePct,
      avgFavorablePct
    };
  });
}

function buildTechnicalEventBacktest(technical, maxLookback = 260) {
  const rows = Array.isArray(technical?.rows) ? technical.rows : [];
  const timeline = technical?.eventTimeline;
  const focusEvent = (timeline?.freshEvents || []).slice().sort((left, right) => right.priority - left.priority || left.daysAgo - right.daysAgo)[0]
    || (timeline?.activeEvents || []).slice().sort((left, right) => right.priority - left.priority || left.daysAgo - right.daysAgo)[0]
    || null;
  const type = normalizeTechnicalEventType(focusEvent);
  const meta = technicalEventTypeMeta(type);
  if (!technical?.ready || rows.length < 45 || !focusEvent || !type || !meta) {
    return {
      available: false,
      focusEvent,
      type,
      meta,
      matches: [],
      horizons: [],
      sampleSize: 0,
      confidence: "不足",
      tone: "flat",
      score: 0,
      summary: focusEvent ? "此事件目前沒有足夠歷史樣本可做續航統計。" : "近 20 日沒有可回測的技術事件。",
      note: "需累積足夠日線，且事件類型需屬於大量 K、週線大量 K、POC、MA20 或 ATR。"
    };
  }

  const closes = rows.map((row) => row.close);
  const ma20Series = smaSeries(closes, 20);
  const atr14Series = atrSeries(rows, 14);
  const maxHorizon = Math.max(...EVENT_BACKTEST_HORIZONS);
  const startIndex = Math.max(22, rows.length - maxLookback);
  const endIndex = Math.max(startIndex, rows.length - maxHorizon - 1);
  const matches = [];
  for (let index = startIndex; index <= endIndex; index += 1) {
    if (focusEvent?.index === index) continue;
    if (!detectHistoricalEventType(rows, index, type, ma20Series, atr14Series)) continue;
    matches.push({
      index,
      date: rows[index].date,
      close: rows[index].close
    });
  }

  const horizons = summarizeEventBacktestMatches(rows, matches, meta.direction);
  const h5 = horizons.find((item) => item.horizon === 5) || horizons.find((item) => item.n) || null;
  const sampleSize = h5?.n || 0;
  const confidence = sampleSize >= 12 ? "高"
    : sampleSize >= 6 ? "中"
      : sampleSize >= 3 ? "低"
        : "不足";
  const continuationRate = h5?.continuationRate ?? null;
  const directionalAvg = h5?.avgReturnPct !== null && h5?.avgReturnPct !== undefined ? h5.avgReturnPct * meta.direction : null;
  const continuationStrong = continuationRate !== null && continuationRate >= 58 && directionalAvg !== null && directionalAvg > 0;
  const continuationWeak = continuationRate !== null && continuationRate <= 42;
  const tone = sampleSize < 3 ? "flat"
    : continuationStrong ? meta.tone
      : continuationWeak ? (meta.tone === "up" ? "down" : "up")
        : "flat";
  const score = sampleSize < 3 || continuationRate === null || directionalAvg === null
    ? 0
    : Math.round((continuationRate - 50) * 0.5 + directionalAvg * 2);
  const summary = sampleSize < 3
    ? `${meta.label} 歷史樣本不足（${sampleSize} 筆），暫不把續航統計納入判斷。`
    : `${meta.label} 歷史樣本 ${sampleSize} 筆：5日續航 ${formatNumber(continuationRate, 0)}%，平均 ${formatSignedMetric(h5.avgReturnPct, 2, "%")}，平均逆風 ${formatSignedMetric(h5.avgAdversePct, 2, "%")}`;

  return {
    available: true,
    focusEvent,
    type,
    meta,
    matches,
    horizons,
    sampleSize,
    confidence,
    tone,
    score,
    summary,
    note: `現行方法以同一檔個股過去 ${maxLookback} 根日線內的相似事件做簡易事件研究；續航率是事件後指定天數收盤沿事件方向延續的比例，樣本少於 3 筆時僅作提示。`
  };
}

function buildTradingStateMachine(technical) {
  const events = Array.isArray(technical?.events) && technical.events.length
    ? technical.events
    : buildTechnicalEvents(technical);
  if (!technical || !technical.ready) {
    return {
      available: false,
      state: "dataPending",
      label: "資料待補",
      tone: "flat",
      score: 0,
      priority: 0,
      action: "先更新日線與報價。",
      positionRule: "不建立新部位",
      riskRule: "缺資料時不做交易判斷",
      nextCheck: "更新日線後重新計算",
      reasons: [],
      blockers: ["日線資料不足"],
      events: []
    };
  }

  const daily = technical.largeVolumeDefense || technical.decisionLayer?.dailyDefense || null;
  const decision = technical.decisionLayer || {};
  const weekly = technical.weeklyLargeVolumeDefense || decision.weeklyDefense || null;
  const recovery = technical.recoverySignal || decision.recoverySignal || null;
  const oscillator = technical.oscillatorChecklist || decision.oscillatorChecklist || null;
  const playbook = technical.playbook || {};
  const latestClose = toNumber(technical.latest?.close);
  const dailyLowBreak = daily?.available && daily.lowCheck?.status === "breakdown";
  const dailyHighBreak = daily?.available && daily.highCheck?.status === "breakout";
  const weeklyLowBreak = weekly?.available && weekly.lowCheck?.status === "breakdown";
  const weeklyHighBreak = weekly?.available && weekly.highCheck?.status === "breakout";
  const atrBreak = decision.atrRisk?.available && decision.atrRisk.status === "trailBreak";
  const atrNear = decision.atrRisk?.available && decision.atrRisk.status === "near";
  const pocBelow = decision.pocCheck?.available && decision.pocCheck.status === "below";
  const pocAbove = decision.pocCheck?.available && decision.pocCheck.status === "above";
  const recoveryFailed = recovery?.available && recovery.status === "failedRetest";
  const recoveryUnrecovered = recovery?.available && recovery.status === "unrecovered";
  const recoveryLow = recovery?.available && recovery.status === "reclaimedLow";
  const recoveryStrong = recovery?.available && ["reclaimedHalf", "reclaimedHigh"].includes(recovery.status);
  const oscillatorBear = oscillator?.available && oscillator.tone === "down";
  const oscillatorBull = oscillator?.available && oscillator.tone === "up";
  const nearResistance = latestClose !== null && Number.isFinite(technical.resistance)
    ? (technical.resistance - latestClose) / latestClose * 100 <= 2.5
    : false;
  const overheat = technical.rsi14 !== null && technical.rsi14 >= 75;
  const trendBull = playbook.trendLabel === "多頭趨勢" || technical.signal === "技術偏多";
  const trendBear = playbook.trendLabel === "空頭趨勢" || technical.signal === "技術偏弱";

  const makeState = ({ state, label, tone, score, priority, action, positionRule, riskRule, nextCheck, reasons = [], blockers = [] }) => ({
    available: true,
    state,
    label,
    tone,
    score,
    priority,
    action,
    positionRule,
    riskRule,
    nextCheck,
    reasons,
    blockers,
    events
  });

  if (weeklyLowBreak) {
    return makeState({
      state: "avoid",
      label: "週線失守，先避開",
      tone: "down",
      score: -9,
      priority: 98,
      action: "波段結構失守，未持有者先不追反彈。",
      positionRule: "不加碼；已有部位降風險",
      riskRule: "等週線大量低重新站回才重新評估",
      nextCheck: "週線大量低 / POC 是否收復",
      reasons: ["週線大量低失守"],
      blockers: ["波段防線失效"]
    });
  }
  if (atrBreak || dailyLowBreak) {
    return makeState({
      state: "riskTriggered",
      label: "停損觸發",
      tone: "down",
      score: -8,
      priority: 96,
      action: "先按風控處理，不把反彈直接視為買點。",
      positionRule: "不新增部位；已有部位檢查停損",
      riskRule: atrBreak ? "跌破 ATR 追蹤停損" : "跌破日線大量低",
      nextCheck: "收盤重新站回大量低與 ATR 線",
      reasons: [atrBreak ? "ATR 追蹤停損跌破" : "", dailyLowBreak ? "日線大量低失守" : ""].filter(Boolean),
      blockers: [pocBelow ? "仍在 POC 下方" : "", oscillatorBear ? "動能轉弱" : ""].filter(Boolean)
    });
  }
  if (recoveryFailed) {
    return makeState({
      state: "failedRecovery",
      label: "反彈未收復",
      tone: "down",
      score: -7,
      priority: 92,
      action: "反彈先視為壓力測試，等收盤站回大量低。",
      positionRule: "避免追反彈；只允許觀察",
      riskRule: "大量低未收復前風險未解除",
      nextCheck: "收盤是否站回大量低",
      reasons: [recovery.label],
      blockers: [recovery.detail]
    });
  }
  if (recoveryUnrecovered || pocBelow) {
    return makeState({
      state: "waitRecovery",
      label: "等待修復",
      tone: "flat",
      score: -4,
      priority: 78,
      action: "先等大量低 / 半價 / POC 逐步收復。",
      positionRule: "小部位以下或不動作",
      riskRule: "尚未收復成本區前不放大部位",
      nextCheck: "大量低、半價與 POC 是否重新站回",
      reasons: [recoveryUnrecovered ? recovery.label : "", pocBelow ? "POC 仍在上方" : ""].filter(Boolean),
      blockers: [oscillatorBear ? "KD / 背離轉弱" : "", atrNear ? "貼近 ATR 風控線" : ""].filter(Boolean)
    });
  }
  if ((overheat || nearResistance) && oscillatorBear) {
    return makeState({
      state: "takeProfitTighten",
      label: "停利 / 緊縮停利",
      tone: "down",
      score: -2,
      priority: 74,
      action: "已有獲利者可緊縮停利；新倉避免追價。",
      positionRule: "不追高；保留部分持倉或降槓桿",
      riskRule: "以 MA10 / ATR / 大量低作移動風控",
      nextCheck: "KD 是否恢復、量價是否續攻",
      reasons: [overheat ? "RSI 過熱" : "", nearResistance ? "接近壓力區" : "", "動能轉弱"].filter(Boolean),
      blockers: oscillator.blockers || []
    });
  }
  if (recoveryStrong && !pocBelow && !oscillatorBear) {
    return makeState({
      state: "reEntryCandidate",
      label: "再進場候選",
      tone: "up",
      score: 7,
      priority: 88,
      action: "已完成修復條件，可搭配 R:R 與法人籌碼評估小部位再進場。",
      positionRule: "先小部位；放大前等收盤續站半價 / 大量高",
      riskRule: "大量低或 ATR 追蹤停損失守即降級",
      nextCheck: "半價 / 大量高是否續守，KD 是否不轉弱",
      reasons: [recovery.label, pocAbove ? "站上 POC" : "未跌破 POC", oscillatorBull ? oscillator.summary : ""].filter(Boolean),
      blockers: atrNear ? ["貼近 ATR 風控線"] : []
    });
  }
  if (decision.tone === "up" && dailyHighBreak && !oscillatorBear) {
    return makeState({
      state: "attackCandidate",
      label: "攻擊候選",
      tone: "up",
      score: 8,
      priority: 90,
      action: "短線突破條件較完整，可列攻擊清單並用停損控風險。",
      positionRule: "依 R:R 分批；不追超出入場帶太遠的價格",
      riskRule: "跌回大量高下方或 ATR 風控線需降級",
      nextCheck: "量能是否延續、週線大量高是否收復",
      reasons: ["日線站上大量高", decision.summary, weeklyHighBreak ? "週線同步收復" : ""].filter(Boolean),
      blockers: [atrNear ? "貼近 ATR 風控線" : ""].filter(Boolean)
    });
  }
  if (recoveryLow) {
    return makeState({
      state: "earlyRecovery",
      label: "初步修復",
      tone: "flat",
      score: 3,
      priority: 66,
      action: "剛站回大量低，先等半價、POC 與動能確認。",
      positionRule: "僅觀察或很小部位試單",
      riskRule: "大量低再失守即回到等待修復",
      nextCheck: "是否站回大量半價",
      reasons: [recovery.label],
      blockers: [pocBelow ? "POC 仍在上方" : "", oscillatorBear ? "動能轉弱" : ""].filter(Boolean)
    });
  }
  if (trendBull || decision.tone === "up" || pocAbove) {
    return makeState({
      state: "holdWatch",
      label: "持有觀察",
      tone: "up",
      score: 4,
      priority: 52,
      action: "趨勢尚可，依原計畫持有並追蹤風控線。",
      positionRule: "持有為主；新增需等回測或突破確認",
      riskRule: "MA20 / 大量低 / ATR 為主要降級線",
      nextCheck: "是否帶量突破或回測守住",
      reasons: [trendBull ? "趨勢偏多" : "", pocAbove ? "站上成本區" : "", decision.tone === "up" ? decision.summary : ""].filter(Boolean),
      blockers: [overheat ? "RSI 偏熱" : "", atrNear ? "貼近 ATR 風控線" : ""].filter(Boolean)
    });
  }
  return makeState({
    state: "observe",
    label: trendBear ? "偏弱觀察" : "觀察",
    tone: trendBear ? "down" : "flat",
    score: trendBear ? -3 : 0,
    priority: trendBear ? 44 : 30,
    action: "條件未齊，等待更明確的價量或修復訊號。",
    positionRule: "不急著建立新部位",
    riskRule: "若跌破大量低或 ATR 線即轉風控優先",
    nextCheck: "大量高 / 大量低、POC、KD 與 MA20",
    reasons: [playbook.cardSummary || technical.signal].filter(Boolean),
    blockers: [oscillatorBear ? "動能轉弱" : "", atrNear ? "貼近 ATR 風控線" : ""].filter(Boolean)
  });
}

function previousWindowHigh(rows, window = 20) {
  const prevRows = Array.isArray(rows) ? rows.slice(Math.max(0, rows.length - window - 1), -1) : [];
  if (!prevRows.length) return null;
  return Math.max(...prevRows.map((row) => row.high).filter(Number.isFinite));
}

function previousWindowLow(rows, window = 20) {
  const prevRows = Array.isArray(rows) ? rows.slice(Math.max(0, rows.length - window - 1), -1) : [];
  if (!prevRows.length) return null;
  return Math.min(...prevRows.map((row) => row.low).filter(Number.isFinite));
}

function playbookEntryText(entry) {
  if (!entry) return "-";
  if (entry.low !== null && entry.high !== null) {
    return Math.abs(entry.high - entry.low) < 0.01
      ? formatNumber(entry.low)
      : `${formatNumber(entry.low)} – ${formatNumber(entry.high)}`;
  }
  if (entry.trigger !== null) return formatNumber(entry.trigger);
  return "-";
}

function buildPlaybookPriceLevels(technical, trend, position, volumeStudy, checklistPasses = 0) {
  const rows = technical.rows || [];
  const latest = technical.latest;
  const currentPrice = toNumber(latest?.close);
  if (currentPrice === null || !rows.length) return null;

  const swings = trend.swings || recentSwingPoints(rows);
  const trendLineSupport = projectedTrendLine(swings.lows, rows.length - 1, "上升切線");
  const trendLinePressure = projectedTrendLine(swings.highs, rows.length - 1, "下降切線");
  const candles = recentLargeCandles(rows);
  const largeBull = candles.bullish;
  const largeBear = candles.bearish;
  const volumeDefense = technical.largeVolumeDefense || analyzeLargeVolumeDefense(rows, 60);
  const decisionLayer = technical.decisionLayer || null;
  const recoverySignal = technical.recoverySignal || decisionLayer?.recoverySignal || null;
  const atrRisk = decisionLayer?.atrRisk || analyzeAtrRisk(rows, latest, technical.atr14);
  const pocCheck = decisionLayer?.pocCheck || analyzePocPosition(latest, technical.volumeProfile);
  const prevResistance = previousWindowHigh(rows);
  const prevSupport = previousWindowLow(rows);
  const yearRows = rows.slice(-252);
  const high52w = yearRows.length ? Math.max(...yearRows.map((row) => row.high)) : null;
  const pocSupport = pocCheck?.available && currentPrice >= pocCheck.low
    ? priceLevelCandidate(pocCheck.mid, "POC 成本區", `${formatNumber(pocCheck.low)} – ${formatNumber(pocCheck.high)} 成交密集區`)
    : null;
  const pocPressure = pocCheck?.available && currentPrice < pocCheck.high
    ? priceLevelCandidate(pocCheck.mid, "POC 成本區", `${formatNumber(pocCheck.low)} – ${formatNumber(pocCheck.high)} 成交密集區`)
    : null;
  const atrTrailSupport = atrRisk?.available
    ? priceLevelCandidate(atrRisk.trailingStop, "ATR 追蹤停損", "20 日高點扣 2ATR 的波動風控線")
    : null;
  const recoveryLow = recoverySignal?.available
    ? priceLevelCandidate(recoverySignal.levels?.low, "修復大量低", `${recoverySignal.anchor?.date || ""} 失守後第一道收復線`)
    : null;
  const recoveryHalf = recoverySignal?.available
    ? priceLevelCandidate(recoverySignal.levels?.half, "修復半價", "大量 K 區間半價，站回後代表修復力道提高")
    : null;
  const recoveryHigh = recoverySignal?.available
    ? priceLevelCandidate(recoverySignal.levels?.high, "修復大量高", "大量 K 上緣，完整收復區間才算強修復")
    : null;

  const supportCandidates = [
    priceLevelCandidate(prevSupport, "前 20 日低點", "區間支撐"),
    priceLevelCandidate(technical.support, "20 日支撐", "近期最低區"),
    priceLevelCandidate(technical.ma20, "MA20(月線)", "中線操作線"),
    priceLevelCandidate(technical.ma60, "MA60(季線)", "波段操作線"),
    pocSupport,
    atrTrailSupport,
    trendLineSupport ? priceLevelCandidate(trendLineSupport.price, "上升切線", trendLineSupport.from + " → " + trendLineSupport.to) : null,
    largeBull ? priceLevelCandidate(largeBull.half, "大量長紅 1/2 價", `${largeBull.date} 平均成本支撐`) : null,
    largeBull ? priceLevelCandidate(largeBull.low, "大量長紅低點", `${largeBull.date} 多方防線`) : null,
    volumeDefense?.lowAnchor ? priceLevelCandidate(volumeDefense.lowAnchor.low, "大量 K 低點", `${volumeDefense.lowAnchor.date} 攻防低點`) : null,
    recoverySignal?.available && currentPrice >= recoverySignal.levels?.low ? recoveryLow : null,
    recoverySignal?.available && currentPrice >= recoverySignal.levels?.half ? recoveryHalf : null,
    largeBear && currentPrice > largeBear.high ? priceLevelCandidate(largeBear.high, "長黑高點轉支撐", `${largeBear.date} 多空易位後支撐`) : null
  ].filter(Boolean);

  const pressureCandidates = [
    priceLevelCandidate(prevResistance, "前 20 日高點", "突破確認價"),
    priceLevelCandidate(technical.resistance, "20 日壓力", "近期高點區"),
    pocPressure,
    trendLinePressure ? priceLevelCandidate(trendLinePressure.price, "下降切線", trendLinePressure.from + " → " + trendLinePressure.to) : null,
    largeBear ? priceLevelCandidate(largeBear.half, "大量長黑 1/2 價", `${largeBear.date} 平均成本壓力`) : null,
    largeBear ? priceLevelCandidate(largeBear.high, "大量長黑高點", `${largeBear.date} 空方防線`) : null,
    largeBull && currentPrice < largeBull.high ? priceLevelCandidate(largeBull.high, "長紅高點", `${largeBull.date} 攻擊高點`) : null,
    volumeDefense?.highAnchor ? priceLevelCandidate(volumeDefense.highAnchor.high, "大量 K 高點", `${volumeDefense.highAnchor.date} 攻防高點`) : null,
    recoverySignal?.available && currentPrice < recoverySignal.levels?.low ? recoveryLow : null,
    recoverySignal?.available && currentPrice < recoverySignal.levels?.half ? recoveryHalf : null,
    recoverySignal?.available && currentPrice < recoverySignal.levels?.high ? recoveryHigh : null,
    priceLevelCandidate(high52w, "52 週高點", "中期壓力")
  ].filter(Boolean);

  const mainSupport = selectNearestBelow(supportCandidates, currentPrice);
  const mainPressure = selectNearestAbove(pressureCandidates, currentPrice);
  const breakoutTrigger = selectNearestAbove([
    priceLevelCandidate(prevResistance, "突破前高", "收盤站上確認"),
    pocCheck?.available && pocCheck.status !== "above" ? priceLevelCandidate(pocCheck.high, "站上 POC 上緣", "收復成本密集區") : null,
    recoverySignal?.available && currentPrice < recoverySignal.levels?.low ? recoveryLow : null,
    recoverySignal?.available && currentPrice < recoverySignal.levels?.half ? recoveryHalf : null,
    recoverySignal?.available && currentPrice < recoverySignal.levels?.high ? recoveryHigh : null,
    trendLinePressure ? priceLevelCandidate(trendLinePressure.price, "突破下降切線", "空方壓力轉弱") : null,
    largeBear ? priceLevelCandidate(largeBear.half, "站上長黑 1/2 價", "空方平均成本被收復") : null
  ].filter(Boolean), currentPrice);

  let primaryEntry = null;
  let secondaryEntry = null;
  let actionBias = "先觀察";
  const maPullbackValues = [technical.ma10, technical.ma20]
    .map(roundPriceLevel)
    .filter((value) => value !== null && value > 0);
  const maPullbackLow = maPullbackValues.length ? Math.min(...maPullbackValues) : null;
  const maPullbackHigh = maPullbackValues.length ? Math.max(...maPullbackValues) : null;

  if (trend.code === "bull") {
    actionBias = position.label === "多頭高檔 / 壓力前" ? "等回檔" : "偏多規劃";
    if (maPullbackLow !== null && maPullbackHigh !== null) {
      primaryEntry = {
        label: "回測買點",
        low: maPullbackLow,
        high: maPullbackHigh,
        trigger: null,
        source: "MA10~MA20 回測，收盤不破再規劃",
        confirmation: "收盤價維持在操作線之上"
      };
    } else if (mainSupport) {
      primaryEntry = {
        label: "支撐買點",
        low: mainSupport.price,
        high: mainSupport.price,
        trigger: null,
        source: mainSupport.label,
        confirmation: "收盤不破支撐"
      };
    }
    if (breakoutTrigger && breakoutTrigger.price > currentPrice * 1.005) {
      secondaryEntry = {
        label: "突破買點",
        low: null,
        high: null,
        trigger: breakoutTrigger.price,
        source: breakoutTrigger.label,
        confirmation: "收盤站上且量價配合"
      };
    }
  } else if (trend.code === "range") {
    actionBias = position.label === "盤整突破候選" ? "等突破確認" : "盤整等方向";
    if (breakoutTrigger) {
      primaryEntry = {
        label: "盤整突破",
        low: null,
        high: null,
        trigger: breakoutTrigger.price,
        source: breakoutTrigger.label,
        confirmation: "收盤站上區間壓力"
      };
    }
    if (mainSupport) {
      secondaryEntry = {
        label: "區間支撐",
        low: mainSupport.price,
        high: mainSupport.price,
        trigger: null,
        source: mainSupport.label,
        confirmation: "只適合小部位，收盤跌破即失效"
      };
    }
  } else {
    actionBias = "空頭不做多";
    if (breakoutTrigger) {
      primaryEntry = {
        label: "翻多確認",
        low: null,
        high: null,
        trigger: breakoutTrigger.price,
        source: breakoutTrigger.label,
        confirmation: "先站回壓力 / 月線，再重新評估"
      };
    }
  }

  const entryRef = primaryEntry
    ? (primaryEntry.trigger ?? midpoint(primaryEntry.low, primaryEntry.high))
    : currentPrice;
  const rawStop = mainSupport && (entryRef === null || mainSupport.price < entryRef)
    ? mainSupport.price * 0.985
    : technical.previous?.low
      ? technical.previous.low * 0.985
      : null;
  const stopRef = entryRef ?? currentPrice;
  const stopCandidates = [
    rawStop !== null ? {
      price: rawStop,
      source: mainSupport ? `${mainSupport.label} 下 1.5%` : "前一日低點下 1.5%",
      confirmation: "以收盤跌破視為 setup 失效"
    } : null,
    atrRisk?.available && atrRisk.trailingStop !== null ? {
      price: atrRisk.trailingStop,
      source: "ATR 追蹤停損",
      confirmation: "收盤跌破代表波動停損觸發"
    } : null,
    atrRisk?.available && atrRisk.initialStop !== null ? {
      price: atrRisk.initialStop,
      source: "ATR 初始停損",
      confirmation: "以 2ATR 控制單筆風險"
    } : null
  ].filter(Boolean)
    .filter((candidate) => stopRef === null || candidate.price < stopRef * 0.995)
    .sort((left, right) => right.price - left.price);
  const selectedStop = stopCandidates[0] || null;
  const stop = selectedStop
    ? {
      price: roundPriceLevel(selectedStop.price),
      source: selectedStop.source,
      confirmation: selectedStop.confirmation
    }
    : null;

  const target1 = mainPressure
    ? { price: mainPressure.price, source: mainPressure.label, note: mainPressure.note }
    : null;
  const measuredTarget = mainPressure && mainSupport
    ? roundPriceLevel(mainPressure.price + Math.max(0, mainPressure.price - mainSupport.price))
    : null;
  const target2Price = measuredTarget && measuredTarget > (target1?.price || currentPrice)
    ? measuredTarget
    : high52w && high52w > (target1?.price || currentPrice)
      ? roundPriceLevel(high52w)
      : null;
  const target2 = target2Price
    ? { price: target2Price, source: measuredTarget === target2Price ? "區間等幅目標" : "52 週高點", note: "第二段觀察價" }
    : null;

  const evidence = [
    "進出場以趨勢、位置、均線、量價、支撐壓力與指標合併檢查",
    "均線交易以收盤確認，趨勢不變時才使用操作線",
    "大量長紅 / 長黑的高低點與 1/2 價作為後續支撐壓力",
    "成交量需與走勢、位置與後續 1-3 日變化一起看",
    "失守後修復、KD / 背離、ATR、週線大量 K 與 POC 是本工具新增的風控 / 成本區 proxy"
  ];

  const confidence = trend.code === "bull" && checklistPasses >= 4
    ? "較高"
    : trend.code === "bear"
      ? "偏低"
      : "中等";

  return {
    actionBias,
    confidence,
    source: `${PLAYBOOK_SOURCE_TITLE}（${PLAYBOOK_SOURCE_PDF}）`,
    basis: [
      "轉折波趨勢 p.12-77",
      "均線扣抵 p.148-156",
      "量價心法 p.294-299",
      "進出場 Check List p.300-306",
      "單一長紅 / 長黑 K 棒 p.98-137"
    ],
    evidence,
    primaryEntry,
    secondaryEntry,
    mainSupport,
    mainPressure,
    stop,
    target1,
    target2,
    trendLineSupport,
    trendLinePressure,
    largeBull,
    largeBear,
    volumeDefense,
    recoverySignal,
    atrRisk,
    pocCheck,
    volumeContext: volumeStudy?.label || "",
    supportCandidates,
    pressureCandidates
  };
}

function inferPlaybookTrend(rows, latestClose, ma20, ma60, ma240, ma20Slope, ma60Slope) {
  const swings = recentSwingPoints(rows);
  const latestHigh = swings.highs.at(-1);
  const previousHigh = swings.highs.at(-2);
  const latestLow = swings.lows.at(-1);
  const previousLow = swings.lows.at(-2);
  const breaksConfirmedHigh = latestHigh && latestClose > latestHigh.value;
  const breaksConfirmedLow = latestLow && latestClose < latestLow.value;
  const recentDownCloses = consecutiveCloseDirection(rows, "down", 4);
  const belowMa20 = ma20 !== null && latestClose < ma20;
  const belowMa60 = ma60 !== null && latestClose < ma60;
  const latestLowGapPct = latestLow && latestClose
    ? (latestClose - latestLow.value) / latestClose * 100
    : null;
  const nearLatestLow = latestLowGapPct !== null && latestLowGapPct <= 3;

  if (breaksConfirmedLow) {
    return {
      code: "range",
      label: "盤整趨勢",
      detail: "跌破前波確認低點，多頭結構失效",
      swings
    };
  }

  if (breaksConfirmedHigh && ma20 !== null && ma60 !== null && latestClose > ma20 && ma20 >= ma60) {
    return {
      code: "bull",
      label: "多頭趨勢",
      detail: "突破前波確認高點",
      swings
    };
  }

  if (latestHigh && previousHigh && latestLow && previousLow) {
    if (latestHigh.value > previousHigh.value && latestLow.value > previousLow.value) {
      if ((belowMa20 && belowMa60) || (belowMa20 && nearLatestLow) || (belowMa20 && recentDownCloses >= 3)) {
        return {
          code: "range",
          label: "盤整趨勢",
          detail: "高低點結構仍偏多，但價格已壓回弱勢區",
          swings
        };
      }
      return {
        code: "bull",
        label: "多頭趨勢",
        detail: "頭頭高、底底高",
        swings
      };
    }
    if (latestHigh.value < previousHigh.value && latestLow.value < previousLow.value) {
      return {
        code: "bear",
        label: "空頭趨勢",
        detail: "頭頭低、底底低",
        swings
      };
    }
  }

  if (ma20 !== null && ma60 !== null && latestClose > ma20 && ma20 > ma60 && (ma20Slope ?? 0) >= 0 && (ma60Slope ?? 0) >= 0) {
    return {
      code: "bull",
      label: "多頭趨勢",
      detail: ma240 !== null && latestClose > ma240 ? "均線多排偏多" : "均線結構偏多",
      swings
    };
  }

  if (ma20 !== null && ma60 !== null && latestClose < ma20 && ma20 < ma60 && (ma20Slope ?? 0) <= 0 && (ma60Slope ?? 0) <= 0) {
    return {
      code: "bear",
      label: "空頭趨勢",
      detail: ma240 !== null && latestClose < ma240 ? "均線空排偏空" : "均線結構偏空",
      swings
    };
  }

  return {
    code: "range",
    label: "盤整趨勢",
    detail: "高低點未形成一致方向",
    swings
  };
}

function inferPlaybookPosition(technical, trend) {
  const {
    latest,
    previous,
    ma10,
    ma20,
    support,
    resistance,
    changePct,
    bias20
  } = technical;
  const latestClose = latest.close;
  const distanceToSupport = support && latestClose
    ? (latestClose - support) / latestClose * 100
    : null;
  const distanceToResistance = resistance && latestClose
    ? (resistance - latestClose) / latestClose * 100
    : null;
  const breaksPreviousHigh = previous ? latest.close > previous.high : false;
  const breaksPreviousLow = previous ? latest.close < previous.low : false;

  if (trend.code === "bull") {
    if (breaksPreviousHigh && changePct !== null && changePct >= 2) {
      return {
        label: "回後買上漲 / 攻擊段",
        note: "價漲且過前高，接近講義的攻擊 K 與回後買上漲。"
      };
    }
    if (distanceToResistance !== null && distanceToResistance <= 2) {
      return {
        label: "多頭高檔 / 壓力前",
        note: "已接近前波壓力，適合防追高。"
      };
    }
    if (ma20 !== null && latest.close >= ma20 && ma10 !== null && latest.close <= ma10) {
      return {
        label: "多頭回檔",
        note: "仍在月線之上，屬多頭回測觀察區。"
      };
    }
    return {
      label: "多頭行進間",
      note: "多頭結構未破，等待下一次攻擊量或回檔買點。"
    };
  }

  if (trend.code === "bear") {
    if (breaksPreviousLow && changePct !== null && changePct <= -2) {
      return {
        label: "彈後空下跌 / 主跌段",
        note: "跌破前低，偏向講義中的空方攻擊位置。"
      };
    }
    if (distanceToSupport !== null && distanceToSupport <= 2) {
      return {
        label: "空頭低檔 / 反彈區",
        note: "接近支撐，容易出現搶反彈，但尚未翻多。"
      };
    }
    return {
      label: "空頭反彈或續跌",
      note: "未站回關鍵均線前，仍以空方結構看待。"
    };
  }

  if (breaksPreviousHigh && changePct !== null && changePct >= 2) {
    return {
      label: "盤整突破候選",
      note: "已嘗試往上脫離區間，仍需量價延續確認。"
    };
  }
  if (breaksPreviousLow && changePct !== null && changePct <= -2) {
    return {
      label: "盤整跌破候選",
      note: "已嘗試往下脫離區間，須觀察是否轉成主跌段。"
    };
  }
  if (bias20 !== null && Math.abs(bias20) <= 3) {
    return {
      label: "盤整等待",
      note: "股價圍繞月線整理，先等方向確認。"
    };
  }
  return {
    label: "區間震盪",
    note: "趨勢與位置尚未出現明確優勢。"
  };
}

function classifyPlaybookVolume(technical, trend) {
  const { rows, latest, previous, changePct, support, resistance } = technical;
  const volumes = rows.map((row) => row.volume || 0);
  const volumeMa5 = sma(volumes, Math.min(5, volumes.length));
  const volumeRatio5 = volumeMa5 ? latest.volume / volumeMa5 : null;
  const breaksPreviousHigh = previous ? latest.close > previous.high : false;
  const nearResistance = resistance && latest.close && resistance >= latest.close
    ? (resistance - latest.close) / latest.close * 100 <= 2
    : false;

  if (volumeRatio5 !== null && volumeRatio5 >= 2 && trend.code === "bull" && changePct !== null && changePct > 0 && breaksPreviousHigh) {
    return {
      code: "rotation",
      label: "爆大量 / 換手候選",
      note: "突破時放到 5 日均量 2 倍以上，符合講義爆大量；後續 1-3 日續漲才算換手成功。",
      volumeMa5,
      volumeRatio5
    };
  }

  if (volumeRatio5 !== null && volumeRatio5 >= 1.2 && changePct !== null && changePct > 2 && breaksPreviousHigh) {
    return {
      code: "attack",
      label: "攻擊量",
      note: "價漲、量增、過前高，接近講義短線做多的攻擊量定義。",
      volumeMa5,
      volumeRatio5
    };
  }

  if (volumeRatio5 !== null && volumeRatio5 >= 2 && (changePct === null || changePct <= 0 || nearResistance)) {
    return {
      code: "distribution",
      label: "高檔出貨疑慮",
      note: "高檔或壓力前爆大量但股價不強，偏向講義中的出貨量風險。",
      volumeMa5,
      volumeRatio5
    };
  }

  if (trend.code === "bear" && volumeRatio5 !== null && volumeRatio5 <= 0.55 && previous && latest.low >= previous.low) {
    return {
      code: "stop",
      label: "止跌量候選",
      note: "下跌後量縮到接近 5 日均量一半，且未再破低，符合止跌量候選語意。",
      volumeMa5,
      volumeRatio5
    };
  }

  if (changePct !== null && changePct < 0 && volumeRatio5 !== null && volumeRatio5 >= 1.5) {
    return {
      code: "selloff",
      label: "下跌大量",
      note: "下跌帶量代表賣壓放大，不宜急著接刀。",
      volumeMa5,
      volumeRatio5
    };
  }

  if (changePct !== null && changePct > 0 && volumeRatio5 !== null && volumeRatio5 < 0.8) {
    return {
      code: "light-up",
      label: "量縮價漲",
      note: "上漲但量未放大，續攻力道需要再確認。",
      volumeMa5,
      volumeRatio5
    };
  }

  return {
    code: "base",
    label: "基本量",
    note: "量能沒有明顯失真，需配合趨勢與 K 棒一起判讀。",
    volumeMa5,
    volumeRatio5
  };
}

function buildPlaybookAnalysis(technical) {
  const trend = inferPlaybookTrend(
    technical.rows,
    technical.latest.close,
    technical.ma20,
    technical.ma60,
    technical.ma240,
    technical.ma20Slope,
    technical.ma60Slope
  );
  const position = inferPlaybookPosition(technical, trend);
  const volumeStudy = classifyPlaybookVolume(technical, trend);
  const volumeDefense = technical.largeVolumeDefense || null;
  const decisionLayer = technical.decisionLayer || null;
  const recoverySignal = technical.recoverySignal || decisionLayer?.recoverySignal || null;
  const oscillatorChecklist = technical.oscillatorChecklist || decisionLayer?.oscillatorChecklist || null;
  const deductions = [
    movingDeductionSignal(technical.rows, 10, technical.ma10Slope),
    movingDeductionSignal(technical.rows, 20, technical.ma20Slope),
    movingDeductionSignal(technical.rows, 60, technical.ma60Slope)
  ].filter(Boolean);
  const macdImproving = technical.macd.histogram !== null && (
    technical.macd.histogram > 0
    || (technical.macd.previousHistogram !== null && technical.macd.histogram > technical.macd.previousHistogram)
  );
  const checklist = [
    {
      label: "日線趨勢偏多或剛轉強",
      pass: trend.code === "bull" || position.label === "盤整突破候選"
    },
    {
      label: "MA10 / MA20 多頭排列",
      pass: technical.ma10 !== null && technical.ma20 !== null && technical.ma10 > technical.ma20
    },
    {
      label: "MA10 / MA20 方向向上",
      pass: (technical.ma10Slope ?? Number.NEGATIVE_INFINITY) > 0 && (technical.ma20Slope ?? Number.NEGATIVE_INFINITY) > 0
    },
    {
      label: "收盤站上 MA10 / MA20",
      pass: technical.ma10 !== null && technical.ma20 !== null && technical.latest.close > technical.ma10 && technical.latest.close > technical.ma20
    },
    {
      label: "出現攻擊量或有效放量",
      pass: ["attack", "rotation"].includes(volumeStudy.code)
    },
    {
      label: "站上大量高或守住大量低",
      pass: Boolean(volumeDefense?.available && (
        volumeDefense.highCheck?.status === "breakout"
        || ["above", "test"].includes(volumeDefense.lowCheck?.status)
      ))
    },
    {
      label: "大量低未失守或失守後已修復",
      pass: Boolean(recoverySignal?.available && !["failedRetest", "unrecovered"].includes(recoverySignal.status))
    },
    {
      label: "週線大量低未失守",
      pass: Boolean(decisionLayer?.weeklyDefense?.available && decisionLayer.weeklyDefense.lowCheck?.status !== "breakdown")
    },
    {
      label: "收盤站上 POC 成本區",
      pass: Boolean(decisionLayer?.pocCheck?.available && ["above", "inside"].includes(decisionLayer.pocCheck.status))
    },
    {
      label: "ATR 追蹤停損未觸發",
      pass: Boolean(decisionLayer?.atrRisk?.available && decisionLayer.atrRisk.status !== "trailBreak")
    },
    {
      label: "MACD 綠柱縮短或紅柱延長",
      pass: macdImproving
    },
    {
      label: "KD / 背離動能未轉弱",
      pass: Boolean(oscillatorChecklist?.available && oscillatorChecklist.tone !== "down")
    }
  ];
  const checklistPasses = checklist.filter((item) => item.pass).length;
  const levels = buildPlaybookPriceLevels(technical, trend, position, volumeStudy, checklistPasses);
  const consecutiveUp = consecutiveCloseDirection(technical.rows, "up");
  const risks = [];
  if (technical.ma20 !== null && technical.latest.close < technical.ma20) risks.push("收盤尚未站穩月線，不宜視為完整多頭");
  if (volumeStudy.code === "distribution") risks.push("高檔爆大量但股價不強，需防主力出貨");
  if (volumeDefense?.lowCheck?.status === "breakdown") risks.push("收盤跌破大量 K 低點，代表原攻防區失守，應先控風險");
  if (volumeDefense?.highCheck?.status === "test") risks.push("盤中碰大量 K 高點但未收上，突破尚未確認");
  if (recoverySignal?.status === "failedRetest") risks.push("反彈測大量低但收盤未站回，屬假修復壓力測試");
  if (recoverySignal?.status === "unrecovered") risks.push("大量低失守後尚未修復，需等收盤重新站回大量低 / 半價");
  if (oscillatorChecklist?.tone === "down") risks.push("KD / RSI / MACD 動能轉弱或出現頂背離，追價風險提高");
  if (decisionLayer?.weeklyDefense?.lowCheck?.status === "breakdown") risks.push("週線大量 K 低點失守，波段結構需降級看待");
  if (decisionLayer?.pocCheck?.status === "below") risks.push("收盤仍在 POC 成本密集區下方，上方成本區可能形成壓力");
  if (decisionLayer?.atrRisk?.status === "trailBreak") risks.push("收盤跌破 ATR 追蹤停損，波動風控已觸發");
  if (trend.code === "bear") risks.push("目前較像空頭反彈，不視為做多主戰場");
  if (position.label.includes("高檔") || consecutiveUp >= 3) risks.push("連續上漲或接近壓力區，避免追第 3 根以上");

  let conclusion = "條件未齊，先觀察";
  if (trend.code === "bear" || position.label === "盤整跌破候選") {
    conclusion = "偏空結構，暫不符合講義短線做多框架";
  } else if (decisionLayer?.weeklyDefense?.lowCheck?.status === "breakdown") {
    conclusion = "週線大量低失守，波段先控風險";
  } else if (decisionLayer?.atrRisk?.status === "trailBreak") {
    conclusion = "跌破 ATR 追蹤停損，先按風控處理";
  } else if (recoverySignal?.status === "failedRetest" || recoverySignal?.status === "unrecovered") {
    conclusion = "大量低失守後尚未修復，反彈先當壓力測試";
  } else if (volumeDefense?.lowCheck?.status === "breakdown") {
    conclusion = "大量低失守，優先檢查停損與風險";
  } else if (["reclaimedHalf", "reclaimedHigh"].includes(recoverySignal?.status) && oscillatorChecklist?.tone !== "down" && checklistPasses >= 7) {
    conclusion = "失守後已修復，且動能未轉弱，可列再進場候選";
  } else if (decisionLayer?.tone === "up" && checklistPasses >= 7) {
    conclusion = "日線突破、成本區與風控條件較完整，可列入攻擊候選";
  } else if (volumeDefense?.highCheck?.status === "breakout" && checklistPasses >= 5) {
    conclusion = "收復大量高且條件齊全，可列入攻擊候選";
  } else if (checklistPasses >= 5 && ["attack", "rotation"].includes(volumeStudy.code)) {
    conclusion = "接近講義短線做多框架，可列入進場候選";
  } else if (trend.code === "bull" && checklistPasses >= 4) {
    conclusion = "多頭結構成立，但量價或突破確認尚差一步";
  } else if (position.label === "盤整突破候選" && checklistPasses >= 3) {
    conclusion = "接近盤整突破，需觀察是否帶攻擊量續攻";
  }

  return {
    trendLabel: trend.label,
    trendDetail: trend.detail,
    positionLabel: position.label,
    positionNote: position.note,
    volumeLabel: volumeStudy.label,
    volumeNote: volumeStudy.note,
    volumeRatio5: volumeStudy.volumeRatio5,
    volumeMa5: volumeStudy.volumeMa5,
    deductions,
    maStackLabel: maStackLabel(technical.ma10, technical.ma20, technical.ma60, technical.ma240),
    checklist,
    checklistPasses,
    levels,
    volumeDefense,
    decisionLayer,
    recoverySignal,
    oscillatorChecklist,
    conclusion,
    cardSummary: `${trend.label} · ${position.label}`,
    methodNote: `${PLAYBOOK_SOURCE_PDF}：依講義目錄與章節頁碼核對，主要引用轉折波趨勢 p.12-77、均線與移動扣抵 p.138-222 / p.148-156、K棒 p.95-137、量價 p.268-299、進出場 Check List p.300-306；目前用日線 OHLCV、均線、轉折波、大量 K 高低 / 半價、失守後修復、週線大量 K、ATR 風控、POC 成本區與 KD / RSI / MACD 背離近似；完整型態仍需人工複核。`,
    risks
  };
}

function maBiasLevel(entry) {
  if (!entry?.available) return { key: "unavailable", label: "資料不足", tone: "flat", action: "需先更新日線。" };
  if (!entry.enough) return { key: "sample-low", label: "樣本偏少", tone: "flat", action: "可先看乖離方向，但不要把分位當主要依據。" };
  const bias = toNumber(entry.currentBias);
  if (bias === null) return { key: "unavailable", label: "資料不足", tone: "flat", action: "乖離缺值。" };
  if (bias > 0) {
    const pct = entry.positivePercentile ?? 0;
    if (pct >= 95) return { key: "extreme-positive", label: `${entry.shortLabel}極高正乖離`, tone: "warn", action: "追價風險升高，先看量價是否失速與籌碼是否轉弱。" };
    if (pct >= 90) return { key: "high-positive", label: `${entry.shortLabel}高正乖離`, tone: "warn", action: "偏高水位，適合檢查壓力、停利與買回紀律。" };
    if (pct >= 75) return { key: "warm-positive", label: `${entry.shortLabel}正乖離偏高`, tone: "up", action: "趨勢偏延伸，但尚未到極端。" };
  }
  if (bias < 0) {
    const pct = entry.negativePercentile ?? 0;
    if (pct >= 95) return { key: "extreme-negative", label: `${entry.shortLabel}極深負乖離`, tone: "down", action: "深跌水位，先看基本面、籌碼與止跌結構。" };
    if (pct >= 90) return { key: "deep-negative", label: `${entry.shortLabel}深負乖離`, tone: "down", action: "已在自身歷史偏深區，賣壓可能接近情緒化但仍需等修復。" };
    if (pct >= 75) return { key: "cool-negative", label: `${entry.shortLabel}負乖離偏深`, tone: "down", action: "偏冷水位，留意是否出現止跌與修復。" };
  }
  return { key: "normal", label: `${entry.shortLabel}乖離一般`, tone: "flat", action: "目前不因這條均線乖離單獨調整判斷。" };
}

function maBiasFallbackHeatPoints(entry) {
  const bias = toNumber(entry?.currentBias);
  if (bias === null || bias <= 0) return 0;
  if (entry.period === 20) {
    if (bias >= 12) return 10;
    if (bias >= 8) return 7;
    if (bias >= 5) return 4;
    return 0;
  }
  if (entry.period === 60) {
    if (bias >= 25) return 9;
    if (bias >= 18) return 6;
    if (bias >= 12) return 4;
    return 0;
  }
  if (entry.period === 240) {
    if (bias >= 45) return 8;
    if (bias >= 30) return 5;
    if (bias >= 20) return 3;
    return 0;
  }
  return 0;
}

function maBiasFallbackDeepPoints(entry) {
  const bias = toNumber(entry?.currentBias);
  if (bias === null || bias >= 0) return 0;
  const abs = Math.abs(bias);
  if (entry.period === 20) {
    if (abs >= 12) return 10;
    if (abs >= 8) return 7;
    if (abs >= 5) return 4;
    return 0;
  }
  if (entry.period === 60) {
    if (abs >= 25) return 10;
    if (abs >= 18) return 7;
    if (abs >= 12) return 4;
    return 0;
  }
  if (entry.period === 240) {
    if (abs >= 35) return 10;
    if (abs >= 25) return 7;
    if (abs >= 15) return 4;
    return 0;
  }
  return 0;
}

function maBiasProfilePoints(entry, direction = "heat") {
  if (!entry?.available) return 0;
  const pct = direction === "heat" ? entry.positivePercentile : entry.negativePercentile;
  const bias = toNumber(entry.currentBias);
  if (bias === null) return 0;
  if (direction === "heat" && bias <= 0) return 0;
  if (direction === "deep" && bias >= 0) return 0;
  const maxByPeriod = entry.period === 20 ? 15 : entry.period === 60 ? 10 : 8;
  const midByPeriod = entry.period === 20 ? 11 : entry.period === 60 ? 7 : 6;
  const lowByPeriod = entry.period === 20 ? 6 : entry.period === 60 ? 4 : 3;
  if (entry.enough && pct !== null && pct !== undefined) {
    if (pct >= 95) return maxByPeriod;
    if (pct >= 90) return midByPeriod;
    if (pct >= 75) return lowByPeriod;
  }
  return direction === "heat" ? maBiasFallbackHeatPoints(entry) : maBiasFallbackDeepPoints(entry);
}

function buildMovingAverageBiasProfile(rows, latestPrice = null, seriesByPeriod = {}) {
  if (!Array.isArray(rows) || rows.length < 20) {
    return { available: false, reason: "日線不足，至少需要 20 根日線。", periods: [], heatScore: 0, deepScore: 0 };
  }
  const closes = rows.map((row) => toNumber(row?.close));
  const periods = MA_BIAS_PERIODS.map((def) => {
    const series = Array.isArray(seriesByPeriod[def.period]) && seriesByPeriod[def.period].length === rows.length
      ? seriesByPeriod[def.period]
      : smaSeries(closes, def.period);
    const biasRows = rows.map((row, index) => {
      const close = closes[index];
      const ma = toNumber(series[index]);
      if (close === null || ma === null || ma === 0) return null;
      return {
        date: row?.date || "",
        close,
        ma,
        bias: (close - ma) / ma * 100
      };
    }).filter(Boolean);
    const sample = biasRows.slice(-BIAS_DISCIPLINE_LOOKBACK_DAYS);
    const current = sample.at(-1) || null;
    if (!current) {
      return {
        ...def,
        available: false,
        enough: false,
        reason: `尚無可用 ${def.label} 乖離序列。`
      };
    }
    const biasValues = sample.map((row) => row.bias);
    const positiveValues = biasValues.filter((value) => value > 0);
    const negativeAbsValues = biasValues.filter((value) => value < 0).map((value) => Math.abs(value));
    const currentBias = current.bias;
    const currentAbs = Math.abs(currentBias);
    const positivePercentile = currentBias > 0 && positiveValues.length
      ? percentileRank(positiveValues, currentBias)
      : null;
    const negativePercentile = currentBias < 0 && negativeAbsValues.length
      ? percentileRank(negativeAbsValues, currentAbs)
      : null;
    const entry = {
      ...def,
      available: true,
      enough: sample.length >= def.minObs,
      observationDays: sample.length,
      firstDate: sample[0]?.date || "",
      lastDate: current.date || "",
      currentBias,
      currentAbs,
      directionPercentile: currentBias >= 0 ? positivePercentile : negativePercentile,
      positivePercentile,
      negativePercentile,
      absPercentile: percentileRank(biasValues.map((value) => Math.abs(value)), currentAbs),
      p90Positive: quantileNumber(positiveValues, 0.9),
      p95Positive: quantileNumber(positiveValues, 0.95),
      p90NegativeAbs: quantileNumber(negativeAbsValues, 0.9),
      p95NegativeAbs: quantileNumber(negativeAbsValues, 0.95),
      maxPositive: positiveValues.length ? Math.max(...positiveValues) : null,
      maxNegativeAbs: negativeAbsValues.length ? Math.max(...negativeAbsValues) : null,
      currentPrice: toNumber(latestPrice) ?? current.close,
      ma: current.ma,
      source: `本機日線 ${def.label} 乖離序列`
    };
    entry.level = maBiasLevel(entry);
    entry.heatPoints = maBiasProfilePoints(entry, "heat");
    entry.deepPoints = maBiasProfilePoints(entry, "deep");
    return entry;
  });
  const availablePeriods = periods.filter((entry) => entry.available);
  const heatScore = clamp(availablePeriods.reduce((sum, entry) => sum + (entry.heatPoints || 0), 0), 0, 35);
  const deepScore = clamp(availablePeriods.reduce((sum, entry) => sum + (entry.deepPoints || 0), 0), 0, 35);
  const dominant = heatScore >= deepScore ? "heat" : "deep";
  const dominantEntry = availablePeriods
    .filter((entry) => dominant === "heat" ? entry.currentBias > 0 : entry.currentBias < 0)
    .sort((left, right) => (dominant === "heat" ? (right.heatPoints || 0) - (left.heatPoints || 0) : (right.deepPoints || 0) - (left.deepPoints || 0)))[0] || availablePeriods[0] || null;
  const level = dominantEntry?.level || { key: "unavailable", label: "資料不足", tone: "flat", action: "需先更新日線。" };
  const summary = availablePeriods.length
    ? availablePeriods.map((entry) => `${entry.shortLabel} ${formatSignedMetric(entry.currentBias, 1, "%")}`).join(" / ")
    : "資料不足";
  return {
    available: availablePeriods.length > 0,
    reason: availablePeriods.length ? "" : "尚無可用均線乖離資料。",
    periods,
    availablePeriods,
    heatScore,
    deepScore,
    dominant,
    dominantEntry,
    level,
    summary,
    source: "本機 TWSE / TPEx / Yahoo 日線快取衍生；缺值不視為低風險"
  };
}

function maBiasProfilePeriod(profile, period) {
  return (profile?.periods || []).find((entry) => Number(entry.period) === Number(period)) || null;
}

function buildBiasDisciplineStudy(rows, latestPrice = null, ma20SeriesInput = null) {
  if (!Array.isArray(rows) || rows.length < 20) {
    return { available: false, reason: "日線不足，至少需要 20 根日線。" };
  }
  const closes = rows.map((row) => toNumber(row?.close));
  const ma20Series = Array.isArray(ma20SeriesInput) && ma20SeriesInput.length === rows.length
    ? ma20SeriesInput
    : smaSeries(closes, 20);
  const biasRows = rows.map((row, index) => {
    const close = closes[index];
    const ma20 = toNumber(ma20Series[index]);
    if (close === null || ma20 === null || ma20 === 0) return null;
    return {
      date: row?.date || "",
      close,
      ma20,
      bias: (close - ma20) / ma20 * 100
    };
  }).filter(Boolean);
  const sample = biasRows.slice(-BIAS_DISCIPLINE_LOOKBACK_DAYS);
  const current = sample.at(-1) || null;
  if (!current) {
    return { available: false, reason: "尚無可用 MA20 乖離序列。" };
  }

  const biasValues = sample.map((row) => row.bias);
  const positiveValues = biasValues.filter((value) => value > 0);
  const negativeAbsValues = biasValues.filter((value) => value < 0).map((value) => Math.abs(value));
  const currentBias = current.bias;
  const currentAbs = Math.abs(currentBias);
  const currentPrice = toNumber(latestPrice) ?? current.close;
  const positivePercentile = currentBias > 0 && positiveValues.length
    ? percentileRank(positiveValues, currentBias)
    : null;
  const negativePercentile = currentBias < 0 && negativeAbsValues.length
    ? percentileRank(negativeAbsValues, currentAbs)
    : null;
  const directionPercentile = currentBias >= 0 ? positivePercentile : negativePercentile;
  const absPercentile = percentileRank(biasValues.map((value) => Math.abs(value)), currentAbs);
  const enough = sample.length >= BIAS_DISCIPLINE_MIN_OBS;
  let level = { key: "insufficient", label: "樣本不足", tone: "flat", action: "先累積更多日線資料。" };

  if (enough) {
    if (currentBias > 0 && (positivePercentile ?? 0) >= 95) {
      level = { key: "extreme-positive", label: "近1-2年極高正乖離", tone: "warn", action: "滿倉時才討論小幅降風險，核心部位不宜清空。" };
    } else if (currentBias > 0 && (positivePercentile ?? 0) >= 90) {
      level = { key: "high-positive", label: "高正乖離", tone: "warn", action: "偏高水位，適合先設定減碼與買回紀律。" };
    } else if (currentBias > 0 && (positivePercentile ?? 0) >= 75) {
      level = { key: "warm-positive", label: "正乖離偏高", tone: "up", action: "偏熱但未到極端，優先觀察量價是否失速。" };
    } else if (currentBias < 0 && (negativePercentile ?? 0) >= 90) {
      level = { key: "deep-negative", label: "深度負乖離", tone: "down", action: "屬拉回 / 超跌水位，需搭配趨勢與籌碼確認是否止穩。" };
    } else {
      level = { key: "normal", label: "乖離一般", tone: "flat", action: "目前不因乖離單獨調整部位。" };
    }
  }

  return {
    available: true,
    enough,
    observationDays: sample.length,
    firstDate: sample[0]?.date || "",
    lastDate: current.date || "",
    currentBias,
    currentAbs,
    directionPercentile,
    positivePercentile,
    negativePercentile,
    absPercentile,
    p90Positive: quantileNumber(positiveValues, 0.9),
    p95Positive: quantileNumber(positiveValues, 0.95),
    maxPositive: positiveValues.length ? Math.max(...positiveValues) : null,
    maxNegativeAbs: negativeAbsValues.length ? Math.max(...negativeAbsValues) : null,
    currentPrice,
    ma20: current.ma20,
    buybackDisciplinePrice: currentPrice !== null ? currentPrice * (1 + BIAS_DISCIPLINE_BUYBACK_PCT / 100) : null,
    level,
    source: "本機日線 MA20 乖離序列",
    note: "以個股自身歷史乖離分位比較，不用單一固定百分比套所有股票。"
  };
}

function biasLongTrendIntact(technical) {
  if (!technical?.ready) return false;
  const close = toNumber(technical.latest?.close);
  const ma20 = toNumber(technical.ma20);
  const ma60 = toNumber(technical.ma60);
  if (close === null || ma20 === null || ma60 === null) return false;
  return close >= ma20 && ma20 >= ma60 && (technical.ma60Slope === null || technical.ma60Slope >= 0);
}

function biasDisciplineAction(study, technical) {
  if (!study?.available) return study?.reason || "乖離資料不足。";
  if (!study.enough) return `目前只有 ${formatNumber(study.observationDays, 0)} 筆可用乖離，先不要用分位當主要依據。`;
  const longTrend = biasLongTrendIntact(technical);
  if (study.currentBias > 0 && (study.positivePercentile ?? 0) >= 90) {
    return longTrend
      ? "若基本面另行確認且長線趨勢未變，滿倉才討論減碼 2-3 成，保留超過 2/3 核心部位。"
      : "乖離偏高但長線趨勢不完整，先檢查是否已轉弱，不只用乖離做判斷。";
  }
  if (study.currentBias < 0 && (study.negativePercentile ?? 0) >= 90) {
    return "負乖離已在自身歷史深水區，若基本面未壞，賣出後追低回補難度會升高。";
  }
  return study.level.action;
}

function calculateTechnical(code, externalRows = null) {
  const rows = externalRows !== null ? externalRows : latestKlines(code);
  const memoKey = externalRows === null ? klineMemoSignature(code, rows) : "";
  if (memoKey && _technicalDerivedCache.has(memoKey)) {
    recordPerformanceCache("calculateTechnical", "hit");
    return _technicalDerivedCache.get(memoKey);
  }
  recordPerformanceCache("calculateTechnical", memoKey ? "miss" : "bypass");
  if (rows.length < 20) {
    return rememberTechnicalDerived(memoKey, {
      ready: false,
      rows,
      message: rows.length ? `僅 ${rows.length} 根日線，至少需要 20 根。` : "尚未抓取日線。",
      playbook: null
    });
  }

  const closes = rows.map((row) => row.close);
  const volumes = rows.map((row) => row.volume || 0);
  const latest = rows.at(-1);
  const previous = rows.at(-2) || null;
  const ma5 = sma(closes, 5);
  const ma10 = sma(closes, 10);
  const ma20 = sma(closes, 20);
  const ma60 = sma(closes, 60);
  const ma120 = sma(closes, 120);
  const ma240 = sma(closes, 240);
  const ma10Series = smaSeries(closes, 10);
  const ma20Series = smaSeries(closes, 20);
  const ma60Series = smaSeries(closes, 60);
  const ma120Series = smaSeries(closes, 120);
  const ma240Series = smaSeries(closes, 240);
  const rsi14 = rsi(closes, 14);
  const macdValue = macd(closes);
  const recent20 = closes.slice(-20);
  const bbMid = sma(closes, 20);
  const bbStd = standardDeviation(recent20);
  const bbUpper = bbMid !== null && bbStd !== null ? bbMid + bbStd * 2 : null;
  const bbLower = bbMid !== null && bbStd !== null ? bbMid - bbStd * 2 : null;
  const volumeMa20 = sma(volumes, Math.min(20, volumes.length));
  const volumeMa5 = sma(volumes, Math.min(5, volumes.length));
  const volumeRatio = volumeMa20 ? latest.volume / volumeMa20 : null;
  const volumeRatio5 = volumeMa5 ? latest.volume / volumeMa5 : null;
  const support = Math.min(...rows.slice(-20).map((row) => row.low));
  const resistance = Math.max(...rows.slice(-20).map((row) => row.high));
  const changePct = previous ? (latest.close - previous.close) / previous.close * 100 : null;
  const bias20 = ma20 ? (latest.close - ma20) / ma20 * 100 : null;
  const bias60 = ma60 ? (latest.close - ma60) / ma60 * 100 : null;
  const bias240 = ma240 ? (latest.close - ma240) / ma240 * 100 : null;
  const maBiasProfile = buildMovingAverageBiasProfile(rows, latest.close, {
    20: ma20Series,
    60: ma60Series,
    240: ma240Series
  });
  const biasStudy = buildBiasDisciplineStudy(rows, latest.close, ma20Series);
  const ma10Slope = ma10Series.at(-1) !== null && ma10Series.at(-6) !== null
    ? ma10Series.at(-1) - ma10Series.at(-6)
    : null;
  const ma20Slope = ma20Series.at(-1) !== null && ma20Series.at(-6) !== null
    ? ma20Series.at(-1) - ma20Series.at(-6)
    : null;
  const ma60Slope = ma60Series.at(-1) !== null && ma60Series.at(-6) !== null
    ? ma60Series.at(-1) - ma60Series.at(-6)
    : null;
  const ma120Latest = toNumber(ma120Series.at(-1));
  const ma120Prior = toNumber(ma120Series.at(-21));
  const ma120Slope = ma120Latest !== null && ma120Prior !== null
    ? ma120Latest - ma120Prior
    : null;
  const ma240Latest = toNumber(ma240Series.at(-1));
  const ma240Prior = toNumber(ma240Series.at(-21));
  const ma240Slope = ma240Latest !== null && ma240Prior !== null
    ? ma240Latest - ma240Prior
    : null;

  let score = 0;
  if (ma5 && latest.close > ma5) score += 1;
  if (ma10 && latest.close > ma10) score += 1;
  if (ma20 && latest.close > ma20) score += 1;
  if (ma60 && latest.close > ma60) score += 1;
  if (ma240 && latest.close > ma240) score += 1;
  if (ma20 && ma60 && ma20 > ma60) score += 1;
  if (ma60 && ma240 && ma60 > ma240) score += 1;
  if (macdValue.histogram !== null && macdValue.histogram > 0) score += 1;
  if (rsi14 !== null && rsi14 >= 45 && rsi14 <= 70) score += 1;
  if (volumeRatio !== null && volumeRatio >= 1.3 && changePct !== null && changePct > 0) score += 1;
  if (rsi14 !== null && rsi14 > 78) score -= 1;
  if (ma20 && latest.close < ma20) score -= 1;
  if (ma240 && latest.close < ma240) score -= 1;
  if (macdValue.histogram !== null && macdValue.histogram < 0) score -= 1;

  let signal = "盤整觀察";
  if (score >= 7) signal = "技術偏多";
  else if (score >= 4) signal = "轉強觀察";
  else if (score <= 0) signal = "技術偏弱";

  const tags = [];
  if (ma5 && ma10 && ma20 && ma60 && (!ma240 || ma60 > ma240) && latest.close > ma5 && ma5 > ma10 && ma10 > ma20 && ma20 > ma60) tags.push("均線多頭排列");
  if (ma10 && latest.close > ma10) tags.push("站上10日線");
  if (ma20 && latest.close < ma20) tags.push("跌破月線");
  if (ma20 && latest.close > ma20) tags.push("站上月線");
  if (ma60 && latest.close > ma60) tags.push("站上季線");
  if (ma240 && latest.close > ma240) tags.push("站上年線");
  if (volumeRatio !== null && volumeRatio >= 1.8) tags.push("量能放大");
  if (rsi14 !== null && rsi14 >= 75) tags.push("RSI過熱");
  if (rsi14 !== null && rsi14 <= 30) tags.push("RSI偏冷");
  if (bbUpper && latest.close > bbUpper) tags.push("突破布林上緣");
  if (bbLower && latest.close < bbLower) tags.push("跌破布林下緣");
  if (macdValue.histogram !== null && macdValue.histogram > 0) tags.push("MACD偏多");

  // ─── Tier 1/2/3 進階指標 ────────────────────────────────────────────────
  // ATR / 背離 / K 棒型態 / Ichimoku / Fibonacci / Volume Profile
  const atr14 = atr(rows, 14);
  const rsiSer = rsiSeries(closes, 14);
  const macdFull = macdFullSeries(closes);
  const rsiDivergence = detectDivergence(rows, rsiSer, 60);
  const macdDivergence = detectDivergence(rows, macdFull.macdLines, 60);
  const candlePatterns = detectCandlePatterns(rows);
  const ichimoku = calculateIchimoku(rows);
  const fibLevels = calculateFibonacci(rows, 60);
  const volumeProfile = calculateVolumeProfile(rows.slice(-60), 12);
  const largeVolumeDefense = analyzeLargeVolumeDefense(rows, 60);
  const weeklyLargeVolumeDefense = externalRows === null ? analyzeWeeklyLargeVolumeDefense(rows) : null;
  const recoverySignal = analyzeLargeVolumeRecovery(rows, largeVolumeDefense);
  const oscillatorChecklist = analyzeOscillatorChecklist(rows, rsiDivergence, macdDivergence, macdValue, rsi14);
  if (recoverySignal.available && ["reclaimedLow", "reclaimedHalf", "reclaimedHigh"].includes(recoverySignal.status)) tags.push("失守後修復");
  if (recoverySignal.available && ["failedRetest", "unrecovered"].includes(recoverySignal.status)) tags.push("失守未修復");
  if (oscillatorChecklist.available && oscillatorChecklist.tone === "up") tags.push("KD/背離轉強");
  if (oscillatorChecklist.available && oscillatorChecklist.tone === "down") tags.push("KD/背離轉弱");
  // ATR-based stops (2 ATR 為常見初始停損)
  const atrStopLong = latest.close && atr14 ? latest.close - atr14 * 2 : null;
  const atrStopShort = latest.close && atr14 ? latest.close + atr14 * 2 : null;
  const decisionLayer = buildTechnicalDecisionLayer({
    rows,
    latest,
    atr14,
    volumeProfile,
    dailyDefense: largeVolumeDefense,
    weeklyDefense: weeklyLargeVolumeDefense,
    recoverySignal,
    oscillatorChecklist
  });

  const technical = {
    ready: true,
    rows,
    latest,
    previous,
    source: latest.source,
    signal,
    score,
    changePct,
    ma5,
    ma10,
    ma20,
    ma60,
    ma120,
    ma240,
    ma10Slope,
    ma20Slope,
    ma60Slope,
    ma120Slope,
    ma240Slope,
    rsi14,
    macd: macdValue,
    bbMid,
    bbUpper,
    bbLower,
    volumeMa5,
    volumeRatio,
    volumeRatio5,
    support,
    resistance,
    bias20,
    bias60,
    bias240,
    maBiasProfile,
    biasStudy,
    tags,
    // 新增 Tier 1/2/3 進階指標
    atr14,
    atrStopLong,
    atrStopShort,
    rsiDivergence,
    macdDivergence,
    candlePatterns,
    ichimoku,
    fibLevels,
    volumeProfile,
    largeVolumeDefense,
    weeklyLargeVolumeDefense,
    recoverySignal,
    oscillatorChecklist,
    decisionLayer
  };

  technical.playbook = buildPlaybookAnalysis(technical);
  technical.events = buildTechnicalEvents(technical);
  technical.eventTimeline = buildTechnicalEventTimeline(technical);
  technical.eventBacktest = buildTechnicalEventBacktest(technical);
  technical.tradingState = buildTradingStateMachine(technical);
  return rememberTechnicalDerived(memoKey, technical);
}

// 週線技術分析包裝器 — 使用週K聚合後呼叫 calculateTechnical
function calculateWeeklyTechnical(code) {
  return calculateTechnical(code, aggregateWeeklyBars(latestKlines(code)));
}

// ─── v7.7 簡易回測引擎 ─────────────────────────────────────────────────────
// 對日 K 序列逐根呼叫 calculateTechnical()，遇到 playbook 多頭訊號則模擬進場，
// 採 N×ATR 停損 / M×ATR 目標 / 最長 holdDays 滿期出場，產生交易紀錄與績效統計。
function backtestPlaybook(code, opts = {}) {
  const lookback = opts.lookback ?? 252;      // 近 1 年交易日
  const holdDays = opts.holdDays ?? 20;       // 最長持有天數
  const stopAtrMul = opts.stopAtrMul ?? 2;    // 2 × ATR 停損
  const targetAtrMul = opts.targetAtrMul ?? 3; // 3 × ATR 目標
  const rows = latestKlines(code);
  if (!Array.isArray(rows) || rows.length < 80) return null;
  const startIdx = Math.max(60, rows.length - lookback);
  const trades = [];
  for (let i = startIdx; i < rows.length - holdDays; i++) {
    const partial = rows.slice(0, i + 1);
    let signal;
    try { signal = calculateTechnical(code, partial); } catch (_) { continue; }
    if (!signal || !signal.ready || !signal.playbook) continue;
    const pb = signal.playbook;
    if (!pb.levels?.primaryEntry || !pb.levels?.stop) continue;
    const isBullish = (pb.trendLabel && pb.trendLabel.includes("多"))
      || (pb.cardSummary && (pb.cardSummary.includes("進場") || pb.cardSummary.includes("做多")));
    if (!isBullish) continue;
    const entry = signal.latest.close;
    const atr = signal.atr14 || (signal.latest.high - signal.latest.low);
    if (!Number.isFinite(entry) || !Number.isFinite(atr) || atr <= 0) continue;
    const stop = entry - atr * stopAtrMul;
    const target = entry + atr * targetAtrMul;
    let exitPrice = null;
    let exitDay = null;
    let exitReason = "time";
    for (let j = i + 1; j <= Math.min(i + holdDays, rows.length - 1); j++) {
      const r = rows[j];
      if (!Number.isFinite(r.low) || !Number.isFinite(r.high)) continue;
      if (r.low <= stop) { exitPrice = stop; exitDay = j; exitReason = "stop"; break; }
      if (r.high >= target) { exitPrice = target; exitDay = j; exitReason = "target"; break; }
    }
    if (exitPrice === null) {
      exitDay = Math.min(i + holdDays, rows.length - 1);
      exitPrice = rows[exitDay].close;
    }
    if (!Number.isFinite(exitPrice)) continue;
    const pnl = (exitPrice - entry) / entry;
    const rMultiple = atr > 0 ? (exitPrice - entry) / (atr * stopAtrMul) : 0;
    trades.push({
      entryDate: rows[i].date,
      entryPrice: entry,
      exitDate: rows[exitDay].date,
      exitPrice,
      exitReason,
      pnl,
      rMultiple,
      holdDays: exitDay - i
    });
  }
  if (!trades.length) {
    return { trades: [], winRate: null, avgR: null, totalPnl: 0, maxDD: 0, count: 0, wins: 0, avgPnl: 0, stopReason: 0, targetReason: 0, timeReason: 0 };
  }
  const wins = trades.filter((t) => t.pnl > 0);
  const avgR = trades.reduce((s, t) => s + t.rMultiple, 0) / trades.length;
  const totalPnl = trades.reduce((s, t) => s + t.pnl, 0);
  let peak = 0;
  let cumul = 0;
  let maxDD = 0;
  for (const t of trades) {
    cumul += t.pnl;
    if (cumul > peak) peak = cumul;
    if (peak - cumul > maxDD) maxDD = peak - cumul;
  }
  return {
    trades,
    count: trades.length,
    wins: wins.length,
    winRate: wins.length / trades.length,
    avgR,
    avgPnl: totalPnl / trades.length,
    totalPnl,
    maxDD,
    stopReason: trades.filter((t) => t.exitReason === "stop").length,
    targetReason: trades.filter((t) => t.exitReason === "target").length,
    timeReason: trades.filter((t) => t.exitReason === "time").length
  };
}

// ─── v7.8 Feature 1：全 WATCHLIST 回測排名表 ──────────────────────────────────
// 對整個 WATCHLIST 跑 playbook 回測，依「勝率 × 平均 R」綜合分排序。
async function runWatchlistBacktest(opts = {}) {
  const results = [];
  const filteredStocks = WATCHLIST.filter((s) => s.suffix && (latestKlines(s.code) || []).length >= 80);
  let done = 0;
  for (const stock of filteredStocks) {
    try {
      const result = backtestPlaybook(stock.code, opts);
      if (result && result.count >= 3) {
        results.push({
          code: stock.code,
          name: stock.name,
          count: result.count,
          wins: result.wins,
          winRate: result.winRate,
          avgR: result.avgR,
          avgPnl: result.avgPnl,
          totalPnl: result.totalPnl,
          maxDD: result.maxDD,
          stopReason: result.stopReason,
          targetReason: result.targetReason,
          timeReason: result.timeReason
        });
      }
    } catch (_) {
      // 個別股票回測失敗則跳過，不阻塞全市場跑
    }
    done++;
    if (done % 20 === 0) {
      setStatus(`回測進度 ${done}/${filteredStocks.length}...`);
      // 讓 UI 有機會更新
      await new Promise((r) => setTimeout(r, 0));
    }
  }
  // 綜合分 = 勝率 × 平均 R（兩者皆正才有意義）
  results.forEach((r) => {
    r.score = (r.winRate || 0) * (r.avgR || 0);
  });
  results.sort((a, b) => b.score - a.score);
  return results;
}

