// ─── v7.8 Feature 3：TWSE50 / MID100 自動同步 ─────────────────────────────────
// 依本機 state.marketCaps 排序產生 T50 / MID100；非元大投信官方名單，僅供推估。
async function syncIndexComponents() {
  setStatus("同步 TWSE 市值排名中...");
  try {
    // 從 state.marketCaps 直接排序：避免額外抓 TWSE API（已有資料即可使用）
    const caps = state.marketCaps || {};
    const all = Object.keys(caps)
      .map((code) => ({ code, cap: toNumber(caps[code]?.marketCap100m) }))
      .filter((x) => x.cap !== null && x.cap > 0 && /^\d{4,6}[A-Z]?$/.test(x.code));
    if (all.length < 30) {
      // 資料不足，回落到 TWSE OpenAPI 個股清單，從 quotes / shares 估算
      const fallback = [];
      for (const stock of WATCHLIST) {
        const shares = stockSharesIssued(stock);
        const price = stockPriceForMarketCap(stock);
        const cap = marketCapHundredMillion(price, shares);
        if (cap !== null && cap > 0) fallback.push({ code: stock.code, cap });
      }
      if (fallback.length < 30) {
        throw new Error("市值資料不足 30 檔，請先按「報價估值」累積");
      }
      all.push(...fallback.filter((f) => !all.some((a) => a.code === f.code)));
    }
    all.sort((a, b) => b.cap - a.cap);
    const top50 = all.slice(0, 50).map((x) => x.code);
    const mid100 = all.slice(50, 150).map((x) => x.code);
    state.customTWSE50 = top50;
    state.customMID100 = mid100;
    state.indexComponentsSync = {
      syncedAt: new Date().toISOString(),
      top50Count: top50.length,
      mid100Count: mid100.length,
      source: "本機 marketCaps 推估"
    };
    persistStateSilently("指數成分股同步");
    setStatus(`指數成分股同步完成：T50 ${top50.length} / MID100 ${mid100.length}`, "good");
    return { top50, mid100 };
  } catch (err) {
    setStatus(`指數同步失敗：${err?.message || err}`, "error");
    throw err;
  }
}

