function signalClass(technical) {
  if (!technical || !technical.ready) return "warn";
  if (technical.score >= 4) return "good";
  if (technical.score <= 0) return "bad";
  return "warn";
}

// 均線位置分區：回傳 { label, bg, fg, title } 或 null
function maZoneInfo(price, ma5, ma20, ma60, ma240) {
  if (!price) return null;
  if (ma5 && price > ma5) {
    return { label: "5日↑", bg: "#b7202e", fg: "#fff", title: "站上五日線" };
  }
  if (ma5 && ma20 && price <= ma5 && price >= ma20) {
    const pos = (ma5 - ma20) > 0 ? (price - ma20) / (ma5 - ma20) : 0.5;
    return pos >= 0.5
      ? { label: "5~月近5", bg: "#c05621", fg: "#fff", title: "五日線到月線間，靠近五日線" }
      : { label: "5~月近月", bg: "#dd6b20", fg: "#fff", title: "五日線到月線間，靠近月線" };
  }
  if (!ma5 && ma20 && price >= ma20) {
    return { label: "月線↑", bg: "#c05621", fg: "#fff", title: "站上月線" };
  }
  if (ma20 && ma60 && price < ma20 && price >= ma60) {
    const pos = (ma20 - ma60) > 0 ? (price - ma60) / (ma20 - ma60) : 0.5;
    return pos >= 0.5
      ? { label: "月~季近月", bg: "#b7791f", fg: "#fff", title: "月線到季線間，靠近月線" }
      : { label: "月~季近季", bg: "#744210", fg: "#fff", title: "月線到季線間，靠近季線" };
  }
  if (ma20 && price < ma20 && !ma60) {
    return { label: "月線↓", bg: "#2f855a", fg: "#fff", title: "跌破月線" };
  }
  if (ma60 && price < ma60) {
    if (ma240 && Math.abs((price - ma240) / ma240) <= 0.05) {
      return { label: "年線±", bg: "#4a5568", fg: "#fff", title: "接近年線（±5%）" };
    }
    if (ma240 && price < ma240) {
      return { label: "年線↓", bg: "#1a202c", fg: "#fff", title: "跌破年線" };
    }
    return { label: "季線↓", bg: "#276749", fg: "#fff", title: "跌破季線" };
  }
  return null;
}

// 三大法人賣壓警示：回傳 { level: 'warn'|'danger', text } 或 null
function stockInstAlertLevel(code) {
  const inst = (state.institutional || {})[code];
  if (!inst) return null;
  const history = Array.isArray(inst.history) ? inst.history : [];
  const recent = history.slice(-3);
  let total, foreign;
  if (recent.length >= 2) {
    total = recent.reduce((s, r) => s + (r.totalNet || 0), 0);
    foreign = recent.reduce((s, r) => s + (r.foreignNet || 0), 0);
  } else {
    total = inst.totalNet || 0;
    foreign = inst.foreignNet || 0;
  }
  const allSelling = recent.length >= 2 && recent.every((r) => (r.totalNet || 0) < 0);
  if (total <= -3000 || (allSelling && total <= -800)) {
    return { level: "danger", text: `賣超${formatNumber(Math.abs(total), 0)}張` };
  }
  if (total <= -800 || foreign <= -600) {
    return { level: "warn", text: `小量賣超${formatNumber(Math.abs(total), 0)}張` };
  }
  return null;
}

function chipScoreComponentLevel(score) {
  if (score <= -2) return "danger";
  if (score < 0) return "warn";
  if (score > 0) return "good";
  return "flat";
}

function chipScoreLevel(score) {
  if (score <= -2) return "danger";
  if (score < 0) return "warn";
  if (score > 0) return "good";
  return "flat";
}

function chipComponent(label, score, detail, options = {}) {
  return {
    label,
    score,
    level: chipScoreComponentLevel(score),
    detail,
    available: options.available !== false,
    source: options.source || "",
    rule: options.rule || ""
  };
}

function limitLockDenominatorInfo(stock) {
  if (!stock) return { shares: null, lots: null, label: "分母缺資料", source: "", confidence: "low" };
  const code = String(stock.code || "");
  const foreignOwn = (state.foreignOwnership || {})[code];
  const marketCap = (state.marketCaps || {})[code];
  const tdccData = (state.tdcc || {})[code];
  const candidates = [
    {
      shares: toNumber(foreignOwn?.sharesIssued),
      source: foreignOwn?.source || "",
      date: foreignOwn?.date || "",
      confidence: "medium"
    },
    {
      shares: toNumber(marketCap?.sharesIssued),
      source: marketCap?.sourceLabel || "",
      date: marketCap?.sourceDate || "",
      confidence: "medium"
    },
    {
      shares: toNumber(tdccData?.totalShares),
      source: tdccData?.source || "",
      date: tdccData?.dataDate || "",
      confidence: "low"
    }
  ];
  const candidate = candidates.find((item) => item.shares !== null && item.shares > 0);
  if (!candidate) return { shares: null, lots: null, label: "分母缺資料", source: "", confidence: "low" };
  return {
    shares: candidate.shares,
    lots: candidate.shares / 1000,
    label: "發行股數代理流通張數",
    source: [candidate.source, candidate.date].filter(Boolean).join(" "),
    confidence: candidate.confidence,
    note: "尚未扣除董監、大股東、庫藏股或長期鎖定持股；此欄僅作研究排序 proxy。"
  };
}

function limitLockStrength(ratioPct) {
  const ratio = toNumber(ratioPct);
  if (ratio === null) return { key: "unknown", label: "待算", scoreTier: 0 };
  if (ratio >= 1) return { key: "strong", label: "強鎖", scoreTier: 2 };
  if (ratio >= 0.2) return { key: "medium", label: "中等鎖", scoreTier: 1 };
  if (ratio > 0) return { key: "thin", label: "薄鎖", scoreTier: -1 };
  return { key: "none", label: "未鎖", scoreTier: 0 };
}

function limitLockInfo(stockInput) {
  const stock = typeof stockInput === "string" ? STOCK_MAP.get(stockInput) : stockInput;
  const code = String(stock?.code || stockInput || "");
  const quote = quoteFor(code);
  if (!quote) {
    return {
      available: false,
      status: "missing",
      label: "尚未更新報價",
      reason: "需先更新官方 MIS 報價才有五檔鎖單。",
      tone: "flat"
    };
  }
  const sourceKind = String(quote.sourceKind || "");
  const hasOrderBook = quote.bestBid !== undefined || quote.bestAsk !== undefined
    || Array.isArray(quote.bidPrices) || Array.isArray(quote.askPrices);
  if (sourceKind === "fallback" || quote.fallbackUsed || !hasOrderBook) {
    return {
      available: false,
      status: "no-orderbook",
      label: "缺官方五檔",
      reason: "目前報價來源沒有五檔委買委賣與漲跌停價，無法判斷真假鎖單。",
      source: quote.source || "",
      tone: "flat"
    };
  }

  const denominator = limitLockDenominatorInfo(stock || { code });
  const limitUpPrice = toNumber(quote.limitUpPrice);
  const limitDownPrice = toNumber(quote.limitDownPrice);
  const price = toNumber(quote.price);
  const bestBid = toNumber(quote.bestBid);
  const bestAsk = toNumber(quote.bestAsk);
  const totalBid = toNumber(quote.totalBid) || 0;
  const totalAsk = toNumber(quote.totalAsk) || 0;
  const bestBidVol = toNumber(quote.bestBidVol) || 0;
  const bestAskVol = toNumber(quote.bestAskVol) || 0;
  const atLimitUp = limitUpPrice !== null && (priceEquals(price, limitUpPrice) || priceEquals(bestBid, limitUpPrice));
  const atLimitDown = limitDownPrice !== null && (priceEquals(price, limitDownPrice) || priceEquals(bestAsk, limitDownPrice));
  const upLocked = atLimitUp && priceEquals(bestBid, limitUpPrice) && totalBid > 0 && totalAsk <= 0;
  const downLocked = atLimitDown && priceEquals(bestAsk, limitDownPrice) && totalAsk > 0 && totalBid <= 0;
  const side = upLocked || atLimitUp ? "up" : downLocked || atLimitDown ? "down" : "";
  const isLocked = upLocked || downLocked;
  const lockLots = side === "up"
    ? (bestBidVol || totalBid)
    : side === "down"
      ? (bestAskVol || totalAsk)
      : 0;
  const denominatorLots = toNumber(denominator.lots);
  const ratioPct = denominatorLots && denominatorLots > 0 ? lockLots / denominatorLots * 100 : null;
  const strength = isLocked ? limitLockStrength(ratioPct) : { key: "none", label: side ? "觸價未鎖" : "未觸漲跌停", scoreTier: 0 };
  const quoteTime = [quote.sourceDate, quote.sourceTime].filter(Boolean).join(" ");
  const source = [quote.source || "證交所 MIS", quoteTime].filter(Boolean).join(" ");
  const label = !side
    ? "未觸漲跌停"
    : `${side === "up" ? "漲停" : "跌停"}${isLocked ? strength.label : "觸價未鎖"}`;
  const tone = !side
    ? "flat"
    : side === "down"
      ? "down"
      : isLocked && strength.key !== "thin"
        ? "up"
        : "warn";
  const status = !side ? "none" : isLocked ? "locked" : "touch";
  const detail = side
    ? `${label}：鎖單 ${formatNumber(lockLots, 0)} 張 / ${denominator.label} ${formatNumber(denominatorLots, 0)} 張 = ${ratioPct !== null ? formatPercentMetric(ratioPct, 3) : "待算"}`
    : "尚未觸及漲跌停，無鎖單判讀。";

  return {
    available: true,
    status,
    side,
    isLocked,
    label,
    strength,
    tone,
    quote,
    price,
    limitUpPrice,
    limitDownPrice,
    bestBid,
    bestAsk,
    totalBid,
    totalAsk,
    bestBidVol,
    bestAskVol,
    lockLots,
    denominatorLots,
    ratioPct,
    denominator,
    source,
    detail,
    confidence: denominator.confidence === "medium" && denominatorLots !== null && denominatorLots > 0 ? "medium" : "low",
    reason: denominator.note || ""
  };
}

function limitLockMiniHtml(stockInput, options = {}) {
  const info = limitLockInfo(stockInput);
  if (!info.available) {
    return options.showUnavailable ? `<span class="chip flat" title="${escapeHtml(info.reason || "")}">${escapeHtml(info.label || "鎖單待更新")}</span>` : "";
  }
  if (info.status === "none" && options.hideNone !== false) return "";
  const ratio = info.ratioPct !== null ? ` ${formatPercentMetric(info.ratioPct, 2)}` : "";
  const title = [
    info.detail,
    info.source ? `來源：${info.source}` : "",
    info.denominator?.source ? `分母：${info.denominator.source}` : ""
  ].filter(Boolean).join("；");
  return `<span class="chip ${info.tone}" title="${escapeHtml(title)}">${escapeHtml(info.label)}${escapeHtml(ratio)}</span>`;
}

function limitLockChipComponent(code) {
  const stock = STOCK_MAP.get(code) || { code };
  const info = limitLockInfo(stock);
  if (!info.available) {
    return chipComponent("漲跌停鎖單", 0, info.label || "缺鎖單資料", {
      available: false,
      source: info.source || "",
      rule: "需官方 MIS 五檔報價"
    });
  }
  if (info.status === "none") {
    return chipComponent("漲跌停鎖單", 0, "未觸漲跌停", {
      source: info.source || "",
      rule: "中性"
    });
  }
  if (info.status === "touch") {
    const score = info.side === "up" ? -1 : -1;
    return chipComponent("漲跌停鎖單", score, `${info.label}；五檔仍有對手方`, {
      source: info.source || "",
      rule: "自訂觀察：觸價但未鎖，視為假鎖風險"
    });
  }
  const ratioText = info.ratioPct !== null ? formatPercentMetric(info.ratioPct, 3) : "待算";
  if (info.ratioPct === null) {
    return chipComponent("漲跌停鎖單", 0, `${info.label}；分母缺資料，僅顯示五檔狀態`, {
      source: info.source || "",
      rule: "需發行股數或 TDCC 分母才計算鎖單比"
    });
  }
  if (info.side === "down") {
    const score = info.ratioPct !== null && info.ratioPct >= 1 ? -2 : -1;
    return chipComponent("漲跌停鎖單", score, `${info.label} ${ratioText}（賣壓鎖住）`, {
      source: info.source || "",
      rule: "鎖跌停張數 ÷ 發行股數代理流通張數"
    });
  }
  if (info.strength.key === "thin") {
    return chipComponent("漲跌停鎖單", -1, `${info.label} ${ratioText}（薄鎖，易開）`, {
      source: info.source || "",
      rule: "鎖漲停比 <0.2%，假鎖風險"
    });
  }
  return chipComponent("漲跌停鎖單", 1, `${info.label} ${ratioText}`, {
    source: info.source || "",
    rule: "鎖漲停張數 ÷ 發行股數代理流通張數"
  });
}

function institutionalChipComponent(code) {
  const inst = (state.institutional || {})[code];
  if (!inst) {
    return chipComponent("三大法人", 0, "缺三大法人資料", { available: false });
  }
  const history = Array.isArray(inst.history) ? inst.history : [];
  const recent5 = history.slice(-5);
  const recent3 = history.slice(-3);

  // 5日累計
  let total5 = 0;
  let foreign5 = 0;
  if (recent5.length >= 2) {
    total5 = recent5.reduce((sum, row) => sum + (toNumber(row.totalNet) || 0), 0);
    foreign5 = recent5.reduce((sum, row) => sum + (toNumber(row.foreignNet) || 0), 0);
  } else {
    total5 = toNumber(inst.totalNet) || 0;
    foreign5 = toNumber(inst.foreignNet) || 0;
  }
  // 3日累計（短線判斷）
  const total3 = recent3.length >= 2
    ? recent3.reduce((sum, row) => sum + (toNumber(row.totalNet) || 0), 0)
    : total5;

  // 計算連續買超/賣超天數
  let buyStreak = 0;
  let sellStreak = 0;
  for (let i = history.length - 1; i >= 0; i--) {
    const net = toNumber(history[i].totalNet) || 0;
    if (net > 0) { if (sellStreak > 0) break; buyStreak++; }
    else if (net < 0) { if (buyStreak > 0) break; sellStreak++; }
    else break;
  }

  const alert = stockInstAlertLevel(code);
  if (alert?.level === "danger") {
    return chipComponent("三大法人", -2, alert.text, {
      source: inst.source || "",
      rule: "沿用三大法人賣壓警示"
    });
  }
  if (alert?.level === "warn") {
    return chipComponent("三大法人", -1, alert.text, {
      source: inst.source || "",
      rule: "沿用三大法人賣壓警示"
    });
  }

  // 強烈買超訊號
  if (buyStreak >= 4) {
    return chipComponent("三大法人", 2, `${buyStreak}連買 5日+${formatNumber(total5, 0)}張`, {
      source: inst.source || "",
      rule: "自訂觀察：連續 ≥4 日法人買超"
    });
  }
  if (total5 >= 5000 || (buyStreak >= 2 && total5 >= 1500)) {
    return chipComponent("三大法人", 1, `${buyStreak >= 2 ? buyStreak + "連買 " : ""}5日+${formatNumber(total5, 0)}張`, {
      source: inst.source || "",
      rule: "自訂觀察：法人連續或大量買超"
    });
  }

  // 強烈賣超訊號
  if (sellStreak >= 4) {
    return chipComponent("三大法人", -2, `${sellStreak}連賣 5日${formatNumber(total5, 0)}張`, {
      source: inst.source || "",
      rule: "自訂觀察：連續 ≥4 日法人賣超"
    });
  }
  if (total5 <= -5000 || (sellStreak >= 2 && total5 <= -1500)) {
    return chipComponent("三大法人", -1, `${sellStreak >= 2 ? sellStreak + "連賣 " : ""}5日${formatNumber(total5, 0)}張`, {
      source: inst.source || "",
      rule: "自訂觀察：法人連續或大量賣超"
    });
  }

  const direction = total3 > 0 ? "買超" : total3 < 0 ? "賣超" : "持平";
  const streakText = buyStreak > 0 ? `${buyStreak}連買 ` : sellStreak > 0 ? `${sellStreak}連賣 ` : "";
  return chipComponent("三大法人", 0, `${streakText}3日${direction}${formatNumber(Math.abs(total3), 0)}張`, {
    source: inst.source || "",
    rule: "中性"
  });
}

function foreignOwnershipChipComponent(code) {
  const trend = foreignOwnershipTrend(code);
  const hasRows = Array.isArray(trend?.rows) && trend.rows.length > 0;
  if (!hasRows) {
    return chipComponent("外資持股", 0, "缺外資持股歷史", {
      available: false,
      rule: "自訂觀察：最近持股比率變化"
    });
  }
  if (trend.signal === "accumulation") {
    return chipComponent("外資持股", 2, trend.text, {
      source: trend.latest?.source || "",
      rule: `最近 ${FOREIGN_OWNERSHIP_TREND_WINDOW} 筆 +${FOREIGN_ACCUMULATION_THRESHOLD_PP.toFixed(1)}百分點`
    });
  }
  if (trend.signal === "exit") {
    const score = trend.level === "danger" ? -2 : -1;
    return chipComponent("外資持股", score, trend.text, {
      source: trend.latest?.source || "",
      rule: `最近 ${FOREIGN_OWNERSHIP_TREND_WINDOW} 筆 ${FOREIGN_EXIT_THRESHOLD_PP.toFixed(1)}百分點`
    });
  }
  return chipComponent("外資持股", 0, trend.text || "外資持股持平", {
    source: trend.latest?.source || "",
    rule: "中性"
  });
}

function marginChipComponent(code) {
  const marg = (state.margin || {})[code];
  if (!marg) {
    return chipComponent("融資融券", 0, "缺融資融券資料", {
      available: false,
      rule: "自訂觀察：融資使用率"
    });
  }
  const usage = cellNumber(marg.marginUsagePct);
  if (usage === null) {
    return chipComponent("融資融券", 0, "融資使用率缺值", {
      source: marg.source || "",
      rule: "自訂觀察：融資使用率"
    });
  }

  const shortBalance = cellNumber(marg.shortBalance) || 0;
  const marginBalance = cellNumber(marg.marginBalance) || 0;
  const shortRatio = marginBalance > 0 ? shortBalance / marginBalance * 100 : null;
  const shortSuffix = shortRatio !== null && shortRatio >= 30
    ? `；融券/融資 ${formatNumber(shortRatio, 0)}%↑`
    : "";

  // 高融資使用率 → 多頭過熱警示
  if (usage >= 80) {
    return chipComponent("融資融券", -2, `融資 ${formatPercentMetric(usage)} 過高${shortSuffix}`, {
      source: marg.source || "",
      rule: "自訂門檻：融資≥80%"
    });
  }
  if (usage >= 60) {
    return chipComponent("融資融券", -1, `融資 ${formatPercentMetric(usage)} 偏高${shortSuffix}`, {
      source: marg.source || "",
      rule: "自訂門檻：融資≥60%"
    });
  }

  // 低融資 + 高融券 → 軋空潛力
  if (usage <= 20 && shortRatio !== null && shortRatio >= 40) {
    return chipComponent("融資融券", 1, `融資低 ${formatPercentMetric(usage)}；融券/融資 ${formatNumber(shortRatio, 0)}% 高`, {
      source: marg.source || "",
      rule: "自訂觀察：低融資高融券軋空潛力"
    });
  }
  // 低融資 → 多頭乾淨
  if (usage <= 20) {
    return chipComponent("融資融券", 1, `融資 ${formatPercentMetric(usage)} 偏低${shortSuffix}`, {
      source: marg.source || "",
      rule: "自訂門檻：融資≤20%"
    });
  }
  return chipComponent("融資融券", 0, `融資 ${formatPercentMetric(usage)}${shortSuffix}`, {
    source: marg.source || "",
    rule: "中性"
  });
}

function tdccChipComponent(code) {
  const tdccData = (state.tdcc || {})[code];
  if (!tdccData) {
    return chipComponent("TDCC 集保", 0, "缺集保持股分布", {
      available: false,
      rule: "自訂觀察：大戶持股比"
    });
  }
  const whalePct = cellNumber(tdccData.whalePercent);
  if (whalePct === null) {
    return chipComponent("TDCC 集保", 0, "大戶持股比缺值", {
      source: tdccData.source || "",
      rule: "自訂觀察：大戶持股比"
    });
  }
  if (whalePct >= 45) {
    return chipComponent("TDCC 集保", 1, `大戶持股 ${formatPercentMetric(whalePct)} 偏集中`, {
      source: tdccData.source || "",
      rule: "自訂門檻：≥45%"
    });
  }
  if (whalePct <= 30) {
    return chipComponent("TDCC 集保", -1, `大戶持股 ${formatPercentMetric(whalePct)} 偏低`, {
      source: tdccData.source || "",
      rule: "自訂門檻：≤30%"
    });
  }
  return chipComponent("TDCC 集保", 0, `大戶持股 ${formatPercentMetric(whalePct)}`, {
    source: tdccData.source || "",
    rule: "中性"
  });
}

function chipScoreBreakdown(code) {
  const components = [
    institutionalChipComponent(code),
    limitLockChipComponent(code),
    foreignOwnershipChipComponent(code),
    marginChipComponent(code),
    tdccChipComponent(code)
  ];
  const rawScore = components.reduce((sum, component) => sum + component.score, 0);
  const score = clamp(rawScore, -2, 2);
  const lead = components
    .filter((component) => component.score !== 0)
    .sort((left, right) => Math.abs(right.score) - Math.abs(left.score) || right.score - left.score)[0] || null;
  const missingCount = components.filter((component) => !component.available).length;
  return {
    score,
    rawScore,
    level: chipScoreLevel(score),
    text: lead ? `${lead.label}：${lead.detail}` : missingCount === components.length ? "籌碼資料不足" : "籌碼中性",
    source: lead?.label || "",
    lead,
    components,
    missingCount
  };
}

function stockChipSignal(code) {
  const breakdown = chipScoreBreakdown(code);
  const foreignTrend = foreignOwnershipTrend(code);
  return {
    level: breakdown.level,
    score: breakdown.score,
    text: breakdown.text,
    source: breakdown.source,
    foreignTrend,
    breakdown
  };
}

// ─── 三大法人連續買賣超天數 ────────────────────────────────────────────────
// 回傳值：正數＝連續買超天數；負數＝連續賣超天數；0＝中性
function institutionalStreak(code) {
  const inst = (state.institutional || {})[code];
  if (!inst || !Array.isArray(inst.history) || !inst.history.length) return null;
  const sorted = [...inst.history].sort((a, b) => String(b.date || "").localeCompare(String(a.date || "")));
  const calc = (key) => {
    if (!sorted.length) return 0;
    const first = toNumber(sorted[0][key]);
    if (first === null || first === 0) return 0;
    const sign = first > 0 ? 1 : -1;
    let count = 0;
    for (const row of sorted) {
      const v = toNumber(row[key]);
      if (v === null || v === 0) break;
      if ((v > 0 ? 1 : -1) !== sign) break;
      count++;
    }
    return count * sign;
  };
  return {
    foreign: calc("foreignNet"),
    trust: calc("trustNet"),
    dealer: calc("dealerNet"),
    total: calc("totalNet")
  };
}

// 投信認養偵測：連續 5 日以上買超視為認養訊號
function detectTrustAdoption(code) {
  const streak = institutionalStreak(code);
  if (!streak) return null;
  if (streak.trust >= 5) {
    const inst = state.institutional[code];
    const history = Array.isArray(inst?.history) ? inst.history : [];
    if (!history.length) return null;
    const recent = history.slice(-streak.trust);
    const totalBuy = recent.reduce((s, r) => s + (toNumber(r.trustNet) || 0), 0);
    return {
      detected: true,
      streak: streak.trust,
      totalBuyLots: totalBuy,
      level: streak.trust >= 10 ? "強烈認養" : streak.trust >= 7 ? "持續認養" : "認養訊號",
      tone: "up"
    };
  }
  return null;
}

// 借券回補偵測：近 5 日 SBL 餘額下降且股價同步上漲
function detectSblCovering(code) {
  const sbl = (state.sbl || {})[code];
  if (!sbl) return null;
  const balanceHistory = Array.isArray(sbl.balanceTrend)
    ? sbl.balanceTrend
    : Array.isArray(sbl.history)
      ? sbl.history
      : null;
  if (!balanceHistory || balanceHistory.length < 5) return null;
  const recent = balanceHistory.slice(-5);
  const oldest = toNumber(recent[0]?.balance ?? recent[0]?.totalBalance);
  const latest = toNumber(recent.at(-1)?.balance ?? recent.at(-1)?.totalBalance);
  if (!oldest || !latest || oldest <= 0) return null;
  const sblChange = (latest - oldest) / oldest;
  if (sblChange >= -0.15) return null;
  // Cross-reference price
  const krows = latestKlines(code);
  if (krows.length < 6) return null;
  const priceOld = krows.at(-6).close;
  const priceNew = krows.at(-1).close;
  if (!priceOld || !priceNew) return null;
  const priceChange = (priceNew - priceOld) / priceOld;
  if (priceChange > 0.02) {
    return {
      detected: true,
      sblChangePct: sblChange * 100,
      priceChangePct: priceChange * 100,
      level: priceChange > 0.05 ? "強烈軋空" : "借券回補",
      tone: "up"
    };
  }
  return null;
}

function chipProxyComponent(label, score, detail, options = {}) {
  const safeScore = Number.isFinite(Number(score)) ? Number(score) : 0;
  return {
    label,
    score: safeScore,
    detail,
    available: options.available !== false,
    source: options.source || "",
    asOf: options.asOf || "",
    rule: options.rule || "",
    proxy: options.proxy || ""
  };
}

function chipProxyComponentClass(component) {
  if (!component?.available) return "flat";
  if (component.score > 0) return "up";
  if (component.score < 0) return "down";
  return "flat";
}

function signalToneClass(signal) {
  if (!signal || !signal.available) return "flat";
  if (signal.tone === "up" || signal.level === "good") return "up";
  if (signal.tone === "down" || signal.level === "danger" || signal.level === "warn") return "down";
  return "flat";
}

function institutionalWindowTotals(code, windowSize = 5) {
  const inst = (state.institutional || {})[code] || null;
  const rows = normalizeInstitutionalHistoryRows([...(Array.isArray(inst?.history) ? inst.history : []), inst].filter(Boolean), INSTITUTIONAL_HISTORY_TARGET_DAYS)
    .filter((row) => toNumber(row.totalNet) !== null || toNumber(row.foreignNet) !== null || toNumber(row.trustNet) !== null || toNumber(row.dealerNet) !== null);
  const sourceRows = rows.slice(-Math.min(windowSize, rows.length));
  const sum = (key) => sourceRows.reduce((total, row) => total + (toNumber(row[key]) || 0), 0);
  return {
    rows: sourceRows,
    allRows: rows,
    obsDays: sourceRows.length,
    firstDate: sourceRows[0]?.date || "",
    lastDate: sourceRows.at(-1)?.date || inst?.date || "",
    totalNet: sum("totalNet"),
    foreignNet: sum("foreignNet"),
    trustNet: sum("trustNet"),
    dealerNet: sum("dealerNet"),
    buyDays: sourceRows.filter((row) => (toNumber(row.totalNet) || 0) > 0).length,
    sellDays: sourceRows.filter((row) => (toNumber(row.totalNet) || 0) < 0).length,
    source: inst?.source || ""
  };
}

function institutionalNetScore(totalNet, avgVolumeLots) {
  const total = toNumber(totalNet) || 0;
  const avgVol = toNumber(avgVolumeLots);
  const intensity = avgVol && avgVol > 0 ? total / avgVol : null;
  if (total >= 5000 || (intensity !== null && intensity >= 3)) return 2;
  if (total >= 1500 || (intensity !== null && intensity >= 1.2)) return 1;
  if (total <= -5000 || (intensity !== null && intensity <= -3)) return -2;
  if (total <= -1500 || (intensity !== null && intensity <= -1.2)) return -1;
  return 0;
}

function tdccWhaleTrend(code) {
  const tdccData = (state.tdcc || {})[code] || null;
  const history = Array.isArray((state.tdccHistory || {})[code]) ? [...state.tdccHistory[code]] : [];
  const latestPct = toNumber(tdccData?.whalePercent);
  if (latestPct !== null && !history.some((row) => row.date === (tdccData?.dataDate || dateKeyInTaipei()))) {
    history.push({ date: tdccData?.dataDate || dateKeyInTaipei(), whalePct: latestPct });
  }
  const rows = history
    .map((row) => ({ date: row.date || "", whalePct: toNumber(row.whalePct) }))
    .filter((row) => row.whalePct !== null)
    .sort((a, b) => String(a.date || "").localeCompare(String(b.date || "")))
    .slice(-6);
  if (!rows.length) {
    return { rows, latestPct, deltaPp: null, label: latestPct === null ? "TDCC 待更新" : `大戶 ${formatPercentMetric(latestPct)}` };
  }
  const first = rows[0];
  const last = rows.at(-1);
  const deltaPp = rows.length >= 2 ? last.whalePct - first.whalePct : null;
  const deltaText = deltaPp !== null ? `${deltaPp >= 0 ? "+" : ""}${deltaPp.toFixed(2)}百分點` : "待累積";
  return {
    rows,
    latestPct: last.whalePct,
    deltaPp,
    first,
    last,
    label: `大戶 ${formatPercentMetric(last.whalePct)}；近${rows.length}筆 ${deltaText}`
  };
}

function bigMoneyPresenceSignal(code, technical = null) {
  const stock = STOCK_MAP.get(code) || { code };
  const liq = stockLiquidityInfo(code);
  const avgVolumeLots = toNumber(liq?.avgVolume);
  const inst5 = institutionalWindowTotals(code, 5);
  const inst10 = institutionalWindowTotals(code, 10);
  const streak = institutionalStreak(code);
  const adoption = detectTrustAdoption(code);
  const foreignTrend = foreignOwnershipTrend(code);
  const tdccTrend = tdccWhaleTrend(code);
  const tdccData = (state.tdcc || {})[code] || null;
  const t = technical?.ready ? technical : calculateTechnical(code);
  const components = [];

  if (inst5.obsDays) {
    const score = institutionalNetScore(inst5.totalNet, avgVolumeLots);
    const streakText = streak?.total > 0 ? `；三大法人 ${streak.total} 連買` : streak?.total < 0 ? `；三大法人 ${-streak.total} 連賣` : "";
    components.push(chipProxyComponent(
      "三大法人",
      score,
      `近${inst5.obsDays}日合計 ${signedLotsText(inst5.totalNet)}${streakText}`,
      { source: inst5.source, asOf: inst5.lastDate, rule: "近5日合計與相對流動性 proxy" }
    ));
  } else {
    components.push(chipProxyComponent("三大法人", 0, "缺三大法人歷史", { available: false, rule: "需 TWSE T86 / TPEx 三大法人日報" }));
  }

  if (inst10.obsDays >= 5) {
    const score = institutionalNetScore(inst10.trustNet, avgVolumeLots);
    const trustScore = adoption ? Math.max(score, adoption.streak >= 10 ? 2 : 1) : score;
    components.push(chipProxyComponent(
      "投信認養",
      trustScore,
      adoption ? `${adoption.level}：${adoption.streak}日，合計 ${signedLotsText(adoption.totalBuyLots)}` : `近${inst10.obsDays}日投信 ${signedLotsText(inst10.trustNet)}`,
      { source: inst10.source, asOf: inst10.lastDate, rule: "投信連買 / 近10日買賣超 proxy" }
    ));
  } else {
    components.push(chipProxyComponent("投信認養", 0, "投信歷史不足", { available: false, rule: "需至少 5 筆法人歷史" }));
  }

  if (foreignTrend?.signal && foreignTrend.signal !== "insufficient") {
    const score = foreignTrend.signal === "accumulation" ? 2 : foreignTrend.signal === "exit" ? (foreignTrend.level === "danger" ? -2 : -1) : 0;
    components.push(chipProxyComponent(
      "外資持股",
      score,
      foreignTrend.text || "外資持股持平",
      { source: foreignTrend.latest?.source || "", asOf: foreignTrend.latest?.date || "", rule: "最近數筆外資持股比率變化" }
    ));
  } else {
    components.push(chipProxyComponent("外資持股", 0, foreignTrend?.text || "缺外資持股歷史", { available: false, rule: "需 MI_QFIIS / TPEx 外資持股歷史" }));
  }

  const whalePct = toNumber(tdccData?.whalePercent ?? tdccTrend.latestPct);
  if (whalePct !== null) {
    let score = whalePct >= 45 ? 1 : whalePct <= 30 ? -1 : 0;
    if (tdccTrend.deltaPp !== null && tdccTrend.deltaPp >= 0.5) score += 1;
    else if (tdccTrend.deltaPp !== null && tdccTrend.deltaPp <= -0.5) score -= 1;
    components.push(chipProxyComponent(
      "TDCC 大戶",
      clamp(score, -2, 2),
      tdccTrend.label,
      { source: tdccData?.source || "TDCC 集保持股分布", asOf: tdccData?.dataDate || tdccTrend.last?.date || "", rule: "持股 ≥400 張級距 proxy；週資料" }
    ));
  } else {
    components.push(chipProxyComponent("TDCC 大戶", 0, "缺 TDCC 集保大戶資料", { available: false, rule: "需 TDCC 股權分散表" }));
  }

  if (t?.ready) {
    const latestClose = toNumber(t.latest?.close);
    let score = 0;
    const details = [];
    if (t.tradingState?.available) {
      if (["riskTriggered", "failedRecovery", "avoid"].includes(t.tradingState.state)) score -= 2;
      else if (["attackCandidate", "reEntryCandidate", "holdWatch"].includes(t.tradingState.state)) score += 1;
      details.push(t.tradingState.label);
    }
    if (t.decisionLayer?.tone === "up") score += 1;
    else if (t.decisionLayer?.tone === "down") score -= 2;
    if (t.largeVolumeDefense?.lowCheck?.status === "breakdown") score -= 2;
    else if (t.largeVolumeDefense?.highCheck?.status === "breakout") score += 1;
    if (latestClose !== null && t.ma20) score += latestClose >= t.ma20 ? 0.5 : -0.5;
    components.push(chipProxyComponent(
      "價格防線",
      clamp(score, -2, 2),
      details.length ? details.join("；") : (t.decisionLayer?.summary || "日線防線中性"),
      { source: "本機日線技術計算", asOf: t.latest?.date || "", rule: "大量K / POC / MA20 / 交易狀態 proxy" }
    ));
  } else {
    components.push(chipProxyComponent("價格防線", 0, "缺日線技術資料", { available: false, rule: "需更新日線" }));
  }

  const available = components.filter((component) => component.available);
  const score = clamp(components.reduce((sum, component) => sum + component.score, 0), -8, 8);
  const marginUsage = toNumber((state.margin || {})[code]?.marginUsagePct);
  const retailTakeover = score <= -3 && marginUsage !== null && marginUsage >= 60;
  let label = "大戶換手觀察";
  let tone = "flat";
  let level = "flat";
  if (!available.length) {
    label = "大戶資料不足";
  } else if (retailTakeover) {
    label = "疑似散戶接手";
    tone = "down";
    level = "danger";
  } else if (score >= 5) {
    label = "大戶仍在場";
    tone = "up";
    level = "good";
  } else if (score >= 2) {
    label = "大戶偏在場";
    tone = "up";
    level = "good";
  } else if (score <= -4) {
    label = "大戶撤退";
    tone = "down";
    level = "danger";
  } else if (score <= -2) {
    label = "大戶轉弱";
    tone = "down";
    level = "warn";
  }
  const leaders = components
    .filter((component) => component.available && component.score !== 0)
    .sort((a, b) => Math.abs(b.score) - Math.abs(a.score))
    .slice(0, 3);
  const confidence = available.length >= 4 ? "medium" : available.length >= 2 ? "low" : "very-low";
  return {
    available: available.length > 0,
    score,
    sortScore: score,
    label,
    tone,
    level,
    confidence,
    components,
    leaders,
    summary: leaders.length ? leaders.map((item) => `${item.label}：${item.detail}`).join("；") : "主要資料不足或中性",
    sourceSummary: available.map((component) => [component.label, component.asOf].filter(Boolean).join(" ")).filter(Boolean).slice(0, 4).join("；"),
    stock
  };
}

function retailSentimentSignal(code, technical = null) {
  const marg = (state.margin || {})[code] || null;
  const quote = quoteFor(code);
  const vol = volumeAnomalyInfo(code);
  const liq = stockLiquidityInfo(code);
  const avgVolumeLots = toNumber(liq?.avgVolume);
  const taifexSummary = futuresSentimentSummary();
  const limitLock = limitLockInfo(STOCK_MAP.get(code) || { code });
  const t = technical?.ready ? technical : calculateTechnical(code);
  const components = [];

  if (marg) {
    const usage = toNumber(marg.marginUsagePct);
    const marginDelta = (toNumber(marg.marginBuy) || 0) - (toNumber(marg.marginSell) || 0);
    const deltaIntensity = avgVolumeLots && avgVolumeLots > 0 ? marginDelta / avgVolumeLots : null;
    let usageScore = 0;
    if (usage !== null && usage >= 80) usageScore = 3;
    else if (usage !== null && usage >= 60) usageScore = 2;
    else if (usage !== null && usage <= 20) usageScore = -1;
    components.push(chipProxyComponent(
      "融資使用率",
      usageScore,
      usage !== null ? `融資 ${formatPercentMetric(usage)}` : "融資使用率缺值",
      { source: marg.source || "", asOf: marg.date || "", rule: "散戶槓桿擁擠 proxy" }
    ));
    let deltaScore = 0;
    if (marginDelta >= 1000 || (deltaIntensity !== null && deltaIntensity >= 0.25)) deltaScore = 1;
    else if (marginDelta <= -1000 || (deltaIntensity !== null && deltaIntensity <= -0.25)) deltaScore = -1;
    components.push(chipProxyComponent(
      "融資增減",
      deltaScore,
      `當日融資淨變化 ${signedLotsText(marginDelta)}${deltaIntensity !== null ? `，約日均 ${formatNumber(deltaIntensity * 100, 0)}%` : ""}`,
      { source: marg.source || "", asOf: marg.date || "", rule: "融資買進 - 融資賣出" }
    ));
    const shortRatio = (toNumber(marg.marginBalance) || 0) > 0 ? (toNumber(marg.shortBalance) || 0) / (toNumber(marg.marginBalance) || 1) * 100 : null;
    if (shortRatio !== null && shortRatio >= 40) {
      components.push(chipProxyComponent(
        "券資比",
        -1,
        `券資比 ${formatPercentMetric(shortRatio)}，空方擁擠 / 軋空燃料`,
        { source: marg.source || "", asOf: marg.date || "", rule: "融券餘額 ÷ 融資餘額" }
      ));
    }
  } else {
    components.push(chipProxyComponent("融資融券", 0, "缺融資融券資料", { available: false, rule: "需 TWSE / TPEx 融資融券" }));
  }

  if (taifexSummary?.retailProxy !== null && taifexSummary?.retailProxy !== undefined) {
    const value = toNumber(taifexSummary.retailProxy);
    const score = value >= 3000 ? 2 : value >= 1000 ? 1 : value <= -3000 ? -1 : 0;
    components.push(chipProxyComponent(
      "小微台 proxy",
      score,
      `${taifexSummary.retailDirection} ${formatNumber(value, 0)} 口`,
      { source: "TAIFEX 三大法人期貨未平倉", asOf: taifexSummary.sourceDate || "", rule: "小台 / 微台非法人代理；非官方散戶分類" }
    ));
  } else {
    components.push(chipProxyComponent("小微台 proxy", 0, "期貨散戶 proxy 待更新", { available: false, rule: "需更新 TAIFEX 期貨水位" }));
  }

  if (vol) {
    const pct = toNumber(quote?.pct);
    const priceHot = pct !== null && Math.abs(pct) >= 3;
    const score = vol.zScore >= 2 && priceHot ? 1 : 0;
    const direction = vol.bullish ? "追價放量" : "殺低放量";
    components.push(chipProxyComponent(
      "量價情緒",
      score,
      `${direction}：${vol.zScore.toFixed(1)}σ，量能×${vol.ratio.toFixed(1)}${pct !== null ? `，今日 ${formatPct(pct)}` : ""}`,
      { source: "本機日線 / 報價", asOf: vol.date || t?.latest?.date || "", rule: "放量 + 單日漲跌 proxy" }
    ));
  }

  if (limitLock.available && limitLock.status !== "none") {
    const score = limitLock.side === "up" ? 1 : 2;
    components.push(chipProxyComponent(
      "漲跌停情緒",
      score,
      `${limitLock.label}${limitLock.ratioPct !== null ? ` ${formatPercentMetric(limitLock.ratioPct, 3)}` : ""}`,
      { source: limitLock.source || "", asOf: quote?.sourceDate || "", rule: "五檔鎖單情緒 proxy" }
    ));
  }

  const available = components.filter((component) => component.available);
  const heatScore = clamp(components.reduce((sum, component) => sum + Math.max(0, component.score), 0), 0, 10);
  const coolScore = components.reduce((sum, component) => sum + Math.min(0, component.score), 0);
  let label = "散戶情緒中性";
  let tone = "flat";
  let level = "flat";
  if (!available.length) {
    label = "散戶資料不足";
  } else if (heatScore >= 5) {
    label = "散戶槓桿過熱";
    tone = "down";
    level = "danger";
  } else if (heatScore >= 3) {
    label = "散戶偏熱";
    tone = "down";
    level = "warn";
  } else if (heatScore >= 1) {
    label = "情緒升溫";
  } else if (coolScore <= -2) {
    label = "散戶偏冷";
    tone = "up";
    level = "good";
  }
  const leaders = components
    .filter((component) => component.available && component.score !== 0)
    .sort((a, b) => Math.abs(b.score) - Math.abs(a.score))
    .slice(0, 3);
  return {
    available: available.length > 0,
    heatScore,
    coolScore,
    sortScore: heatScore,
    label,
    tone,
    level,
    components,
    leaders,
    summary: leaders.length ? leaders.map((item) => `${item.label}：${item.detail}`).join("；") : "散戶槓桿與情緒 proxy 中性",
    sourceSummary: available.map((component) => [component.label, component.asOf].filter(Boolean).join(" ")).filter(Boolean).slice(0, 4).join("；"),
    confidence: available.length >= 3 ? "medium" : available.length >= 2 ? "low" : "very-low"
  };
}

function stockHeatFactor(label, points, detail, options = {}) {
  const safePoints = Number.isFinite(Number(points)) ? Number(points) : 0;
  return {
    label,
    points: safePoints,
    detail,
    bucket: options.bucket || "technical",
    tone: options.tone || "neutral",
    source: options.source || "",
    asOf: options.asOf || "",
    available: options.available !== false
  };
}

function stockHeatLevel(heatScore, deepScore, context = {}) {
  const repairCandidate = context.repairCandidate === true;
  if (heatScore >= 70) {
    return {
      key: "hot-danger",
      label: "高度過熱",
      badge: "過熱",
      tone: "hot",
      action: "追價風險高，先看量價是否失速與籌碼是否轉弱"
    };
  }
  if (heatScore >= 50) {
    return {
      key: "hot-warn",
      label: "過熱追價風險",
      badge: "偏熱",
      tone: "warm",
      action: "偏熱區，適合檢查停利、壓力與法人是否退場"
    };
  }
  if (deepScore >= 70) {
    return {
      key: "deep-danger",
      label: repairCandidate ? "深跌修復觀察" : "深跌超賣",
      badge: repairCandidate ? "修復" : "超賣",
      tone: repairCandidate ? "repair" : "deep",
      action: repairCandidate ? "低檔正在修復，仍要等收復關鍵價位確認" : "深跌區，不等於買點，先看止跌與量縮"
    };
  }
  if (deepScore >= 50) {
    return {
      key: "deep-watch",
      label: repairCandidate ? "低檔修復候選" : "超賣待修復",
      badge: repairCandidate ? "修復" : "偏冷",
      tone: repairCandidate ? "repair" : "deep",
      action: repairCandidate ? "可列入低檔修復追蹤，重點看站回月線 / 大量低" : "偏冷區，等待止跌、量縮或收復訊號"
    };
  }
  return {
    key: "neutral",
    label: "中性",
    badge: "中性",
    tone: "neutral",
    action: "尚未出現明顯過熱或深跌超賣"
  };
}

function buildStockHeatSignal(code, technical = null, options = {}) {
  const t = technical?.ready ? technical : calculateTechnical(code);
  if (!t?.ready) {
    return {
      available: false,
      heatScore: 0,
      deepScore: 0,
      netScore: 0,
      level: stockHeatLevel(0, 0),
      drivers: [],
      heatDrivers: [],
      deepDrivers: [],
      missing: ["日線資料不足"],
      sourceSummary: "",
      confidence: "very-low",
      summary: t?.message || "尚未抓取足夠日線資料"
    };
  }

  const quote = quoteFor(code);
  const close = toNumber(quote?.price ?? t.latest?.close);
  const changePct = toNumber(quote?.pct ?? t.changePct);
  const rsi14 = toNumber(t.rsi14);
  const volumeRatio = toNumber(t.volumeRatio);
  const bias20 = toNumber(t.bias20);
  const bbRange = t.bbUpper !== null && t.bbLower !== null ? t.bbUpper - t.bbLower : null;
  const bbPosition = close !== null && bbRange && bbRange > 0
    ? (close - t.bbLower) / bbRange * 100
    : null;
  const oscillator = t.oscillatorChecklist || null;
  const kd = oscillator?.kd || null;
  const recovery = t.recoverySignal || null;
  const tradingState = t.tradingState || null;
  const largeDefense = t.largeVolumeDefense || null;
  const chip = stockChipSignal(code);
  const bigMoney = options.bigMoney || bigMoneyPresenceSignal(code, t);
  const retail = options.retail || retailSentimentSignal(code, t);
  const marginUsage = toNumber((state.margin || {})[code]?.marginUsagePct);
  const date = t.latest?.date || quote?.sourceDate || "";
  const heatFactors = [];
  const deepFactors = [];
  const missing = [];

  const addHeat = (label, points, detail, options = {}) => {
    if (points > 0) heatFactors.push(stockHeatFactor(label, points, detail, { ...options, tone: options.tone || "hot" }));
  };
  const addDeep = (label, points, detail, options = {}) => {
    if (points > 0) deepFactors.push(stockHeatFactor(label, points, detail, { ...options, tone: options.tone || "deep" }));
  };

  if (rsi14 !== null) {
    if (rsi14 >= 82) addHeat("RSI 極熱", 18, `RSI14 ${formatNumber(rsi14, 1)} 已高於 82`, { source: "本機日線技術計算", asOf: date });
    else if (rsi14 >= 75) addHeat("RSI 過熱", 14, `RSI14 ${formatNumber(rsi14, 1)} 高於 75`, { source: "本機日線技術計算", asOf: date });
    else if (rsi14 >= 70) addHeat("RSI 偏熱", 10, `RSI14 ${formatNumber(rsi14, 1)} 高於常見過熱參考 70`, { source: "本機日線技術計算", asOf: date });
    if (rsi14 <= 20) addDeep("RSI 極冷", 18, `RSI14 ${formatNumber(rsi14, 1)} 低於 20`, { source: "本機日線技術計算", asOf: date });
    else if (rsi14 <= 30) addDeep("RSI 超賣", 14, `RSI14 ${formatNumber(rsi14, 1)} 低於常見超賣參考 30`, { source: "本機日線技術計算", asOf: date });
    else if (rsi14 <= 35) addDeep("RSI 偏冷", 8, `RSI14 ${formatNumber(rsi14, 1)} 低於 35`, { source: "本機日線技術計算", asOf: date });
  } else {
    missing.push("RSI14");
  }

  if (bbPosition !== null) {
    if (bbPosition >= 112) addHeat("布林上緣外", 14, `收盤位於布林區間 ${formatNumber(bbPosition, 1)}%`, { source: "本機日線技術計算", asOf: date });
    else if (bbPosition >= 90) addHeat("貼近布林上緣", 8, `收盤位於布林區間 ${formatNumber(bbPosition, 1)}%`, { source: "本機日線技術計算", asOf: date });
    if (bbPosition <= -12) addDeep("布林下緣外", 14, `收盤位於布林區間 ${formatNumber(bbPosition, 1)}%`, { source: "本機日線技術計算", asOf: date });
    else if (bbPosition <= 10) addDeep("貼近布林下緣", 8, `收盤位於布林區間 ${formatNumber(bbPosition, 1)}%`, { source: "本機日線技術計算", asOf: date });
  } else {
    missing.push("布林位置");
  }

  if (bias20 !== null) {
    const biasStudy = t.biasStudy || null;
    const percentileText = biasStudy?.directionPercentile !== null && biasStudy?.directionPercentile !== undefined
      ? `，自身歷史 ${formatNumber(biasStudy.directionPercentile, 0)}%ile`
      : "";
    if (bias20 > 0 && biasStudy?.enough && (biasStudy.positivePercentile ?? 0) >= 95) {
      addHeat("自身歷史極高乖離", 15, `收盤高於 MA20 ${formatPct(bias20)}${percentileText}`, { source: "本機日線 MA20 乖離分位", asOf: date });
    } else if (bias20 > 0 && biasStudy?.enough && (biasStudy.positivePercentile ?? 0) >= 90) {
      addHeat("自身歷史高乖離", 11, `收盤高於 MA20 ${formatPct(bias20)}${percentileText}`, { source: "本機日線 MA20 乖離分位", asOf: date });
    } else if (bias20 >= 12) {
      addHeat("月線乖離過大", 10, `收盤高於 MA20 ${formatPct(bias20)}`, { source: "本機日線技術計算", asOf: date });
    } else if (bias20 >= 8) {
      addHeat("月線乖離偏高", 7, `收盤高於 MA20 ${formatPct(bias20)}`, { source: "本機日線技術計算", asOf: date });
    } else if (bias20 >= 5) {
      addHeat("月線乖離升溫", 4, `收盤高於 MA20 ${formatPct(bias20)}`, { source: "本機日線技術計算", asOf: date });
    }
    if (bias20 < 0 && biasStudy?.enough && (biasStudy.negativePercentile ?? 0) >= 95) {
      addDeep("自身歷史極深負乖離", 15, `收盤低於 MA20 ${formatPct(Math.abs(bias20))}${percentileText}`, { source: "本機日線 MA20 乖離分位", asOf: date });
    } else if (bias20 < 0 && biasStudy?.enough && (biasStudy.negativePercentile ?? 0) >= 90) {
      addDeep("自身歷史深負乖離", 11, `收盤低於 MA20 ${formatPct(Math.abs(bias20))}${percentileText}`, { source: "本機日線 MA20 乖離分位", asOf: date });
    } else if (bias20 <= -12) {
      addDeep("月線負乖離過大", 10, `收盤低於 MA20 ${formatPct(Math.abs(bias20))}`, { source: "本機日線技術計算", asOf: date });
    } else if (bias20 <= -8) {
      addDeep("月線負乖離偏大", 7, `收盤低於 MA20 ${formatPct(Math.abs(bias20))}`, { source: "本機日線技術計算", asOf: date });
    } else if (bias20 <= -5) {
      addDeep("月線負乖離", 4, `收盤低於 MA20 ${formatPct(Math.abs(bias20))}`, { source: "本機日線技術計算", asOf: date });
    }
  } else {
    missing.push("MA20 乖離");
  }

  const addLongMaBiasFactor = (entry) => {
    if (!entry?.available) {
      missing.push(`${entry?.label || "長天期均線"} 乖離`);
      return;
    }
    if (![60, 240].includes(Number(entry.period))) return;
    const percentileText = entry.directionPercentile !== null && entry.directionPercentile !== undefined
      ? `，自身歷史 ${formatNumber(entry.directionPercentile, 0)}%ile`
      : entry.enough ? "" : `，樣本 ${formatNumber(entry.observationDays, 0)} 筆`;
    const detail = `${entry.label} 乖離 ${formatSignedMetric(entry.currentBias, 1, "%")}${percentileText}；${entry.level?.action || "需搭配量價與籌碼複核"}`;
    const source = entry.source || "本機日線均線乖離序列";
    const heatPoints = maBiasProfilePoints(entry, "heat");
    const deepPoints = maBiasProfilePoints(entry, "deep");
    if (heatPoints > 0) {
      addHeat(entry.level?.key === "sample-low" ? `${entry.shortLabel}正乖離` : entry.level.label, heatPoints, detail, { source, asOf: entry.lastDate });
    }
    if (deepPoints > 0) {
      addDeep(entry.level?.key === "sample-low" ? `${entry.shortLabel}負乖離` : entry.level.label, deepPoints, detail, { source, asOf: entry.lastDate });
    }
  };
  addLongMaBiasFactor(maBiasProfilePeriod(t.maBiasProfile, 60));
  addLongMaBiasFactor(maBiasProfilePeriod(t.maBiasProfile, 240));

  if (volumeRatio !== null && changePct !== null) {
    if (volumeRatio >= 2 && changePct > 0) addHeat("放量上漲", 8, `量能 ${formatNumber(volumeRatio, 2)}x，漲跌幅 ${formatPct(changePct)}`, { source: "本機日線 / 報價", asOf: date });
    else if (volumeRatio >= 1.5 && changePct > 0) addHeat("量價升溫", 5, `量能 ${formatNumber(volumeRatio, 2)}x，漲跌幅 ${formatPct(changePct)}`, { source: "本機日線 / 報價", asOf: date });
    if (volumeRatio >= 1.8 && changePct < 0) addDeep("放量下跌", 8, `量能 ${formatNumber(volumeRatio, 2)}x，漲跌幅 ${formatPct(changePct)}`, { source: "本機日線 / 報價", asOf: date });
  } else {
    missing.push("量價");
  }

  if (changePct !== null) {
    if (changePct >= 5) addHeat("單日急漲", 8, `漲跌幅 ${formatPct(changePct)}`, { source: quote?.source || "本機日線 / 報價", asOf: quote?.sourceDate || date });
    else if (changePct >= 3) addHeat("單日強彈", 5, `漲跌幅 ${formatPct(changePct)}`, { source: quote?.source || "本機日線 / 報價", asOf: quote?.sourceDate || date });
    if (changePct <= -5) addDeep("單日急跌", 8, `漲跌幅 ${formatPct(changePct)}`, { source: quote?.source || "本機日線 / 報價", asOf: quote?.sourceDate || date });
    else if (changePct <= -3) addDeep("單日重跌", 5, `漲跌幅 ${formatPct(changePct)}`, { source: quote?.source || "本機日線 / 報價", asOf: quote?.sourceDate || date });
  }

  if (kd?.k !== null && kd?.d !== null) {
    if (kd.k >= 80 && kd.d >= 80) addHeat("KD 高檔", oscillator?.tone === "down" ? 8 : 5, `KD ${formatNumber(kd.k, 1)} / ${formatNumber(kd.d, 1)}；${oscillator?.kdSignal || "高檔鈍化觀察"}`, { source: "本機日線技術計算", asOf: date });
    if (kd.k <= 20 && kd.d <= 20) addDeep("KD 低檔", oscillator?.tone === "up" ? 5 : 8, `KD ${formatNumber(kd.k, 1)} / ${formatNumber(kd.d, 1)}；${oscillator?.kdSignal || "低檔鈍化觀察"}`, { source: "本機日線技術計算", asOf: date });
  }

  if (largeDefense?.available) {
    if (largeDefense.highCheck?.status === "nearHigh" || largeDefense.highCheck?.status === "breakout") {
      addHeat("接近大量高", largeDefense.highCheck.status === "breakout" ? 7 : 4, largeDefense.highCheck.detail || largeDefense.summary || "大量高附近", { source: "本機日線技術計算", asOf: date });
    }
    if (largeDefense.lowCheck?.status === "breakdown") {
      addDeep("跌破大量低", 9, largeDefense.lowCheck.detail || largeDefense.summary || "大量低失守", { source: "本機日線技術計算", asOf: date });
    }
  }

  const repairCandidate = recovery?.available && ["reclaimedLow", "reclaimedHalf", "reclaimedHigh"].includes(recovery.status)
    || tradingState?.available && ["earlyRecovery", "reEntryCandidate"].includes(tradingState.state);
  if (recovery?.available && ["failedRetest", "unrecovered"].includes(recovery.status)) {
    addDeep("失守未修復", 8, recovery.summary || recovery.label, { source: "本機日線技術計算", asOf: date });
  } else if (repairCandidate) {
    addDeep("低檔修復", 5, recovery?.summary || tradingState?.label || "修復候選", { source: "本機日線技術計算", asOf: date, tone: "repair" });
  }

  if (retail?.available) {
    if (retail.heatScore >= 5) addHeat("散戶槓桿過熱", 14, retail.summary, { bucket: "chip", source: retail.sourceSummary, tone: "hot" });
    else if (retail.heatScore >= 3) addHeat("散戶偏熱", 10, retail.summary, { bucket: "chip", source: retail.sourceSummary, tone: "hot" });
    else if (retail.heatScore >= 1) addHeat("情緒升溫", 5, retail.summary, { bucket: "chip", source: retail.sourceSummary, tone: "warm" });
    if (retail.coolScore <= -2) addDeep("散戶偏冷", 5, retail.summary, { bucket: "chip", source: retail.sourceSummary, tone: "deep" });
  } else {
    missing.push("散戶情緒");
  }

  if (bigMoney?.available) {
    if (bigMoney.score <= -4 && (heatFactors.length || changePct > 0)) {
      addHeat("大戶退場分歧", 12, bigMoney.summary, { bucket: "chip", source: bigMoney.sourceSummary, tone: "hot" });
    } else if (bigMoney.score <= -2 && (heatFactors.length || changePct > 0)) {
      addHeat("大戶轉弱", 7, bigMoney.summary, { bucket: "chip", source: bigMoney.sourceSummary, tone: "hot" });
    }
    if (bigMoney.score >= 4 && deepFactors.length) {
      addDeep("低檔大戶仍在", 6, bigMoney.summary, { bucket: "chip", source: bigMoney.sourceSummary, tone: "repair" });
    }
  } else {
    missing.push("大戶在場");
  }

  if (chip?.level === "danger" && heatFactors.length) {
    addHeat("Chip Score 轉弱", 8, chip.text || "籌碼轉弱", { bucket: "chip", source: chip.source || "", tone: "hot" });
  } else if (chip?.level === "good" && deepFactors.length) {
    addDeep("Chip Score 支撐", 5, chip.text || "籌碼偏多", { bucket: "chip", source: chip.source || "", tone: "repair" });
  }

  if (marginUsage !== null) {
    if (marginUsage >= 80) addHeat("融資高度擁擠", 10, `融資使用率 ${formatPercentMetric(marginUsage)}`, { bucket: "chip", source: (state.margin || {})[code]?.source || "", asOf: (state.margin || {})[code]?.date || "" });
    else if (marginUsage >= 60) addHeat("融資偏高", 6, `融資使用率 ${formatPercentMetric(marginUsage)}`, { bucket: "chip", source: (state.margin || {})[code]?.source || "", asOf: (state.margin || {})[code]?.date || "" });
  } else {
    missing.push("融資使用率");
  }

  const heatScore = clamp(heatFactors.reduce((sum, factor) => sum + factor.points, 0), 0, 100);
  const deepScore = clamp(deepFactors.reduce((sum, factor) => sum + factor.points, 0), 0, 100);
  const level = stockHeatLevel(heatScore, deepScore, { repairCandidate });
  const dominant = heatScore >= deepScore ? "heat" : "deep";
  const primaryDrivers = (dominant === "heat" ? heatFactors : deepFactors)
    .slice()
    .sort((left, right) => right.points - left.points)
    .slice(0, 4);
  const secondaryDrivers = (dominant === "heat" ? deepFactors : heatFactors)
    .slice()
    .sort((left, right) => right.points - left.points)
    .slice(0, 2);
  const driverLabels = primaryDrivers.map((driver) => driver.label).join("、");
  const availableSources = [
    t.latest?.source ? `日線 ${t.latest.source}${date ? ` ${date}` : ""}` : "",
    t.maBiasProfile?.source ? `乖離 ${t.maBiasProfile.summary}` : "",
    quote?.source ? `報價 ${quote.source}${quote.sourceDate ? ` ${quote.sourceDate}` : ""}` : "",
    bigMoney?.sourceSummary ? `大戶 ${bigMoney.sourceSummary}` : "",
    retail?.sourceSummary ? `散戶 ${retail.sourceSummary}` : ""
  ].filter(Boolean);
  const confidence = availableSources.length >= 3 && missing.length <= 2 ? "medium" : availableSources.length >= 2 ? "low" : "very-low";

  return {
    available: true,
    heatScore,
    deepScore,
    netScore: heatScore - deepScore,
    dominant,
    level,
    drivers: [...primaryDrivers, ...secondaryDrivers],
    heatDrivers: heatFactors.slice().sort((left, right) => right.points - left.points),
    deepDrivers: deepFactors.slice().sort((left, right) => right.points - left.points),
    missing,
    repairCandidate,
    bbPosition,
    bias20,
    confidence,
    sourceSummary: availableSources.slice(0, 4).join("；"),
    summary: driverLabels ? `${level.label}：${driverLabels}` : level.label
  };
}

function stockHeatChipHtml(signal, options = {}) {
  const compact = options.compact === true;
  if (!signal?.available) {
    return `<span class="stock-heat-chip neutral">${compact ? "熱度 -" : "個股熱度資料不足"}</span>`;
  }
  const cls = signal.level?.tone || "neutral";
  const label = compact ? signal.level.badge : `${signal.level.label} H${formatNumber(signal.heatScore, 0)} / D${formatNumber(signal.deepScore, 0)}`;
  const title = [
    signal.summary,
    signal.sourceSummary ? `來源：${signal.sourceSummary}` : "",
    signal.missing?.length ? `缺資料：${signal.missing.slice(0, 3).join("、")}` : ""
  ].filter(Boolean).join("｜");
  return `<span class="stock-heat-chip ${escapeHtml(cls)}" title="${escapeHtml(title)}">${escapeHtml(label)}</span>`;
}

function renderStockHeatDriverList(drivers, emptyText) {
  if (!Array.isArray(drivers) || !drivers.length) {
    return `<div class="empty" style="padding:8px;">${escapeHtml(emptyText)}</div>`;
  }
  return drivers.slice(0, 5).map((driver) => `
    <div class="stock-heat-driver ${escapeHtml(driver.tone || "neutral")}">
      <div>
        <span>${escapeHtml(driver.label)}</span>
        <strong>${formatNumber(driver.points, 0)} 分</strong>
      </div>
      <p>${escapeHtml(driver.detail || "")}</p>
      ${driver.source || driver.asOf ? `<small>${escapeHtml([driver.source, driver.asOf].filter(Boolean).join(" · "))}</small>` : ""}
    </div>
  `).join("");
}

function renderStockHeatDetailPanel(stock, technical = null) {
  if (!stock) return "";
  const signal = buildStockHeatSignal(stock.code, technical);
  if (!signal.available) {
    return `
      <div class="report-card stock-heat-panel" style="grid-column:1/-1;">
        <h3>個股過熱 / 深跌超賣</h3>
        <div class="empty">${escapeHtml(signal.summary || "日線資料不足。")}</div>
      </div>
    `;
  }
  const missingText = signal.missing.length ? `缺資料：${signal.missing.slice(0, 5).join("、")}` : "核心資料可用";
  return `
    <div class="report-card stock-heat-panel ${escapeHtml(signal.level.tone)}" style="grid-column:1/-1;">
      <div class="stock-heat-head">
        <div>
          <h3>個股過熱 / 深跌超賣：${escapeHtml(stock.name)} ${escapeHtml(stock.code)}</h3>
          <p class="snapshot-trend-note">${escapeHtml(signal.level.action)}。此為工具內研究 proxy，不是買賣建議。</p>
        </div>
        <div class="stock-heat-score-pair">
          <div><span>過熱</span><strong>${formatNumber(signal.heatScore, 0)}</strong></div>
          <div><span>深跌</span><strong>${formatNumber(signal.deepScore, 0)}</strong></div>
        </div>
      </div>
      <div class="stock-heat-meter-row">
        <div>
          <span>過熱</span>
          <i class="stock-heat-meter hot"><b style="width:${clamp(signal.heatScore, 0, 100)}%;"></b></i>
        </div>
        <div>
          <span>深跌 / 超賣</span>
          <i class="stock-heat-meter deep"><b style="width:${clamp(signal.deepScore, 0, 100)}%;"></b></i>
        </div>
      </div>
      <div class="stock-heat-driver-grid">
        <div>
          <h4>升溫 / 過熱因子</h4>
          ${renderStockHeatDriverList(signal.heatDrivers, "目前沒有明顯過熱因子。")}
        </div>
        <div>
          <h4>深跌 / 修復因子</h4>
          ${renderStockHeatDriverList(signal.deepDrivers, "目前沒有明顯深跌因子。")}
        </div>
      </div>
      <p class="snapshot-trend-note" style="margin-top:10px;">來源：${escapeHtml(signal.sourceSummary || "本機日線與籌碼快取")}；信心 ${escapeHtml(signal.confidence)}；${escapeHtml(missingText)}。RSI / 布林 / KD 門檻是常見技術分析參考，需搭配趨勢、量價與官方籌碼資料複核。</p>
    </div>
  `;
}

function playbookTrendRank(playbook) {
  if (!playbook) return -2;
  if (playbook.trendLabel === "多頭趨勢") return 3;
  if (playbook.trendLabel === "盤整趨勢") return 1;
  return -2;
}

function playbookPositionRank(playbook) {
  if (!playbook) return -2;
  const ranks = {
    "回後買上漲 / 攻擊段": 5,
    "盤整突破候選": 4,
    "多頭回檔": 3,
    "多頭行進間": 2,
    "盤整等待": 1,
    "區間震盪": 0,
    "多頭高檔 / 壓力前": -1,
    "空頭低檔 / 反彈區": -2,
    "空頭反彈或續跌": -3,
    "盤整跌破候選": -4,
    "彈後空下跌 / 主跌段": -5
  };
  return ranks[playbook.positionLabel] ?? 0;
}

function playbookSortScore(technical) {
  if (!technical || !technical.ready || !technical.playbook) return Number.NEGATIVE_INFINITY;
  const playbook = technical.playbook;
  const volumeBoost = ["攻擊量", "爆大量 / 換手候選"].includes(playbook.volumeLabel) ? 1 : 0;
  const volumeDefense = playbook.volumeDefense || technical.largeVolumeDefense;
  const decisionLayer = playbook.decisionLayer || technical.decisionLayer;
  const recovery = playbook.recoverySignal || technical.recoverySignal || decisionLayer?.recoverySignal;
  const oscillator = playbook.oscillatorChecklist || technical.oscillatorChecklist || decisionLayer?.oscillatorChecklist;
  const defenseBoost = volumeDefense?.lowCheck?.status === "breakdown" ? -5
    : volumeDefense?.highCheck?.status === "breakout" ? 3
      : volumeDefense?.lowCheck?.status === "test" ? 1
        : 0;
  const decisionBoost = decisionLayer?.tone === "up" ? 4
    : decisionLayer?.tone === "down" ? -8
      : decisionLayer?.pocCheck?.status === "above" ? 1
        : 0;
  const recoveryBoost = ["reclaimedHalf", "reclaimedHigh"].includes(recovery?.status) ? 4
    : recovery?.status === "reclaimedLow" ? 2
      : ["failedRetest", "unrecovered"].includes(recovery?.status) ? -7
        : 0;
  const oscillatorBoost = oscillator?.tone === "up" ? 2
    : oscillator?.tone === "down" ? -3
      : 0;
  return playbook.checklistPasses * 100
    + playbookTrendRank(playbook) * 10
    + playbookPositionRank(playbook)
    + volumeBoost
    + defenseBoost
    + decisionBoost
    + recoveryBoost
    + oscillatorBoost;
}

function playbookRankLabel(playbook) {
  if (!playbook) return "-";
  return `${playbook.checklistPasses}/${playbook.checklist.length} · ${playbook.positionLabel}`;
}

// 依趨勢方向（非今日漲跌）決定顏色 class
function trendColorClass(technical) {
  if (!technical || !technical.ready) return "flat";
  if (technical.playbook) {
    const label = technical.playbook.trendLabel || "";
    if (label === "多頭趨勢") return "up";
    if (label === "空頭趨勢") return "down";
    return "flat";
  }
  // fallback: use technical score
  if (technical.score >= 4) return "up";
  if (technical.score <= 0) return "down";
  return "flat";
}

function snapshotMoment(snapshot) {
  return new Date(snapshot.capturedAt || snapshot.sourceDate || 0).getTime();
}

function pruneSnapshots() {
  const cutoff = Date.now() - SNAPSHOT_RETENTION_DAYS * ONE_DAY_MS;
  for (const code of Object.keys(state.snapshots)) {
    state.snapshots[code] = (state.snapshots[code] || []).filter((snapshot) => {
      const moment = snapshotMoment(snapshot);
      return !moment || moment >= cutoff;
    });
  }
  for (const code of Object.keys(state.klines || {})) {
    state.klines[code] = compactKlineRows(state.klines[code] || []);
  }
}

function storeSnapshot(quote) {
  if (!quote || !quote.code) return;
  const code = quote.code;
  const key = quote.sourceDate || todayKey();
  const rows = Array.isArray(state.snapshots[code]) ? state.snapshots[code] : [];
  const filtered = rows.filter((row) => row.sourceDate !== key);
  filtered.push({ ...quote });
  filtered.sort((a, b) => snapshotMoment(b) - snapshotMoment(a));
  state.snapshots[code] = filtered.slice(0, 220);
  pruneSnapshots();
}

function latestSnapshot(code) {
  const rows = state.snapshots[code] || [];
  return rows.length ? rows[0] : null;
}

function previousSnapshot(code) {
  const rows = state.snapshots[code] || [];
  return rows.length > 1 ? rows[1] : null;
}

function snapshotRowsForStock(code) {
  return [...(state.snapshots[code] || [])]
    .sort((a, b) => snapshotMoment(a) - snapshotMoment(b))
    .map((snapshot) => ({
      ...snapshot,
      price: toNumber(snapshot.price),
      pct: toNumber(snapshot.pct),
      volume: toNumber(snapshot.volume)
    }))
    .filter((snapshot) => snapshot.price !== null);
}

function snapshotTrendSignal(pricePct) {
  const number = toNumber(pricePct);
  if (number === null) return "資料不足";
  if (number >= 6) return "區間走升";
  if (number <= -6) return "區間走弱";
  if (number >= 1) return "緩步墊高";
  if (number <= -1) return "高檔回落";
  return "區間盤整";
}

function summarizeSnapshotTrend(stock, maxPoints = state.snapshotTrendWindow) {
  const rows = snapshotRowsForStock(stock.code);
  if (!rows.length) return null;
  const windowSize = normalizeSnapshotTrendWindow(maxPoints);
  const windowRows = rows.slice(-windowSize);
  const latest = windowRows.at(-1);
  const start = windowRows[0];
  const priceDelta = start && latest ? latest.price - start.price : null;
  const pricePct = start && latest && start.price
    ? (latest.price - start.price) / start.price * 100
    : null;
  const volumes = windowRows.map((row) => row.volume).filter((value) => Number.isFinite(value));
  const avgVolume = volumes.length ? average(volumes) : null;
  const volumePct = avgVolume && latest && latest.volume !== null
    ? (latest.volume - avgVolume) / avgVolume * 100
    : null;
  const spanDays = start && latest
    ? Math.max(0, Math.round((snapshotMoment(latest) - snapshotMoment(start)) / ONE_DAY_MS))
    : 0;

  return {
    stock,
    rows,
    windowRows,
    latest,
    start,
    observationCount: windowRows.length,
    priceDelta,
    pricePct,
    avgVolume,
    latestVolume: latest ? latest.volume : null,
    volumePct,
    latestPct: latest ? latest.pct : null,
    spanDays,
    spanLabel: spanDays > 0 ? `${spanDays} 天` : "同日",
    signal: snapshotTrendSignal(pricePct)
  };
}

function summarizeSnapshotThemeTrend(stocks, maxPoints = state.snapshotTrendWindow) {
  const entries = stocks
    .map((stock) => ({ stock, trend: summarizeSnapshotTrend(stock, maxPoints) }))
    .filter((entry) => entry.trend);
  if (!entries.length) return null;

  const pctSeries = entries
    .map((entry) => entry.trend.pricePct)
    .filter((value) => Number.isFinite(value));
  const avgTrend = pctSeries.length ? average(pctSeries) : null;
  const strongest = entries.reduce((best, entry) => {
    if (!best) return entry;
    if ((entry.trend.pricePct ?? Number.NEGATIVE_INFINITY) > (best.trend.pricePct ?? Number.NEGATIVE_INFINITY)) return entry;
    return best;
  }, null);
  const weakest = entries.reduce((best, entry) => {
    if (!best) return entry;
    if ((entry.trend.pricePct ?? Number.POSITIVE_INFINITY) < (best.trend.pricePct ?? Number.POSITIVE_INFINITY)) return entry;
    return best;
  }, null);
  const rising = entries.filter((entry) => (entry.trend.pricePct ?? 0) >= 1).length;
  const falling = entries.filter((entry) => (entry.trend.pricePct ?? 0) <= -1).length;

  return {
    entries,
    avgTrend,
    strongest,
    weakest,
    rising,
    falling,
    flat: entries.length - rising - falling
  };
}

const THEME_CHIP_TREND_WINDOW = 14;

function signedLotsText(value) {
  const number = toNumber(value);
  if (number === null) return "-";
  return `${number >= 0 ? "+" : ""}${formatNumber(number, 0)} 張`;
}

function institutionalTrendForStock(stock, windowSize = THEME_CHIP_TREND_WINDOW) {
  const inst = (state.institutional || {})[stock.code] || null;
  const baseRows = Array.isArray(inst?.history) ? inst.history : [];
  const rows = normalizeInstitutionalHistoryRows([...baseRows, inst].filter(Boolean), windowSize)
    .filter((row) => toNumber(row.totalNet) !== null || toNumber(row.foreignNet) !== null || toNumber(row.trustNet) !== null);
  const totalNet = rows.reduce((sum, row) => sum + (toNumber(row.totalNet) || 0), 0);
  const foreignNet = rows.reduce((sum, row) => sum + (toNumber(row.foreignNet) || 0), 0);
  const trustNet = rows.reduce((sum, row) => sum + (toNumber(row.trustNet) || 0), 0);
  const dealerNet = rows.reduce((sum, row) => sum + (toNumber(row.dealerNet) || 0), 0);
  const buyDays = rows.filter((row) => (toNumber(row.totalNet) || 0) > 0).length;
  const sellDays = rows.filter((row) => (toNumber(row.totalNet) || 0) < 0).length;
  const chipSignal = stockChipSignal(stock.code);
  const foreignTrend = foreignOwnershipTrend(stock.code);
  let score = 0;
  if (rows.length) {
    if (totalNet > 0) score += 1;
    else if (totalNet < 0) score -= 1;
    if (foreignNet > 0) score += 0.5;
    else if (foreignNet < 0) score -= 0.5;
    if (trustNet > 0) score += 0.5;
    else if (trustNet < 0) score -= 0.5;
    if (buyDays >= Math.max(2, Math.ceil(rows.length * 0.6))) score += 0.5;
    if (sellDays >= Math.max(2, Math.ceil(rows.length * 0.6))) score -= 0.5;
  }
  if (foreignTrend.signal === "accumulation") score += 1;
  else if (foreignTrend.signal === "exit") score -= foreignTrend.level === "danger" ? 1.5 : 1;
  score += clamp(toNumber(chipSignal.score) || 0, -2, 2);
  score = clamp(score, -4, 4);

  let label = "籌碼中性";
  let level = "flat";
  if (!rows.length && foreignTrend.signal === "insufficient" && chipSignal.breakdown?.missingCount >= chipSignal.breakdown?.components?.length) {
    label = "資料不足";
  } else if (score >= 2) {
    label = "籌碼轉強";
    level = "good";
  } else if (score <= -2) {
    label = "籌碼轉弱";
    level = "danger";
  } else if (totalNet > 0 || foreignTrend.signal === "accumulation") {
    label = "偏多觀察";
    level = "good";
  } else if (totalNet < 0 || foreignTrend.signal === "exit") {
    label = "偏弱觀察";
    level = foreignTrend.level === "danger" ? "danger" : "warn";
  }

  return {
    stock,
    rows,
    latest: rows.at(-1) || null,
    first: rows[0] || null,
    obsDays: rows.length,
    totalNet,
    foreignNet,
    trustNet,
    dealerNet,
    buyDays,
    sellDays,
    chipSignal,
    foreignTrend,
    score,
    label,
    level
  };
}

function foreignOwnershipTrendRank(entry) {
  const trend = entry?.foreignTrend || {};
  const deltaPp = toNumber(trend.deltaPp);
  const deltaSharesLots = toNumber(trend.deltaSharesLots);
  const rows = Array.isArray(trend.rows) ? trend.rows : [];
  const latest = trend.latest || rows.at(-1) || null;
  const start = trend.start || rows[0] || null;
  const source = latest?.source || start?.source || "";
  const sourceTier = /TWSE|TPEx|證交|櫃買/.test(source) ? "Tier 1" : "待複核";
  const coverageRows = rows.length;
  const coverageScore = Math.min(coverageRows, FOREIGN_OWNERSHIP_TREND_WINDOW) / FOREIGN_OWNERSHIP_TREND_WINDOW;
  const magnitudeScore = deltaPp !== null
    ? Math.min(Math.abs(deltaPp) / Math.max(FOREIGN_ACCUMULATION_THRESHOLD_PP, 0.01), 6)
    : Math.min(Math.abs(deltaSharesLots || 0) / 3000, 6);
  const sourceScore = sourceTier === "Tier 1" ? 1 : 0.35;
  const direction = trend.signal === "accumulation" ? 1 : trend.signal === "exit" ? -1 : 0;
  const score = direction * (magnitudeScore * 10 + coverageScore * 2 + sourceScore);
  let confidence = "低";
  if (sourceTier === "Tier 1" && coverageRows >= FOREIGN_OWNERSHIP_TREND_WINDOW) confidence = "高";
  else if (sourceTier === "Tier 1" && coverageRows >= 2) confidence = "中";
  return {
    score,
    absScore: Math.abs(score),
    coverageRows,
    source,
    sourceTier,
    confidence,
    startDate: start?.date || "",
    latestDate: latest?.date || ""
  };
}

function summarizeThemeChipTrend(stocks) {
  const entries = stocks.map((stock) => institutionalTrendForStock(stock));
  const withInst = entries.filter((entry) => entry.obsDays > 0);
  const withForeignTrend = entries.filter((entry) => entry.foreignTrend && entry.foreignTrend.signal !== "insufficient");
  const totalNet = withInst.reduce((sum, entry) => sum + entry.totalNet, 0);
  const foreignNet = withInst.reduce((sum, entry) => sum + entry.foreignNet, 0);
  const trustNet = withInst.reduce((sum, entry) => sum + entry.trustNet, 0);
  const improving = entries.filter((entry) => ["good"].includes(entry.level)).length;
  const weakening = entries.filter((entry) => ["warn", "danger"].includes(entry.level)).length;
  const topBuy = [...withInst].sort((a, b) => b.totalNet - a.totalNet).slice(0, 5);
  const topSell = [...withInst].sort((a, b) => a.totalNet - b.totalNet).slice(0, 5);
  const foreignRanked = entries
    .filter((entry) => ["accumulation", "exit"].includes(entry.foreignTrend?.signal))
    .map((entry) => ({ ...entry, foreignTrendRank: foreignOwnershipTrendRank(entry) }));
  const foreignAccumulation = foreignRanked
    .filter((entry) => entry.foreignTrend?.signal === "accumulation")
    .sort((a, b) => b.foreignTrendRank.absScore - a.foreignTrendRank.absScore || (b.foreignTrend.deltaPp ?? -999) - (a.foreignTrend.deltaPp ?? -999))
    .slice(0, 8);
  const foreignExit = foreignRanked
    .filter((entry) => entry.foreignTrend?.signal === "exit")
    .sort((a, b) => b.foreignTrendRank.absScore - a.foreignTrendRank.absScore || (a.foreignTrend.deltaPp ?? 999) - (b.foreignTrend.deltaPp ?? 999))
    .slice(0, 8);
  const foreignRanking = [...foreignRanked]
    .sort((a, b) => b.foreignTrendRank.absScore - a.foreignTrendRank.absScore)
    .slice(0, 12);
  const chipLeaders = [...entries]
    .filter((entry) => entry.score > 0 || entry.chipSignal.score > 0)
    .sort((a, b) => b.score - a.score || b.totalNet - a.totalNet)
    .slice(0, 5);
  const chipLaggards = [...entries]
    .filter((entry) => entry.score < 0 || entry.chipSignal.score < 0)
    .sort((a, b) => a.score - b.score || a.totalNet - b.totalNet)
    .slice(0, 5);
  return {
    entries,
    withInst,
    withForeignTrend,
    totalNet,
    foreignNet,
    trustNet,
    improving,
    weakening,
    topBuy,
    topSell,
    foreignAccumulation,
    foreignExit,
    foreignRanking,
    chipLeaders,
    chipLaggards,
    hasCoverage: Boolean(withInst.length || withForeignTrend.length || chipLeaders.length || chipLaggards.length)
  };
}

function isRecordMap(value) {
  return value !== null && typeof value === "object" && !Array.isArray(value);
}

function normalizeRecordMap(value) {
  return isRecordMap(value) ? value : {};
}

function institutionalDateKey(row) {
  const raw = String(row?.date || "").trim();
  const digits = raw.replace(/\D/g, "");
  if (digits.length === 8 && Number(digits.slice(0, 4)) >= 1900) return digits;
  if (digits.length >= 7) {
    const rocYear = Number(digits.slice(0, digits.length - 4));
    if (rocYear > 0 && rocYear < 1911) return `${rocYear + 1911}${digits.slice(-4)}`;
  }
  const parsed = Date.parse(raw);
  if (Number.isFinite(parsed)) {
    const date = new Date(parsed);
    return `${date.getFullYear()}${String(date.getMonth() + 1).padStart(2, "0")}${String(date.getDate()).padStart(2, "0")}`;
  }
  return "";
}

function institutionalRowTime(row) {
  const key = institutionalDateKey(row);
  return key ? Number(key) : 0;
}

function normalizeInstitutionalHistoryRows(rows, limit = 30) {
  if (!Array.isArray(rows)) return [];
  const byDate = new Map();
  for (const row of rows) {
    if (!row || typeof row !== "object" || Array.isArray(row)) continue;
    const key = institutionalDateKey(row) || String(row.source || JSON.stringify(row));
    if (!key) continue;
    byDate.set(key, { ...row });
  }
  return [...byDate.values()]
    .sort((a, b) => institutionalRowTime(a) - institutionalRowTime(b) || String(a.date || "").localeCompare(String(b.date || "")))
    .slice(-limit);
}

function mergeInstitutionalHistoryRows(existingRows, incomingRows, limit = INSTITUTIONAL_HISTORY_TARGET_DAYS) {
  return normalizeInstitutionalHistoryRows([
    ...(Array.isArray(existingRows) ? existingRows : []),
    ...(Array.isArray(incomingRows) ? incomingRows : [])
  ], limit);
}

function normalizeInstitutionalRecord(row) {
  if (!row || typeof row !== "object" || Array.isArray(row)) return null;
  return { ...row, history: normalizeInstitutionalHistoryRows(row.history, INSTITUTIONAL_HISTORY_TARGET_DAYS) };
}

function normalizeInstitutionalMap(value) {
  const map = normalizeRecordMap(value);
  for (const [code, row] of Object.entries(map)) {
    map[code] = normalizeInstitutionalRecord(row);
  }
  return map;
}

function normalizeForeignOwnershipHistoryMap(historyMap, latestMap) {
  const normalized = {};
  for (const [code, rows] of Object.entries(normalizeRecordMap(historyMap))) {
    const inputRows = Array.isArray(rows) ? rows : [rows];
    const cleanRows = inputRows
      .map((row) => foreignOwnershipHistoryEntry(row))
      .filter(Boolean)
      .sort((a, b) => String(a.date || "").localeCompare(String(b.date || "")));
    if (!cleanRows.length) continue;
    const byDate = new Map();
    for (const row of cleanRows) byDate.set(row.date || row.capturedAt || String(byDate.size), row);
    normalized[code] = Array.from(byDate.values()).slice(-30);
  }
  for (const [code, foreignOwn] of Object.entries(normalizeRecordMap(latestMap))) {
    const historyEntry = foreignOwnershipHistoryEntry(foreignOwn);
    if (!historyEntry) continue;
    const rows = Array.isArray(normalized[code]) ? normalized[code] : [];
    if (!rows.some((row) => row.date === historyEntry.date)) rows.push(historyEntry);
    rows.sort((a, b) => String(a.date || "").localeCompare(String(b.date || "")));
    normalized[code] = rows.slice(-30);
  }
  return normalized;
}

function normalizeActiveEtfHolding(row) {
  if (!row || typeof row !== "object") return null;
  const rawCode = String(row.code || row.stockCode || "").trim().toUpperCase();
  const taiwanCode = rawCode.match(/^([0-9]{4,6}[A-Z]?)(?:\s+(?:TT|TW|TWO)|\.(?:TW|TWO))$/i);
  const code = taiwanCode ? taiwanCode[1] : rawCode;
  const weight = cellNumber(row.weight);
  if (!code || weight === null) return null;
  return {
    code,
    name: String(row.name || row.stockName || "").trim(),
    weight,
    weightDelta: cellNumber(row.weightDelta),
    shares: cellNumber(row.shares),
    industry: String(row.industry || "").trim()
  };
}

function normalizeActiveEtfSnapshot(row, fallbackCode = "") {
  if (!row || typeof row !== "object") return null;
  const etfCode = String(row.etfCode || row.code || fallbackCode || "").trim().toUpperCase();
  if (!ACTIVE_ETF_MAP.has(etfCode)) return null;
  const etf = ACTIVE_ETF_MAP.get(etfCode);
  const holdings = Array.isArray(row.holdings)
    ? row.holdings.map((holding) => normalizeActiveEtfHolding(holding)).filter(Boolean)
    : [];
  return {
    etfCode,
    etfShortName: row.etfShortName || etf.shortName,
    etfName: row.etfName || etf.fullName,
    focus: row.focus || etf.focus,
    group: row.group || etf.group,
    sourceLabel: row.sourceLabel || "",
    sourceUrl: row.sourceUrl || "",
    sourceDate: row.sourceDate || "",
    capturedAt: row.capturedAt || row.importedAt || new Date().toISOString(),
    holdings
  };
}

function normalizeActiveEtfSnapshotsMap(snapshots) {
  const normalized = {};
  for (const [code, rows] of Object.entries(normalizeRecordMap(snapshots))) {
    const inputRows = Array.isArray(rows) ? rows : [rows];
    const cleanRows = inputRows
      .map((row) => normalizeActiveEtfSnapshot(row, code))
      .filter(Boolean)
      .sort((a, b) => String(b.capturedAt || "").localeCompare(String(a.capturedAt || "")))
      .slice(0, 14);
    if (cleanRows.length) normalized[code] = cleanRows;
  }
  return normalized;
}

function normalizeActiveEtfSourceDiagnostic(row) {
  if (!row || typeof row !== "object") return null;
  return {
    label: String(row.label || "").trim(),
    url: String(row.url || "").trim(),
    status: ["success", "duplicate", "error"].includes(row.status) ? row.status : "error",
    durationMs: Math.max(0, Math.round(Number(row.durationMs) || 0)),
    bytes: Math.max(0, Math.round(Number(row.bytes) || 0)),
    holdingsCount: Math.max(0, Math.round(Number(row.holdingsCount) || 0)),
    sourceDate: String(row.sourceDate || "").trim(),
    error: String(row.error || "").trim()
  };
}

function normalizeActiveEtfDiagnostic(row, fallbackCode = "") {
  if (!row || typeof row !== "object") return null;
  const etfCode = String(row.etfCode || row.code || fallbackCode || "").trim().toUpperCase();
  if (!ACTIVE_ETF_MAP.has(etfCode)) return null;
  const sources = Array.isArray(row.sources)
    ? row.sources.map((source) => normalizeActiveEtfSourceDiagnostic(source)).filter(Boolean)
    : [];
  const successSources = sources.filter((source) => source.status === "success");
  return {
    etfCode,
    startedAt: row.startedAt || null,
    finishedAt: row.finishedAt || null,
    durationMs: Math.max(0, Math.round(Number(row.durationMs) || 0)),
    status: successSources.length ? "success" : "error",
    attemptCount: sources.length,
    successCount: successSources.length,
    snapshotsCount: Math.max(0, Math.round(Number(row.snapshotsCount) || successSources.length || 0)),
    latestHoldingsCount: Math.max(0, Math.round(Number(row.latestHoldingsCount) || (successSources[0]?.holdingsCount || 0))),
    sources,
    error: String(row.error || sources.find((source) => source.status === "error")?.error || "").trim()
  };
}

function normalizeActiveEtfDiagnosticsMap(diagnostics) {
  const normalized = {};
  for (const [code, row] of Object.entries(normalizeRecordMap(diagnostics))) {
    const diagnostic = normalizeActiveEtfDiagnostic(row, code);
    if (diagnostic) normalized[diagnostic.etfCode] = diagnostic;
  }
  return normalized;
}

function normalizeActiveEtfState(value) {
  const incoming = normalizeRecordMap(value);
  return {
    snapshots: normalizeActiveEtfSnapshotsMap(incoming.snapshots),
    diagnostics: normalizeActiveEtfDiagnosticsMap(incoming.diagnostics),
    sourcePath: incoming.sourcePath || ACTIVE_TWETF_SOURCE_PATH,
    loadedAt: incoming.loadedAt || null,
    importedAt: incoming.importedAt || null,
    generatedAt: incoming.generatedAt || null,
    lastSuccessAt: incoming.lastSuccessAt || null,
    lastFailedAt: incoming.lastFailedAt || null,
    lastFailureMessage: incoming.lastFailureMessage || ""
  };
}

function normalizeDispositionState(value) {
  const incoming = normalizeRecordMap(value);
  return {
    rows: Array.isArray(incoming.rows) ? incoming.rows.filter((row) => row && typeof row === "object") : [],
    fetchedAt: incoming.fetchedAt || null,
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : [],
    sourceSummary: incoming.sourceSummary || ""
  };
}

function normalizeDispositionRiskState(value) {
  const incoming = normalizeRecordMap(value);
  return {
    cumulativeRows: Array.isArray(incoming.cumulativeRows) ? incoming.cumulativeRows.filter((row) => row && typeof row === "object") : [],
    attentionRows: Array.isArray(incoming.attentionRows) ? incoming.attentionRows.filter((row) => row && typeof row === "object") : [],
    fetchedAt: incoming.fetchedAt || null,
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : [],
    sourceSummary: incoming.sourceSummary || ""
  };
}

function taifexProductStaleReason(product) {
  const dateText = product?.sourceDate || product?.quote?.sourceDate || product?.date || "";
  return localMarketStaleReason(product?.label || product?.shortLabel || product?.commodityId || "TAIFEX 期貨", dateText);
}

function normalizeTaifexState(value) {
  if (!isRecordMap(value)) return null;
  const incoming = normalizeRecordMap(value);
  const products = normalizeRecordMap(incoming.products);
  for (const product of FUTURES_PRODUCTS) {
    if (!products[product.key] && incoming[product.key]) {
      products[product.key] = {
        key: product.key,
        commodityId: product.commodityId,
        label: product.label,
        shortLabel: product.shortLabel,
        retailProxy: product.retailProxy,
        ...incoming[product.key]
      };
    }
  }
  const errors = Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : [];
  for (const [key, product] of Object.entries(products)) {
    const staleReason = taifexProductStaleReason(product);
    if (!staleReason) continue;
    errors.push(staleReason);
    delete products[key];
  }
  return {
    ...incoming,
    products,
    txf: products.txf || null,
    mxf: products.mxf || null,
    tmf: products.tmf || null,
    sourceLabel: incoming.sourceLabel || "TAIFEX 期貨資料",
    errors: uniqueList(errors).slice(-8)
  };
}

function parseCsvLine(line) {
  const cells = [];
  let cell = "";
  let quoted = false;
  const text = String(line || "");
  for (let index = 0; index < text.length; index += 1) {
    const char = text[index];
    if (char === '"') {
      if (quoted && text[index + 1] === '"') {
        cell += '"';
        index += 1;
      } else {
        quoted = !quoted;
      }
    } else if (char === "," && !quoted) {
      cells.push(cell.trim());
      cell = "";
    } else {
      cell += char;
    }
  }
  cells.push(cell.trim());
  return cells.map((value) => value.replace(/^\uFEFF/, "").replace(/^"|"$/g, ""));
}

function parseCsvTable(text) {
  const lines = String(text || "").split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  if (!lines.length) return [];
  const headers = parseCsvLine(lines[0]);
  return lines.slice(1).map((line) => {
    const cells = parseCsvLine(line);
    return Object.fromEntries(headers.map((header, index) => [header, cells[index] ?? ""]));
  });
}

function rowFirstText(row, keys) {
  for (const key of keys) {
    const value = row?.[key];
    if (value !== null && value !== undefined && String(value).trim()) return String(value).trim();
  }
  return "";
}

function rowFirstNumber(row, keys) {
  for (const key of keys) {
    const value = cellNumber(row?.[key]);
    if (value !== null) return value;
  }
  return null;
}

function normalizeQuarterKey(value) {
  const text = String(value || "").trim();
  if (!text) return "";
  let match = text.match(/^(\d{4})[-/\s]?[Qq季]?([1-4])$/);
  if (match) return `${match[1]}Q${match[2]}`;
  match = text.match(/^(\d{4}).*第?\s*([1-4])\s*季/);
  if (match) return `${match[1]}Q${match[2]}`;
  match = text.match(/^(\d{2,3}).*第?\s*([1-4])\s*季/);
  if (match) return `${Number(match[1]) + 1911}Q${match[2]}`;
  match = text.match(/^(\d{2,3})[-/\s]?[Qq季]?([1-4])$/);
  if (match) return `${Number(match[1]) + 1911}Q${match[2]}`;
  return text;
}

function marginPctFromAmounts(numerator, denominator) {
  const num = toNumber(numerator);
  const den = toNumber(denominator);
  if (num === null || den === null || den === 0) return null;
  return num / den * 100;
}

function normalizeQuarterlyMarginRow(row, source = {}, fetchedAt = new Date().toISOString()) {
  const code = rowFirstText(row, ["公司代號", "代號", "股票代號", "code", "Code"]).toUpperCase();
  if (!code || !STOCK_MAP.has(code)) return null;
  const period = normalizeQuarterKey(rowFirstText(row, ["期間", "年度季別", "年季", "季別", "quarter", "period", "yearQuarter"]));
  if (!period) return null;
  const revenue = rowFirstNumber(row, ["營業收入", "營業收入合計", "收入", "收益", "revenue", "operatingRevenue", "netRevenue"]);
  const grossProfit = rowFirstNumber(row, ["營業毛利", "營業毛利（毛損）", "營業毛利(毛損)", "毛利", "grossProfit"]);
  const operatingIncome = rowFirstNumber(row, ["營業利益", "營業利益（損失）", "營業利益(損失)", "營益", "operatingIncome"]);
  const netIncome = rowFirstNumber(row, ["本期淨利", "本期淨利（淨損）", "本期淨利(淨損)", "稅後淨利", "淨利", "netIncome"]);
  const grossMargin = rowFirstNumber(row, ["毛利率", "營業毛利率", "grossMargin", "grossProfitMargin"]) ?? marginPctFromAmounts(grossProfit, revenue);
  const operatingMargin = rowFirstNumber(row, ["營益率", "營業利益率", "operatingMargin", "operatingProfitMargin"]) ?? marginPctFromAmounts(operatingIncome, revenue);
  const netMargin = rowFirstNumber(row, ["淨利率", "稅後淨利率", "netMargin", "netProfitMargin"]) ?? marginPctFromAmounts(netIncome, revenue);
  if (grossMargin === null && operatingMargin === null && netMargin === null) return null;
  return {
    code,
    name: rowFirstText(row, ["公司名稱", "名稱", "name"]) || STOCK_MAP.get(code)?.name || code,
    period,
    revenue,
    grossProfit,
    operatingIncome,
    netIncome,
    grossMargin,
    operatingMargin,
    netMargin,
    source: source.label || "MOPS 季損益表匯入",
    sourceTier: source.sourceTier || "Tier 1 官方 / 本機匯入",
    sourceUrl: source.url || FINANCIAL_MARGIN_SOURCE_LINKS.mopsFinancials,
    fallbackUsed: source.fallbackUsed === true,
    fetchedAt,
    asOf: period
  };
}

function quarterlyMarginRowsFromCsv(text, source = {}, fetchedAt = new Date().toISOString()) {
  return parseCsvTable(text).map((row) => normalizeQuarterlyMarginRow(row, source, fetchedAt)).filter(Boolean);
}

function parseRocCompactDate(value) {
  const digits = String(value || "").replace(/\D/g, "");
  if (!digits) return "";
  if (digits.length === 8 && Number(digits.slice(0, 4)) >= 1900) return parseCompactDay(digits);
  if (digits.length === 7) {
    const year = Number(digits.slice(0, 3)) + 1911;
    return `${year}-${digits.slice(3, 5)}-${digits.slice(5, 7)}`;
  }
  if (digits.length === 6) {
    const year = Number(digits.slice(0, 2)) + 1911;
    return `${year}-${digits.slice(2, 4)}-${digits.slice(4, 6)}`;
  }
  return String(value || "").trim();
}

function parseSlashDate(value) {
  const text = String(value || "").trim();
  const match = text.match(/^(\d{4})[/-](\d{1,2})[/-](\d{1,2})$/);
  if (!match) return "";
  return `${match[1]}-${match[2].padStart(2, "0")}-${match[3].padStart(2, "0")}`;
}

function rowNumber(row, key) {
  return cellNumber(row?.[key]);
}

function normalizeMopsDividendRow(row, market) {
  const code = String(row["公司代號"] || "").trim().toUpperCase();
  if (!code || !STOCK_MAP.has(code)) return null;
  const cashDividend = [
    "股東配發-盈餘分配之現金股利(元/股)",
    "股東配發-法定盈餘公積發放之現金(元/股)",
    "股東配發-資本公積發放之現金(元/股)"
  ].reduce((sum, key) => sum + (rowNumber(row, key) || 0), 0);
  const stockDividend = [
    "股東配發-盈餘轉增資配股(元/股)",
    "股東配發-法定盈餘公積轉增資配股(元/股)",
    "股東配發-資本公積轉增資配股(元/股)"
  ].reduce((sum, key) => sum + (rowNumber(row, key) || 0), 0);
  return {
    code,
    name: String(row["公司名稱"] || STOCK_MAP.get(code)?.name || "").trim(),
    market,
    status: String(row["決議（擬議）進度"] || "").trim(),
    dividendYear: String(row["股利年度"] || "").trim(),
    period: String(row["股利所屬年(季)度"] || row["股利所屬期間"] || "").trim(),
    boardDate: parseRocCompactDate(row["董事會（擬議）股利分派日"]),
    shareholderMeetingDate: parseRocCompactDate(row["股東會日期"]),
    sourceDate: parseRocCompactDate(row["出表日期"]),
    netIncome: rowNumber(row, "本期淨利(淨損)(元)"),
    distributableEarnings: rowNumber(row, "可分配盈餘(元)"),
    undistributedAfter: rowNumber(row, "分配後期末未分配盈餘(元)"),
    cashDividend: +cashDividend.toFixed(4),
    stockDividend: +stockDividend.toFixed(4),
    cashDividendTotal: rowNumber(row, "股東配發-股東配發之現金(股利)總金額(元)"),
    stockSharesTotal: rowNumber(row, "股東配發-股東配股總股數(股)"),
    note: String(row["備註"] || "").trim(),
    source: market === "listed" ? "MOPS t187ap45_L" : "MOPS t187ap45_O",
    sourceUrl: market === "listed" ? DIVIDEND_SOURCE_LINKS.listed : DIVIDEND_SOURCE_LINKS.otc,
    fetchedAt: new Date().toISOString()
  };
}

function dividendRecordKey(row) {
  return [row.dividendYear, row.period, row.boardDate, row.cashDividend, row.stockDividend].join("|");
}

function normalizeDividendRecord(row = {}) {
  const cashDividend = toNumber(row.cashDividend);
  const stockDividend = toNumber(row.stockDividend);
  return {
    code: String(row.code || "").trim().toUpperCase(),
    name: String(row.name || "").trim(),
    market: row.market || "",
    status: row.status || "",
    dividendYear: row.dividendYear || "",
    period: row.period || "",
    boardDate: row.boardDate || "",
    shareholderMeetingDate: row.shareholderMeetingDate || "",
    exDividendDate: row.exDividendDate || "",
    exRightDate: row.exRightDate || "",
    cashPayDate: row.cashPayDate || "",
    stockPayDate: row.stockPayDate || "",
    cashYield: toNumber(row.cashYield),
    sourceDate: row.sourceDate || "",
    netIncome: toNumber(row.netIncome),
    distributableEarnings: toNumber(row.distributableEarnings),
    undistributedAfter: toNumber(row.undistributedAfter),
    cashDividend,
    stockDividend,
    cashDividendTotal: toNumber(row.cashDividendTotal),
    stockSharesTotal: toNumber(row.stockSharesTotal),
    note: row.note || "",
    source: row.source || "",
    sourceUrl: row.sourceUrl || "",
    fetchedAt: row.fetchedAt || null
  };
}

function mergeDividendRecord(existing, latest) {
  const currentHistory = Array.isArray(existing?.history)
    ? existing.history.map((row) => normalizeDividendRecord(row)).filter((row) => row.code)
    : [];
  const nextLatest = normalizeDividendRecord(latest || existing?.latest || {});
  const rows = [...currentHistory, nextLatest].filter((row) => row.code);
  const byKey = new Map();
  for (const row of rows) byKey.set(dividendRecordKey(row), row);
  const history = Array.from(byKey.values())
    .sort((a, b) => String(b.dividendYear || b.sourceDate || "").localeCompare(String(a.dividendYear || a.sourceDate || "")))
    .slice(0, 5);
  return {
    latest: history[0] || nextLatest,
    history
  };
}

function normalizeDividendState(value) {
  const incoming = normalizeRecordMap(value);
  const records = {};
  for (const [code, record] of Object.entries(normalizeRecordMap(incoming.records))) {
    const merged = mergeDividendRecord(record, record?.latest);
    if (merged.latest?.code || code) records[code] = merged;
  }
  return {
    records,
    fetchedAt: incoming.fetchedAt || null,
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : [],
    sourceSummary: incoming.sourceSummary || ""
  };
}

function normalizeExDividendType(value) {
  const text = stripHtml(String(value || "")).replace(/\s+/g, "");
  if (!text) return "除權息";
  if (text.includes("權") && text.includes("息")) return "除權息";
  if (text.includes("權")) return "除權";
  if (text.includes("息")) return "除息";
  return text;
}

function normalizeExDividendEvent(row = {}) {
  const code = String(row.code || "").trim().toUpperCase();
  const date = parseRocCompactDate(row.date || row.exDate || "");
  if (!code || !date) return null;
  const cashDividend = toNumber(row.cashDividend);
  const stockDividendRatio = toNumber(row.stockDividendRatio);
  return {
    date,
    code,
    name: sanitizeSecurityName(row.name || STOCK_MAP.get(code)?.name || ""),
    market: row.market === "otc" ? "上櫃" : row.market === "listed" ? "上市" : String(row.market || ""),
    tracked: STOCK_MAP.has(code),
    type: normalizeExDividendType(row.type),
    cashDividend,
    cashDividendText: String(row.cashDividendText || "").trim(),
    stockDividendRatio,
    subscriptionRatio: toNumber(row.subscriptionRatio),
    subscriptionPrice: toNumber(row.subscriptionPrice),
    source: String(row.source || "").trim(),
    sourceTier: row.sourceTier || "Tier 1 官方",
    sourceUrl: String(row.sourceUrl || "").trim(),
    fetchedAt: row.fetchedAt || null,
    confidence: row.confidence || "high",
    fallbackUsed: row.fallbackUsed === true
  };
}

function exDividendEventKey(row) {
  return [row.market, row.date, row.code, row.type].join("|");
}

function normalizeExDividendRows(rows) {
  const byKey = new Map();
  for (const row of Array.isArray(rows) ? rows : []) {
    const normalized = normalizeExDividendEvent(row);
    if (!normalized) continue;
    byKey.set(exDividendEventKey(normalized), normalized);
  }
  return [...byKey.values()]
    .sort((a, b) => String(a.date).localeCompare(String(b.date)) || String(a.code).localeCompare(String(b.code)));
}

function normalizeExDividendCalendarState(value) {
  const incoming = normalizeRecordMap(value);
  return {
    rows: normalizeExDividendRows(incoming.rows),
    fetchedAt: incoming.fetchedAt || null,
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : [],
    sources: Array.isArray(incoming.sources) ? incoming.sources.filter((item) => item && typeof item === "object") : [],
    sourceSummary: incoming.sourceSummary || ""
  };
}

function parseMopsDividendCsv(text, market) {
  return parseCsvTable(text).map((row) => normalizeMopsDividendRow(row, market)).filter(Boolean);
}

function normalizeMarketSeries(rows) {
  return Array.isArray(rows)
    ? rows
        .map((point, index) => ({
          ts: Number(point?.ts) || index,
          date: point?.date || point?.time || "",
          time: point?.time || point?.date || "",
          value: toNumber(point?.value)
        }))
        .filter((point) => point.value !== null)
        .sort((left, right) => left.ts - right.ts)
        .slice(-120)
    : [];
}

function normalizeMarketIndexSnapshot(value) {
  const incoming = normalizeRecordMap(value);
  if (!Object.keys(incoming).length) return null;
  return {
    key: incoming.key || "",
    label: incoming.label || "",
    symbol: incoming.symbol || "",
    value: toNumber(incoming.value),
    previousClose: toNumber(incoming.previousClose),
    change: toNumber(incoming.change),
    pct: toNumber(incoming.pct),
    open: toNumber(incoming.open),
    high: toNumber(incoming.high),
    low: toNumber(incoming.low),
    volume: toNumber(incoming.volume),
    turnover100m: toNumber(incoming.turnover100m),
    sourceDate: incoming.sourceDate || "",
    sourceTime: incoming.sourceTime || "",
    timeZone: incoming.timeZone || incoming.exchangeTimezoneName || "",
    fetchedAt: incoming.fetchedAt || null,
    source: incoming.source || "",
    sourceTier: incoming.sourceTier || "",
    fallbackUsed: incoming.fallbackUsed === true,
    confidence: incoming.confidence || "",
    url: incoming.url || "",
    sourceLinks: Array.isArray(incoming.sourceLinks)
      ? incoming.sourceLinks
          .filter((link) => link && typeof link === "object" && link.url)
          .map((link) => ({ label: link.label || "來源", url: link.url }))
      : [],
    note: incoming.note || "",
    series: normalizeMarketSeries(incoming.series)
  };
}

function marketDashboardSnapshotStaleReason(snapshot, kind = "local") {
  if (!snapshot) return "";
  const dateText = snapshot.sourceDate || snapshot.fetchedAt || snapshot.sourceTime || "";
  const maxDays = kind === "global" ? MARKET_DASHBOARD_STALE_GLOBAL_DAYS : MARKET_DASHBOARD_STALE_LOCAL_DAYS;
  return localMarketStaleReason(snapshot.label || snapshot.symbol || "行情", dateText, maxDays);
}

function sanitizeMarketDashboardSnapshot(value, kind, errors) {
  const snapshot = normalizeMarketIndexSnapshot(value);
  if (!snapshot) return null;
  const staleReason = marketDashboardSnapshotStaleReason(snapshot, kind);
  if (staleReason) {
    errors.push(staleReason);
    return null;
  }
  return snapshot;
}

function normalizeMarketDashboardDelivery(value) {
  const incoming = normalizeRecordMap(value);
  const allowedModes = new Set(["github-actions-delayed-snapshot", "bundled-fallback"]);
  const mode = allowedModes.has(incoming.mode) ? incoming.mode : "";
  if (!mode) return null;
  return {
    mode,
    generatedAt: String(incoming.generatedAt || "").slice(0, 40),
    scheduleMinutes: Math.max(0, Math.min(1440, Number(incoming.scheduleMinutes) || 0)),
    freshSources: Array.isArray(incoming.freshSources)
      ? uniqueList(incoming.freshSources.map((item) => String(item || "").slice(0, 80)).filter(Boolean)).slice(0, 16)
      : [],
    note: String(incoming.note || "").slice(0, 300)
  };
}

function normalizeMarketDashboardCache(value) {
  const incoming = normalizeRecordMap(value);
  const errors = Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : [];
  const taiwan = sanitizeMarketDashboardSnapshot(incoming.taiwan, "local", errors);
  const taifexNight = sanitizeMarketDashboardSnapshot(incoming.taifexNight, "local", errors);
  const global = Array.isArray(incoming.global)
    ? incoming.global.map((item) => sanitizeMarketDashboardSnapshot(item, "global", errors)).filter(Boolean)
    : [];
  return {
    ts: Number(incoming.ts) || 0,
    fetchedAt: incoming.fetchedAt || null,
    taiwan,
    taifexNight,
    global,
    errors: uniqueList(errors).slice(-8),
    delivery: normalizeMarketDashboardDelivery(incoming.delivery)
  };
}

function normalizeTideSectorRow(row) {
  if (!row || typeof row !== "object") return null;
  const name = String(row.name || "").trim();
  if (!name) return null;
  const stocks = Array.isArray(row.stocks)
    ? row.stocks.map((code) => String(code || "").trim()).filter(Boolean).slice(0, 24)
    : [];
  return {
    name,
    stocks,
    net1dYi: toNumber(row.net1dYi ?? row.net_1d_yi),
    net5dYi: toNumber(row.net5dYi ?? row.net_5d_yi),
    net20dYi: toNumber(row.net20dYi ?? row.net_20d_yi),
    position: toNumber(row.position),
    chg1d: toNumber(row.chg1d ?? row.chg_1d),
    chg5d: toNumber(row.chg5d ?? row.chg_5d),
    avgAbsDaily20d: toNumber(row.avgAbsDaily20d ?? row.avg_abs_daily_20d),
    inflowStreak: toNumber(row.inflowStreak ?? row.inflow_streak),
    source: row.source || "Tide latest.json",
    sourceUrl: row.sourceUrl || TIDE_LATEST_JSON_URL,
    sourceTier: row.sourceTier || "Tier 2 市場資料 / 第三方整理",
    asOf: row.asOf || ""
  };
}

function normalizeTideSectorRows(rows, limit = 8) {
  return (Array.isArray(rows) ? rows : [])
    .map(normalizeTideSectorRow)
    .filter(Boolean)
    .slice(0, limit);
}

function normalizeTideDigestStockRow(row) {
  if (!row || typeof row !== "object") return null;
  const code = String(row.code || "").trim();
  const stock = code ? (STOCK_MAP.get(code) || STOCK_UNIVERSE[code] || {}) : {};
  const name = String(row.name || stock.name || "").trim();
  if (!code && !name) return null;
  return {
    code,
    name,
    net1dYi: toNumber(row.net1dYi ?? row.net_1d_yi),
    chg1d: toNumber(row.chg1d ?? row.chg_1d),
    inflowStreak: toNumber(row.inflowStreak ?? row.inflow_streak),
    source: row.source || "Tide daily_digest.json",
    sourceUrl: row.sourceUrl || TIDE_DAILY_DIGEST_JSON_URL,
    sourceTier: row.sourceTier || "Tier 2 市場資料 / 第三方整理",
    asOf: row.asOf || ""
  };
}

function normalizeTideDigestStockRows(rows, limit = 6) {
  return (Array.isArray(rows) ? rows : [])
    .map(normalizeTideDigestStockRow)
    .filter(Boolean)
    .slice(0, limit);
}

function normalizeTideSentimentDigest(value) {
  const incoming = normalizeRecordMap(value);
  const hasDigest = Boolean(
    incoming.date ||
    incoming.asOf ||
    incoming.generatedAt ||
    incoming.generated_at ||
    incoming.panicIndex ||
    incoming.panic_index ||
    incoming.safeHarbor ||
    incoming.safe_harbor ||
    incoming.bigMoney ||
    incoming.big_money ||
    incoming.pushHeadline ||
    incoming.push_headline ||
    incoming.recapHeadline ||
    incoming.recap_headline
  );
  if (!hasDigest) return null;
  const asOf = incoming.asOf || incoming.date || "";
  const panicRaw = normalizeRecordMap(incoming.panicIndex || incoming.panic_index);
  const safeRaw = normalizeRecordMap(incoming.safeHarbor || incoming.safe_harbor);
  const bigMoneyRaw = normalizeRecordMap(incoming.bigMoney || incoming.big_money);
  const withDigestSectorSource = (row) => ({
    ...normalizeRecordMap(row),
    source: row?.source || "Tide daily_digest.json",
    sourceUrl: row?.sourceUrl || TIDE_DAILY_DIGEST_JSON_URL,
    sourceTier: row?.sourceTier || "Tier 2 市場資料 / 第三方整理",
    asOf: row?.asOf || asOf
  });
  const withDigestStockSource = (row) => ({
    ...normalizeRecordMap(row),
    source: row?.source || "Tide daily_digest.json",
    sourceUrl: row?.sourceUrl || TIDE_DAILY_DIGEST_JSON_URL,
    sourceTier: row?.sourceTier || "Tier 2 市場資料 / 第三方整理",
    asOf: row?.asOf || asOf
  });
  return {
    asOf,
    generatedAt: incoming.generatedAt || incoming.generated_at || null,
    source: incoming.source || "Tide daily_digest.json",
    sourceUrl: incoming.sourceUrl || TIDE_DAILY_DIGEST_JSON_URL,
    sourceTier: incoming.sourceTier || "Tier 2 市場資料 / 第三方整理",
    confidence: incoming.confidence || "low-to-medium / 待複核",
    marketChg1d: toNumber(incoming.marketChg1d ?? incoming.market_chg_1d),
    isMarketDown: incoming.isMarketDown === true || incoming.is_market_down === true,
    panicIndex: {
      score: toNumber(panicRaw.score),
      label: String(panicRaw.label || "").trim(),
      advancers: toNumber(panicRaw.advancers),
      decliners: toNumber(panicRaw.decliners),
      downRatio: toNumber(panicRaw.downRatio ?? panicRaw.down_ratio)
    },
    safeHarbor: {
      mode: String(safeRaw.mode || "").trim(),
      sectors: normalizeTideSectorRows(
        Array.isArray(safeRaw.sectors) ? safeRaw.sectors.map(withDigestSectorSource) : [],
        6
      )
    },
    bigMoney: {
      abnormalBuy: normalizeTideDigestStockRows(
        Array.isArray(bigMoneyRaw.abnormalBuy) ? bigMoneyRaw.abnormalBuy.map(withDigestStockSource)
          : Array.isArray(bigMoneyRaw.abnormal_buy) ? bigMoneyRaw.abnormal_buy.map(withDigestStockSource)
          : [],
        6
      ),
      abnormalSell: normalizeTideDigestStockRows(
        Array.isArray(bigMoneyRaw.abnormalSell) ? bigMoneyRaw.abnormalSell.map(withDigestStockSource)
          : Array.isArray(bigMoneyRaw.abnormal_sell) ? bigMoneyRaw.abnormal_sell.map(withDigestStockSource)
          : [],
        6
      ),
      streakLeaders: normalizeTideDigestStockRows(
        Array.isArray(bigMoneyRaw.streakLeaders) ? bigMoneyRaw.streakLeaders.map(withDigestStockSource)
          : Array.isArray(bigMoneyRaw.streak_leaders) ? bigMoneyRaw.streak_leaders.map(withDigestStockSource)
          : [],
        6
      )
    },
    pushHeadline: String(incoming.pushHeadline || incoming.push_headline || "").trim(),
    recapHeadline: String(incoming.recapHeadline || incoming.recap_headline || "").trim()
  };
}

function normalizeTideSectorCache(value) {
  const incoming = normalizeRecordMap(value);
  return {
    ts: Number(incoming.ts) || 0,
    fetchedAt: incoming.fetchedAt || null,
    asOf: incoming.asOf || incoming.date || "",
    updatedAt: incoming.updatedAt || incoming.updated_at || null,
    source: incoming.source || "Tide 台股板塊輪動",
    sourceUrl: incoming.sourceUrl || TIDE_LATEST_JSON_URL,
    sourceTier: incoming.sourceTier || "Tier 2 市場資料 / 第三方整理",
    fallbackUsed: incoming.fallbackUsed === true,
    confidence: incoming.confidence || "low-to-medium / 待複核",
    marketChg1d: toNumber(incoming.marketChg1d ?? incoming.market_chg_1d),
    isMarketDown: incoming.isMarketDown === true || incoming.is_market_down === true,
    sectorCount: Number(incoming.sectorCount) || 0,
    stockCount: Number(incoming.stockCount) || 0,
    dailyBrief: String(incoming.dailyBrief || incoming.brief || "").trim(),
    sentiment: normalizeTideSentimentDigest(incoming.sentiment || incoming.digest || incoming.dailyDigest || incoming.daily_digest),
    topInflow5: normalizeTideSectorRows(incoming.topInflow5),
    topOutflow5: normalizeTideSectorRows(incoming.topOutflow5),
    topInflow20: normalizeTideSectorRows(incoming.topInflow20),
    contrarianBuy: normalizeTideSectorRows(incoming.contrarianBuy),
    sourceLinks: Array.isArray(incoming.sourceLinks)
      ? incoming.sourceLinks
          .filter((link) => link && typeof link === "object" && link.url)
          .map((link) => ({ label: link.label || "來源", url: link.url }))
      : TIDE_SOURCE_LINKS,
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : []
  };
}

function topTideSectorRows(sectors, key, direction = "desc", limit = 8, predicate = null) {
  const rows = (Array.isArray(sectors) ? sectors : [])
    .map(normalizeTideSectorRow)
    .filter((row) => row && row[key] !== null && (!predicate || predicate(row)));
  rows.sort((left, right) => direction === "asc" ? left[key] - right[key] : right[key] - left[key]);
  return rows.slice(0, limit);
}

function buildTideSectorCacheFromPayload(latestPayload, dailyBriefPayload = null, dailyDigestPayload = null, fetchedAt = new Date().toISOString()) {
  if (typeof dailyDigestPayload === "string" && arguments.length === 3) {
    fetchedAt = dailyDigestPayload;
    dailyDigestPayload = null;
  }
  const latest = normalizeRecordMap(latestPayload);
  const sectors = Array.isArray(latest.sectors) ? latest.sectors : [];
  const normalizedSectors = sectors.map(normalizeTideSectorRow).filter(Boolean);
  const asOf = latest.date || "";
  const marketChg1d = toNumber(latest.market_chg_1d ?? latest.marketChg1d);
  const stockData = normalizeRecordMap(latest.stock_data || latest.stockData || {});
  const brief = typeof dailyBriefPayload === "string"
    ? dailyBriefPayload
    : String(dailyBriefPayload?.text || "").trim();
  const cache = {
    ts: Date.now(),
    fetchedAt,
    asOf,
    updatedAt: latest.updated_at || latest.updatedAt || null,
    source: "Tide 台股板塊輪動",
    sourceUrl: TIDE_LATEST_JSON_URL,
    sourceTier: "Tier 2 市場資料 / 第三方整理",
    fallbackUsed: false,
    confidence: "low-to-medium / 待複核",
    marketChg1d,
    isMarketDown: latest.is_market_down === true || latest.isMarketDown === true || (marketChg1d !== null && marketChg1d < 0),
    sectorCount: normalizedSectors.length,
    stockCount: Object.keys(stockData).length,
    dailyBrief: brief,
    sentiment: normalizeTideSentimentDigest(dailyDigestPayload),
    topInflow5: topTideSectorRows(normalizedSectors, "net5dYi", "desc"),
    topOutflow5: topTideSectorRows(normalizedSectors, "net5dYi", "asc"),
    topInflow20: topTideSectorRows(normalizedSectors, "net20dYi", "desc"),
    contrarianBuy: topTideSectorRows(normalizedSectors, "net1dYi", "desc", 8, (row) => (row.net1dYi || 0) > 0 && ((row.chg1d || 0) < 0 || marketChg1d < 0)),
    sourceLinks: TIDE_SOURCE_LINKS,
    errors: []
  };
  return normalizeTideSectorCache(cache);
}

function normalizeMarketInstitutionalRankingRow(row) {
  if (!row || typeof row !== "object") return null;
  const code = String(row.code || "").trim();
  if (!code) return null;
  const stock = STOCK_MAP.get(code) || STOCK_UNIVERSE[code] || {};
  return {
    code,
    name: String(row.name || stock.name || "").trim(),
    market: row.market || stock.suffix || "",
    date: row.date || "",
    foreignNet: toNumber(row.foreignNet) ?? 0,
    trustNet: toNumber(row.trustNet) ?? 0,
    dealerNet: toNumber(row.dealerNet) ?? 0,
    totalNet: toNumber(row.totalNet) ?? (
      (toNumber(row.foreignNet) ?? 0) +
      (toNumber(row.trustNet) ?? 0) +
      (toNumber(row.dealerNet) ?? 0)
    ),
    source: row.source || ""
  };
}

function normalizeMarketInstitutionalRankings(value) {
  const incoming = normalizeRecordMap(value);
  return {
    ts: Number(incoming.ts) || 0,
    fetchedAt: incoming.fetchedAt || null,
    asOf: incoming.asOf || "",
    source: incoming.source || "",
    sourceTier: incoming.sourceTier || "",
    fallbackUsed: incoming.fallbackUsed === true,
    confidence: incoming.confidence || "",
    url: incoming.url || "",
    sourceLinks: Array.isArray(incoming.sourceLinks)
      ? incoming.sourceLinks
          .filter((link) => link && typeof link === "object" && link.url)
          .map((link) => ({ label: link.label || "來源", url: link.url }))
      : [],
    rows: Array.isArray(incoming.rows)
      ? incoming.rows.map((row) => normalizeMarketInstitutionalRankingRow(row)).filter(Boolean)
      : [],
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : []
  };
}

function normalizeFedPathTrend(value) {
  const incoming = normalizeRecordMap(value);
  const rows = Array.isArray(incoming.rows)
    ? incoming.rows.map((row) => normalizeFedPathHistoryRow(row)).filter(Boolean).slice(-8)
    : [];
  return {
    label: incoming.label || "",
    tone: incoming.tone || "flat",
    detail: incoming.detail || "",
    diffChangeBp: toNumber(incoming.diffChangeBp),
    marketChangeBp: toNumber(incoming.marketChangeBp),
    sepChangeBp: toNumber(incoming.sepChangeBp),
    rows,
    confidence: incoming.confidence || "low"
  };
}

function normalizeFedPathHistoryRow(value) {
  if (!value || typeof value !== "object") return null;
  const diffBp = toNumber(value.diffBp);
  const marketRate = toNumber(value.marketRate);
  const sepRate = toNumber(value.sepRate);
  if (diffBp === null && marketRate === null && sepRate === null) return null;
  return {
    ts: Number(value.ts) || 0,
    fetchedAt: value.fetchedAt || null,
    asOf: value.asOf || "",
    marketRate,
    sepRate,
    diffBp,
    label: value.label || "",
    regimeLabel: value.regimeLabel || "",
    confidence: value.confidence || "low",
    fallbackUsed: value.fallbackUsed === true,
    source: value.source || "CME FedWatch + Fed SEP"
  };
}

function fedPathHistorySnapshot(fedPath) {
  if (!fedPath || typeof fedPath !== "object") return null;
  const gap = fedPath.gap || {};
  const fedWatch = fedPath.fedWatch || {};
  const sep = fedPath.sep || {};
  return normalizeFedPathHistoryRow({
    ts: Number(fedPath.ts) || Date.now(),
    fetchedAt: fedPath.fetchedAt || null,
    asOf: fedPath.asOf || fedWatch.fetchedAt || sep.releaseDate || "",
    marketRate: gap.marketRate ?? fedWatch.yearEndExpectedRate ?? null,
    sepRate: gap.sepRate ?? sep.currentYearMedian ?? null,
    diffBp: gap.diffBp ?? null,
    label: gap.label || "",
    regimeLabel: fedPath.regime?.label || "",
    confidence: gap.confidence || fedPath.regime?.confidence || "low",
    fallbackUsed: fedWatch.fallbackUsed === true,
    source: fedWatch.fallbackUsed ? "CME FedWatch cached + Fed SEP" : "CME FedWatch + Fed SEP"
  });
}

function fedPathHistoryRowsFromCache(cache) {
  const normalized = normalizeMacroCache(cache);
  const rows = [
    ...(normalized.history || []).map((row) => normalizeFedPathHistoryRow(row.fedPath)).filter(Boolean),
    fedPathHistorySnapshot(normalized.fedPath)
  ].filter(Boolean);
  const deduped = new Map();
  rows.forEach((row) => {
    const key = row.fetchedAt || row.asOf || String(row.ts || "");
    if (!key) return;
    deduped.set(key, row);
  });
  return Array.from(deduped.values())
    .sort((left, right) => (left.ts || Date.parse(left.fetchedAt || left.asOf || "") || 0) - (right.ts || Date.parse(right.fetchedAt || right.asOf || "") || 0))
    .slice(-FED_PATH_HISTORY_LIMIT);
}

function sourceDateTextToDateKey(value, fallbackYear = null) {
  const text = String(value || "").trim();
  if (!text) return "";
  const ymd = text.match(/(\d{4})[-/](\d{1,2})[-/](\d{1,2})/);
  if (ymd) return dateKeyFromParts(ymd[1], ymd[2], ymd[3]);
  const compact = text.match(/\b(\d{4})(\d{2})(\d{2})\b/);
  if (compact) return dateKeyFromParts(compact[1], compact[2], compact[3]);
  const mdy = text.match(/\b(\d{1,2})\/(\d{1,2})\/(\d{4})\b/);
  if (mdy) return dateKeyFromParts(mdy[3], mdy[1], mdy[2]);
  const year = fallbackYear || Number(dateKeyInTaipei().slice(0, 4));
  const md = text.match(/(?:^|\D)(\d{1,2})\/(\d{1,2})(?:\D|$)/);
  if (md && year) return dateKeyFromParts(year, md[1], md[2]);
  return "";
}

function sourceDateAgeDays(value, now = new Date()) {
  const fallbackYear = Number(dateKeyInTaipei(now).slice(0, 4));
  const key = sourceDateTextToDateKey(value, fallbackYear);
  if (!key) return null;
  return dateKeyDiffDays(key, dateKeyInTaipei(now));
}

function localMarketStaleReason(label, dateText, maxDays = MARKET_DASHBOARD_STALE_LOCAL_DAYS) {
  const ageDays = sourceDateAgeDays(dateText);
  if (ageDays === null) return "";
  if (ageDays > maxDays) return `${label}資料日期 ${dateText || "待補"} 已過期 ${formatNumber(ageDays, 0)} 天，已改為待更新`;
  if (ageDays < -1) return `${label}資料日期 ${dateText || "待補"} 晚於目前日期，已改為待複核`;
  return "";
}

function macroItemStaleReason(item) {
  if (!item || typeof item !== "object") return "";
  const key = String(item.key || "");
  if (!key.startsWith("twse-")) return "";
  return localMarketStaleReason(item.label || key, item.date || item.fetchedAt || item.asOf || "");
}

function normalizeMacroItems(value) {
  if (Array.isArray(value)) return value.filter((item) => item && typeof item === "object");
  if (value && typeof value === "object") {
    return Object.entries(value)
      .map(([key, item]) => item && typeof item === "object" ? { key, ...item } : null)
      .filter(Boolean);
  }
  return [];
}

function normalizeMacroCache(value) {
  const incoming = normalizeRecordMap(value);
  const errors = Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : [];
  const items = normalizeMacroItems(incoming.items).filter((item) => {
    const staleReason = macroItemStaleReason(item);
    if (staleReason) {
      errors.push(staleReason);
      return false;
    }
    return true;
  });
  const history = Array.isArray(incoming.history)
    ? incoming.history
        .filter((row) => row && typeof row === "object")
        .map((row) => ({
          ts: Number(row.ts) || 0,
          fetchedAt: row.fetchedAt || null,
          items: normalizeRecordMap(row.items),
          marketMargin: row.marketMargin && typeof row.marketMargin === "object" ? row.marketMargin : null,
          fedPath: normalizeFedPathHistoryRow(row.fedPath)
        }))
        .filter((row) => row.ts || row.fetchedAt)
        .slice(-FED_PATH_HISTORY_LIMIT)
    : [];
  return {
    ts: Number(incoming.ts) || 0,
    fetchedAt: incoming.fetchedAt || null,
    items,
    history,
    marketMargin: incoming.marketMargin && typeof incoming.marketMargin === "object" ? incoming.marketMargin : null,
    usdTwd: incoming.usdTwd && typeof incoming.usdTwd === "object" ? incoming.usdTwd : null,
    fedPath: incoming.fedPath && typeof incoming.fedPath === "object" ? {
      ts: Number(incoming.fedPath.ts) || 0,
      fetchedAt: incoming.fedPath.fetchedAt || null,
      asOf: incoming.fedPath.asOf || "",
      fedWatch: incoming.fedPath.fedWatch && typeof incoming.fedPath.fedWatch === "object" ? incoming.fedPath.fedWatch : null,
      sep: incoming.fedPath.sep && typeof incoming.fedPath.sep === "object" ? incoming.fedPath.sep : null,
      gap: incoming.fedPath.gap && typeof incoming.fedPath.gap === "object" ? incoming.fedPath.gap : null,
      regime: incoming.fedPath.regime && typeof incoming.fedPath.regime === "object" ? incoming.fedPath.regime : null,
      trend: incoming.fedPath.trend && typeof incoming.fedPath.trend === "object" ? normalizeFedPathTrend(incoming.fedPath.trend) : null,
      errors: Array.isArray(incoming.fedPath.errors) ? incoming.fedPath.errors.map((item) => String(item || "")).filter(Boolean) : []
    } : null,
    errors: uniqueList(errors).slice(-8)
  };
}

function normalizeBondSignalCache(value) {
  const incoming = normalizeRecordMap(value);
  return {
    ts: Number(incoming.ts) || 0,
    fetchedAt: incoming.fetchedAt || null,
    signal: incoming.signal && typeof incoming.signal === "object" ? incoming.signal : null,
    fed: incoming.fed && typeof incoming.fed === "object" ? incoming.fed : null,
    usdtwd: incoming.usdtwd && typeof incoming.usdtwd === "object" ? incoming.usdtwd : null,
    yields: incoming.yields && typeof incoming.yields === "object" ? incoming.yields : null,
    checks: Array.isArray(incoming.checks) ? incoming.checks.filter((item) => item && typeof item === "object") : [],
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : []
  };
}

function normalizeMemoryPriceRows(rows) {
  return Array.isArray(rows)
    ? rows
        .filter((row) => row && typeof row === "object" && row.product)
        .map((row) => ({ ...row, product: String(row.product || "") }))
    : [];
}

function normalizeMemoryPriceSection(value) {
  const incoming = normalizeRecordMap(value);
  return {
    updatedAt: incoming.updatedAt || "",
    period: incoming.period || "",
    rows: normalizeMemoryPriceRows(incoming.rows)
  };
}

function normalizeMemoryMarketSnapshot(value) {
  const incoming = normalizeRecordMap(value);
  return {
    source: incoming.source || "TrendForce Price",
    sourceTier: incoming.sourceTier || "Tier 2 市場資料",
    sourceUrl: incoming.sourceUrl || MEMORY_PRICE_URL,
    fetchedAt: incoming.fetchedAt || null,
    asOf: incoming.asOf || "",
    fallbackUsed: incoming.fallbackUsed === true,
    confidence: incoming.confidence || "",
    note: incoming.note || "",
    spot: normalizeMemoryPriceSection(incoming.spot),
    contract: normalizeMemoryPriceSection(incoming.contract),
    module: normalizeMemoryPriceSection(incoming.module),
    nandSpot: normalizeMemoryPriceSection(incoming.nandSpot),
    nandContract: normalizeMemoryPriceSection(incoming.nandContract),
    nandWafer: normalizeMemoryPriceSection(incoming.nandWafer),
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : []
  };
}

function memorySnapshotTime(snapshot) {
  const candidates = [
    snapshot?.fetchedAt,
    snapshot?.asOf,
    snapshot?.spot?.updatedAt,
    snapshot?.contract?.updatedAt,
    snapshot?.module?.updatedAt,
    snapshot?.nandSpot?.updatedAt,
    snapshot?.nandWafer?.updatedAt
  ];
  for (const value of candidates) {
    const raw = String(value || "").replace(" GMT+8", "+08:00");
    const time = Date.parse(raw);
    if (Number.isFinite(time)) return time;
  }
  return 0;
}

function memorySnapshotHistoryKey(snapshot) {
  const firstAverage = (section) => toNumber(snapshot?.[section]?.rows?.[0]?.average);
  return [
    snapshot?.asOf || "",
    snapshot?.spot?.updatedAt || "",
    snapshot?.contract?.updatedAt || "",
    snapshot?.module?.updatedAt || "",
    snapshot?.nandSpot?.updatedAt || "",
    snapshot?.nandWafer?.updatedAt || "",
    firstAverage("spot"),
    firstAverage("contract"),
    firstAverage("module"),
    firstAverage("nandSpot"),
    firstAverage("nandWafer")
  ].join("|");
}

function normalizeMemoryMarketHistory(rows) {
  const seen = new Map();
  for (const row of Array.isArray(rows) ? rows : []) {
    const snapshot = normalizeMemoryMarketSnapshot(row);
    const key = memorySnapshotHistoryKey(snapshot);
    if (!key.replace(/\|/g, "")) continue;
    seen.set(key, snapshot);
  }
  return [...seen.values()]
    .sort((a, b) => memorySnapshotTime(a) - memorySnapshotTime(b))
    .slice(-90);
}

function mergeMemorySnapshotHistory(history, snapshot) {
  return normalizeMemoryMarketHistory([
    ...(Array.isArray(history) ? history : []),
    snapshot
  ]);
}

function normalizeMemoryMarketCache(value) {
  const incoming = normalizeRecordMap(value);
  return {
    ts: Number(incoming.ts) || 0,
    fetchedAt: incoming.fetchedAt || null,
    snapshot: incoming.snapshot && typeof incoming.snapshot === "object" ? normalizeMemoryMarketSnapshot(incoming.snapshot) : null,
    history: normalizeMemoryMarketHistory(incoming.history),
    errors: Array.isArray(incoming.errors) ? incoming.errors.map((item) => String(item || "")).filter(Boolean) : []
  };
}

function activeEtfSnapshotCount(snapshots = state.activeEtf?.snapshots || {}) {
  return Object.values(normalizeRecordMap(snapshots)).reduce((sum, rows) => {
    return sum + (Array.isArray(rows) ? rows.length : 0);
  }, 0);
}

function mergeActiveEtfPayload(payload, sourceLabel = "", options = {}) {
  const incoming = normalizeRecordMap(payload);
  const snapshots = normalizeActiveEtfSnapshotsMap(incoming.snapshots);
  const current = normalizeActiveEtfState(state.activeEtf);
  const incomingCount = activeEtfSnapshotCount(snapshots);
  const shouldReplace = options.replace === true && (incomingCount > 0 || options.allowEmptyReplace === true);
  state.activeEtf = {
    ...current,
    snapshots: shouldReplace ? snapshots : { ...current.snapshots, ...snapshots },
    sourcePath: sourceLabel || current.sourcePath || ACTIVE_TWETF_SOURCE_PATH,
    loadedAt: new Date().toISOString(),
    importedAt: options.imported === true ? new Date().toISOString() : current.importedAt,
    generatedAt: incoming.generatedAt || current.generatedAt,
    lastSuccessAt: incoming.lastSuccessAt || current.lastSuccessAt,
    lastFailedAt: incoming.lastFailedAt || current.lastFailedAt,
    lastFailureMessage: incoming.lastFailureMessage || current.lastFailureMessage || "",
    diagnostics: { ...current.diagnostics, ...normalizeActiveEtfDiagnosticsMap(incoming.diagnostics) }
  };
  return incomingCount;
}

