// ─── File System Sync（跨裝置 Google Drive 同步） ────────────────────────
// 使用 File System Access API：使用者選一次 data/ 資料夾後，
// loadState / saveState 自動讀寫 state.json，Google Drive 自動同步。

let _fsSyncDir = null; // FileSystemDirectoryHandle | null

async function _idb(mode, fn) {
  return new Promise((res, rej) => {
    const req = indexedDB.open("twStockFS_v1", 1);
    req.onupgradeneeded = (e) => e.target.result.createObjectStore("h");
    req.onsuccess = (e) => {
      try {
        const tx = e.target.result.transaction("h", mode);
        const r = fn(tx.objectStore("h"));
        if (r) { r.onsuccess = () => res(r.result); r.onerror = () => rej(r.error); }
        else { tx.oncomplete = () => res(true); tx.onerror = () => rej(tx.error); }
      } catch (err) { rej(err); }
    };
    req.onerror = () => rej(req.error);
  });
}

async function initFSSync() {
  try {
    const h = await _idb("readonly", (s) => s.get("dir"));
    if (!h) return;
    const perm = await h.queryPermission({ mode: "readwrite" });
    if (perm === "granted") { _fsSyncDir = h; return; }
    if ((await h.requestPermission({ mode: "readwrite" })) === "granted") _fsSyncDir = h;
  } catch (_) {}
}

async function chooseSyncDir() {
  if (!window.showDirectoryPicker) {
    alert("此瀏覽器不支援 File System Access API，請使用 Chrome 86+。");
    return false;
  }
  try {
    const h = await window.showDirectoryPicker({ mode: "readwrite" });
    await _idb("readwrite", (s) => s.put(h, "dir"));
    _fsSyncDir = h;
    return true;
  } catch (_) { return false; }
}

async function clearSyncDir() {
  _fsSyncDir = null;
  try { await _idb("readwrite", (s) => s.delete("dir")); } catch (_) {}
}

async function readStateFile() {
  if (!_fsSyncDir) return null;
  try {
    const fh = await _fsSyncDir.getFileHandle("state.json");
    return JSON.parse(await (await fh.getFile()).text());
  } catch (_) { return null; }
}

async function writeStateFile(payload) {
  if (!_fsSyncDir) return;
  try {
    const fh = await _fsSyncDir.getFileHandle("state.json", { create: true });
    const w = await fh.createWritable();
    await w.write(JSON.stringify(payload));
    await w.close();
  } catch (_) {}
}

async function readResearchDataFile() {
  if (!_fsSyncDir) return null;
  try {
    const fh = await _fsSyncDir.getFileHandle(RESEARCH_DATA_SYNC_FILE_NAME);
    return JSON.parse(await (await fh.getFile()).text());
  } catch (_) {
    return null;
  }
}

async function writeResearchDataFile(payload) {
  if (!_fsSyncDir) return false;
  try {
    const fh = await _fsSyncDir.getFileHandle(RESEARCH_DATA_SYNC_FILE_NAME, { create: true });
    const writable = await fh.createWritable();
    await writable.write(JSON.stringify(payload, null, 2));
    await writable.close();
    return true;
  } catch (error) {
    console.warn("writeResearchDataFile skipped", error);
    return false;
  }
}

function fsSyncDirName() {
  return _fsSyncDir ? (_fsSyncDir.name || "已設定") : null;
}

// ─── v7.8 Feature 7：IndexedDB K 線快取分層 ───────────────────────────────────
// 將 K 線資料移到 IDB 解放 chrome.storage.local 配額；現階段採「雙寫」策略，
// state.klines 仍維持，IDB 是備援/長期儲存層。
const KLINE_IDB_NAME = "twStockKlines_v1";
const KLINE_IDB_STORE = "klines";

function _klineIdbOpen() {
  return new Promise((resolve, reject) => {
    let req;
    try { req = indexedDB.open(KLINE_IDB_NAME, 1); } catch (err) { reject(err); return; }
    req.onupgradeneeded = (e) => {
      const db = e.target.result;
      if (!db.objectStoreNames.contains(KLINE_IDB_STORE)) {
        db.createObjectStore(KLINE_IDB_STORE);
      }
    };
    req.onsuccess = (e) => resolve(e.target.result);
    req.onerror = (e) => reject(e.target.error);
  });
}

async function klineIdbSet(code, rows) {
  try {
    const db = await _klineIdbOpen();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(KLINE_IDB_STORE, "readwrite");
      tx.objectStore(KLINE_IDB_STORE).put(rows, code);
      tx.oncomplete = () => resolve(true);
      tx.onerror = () => reject(tx.error);
    });
  } catch (_) { return false; }
}

const _pendingKlineIdbWrites = new Set();

function persistKlinesToIdb(code, rows) {
  const promise = klineIdbSet(code, rows)
    .catch(() => false)
    .finally(() => _pendingKlineIdbWrites.delete(promise));
  _pendingKlineIdbWrites.add(promise);
  return promise;
}

async function flushPendingKlineIdbWrites() {
  if (!_pendingKlineIdbWrites.size) return;
  await Promise.allSettled(Array.from(_pendingKlineIdbWrites));
}

async function klineIdbGet(code) {
  try {
    const db = await _klineIdbOpen();
    return new Promise((resolve) => {
      const tx = db.transaction(KLINE_IDB_STORE, "readonly");
      const req = tx.objectStore(KLINE_IDB_STORE).get(code);
      req.onsuccess = () => resolve(req.result || null);
      req.onerror = () => resolve(null);
    });
  } catch (_) { return null; }
}

async function klineIdbAll() {
  try {
    const db = await _klineIdbOpen();
    return new Promise((resolve) => {
      const tx = db.transaction(KLINE_IDB_STORE, "readonly");
      const result = {};
      const store = tx.objectStore(KLINE_IDB_STORE);
      const req = store.openCursor();
      req.onsuccess = (e) => {
        const cursor = e.target.result;
        if (cursor) {
          result[cursor.key] = cursor.value;
          cursor.continue();
        } else {
          resolve(result);
        }
      };
      req.onerror = () => resolve({});
    });
  } catch (_) { return {}; }
}

function compactKlineRows(rows) {
  return (Array.isArray(rows) ? rows : [])
    .slice(-KLINE_RETENTION_BARS)
    .map((row) => ({
      ...row,
      source: row.source || "K 線快取"
    }));
}

function normalizeKlineStorageMeta(value) {
  const incoming = normalizeRecordMap(value);
  return {
    mode: incoming.mode || KLINE_HOT_STORAGE_MODE,
    inlineLimit: Number(incoming.inlineLimit) || KLINE_STATE_INLINE_LIMIT,
    inlineCount: Number(incoming.inlineCount) || 0,
    totalInMemory: Number(incoming.totalInMemory) || 0,
    updatedAt: incoming.updatedAt || null,
    lastHydratedAt: incoming.lastHydratedAt || null,
    lastHydratedCount: Number(incoming.lastHydratedCount) || 0
  };
}

function addHotKlineCode(list, seen, code) {
  const value = String(code || "").trim();
  if (!value || seen.has(value) || list.length >= KLINE_STATE_INLINE_LIMIT) return;
  seen.add(value);
  list.push(value);
}

function currentThemeKlineCodes() {
  const filter = state?.filter || HOLDINGS_THEME_KEY;
  const theme = THEME_MEMBERS.find((item) => item.key === filter);
  if (theme?.codes?.length) return theme.codes;
  if (filter === HOLDINGS_THEME_KEY) return (state.holdings || []).map((entry) => entry.code);
  if (state.customGroups?.[filter]?.codes) return state.customGroups[filter].codes;
  return [];
}

function hotKlineCodes() {
  const list = [];
  const seen = new Set();
  addHotKlineCode(list, seen, TAIEX_CODE);
  addHotKlineCode(list, seen, "^TWXT");
  addHotKlineCode(list, seen, "^TWTSC");
  addHotKlineCode(list, seen, state.selectedCode);
  const holdings = Array.isArray(state.holdings) && state.holdings.length ? state.holdings : currentHoldingsSeedCopy();
  for (const holding of holdings) addHotKlineCode(list, seen, holding.code);
  for (const code of currentThemeKlineCodes()) addHotKlineCode(list, seen, code);
  for (const code of Object.keys(state.klines || {})) addHotKlineCode(list, seen, code);
  return list;
}

function selectInlineKlines(sourceMap, extraCodes = []) {
  const source = normalizeRecordMap(sourceMap);
  const codes = Object.keys(source);
  const keepCodes = codes.length <= KLINE_STATE_INLINE_LIMIT
    ? codes
    : uniqueList([...extraCodes.map((code) => String(code || "").trim()).filter(Boolean), ...hotKlineCodes()]).slice(0, KLINE_STATE_INLINE_LIMIT);
  const payload = {};
  for (const code of keepCodes) {
    const rows = compactKlineRows(source[code]);
    if (rows.length) payload[code] = rows;
  }
  return payload;
}

function buildStateKlinePayload() {
  return selectInlineKlines(state.klines);
}

function buildKlineStorageMeta(inlineKlines) {
  return {
    mode: KLINE_HOT_STORAGE_MODE,
    inlineLimit: KLINE_STATE_INLINE_LIMIT,
    inlineCount: Object.keys(inlineKlines || {}).length,
    totalInMemory: Object.keys(state.klines || {}).length,
    updatedAt: new Date().toISOString(),
    lastHydratedAt: state.klineStorage?.lastHydratedAt || null,
    lastHydratedCount: state.klineStorage?.lastHydratedCount || 0
  };
}

function normalizeHeavyCacheStorageMeta(value) {
  const incoming = normalizeRecordMap(value);
  return {
    mode: incoming.mode || HEAVY_CACHE_STORAGE_MODE,
    codeLimit: Number(incoming.codeLimit) || HOT_CACHE_CODE_LIMIT,
    snapshotRowsPerCode: Number(incoming.snapshotRowsPerCode) || SNAPSHOT_STATE_ROWS_PER_CODE,
    institutionalRowsPerCode: Number(incoming.institutionalRowsPerCode) || INSTITUTIONAL_STATE_HISTORY_ROWS,
    foreignOwnershipRowsPerCode: Number(incoming.foreignOwnershipRowsPerCode) || FOREIGN_OWNERSHIP_HISTORY_ROWS,
    activeEtfSnapshotsPerCode: Number(incoming.activeEtfSnapshotsPerCode) || ACTIVE_ETF_STATE_SNAPSHOT_LIMIT,
    snapshotInlineCount: Number(incoming.snapshotInlineCount) || 0,
    snapshotTotalInMemory: Number(incoming.snapshotTotalInMemory) || 0,
    institutionalInlineCount: Number(incoming.institutionalInlineCount) || 0,
    institutionalTotalInMemory: Number(incoming.institutionalTotalInMemory) || 0,
    foreignOwnershipHistoryInlineCount: Number(incoming.foreignOwnershipHistoryInlineCount) || 0,
    foreignOwnershipHistoryTotalInMemory: Number(incoming.foreignOwnershipHistoryTotalInMemory) || 0,
    activeEtfSnapshotInlineCount: Number(incoming.activeEtfSnapshotInlineCount) || 0,
    activeEtfSnapshotTotalInMemory: Number(incoming.activeEtfSnapshotTotalInMemory) || 0,
    updatedAt: incoming.updatedAt || null
  };
}

function rowTimestamp(row) {
  if (!row || typeof row !== "object") return 0;
  const raw = row.capturedAt || row.fetchedAt || row.marketTime || row.sourceDate || row.date || row.startedAt || row.finishedAt || "";
  const parsed = Date.parse(raw);
  return Number.isFinite(parsed) ? parsed : 0;
}

function latestRowsPreserveOrder(rows, limit) {
  const input = Array.isArray(rows) ? rows : [];
  const max = Math.max(0, Number(limit) || 0);
  if (!max || input.length <= max) return input.slice();
  const keep = new Set(input
    .map((row, index) => ({ index, ts: rowTimestamp(row) }))
    .sort((a, b) => b.ts - a.ts || b.index - a.index)
    .slice(0, max)
    .map((item) => item.index));
  return input.filter((_, index) => keep.has(index));
}

function addHotCacheCode(list, seen, code, limit = HOT_CACHE_CODE_LIMIT) {
  const value = String(code || "").trim();
  if (!value || seen.has(value) || list.length >= limit) return;
  seen.add(value);
  list.push(value);
}

function hotCacheCodes(limit = HOT_CACHE_CODE_LIMIT) {
  return hotCacheCodesForPayload(state, limit);
}

function themeCodesForPayload(payload) {
  const filter = payload?.filter || HOLDINGS_THEME_KEY;
  const theme = THEME_MEMBERS.find((item) => item.key === filter);
  if (theme?.codes?.length) return theme.codes;
  if (filter === HOLDINGS_THEME_KEY) return (payload?.holdings || state.holdings || []).map((entry) => entry.code);
  if (payload?.customGroups?.[filter]?.codes) return payload.customGroups[filter].codes;
  if (state.customGroups?.[filter]?.codes) return state.customGroups[filter].codes;
  return [];
}

function hotCacheCodesForPayload(payload, limit = HOT_CACHE_CODE_LIMIT) {
  const list = [];
  const seen = new Set();
  addHotCacheCode(list, seen, payload?.selectedCode || state.selectedCode, limit);
  const holdings = Array.isArray(payload?.holdings) && payload.holdings.length
    ? payload.holdings
    : (Array.isArray(state.holdings) && state.holdings.length ? state.holdings : currentHoldingsSeedCopy());
  for (const holding of holdings) addHotCacheCode(list, seen, typeof holding === "string" ? holding : holding?.code, limit);
  for (const code of themeCodesForPayload(payload)) addHotCacheCode(list, seen, code, limit);
  addHotCacheCode(list, seen, TAIEX_CODE, limit);
  return list;
}

function selectHotRecordMap(sourceMap, limit, transform) {
  return selectHotRecordMapForPayload(sourceMap, state, limit, transform);
}

function selectHotRecordMapForPayload(sourceMap, sourcePayload, limit, transform) {
  const source = normalizeRecordMap(sourceMap);
  const sourceCodes = Object.keys(source);
  const keepCodes = uniqueList([...hotCacheCodesForPayload(sourcePayload, limit), ...sourceCodes]).slice(0, limit);
  const result = {};
  for (const code of keepCodes) {
    if (source[code] === undefined) continue;
    const value = typeof transform === "function" ? transform(source[code], code) : source[code];
    if (Array.isArray(value) && !value.length) continue;
    if (value && typeof value === "object" && !Array.isArray(value) && !Object.keys(value).length) continue;
    if (value !== undefined && value !== null) result[code] = value;
  }
  return result;
}

function trimInstitutionalRecordForState(row) {
  const normalized = normalizeInstitutionalRecord(row);
  if (!normalized) return null;
  return {
    ...normalized,
    history: latestRowsPreserveOrder(normalized.history, INSTITUTIONAL_STATE_HISTORY_ROWS)
  };
}

function buildStateSnapshotPayload() {
  return selectHotRecordMap(
    state.snapshots,
    HOT_CACHE_CODE_LIMIT,
    (rows) => latestRowsPreserveOrder(rows, SNAPSHOT_STATE_ROWS_PER_CODE)
  );
}

function buildStateInstitutionalPayload() {
  return selectHotRecordMap(
    state.institutional,
    INSTITUTIONAL_STATE_INLINE_LIMIT,
    (row) => trimInstitutionalRecordForState(row)
  );
}

function buildStateForeignOwnershipHistoryPayload() {
  return selectHotRecordMap(
    state.foreignOwnershipHistory,
    FOREIGN_OWNERSHIP_HISTORY_INLINE_LIMIT,
    (rows) => latestRowsPreserveOrder(rows, FOREIGN_OWNERSHIP_HISTORY_ROWS)
  );
}

function buildStateTdccHistoryPayload() {
  return selectHotRecordMap(
    state.tdccHistory,
    HOT_CACHE_CODE_LIMIT,
    (rows) => latestRowsPreserveOrder(rows, FOREIGN_OWNERSHIP_HISTORY_ROWS)
  );
}

function buildActiveEtfPayloadForState(value) {
  const current = normalizeActiveEtfState(value);
  const snapshots = {};
  for (const [code, rows] of Object.entries(current.snapshots || {})) {
    const trimmed = latestRowsPreserveOrder(rows, ACTIVE_ETF_STATE_SNAPSHOT_LIMIT);
    if (trimmed.length) snapshots[code] = trimmed;
  }
  return { ...current, snapshots };
}

function buildStateActiveEtfPayload() {
  return buildActiveEtfPayloadForState(state.activeEtf);
}

function buildHeavyCacheStorageMeta({ snapshots, institutional, foreignOwnershipHistory, activeEtf }) {
  const activeEtfSnapshots = normalizeRecordMap(activeEtf?.snapshots || {});
  return {
    mode: HEAVY_CACHE_STORAGE_MODE,
    codeLimit: HOT_CACHE_CODE_LIMIT,
    snapshotRowsPerCode: SNAPSHOT_STATE_ROWS_PER_CODE,
    institutionalRowsPerCode: INSTITUTIONAL_STATE_HISTORY_ROWS,
    foreignOwnershipRowsPerCode: FOREIGN_OWNERSHIP_HISTORY_ROWS,
    activeEtfSnapshotsPerCode: ACTIVE_ETF_STATE_SNAPSHOT_LIMIT,
    snapshotInlineCount: Object.keys(snapshots || {}).length,
    snapshotTotalInMemory: Object.keys(state.snapshots || {}).length,
    institutionalInlineCount: Object.keys(institutional || {}).length,
    institutionalTotalInMemory: Object.keys(state.institutional || {}).length,
    foreignOwnershipHistoryInlineCount: Object.keys(foreignOwnershipHistory || {}).length,
    foreignOwnershipHistoryTotalInMemory: Object.keys(state.foreignOwnershipHistory || {}).length,
    activeEtfSnapshotInlineCount: Object.values(activeEtfSnapshots).reduce((sum, rows) => sum + (Array.isArray(rows) ? rows.length : 0), 0),
    activeEtfSnapshotTotalInMemory: Object.values(normalizeRecordMap(state.activeEtf?.snapshots || {})).reduce((sum, rows) => sum + (Array.isArray(rows) ? rows.length : 0), 0),
    updatedAt: new Date().toISOString()
  };
}

function buildHeavyCacheStorageMetaForPayload(sourcePayload, { snapshots, institutional, foreignOwnershipHistory, activeEtf }) {
  const sourceActiveEtfSnapshots = normalizeRecordMap(sourcePayload?.activeEtf?.snapshots || {});
  const activeEtfSnapshots = normalizeRecordMap(activeEtf?.snapshots || {});
  return {
    mode: HEAVY_CACHE_STORAGE_MODE,
    codeLimit: HOT_CACHE_CODE_LIMIT,
    snapshotRowsPerCode: SNAPSHOT_STATE_ROWS_PER_CODE,
    institutionalRowsPerCode: INSTITUTIONAL_STATE_HISTORY_ROWS,
    foreignOwnershipRowsPerCode: FOREIGN_OWNERSHIP_HISTORY_ROWS,
    activeEtfSnapshotsPerCode: ACTIVE_ETF_STATE_SNAPSHOT_LIMIT,
    snapshotInlineCount: Object.keys(snapshots || {}).length,
    snapshotTotalInMemory: Number(sourcePayload?.heavyCacheStorage?.snapshotTotalInMemory) || Object.keys(sourcePayload?.snapshots || {}).length,
    institutionalInlineCount: Object.keys(institutional || {}).length,
    institutionalTotalInMemory: Number(sourcePayload?.heavyCacheStorage?.institutionalTotalInMemory) || Object.keys(sourcePayload?.institutional || {}).length,
    foreignOwnershipHistoryInlineCount: Object.keys(foreignOwnershipHistory || {}).length,
    foreignOwnershipHistoryTotalInMemory: Number(sourcePayload?.heavyCacheStorage?.foreignOwnershipHistoryTotalInMemory) || Object.keys(sourcePayload?.foreignOwnershipHistory || {}).length,
    activeEtfSnapshotInlineCount: Object.values(activeEtfSnapshots).reduce((sum, rows) => sum + (Array.isArray(rows) ? rows.length : 0), 0),
    activeEtfSnapshotTotalInMemory: Number(sourcePayload?.heavyCacheStorage?.activeEtfSnapshotTotalInMemory) || Object.values(sourceActiveEtfSnapshots).reduce((sum, rows) => sum + (Array.isArray(rows) ? rows.length : 0), 0),
    updatedAt: sourcePayload?.heavyCacheStorage?.updatedAt || sourcePayload?.savedAt || sourcePayload?.lastUpdated || null
  };
}

let _bulkKlineIdbPersistTimer = null;
let _bulkKlineIdbPersistRunning = false;

function scheduleBulkKlineIdbPersist(sourceMap, label = "state") {
  if (typeof indexedDB === "undefined" || _bulkKlineIdbPersistTimer || _bulkKlineIdbPersistRunning) return;
  const entries = Object.entries(normalizeRecordMap(sourceMap))
    .filter(([, rows]) => Array.isArray(rows) && rows.length);
  if (!entries.length) return;
  const run = () => {
    _bulkKlineIdbPersistTimer = null;
    _bulkKlineIdbPersistRunning = true;
    (async () => {
      let count = 0;
      for (const [code, rows] of entries) {
        if (await klineIdbSet(code, compactKlineRows(rows))) count++;
        if (count && count % 40 === 0) await wait(0);
      }
      state.klineStorage = {
        ...normalizeKlineStorageMeta(state.klineStorage),
        mode: KLINE_HOT_STORAGE_MODE,
        updatedAt: new Date().toISOString()
      };
      console.info(`K line ${label} migration persisted ${count}/${entries.length} to IndexedDB`);
    })()
      .catch((error) => console.warn("bulk K line IDB persist skipped", error))
      .finally(() => { _bulkKlineIdbPersistRunning = false; });
  };
  if (typeof window !== "undefined" && typeof window.requestIdleCallback === "function") {
    _bulkKlineIdbPersistTimer = window.requestIdleCallback(run, { timeout: 2500 });
  } else {
    _bulkKlineIdbPersistTimer = setTimeout(run, 800);
  }
}

function slimStatePayloadForMemory(payload, label = "state") {
  if (!payload || typeof payload !== "object") return payload;
  const klines = normalizeRecordMap(payload.klines);
  if (Object.keys(klines).length > KLINE_STATE_INLINE_LIMIT) {
    scheduleBulkKlineIdbPersist(klines, label);
  }
  const extraCodes = [
    payload.selectedCode,
    ...(Array.isArray(payload.holdings) ? payload.holdings.map((entry) => entry?.code) : [])
  ];
  const inlineKlines = selectInlineKlines(klines, extraCodes);
  const totalInMemory = Math.max(Object.keys(klines).length, Number(payload.klineStorage?.totalInMemory) || 0);
  const inlineSnapshots = selectHotRecordMapForPayload(
    payload.snapshots,
    payload,
    HOT_CACHE_CODE_LIMIT,
    (rows) => latestRowsPreserveOrder(rows, SNAPSHOT_STATE_ROWS_PER_CODE)
  );
  const inlineInstitutional = selectHotRecordMapForPayload(
    payload.institutional,
    payload,
    INSTITUTIONAL_STATE_INLINE_LIMIT,
    (row) => trimInstitutionalRecordForState(row)
  );
  const inlineForeignOwnershipHistory = selectHotRecordMapForPayload(
    payload.foreignOwnershipHistory,
    payload,
    FOREIGN_OWNERSHIP_HISTORY_INLINE_LIMIT,
    (rows) => latestRowsPreserveOrder(rows, FOREIGN_OWNERSHIP_HISTORY_ROWS)
  );
  const inlineTdccHistory = selectHotRecordMapForPayload(
    payload.tdccHistory,
    payload,
    HOT_CACHE_CODE_LIMIT,
    (rows) => latestRowsPreserveOrder(rows, FOREIGN_OWNERSHIP_HISTORY_ROWS)
  );
  const inlineActiveEtf = buildActiveEtfPayloadForState(payload.activeEtf);
  return {
    ...payload,
    snapshots: inlineSnapshots,
    klines: inlineKlines,
    klineStorage: {
      ...normalizeKlineStorageMeta(payload.klineStorage),
      mode: KLINE_HOT_STORAGE_MODE,
      inlineLimit: KLINE_STATE_INLINE_LIMIT,
      inlineCount: Object.keys(inlineKlines).length,
      totalInMemory,
      updatedAt: payload.klineStorage?.updatedAt || payload.klineUpdatedAt || payload.savedAt || null
    },
    heavyCacheStorage: buildHeavyCacheStorageMetaForPayload(payload, {
      snapshots: inlineSnapshots,
      institutional: inlineInstitutional,
      foreignOwnershipHistory: inlineForeignOwnershipHistory,
      activeEtf: inlineActiveEtf
    }),
    institutional: inlineInstitutional,
    foreignOwnershipHistory: inlineForeignOwnershipHistory,
    tdccHistory: inlineTdccHistory,
    activeEtf: inlineActiveEtf
  };
}

let _klineHydrationQueue = new Set();
let _klineHydrationTimer = null;
let _klineHydrationRunning = false;

function queueKlineHydration(codes, reason = "lazy") {
  if (typeof indexedDB === "undefined") return;
  for (const code of codes || []) {
    const value = String(code || "").trim();
    if (!value) continue;
    if (Array.isArray(state.klines?.[value]) && state.klines[value].length) continue;
    _klineHydrationQueue.add(value);
  }
  if (!_klineHydrationQueue.size || _klineHydrationTimer || _klineHydrationRunning) return;
  const run = () => {
    _klineHydrationTimer = null;
    hydrateQueuedKlinesFromIdb(reason).catch((error) => console.warn("K line lazy hydration skipped", error));
  };
  if (typeof window !== "undefined" && typeof window.requestIdleCallback === "function") {
    _klineHydrationTimer = window.requestIdleCallback(run, { timeout: 1500 });
  } else {
    _klineHydrationTimer = setTimeout(run, 250);
  }
}

async function hydrateKlinesFromIdbForCodes(codes, options = {}) {
  const wanted = uniqueList((codes || []).map((code) => String(code || "").trim()).filter(Boolean))
    .filter((code) => options.force === true || !(Array.isArray(state.klines?.[code]) && state.klines[code].length))
    .slice(0, options.limit || KLINE_IDB_HYDRATE_BATCH_LIMIT);
  if (!wanted.length) return 0;
  let count = 0;
  for (const code of wanted) {
    const rows = await klineIdbGet(code);
    if (Array.isArray(rows) && rows.length) {
      state.klines[code] = compactKlineRows(rows);
      count++;
    }
  }
  if (count) {
    state.klineStorage = {
      ...normalizeKlineStorageMeta(state.klineStorage),
      lastHydratedAt: new Date().toISOString(),
      lastHydratedCount: count,
      totalInMemory: Object.keys(state.klines || {}).length
    };
    if (options.render !== false && typeof document !== "undefined" && document.body) render({ scope: "active" });
  }
  return count;
}

async function hydrateQueuedKlinesFromIdb(reason = "lazy") {
  if (_klineHydrationRunning || !_klineHydrationQueue.size) return 0;
  _klineHydrationRunning = true;
  const batch = Array.from(_klineHydrationQueue).slice(0, KLINE_IDB_HYDRATE_BATCH_LIMIT);
  batch.forEach((code) => _klineHydrationQueue.delete(code));
  try {
    const count = await hydrateKlinesFromIdbForCodes(batch, { render: true });
    if (count) console.info(`K line ${reason} hydration loaded ${count}/${batch.length}`);
    return count;
  } finally {
    _klineHydrationRunning = false;
    if (_klineHydrationQueue.size) queueKlineHydration([], reason);
  }
}

function scheduleStartupKlineHydration() {
  queueKlineHydration(hotKlineCodes(), "startup");
}

async function migrateKlinesToIdb() {
  setStatus("K 線資料遷移到 IndexedDB...");
  const klines = state.klines || {};
  const entries = Object.entries(klines);
  if (!entries.length) {
    setStatus("尚無 K 線資料可同步", "warn");
    return 0;
  }
  let count = 0;
  for (const [code, rows] of entries) {
    if (!Array.isArray(rows) || !rows.length) continue;
    const ok = await klineIdbSet(code, rows);
    if (ok) count++;
  }
  setStatus(`已同步 ${count} 檔 K 線至 IndexedDB`, "good");
  return count;
}

async function hydrateKlinesFromIdb() {
  setStatus("從 IndexedDB 還原 K 線...");
  const data = await klineIdbAll();
  let count = 0;
  for (const [code, rows] of Object.entries(data)) {
    if (Array.isArray(rows) && rows.length) {
      state.klines[code] = compactKlineRows(rows);
      count++;
    }
  }
  state.klineStorage = {
    ...normalizeKlineStorageMeta(state.klineStorage),
    lastHydratedAt: new Date().toISOString(),
    lastHydratedCount: count,
    totalInMemory: Object.keys(state.klines || {}).length
  };
  if (count) await saveState();
  setStatus(`已還原 ${count} 檔 K 線`, count ? "good" : "warn");
  return count;
}

function renderStorageMigrationPanel() {
  const klineCount = Object.keys(state.klines || {}).length;
  const meta = normalizeKlineStorageMeta(state.klineStorage);
  const totalText = meta.totalInMemory && meta.totalInMemory > klineCount ? ` / 原始 ${formatNumber(meta.totalInMemory, 0)} 檔` : "";
  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <h3 style="margin:0 0 6px;font-size:1rem;">儲存層管理</h3>
      <p style="color:var(--muted);font-size:0.78rem;margin:0 0 8px;">目前 K 線 hot cache：${formatNumber(klineCount, 0)} 檔${totalText}；完整 K 線優先放 IndexedDB，chrome.storage / state.json 只保留常用 subset。月營收歷史與季報三率另存 IndexedDB，設定 data/ 後同步 ${escapeHtml(RESEARCH_DATA_SYNC_FILE_NAME)}。</p>
      <div class="link-row">
        <button id="migrateKlinesIdbBtn" class="secondary-btn" type="button">同步 K 線到 IndexedDB</button>
        <button id="hydrateKlinesIdbBtn" class="ghost-btn" type="button">從 IndexedDB 還原</button>
      </div>
    </div>
  `;
}

const STATE_CACHE_MAP_KEYS = [
  "quotes",
  "snapshots",
  "klines",
  "valuations",
  "valuationMeta",
  "marketCaps",
  "marketCapMeta",
  "institutional",
  "margin",
  "tdcc",
  "foreignOwnership",
  "foreignOwnershipHistory",
  "revenue",
  "errors"
];

let _cacheLoadInfo = {
  source: "預設",
  seedApplied: false,
  seedLabel: "",
  seedMessage: ""
};

function stateMapCount(payload, key) {
  const value = payload && payload[key];
  if (!value || typeof value !== "object") return 0;
  if (Array.isArray(value)) return value.length;
  return Object.keys(value).length;
}

function stateActiveEtfCount(payload) {
  const snapshots = normalizeRecordMap(payload?.activeEtf?.snapshots || {});
  return Object.values(snapshots).reduce((sum, rows) => sum + (Array.isArray(rows) ? rows.length : 0), 0);
}

function stateDataFootprint(payload) {
  if (!payload || typeof payload !== "object") return 0;
  return STATE_CACHE_MAP_KEYS.reduce((sum, key) => sum + stateMapCount(payload, key), 0)
    + stateActiveEtfCount(payload)
    + stateMapCount(payload?.dividends, "records")
    + (Array.isArray(payload?.exDividendCalendar?.rows) ? payload.exDividendCalendar.rows.length : 0)
    + (payload.marketDashboardCache ? 1 : 0)
    + (payload.tideSectorCache ? 1 : 0)
    + (payload.marketInstitutionalRankings ? 1 : 0)
    + (payload.memoryMarketCache ? 1 : 0)
    + (payload.taifex ? 1 : 0);
}

function statePayloadTime(payload) {
  const candidates = [
    payload?.lastUpdated,
    payload?.klineUpdatedAt,
    payload?.activeEtf?.lastSuccessAt,
    payload?.activeEtf?.loadedAt,
    payload?.activeEtf?.generatedAt,
    payload?.dividends?.fetchedAt,
    payload?.exDividendCalendar?.fetchedAt,
    payload?.marketDashboardCache?.fetchedAt,
    payload?.tideSectorCache?.fetchedAt,
    payload?.marketInstitutionalRankings?.fetchedAt,
    payload?.memoryMarketCache?.fetchedAt,
    payload?.savedAt
  ].map((value) => Date.parse(value || "")).filter(Number.isFinite);
  return candidates.length ? Math.max(...candidates) : 0;
}

function mergeCacheMap(current, incoming, preferIncoming = false) {
  const next = { ...normalizeRecordMap(current) };
  for (const [key, value] of Object.entries(normalizeRecordMap(incoming))) {
    if (preferIncoming || next[key] === undefined) next[key] = value;
  }
  return next;
}

function mergeActiveEtfCache(current, incoming, preferIncoming = false) {
  const currentEtf = normalizeActiveEtfState(current);
  const incomingEtf = normalizeActiveEtfState(incoming);
  return {
    ...currentEtf,
    snapshots: mergeCacheMap(currentEtf.snapshots, incomingEtf.snapshots, preferIncoming),
    diagnostics: mergeCacheMap(currentEtf.diagnostics, incomingEtf.diagnostics, preferIncoming),
    sourcePath: preferIncoming ? (incomingEtf.sourcePath || currentEtf.sourcePath) : (currentEtf.sourcePath || incomingEtf.sourcePath),
    loadedAt: preferIncoming ? (incomingEtf.loadedAt || currentEtf.loadedAt) : (currentEtf.loadedAt || incomingEtf.loadedAt),
    importedAt: currentEtf.importedAt || incomingEtf.importedAt,
    generatedAt: preferIncoming ? (incomingEtf.generatedAt || currentEtf.generatedAt) : (currentEtf.generatedAt || incomingEtf.generatedAt),
    lastSuccessAt: preferIncoming ? (incomingEtf.lastSuccessAt || currentEtf.lastSuccessAt) : (currentEtf.lastSuccessAt || incomingEtf.lastSuccessAt),
    lastFailedAt: preferIncoming ? (incomingEtf.lastFailedAt || currentEtf.lastFailedAt) : (currentEtf.lastFailedAt || incomingEtf.lastFailedAt),
    lastFailureMessage: currentEtf.lastFailureMessage || incomingEtf.lastFailureMessage || ""
  };
}

function hydrateStateDataCache(incoming, label = "state seed") {
  const incomingCount = stateDataFootprint(incoming);
  if (!incomingCount) return { applied: false, reason: "empty", incomingCount, currentCount: stateDataFootprint(state) };

  const currentCount = stateDataFootprint(state);
  const incomingTime = statePayloadTime(incoming);
  const currentTime = statePayloadTime(state);
  const preferIncoming = currentCount === 0 || (incomingTime && incomingTime > currentTime + 60 * 1000);

  if (!preferIncoming && currentCount >= incomingCount) {
    return { applied: false, reason: "current-newer-or-richer", incomingCount, currentCount };
  }

  const slimIncoming = slimStatePayloadForMemory(incoming, label);
  for (const key of STATE_CACHE_MAP_KEYS) {
    if (key === "klines") continue;
    state[key] = mergeCacheMap(state[key], slimIncoming[key], preferIncoming);
  }
  state.klines = mergeCacheMap(state.klines, slimIncoming.klines, preferIncoming);
  state.klineStorage = normalizeKlineStorageMeta(slimIncoming.klineStorage || state.klineStorage);
  state.activeEtf = mergeActiveEtfCache(state.activeEtf, slimIncoming.activeEtf, preferIncoming);
  if (preferIncoming || !state.taifex) state.taifex = slimIncoming.taifex || state.taifex || null;
  if (preferIncoming || !state.dividends?.fetchedAt) state.dividends = normalizeDividendState(slimIncoming.dividends || state.dividends);
  if (preferIncoming || !state.exDividendCalendar?.fetchedAt) state.exDividendCalendar = normalizeExDividendCalendarState(slimIncoming.exDividendCalendar || state.exDividendCalendar);
  if (preferIncoming || !state.exDividendBehavior?.fetchedAt) state.exDividendBehavior = normalizeExDividendBehaviorState(slimIncoming.exDividendBehavior || state.exDividendBehavior);
  if (preferIncoming || !state.marketDashboardCache?.fetchedAt) state.marketDashboardCache = normalizeMarketDashboardCache(slimIncoming.marketDashboardCache || state.marketDashboardCache);
  if (preferIncoming || !state.tideSectorCache?.fetchedAt) state.tideSectorCache = normalizeTideSectorCache(slimIncoming.tideSectorCache || state.tideSectorCache);
  if (preferIncoming || !state.marketInstitutionalRankings?.fetchedAt) state.marketInstitutionalRankings = normalizeMarketInstitutionalRankings(slimIncoming.marketInstitutionalRankings || state.marketInstitutionalRankings);
  if (preferIncoming || !state.lastUpdated) state.lastUpdated = slimIncoming.lastUpdated || state.lastUpdated || null;
  if (preferIncoming || !state.klineUpdatedAt) state.klineUpdatedAt = slimIncoming.klineUpdatedAt || state.klineUpdatedAt || null;

  return { applied: true, preferIncoming, incomingCount, currentCount, label };
}

async function readBundledStateFile(path = STATE_SEED_PATH) {
  try {
    return await fetchJson(bundledAssetUrl(path));
  } catch (error) {
    console.warn(`readBundledStateFile skipped: ${path}`, error);
    return null;
  }
}

let _bundledStateHydrationScheduled = false;

function applyBundledStateHydration(bundledState, label = STATE_SEED_PATH) {
  if (!bundledState) return false;
  const hydrated = hydrateStateDataCache(bundledState, label);
  if (!hydrated.applied) return false;
  _cacheLoadInfo.seedApplied = true;
  _cacheLoadInfo.seedLabel = label;
  _cacheLoadInfo.seedMessage = `已延後補內建快取 ${hydrated.incomingCount}/${hydrated.currentCount}`;
  persistStateSilently("內建快取延後補資料");
  if (typeof document !== "undefined" && document.body) {
    setStatus(_cacheLoadInfo.seedMessage, "good");
    render({ scope: "active" });
  }
  return true;
}

function scheduleBundledStateHydration() {
  if (_bundledStateHydrationScheduled) return;
  _bundledStateHydrationScheduled = true;
  const run = () => {
    readBundledStateFile(STATE_SEED_PATH)
      .then((bundledState) => applyBundledStateHydration(bundledState, STATE_SEED_PATH))
      .catch((error) => console.warn("deferred bundled state hydration skipped", error));
  };
  const scheduleIdle = () => {
    if (typeof window !== "undefined" && typeof window.requestIdleCallback === "function") {
      window.requestIdleCallback(run, { timeout: 2500 });
    } else {
      setTimeout(run, 800);
    }
  };
  setTimeout(scheduleIdle, STARTUP_DEFER_BUNDLED_STATE_MS);
}

let _perfWorker = null;
let _perfWorkerSeq = 0;
const _perfWorkerPending = new Map();

function perfWorkerUrl() {
  if (typeof chrome !== "undefined" && chrome.runtime?.getURL) {
    return chrome.runtime.getURL("app_files/perf_worker.js");
  }
  if (typeof window !== "undefined" && window.location) {
    return new URL("app_files/perf_worker.js", window.location.href).href;
  }
  return "app_files/perf_worker.js";
}

function getPerfWorker() {
  if (typeof Worker === "undefined") return null;
  if (_perfWorker) return _perfWorker;
  try {
    _perfWorker = new Worker(perfWorkerUrl());
    _perfWorker.addEventListener("message", (event) => {
      const message = event.data || {};
      const pending = _perfWorkerPending.get(message.id);
      if (!pending) return;
      _perfWorkerPending.delete(message.id);
      clearTimeout(pending.timer);
      if (message.ok) pending.resolve(message.value !== undefined ? message.value : message);
      else pending.reject(new Error(message.error || "worker task failed"));
    });
    _perfWorker.addEventListener("error", (error) => {
      for (const [id, pending] of _perfWorkerPending.entries()) {
        clearTimeout(pending.timer);
        pending.reject(error instanceof Error ? error : new Error("worker error"));
        _perfWorkerPending.delete(id);
      }
      try { _perfWorker.terminate(); } catch (_) {}
      _perfWorker = null;
    });
  } catch (_) {
    _perfWorker = null;
  }
  return _perfWorker;
}

function runPerfWorkerTask(type, payload = {}, timeoutMs = 2000) {
  const worker = getPerfWorker();
  if (!worker) return Promise.reject(new Error("Web Worker unavailable"));
  const id = ++_perfWorkerSeq;
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      _perfWorkerPending.delete(id);
      if (!_perfWorkerPending.size && _perfWorker) {
        try { _perfWorker.terminate(); } catch (_) {}
        _perfWorker = null;
      }
      reject(new Error("worker task timeout"));
    }, timeoutMs);
    _perfWorkerPending.set(id, { resolve, reject, timer });
    worker.postMessage({ id, type, payload });
  });
}

function warmPerformanceWorker() {
  return runPerfWorkerTask("ping", { version: APP_VERSION }, 3000)
    .then(() => {
      state.performance = {
        ...(state.performance || {}),
        worker: { available: true, checkedAt: new Date().toISOString(), mode: "web-worker-v1" }
      };
      return true;
    })
    .catch((error) => {
      state.performance = {
        ...(state.performance || {}),
        worker: {
          available: false,
          checkedAt: new Date().toISOString(),
          mode: "fallback-main-thread",
          error: error && error.message ? error.message : String(error)
        }
      };
      return false;
    });
}

function cacheRepository() {
  const repo = typeof window !== "undefined" ? window.TwStockCacheRepository : null;
  return repo && typeof repo.get === "function" && typeof repo.set === "function" ? repo : null;
}

function rememberCacheRepositoryHealth(context = "startup") {
  const repo = cacheRepository();
  state.performance = {
    ...(state.performance || {}),
    cacheRepository: {
      available: Boolean(repo && repo.available && repo.available()),
      checkedAt: new Date().toISOString(),
      context,
      mode: repo?.version || "unavailable"
    }
  };
  return Boolean(repo);
}

function cacheRepositorySet(key, value, meta = {}) {
  const repo = cacheRepository();
  if (!repo) return Promise.resolve(false);
  return repo.set(key, value, meta)
    .then(() => true)
    .catch((error) => {
      state.performance = {
        ...(state.performance || {}),
        cacheRepository: {
          ...(state.performance?.cacheRepository || {}),
          available: false,
          checkedAt: new Date().toISOString(),
          error: error && error.message ? error.message : String(error)
        }
      };
      return false;
    });
}

function cacheRepositoryGet(key) {
  const repo = cacheRepository();
  if (!repo) return Promise.resolve(null);
  return repo.get(key).catch((error) => {
    console.warn(`cache repository read skipped: ${key}`, error);
    return null;
  });
}

let _researchDataCatalog = {
  schemaVersion: RESEARCH_DATA_SCHEMA_VERSION,
  appVersion: APP_VERSION,
  generatedAt: null,
  methodology: CURRENT_RESEARCH_METHODOLOGY,
  cachePolicy: {}
};

let _researchDataLayerStatus = {
  loadedAt: null,
  loadedSources: [],
  lastPersistedAt: null,
  lastPersistReason: "",
  syncFileWritten: false
};

function normalizeResearchDataMeta(meta, fallbackSummary = "") {
  const value = meta && typeof meta === "object" && !Array.isArray(meta) ? meta : {};
  return {
    fetchedAt: value.fetchedAt || null,
    sourceSummary: value.sourceSummary || fallbackSummary,
    sources: Array.isArray(value.sources) ? value.sources.filter((item) => item && typeof item === "object") : [],
    errors: Array.isArray(value.errors) ? value.errors.map((item) => String(item || "")).filter(Boolean) : [],
    missingHoldings: Array.isArray(value.missingHoldings) ? value.missingHoldings.filter((item) => item && typeof item === "object") : [],
    missingByCode: normalizeRecordMap(value.missingByCode)
  };
}

function normalizeResearchDataPayload(payload) {
  const value = payload && typeof payload === "object" && !Array.isArray(payload) ? payload : {};
  const financial = value.financialPerformance && typeof value.financialPerformance === "object"
    ? value.financialPerformance
    : value;
  const monthly = financial.monthlyRevenue && typeof financial.monthlyRevenue === "object"
    ? financial.monthlyRevenue
    : {};
  const quarterly = financial.quarterlyMargins && typeof financial.quarterlyMargins === "object"
    ? financial.quarterlyMargins
    : {};
  const methodology = value.methodology && typeof value.methodology === "object"
    ? value.methodology
    : CURRENT_RESEARCH_METHODOLOGY;
  return {
    schemaVersion: Number(value.schemaVersion) || RESEARCH_DATA_SCHEMA_VERSION,
    appVersion: String(value.appVersion || ""),
    generatedAt: value.generatedAt || null,
    methodology: {
      status: methodology.status || "current",
      label: methodology.label || CURRENT_RESEARCH_METHODOLOGY.label,
      sections: {
        ...CURRENT_RESEARCH_METHODOLOGY.sections,
        ...normalizeRecordMap(methodology.sections)
      }
    },
    financialPerformance: {
      monthlyRevenue: {
        records: normalizeRecordMap(monthly.records || monthly.revenue),
        history: normalizeRecordMap(monthly.history || monthly.revenueHistory),
        meta: normalizeResearchDataMeta(monthly.meta || monthly.revenueMeta)
      },
      quarterlyMargins: {
        records: normalizeRecordMap(quarterly.records || quarterly.financialRatios),
        meta: normalizeResearchDataMeta(quarterly.meta || quarterly.financialRatioMeta)
      }
    },
    cachePolicy: normalizeRecordMap(value.cachePolicy)
  };
}

function researchRecordRank(row, periodKeys = []) {
  const fetchedAt = Date.parse(row?.fetchedAt || "");
  if (Number.isFinite(fetchedAt)) return fetchedAt;
  for (const key of periodKeys) {
    const value = String(row?.[key] || "").replace(/\D/g, "");
    if (value) return Number(value);
  }
  return 0;
}

function mergeResearchRecordMap(currentMap, incomingMap, periodKeys = []) {
  const merged = { ...normalizeRecordMap(currentMap) };
  for (const [code, incoming] of Object.entries(normalizeRecordMap(incomingMap))) {
    const current = merged[code];
    if (!current || researchRecordRank(incoming, periodKeys) >= researchRecordRank(current, periodKeys)) {
      merged[code] = incoming;
    }
  }
  return merged;
}

function mergeRevenueHistoryMap(currentMap, incomingMap) {
  const merged = { ...normalizeRecordMap(currentMap) };
  for (const [code, incomingRows] of Object.entries(normalizeRecordMap(incomingMap))) {
    const byMonth = new Map();
    for (const row of Array.isArray(merged[code]) ? merged[code] : []) {
      const month = normalizeMonthKey(row?.yearMonth || row?.period || row?.date);
      if (month) byMonth.set(month, { ...row, yearMonth: month });
    }
    for (const row of Array.isArray(incomingRows) ? incomingRows : []) {
      const month = normalizeMonthKey(row?.yearMonth || row?.period || row?.date);
      if (!month) continue;
      const current = byMonth.get(month);
      if (!current || researchRecordRank(row, ["yearMonth"]) >= researchRecordRank(current, ["yearMonth"])) {
        byMonth.set(month, { ...row, yearMonth: month });
      }
    }
    merged[code] = [...byMonth.values()]
      .sort((left, right) => left.yearMonth.localeCompare(right.yearMonth))
      .slice(-REVENUE_HISTORY_MONTH_LIMIT);
  }
  return merged;
}

function mergeQuarterlyMarginMap(currentMap, incomingMap) {
  const merged = { ...normalizeRecordMap(currentMap) };
  for (const [code, incomingRaw] of Object.entries(normalizeRecordMap(incomingMap))) {
    const currentRaw = merged[code];
    const currentRows = Array.isArray(currentRaw) ? currentRaw : Array.isArray(currentRaw?.rows) ? currentRaw.rows : [];
    const incomingRows = Array.isArray(incomingRaw) ? incomingRaw : Array.isArray(incomingRaw?.rows) ? incomingRaw.rows : [];
    const byPeriod = new Map();
    for (const row of currentRows) {
      const period = normalizeQuarterKey(row?.period || row?.quarter || row?.yearQuarter || row?.date);
      if (period) byPeriod.set(period, { ...row, period });
    }
    for (const row of incomingRows) {
      const period = normalizeQuarterKey(row?.period || row?.quarter || row?.yearQuarter || row?.date);
      if (!period) continue;
      const current = byPeriod.get(period);
      if (!current || researchRecordRank(row, ["period"]) >= researchRecordRank(current, ["period"])) {
        byPeriod.set(period, { ...row, period });
      }
    }
    const rows = [...byPeriod.values()]
      .sort((left, right) => left.period.localeCompare(right.period))
      .slice(-QUARTERLY_MARGIN_RETENTION_QUARTERS);
    if (!rows.length) continue;
    const incomingRank = researchRecordRank(incomingRaw, ["fetchedAt"]);
    const currentRank = researchRecordRank(currentRaw, ["fetchedAt"]);
    const wrapper = incomingRank >= currentRank ? incomingRaw : currentRaw;
    merged[code] = {
      ...(wrapper && typeof wrapper === "object" && !Array.isArray(wrapper) ? wrapper : {}),
      rows
    };
  }
  return merged;
}

function preferResearchDataMeta(currentMeta, incomingMeta) {
  const current = normalizeResearchDataMeta(currentMeta);
  const incoming = normalizeResearchDataMeta(incomingMeta);
  const currentTime = Date.parse(current.fetchedAt || "");
  const incomingTime = Date.parse(incoming.fetchedAt || "");
  if (Number.isFinite(incomingTime) && (!Number.isFinite(currentTime) || incomingTime >= currentTime)) return incoming;
  if (!current.sourceSummary && incoming.sourceSummary) return incoming;
  return current;
}

function mergeResearchDataPayload(payload, sourceLabel = RESEARCH_DATA_SEED_PATH) {
  if (!payload) return { applied: false, sourceLabel };
  const incoming = normalizeResearchDataPayload(payload);
  const monthly = incoming.financialPerformance.monthlyRevenue;
  const quarterly = incoming.financialPerformance.quarterlyMargins;
  state.revenue = mergeResearchRecordMap(state.revenue, monthly.records, ["yearMonth", "period"]);
  state.revenueHistory = mergeRevenueHistoryMap(state.revenueHistory, monthly.history);
  state.revenueMeta = preferResearchDataMeta(state.revenueMeta, monthly.meta);
  state.financialRatios = mergeQuarterlyMarginMap(state.financialRatios, quarterly.records);
  state.financialRatioMeta = preferResearchDataMeta(state.financialRatioMeta, quarterly.meta);
  _researchDataCatalog = {
    schemaVersion: incoming.schemaVersion,
    appVersion: incoming.appVersion || APP_VERSION,
    generatedAt: incoming.generatedAt,
    methodology: incoming.methodology,
    cachePolicy: incoming.cachePolicy
  };
  _researchDataLayerStatus.loadedSources = uniqueList([
    ..._researchDataLayerStatus.loadedSources,
    sourceLabel
  ]);
  return {
    applied: true,
    sourceLabel,
    revenueCount: Object.keys(monthly.records).length,
    revenueHistoryCount: Object.keys(monthly.history).length,
    marginCount: Object.keys(quarterly.records).length
  };
}

function buildResearchDataPayload() {
  return {
    schemaVersion: RESEARCH_DATA_SCHEMA_VERSION,
    appVersion: APP_VERSION,
    generatedAt: new Date().toISOString(),
    methodology: _researchDataCatalog.methodology || CURRENT_RESEARCH_METHODOLOGY,
    financialPerformance: {
      monthlyRevenue: {
        records: state.revenue,
        history: state.revenueHistory,
        meta: state.revenueMeta
      },
      quarterlyMargins: {
        records: state.financialRatios,
        meta: state.financialRatioMeta
      }
    },
    cachePolicy: {
      bundledBaseline: RESEARCH_DATA_SEED_PATH,
      runtimeCache: `IndexedDB ${RESEARCH_DATA_CACHE_KEY}`,
      syncFile: RESEARCH_DATA_SYNC_FILE_NAME,
      monthlyRevenueRetentionMonths: REVENUE_HISTORY_MONTH_LIMIT,
      quarterlyMarginRetentionQuarters: QUARTERLY_MARGIN_RETENTION_QUARTERS,
      monthlyRevenueUpdate: "完整更新只在缺資料或預期公告月份尚未取得時下載；手動月營收更新可強制重新抓取。",
      quarterlyMarginUpdate: "CSV 匯入後增量合併，不以月營收替代季報三率。"
    }
  };
}

async function loadResearchDataLayer() {
  const [bundled, synced, cached] = await Promise.all([
    readBundledStateFile(RESEARCH_DATA_SEED_PATH),
    readResearchDataFile(),
    cacheRepositoryGet(RESEARCH_DATA_CACHE_KEY)
  ]);
  mergeResearchDataPayload(bundled, RESEARCH_DATA_SEED_PATH);
  mergeResearchDataPayload(synced, `${fsSyncDirName() || "data"}/${RESEARCH_DATA_SYNC_FILE_NAME}`);
  mergeResearchDataPayload(cached, `IndexedDB ${RESEARCH_DATA_CACHE_KEY}`);
  const revenueMissing = monthlyRevenueMissingHoldings(state.revenue);
  state.revenueMeta = {
    ...state.revenueMeta,
    missingHoldings: revenueMissing.missingHoldings,
    missingByCode: revenueMissing.missingByCode
  };
  const marginMissing = quarterlyMarginMissingHoldings(state.financialRatios);
  state.financialRatioMeta = {
    ...state.financialRatioMeta,
    missingHoldings: marginMissing.missingHoldings,
    missingByCode: marginMissing.missingByCode
  };
  _researchDataLayerStatus.loadedAt = new Date().toISOString();
  return _researchDataLayerStatus;
}

let _researchDataLayerLoadPromise = null;

function startResearchDataLayerLoad(reason = "startup") {
  if (_researchDataLayerLoadPromise) return _researchDataLayerLoadPromise;
  _researchDataLayerLoadPromise = loadResearchDataLayer()
    .then((status) => {
      state.performance = {
        ...(state.performance || {}),
        researchDataLayer: {
          loadedAt: status?.loadedAt || new Date().toISOString(),
          loadedSources: Array.isArray(status?.loadedSources) ? status.loadedSources.slice() : [],
          reason
        }
      };
      if (typeof document !== "undefined" && document.body && ["overview", "screener", "report", "technical"].includes(state.activeTab)) {
        render({ scope: "active" });
      }
      return status;
    })
    .catch((error) => {
      const message = error && error.message ? error.message : String(error);
      console.warn("loadResearchDataLayer skipped", error);
      _researchDataLayerStatus.loadedAt = new Date().toISOString();
      _researchDataLayerStatus.lastError = message;
      state.performance = {
        ...(state.performance || {}),
        researchDataLayer: {
          loadedAt: _researchDataLayerStatus.loadedAt,
          loadedSources: [],
          reason,
          error: message
        }
      };
      return _researchDataLayerStatus;
    });
  return _researchDataLayerLoadPromise;
}

async function persistResearchDataLayer(reason = "update") {
  const payload = buildResearchDataPayload();
  const [cacheResult, syncResult] = await Promise.all([
    cacheRepositorySet(RESEARCH_DATA_CACHE_KEY, payload, {
      version: APP_VERSION,
      schemaVersion: RESEARCH_DATA_SCHEMA_VERSION,
      type: "researchData"
    }),
    writeResearchDataFile(payload)
  ]);
  _researchDataLayerStatus.lastPersistedAt = payload.generatedAt;
  _researchDataLayerStatus.lastPersistReason = reason;
  _researchDataLayerStatus.syncFileWritten = syncResult === true;
  return { cacheResult, syncResult, payload };
}

