async function fetchInstitutionalFlowCached(stock, cache) {
  if (!cache) return fetchInstitutionalFlow(stock);
  if (stock.suffix === "TWO") {
    const apiData = await getTpexInstitutionalOpenApi(cache);
    const apiResult = apiData ? parseInstitutionalTPEx(apiData, stock.code) : null;
    if (apiResult) return apiResult;
  }
  for (const { dateStr } of recentTradingDates(14, 0)) {
    const data = stock.suffix === "TW"
      ? await getTwseInstitutionalDaily(cache, dateStr)
      : await getTpexInstitutionalDaily(cache, dateStr);
    const result = stock.suffix === "TW"
      ? parseInstitutionalTWSE(data, stock.code)
      : parseInstitutionalTPEx(data, stock.code);
    if (result) return result;
  }
  return null;
}

async function fetch7DayInstitutionalCached(stock, cache, targetDays = INSTITUTIONAL_RECENT_TARGET_DAYS, lookbackDays = INSTITUTIONAL_RECENT_LOOKBACK_DAYS) {
  if (!cache) return fetch7DayInstitutional(stock, targetDays, lookbackDays);
  const rows = [];
  for (const { dateStr } of recentTradingDates(lookbackDays, 0)) {
    const data = stock.suffix === "TW"
      ? await getTwseInstitutionalDaily(cache, dateStr)
      : await getTpexInstitutionalDaily(cache, dateStr);
    const result = stock.suffix === "TW"
      ? parseInstitutionalTWSE(data, stock.code)
      : parseInstitutionalTPEx(data, stock.code);
    if (result) {
      const normalized = normalizeInstitutionalHistoryRows([...rows, result], targetDays);
      rows.splice(0, rows.length, ...normalized);
    }
    if (rows.length >= targetDays) break;
  }
  return rows.length ? rows : null;
}

