// ─── 持倉 P&L 總覽 + 倉位計算器 ──────────────────────────────────────────────

function portfolioPnlRows() {
  return Object.entries(state.costBasis || {})
    .filter(([, cost]) => cost?.price > 0 && cost?.shares > 0)
    .map(([code, cost]) => {
      const stock = STOCK_MAP.get(code);
      const price = latestValue(stock || { code, ref: null });
      const stopLoss = (state.alerts || {})[code]?.stopLoss ?? null;
      const unrealizedPnl = price !== null ? (price - cost.price) * cost.shares * 1000 : null;
      const unrealizedPct = cost.price > 0 && price !== null ? (price - cost.price) / cost.price * 100 : null;
      const distToStop = stopLoss !== null && price !== null && price > 0 ? (price - stopLoss) / price * 100 : null;
      return { code, name: stock?.name || code, costPrice: cost.price, shares: cost.shares, price, stopLoss, unrealizedPnl, unrealizedPct, distToStop };
    })
    .sort((a, b) => (b.unrealizedPct ?? -999) - (a.unrealizedPct ?? -999));
}

function buildHoldingMaRisk(holding, technical, quote = null) {
  if (!technical?.ready) {
    return {
      available: false,
      status: "unavailable",
      label: "日線不足",
      warnings: [],
      priority: 0
    };
  }
  const rows = Array.isArray(technical.rows) ? technical.rows : [];
  const latestClose = toNumber(technical.latest?.close);
  const quotePrice = toNumber(quote?.price);
  const currentPrice = quotePrice ?? latestClose;
  const currentDate = quote?.sourceDate || technical.latest?.date || "";
  if (currentPrice === null) {
    return {
      available: false,
      status: "unavailable",
      label: "現價不足",
      warnings: [],
      priority: 0
    };
  }
  const quoteAfterLatestKline = quote?.sourceDate && technical.latest?.date && quote.sourceDate > technical.latest.date;
  const closes = rows.map((row) => toNumber(row.close));
  const checks = [
    { key: "ma5", label: "5日線", period: 5, value: toNumber(technical.ma5), weight: 2 },
    { key: "ma20", label: "月線", period: 20, value: toNumber(technical.ma20), weight: 4 }
  ];
  const warnings = checks.map((check) => {
    if (check.value === null || check.value <= 0 || currentPrice >= check.value) return null;
    const previousClose = quoteAfterLatestKline ? latestClose : toNumber(rows.at(-2)?.close);
    const previousMa = quoteAfterLatestKline ? check.value : sma(closes.slice(0, -1), check.period);
    const crossedToday = previousClose !== null && previousMa !== null && previousClose >= previousMa;
    const distancePct = (currentPrice - check.value) / check.value * 100;
    return {
      ...check,
      ma: check.value,
      close: currentPrice,
      date: currentDate,
      distancePct,
      crossedToday,
      priority: check.weight * 10 + (crossedToday ? 5 : 0) + Math.min(5, Math.abs(distancePct))
    };
  }).filter(Boolean);
  warnings.sort((left, right) => right.priority - left.priority);
  const hasMa20 = warnings.some((warning) => warning.key === "ma20");
  const hasFreshBreak = warnings.some((warning) => warning.crossedToday);
  return {
    available: true,
    status: warnings.length ? (hasMa20 ? "danger" : "warn") : "ok",
    label: warnings.length
      ? `目前有問題：${warnings.map((warning) => `${warning.crossedToday ? "今日跌破" : "低於"}${warning.label}`).join(" / ")}`
      : "MA5 / 月線未失守",
    warnings,
    priority: warnings.reduce((max, warning) => Math.max(max, warning.priority), 0) + (hasMa20 ? 20 : 0) + (hasFreshBreak ? 8 : 0),
    source: "本機日線 MA5 / MA20 與最新報價"
  };
}

function monotonicDirection(values) {
  const nums = values.map((value) => toNumber(value)).filter((value) => value !== null);
  if (nums.length < 3) return "insufficient";
  const last3 = nums.slice(-3);
  if (last3[0] < last3[1] && last3[1] < last3[2]) return "up";
  if (last3[0] > last3[1] && last3[1] > last3[2]) return "down";
  return "mixed";
}

function revenueHistoryRowsForCode(code) {
  const byMonth = new Map();
  const addRow = (row) => {
    if (!row || typeof row !== "object" || Array.isArray(row)) return;
    const month = normalizeMonthKey(row.yearMonth || row.period || row.date || row.fetchedAt);
    if (!month) return;
    byMonth.set(month, {
      yearMonth: month,
      yoyPct: toNumber(row.yoyPct),
      momPct: toNumber(row.momPct),
      current: toNumber(row.current),
      fetchedAt: row.fetchedAt || ""
    });
  };
  for (const row of (Array.isArray(state.revenueHistory?.[code]) ? state.revenueHistory[code] : [])) addRow(row);
  addRow(revenueFor(code));
  return [...byMonth.values()].sort((a, b) => a.yearMonth.localeCompare(b.yearMonth));
}

function holdingRevenueSignal(code) {
  const rev = revenueFor(code);
  const hist = revenueHistoryRowsForCode(code);
  const latest = rev || hist.at(-1) || null;
  if (!latest) {
    const missingReason = state.revenueMeta?.missingByCode?.[code] || "請先更新月營收";
    return {
      available: false,
      label: "缺月營收",
      toneClass: "warn",
      detail: missingReason,
      priority: 95,
      yearMonth: "",
      signals: []
    };
  }
  const yoy = toNumber(latest.yoyPct);
  const mom = toNumber(latest.momPct);
  const current = toNumber(latest.current);
  const yearMonth = normalizeMonthKey(latest.yearMonth || latest.period || latest.date) || latest.fetchedAt?.slice(0, 7) || "";
  const yoyTrend = monotonicDirection(hist.map((row) => row.yoyPct));
  const revenueTrend = monotonicDirection(hist.map((row) => row.current));
  const signals = [];
  if (yoyTrend === "up") signals.push("YoY 連三升");
  if (yoyTrend === "down") signals.push("YoY 連三降");
  if (revenueTrend === "up") signals.push("營收額連三升");
  if (revenueTrend === "down") signals.push("營收額連三降");
  if (yoy !== null) signals.push(`YoY ${formatSignedMetric(yoy, 1, "%")}`);
  if (mom !== null) signals.push(`MoM ${formatSignedMetric(mom, 1, "%")}`);

  let label = "營收資料混合";
  let toneClass = "flat";
  let priority = 40;
  if (yoyTrend === "down" || revenueTrend === "down" || (yoy !== null && yoy < 0 && mom !== null && mom < 0)) {
    label = "營收轉弱";
    toneClass = "quality-negative";
    priority = 88 + Math.min(10, Math.abs(yoy || 0) * 0.2);
  } else if (yoyTrend === "up" || revenueTrend === "up") {
    label = "營收連續改善";
    toneClass = "quality-positive";
    priority = 72 + Math.min(10, Math.max(yoy || 0, 0) * 0.15);
  } else if (yoy !== null && yoy > 0 && mom !== null && mom > 0) {
    label = "營收正成長";
    toneClass = "quality-positive";
    priority = 64 + Math.min(8, yoy * 0.12);
  } else if (yoy !== null && yoy < 0) {
    label = "YoY 衰退";
    toneClass = "quality-negative";
    priority = 78 + Math.min(8, Math.abs(yoy) * 0.12);
  }

  return {
    available: true,
    label,
    toneClass,
    detail: signals.join(" / ") || "已有月營收資料",
    priority,
    yearMonth,
    yoy,
    mom,
    current,
    signals,
    source: latest.source || "MOPS t187ap05 月營收",
    fetchedAt: latest.fetchedAt || ""
  };
}

function marginValue(row, keys) {
  for (const key of keys) {
    const value = toNumber(row?.[key]);
    if (value !== null) return value;
  }
  return null;
}

function holdingTripleMarginSignal(code) {
  const store = state.financialRatios || state.financialMargins || state.quarterlyFinancials || {};
  const raw = store?.[code];
  const rows = Array.isArray(raw) ? raw : Array.isArray(raw?.rows) ? raw.rows : Array.isArray(raw?.history) ? raw.history : [];
  const normalized = rows.map((row) => ({
    period: row.period || row.quarter || row.yearQuarter || row.date || "",
    gross: marginValue(row, ["grossMargin", "grossProfitMargin", "毛利率"]),
    operating: marginValue(row, ["operatingMargin", "operatingProfitMargin", "營益率", "營業利益率"]),
    net: marginValue(row, ["netMargin", "netProfitMargin", "稅後淨利率", "淨利率"]),
    source: row.source || raw?.source || "MOPS 財報",
    sourceUrl: row.sourceUrl || raw?.sourceUrl || FINANCIAL_MARGIN_SOURCE_LINKS.mopsFinancials,
    fetchedAt: row.fetchedAt || raw?.fetchedAt || ""
  })).filter((row) => row.gross !== null && row.operating !== null && row.net !== null)
    .sort((a, b) => String(a.period).localeCompare(String(b.period)));
  if (normalized.length < 2) {
    const missingReason = state.financialRatioMeta?.missingByCode?.[code] || "需季損益表毛利率 / 營益率 / 淨利率";
    return {
      available: false,
      label: "三率待補",
      toneClass: "warn",
      detail: missingReason,
      source: "MOPS 財報待接",
      sourceUrl: FINANCIAL_MARGIN_SOURCE_LINKS.mopsFinancials
    };
  }
  const latest = normalized.at(-1);
  const previous = normalized.at(-2);
  const deltas = {
    gross: latest.gross - previous.gross,
    operating: latest.operating - previous.operating,
    net: latest.net - previous.net
  };
  const allUp = deltas.gross > 0 && deltas.operating > 0 && deltas.net > 0;
  const allDown = deltas.gross < 0 && deltas.operating < 0 && deltas.net < 0;
  return {
    available: true,
    label: allUp ? "三率三升" : allDown ? "三率三降" : "三率分歧",
    toneClass: allUp ? "quality-positive" : allDown ? "quality-negative" : "flat",
    detail: `毛利 ${formatSignedMetric(deltas.gross, 1, "pp")} / 營益 ${formatSignedMetric(deltas.operating, 1, "pp")} / 淨利 ${formatSignedMetric(deltas.net, 1, "pp")}`,
    period: latest.period,
    latest,
    previous,
    deltas,
    source: latest.source || raw?.source || "MOPS 財報",
    sourceUrl: latest.sourceUrl || raw?.sourceUrl || FINANCIAL_MARGIN_SOURCE_LINKS.mopsFinancials,
    fetchedAt: latest.fetchedAt || raw?.fetchedAt || "",
    rows: normalized
  };
}

function researchReportDiscoveryLinks(stock) {
  if (!stock) return [];
  return [
    { label: "公開法說 / WebPro", url: "https://webpro.twse.com.tw/WebPortal/" },
    { label: "公司 IR / 法說簡報", url: googleSearchUrl(stock, "IR 法說會 簡報 investor presentation") },
    { label: "出貨量 / 訂單能見度", url: googleSearchUrl(stock, "出貨量 訂單 能見度 產能利用率") },
    { label: "交期 / 等待時間", url: googleSearchUrl(stock, "lead time waiting time 交期 等待時間") },
    { label: "法人報告片段", url: googleSearchUrl(stock, "法人報告 目標價 出貨量") },
    { label: "產業報告", url: googleSearchUrl(stock, "產業報告 supply chain outlook") }
  ];
}

function holdingRevenueDiagnosticRow(row) {
  const holding = row.holding;
  const stock = row.stock || STOCK_MAP.get(holding.code) || holding;
  if (isEtfCode(holding.code)) {
    return {
      holding,
      stock,
      type: "ETF / 基金",
      status: "ETF / 不適用",
      statusClass: "flat",
      yearMonth: "-",
      currentText: "-",
      growthText: "-",
      sourceText: "投信 / ETF 公開說明書",
      reason: "ETF 不公告公司月營收；改看 NAV、折溢價、成分持股、費用率與配息來源。",
      priority: 3
    };
  }

  const rev = row.revenueSignal || holdingRevenueSignal(holding.code);
  const sourceText = [
    rev?.source || "MOPS t187ap05 月營收",
    rev?.fetchedAt ? `抓取 ${formatDateTime(rev.fetchedAt)}` : ""
  ].filter(Boolean).join("；");
  if (rev?.available) {
    return {
      holding,
      stock,
      type: stock.market || (holding.suffix === "TWO" ? "上櫃普通股" : "上市普通股"),
      status: "已取得",
      statusClass: "good",
      yearMonth: rev.yearMonth || "-",
      currentText: rev.current !== null ? formatNumber(rev.current, 0) : "-",
      growthText: [rev.yoy !== null ? `YoY ${formatSignedMetric(rev.yoy, 1, "%")}` : "", rev.mom !== null ? `MoM ${formatSignedMetric(rev.mom, 1, "%")}` : ""].filter(Boolean).join(" / ") || "-",
      sourceText,
      reason: rev.detail || "已有 MOPS 月營收資料。",
      priority: 2
    };
  }

  const meta = state.revenueMeta || {};
  const reason = meta.missingByCode?.[holding.code] || rev?.detail || "尚未更新月營收；請先按「更新月營收」。";
  const status = meta.fetchedAt ? "缺月營收" : "尚未更新";
  return {
    holding,
    stock,
    type: stock.market || (holding.suffix === "TWO" ? "上櫃普通股" : "上市普通股"),
    status,
    statusClass: meta.fetchedAt ? "warn" : "flat",
    yearMonth: "-",
    currentText: "-",
    growthText: "-",
    sourceText: meta.fetchedAt ? `MOPS t187ap05；抓取 ${formatDateTime(meta.fetchedAt)}` : "MOPS t187ap05 尚未更新",
    reason,
    priority: meta.fetchedAt ? 0 : 1
  };
}

