function renderHoldingsDetailGate(rows) {
  const inputRows = Array.isArray(rows) ? rows : [];
  const revenueRows = inputRows.filter((row) => row.revenueSignal);
  const marginRows = inputRows.filter((row) => isTripleMarginEligibleStock(row.stock));
  const missingRevenue = revenueRows.filter((row) => row.revenueSignal && !row.revenueSignal.available).length;
  const missingMargins = marginRows.filter((row) => row.marginSignal && !row.marginSignal.available).length;
  return `
    <article class="rank-card" data-holdings-detail-gate style="grid-column:1/-1;">
      <h3>持股詳表</h3>
      <div class="chip-row chip-row-compact" style="margin-bottom:8px;">
        <span class="chip ${missingRevenue ? "warn" : "good"}">月營收待補 ${formatNumber(missingRevenue, 0)}</span>
        <span class="chip ${missingMargins ? "warn" : "good"}">三率待補 ${formatNumber(missingMargins, 0)}</span>
        <span class="chip">持股 ${formatNumber(inputRows.length, 0)} 檔</span>
      </div>
      <p style="margin:0 0 10px;color:var(--muted);font-size:0.78rem;line-height:1.55;">預設先保留作戰摘要；需要逐檔月營收 / 三率診斷、持倉損益與倉位試算時再載入詳表。</p>
      <button class="secondary-btn" type="button" data-overview-detail="holdings">載入持股詳表</button>
    </article>
  `;
}

function renderHoldingsCommandCenter(options = {}) {
  const showDetails = options.details !== false;
  const holdings = (state.holdings || []).map((entry) => normalizeHoldingEntry(entry)).filter(Boolean);
  if (!holdings.length) return "";
  const rows = holdings.map((holding) => {
    const stock = STOCK_MAP.get(holding.code) || { ...holding, themes: [] };
    const quote = quoteFor(holding.code);
    const klines = latestKlines(holding.code);
    const inst = institutionalFor(holding.code);
    let technical = null;
    let technicalError = "";
    if (klines.length >= 20) {
      try {
        technical = calculateTechnical(holding.code);
      } catch (error) {
        technicalError = error && error.message ? error.message : String(error);
      }
    }
    const heat = technical?.ready ? buildStockHeatSignal(holding.code, technical) : null;
    const maRisk = buildHoldingMaRisk(holding, technical, quote);
    const revenueSignal = isEtfCode(holding.code) ? null : holdingRevenueSignal(holding.code);
    const marginSignal = isTripleMarginEligibleStock(stock) ? holdingTripleMarginSignal(holding.code) : null;
    const missing = [];
    if (!quote) missing.push("報價");
    if (klines.length < 80) missing.push("日線");
    if (technicalError) missing.push("技術");
    if (revenueSignal && !revenueSignal.available) missing.push("月營收");
    if (isTripleMarginEligibleStock(stock) && marginSignal && !marginSignal.available) missing.push("三率");
    if (!inst?.history?.length && !inst?.available) missing.push("法人");
    return { holding, stock, quote, klines, inst, heat, maRisk, revenueSignal, marginSignal, technicalError, missing };
  });
  const quoteReady = rows.filter((row) => row.quote).length;
  const klineReady = rows.filter((row) => row.klines.length >= 80).length;
  const instReady = rows.filter((row) => row.inst?.history?.length || row.inst?.available).length;
  const fundamentalRows = rows.filter((row) => row.revenueSignal);
  const revenueReady = fundamentalRows.filter((row) => row.revenueSignal?.available).length;
  const marginEligibleRows = rows.filter((row) => isTripleMarginEligibleStock(row.stock));
  const marginReady = marginEligibleRows.filter((row) => row.marginSignal?.available).length;
  const maWarnings = rows
    .filter((row) => row.maRisk?.warnings?.length)
    .sort((a, b) => b.maRisk.priority - a.maRisk.priority || a.holding.code.localeCompare(b.holding.code))
    .slice(0, 8);
  const heatRisks = rows
    .filter((row) => row.heat?.available && (row.heat.heatScore >= 50 || row.heat.deepScore >= 50))
    .sort((a, b) => Math.max(b.heat.heatScore, b.heat.deepScore) - Math.max(a.heat.heatScore, a.heat.deepScore))
    .slice(0, 5);
  const dataQueue = rows
    .filter((row) => row.missing.length)
    .sort((a, b) => b.missing.length - a.missing.length || a.holding.code.localeCompare(b.holding.code))
    .slice(0, 6);
  const themeCounts = new Map();
  for (const row of rows) {
    const theme = (row.stock.themes || []).find((key) => key !== HOLDINGS_THEME_KEY) || row.stock.primaryTheme || "other";
    const label = THEME_LABELS[theme] || row.stock.sector || "其他";
    themeCounts.set(label, (themeCounts.get(label) || 0) + 1);
  }
  const topThemes = [...themeCounts.entries()]
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0], "zh-Hant"))
    .slice(0, 5);
  const actionRows = dataQueue.length ? dataQueue : heatRisks;
  const revenueWatchRows = fundamentalRows
    .slice()
    .sort((a, b) => (b.revenueSignal?.priority || 0) - (a.revenueSignal?.priority || 0) || a.holding.code.localeCompare(b.holding.code))
    .slice(0, 6);
  const revenueMeta = state.revenueMeta || {};
  const revenueSourceNote = revenueMeta.sourceSummary || "月營收以 MOPS t187ap05_L / t187ap05_O 官方 CSV 為準；TWSE / TPEx OpenAPI 僅作備援。";

  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap;margin-bottom:12px;">
        <div>
          <h3 style="margin:0;font-size:1rem;">持股作戰室</h3>
          <p style="margin:4px 0 0;color:var(--muted);font-size:0.8rem;line-height:1.55;">開盤前先看資料覆蓋率、曝險集中度與需要優先處理的標的；這是研究排序，不是買賣建議。</p>
        </div>
        <div class="chip-row chip-row-compact">
          <span class="chip">持股 ${formatNumber(holdings.length, 0)} 檔</span>
          <span class="chip ${quoteReady === holdings.length ? "good" : "warn"}">報價 ${formatNumber(quoteReady, 0)}/${formatNumber(holdings.length, 0)}</span>
          <span class="chip ${klineReady === holdings.length ? "good" : "warn"}">日線 ${formatNumber(klineReady, 0)}/${formatNumber(holdings.length, 0)}</span>
          <span class="chip ${instReady === holdings.length ? "good" : "warn"}">籌碼 ${formatNumber(instReady, 0)}/${formatNumber(holdings.length, 0)}</span>
          <span class="chip ${revenueReady === fundamentalRows.length ? "good" : "warn"}">月營收 ${formatNumber(revenueReady, 0)}/${formatNumber(fundamentalRows.length, 0)}</span>
          <span class="chip ${marginReady === marginEligibleRows.length ? "good" : "warn"}">三率 ${formatNumber(marginReady, 0)}/${formatNumber(marginEligibleRows.length, 0)}</span>
          <span class="chip ${maWarnings.length ? "danger" : "good"}">均線警告 ${formatNumber(maWarnings.length, 0)}/${formatNumber(holdings.length, 0)}</span>
        </div>
      </div>
      ${renderFinancialDataLayerSummary()}
      ${maWarnings.length ? `
        <div class="note-box" style="margin-bottom:12px;border-color:rgba(181,106,13,0.42);background:rgba(181,106,13,0.1);">
          <div style="display:flex;justify-content:space-between;gap:10px;align-items:flex-start;flex-wrap:wrap;">
            <div>
              <strong style="display:block;color:var(--warn);font-size:1.02rem;">目前有問題：${formatNumber(maWarnings.length, 0)} 檔持股跌破 5 日線 / 月線</strong>
              <p style="margin:4px 0 0;color:var(--muted);font-size:0.78rem;line-height:1.55;">持股風控優先檢查：跌破月線代表中線防線失守；跌破 5 日線代表短線動能轉弱。訊號使用本機日線 MA5 / MA20 與最新報價，不是買賣建議。</p>
            </div>
            <span class="chip danger">先檢查停損 / 減碼線</span>
          </div>
          <div class="rank-list" style="margin-top:10px;">
            ${maWarnings.slice(0, 5).map((row) => {
              const first = row.maRisk.warnings[0];
              return `
                <div class="rank-row" style="cursor:pointer;" data-jump-section="technical" data-jump-stock-code="${escapeHtml(row.holding.code)}">
                  <span><strong>${escapeHtml(row.holding.code)}</strong> ${escapeHtml(row.holding.name)} · ${escapeHtml(row.maRisk.label)}</span>
                  <strong class="down">${formatNumber(first.close)} / ${escapeHtml(first.label)} ${formatNumber(first.ma)} (${formatSignedMetric(first.distancePct, 1, "%")})</strong>
                </div>
              `;
            }).join("")}
          </div>
        </div>
      ` : ""}
      <div class="report-grid">
        <article class="rank-card">
          <h3>曝險前五主題</h3>
          <div class="rank-list">
            ${topThemes.map(([label, count]) => `
              <div class="rank-row">
                <span>${escapeHtml(label)}</span>
                <strong>${formatNumber(count, 0)} 檔</strong>
              </div>
            `).join("") || `<div class="empty">尚無主題資料。</div>`}
          </div>
        </article>
        <article class="rank-card">
          <h3>${maWarnings.length ? "目前有問題：均線失守" : "均線風控狀態"}</h3>
          <div class="rank-list">
            ${maWarnings.map((row) => {
              const first = row.maRisk.warnings[0];
              return `
                <div class="rank-row" style="cursor:pointer;" data-jump-section="technical" data-jump-stock-code="${escapeHtml(row.holding.code)}">
                  <span><strong>${escapeHtml(row.holding.code)}</strong> ${escapeHtml(row.holding.name)}</span>
                  <strong class="down">${escapeHtml(first.crossedToday ? "今日跌破" : "低於")}${escapeHtml(first.label)} ${formatSignedMetric(first.distancePct, 1, "%")}</strong>
                </div>
              `;
            }).join("") || `<div class="empty">目前持股未偵測到 MA5 / MA20 失守。</div>`}
          </div>
        </article>
        <article class="rank-card">
          <h3>${dataQueue.length ? "資料優先補齊" : "熱度 / 深跌優先檢查"}</h3>
          <div class="rank-list">
            ${actionRows.map((row) => `
              <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(row.holding.code)}">
                <span><strong>${escapeHtml(row.holding.code)}</strong> ${escapeHtml(row.holding.name)}</span>
                <strong class="${row.missing.length ? "warn" : "flat"}">
                  ${row.missing.length ? `缺 ${escapeHtml(row.missing.join(" / "))}` : escapeHtml(row.heat?.level?.label || "待檢查")}
                </strong>
              </div>
            `).join("") || `<div class="empty">目前未偵測到明顯資料缺口或熱度警示。</div>`}
          </div>
        </article>
        <article class="rank-card" data-holdings-revenue-card>
          <h3>持股營收動能</h3>
          <div class="rank-list">
            ${revenueWatchRows.map((row) => {
              const rev = row.revenueSignal;
              const margin = row.marginSignal;
              return `
                <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(row.holding.code)}">
                  <span>
                    <strong>${escapeHtml(row.holding.code)}</strong> ${escapeHtml(row.holding.name)}${rev.yearMonth ? ` · ${escapeHtml(rev.yearMonth)}` : ""}
                    <br><span style="font-size:0.72rem;color:var(--muted);">${escapeHtml(rev.detail || "月營收待更新")}；${escapeHtml(margin?.label || "三率待補")}</span>
                  </span>
                  <strong class="${escapeHtml(rev.toneClass || "flat")}">${escapeHtml(rev.label)}</strong>
                </div>
              `;
            }).join("") || `
              <div class="empty">
                請先按「月營收」更新持股營收。
                <div style="margin-top:8px;"><button class="link-chip inline-action-chip" type="button" data-market-action="update-revenue">更新月營收</button></div>
              </div>
            `}
          </div>
          <p style="margin:8px 0 0;color:var(--muted);font-size:0.76rem;line-height:1.5;">
            ${escapeHtml(revenueSourceNote)}<br>
            三率三升需季財報毛利率、營益率與淨利率；目前只標示資料狀態，不用月營收替代三率。
          </p>
        </article>
        ${showDetails ? `${renderHoldingsRevenueDiagnostics(rows)}${renderHoldingsMarginDiagnostics(rows)}` : renderHoldingsDetailGate(rows)}
      </div>
    </div>
  `;
}

function renderPortfolioPanel(options = {}) {
  const showDetails = options.details !== false;
  const rows = portfolioPnlRows();
  const commandCenter = renderHoldingsCommandCenter({ details: showDetails });
  if (!rows.length) {
    return showDetails
      ? `${commandCenter}<div class="note-box" style="margin-bottom:14px;">尚無持倉成本資料。請在個股研究頁 → 籌碼分頁設定各股的「成本均價」與「張數」。</div>`
      : commandCenter;
  }
  const withPrice = rows.filter((r) => r.price !== null);
  const totalInvested = rows.reduce((s, r) => s + r.costPrice * r.shares * 1000, 0);
  const totalMktVal = withPrice.reduce((s, r) => s + r.price * r.shares * 1000, 0);
  const totalPnl = withPrice.reduce((s, r) => s + r.unrealizedPnl, 0);
  const totalPct = totalInvested > 0 ? totalPnl / totalInvested * 100 : null;
  const nearStop = rows.filter((r) => r.distToStop !== null && r.distToStop < 5);

  return `
    ${commandCenter}
    ${!showDetails ? `
      <div class="note-box" style="margin-bottom:14px;">
        持倉損益表與倉位試算已收斂到「載入持股詳表」後顯示，避免主題總覽預設畫面過長。
      </div>
    ` : ""}
    ${!showDetails ? "" : `
    <div class="panel-lite" style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:12px;">
        <h3 style="margin:0;font-size:1rem;">持倉損益總覽</h3>
        <button id="exportHoldingsCsvBtn" class="ghost-btn" type="button" style="font-size:0.78rem;">匯出持倉 CSV</button>
      </div>
      <div class="report-grid" style="margin-bottom:12px;">
        <div class="report-card">
          <h3>資金概況</h3>
          <div class="kv-row"><span>持倉檔數</span><strong>${rows.length} 檔</strong></div>
          <div class="kv-row"><span>成本總計</span><strong>${formatNumber(totalInvested / 10000, 1)} 萬</strong></div>
          ${withPrice.length ? `
          <div class="kv-row"><span>市值合計</span><strong>${formatNumber(totalMktVal / 10000, 1)} 萬</strong></div>
          <div class="kv-row"><span>未實現損益</span><strong class="${changeClass(totalPnl)}">${totalPnl >= 0 ? "+" : ""}${formatNumber(totalPnl / 10000, 1)} 萬 (${formatPct(totalPct)})</strong></div>` : ""}
        </div>
        ${nearStop.length ? `
        <div class="report-card">
          <h3 style="color:var(--bad);">⚠ 接近停損（&lt; 5%）</h3>
          ${nearStop.map((r) => `
            <div class="kv-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(r.code)}">
              <span>${escapeHtml(r.code)} ${escapeHtml(r.name)}</span>
              <strong class="down">距停損 ${formatNumber(r.distToStop, 1)}%</strong>
            </div>`).join("")}
        </div>` : ""}
      </div>
      <div class="table-wrap">
        <table>
          <thead>
            <tr>
              <th>個股</th>
              <th class="num">成本均價</th>
              <th class="num">張數</th>
              <th class="num">現價</th>
              <th class="num">停損</th>
              <th class="num">未實現損益</th>
              <th class="num">報酬率</th>
              <th class="num">距停損</th>
            </tr>
          </thead>
          <tbody>
            ${rows.map((r) => `
              <tr style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(r.code)}">
                <td><strong>${escapeHtml(r.code)}</strong> ${escapeHtml(r.name)}</td>
                <td class="num">${formatNumber(r.costPrice)}</td>
                <td class="num">${formatNumber(r.shares, 0)}</td>
                <td class="num">${r.price !== null ? formatNumber(r.price) : `<span style="color:var(--muted);">-</span>`}</td>
                <td class="num">${r.stopLoss ? `<span class="down">${formatNumber(r.stopLoss)}</span>` : "—"}</td>
                <td class="num"><strong class="${changeClass(r.unrealizedPnl)}">${r.unrealizedPnl !== null ? `${r.unrealizedPnl >= 0 ? "+" : ""}${formatNumber(r.unrealizedPnl / 10000, 1)} 萬` : "—"}</strong></td>
                <td class="num"><strong class="${changeClass(r.unrealizedPct)}">${r.unrealizedPct !== null ? `${r.unrealizedPct >= 0 ? "+" : ""}${formatNumber(r.unrealizedPct, 1)}%` : "—"}</strong></td>
                <td class="num">${r.distToStop !== null ? `<span class="${r.distToStop < 5 ? "down" : r.distToStop < 10 ? "warn" : ""}">${formatNumber(r.distToStop, 1)}%</span>` : "—"}</td>
              </tr>`).join("")}
          </tbody>
        </table>
      </div>
    </div>
    `}
  `;
}

function renderPositionSizer() {
  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <h3 style="margin:0 0 10px;font-size:1rem;">倉位計算器</h3>
      <p style="color:var(--muted);font-size:0.82rem;margin:0 0 10px;">輸入帳戶資金與每筆最大風險，自動計算最大可買張數（每張 = 1,000 股）</p>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:8px;margin-bottom:10px;">
        <div>
          <label style="font-size:0.76rem;color:var(--muted);">帳戶資金（萬元）</label>
          <input id="psAccount" class="input" type="number" placeholder="例：500" style="min-height:36px;margin-top:4px;" />
        </div>
        <div>
          <label style="font-size:0.76rem;color:var(--muted);">每筆最大風險 %</label>
          <input id="psRisk" class="input" type="number" placeholder="例：1" step="0.1" style="min-height:36px;margin-top:4px;" />
        </div>
        <div>
          <label style="font-size:0.76rem;color:var(--muted);">進場價（元）</label>
          <input id="psEntry" class="input" type="number" placeholder="例：850" style="min-height:36px;margin-top:4px;" />
        </div>
        <div>
          <label style="font-size:0.76rem;color:var(--muted);">停損價（元）</label>
          <input id="psStop" class="input" type="number" placeholder="例：780" style="min-height:36px;margin-top:4px;" />
        </div>
      </div>
      <button id="calcPsBtn" class="ghost-btn" type="button" style="font-size:0.82rem;min-height:32px;">計算倉位</button>
      <div id="psResult" style="margin-top:10px;"></div>
      <p style="color:var(--muted);font-size:0.72rem;margin-top:8px;">⚠️ 此為估算工具，請依個人財務狀況與風險承受度調整。</p>
    </div>
  `;
}

function renderFullMarketInstPanel(rows, topN = 10) {
  if (!rows || !rows.length) return `<div class="note-box">尚無全市場法人資料。按「全市場法人」按鈕抓取今日 TWSE T86。</div>`;
  const fBuy  = [...rows].sort((a, b) => b.foreignNet - a.foreignNet).slice(0, topN);
  const fSell = [...rows].sort((a, b) => a.foreignNet - b.foreignNet).slice(0, topN);
  const tBuy  = [...rows].sort((a, b) => b.totalNet   - a.totalNet  ).slice(0, topN);
  const date  = rows[0]?.date || "";
  const mkRow = (r, key, jumpable) => {
    const inWL = STOCK_MAP.has(r.code);
    return `<div class="rank-row" ${inWL ? `style="cursor:pointer;" data-search-jump="${escapeHtml(r.code)}"` : ""}>
      <span>${escapeHtml(r.code)} ${escapeHtml(r.name)} ${inWL ? `<span style="font-size:0.7rem;color:var(--accent);">★</span>` : ""}</span>
      <strong class="${changeClass(r[key])}">${r[key] > 0 ? "+" : ""}${formatNumber(r[key], 0)} 張</strong>
    </div>`;
  };
  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:10px;">
        <h3 style="margin:0;font-size:1rem;">全市場三大法人今日買賣超 <span style="font-weight:400;font-size:0.78rem;color:var(--muted);">TWSE T86 ${escapeHtml(date)}</span></h3>
        <span style="color:var(--muted);font-size:0.76rem;">★ = 自選股</span>
      </div>
      <div class="report-grid">
        <article class="rank-card">
          <h3>外資大買 Top ${topN}</h3>
          <div class="rank-list">${fBuy.map((r) => mkRow(r, "foreignNet")).join("")}</div>
        </article>
        <article class="rank-card">
          <h3>外資大賣 Top ${topN}</h3>
          <div class="rank-list">${fSell.filter((r) => r.foreignNet < 0).map((r) => mkRow(r, "foreignNet")).join("") || `<div class="empty">無大賣</div>`}</div>
        </article>
        <article class="rank-card">
          <h3>三大法人合計買超 Top ${topN}</h3>
          <div class="rank-list">${tBuy.map((r) => mkRow(r, "totalNet")).join("")}</div>
        </article>
      </div>
    </div>`;
}

function conceptThemeStocks(themeKey) {
  const removals = new Set((state.userThemeRemovals || {})[themeKey] || []);
  return WATCHLIST.filter((stock) => {
    if (removals.has(stock.code)) return false;
    return (stock.themes || []).includes(themeKey) || stock.group === themeKey;
  });
}

function conceptQuoteEntry(stock) {
  const quote = quoteFor(stock.code);
  const pct = toNumber(quote?.pct);
  let volumeRatio = null;
  try {
    volumeRatio = toNumber(volumeAnomalyInfo(stock.code)?.ratio);
  } catch (_) {}
  return {
    stock,
    quote,
    pct,
    volumeRatio,
    capturedAt: quote?.capturedAt || quote?.fetchedAt || null
  };
}

function conceptRotationStats(themeKey) {
  const stocks = conceptThemeStocks(themeKey);
  const entries = stocks.map(conceptQuoteEntry);
  const quoted = entries.filter((entry) => entry.pct !== null);
  const advancers = quoted.filter((entry) => entry.pct > 0).length;
  const decliners = quoted.filter((entry) => entry.pct < 0).length;
  const flat = quoted.length - advancers - decliners;
  const avgChange = meanNumber(quoted.map((entry) => entry.pct));
  const avgVolumeRatio = meanNumber(entries.map((entry) => entry.volumeRatio));
  const breadth = quoted.length ? (advancers - decliners) / quoted.length * 100 : null;
  const score = (avgChange ?? -999) * 10 + (breadth ?? 0) * 0.25 + (avgVolumeRatio ?? 1);
  const sortedUp = [...quoted].sort((a, b) => b.pct - a.pct || a.stock.code.localeCompare(b.stock.code, "en", { numeric: true }));
  const sortedDown = [...quoted].sort((a, b) => a.pct - b.pct || a.stock.code.localeCompare(b.stock.code, "en", { numeric: true }));
  return {
    key: themeKey,
    label: THEME_LABELS[themeKey] || themeKey,
    stocks,
    entries,
    quoted,
    count: stocks.length,
    quotedCount: quoted.length,
    advancers,
    decliners,
    flat,
    avgChange,
    avgVolumeRatio,
    breadth,
    score,
    topUp: sortedUp.slice(0, 5),
    topDown: sortedDown.slice(0, 5),
    latestCapturedAt: entries
      .map((entry) => entry.capturedAt)
      .filter(Boolean)
      .sort()
      .at(-1) || null
  };
}

function conceptRotationRows() {
  return CONCEPT_ROTATION_THEME_KEYS
    .map(conceptRotationStats)
    .filter((row) => row.count > 0);
}

function conceptRotationChip(row, index) {
  const tone = row.avgChange === null ? "flat" : row.avgChange > 0 ? "up" : row.avgChange < 0 ? "down" : "flat";
  const volumeText = row.avgVolumeRatio !== null ? `量能×${row.avgVolumeRatio.toFixed(1)}` : "量能待日線";
  return `
    <button class="chip ${tone}" type="button" data-concept-theme-filter="${escapeHtml(row.key)}" title="切換到${escapeHtml(row.label)}">
      ${index + 1}. ${escapeHtml(row.label)}
      <strong>${row.avgChange !== null ? formatPct(row.avgChange) : "-"}</strong>
      <span>${row.advancers}/${row.quotedCount || row.count} 漲 · ${escapeHtml(volumeText)}</span>
    </button>`;
}

function conceptStockRows(entries, options = {}) {
  const { limit = 5, empty = "尚無報價，請先更新報價", themeKey = "cpo" } = options;
  const rows = entries.filter((entry) => entry.pct !== null).slice(0, limit);
  if (!rows.length) return `<div class="empty">${escapeHtml(empty)}</div>`;
  return rows.map((entry) => {
    const quote = entry.quote;
    const priceText = quote?.price !== null && quote?.price !== undefined ? ` ${formatNumber(quote.price)}` : "";
    const volumeText = entry.volumeRatio !== null ? ` · 量能×${entry.volumeRatio.toFixed(1)}` : "";
    const subBadge = stockSubcategoryBadgeHtml(entry.stock.code, themeKey);
    return `
      <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(entry.stock.code)}">
        <span>${escapeHtml(entry.stock.code)} ${escapeHtml(entry.stock.name)} ${subBadge}</span>
        <strong class="${changeClass(entry.pct)}">${priceText} ${formatPct(entry.pct)}${escapeHtml(volumeText)}</strong>
      </div>`;
  }).join("");
}

function renderConceptRotationPanel() {
  const rows = conceptRotationRows();
  const withQuotes = rows.filter((row) => row.quotedCount > 0);
  const latestQuoteAt = rows
    .map((row) => row.latestCapturedAt)
    .filter(Boolean)
    .sort()
    .at(-1);
  const strongRows = [...withQuotes].sort((a, b) => b.score - a.score).slice(0, 5);
  const weakRows = [...withQuotes].sort((a, b) => a.score - b.score).slice(0, 5);
  const focusKey = CONCEPT_ROTATION_THEME_KEYS.includes(state.filter) ? state.filter : "cpo";
  const focus = rows.find((row) => row.key === focusKey) || rows.find((row) => row.key === "cpo") || rows[0];
  const focusAvgChange = focus && focus.avgChange !== null && focus.avgChange !== undefined ? focus.avgChange : null;
  const focusAvgVolumeRatio = focus && focus.avgVolumeRatio !== null && focus.avgVolumeRatio !== undefined ? focus.avgVolumeRatio : null;
  const focusTone = focusAvgChange === null ? "flat" : focusAvgChange > 0 ? "up" : focusAvgChange < 0 ? "down" : "flat";
  const coverageText = rows.length
    ? `${withQuotes.reduce((sum, row) => sum + row.quotedCount, 0)}/${rows.reduce((sum, row) => sum + row.count, 0)} 檔`
    : "0/0 檔";

  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap;margin-bottom:12px;">
        <div>
          <h3 style="margin:0 0 6px;font-size:1rem;">今日概念股輪動</h3>
          <p style="color:var(--muted);font-size:0.82rem;line-height:1.5;margin:0;">
            依本機已更新個股報價計算主題平均漲跌、漲跌家數與量能比；資料來源沿用每檔報價的官方 / fallback 標示。報價覆蓋 ${coverageText}，最近抓取 ${escapeHtml(latestQuoteAt ? formatDateTime(latestQuoteAt) : "尚未更新")}。
          </p>
        </div>
        <div class="link-row" style="margin-top:0;">
          <button class="ghost-btn" type="button" data-tab-target="overview">開主題總覽</button>
        </div>
      </div>
      ${withQuotes.length ? `
        <div class="report-grid">
          <article class="rank-card" style="grid-column:1/-1;">
            <h3>輪動強勢 Top 5 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">平均漲跌 + 漲跌家數 + 量能</span></h3>
            <div class="chip-row chip-row-compact">${strongRows.map(conceptRotationChip).join("")}</div>
          </article>
          <article class="rank-card">
            <h3>輪動轉弱 Top 5</h3>
            <div class="chip-row chip-row-compact">${weakRows.map(conceptRotationChip).join("")}</div>
          </article>
          <article class="rank-card">
            <h3>${escapeHtml(focus?.label || "CPO / 矽光子")} 族群狀況</h3>
            <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:10px;color:var(--muted);font-size:0.82rem;">
              <span class="${focusTone}"><strong>${focusAvgChange !== null ? formatPct(focusAvgChange) : "-"}</strong> 平均漲跌</span>
              <span>${focus?.advancers || 0} 漲 / ${focus?.decliners || 0} 跌 / ${focus?.flat || 0} 平</span>
              <span>報價 ${focus?.quotedCount || 0}/${focus?.count || 0} 檔</span>
              <span>${focusAvgVolumeRatio !== null ? `平均量能×${focusAvgVolumeRatio.toFixed(1)}` : "量能待日線"}</span>
            </div>
            <div class="rank-list">${conceptStockRows(focus?.topUp || [], { empty: "此族群尚無上漲報價", themeKey: focus?.key || "cpo" })}</div>
          </article>
          <article class="rank-card">
            <h3>${escapeHtml(focus?.label || "CPO / 矽光子")} 回檔 / 弱勢</h3>
            <div class="rank-list">${conceptStockRows(focus?.topDown || [], { empty: "此族群尚無下跌報價", themeKey: focus?.key || "cpo" })}</div>
          </article>
        </div>
      ` : `
        <div class="empty">尚無可計算的概念股報價。請先按「智慧更新」或「完整更新」。</div>
      `}
    </div>
  `;
}

function renderTodayTradingSignals() {
  const container = $("todaySignalsPanel");
  if (!container) return;
  maybeRefreshDispositionRiskData();
  const allStocks = filteredStocks();

  // ── 市場廣度 ──────────────────────────────────────────────────────────────
  const withQuotes = allStocks.filter((s) => quoteFor(s.code));
  const upCount    = withQuotes.filter((s) => (quoteFor(s.code)?.pct ?? 0) > 0).length;
  const downCount  = withQuotes.filter((s) => (quoteFor(s.code)?.pct ?? 0) < 0).length;
  const flatCount  = withQuotes.length - upCount - downCount;
  let aboveMa20 = 0, aboveMa60 = 0, techReady = 0;
  for (const s of allStocks) {
    try {
      const t = calculateTechnical(s.code);
      if (!t.ready) continue;
      techReady++;
      if (t.ma20 && t.latest.close > t.ma20) aboveMa20++;
      if (t.ma60 && t.latest.close > t.ma60) aboveMa60++;
    } catch (_) {}
  }
  const breadthTone = upCount > downCount ? "up" : upCount < downCount ? "down" : "flat";
  const ma20Pct = techReady ? Math.round(aboveMa20 / techReady * 100) : null;
  const ma60Pct = techReady ? Math.round(aboveMa60 / techReady * 100) : null;

  // ── 月營收 YoY Top 5 ─────────────────────────────────────────────────────
  const revRows = allStocks
    .map((stock) => {
      const rev = revenueFor(stock.code);
      const yoyPct = toNumber(rev?.yoyPct);
      return yoyPct === null ? null : { stock, rev, yoyPct };
    })
    .filter(Boolean)
    .sort((a, b) => b.yoyPct - a.yoyPct);
  const revTop = revRows.slice(0, 5);
  const revBottom = [...revRows].reverse().slice(0, 5);
  const hasRevData = revRows.length > 0;

  // ── 今日外資 / 三大法人 大買 Top 5 ────────────────────────────────────────
  const instRows = allStocks
    .map((s) => {
      const inst = (state.institutional || {})[s.code];
      if (!inst || inst.foreignNet == null) return null;
      return { stock: s, foreignNet: inst.foreignNet ?? 0, totalNet: inst.totalNet ?? 0, date: inst.date || "" };
    })
    .filter(Boolean);
  const foreignTopBuy = [...instRows].sort((a, b) => b.foreignNet - a.foreignNet).slice(0, 5);
  const foreignTopSell = [...instRows].sort((a, b) => a.foreignNet - b.foreignNet).slice(0, 5);
  const totalTopBuy  = [...instRows].sort((a, b) => b.totalNet  - a.totalNet ).slice(0, 5);
  const instDate = instRows[0]?.date || "";

  const instRankRow = (row, key) => `
    <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(row.stock.code)}">
      <span>${escapeHtml(row.stock.code)} ${escapeHtml(row.stock.name)}</span>
      <strong class="${changeClass(row[key])}">${row[key] > 0 ? "+" : ""}${formatNumber(row[key], 0)} 張</strong>
    </div>`;

  // ── 量能異常 ──────────────────────────────────────────────────────────────
  const volEntries = allStocks
    .map((s) => ({ stock: s, vol: volumeAnomalyInfo(s.code) }))
    .filter((e) => e.vol !== null && Math.abs(e.vol.zScore) > 1.5)
    .sort((a, b) => Math.abs(b.vol.zScore) - Math.abs(a.vol.zScore))
    .slice(0, 5);
  const volHtml = volEntries.length
    ? volEntries.map((e) => `
        <div class="rank-row">
          <span>${escapeHtml(e.stock.code)} ${escapeHtml(e.stock.name)} <span class="${e.vol.bullish ? "up" : "down"}" style="font-size:0.76rem;">${e.vol.bullish ? "↑多" : "↓空"}</span></span>
          <strong>${e.vol.zScore.toFixed(1)}σ &nbsp;×${e.vol.ratio.toFixed(1)}</strong>
        </div>`).join("")
    : `<div class="empty">無顯著量能異常（請先更新日線）</div>`;

  const dispositionRiskRows = topDispositionRiskRows(allStocks, 5, { minScore: DISPOSITION_RISK_PROXY_MIN_SCORE });
  const dispositionRiskHtml = dispositionRiskRows.length
    ? dispositionRiskRows.map(({ stock, signal, bucket }) => `
        <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(stock.code)}">
          <span>${escapeHtml(stock.code)} ${escapeHtml(stock.name)}<div style="font-size:0.7rem;color:var(--muted);">${escapeHtml(bucket.shortLabel)} · ${escapeHtml(signal.source || "-")}</div></span>
          <strong>${dispositionRiskChipHtml(signal)} <span style="font-size:0.72rem;color:var(--muted);">${formatNumber(signal.riskScore, 0)}</span></strong>
        </div>`).join("")
    : `<div class="empty">本主題目前沒有官方注意累計或明顯量價 proxy。</div>`;

  // ── 技術 Checklist 做多候選 ───────────────────────────────────────────────
  const techTop = technicalReadyList(allStocks)
    .filter((e) => e.technical.playbook)
    .sort((a, b) => playbookSortScore(b.technical) - playbookSortScore(a.technical))
    .slice(0, 5);
  const techHtml = techTop.length
    ? techTop.map((e) => `
        <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(e.stock.code)}">
          <span>${escapeHtml(e.stock.code)} ${escapeHtml(e.stock.name)}</span>
          <strong class="${trendColorClass(e.technical)}">${e.technical.playbook.checklistPasses}/${e.technical.playbook.checklist.length} · ${escapeHtml(e.technical.playbook.trendLabel)}</strong>
        </div>`).join("")
    : `<div class="empty">請先更新日線</div>`;

  container.innerHTML = `
    <div class="panel-lite" style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;flex-wrap:wrap;gap:8px;">
        <h3 style="margin:0;font-size:1rem;">今日操盤手快訊</h3>
        <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;">
          ${instDate ? `<span style="color:var(--muted);font-size:0.76rem;">自選股法人 ${escapeHtml(instDate)}</span>` : ""}
          <button id="fetchFullMarketInstBtn" class="ghost-btn" type="button" style="font-size:0.74rem;min-height:28px;padding:2px 8px;">全市場法人</button>
        </div>
      </div>
      <div id="fullMarketInstPanel">${renderFullMarketInstPanel(_fullMarketInstCache)}</div>
      <div class="report-grid">
        <article class="rank-card" style="grid-column:1/-1;">
          <h3>市場廣度 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">本主題 ${allStocks.length} 檔</span></h3>
          <div style="display:flex;gap:16px;flex-wrap:wrap;align-items:center;">
            <div>
              <span class="up" style="font-size:1.1rem;font-weight:800;">${upCount}</span>
              <span style="color:var(--muted);font-size:0.82rem;">漲</span>
              &nbsp;
              <span class="down" style="font-size:1.1rem;font-weight:800;">${downCount}</span>
              <span style="color:var(--muted);font-size:0.82rem;">跌</span>
              &nbsp;
              <span style="font-size:1.0rem;font-weight:700;">${flatCount}</span>
              <span style="color:var(--muted);font-size:0.82rem;">平</span>
            </div>
            <div style="color:var(--muted);font-size:0.82rem;">
              ${withQuotes.length ? `報價覆蓋 ${withQuotes.length}/${allStocks.length} 檔` : "尚無報價，請更新"}
            </div>
            ${techReady ? `
            <div style="display:flex;gap:10px;">
              <div>
                <span style="font-size:1.0rem;font-weight:800;color:${ma20Pct >= 60 ? "var(--good)" : ma20Pct <= 40 ? "var(--bad)" : "var(--fg)"};">${ma20Pct}%</span>
                <span style="color:var(--muted);font-size:0.78rem;"> 站上月線</span>
              </div>
              <div>
                <span style="font-size:1.0rem;font-weight:800;color:${ma60Pct >= 60 ? "var(--good)" : ma60Pct <= 40 ? "var(--bad)" : "var(--fg)"};">${ma60Pct}%</span>
                <span style="color:var(--muted);font-size:0.78rem;"> 站上季線</span>
              </div>
            </div>` : `<span style="color:var(--muted);font-size:0.78rem;">均線覆蓋：更新日線後可見</span>`}
          </div>
        </article>
        <article class="rank-card">
          <h3>月營收 YoY 成長 Top 5 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">需先按「月營收」</span></h3>
          <div class="rank-list">${hasRevData ? revTop.map((r) => `
            <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(r.stock.code)}">
              <span>${escapeHtml(r.stock.code)} ${escapeHtml(r.stock.name)}</span>
              <strong class="${changeClass(r.yoyPct)}">${r.yoyPct > 0 ? "+" : ""}${formatNumber(r.yoyPct, 1)}%</strong>
            </div>`).join("") : `<div class="empty">請先按「月營收」更新</div>`}</div>
        </article>
        <article class="rank-card">
          <h3>月營收 YoY 衰退 Top 5</h3>
          <div class="rank-list">${hasRevData ? revBottom.filter((r) => r.yoyPct < 0).map((r) => `
            <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(r.stock.code)}">
              <span>${escapeHtml(r.stock.code)} ${escapeHtml(r.stock.name)}</span>
              <strong class="${changeClass(r.yoyPct)}">${formatNumber(r.yoyPct, 1)}%</strong>
            </div>`).join("") || `<div class="empty">無衰退個股</div>` : `<div class="empty">請先按「月營收」更新</div>`}</div>
        </article>
        <article class="rank-card">
          <h3>外資大買 Top 5</h3>
          <div class="rank-list">${foreignTopBuy.length ? foreignTopBuy.map((r) => instRankRow(r, "foreignNet")).join("") : `<div class="empty">尚無法人資料，請按「籌碼」更新</div>`}</div>
        </article>
        <article class="rank-card">
          <h3>外資大賣 Top 5</h3>
          <div class="rank-list">${foreignTopSell.length ? foreignTopSell.filter((r) => r.foreignNet < 0).map((r) => instRankRow(r, "foreignNet")).join("") || `<div class="empty">無外資大賣</div>` : `<div class="empty">尚無法人資料</div>`}</div>
        </article>
        <article class="rank-card">
          <h3>三大法人合計買超 Top 5</h3>
          <div class="rank-list">${totalTopBuy.length ? totalTopBuy.map((r) => instRankRow(r, "totalNet")).join("") : `<div class="empty">尚無法人資料</div>`}</div>
        </article>
        <article class="rank-card">
          <h3>量能異常 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">z &gt; 1.5σ</span></h3>
          <div class="rank-list">${volHtml}</div>
        </article>
        <article class="rank-card">
          <h3>處置風險 Top 5 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">官方優先</span></h3>
          <div class="rank-list">${dispositionRiskHtml}</div>
        </article>
        <article class="rank-card">
          <h3>技術做多候選 Top 5 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">Checklist 分</span></h3>
          <div class="rank-list">${techHtml}</div>
        </article>
      </div>
    </div>
  `;
}

function renderThemeSummaryCards() {
  const container = $("themeSummaryGrid");
  if (!container) return;
  const themes = THEME_ORDER.filter((k) => k !== "all" && k !== HOLDINGS_THEME_KEY && THEME_LABELS[k]);
  container.innerHTML = themes.map((key) => {
    const stocks = WATCHLIST.filter((s) => (s.themes || []).includes(key) || s.group === key);
    if (!stocks.length) return "";
    const changes = stocks.map((s) => quoteFor(s.code)?.pct ?? null).filter((v) => v !== null && Number.isFinite(v));
    const avgChange = changes.length ? changes.reduce((a, b) => a + b, 0) / changes.length : null;
    let aboveMa20 = 0;
    let alertCount = 0;
    for (const s of stocks) {
      try {
        const t = calculateTechnical(s.code);
        if (t.ready && t.ma20 && t.latest.close > t.ma20) aboveMa20++;
      } catch (_) {}
      if (stockChipSignal(s.code)?.level === "danger") alertCount++;
    }
    const avgClass = avgChange !== null ? (avgChange > 0 ? "up" : avgChange < 0 ? "down" : "flat") : "";
    const isActive = state.filter === key;
    return `
      <div class="theme-summary-card${isActive ? " active" : ""}" data-theme-filter="${escapeHtml(key)}">
        <div class="tscard-name">${escapeHtml(THEME_LABELS[key])}</div>
        <div class="tscard-stats">
          ${avgChange !== null ? `<span class="tscard-chg ${avgClass}">${avgChange > 0 ? "+" : ""}${avgChange.toFixed(1)}%</span>` : `<span class="tscard-chg flat">-</span>`}
          ${alertCount ? `<span class="tscard-alert">⚠ ${alertCount}</span>` : ""}
        </div>
        <div class="tscard-foot">月線↑ ${aboveMa20}/${stocks.length}</div>
      </div>`;
  }).join("");
}

function themeRegimeFeatureForStock(stock) {
  const code = stock?.code || "";
  const quote = quoteFor(code);
  const revenue = revenueFor(code);
  const institutional = institutionalFor(code);
  const margin = (state.margin || {})[code] || null;
  const klines = latestKlines(code);
  const latestKline = klines.at(-1) || null;
  const chipSignal = stockChipSignal(code);
  const activeEtfSignal = activeEtfStockSignal(code);
  const volume = volumeAnomalyInfo(code);
  let technical = null;
  let rsMulti = null;
  try { technical = calculateTechnical(code); } catch (_) { technical = null; }
  try { rsMulti = calculateRSMulti(code); } catch (_) { rsMulti = null; }
  return {
    code,
    name: stock?.name || "",
    quotePct: toNumber(quote?.pct),
    quoteDate: quote?.sourceDate || "",
    quoteFallback: Boolean(quote?.fallbackUsed || quote?.sourceKind === "fallback"),
    quoteSourceKind: quote?.sourceKind || "",
    klineDate: technical?.latest?.date || latestKline?.date || "",
    techReady: Boolean(technical?.ready),
    aboveMa20: Boolean(technical?.ready && technical.ma20 && technical.latest?.close > technical.ma20),
    aboveMa60: Boolean(technical?.ready && technical.ma60 && technical.latest?.close > technical.ma60),
    rs21: toNumber(rsMulti?.r21),
    rs65: toNumber(rsMulti?.r65),
    volumeRatio: toNumber(volume?.ratio),
    volumeZ: toNumber(volume?.zScore),
    revenueYoy: toNumber(revenue?.yoyPct),
    revenueMom: toNumber(revenue?.momPct),
    revenueDate: revenue?.yearMonth || revenue?.period || revenue?.date || "",
    chipScore: toNumber(chipSignal?.score),
    chipLevel: chipSignal?.level || "",
    chipLabel: chipSignal?.text || chipSignal?.label || "",
    institutionalNet: toNumber(institutional?.totalNet),
    institutionalDate: institutional?.date || "",
    marginDate: margin?.date || "",
    activeEtfScore: activeEtfSignal?.hasData ? toNumber(activeEtfSignal.score) : null,
    activeEtfLabel: activeEtfSignal?.hasData ? activeEtfSignal.label : ""
  };
}

function themeRegimeRows() {
  const framework = window.TwStockThemeRegime;
  if (!framework?.buildThemeRegimeRows) return [];
  const themeKeys = THEME_ORDER.filter((key) => (
    key !== "all"
    && key !== HOLDINGS_THEME_KEY
    && THEME_LABELS[key]
    && !String(key).startsWith(CUSTOM_GROUP_ID_PREFIX)
  ));
  const themes = themeKeys.map((key) => {
    const stocks = themeRegimeStocksForKey(key);
    return {
      key,
      label: THEME_LABELS[key] || key,
      features: stocks.map(themeRegimeFeatureForStock)
    };
  }).filter((theme) => theme.features.length);
  return framework.buildThemeRegimeRows(themes).map((row) => {
    const holdings = themeHoldingExposureForKey(row.key);
    return {
      ...row,
      holdings,
      holdingCount: holdings.length
    };
  });
}

let _themeRegimeRowsShortCache = { ts: 0, rows: [] };
function cachedThemeRegimeRows(maxAgeMs = 1800) {
  const now = Date.now();
  if (_themeRegimeRowsShortCache.rows.length && now - _themeRegimeRowsShortCache.ts < maxAgeMs) {
    return _themeRegimeRowsShortCache.rows;
  }
  const rows = themeRegimeRows();
  _themeRegimeRowsShortCache = { ts: now, rows };
  return rows;
}

function themeRegimeStocksForKey(key) {
  return WATCHLIST
    .filter((stock) => (stock.themes || []).includes(key) || stock.group === key)
    .filter((stock, index, list) => list.findIndex((item) => item.code === stock.code) === index);
}

function themeHoldingExposureForKey(key) {
  const themeCodes = new Set(themeRegimeStocksForKey(key).map((stock) => stock.code));
  return (state.holdings || [])
    .map((entry) => normalizeHoldingEntry(entry))
    .filter((entry) => entry && themeCodes.has(entry.code))
    .map((entry) => ({
      code: entry.code,
      name: entry.name || STOCK_MAP.get(entry.code)?.name || ""
    }));
}

function themeRegimeActionQueueRows(rows, max = 8) {
  const framework = window.TwStockThemeRegime;
  if (!framework?.buildThemeActionQueue) return [];
  return framework.buildThemeActionQueue(rows, { max });
}

function formatThemeRegimePercent(value, digits = 0) {
  const n = toNumber(value);
  if (n === null) return "-";
  return `${formatNumber(n * 100, digits)}%`;
}

function themeRegimeStockRows(rows, emptyText) {
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) return `<div class="empty">${escapeHtml(emptyText || "尚無資料")}</div>`;
  return list.map((row) => `
    <div class="rank-row" style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(row.code)}">
      <span>${escapeHtml(row.code)} ${escapeHtml(row.name || "")}<div style="font-size:0.7rem;color:var(--muted);">${escapeHtml(row.activeEtfLabel || row.chipLabel || "本機 proxy")}</div></span>
      <strong class="${changeClass(row.quotePct)}">${row.quotePct !== null && row.quotePct !== undefined ? formatPct(row.quotePct) : "-"}</strong>
    </div>
  `).join("");
}

function goodBossRows() {
  return GOOD_BOSS_CODES.map((code) => {
    const stock = STOCK_MAP.get(code);
    const profile = GOOD_BOSS_PROFILES[code];
    if (!stock || !profile) return null;
    return { stock, profile };
  }).filter(Boolean);
}

function goodBossRiskTone(level) {
  if (level === "high") return "warn";
  if (level === "medium-high") return "warn";
  if (level === "medium") return "flat";
  return "up";
}

function goodBossQualityLabel(score) {
  if (score >= 90) return { label: "核心好老闆", tone: "up" };
  if (score >= 84) return { label: "高品質觀察", tone: "good" };
  if (score >= 78) return { label: "紀律型觀察", tone: "flat" };
  return { label: "需再複核", tone: "warn" };
}

function goodBossReviewPriority(row) {
  let score = 0;
  const coverage = row.coverage || {};
  score += (coverage.missing || []).length * 9;
  if (coverage.fallbackUsed) score += 12;
  if (row.riskLevel === "high") score += 18;
  else if (row.riskLevel === "medium-high") score += 12;
  else if (row.riskLevel === "medium") score += 6;
  if ((row.verifyItems || []).length >= 4) score += 5;
  if (row.sourceNote && /研究註記|研究假設|需/.test(row.sourceNote)) score += 8;
  if (score >= 42) return { label: "高", score, tone: "warn" };
  if (score >= 24) return { label: "中", score, tone: "flat" };
  return { label: "低", score, tone: "up" };
}

function goodBossAuditRows() {
  return goodBossRows().map(({ stock, profile }) => {
    const scorecard = profile.scorecard || {};
    const scoreValues = ["culture", "succession", "capital", "moat", "candor"]
      .map((key) => toNumber(scorecard[key]))
      .filter((value) => value !== null);
    const baseScore = scoreValues.length ? meanNumber(scoreValues) : null;
    const coverage = classificationAuditCoverage(stock);
    const coveragePct = coverage.totalCount ? coverage.availableCount / coverage.totalCount : 0;
    const coverageAdjustment = Math.round((coveragePct - 0.7) * 10);
    const riskPenalty = profile.riskLevel === "high" ? 4 : profile.riskLevel === "medium-high" ? 2 : 0;
    const qualityScore = baseScore === null
      ? null
      : clamp(Math.round(baseScore + coverageAdjustment - riskPenalty), 0, 100);
    const quality = qualityScore === null ? { label: "待評分", tone: "flat" } : goodBossQualityLabel(qualityScore);
    const riskTone = goodBossRiskTone(profile.riskLevel);
    const row = {
      code: stock.code,
      suffix: stock.suffix || "",
      name: stock.name || "",
      sector: stock.sector || stock.officialIndustry || "",
      archetype: profile.archetype || "",
      qualityScore,
      qualityLabel: quality.label,
      qualityTone: quality.tone,
      riskLevel: profile.riskLevel || "medium",
      riskTone,
      scorecard,
      coverage,
      coveragePct,
      verifyItems: profile.verifyItems || [],
      watchRules: profile.watchRules || [],
      sourceNote: profile.sourceNote || "",
      thesis: profile.thesis || "",
      risk: profile.risk || "",
      links: classificationAuditOfficialLinks(stock).slice(0, 3)
    };
    row.reviewPriority = goodBossReviewPriority(row);
    return row;
  }).sort((left, right) => (right.qualityScore ?? -1) - (left.qualityScore ?? -1));
}

function goodBossCandidatePriority(row) {
  let score = 18;
  const coverage = row.coverage || {};
  score += (coverage.missing || []).length * 8;
  if (coverage.fallbackUsed) score += 10;
  if (row.riskLevel === "high") score += 16;
  else if (row.riskLevel === "medium-high") score += 10;
  else if (row.riskLevel === "medium") score += 5;
  if ((row.verifyItems || []).length >= 4) score += 4;
  if (row.sourceNote && /待複核|尚未升級|需/.test(row.sourceNote)) score += 8;
  if (score >= 46) return { label: "高", score, tone: "warn" };
  if (score >= 30) return { label: "中", score, tone: "flat" };
  return { label: "低", score, tone: "up" };
}

function goodBossCandidateRows() {
  return GOOD_BOSS_CANDIDATE_CODES.filter((code) => !GOOD_BOSS_CODES.includes(code)).map((code) => {
    const stock = STOCK_MAP.get(code);
    const profile = RESEARCH_CANDIDATE_PROFILES[code];
    if (!stock || !profile) return null;
    const coverage = classificationAuditCoverage(stock);
    const groupMeta = RESEARCH_CANDIDATE_GROUPS[profile.groupKey] || RESEARCH_CANDIDATE_GROUPS.operating;
    const row = {
      code: stock.code,
      suffix: stock.suffix || "",
      name: stock.name || "",
      sector: stock.sector || stock.officialIndustry || "",
      groupKey: profile.groupKey || "operating",
      group: groupMeta.label,
      groupDescription: groupMeta.description,
      groupVerifyFocus: groupMeta.verifyFocus,
      archetype: profile.archetype || "",
      stage: profile.stage || "待複核候選",
      riskLevel: profile.riskLevel || "medium",
      riskTone: goodBossRiskTone(profile.riskLevel),
      coverage,
      verifyItems: profile.verifyItems || [],
      watchRules: profile.watchRules || [],
      sourceNote: profile.sourceNote || "",
      thesis: profile.thesis || "",
      risk: profile.risk || "",
      links: classificationAuditOfficialLinks(stock).slice(0, 3)
    };
    row.reviewPriority = goodBossCandidatePriority(row);
    return row;
  }).filter(Boolean).sort((left, right) => {
    if (left.groupKey !== right.groupKey) return left.groupKey.localeCompare(right.groupKey);
    if (right.reviewPriority.score !== left.reviewPriority.score) return right.reviewPriority.score - left.reviewPriority.score;
    return left.code.localeCompare(right.code);
  });
}

function goodBossCandidateGroupRows(candidateRows) {
  const groups = new Map();
  for (const row of candidateRows || []) {
    const key = row.groupKey || "operating";
    if (!groups.has(key)) {
      const meta = RESEARCH_CANDIDATE_GROUPS[key] || RESEARCH_CANDIDATE_GROUPS.operating;
      groups.set(key, {
        key,
        label: meta.label,
        description: meta.description,
        verifyFocus: meta.verifyFocus,
        rows: []
      });
    }
    groups.get(key).rows.push(row);
  }
  return Array.from(groups.values()).map((group) => ({
    ...group,
    count: group.rows.length,
    highCount: group.rows.filter((row) => row.reviewPriority.label === "高").length,
    codes: group.rows.map((row) => `${row.code} ${row.name}`.trim())
  })).sort((left, right) => {
    if (right.count !== left.count) return right.count - left.count;
    return left.label.localeCompare(right.label);
  });
}

function goodBossScoreCells(scorecard) {
  const items = [
    ["文化", scorecard.culture],
    ["接班", scorecard.succession],
    ["資本", scorecard.capital],
    ["壁壘", scorecard.moat],
    ["坦率", scorecard.candor]
  ];
  return items.map(([label, value]) => `<span class="chip flat" style="font-size:0.70rem;">${escapeHtml(label)} ${formatNumber(value, 0)}</span>`).join("");
}

