function themeRegimeActionQueueHtml(queueRows) {
  const list = Array.isArray(queueRows) ? queueRows : [];
  if (!list.length) return `<div class="empty">目前沒有足夠資料建立盤前行動佇列。</div>`;
  return list.map((row) => {
    const holdingsText = row.holdings?.length
      ? `持股：${row.holdings.slice(0, 4).map((item) => `${item.code} ${item.name || ""}`.trim()).join("、")}${row.holdings.length > 4 ? "…" : ""}`
      : "未持有";
    const checklist = row.checklist?.length ? row.checklist.join("｜") : "待盤中確認";
    return `
      <div class="rank-row" data-theme-action-filter="${escapeHtml(row.key)}" style="cursor:pointer;align-items:flex-start;">
        <span>
          <strong>${escapeHtml(row.category)}</strong> · ${escapeHtml(row.label)}
          <div style="font-size:0.7rem;color:var(--muted);margin-top:2px;">${escapeHtml(row.regimeLabel)} · ${escapeHtml(row.rotation || "-")} · ${escapeHtml(holdingsText)}</div>
          <div style="font-size:0.7rem;color:var(--muted);margin-top:2px;">${escapeHtml(row.action)}</div>
          <div style="font-size:0.68rem;color:var(--muted);margin-top:2px;">${escapeHtml(checklist)}</div>
        </span>
        <strong class="${escapeHtml(row.tone || "flat")}">${formatNumber(row.priority, 0)}</strong>
      </div>
    `;
  }).join("");
}

function renderThemeRegimePanel() {
  const container = $("themeRegimePanel");
  if (!container) return;
  const rows = cachedThemeRegimeRows();
  if (!rows.length) {
    container.innerHTML = `<div class="empty">目前沒有足夠主題資料可計算產業趨勢雷達。</div>`;
    return;
  }

  const selectedKey = state.filter && !["all", HOLDINGS_THEME_KEY].includes(state.filter) ? state.filter : "";
  const selected = rows.find((row) => row.key === selectedKey) || rows[0];
  const topRows = rows.slice(0, 6);
  const actionQueue = themeRegimeActionQueueRows(rows, 8);
  const method = selected.methodVersion || window.TwStockThemeRegime?.version || "theme-regime";
  const scoreClass = selected.regime?.tone === "up" ? "up" : selected.regime?.tone === "down" ? "down" : selected.regime?.tone === "warn" ? "warn" : "flat";
  const missingText = selected.missing?.length ? selected.missing.join("、") : "主要資料齊備";

  container.innerHTML = `
    <div class="panel-lite" data-theme-regime-panel style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap;margin-bottom:12px;">
        <div>
          <div style="margin:0;font-size:1rem;font-weight:800;">產業趨勢雷達</div>
          <p style="margin:6px 0 0;color:var(--muted);font-size:0.78rem;line-height:1.55;">本面板是工具內 derived proxy，用現有快取資料判斷主題 regime；confidence 低或缺資料時需先回官方來源補齊。</p>
        </div>
        <div class="chip-row chip-row-compact" style="justify-content:flex-end;">
          <button id="exportThemeRegimeCsvBtn" class="ghost-btn" type="button" style="font-size:0.78rem;">匯出主線 CSV</button>
          <span class="chip ${escapeHtml(scoreClass)}">方法 ${escapeHtml(method)} · ${escapeHtml(selected.confidence || "low")}</span>
        </div>
      </div>
      <div class="report-grid">
        <article class="rank-card" style="grid-column:1/-1;">
          <h3>主線 Top 6</h3>
          <div class="rank-list">
            ${topRows.map((row) => `
              <div class="rank-row" data-theme-regime-filter="${escapeHtml(row.key)}" style="cursor:pointer;">
                <span>${escapeHtml(row.label)}<div style="font-size:0.7rem;color:var(--muted);">${escapeHtml(row.regime.label)} · ${escapeHtml(row.rotation)} · ${escapeHtml(row.latestAsOf || "日期待補")}</div></span>
                <strong class="${escapeHtml(row.regime.tone || "flat")}">${formatNumber(row.score, 0)}</strong>
              </div>
            `).join("")}
          </div>
        </article>
        <article class="rank-card" data-theme-action-queue style="grid-column:1/-1;">
          <h3>盤前主線行動佇列</h3>
          <div class="rank-list">${themeRegimeActionQueueHtml(actionQueue)}</div>
        </article>
        <article class="rank-card" data-theme-regime-row="${escapeHtml(selected.key)}">
          <h3>${escapeHtml(selected.label)}</h3>
          <div class="kv-row"><span>Regime</span><strong class="${escapeHtml(scoreClass)}">${escapeHtml(selected.regime.label)} · ${formatNumber(selected.score, 0)}</strong></div>
          <div class="kv-row"><span>輪動型態</span><strong>${escapeHtml(selected.rotation)}</strong></div>
          <div class="kv-row"><span>行動</span><strong style="font-size:0.78rem;">${escapeHtml(selected.regime.stage)}</strong></div>
          <p style="margin:8px 0 0;color:var(--muted);font-size:0.78rem;line-height:1.55;">${escapeHtml(selected.action || "")}</p>
        </article>
        <article class="rank-card">
          <h3>廣度 / 動能</h3>
          <div class="kv-row"><span>平均漲跌</span><strong class="${changeClass(selected.metrics.avgChange)}">${selected.metrics.avgChange !== null ? formatPct(selected.metrics.avgChange) : "-"}</strong></div>
          <div class="kv-row"><span>上漲比</span><strong>${formatThemeRegimePercent(selected.metrics.advanceRatio)}</strong></div>
          <div class="kv-row"><span>站上月線</span><strong>${formatThemeRegimePercent(selected.metrics.aboveMa20Ratio)}</strong></div>
          <div class="kv-row"><span>站上季線</span><strong>${formatThemeRegimePercent(selected.metrics.aboveMa60Ratio)}</strong></div>
        </article>
        <article class="rank-card">
          <h3>基本面 / 籌碼</h3>
          <div class="kv-row"><span>月營收中位 YoY</span><strong class="${changeClass(selected.metrics.revMedianYoy)}">${selected.metrics.revMedianYoy !== null ? formatPct(selected.metrics.revMedianYoy) : "-"}</strong></div>
          <div class="kv-row"><span>營收正成長</span><strong>${formatThemeRegimePercent(selected.metrics.revPositiveRatio)}</strong></div>
          <div class="kv-row"><span>平均 Chip</span><strong>${selected.metrics.avgChip !== null ? formatNumber(selected.metrics.avgChip, 1) : "-"}</strong></div>
          <div class="kv-row"><span>法人偏買</span><strong>${formatThemeRegimePercent(selected.metrics.instBuyRatio)}</strong></div>
        </article>
        <article class="rank-card">
          <h3>資料信心</h3>
          <div class="kv-row"><span>覆蓋率</span><strong>${formatNumber(selected.metrics.coveragePct, 0)}%</strong></div>
          <div class="kv-row"><span>樣本</span><strong>${formatNumber(selected.metrics.count, 0)} 檔</strong></div>
          <div class="kv-row"><span>最新日期</span><strong>${escapeHtml(selected.latestAsOf || "-")}</strong></div>
          <div class="kv-row"><span>缺口</span><strong style="font-size:0.78rem;">${escapeHtml(missingText)}</strong></div>
        </article>
        <article class="rank-card">
          <h3>領漲候選</h3>
          <div class="rank-list">${themeRegimeStockRows(selected.leaders, "尚無領漲候選")}</div>
        </article>
        <article class="rank-card">
          <h3>弱勢 / 待修復</h3>
          <div class="rank-list">${themeRegimeStockRows(selected.laggards, "尚無弱勢資料")}</div>
        </article>
      </div>
    </div>
  `;
}

