function classificationAuditThemeKey(stock) {
  if (!stock) return state.filter || "all";
  if (!currentSearchText() && state.filter && state.filter !== "all" && state.filter !== HOLDINGS_THEME_KEY) {
    return state.filter;
  }
  return stock.primaryTheme || (stock.themes || [])[0] || state.filter || "all";
}

function classificationAuditRole(stock, themeKey) {
  const subcategory = stockSubcategoryLabel(stock.code, themeKey);
  const purity = toNumber(stock.theme);
  const reasons = [];
  const customTheme = typeof CUSTOM_GROUP_ID_PREFIX !== "undefined" && String(themeKey || "").startsWith(CUSTOM_GROUP_ID_PREFIX);
  const override = CLASSIFICATION_ROLE_OVERRIDES[stock.code];
  if (override && (themeKey === "pcb" || themeKey === "passive" || themeKey === "thermal" || (stock.themes || []).includes(themeKey))) {
    return override;
  }

  if (stock.userDefined || customTheme) reasons.push(stock.userDefined ? "使用者自選股" : "自訂類股");
  if (/待複核|低純度|廣義/.test(subcategory)) reasons.push(`子分類：${subcategory}`);
  if (purity !== null) reasons.push(`主題純度 ${formatNumber(purity, 0)}%`);

  if (stock.userDefined || customTheme || /待複核|低純度|廣義/.test(subcategory) || (purity !== null && purity < 55)) {
    return {
      role: "待複核",
      className: "warn",
      reason: reasons.join("；") || "需要回官方資料與第二來源確認分類"
    };
  }

  if (
    stock.group === "anchor"
    || stock.group === "core"
    || purity >= 85
    || /核心|第一梯隊|晶圓代工|高息 \/ 低波|台灣主動式ETF/.test(subcategory)
  ) {
    return {
      role: "核心",
      className: "good",
      reason: reasons.join("；") || "內建核心清單 / 高主題純度"
    };
  }

  return {
    role: "延伸",
    className: "flat",
    reason: reasons.join("；") || "主題延伸股池，仍需用官方營收與公告交叉比對"
  };
}

function classificationAuditOfficialLinks(stock) {
  const marketLabel = stock.suffix === "TWO" ? "TPEx 基本資料" : "TWSE 基本資料";
  const links = [
    { label: marketLabel, url: companyProfileUrl(stock) },
    { label: "MOPS 月營收", url: "https://mops.twse.com.tw/mops/web/t21sc04" },
    { label: "MOPS 財報", url: "https://mops.twse.com.tw/mops/web/t163sb04" }
  ];
  if (isEtfCode(stock.code)) {
    const official = ACTIVE_ETF_OFFICIAL_SOURCES[stock.code]?.[0]
      || { label: "TWSE ETF e添富", url: `https://www.twse.com.tw/zh/ETFortune-institute/etfInfo/${stock.code}` };
    return [official, ...links.slice(0, 1)];
  }
  return links;
}

function classificationAuditCoverage(stock) {
  const quote = quoteFor(stock.code);
  const valuation = valuationFor(stock.code);
  const revenue = revenueFor(stock.code);
  const institutional = institutionalFor(stock.code);
  const margin = (state.margin || {})[stock.code] || null;
  const klines = Array.isArray(state.klines?.[stock.code]) ? state.klines[stock.code] : [];
  const latestKline = klines.at(-1) || null;
  const items = [
    {
      label: "報價",
      available: Boolean(quote),
      asOf: quote?.sourceDate || "",
      source: quote?.source || "",
      sourceTier: quote?.sourceKind === "official" ? "Tier 1 官方" : quote ? "Tier 2 fallback" : "missing",
      fallback: Boolean(quote?.fallbackUsed || quote?.sourceKind === "fallback")
    },
    {
      label: "日線",
      available: klines.length >= 20,
      asOf: latestKline?.date || "",
      source: klines.length ? `${klines.length} bars` : "",
      sourceTier: klines.length ? "Tier 1 官方 / 快取" : "missing",
      fallback: false
    },
    {
      label: "估值",
      available: Boolean(valuation),
      asOf: valuation?.sourceDate || valuation?.date || "",
      source: valuation?.sourceLabel || valuation?.source || "",
      sourceTier: valuation ? "Tier 1 官方" : "missing",
      fallback: false
    },
    {
      label: "月營收",
      available: Boolean(revenue),
      asOf: revenue?.yearMonth || revenue?.period || revenue?.date || "",
      source: revenue?.source || "TWSE / TPEx OpenAPI",
      sourceTier: revenue ? "Tier 1 官方" : "missing",
      fallback: false
    },
    {
      label: "三大法人",
      available: Boolean(institutional),
      asOf: institutional?.date || "",
      source: institutional?.source || "",
      sourceTier: institutional ? "Tier 1 官方" : "missing",
      fallback: false
    },
    {
      label: "融資券",
      available: Boolean(margin),
      asOf: margin?.date || "",
      source: margin?.source || "",
      sourceTier: margin ? "Tier 1 官方" : "missing",
      fallback: false
    }
  ];
  const available = items.filter((item) => item.available);
  const missing = items.filter((item) => !item.available).map((item) => item.label);
  const officialCount = available.filter((item) => /官方|Tier 1/.test(item.sourceTier)).length;
  const latestAsOf = latestDateLabel(items.map((item) => item.asOf));
  return {
    items,
    availableCount: available.length,
    totalCount: items.length,
    officialCount,
    missing,
    fallbackUsed: items.some((item) => item.fallback),
    latestAsOf,
    sourceTierSummary: topCountSummary(available.map((item) => item.sourceTier), 2) || "待更新",
    quoteSource: quote?.source || "",
    quoteDate: quote?.sourceDate || "",
    valuationDate: valuation?.sourceDate || valuation?.date || "",
    revenueDate: revenue?.yearMonth || revenue?.period || revenue?.date || "",
    institutionalDate: institutional?.date || "",
    marginDate: margin?.date || ""
  };
}

function classificationAuditConfidence(roleInfo, coverage) {
  if (roleInfo.role === "待複核") return "low";
  if (coverage.fallbackUsed) return coverage.availableCount >= 4 ? "medium" : "low";
  if (coverage.availableCount >= 5 && coverage.officialCount >= 4) return "medium-high";
  if (coverage.availableCount >= 3) return "medium";
  return "low";
}

function classificationAuditRows(stocks = filteredStocks()) {
  return sortedWatchlist(stocks).map((stock) => {
    const themeKey = classificationAuditThemeKey(stock);
    const roleInfo = classificationAuditRole(stock, themeKey);
    const coverage = classificationAuditCoverage(stock);
    const confidence = classificationAuditConfidence(roleInfo, coverage);
    const subcategory = stockSubcategoryLabel(stock.code, themeKey) || stock.sector || stock.officialIndustry || "-";
    const links = classificationAuditOfficialLinks(stock);
    const needs = [];
    if (roleInfo.role === "待複核") needs.push("分類待複核");
    if (coverage.fallbackUsed) needs.push("報價 fallback");
    needs.push(...coverage.missing.map((label) => `缺${label}`));
    return {
      code: stock.code,
      suffix: stock.suffix || "",
      name: stock.name || "",
      market: stock.market || (stock.suffix === "TWO" ? "上櫃" : "上市"),
      themeKey,
      themeLabel: THEME_LABELS[themeKey] || themeKey || "-",
      subcategory,
      role: roleInfo.role,
      roleClass: roleInfo.className,
      reason: roleInfo.reason,
      coverage,
      confidence,
      needs: uniqueList(needs),
      links
    };
  });
}

const CLASSIFICATION_WORKLIST_WEIGHTS = {
  "分類待複核": 30,
  "報價 fallback": 18,
  "缺報價": 24,
  "缺日線": 20,
  "缺估值": 14,
  "缺月營收": 16,
  "缺三大法人": 12,
  "缺融資券": 10
};
const CLASSIFICATION_REPAIR_MAX_TARGETS = 24;
const CLASSIFICATION_REPAIR_ACTIONS = [
  {
    key: "quotes",
    label: "補報價",
    issues: ["缺報價", "報價 fallback"],
    note: "更新 worklist 內缺報價 / fallback 標的"
  },
  {
    key: "klines",
    label: "補日線",
    issues: ["缺日線"],
    note: "補日線樣本，讓技術排行與過熱 / 超賣 proxy 可重算"
  },
  {
    key: "revenue",
    label: "補月營收",
    issues: ["缺月營收"],
    note: "沿用既有 TWSE / TPEx 月營收整包更新"
  },
  {
    key: "valuation",
    label: "補估值",
    issues: ["缺估值"],
    note: "更新交易所估值與市值級距"
  },
  {
    key: "chip",
    label: "補籌碼",
    issues: ["缺三大法人", "缺融資券"],
    note: "更新三大法人、融資券、外資持股與 TDCC"
  },
  {
    key: "review",
    label: "分類待複核",
    issues: ["分類待複核"],
    note: "回 MOPS / 法說 / 月營收入口人工核對"
  }
];

function classificationWorklistPriority(row) {
  let score = 0;
  const issues = uniqueList(row.needs || []);
  for (const issue of issues) score += CLASSIFICATION_WORKLIST_WEIGHTS[issue] || 6;
  if (row.confidence === "low") score += 18;
  else if (row.confidence === "medium") score += 6;
  if (row.role === "待複核") score += 10;
  if (row.coverage.availableCount <= 2) score += 12;
  else if (row.coverage.availableCount <= 4) score += 5;
  return score;
}

function classificationWorklistLevel(score) {
  if (score >= 60) return { label: "高", className: "warn" };
  if (score >= 30) return { label: "中", className: "flat" };
  return { label: "低", className: "good" };
}

function classificationWorklistAction(row) {
  const needs = new Set(row.needs || []);
  if (needs.has("分類待複核")) return "先回 MOPS / 法說 / 月營收確認營收暴露，再決定是否留在此主題";
  if (needs.has("缺報價") || needs.has("報價 fallback")) return "先跑報價更新並核對 TWSE / TPEx 日期";
  if (needs.has("缺日線")) return "先更新日線，避免技術排行與過熱 / 超賣 proxy 缺樣本";
  if (needs.has("缺月營收")) return "補月營收，確認題材是否有營運動能支撐";
  if (needs.has("缺估值")) return "補交易所估值，讓 PE / PBR / 殖利率可交叉比對";
  if (needs.has("缺三大法人")) return "補三大法人，確認主題股是否有法人參與";
  if (needs.has("缺融資券")) return "補融資券，檢查槓桿籌碼是否擁擠";
  return "維持追蹤；低優先度";
}

function classificationWorklistRows(auditRows = classificationAuditRows()) {
  const confidenceRank = { low: 0, medium: 1, "medium-high": 2 };
  return auditRows
    .map((row) => {
      const score = classificationWorklistPriority(row);
      const level = classificationWorklistLevel(score);
      return {
        ...row,
        priorityScore: score,
        priorityLabel: level.label,
        priorityClass: level.className,
        action: classificationWorklistAction(row)
      };
    })
    .filter((row) => row.priorityScore > 0 || row.confidence !== "medium-high")
    .sort((a, b) =>
      b.priorityScore - a.priorityScore
      || ((confidenceRank[a.confidence] ?? 9) - (confidenceRank[b.confidence] ?? 9))
      || a.code.localeCompare(b.code, undefined, { numeric: true })
    );
}

function classificationRepairActionConfig(actionKey) {
  return CLASSIFICATION_REPAIR_ACTIONS.find((action) => action.key === actionKey) || null;
}

function classificationRepairQueueItems(auditRows = classificationAuditRows()) {
  const worklistRows = classificationWorklistRows(auditRows);
  return CLASSIFICATION_REPAIR_ACTIONS.map((action) => {
    const rows = worklistRows.filter((row) => {
      const needs = new Set(row.needs || []);
      return action.issues.some((issue) => needs.has(issue));
    });
    const codes = uniqueList(rows.map((row) => row.code));
    return {
      ...action,
      rows,
      codes,
      count: codes.length,
      visibleCodes: codes.slice(0, 5)
    };
  }).filter((item) => item.count > 0);
}

function renderClassificationRepairQueuePanel(auditRows) {
  const items = classificationRepairQueueItems(auditRows);
  if (!items.length) return "";
  return `
    <div class="note-box" data-classification-repair-queue style="margin:0 0 10px;">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;flex-wrap:wrap;">
        <div>
          <strong>批次補資料佇列</strong>
          <div style="color:var(--muted);font-size:0.78rem;line-height:1.5;margin-top:3px;">
            依 worklist 缺口產生操作入口；報價、日線、估值、籌碼會限制在前 ${formatNumber(CLASSIFICATION_REPAIR_MAX_TARGETS, 0)} 檔高優先標的，月營收沿用官方整包更新。
          </div>
        </div>
        <div class="chip-row chip-row-compact" style="justify-content:flex-end;">
          ${items.map((item) => `
            <button class="ghost-btn" type="button" data-classification-repair="${escapeHtml(item.key)}" title="${escapeHtml(item.note)}" style="font-size:0.76rem;">
              ${escapeHtml(item.label)} ${formatNumber(item.count, 0)}
            </button>
          `).join("")}
        </div>
      </div>
      <div class="chip-row chip-row-compact" style="margin-top:8px;">
        ${items.map((item) => `
          <span class="chip">
            ${escapeHtml(item.label)}：${escapeHtml(item.visibleCodes.join("、") || "-")}${item.count > item.visibleCodes.length ? "…" : ""}
          </span>
        `).join("")}
      </div>
    </div>
  `;
}

function renderClassificationWorklistPanel(auditRows) {
  const rows = classificationWorklistRows(auditRows);
  if (!rows.length) {
    return `
      <div class="note-box" data-classification-worklist style="margin:0 0 12px;">
        目前範圍沒有高優先補資料項目；仍建議定期重新更新報價、日線、月營收與法人資料。
      </div>
    `;
  }
  const visibleRows = rows.slice(0, CLASSIFICATION_WORKLIST_VISIBLE_LIMIT);
  const highCount = rows.filter((row) => row.priorityLabel === "高").length;
  const mediumCount = rows.filter((row) => row.priorityLabel === "中").length;
  const topIssueText = topCountSummary(rows.flatMap((row) => row.needs || []), 4) || "待複核";
  return `
    <div data-classification-worklist style="margin:0 0 14px;">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:10px;flex-wrap:wrap;margin-bottom:8px;">
        <div>
          <h3 style="margin:0 0 5px;font-size:0.95rem;">補資料優先清單</h3>
          <p style="margin:0;color:var(--muted);font-size:0.8rem;line-height:1.5;">依缺資料、fallback、low confidence 與待複核分類加權排序；這是資料品質 worklist，不是買賣訊號。</p>
        </div>
        <div class="chip-row chip-row-compact">
          <span class="chip warn">高 ${formatNumber(highCount, 0)}</span>
          <span class="chip">中 ${formatNumber(mediumCount, 0)}</span>
          <span class="chip">主要缺口：${escapeHtml(topIssueText)}</span>
          <button id="exportClassificationWorklistCsvBtn" class="ghost-btn" type="button" style="font-size:0.78rem;">匯出補資料清單 CSV</button>
        </div>
      </div>
      ${renderClassificationRepairQueuePanel(auditRows)}
      <div class="table-wrap">
        <table style="min-width:1060px;">
          <thead>
            <tr>
              <th>優先</th>
              <th>代碼</th>
              <th>缺口</th>
              <th>下一步</th>
              <th>核對入口</th>
            </tr>
          </thead>
          <tbody>
            ${visibleRows.map((row) => `
              <tr>
                <td>
                  <span class="chip ${escapeHtml(row.priorityClass)}">${escapeHtml(row.priorityLabel)}</span>
                  <div style="font-size:0.72rem;color:var(--muted);margin-top:4px;">score ${formatNumber(row.priorityScore, 0)}</div>
                </td>
                <td>
                  <strong>${escapeHtml(row.code)}.${escapeHtml(row.suffix)}</strong>
                  <div style="font-size:0.74rem;color:var(--muted);">${escapeHtml(row.name)} · ${escapeHtml(row.role)} · ${escapeHtml(row.confidence)}</div>
                </td>
                <td style="font-size:0.78rem;">${escapeHtml((row.needs || []).join("、") || "待定期更新")}</td>
                <td style="font-size:0.78rem;">${escapeHtml(row.action)}</td>
                <td><div class="link-row" style="gap:4px;">${row.links.slice(0, 3).map((link) => `<a class="link-chip" href="${escapeHtml(link.url)}" target="_blank" rel="noopener">${escapeHtml(link.label)}</a>`).join("")}</div></td>
              </tr>
            `).join("")}
          </tbody>
        </table>
      </div>
      ${rows.length > visibleRows.length ? `<p style="margin:8px 0 0;color:var(--muted);font-size:0.78rem;">畫面先顯示前 ${formatNumber(visibleRows.length, 0)} / ${formatNumber(rows.length, 0)} 筆；CSV 會匯出完整 worklist。</p>` : ""}
    </div>
  `;
}

function renderClassificationAuditPanel() {
  const container = $("classificationAuditPanel");
  if (!container) return;
  const rows = classificationAuditRows();
  if (!rows.length) {
    container.innerHTML = `<div class="empty">目前主題 / 搜尋範圍沒有可稽核標的。</div>`;
    return;
  }
  const visibleRows = rows.slice(0, CLASSIFICATION_AUDIT_VISIBLE_LIMIT);
  const counts = rows.reduce((acc, row) => {
    acc[row.role] = (acc[row.role] || 0) + 1;
    return acc;
  }, {});
  const fallbackCount = rows.filter((row) => row.coverage.fallbackUsed).length;
  const lowConfidenceCount = rows.filter((row) => row.confidence === "low").length;
  const scopeLabel = currentSearchText()
    ? `搜尋「${currentSearchText()}」`
    : state.filter === "all"
      ? "全部股池"
      : state.filter === HOLDINGS_THEME_KEY
        ? "目前持股 / 自訂清單"
        : activeThemeLabel();

  container.innerHTML = `
    <div class="report-card" data-classification-audit style="grid-column:1/-1;margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap;margin-bottom:10px;">
        <div>
          <h3 style="margin:0 0 6px;font-size:1rem;">Goodinfo-style 分類稽核表</h3>
          <p style="margin:0;color:var(--muted);font-size:0.82rem;line-height:1.55;">範圍：${escapeHtml(scopeLabel)}。核心 / 延伸 / 待複核是工具內分類層級；交易判讀仍需回 TWSE / TPEx / MOPS 與第二來源交叉比對。</p>
        </div>
        <div class="chip-row chip-row-compact">
          <span class="chip">共 ${formatNumber(rows.length, 0)} 檔</span>
          <span class="chip good">核心 ${formatNumber(counts["核心"] || 0, 0)}</span>
          <span class="chip">延伸 ${formatNumber(counts["延伸"] || 0, 0)}</span>
          <span class="chip warn">待複核 ${formatNumber(counts["待複核"] || 0, 0)}</span>
          ${fallbackCount ? `<span class="chip warn">fallback ${formatNumber(fallbackCount, 0)}</span>` : ""}
          ${lowConfidenceCount ? `<span class="chip warn">low confidence ${formatNumber(lowConfidenceCount, 0)}</span>` : ""}
          <button id="exportClassificationAuditCsvBtn" class="ghost-btn" type="button" style="font-size:0.78rem;">匯出分類稽核 CSV</button>
        </div>
      </div>
      ${renderClassificationWorklistPanel(rows)}
      <div class="table-wrap">
        <table style="min-width:1120px;">
          <thead>
            <tr>
              <th>代碼</th>
              <th>分類層級</th>
              <th>主題 / 子分類</th>
              <th>資料覆蓋</th>
              <th>confidence</th>
              <th>待補 / 風險</th>
              <th>官方核對入口</th>
            </tr>
          </thead>
          <tbody>
            ${visibleRows.map((row) => `
              <tr>
                <td>
                  <strong>${escapeHtml(row.code)}.${escapeHtml(row.suffix)}</strong>
                  <div style="font-size:0.74rem;color:var(--muted);">${escapeHtml(row.name)} · ${escapeHtml(row.market)}</div>
                </td>
                <td>
                  <span class="chip ${escapeHtml(row.roleClass)}">${escapeHtml(row.role)}</span>
                  <div style="font-size:0.72rem;color:var(--muted);margin-top:4px;">${escapeHtml(row.reason)}</div>
                </td>
                <td>
                  <strong style="font-size:0.8rem;">${escapeHtml(row.themeLabel)}</strong>
                  <div style="font-size:0.74rem;color:var(--muted);margin-top:4px;">${escapeHtml(row.subcategory)}</div>
                </td>
                <td>
                  <strong>${formatNumber(row.coverage.availableCount, 0)} / ${formatNumber(row.coverage.totalCount, 0)}</strong>
                  <div style="font-size:0.72rem;color:var(--muted);margin-top:4px;">${escapeHtml(row.coverage.sourceTierSummary)}${row.coverage.latestAsOf ? ` · ${escapeHtml(row.coverage.latestAsOf)}` : ""}</div>
                </td>
                <td><span class="chip ${row.confidence === "low" ? "warn" : row.confidence === "medium-high" ? "good" : "flat"}">${escapeHtml(row.confidence)}</span></td>
                <td style="font-size:0.78rem;">${row.needs.length ? escapeHtml(row.needs.slice(0, 4).join("、")) : `<span style="color:var(--muted);">無明顯缺口</span>`}</td>
                <td>
                  <div class="link-row" style="gap:4px;">${row.links.map((link) => `<a class="link-chip" href="${escapeHtml(link.url)}" target="_blank" rel="noopener">${escapeHtml(link.label)}</a>`).join("")}</div>
                </td>
              </tr>
            `).join("")}
          </tbody>
        </table>
      </div>
      ${rows.length > visibleRows.length ? `<p style="margin:8px 0 0;color:var(--muted);font-size:0.78rem;">畫面先顯示前 ${formatNumber(visibleRows.length, 0)} / ${formatNumber(rows.length, 0)} 檔；CSV 會匯出完整目前範圍。</p>` : ""}
    </div>
  `;
}

