let _bondSignalRefreshPromise = null;

function meanNumber(values) {
  const nums = (values || []).map(toNumber).filter((value) => value !== null);
  return nums.length ? nums.reduce((sum, value) => sum + value, 0) / nums.length : null;
}

function percentileRank(values, current) {
  const nums = (values || []).map(toNumber).filter((value) => value !== null).sort((a, b) => a - b);
  const value = toNumber(current);
  if (!nums.length || value === null) return null;
  const count = nums.filter((item) => item <= value).length;
  return count / nums.length * 100;
}

function quantileNumber(values, q) {
  const nums = (values || []).map(toNumber).filter((value) => value !== null).sort((a, b) => a - b);
  const percentile = toNumber(q);
  if (!nums.length || percentile === null) return null;
  if (nums.length === 1) return nums[0];
  const pos = clamp(percentile, 0, 1) * (nums.length - 1);
  const lower = Math.floor(pos);
  const upper = Math.ceil(pos);
  if (lower === upper) return nums[lower];
  return nums[lower] + (nums[upper] - nums[lower]) * (pos - lower);
}

function parseFedRssItems(text) {
  try {
    const doc = new DOMParser().parseFromString(text, "application/xml");
    return Array.from(doc.querySelectorAll("item")).map((item) => ({
      title: stripHtml(item.querySelector("title")?.textContent || ""),
      description: stripHtml(item.querySelector("description")?.textContent || ""),
      pubDate: item.querySelector("pubDate")?.textContent || "",
      link: item.querySelector("link")?.textContent || FED_MONETARY_RSS_URL
    })).filter((item) => item.title || item.description);
  } catch (_) {
    return [];
  }
}

function fedPolicySignalFromText(item) {
  const text = `${item?.title || ""} ${item?.description || ""}`.toLowerCase();
  if (/lower(ed|ing)?\s+(the\s+)?target\s+range|decreas(ed|ing)?\s+(the\s+)?target\s+range|cut(s|ting)?\s+rates?/.test(text)) {
    return {
      status: "cutting",
      label: "降息路徑 / 已降息",
      score: 2,
      tone: "good",
      detail: "Fed 最新貨幣政策文字出現降低目標利率區間的訊號。"
    };
  }
  if (/rais(ed|ing)?\s+(the\s+)?target\s+range|increas(ed|ing)?\s+(the\s+)?target\s+range|hike(s|d)?\s+rates?/.test(text)) {
    return {
      status: "hiking",
      label: "升息路徑",
      score: -2,
      tone: "bad",
      detail: "Fed 最新貨幣政策文字出現提高目標利率區間的訊號。"
    };
  }
  if (/maintain(ed|ing)?\s+(the\s+)?target\s+range|decided\s+to\s+maintain|keep(s|ing)?\s+(the\s+)?target\s+range|unchanged/.test(text)) {
    return {
      status: "pause",
      label: "高利率維持 / 暫停升息",
      score: 1,
      tone: "flat",
      detail: "Fed 最新貨幣政策文字偏向維持利率；仍需搭配點陣圖與市場預期。"
    };
  }
  return {
    status: "unknown",
    label: "Fed 路徑待複核",
    score: 0,
    tone: "flat",
    detail: "RSS 文字不足以判定升息、暫停或降息，請回官方 FOMC 聲明核對。"
  };
}

async function fetchFedMonetarySignal() {
  const text = await fetchText(FED_MONETARY_RSS_URL, { timeoutMs: 12000 });
  const items = parseFedRssItems(text);
  const latest = items.find((item) => /fomc|monetary policy|target range/i.test(`${item.title} ${item.description}`)) || items[0];
  const signal = fedPolicySignalFromText(latest);
  return {
    ...signal,
    title: latest?.title || "Fed monetary policy RSS",
    summary: latest?.description ? latest.description.slice(0, 260) : "",
    date: latest?.pubDate || "",
    source: "Federal Reserve monetary policy RSS",
    sourceTier: "官方",
    url: latest?.link || FED_MONETARY_RSS_URL,
    confidence: latest ? "medium" : "low"
  };
}

function dateFromMixedFedValue(value) {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const iso = raw.match(/(\d{4})[-/](\d{1,2})[-/](\d{1,2})/);
  if (iso) return `${iso[1]}-${String(iso[2]).padStart(2, "0")}-${String(iso[3]).padStart(2, "0")}`;
  const slash = raw.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if (slash) return `${slash[3]}-${String(slash[1]).padStart(2, "0")}-${String(slash[2]).padStart(2, "0")}`;
  const parsed = Date.parse(raw);
  return Number.isFinite(parsed) ? new Date(parsed).toISOString().slice(0, 10) : "";
}

function absoluteFedUrl(href) {
  const raw = String(href || "").trim();
  if (!raw) return "";
  if (/^https?:\/\//i.test(raw)) return raw;
  return `https://www.federalreserve.gov${raw.startsWith("/") ? raw : `/${raw}`}`;
}

function fedSepDateFromUrl(url) {
  const match = String(url || "").match(/fomcprojtabl(\d{4})(\d{2})(\d{2})/i);
  return match ? `${match[1]}-${match[2]}-${match[3]}` : "";
}

function latestFedSepUrlFromCalendar(html) {
  try {
    const doc = new DOMParser().parseFromString(html, "text/html");
    const today = new Date().toISOString().slice(0, 10);
    const links = Array.from(doc.querySelectorAll('a[href*="fomcprojtabl"]'))
      .map((anchor) => {
        const url = absoluteFedUrl(anchor.getAttribute("href"));
        return { url, date: fedSepDateFromUrl(url) };
      })
      .filter((item) => item.url && item.date && item.date <= today)
      .sort((left, right) => right.date.localeCompare(left.date));
    return links[0]?.url || FED_SEP_FALLBACK_URL;
  } catch (_) {
    return FED_SEP_FALLBACK_URL;
  }
}

function parseRateRangeMidpoint(value) {
  const raw = String(value || "").replace(/[–—−]/g, "-");
  const nums = raw.match(/\d+(?:\.\d+)?/g)?.map(Number).filter(Number.isFinite) || [];
  if (nums.length >= 2) return (nums[0] + nums[1]) / 2;
  return nums.length === 1 ? nums[0] : null;
}

function parseFedSepTable1Rates(text) {
  const normalized = String(text || "")
    .replace(/\u00a0/g, " ")
    .replace(/[–—−]/g, "-")
    .replace(/\s+/g, " ");
  const match = normalized.match(/Federal funds rate\s+(.+?)\s+December projection/i);
  const tokens = match ? match[1].trim().split(/\s+/).filter(Boolean) : [];
  const labels = ["2026", "2027", "2028", "Longer Run"];
  const medians = labels.map((year, index) => ({
    year,
    rate: parseRateRangeMidpoint(tokens[index])
  })).filter((row) => row.rate !== null);
  const centralTendency = labels.map((year, index) => ({
    year,
    range: tokens[index + 4] || ""
  })).filter((row) => row.range);
  const range = labels.map((year, index) => ({
    year,
    range: tokens[index + 8] || ""
  })).filter((row) => row.range);
  return { medians, centralTendency, range };
}

function parseFedSepDotDistribution(doc) {
  const tables = Array.from(doc.querySelectorAll("table"));
  const table = tables.find((candidate) => {
    const text = stripHtml(candidate.textContent || "").replace(/\s+/g, " ");
    const containerText = stripHtml(candidate.closest(".data-table")?.textContent || "").replace(/\s+/g, " ");
    return /federal funds rate/i.test(containerText)
      && /Percent Range/i.test(text)
      && /Longer Run/i.test(text)
      && /March projections/i.test(text);
  });
  if (!table) return [];
  return Array.from(table.querySelectorAll("tbody tr, tr")).map((tr) => {
    const cells = Array.from(tr.querySelectorAll("th,td")).map((cell) => stripHtml(cell.textContent || "").replace(/\s+/g, " ").trim());
    const range = cells[0] || "";
    if (!/^\d/.test(range) || !/[-–—]/.test(range)) return null;
    const midpoint = parseRateRangeMidpoint(range);
    const readCount = (index) => Math.max(0, Math.round(toNumber(cells[index]) || 0));
    const hasPairedProjectionColumns = cells.length >= 9;
    const counts = hasPairedProjectionColumns
      ? {
          "2026": readCount(2),
          "2027": readCount(4),
          "2028": readCount(6),
          longerRun: readCount(8)
        }
      : {
          "2026": readCount(1),
          "2027": readCount(2),
          "2028": readCount(3),
          longerRun: readCount(4)
        };
    const total = Object.values(counts).reduce((sum, value) => sum + value, 0);
    return total ? { range, midpoint, counts } : null;
  }).filter(Boolean);
}

function parseFedSepProjectionMaterials(html, sourceUrl = FED_SEP_FALLBACK_URL) {
  const doc = new DOMParser().parseFromString(html, "text/html");
  const text = stripHtml(html);
  const releaseDate = stripHtml(doc.querySelector("#lastUpdate")?.textContent || "")
    .replace(/^Last Update:\s*/i, "")
    .trim() || fedSepDateFromUrl(sourceUrl);
  const table1 = parseFedSepTable1Rates(text);
  const distribution = parseFedSepDotDistribution(doc);
  const latestMedian = table1.medians.find((row) => row.year === String(new Date().getFullYear())) || table1.medians[0] || null;
  return {
    releaseDate,
    meetingDate: fedSepDateFromUrl(sourceUrl),
    source: "Federal Reserve FOMC Projection Materials",
    sourceTier: "官方",
    url: sourceUrl,
    medians: table1.medians,
    centralTendency: table1.centralTendency,
    range: table1.range,
    distribution,
    currentYearMedian: latestMedian?.rate ?? null,
    confidence: table1.medians.length ? "medium-high" : "low",
    note: "SEP / 點陣圖是 FOMC 參與者對適當政策的個別評估，不是市場機率或保證預測。"
  };
}

async function fetchFedSepProjectionPath() {
  let sourceUrl = FED_SEP_FALLBACK_URL;
  try {
    const calendarHtml = await fetchText(FOMC_CALENDAR_URL, { timeoutMs: 12000 });
    sourceUrl = latestFedSepUrlFromCalendar(calendarHtml);
  } catch (_) {
    sourceUrl = FED_SEP_FALLBACK_URL;
  }
  const html = await fetchText(sourceUrl, { timeoutMs: 12000 });
  return parseFedSepProjectionMaterials(html, sourceUrl);
}

function collectFedWatchDates(value, out = []) {
  if (!value) return out;
  if (typeof value === "string" || typeof value === "number") {
    const date = dateFromMixedFedValue(value);
    if (date) out.push(date);
    return out;
  }
  if (Array.isArray(value)) {
    value.forEach((item) => collectFedWatchDates(item, out));
    return out;
  }
  if (typeof value === "object") {
    ["meetingDate", "fomcMeetingDate", "date", "meeting", "eventDate"].forEach((key) => {
      if (value[key]) collectFedWatchDates(value[key], out);
    });
    ["meetingDates", "dates", "data", "meetings"].forEach((key) => {
      if (value[key]) collectFedWatchDates(value[key], out);
    });
  }
  return out;
}

function fedWatchProbabilityValue(row) {
  const keys = ["probability", "prob", "pct", "percentage", "value", "probabilityPct", "rateProbability"];
  for (const key of keys) {
    const value = toNumber(row?.[key]);
    if (value !== null) return value <= 1 ? value * 100 : value;
  }
  return null;
}

function fedWatchRangeLabel(row) {
  const keys = ["targetRate", "targetRange", "rateRange", "range", "rate", "label", "federalFundsRate", "fedFundsRate"];
  for (const key of keys) {
    const value = String(row?.[key] || "").trim();
    if (value) return value;
  }
  const lower = toNumber(row?.lowerBound ?? row?.lower ?? row?.min);
  const upper = toNumber(row?.upperBound ?? row?.upper ?? row?.max);
  return lower !== null && upper !== null ? `${formatNumber(lower, 2)}-${formatNumber(upper, 2)}` : "";
}

function collectFedWatchProbabilityRows(value, out = []) {
  if (!value) return out;
  if (Array.isArray(value)) {
    value.forEach((item) => collectFedWatchProbabilityRows(item, out));
    return out;
  }
  if (typeof value !== "object") return out;
  const probability = fedWatchProbabilityValue(value);
  const range = fedWatchRangeLabel(value);
  const midpoint = parseRateRangeMidpoint(range);
  if (probability !== null && range && midpoint !== null) {
    out.push({
      range,
      midpoint,
      probability: clamp(probability, 0, 100)
    });
  }
  Object.values(value).forEach((child) => {
    if (child && (Array.isArray(child) || typeof child === "object")) collectFedWatchProbabilityRows(child, out);
  });
  return out;
}

function parseCmeFedWatchMeetingPayload(payload, meetingDate = "") {
  const rows = collectFedWatchProbabilityRows(payload)
    .reduce((acc, row) => {
      const key = `${row.range}|${row.midpoint}`;
      const existing = acc.get(key);
      if (!existing || row.probability > existing.probability) acc.set(key, row);
      return acc;
    }, new Map());
  const probabilities = Array.from(rows.values()).sort((left, right) => left.midpoint - right.midpoint);
  const totalProb = probabilities.reduce((sum, row) => sum + row.probability, 0);
  const expectedRate = totalProb > 0
    ? probabilities.reduce((sum, row) => sum + row.midpoint * row.probability, 0) / totalProb
    : null;
  const dominant = probabilities.reduce((best, row) => (!best || row.probability > best.probability ? row : best), null);
  return {
    meetingDate,
    probabilities,
    expectedRate,
    dominant,
    totalProb,
    confidence: probabilities.length ? "medium" : "low"
  };
}

function fedWatchIsUsable(value) {
  return value && typeof value === "object" && toNumber(value.yearEndExpectedRate) !== null;
}

function fedWatchCacheAgeMs(fedWatch, fallbackFetchedAt = "") {
  const raw = fedWatch?.fetchedAt || fedWatch?.fallbackFromFetchedAt || fallbackFetchedAt || "";
  const parsed = raw ? Date.parse(raw) : NaN;
  return Number.isFinite(parsed) ? Date.now() - parsed : null;
}

function buildCachedFedWatchFallback(previousFedPath, errorMessage = "") {
  const previousFedWatch = previousFedPath?.fedWatch || null;
  if (!fedWatchIsUsable(previousFedWatch)) return null;
  const ageMs = fedWatchCacheAgeMs(previousFedWatch, previousFedPath?.fetchedAt || previousFedPath?.asOf || "");
  if (ageMs !== null && ageMs > FEDWATCH_FALLBACK_MAX_AGE_MS) return null;
  const fallbackError = errorMessage ? `CME runtime failed: ${errorMessage}` : "CME runtime failed";
  return {
    ...previousFedWatch,
    fetchedAt: previousFedWatch.fetchedAt || previousFedPath?.fetchedAt || null,
    confidence: "low",
    fallbackUsed: true,
    fallbackFromFetchedAt: previousFedWatch.fetchedAt || previousFedPath?.fetchedAt || "",
    fallbackAgeHours: ageMs !== null ? Math.round(ageMs / 36e5) : null,
    fallbackReason: "CME FedWatch 即時端點失敗，暫用最近一次成功快取；需人工核對 CME 頁面。",
    errors: [
      ...(Array.isArray(previousFedWatch.errors) ? previousFedWatch.errors : []),
      fallbackError
    ].filter(Boolean)
  };
}

async function fetchCmeFedWatchPath() {
  const text = await fetchText(CME_FEDWATCH_MEETING_DATES_URL, { timeoutMs: 10000 });
  const payload = JSON.parse(text);
  const today = new Date().toISOString().slice(0, 10);
  const meetingDates = Array.from(new Set(collectFedWatchDates(payload)))
    .filter((date) => date >= today)
    .sort()
    .slice(0, 5);
  if (!meetingDates.length) throw new Error("CME FedWatch meeting dates 無法解析");
  const settled = await Promise.allSettled(meetingDates.map(async (meetingDate) => {
    const meetingText = await fetchText(`${CME_FEDWATCH_MEETING_URL}?date=${encodeURIComponent(meetingDate)}`, { timeoutMs: 10000 });
    return parseCmeFedWatchMeetingPayload(JSON.parse(meetingText), meetingDate);
  }));
  const meetings = settled
    .filter((result) => result.status === "fulfilled")
    .map((result) => result.value)
    .filter((meeting) => meeting.probabilities.length);
  const errors = settled
    .filter((result) => result.status === "rejected")
    .map((result) => result.reason?.message || String(result.reason));
  const year = String(new Date().getFullYear());
  const yearEndMeeting = meetings.filter((meeting) => meeting.meetingDate.startsWith(year)).at(-1) || meetings.at(-1) || null;
  return {
    fetchedAt: new Date().toISOString(),
    source: "CME FedWatch",
    sourceTier: "Tier 2 市場預期",
    url: FEDWATCH_TOOL_URL,
    meetingDates,
    meetings,
    yearEndExpectedRate: yearEndMeeting?.expectedRate ?? null,
    yearEndMeetingDate: yearEndMeeting?.meetingDate || "",
    confidence: meetings.length ? "medium" : "low",
    fallbackUsed: false,
    errors
  };
}

function buildFedPolicyGap(fedWatch, sep) {
  const sepRate = toNumber(sep?.currentYearMedian);
  const marketRate = toNumber(fedWatch?.yearEndExpectedRate);
  if (sepRate === null || marketRate === null) {
    return {
      label: sepRate !== null ? "Fed 點陣圖已載入，FedWatch 待複核" : "Fed path 待複核",
      diffBp: null,
      marketRate,
      sepRate,
      score: 0,
      tone: "flat",
      confidence: "low",
      detail: "需同時取得 CME FedWatch 市場預期與 Fed SEP 中位數後，才計算市場-Fed 落差。"
    };
  }
  const diffBp = (marketRate - sepRate) * 100;
  const abs = Math.abs(diffBp);
  const score = abs >= 75 ? 5 : abs >= 50 ? 4 : abs >= 25 ? 2.5 : abs >= 15 ? 1 : 0;
  const label = diffBp <= -25
    ? "市場比 Fed 點陣圖更鴿"
    : diffBp >= 25
      ? "市場比 Fed 點陣圖更鷹"
      : "市場與 Fed 點陣圖大致一致";
  const detail = diffBp <= -25
    ? "市場隱含利率低於 Fed SEP 中位數；若 Fed 不配合，成長股與長債可能面臨預期修正。"
    : diffBp >= 25
      ? "市場隱含利率高於 Fed SEP 中位數；若通膨與就業資料降溫，估值修復空間較容易出現。"
      : "市場預期與 Fed SEP 中位數接近，政策落差不是主要風險源。";
  return {
    label,
    diffBp,
    marketRate,
    sepRate,
    score,
    tone: score >= 4 ? "bad" : score > 0 ? "warn" : "flat",
    confidence: fedWatch?.confidence === "medium" && sep?.confidence !== "low" ? "medium" : "low",
    detail: fedWatch?.fallbackUsed
      ? `${detail} CME 使用最近成功快取，需人工複核。`
      : detail
  };
}

function buildFedMacroRegime(fedWatch, sep, gap) {
  const medians = Array.isArray(sep?.medians) ? sep.medians : [];
  const current = medians.find((row) => row.year === String(new Date().getFullYear())) || medians[0] || null;
  const next = medians.find((row) => row.year === String(new Date().getFullYear() + 1)) || medians[1] || null;
  const officialSlope = current && next && current.rate !== null && next.rate !== null ? next.rate - current.rate : null;
  let label = "Fed regime 待複核";
  let tone = "flat";
  if (gap?.diffBp !== null && gap.diffBp <= -25) {
    label = "市場預期偏鴿，防 Fed 修正";
    tone = "bad";
  } else if (gap?.diffBp !== null && gap.diffBp >= 25) {
    label = "市場偏鷹，等待資料確認";
    tone = "warn";
  } else if (officialSlope !== null && officialSlope <= -0.25) {
    label = "Fed 官方路徑偏降息";
    tone = "good";
  } else if (officialSlope !== null && officialSlope >= 0.25) {
    label = "Fed 官方路徑偏緊縮";
    tone = "bad";
  } else if (sep?.currentYearMedian !== null) {
    label = "Fed 官方路徑偏高利率維持";
    tone = "warn";
  }
  const riskScore = toNumber(gap?.score) || 0;
  const impact = [
    {
      asset: "AI / 高 beta 電子",
      read: gap?.diffBp !== null && gap.diffBp <= -25 ? "預期過鴿時容易反殺，需看 10Y 與 SOX 共振" : "若利率預期下行且長端不升，估值壓力較可控"
    },
    {
      asset: "長天期美債 ETF",
      read: "FedWatch、SEP 與 20Y/30Y 殖利率需同看；只看降息機率容易忽略長端供需。"
    },
    {
      asset: "金融 / 高息防守",
      read: "若市場轉向高利率更久，金融利差與高息防守需分開看，不等同全部受惠。"
    }
  ];
  return {
    label,
    tone,
    riskScore,
    officialSlope,
    action: riskScore >= 4 ? "提高總經風險權重，避免把降息預期當作確定利多。" : "維持交叉比對；等待 FedWatch、SEP、長端利率與美元同向確認。",
    impact,
    confidence: gap?.confidence || "low"
  };
}

function buildFedPolicyTrend(fedPath, previousHistory = []) {
  const current = fedPathHistorySnapshot(fedPath);
  const rows = [
    ...(Array.isArray(previousHistory) ? previousHistory.map((row) => normalizeFedPathHistoryRow(row.fedPath || row)).filter(Boolean) : []),
    current
  ].filter(Boolean);
  const deduped = new Map();
  rows.forEach((row) => {
    const key = row.fetchedAt || row.asOf || String(row.ts || "");
    if (key) deduped.set(key, row);
  });
  const ordered = Array.from(deduped.values())
    .sort((left, right) => (left.ts || Date.parse(left.fetchedAt || left.asOf || "") || 0) - (right.ts || Date.parse(right.fetchedAt || right.asOf || "") || 0))
    .slice(-8);
  const latest = ordered.at(-1) || null;
  const previous = ordered.length >= 2 ? ordered.at(-2) : null;
  const diffChangeBp = latest && previous && latest.diffBp !== null && previous.diffBp !== null ? latest.diffBp - previous.diffBp : null;
  const marketChangeBp = latest && previous && latest.marketRate !== null && previous.marketRate !== null ? (latest.marketRate - previous.marketRate) * 100 : null;
  const sepChangeBp = latest && previous && latest.sepRate !== null && previous.sepRate !== null ? (latest.sepRate - previous.sepRate) * 100 : null;
  let label = "政策落差趨勢待累積";
  let tone = "flat";
  let detail = "需要至少兩次成功總經更新，才判斷 FedWatch 與 SEP 的落差方向。";
  if (diffChangeBp !== null) {
    if (diffChangeBp <= -15) {
      label = "市場相對 Fed 更鴿";
      tone = "bad";
      detail = "市場隱含政策利率相對 SEP 下移，若長端利率或 Fed 語氣不配合，估值修正風險上升。";
    } else if (diffChangeBp >= 15) {
      label = "市場相對 Fed 更鷹";
      tone = "warn";
      detail = "市場隱含政策利率相對 SEP 上移，需觀察通膨 / 就業是否確認或只是短線 risk-off。";
    } else {
      label = "政策落差變化不大";
      tone = Math.abs(latest?.diffBp || 0) >= 50 ? "warn" : "flat";
      detail = "市場與 Fed 的落差方向暫無明顯擴大，仍需搭配 10Y、DXY / USD/TWD 與 VIX 交叉確認。";
    }
  }
  return {
    label,
    tone,
    detail,
    diffChangeBp,
    marketChangeBp,
    sepChangeBp,
    rows: ordered,
    confidence: previous ? "medium" : "low"
  };
}

async function fetchFedPolicyPath(previousCache = null) {
  const [fedWatchResult, sepResult] = await Promise.allSettled([
    fetchCmeFedWatchPath(),
    fetchFedSepProjectionPath()
  ]);
  const errors = [];
  if (fedWatchResult.status === "rejected") errors.push(`CME FedWatch: ${fedWatchResult.reason?.message || String(fedWatchResult.reason)}`);
  if (sepResult.status === "rejected") errors.push(`Fed SEP: ${sepResult.reason?.message || String(sepResult.reason)}`);
  const previous = normalizeMacroCache(previousCache);
  const fedWatch = fedWatchResult.status === "fulfilled"
    ? fedWatchResult.value
    : buildCachedFedWatchFallback(previous.fedPath, fedWatchResult.reason?.message || String(fedWatchResult.reason || ""));
  const sep = sepResult.status === "fulfilled" ? sepResult.value : null;
  if (fedWatch?.fallbackUsed) errors.push("CME FedWatch 使用最近成功快取，需人工核對。");
  const gap = buildFedPolicyGap(fedWatch, sep);
  const regime = buildFedMacroRegime(fedWatch, sep, gap);
  const path = {
    ts: Date.now(),
    fetchedAt: new Date().toISOString(),
    asOf: fedWatch?.fetchedAt || sep?.releaseDate || "",
    fedWatch,
    sep,
    gap,
    regime,
    errors
  };
  path.trend = buildFedPolicyTrend(path, previous.history);
  return path;
}

function parseCbcUsdTwdRows(html) {
  const text = stripHtml(html).replace(/\u00a0/g, " ");
  const rows = [];
  const seen = new Set();
  const pattern = /(\d{4}\/\d{1,2}\/\d{1,2})\s+([23]\d(?:\.\d{2,4})?)/g;
  for (const match of text.matchAll(pattern)) {
    const date = parseSlashDate(match[1]);
    const value = toNumber(match[2]);
    if (!date || value === null || seen.has(date)) continue;
    seen.add(date);
    rows.push({ date, value });
  }
  return rows.sort((left, right) => right.date.localeCompare(left.date));
}

async function fetchCbcUsdTwdSignal() {
  let text = "";
  let sourceUrl = CBC_USDTWD_URL;
  try {
    text = await fetchText(CBC_USDTWD_URL, { timeoutMs: 12000 });
  } catch (error) {
    sourceUrl = CBC_USDTWD_FALLBACK_URL;
    text = await fetchText(CBC_USDTWD_FALLBACK_URL, { timeoutMs: 12000 });
  }
  const rows = parseCbcUsdTwdRows(text);
  const latest = rows[0];
  if (!latest) throw new Error("CBC USD/TWD 匯率頁無法解析");
  const values = rows.map((row) => row.value);
  const recent = values.slice(0, Math.min(values.length, 60));
  const avg20 = meanNumber(values.slice(0, 20));
  const avg60 = meanNumber(recent);
  const min60 = Math.min(...recent);
  const max60 = Math.max(...recent);
  const percentile = percentileRank(recent, latest.value);
  const prev5 = rows[5]?.value ?? null;
  const change5 = prev5 !== null ? latest.value - prev5 : null;
  let score = 0;
  let label = "美元中性";
  let detail = "目前 USD/TWD 接近近期中位區間。";
  if (percentile !== null && percentile <= 25) {
    score = 2;
    label = "台幣偏強 / 美元相對便宜";
    detail = "USD/TWD 位在近期偏低分位，對台幣買進美元資產較有匯率安全邊際。";
  } else if (percentile !== null && percentile <= 45) {
    score = 1;
    label = "台幣略強";
    detail = "USD/TWD 略低於近期區間中位。";
  } else if (percentile !== null && percentile >= 90) {
    score = -2;
    label = "美元偏貴";
    detail = "USD/TWD 位在近期高分位，未來美元回落可能侵蝕台幣報酬。";
  } else if (percentile !== null && percentile >= 75) {
    score = -1;
    label = "美元略強";
    detail = "USD/TWD 高於近期多數觀測值，匯率安全邊際較差。";
  }
  return {
    label,
    detail,
    score,
    tone: score >= 1 ? "good" : score <= -1 ? "bad" : "flat",
    latest: latest.value,
    date: latest.date,
    avg20,
    avg60,
    min60,
    max60,
    percentile,
    change5,
    rows: rows.slice(0, 60),
    source: "中央銀行新臺幣/美元銀行間收盤匯率",
    sourceTier: "官方",
    url: sourceUrl,
    confidence: rows.length >= 20 ? "medium" : "low"
  };
}

function classifyTreasuryYieldSignal(rows) {
  const latest = rows.at(-1);
  const prior = rows.length >= 21 ? rows.at(-21) : rows[0];
  const longYield = latest?.thirtyYear ?? latest?.twentyYear ?? latest?.tenYear ?? null;
  const priorLongYield = prior?.thirtyYear ?? prior?.twentyYear ?? prior?.tenYear ?? null;
  const change20 = longYield !== null && priorLongYield !== null ? longYield - priorLongYield : null;
  let levelScore = 0;
  let levelLabel = "長端殖利率中性";
  if (longYield !== null && longYield >= 5) {
    levelScore = 2;
    levelLabel = "長端殖利率接近 5% 以上";
  } else if (longYield !== null && longYield >= 4.5) {
    levelScore = 1;
    levelLabel = "長端殖利率偏高";
  } else if (longYield !== null && longYield < 3.8) {
    levelScore = -1;
    levelLabel = "長端殖利率不高";
  }

  let trendScore = 0;
  let trendLabel = "長端利率橫盤";
  if (change20 !== null && change20 >= 0.25) {
    trendScore = -1;
    trendLabel = "長端殖利率快速上升";
  } else if (change20 !== null && change20 <= -0.5) {
    trendScore = -1;
    trendLabel = "長端殖利率已大幅下降";
  } else if (change20 !== null && change20 <= -0.1) {
    trendScore = 0.5;
    trendLabel = "長端殖利率溫和回落";
  }

  return {
    label: `${levelLabel}，${trendLabel}`,
    detail: "長天期美債 ETF 對 20Y / 30Y 利率變動最敏感；分數門檻為工具內研究規則。",
    score: levelScore + trendScore,
    levelScore,
    trendScore,
    longYield,
    change20,
    twoYear: latest?.twoYear ?? null,
    tenYear: latest?.tenYear ?? null,
    twentyYear: latest?.twentyYear ?? null,
    thirtyYear: latest?.thirtyYear ?? null,
    date: latest?.date || "",
    source: "U.S. Treasury Yield Curve",
    sourceTier: "官方",
    url: "https://home.treasury.gov/resource-center/data-chart-center/interest-rates/TextView?type=daily_treasury_yield_curve",
    tone: levelScore + trendScore >= 1 ? "good" : levelScore + trendScore <= -1 ? "bad" : "flat",
    confidence: rows.length >= 20 ? "medium" : "low"
  };
}

async function fetchTreasuryBondSignal() {
  return classifyTreasuryYieldSignal(await fetchTreasuryYieldCurveRows());
}

function buildBondEtfSignal(fed, usdtwd, yields, errors = []) {
  const fedScore = toNumber(fed?.score) || 0;
  const fxScore = toNumber(usdtwd?.score) || 0;
  const yieldScore = toNumber(yields?.score) || 0;
  const score = Math.round((fedScore + fxScore + yieldScore) * 10) / 10;
  const hardRed = fed?.status === "hiking" || (usdtwd?.score <= -2 && yields?.levelScore <= 0) || (yields?.trendScore <= -1 && yields?.levelScore <= 0);
  let tone = "flat";
  let light = "黃燈";
  let action = "等待或小額觀察";
  let suggestion = "條件尚未形成明確優勢，先用分批與限額控制久期與匯率風險。";
  if (!hardRed && score >= 4) {
    tone = "good";
    light = "綠燈";
    action = "研究上相對適合分批";
    suggestion = "長端利率、Fed 路徑與匯率條件同時偏有利，可用分批方式建立觀察部位。";
  } else if (!hardRed && score >= 2) {
    tone = "good";
    light = "黃綠燈";
    action = "研究上可小額分批";
    suggestion = "條件偏有利但仍有未確認因子，較適合分批、保留現金與設定再平衡區間。";
  } else if (hardRed || score < 0) {
    tone = "bad";
    light = "紅燈";
    action = "研究上不利，避免長天期重倉";
    suggestion = "升息或匯率 / 長端利率條件不利，長天期 ETF 容易同時承受淨值與匯率壓力。";
  }

  let scenarioRank = "3";
  if (fed?.status === "cutting" && fxScore >= 1 && yields?.levelScore >= 1) scenarioRank = "1";
  else if (fed?.status === "pause" && fxScore >= 1 && yields?.levelScore >= 1) scenarioRank = "2";
  else if (fxScore < 0 && yields?.levelScore >= 2) scenarioRank = "4";
  else if (fed?.status === "cutting" && yields?.levelScore <= 0) scenarioRank = "5";
  const scenario = BOND_BUY_SCENARIO_ROWS.find((row) => row[0] === scenarioRank) || BOND_BUY_SCENARIO_ROWS[2];
  const checks = [
    { factor: "Fed / FOMC", state: fed?.label || "待複核", score: fedScore, source: fed?.source || "Federal Reserve", asOf: fed?.date || "" },
    { factor: "USD/TWD", state: usdtwd?.label || "待複核", score: fxScore, source: usdtwd?.source || "CBC", asOf: usdtwd?.date || "" },
    { factor: "20Y / 30Y 美債殖利率", state: yields?.label || "待複核", score: yieldScore, source: yields?.source || "U.S. Treasury", asOf: yields?.date || "" },
    { factor: "ETF 折溢價 / 淨值", state: "需回投信或 ETF 淨值頁核對", score: 0, source: "投信 / ETF 公開說明書", asOf: "manual" },
    { factor: "配息與稅務", state: "需看收益分配組成與扣繳憑單", score: 0, source: "投信 / 財政部", asOf: "manual" }
  ];
  return {
    score,
    light,
    tone,
    action,
    suggestion,
    scenarioRank,
    scenarioText: scenario[1],
    scenarioReason: scenario[2],
    checks,
    errors
  };
}

async function updateBondEtfSignal(silent = false) {
  if (_bondSignalRefreshPromise) return _bondSignalRefreshPromise;
  if (!silent) setStatus("正在更新美債 ETF 燈號...", "warn");
  _bondSignalRefreshPromise = (async () => {
    const results = await Promise.allSettled([
      fetchFedMonetarySignal(),
      fetchCbcUsdTwdSignal(),
      fetchTreasuryBondSignal()
    ]);
    const errors = [];
    const sourceLabels = ["Fed", "CBC USD/TWD", "U.S. Treasury"];
    results.forEach((result, index) => {
      if (result.status === "rejected") errors.push(`${sourceLabels[index]}: ${result.reason?.message || String(result.reason)}`);
    });
    const fed = results[0].status === "fulfilled" ? results[0].value : null;
    const usdtwd = results[1].status === "fulfilled" ? results[1].value : null;
    const yields = results[2].status === "fulfilled" ? results[2].value : null;
    const signal = buildBondEtfSignal(fed, usdtwd, yields, errors);
    state.bondSignalCache = {
      ts: Date.now(),
      fetchedAt: new Date().toISOString(),
      signal,
      fed,
      usdtwd,
      yields,
      checks: signal.checks,
      errors
    };
    persistStateSilently("美債 ETF 燈號");
    if (state.activeTab === "overview") renderBondEtfScenarioPanel();
    if (!silent) setStatus(`美債 ETF 燈號已更新：${signal.light}，${signal.action}。`, errors.length ? "warn" : "good");
    return state.bondSignalCache;
  })().finally(() => {
    _bondSignalRefreshPromise = null;
  });
  return _bondSignalRefreshPromise;
}

function maybeRefreshBondEtfSignal() {
  const cache = normalizeBondSignalCache(state.bondSignalCache);
  if (!cache.ts || Date.now() - cache.ts > BOND_SIGNAL_CACHE_TTL_MS) {
    updateBondEtfSignal(true).catch((error) => console.warn("updateBondEtfSignal failed", error));
  }
}

function isUsTreasuryEtfOverviewActive() {
  const stocks = filteredStocks();
  return state.filter === "usetf" || stocks.some((stock) => US_TREASURY_ETF_CODES.includes(stock.code));
}

