function retirementProfileFor(stockOrCode) {
  const code = typeof stockOrCode === "string" ? stockOrCode : stockOrCode?.code;
  return RETIREMENT_INCOME_PROFILES[code] || {
    role: "退休現金流觀察",
    cashflow: "依官方公告",
    timing: "殖利率達標、價格不追高、資料來源可複核時分批",
    risk: "需核對配息來源、估值與本金波動",
    source: "TWSE / TPEx / MOPS"
  };
}

function retirementBuyTimingSignal(stock) {
  const valuation = valuationFor(stock.code);
  const dividendYield = valuation ? toNumber(valuation.dividendYield) : null;
  const quote = quoteFor(stock.code);
  const pd = isEtfCode(stock.code) ? etfPremiumDiscountInfo(stock.code) : null;
  let technical = null;
  try { technical = calculateTechnical(stock.code); } catch (_) {}

  const reasons = [];
  let score = 0;
  if (dividendYield !== null) {
    if (dividendYield >= 5) {
      score += 2;
      reasons.push(`殖利率 ${formatPercentMetric(dividendYield, 1)} 達高息門檻`);
    } else if (dividendYield >= 4) {
      score += 1;
      reasons.push(`殖利率 ${formatPercentMetric(dividendYield, 1)} 可觀察`);
    } else {
      score -= 0.5;
      reasons.push(`殖利率 ${formatPercentMetric(dividendYield, 1)} 偏低`);
    }
  } else {
    reasons.push("殖利率待估值更新");
  }

  if (pd) {
    if (pd.pct > 1) {
      score -= 1.5;
      reasons.push(`ETF ${pd.label}，不宜追價`);
    } else if (pd.pct <= 0.2 && pd.pct >= -0.5) {
      score += 1;
      reasons.push(`ETF ${pd.label}，接近淨值`);
    } else if (pd.pct < -0.5) {
      score += 1;
      reasons.push(`ETF ${pd.label}，可查折價原因`);
    }
  } else if (isEtfCode(stock.code)) {
    reasons.push("ETF NAV / 折溢價待更新");
  }

  if (technical?.ready) {
    const close = technical.latest?.close;
    const ma60 = toNumber(technical.ma60);
    const rsi = toNumber(technical.rsi14);
    if (ma60 && close) {
      const dist = (close - ma60) / ma60 * 100;
      if (dist <= -3) {
        score += 1.2;
        reasons.push(`低於季線 ${formatNumber(dist, 1)}%`);
      } else if (dist <= 3) {
        score += 0.6;
        reasons.push("接近季線");
      } else if (dist >= 10) {
        score -= 1;
        reasons.push(`高於季線 ${formatNumber(dist, 1)}%`);
      }
    }
    if (rsi !== null) {
      if (rsi >= 70) {
        score -= 1;
        reasons.push("RSI 偏熱");
      } else if (rsi <= 45) {
        score += 0.6;
        reasons.push("RSI 未過熱");
      }
    }
  } else {
    reasons.push("日線待更新");
  }

  if (stock.code === "2603") {
    score -= 0.8;
    reasons.push("循環股需降部位");
  }
  if (!quote) reasons.push("現價待更新");

  let label = "先補資料";
  let tone = "flat";
  if (score >= 3) {
    label = "分批觀察";
    tone = "up";
  } else if (score >= 1) {
    label = "可等條件";
    tone = "warn";
  } else if (score < 0) {
    label = "先等回檔";
    tone = "down";
  }
  return { label, tone, score, detail: reasons.slice(0, 4).join("；") };
}

function retirementIncomeRowHtml(stock) {
  const profile = retirementProfileFor(stock);
  const quote = quoteFor(stock.code);
  const valuation = valuationFor(stock.code);
  const dividendYield = valuation ? toNumber(valuation.dividendYield) : null;
  const pd = isEtfCode(stock.code) ? etfPremiumDiscountInfo(stock.code) : null;
  const timing = retirementBuyTimingSignal(stock);
  const quoteText = quote
    ? `${formatNumber(quote.price)} <span class="${changeClass(quote.pct)}">${formatPct(quote.pct)}</span>`
    : "待報價";
  const yieldText = dividendYield !== null ? formatPercentMetric(dividendYield, 2) : "待估值";
  const pdText = isEtfCode(stock.code)
    ? pd ? `<span class="chip ${pd.tone}" style="font-size:0.72rem;">${escapeHtml(pd.label)}</span>` : `<span style="color:var(--muted);">NAV 待更新</span>`
    : `<span style="color:var(--muted);">個股</span>`;
  return `
    <tr style="cursor:pointer;" data-jump-section="report" data-jump-stock-code="${escapeHtml(stock.code)}">
      <td><strong>${escapeHtml(stock.code)}</strong><br><span style="color:var(--muted);font-size:0.76rem;">${escapeHtml(stock.name)}</span></td>
      <td>${escapeHtml(profile.role)}<br><span style="color:var(--muted);font-size:0.76rem;">${escapeHtml(profile.cashflow)}</span></td>
      <td>${quoteText}<br><span style="color:var(--muted);font-size:0.76rem;">殖利率 ${yieldText}</span></td>
      <td>${pdText}</td>
      <td><span class="chip ${timing.tone}" style="font-size:0.72rem;">${escapeHtml(timing.label)}</span><br><span style="color:var(--muted);font-size:0.74rem;">${escapeHtml(timing.detail)}</span></td>
      <td>${escapeHtml(profile.risk)}<br><span style="color:var(--muted);font-size:0.74rem;">來源：${escapeHtml(profile.source)}</span></td>
    </tr>
  `;
}

