function cgSaveGroup(groupId, name, desc) {
  if (!name.trim()) {
    setStatus("類股名稱不能為空。", "error");
    return;
  }
  const groups = loadCustomGroups();
  if (groupId) {
    const found = groups.find((g) => g.id === groupId);
    if (found) { found.name = name.trim(); found.desc = desc.trim(); }
  } else {
    groups.push({ id: customGroupId(), name: name.trim(), desc: desc.trim(), members: [] });
  }
  saveCustomGroupsStorage(groups);
  applyCustomGroupsToFilters();   // 即時整合進 filter 系統
  renderCustomGroupsManager();
  renderFilters();
  setStatus(`類股「${name.trim()}」已${groupId ? "更新" : "建立"}；已加入主題篩選列。`, "good");
}

function cgDeleteGroup(groupId) {
  const groups = loadCustomGroups().filter((g) => g.id !== groupId);
  saveCustomGroupsStorage(groups);
  renderCustomGroupsManager();
  setStatus("已刪除類股。", "good");
}

function cgAddMember(groupId, code, name = "", label = "", suffix = "", sector = "") {
  const rawCode = String(code || "").trim();
  const parsed = normalizeTickerInput(suffix && !/\.(TW|TWO)$/i.test(rawCode) ? `${rawCode}.${suffix}` : rawCode);
  if (!parsed) {
    setStatus("請輸入有效股號，例如 2330、6146.TWO。", "error");
    return;
  }
  state.userStocks = state.userStocks || {};
  const known = STOCK_UNIVERSE[parsed.code] || {};
  const memberName = name.trim() || known.name || `股票 ${parsed.code}`;
  const groups = loadCustomGroups();
  const found = groups.find((g) => g.id === groupId);
  if (!found) return;
  const members = found.members || [];
  const memberSector = sector.trim() || label.trim() || known.sector || "自訂觀察";
  const existing = members.find((m) => m.code === parsed.code);
  if (existing) {
    existing.suffix = parsed.suffix;
    existing.name = memberName;
    existing.label = label.trim();
    existing.sector = memberSector;
  } else {
    members.push({ code: parsed.code, suffix: parsed.suffix, name: memberName, sector: memberSector, label: label.trim() });
  }
  found.members = members;
  state.userStocks[parsed.code] = {
    ...(state.userStocks[parsed.code] || {}),
    name: memberName,
    suffix: parsed.suffix,
    sector: memberSector,
    market: parsed.suffix === "TWO" ? "上櫃" : "上市"
  };
  saveCustomGroupsStorage(groups);
  applyCustomGroupsToFilters();   // 讓新成員出現在 filteredStocks
  persistStateSilently("自訂股票");
  renderCustomGroupsManager();
  renderFilters();
  openCgMemberForm(groupId);
  setStatus(`${existing ? "已更新" : "已加入"} ${memberName} ${parsed.code}.${parsed.suffix} 到分組，可用主題篩選查看。`, "good");
}

function cgQuickAddMember() {
  const groupId = (document.getElementById("cgQuickGroup") || {}).value || "";
  const code = (document.getElementById("cgQuickCode") || {}).value || "";
  const name = (document.getElementById("cgQuickName") || {}).value || "";
  const suffix = (document.getElementById("cgQuickSuffix") || {}).value || "";
  const sector = (document.getElementById("cgQuickSector") || {}).value || "";
  if (!groupId) {
    setStatus("請先建立或選擇類股。", "error");
    return;
  }
  cgAddMember(groupId, code, name, sector, suffix, sector);
}

function cgRemoveMember(groupId, code) {
  const groups = loadCustomGroups();
  const found = groups.find((g) => g.id === groupId);
  if (!found) return;
  found.members = (found.members || []).filter((m) => m.code !== code);
  saveCustomGroupsStorage(groups);
  applyCustomGroupsToFilters();
  persistStateSilently("自訂類股");
  renderCustomGroupsManager();
  renderFilters();
  setStatus(`已移除 ${code}。`, "good");
}

function renderPriceAxisTicks(valueMin, valueMax, left, top, width, height) {
  const ticks = [];
  const range = valueMax - valueMin || 1;
  for (let index = 0; index <= 4; index += 1) {
    const value = valueMin + (range * index / 4);
    const y = top + height - ((value - valueMin) / range) * height;
    ticks.push(`
      <line class="chart-grid" x1="${left}" y1="${y.toFixed(1)}" x2="${left + width}" y2="${y.toFixed(1)}"></line>
      <text class="chart-label" x="${left - 8}" y="${(y + 4).toFixed(1)}" text-anchor="end">${formatNumber(value)}</text>
    `);
  }
  return ticks.join("");
}

function renderDateAxisTicks(rows, left, top, width) {
  if (!rows.length) return "";
  const count = Math.min(6, rows.length);
  const ticks = [];
  for (let index = 0; index < count; index += 1) {
    const rowIndex = Math.round(index * (rows.length - 1) / Math.max(1, count - 1));
    const x = scalePoint(rowIndex, rows.length, left, width);
    ticks.push(`
      <line class="chart-grid" x1="${x.toFixed(1)}" y1="${top}" x2="${x.toFixed(1)}" y2="${top + 320}"></line>
      <text class="chart-label" x="${x.toFixed(1)}" y="${top + 344}" text-anchor="middle">${escapeHtml(formatShortDate(rows[rowIndex].date))}</text>
    `);
  }
  return ticks.join("");
}

function technicalReadyList(stocks = WATCHLIST) {
  return stocks
    .map((stock) => ({ stock, technical: calculateTechnical(stock.code) }))
    .filter((entry) => entry.technical.ready);
}

function technicalRankRows(entries, metric, formatter, limit = 5) {
  return entries
    .map((entry) => ({ entry, value: metric(entry) }))
    .filter((row) => Number.isFinite(row.value))
    .sort((a, b) => b.value - a.value)
    .slice(0, limit)
    .map(({ entry, value }) => `
      <div class="rank-row" style="cursor:pointer;" data-search-jump="${escapeHtml(entry.stock.code)}">
        <span>${escapeHtml(entry.stock.name)} ${escapeHtml(entry.stock.code)}</span>
        <strong class="${changeClass(value)}">${formatter(value, entry)}</strong>
      </div>
    `).join("") || `<div class="empty">尚無可排序技術資料，請先更新日線。</div>`;
}

function largeVolumeBreakoutRank(entry) {
  const check = entry?.technical?.largeVolumeDefense?.highCheck;
  if (!check) return null;
  if (check.status === "breakout") return 100 + Math.max(0, check.distancePct || 0);
  if (check.status === "test") return 50 - Math.abs(check.distancePct || 0);
  return null;
}

function largeVolumeBreakdownRank(entry) {
  const check = entry?.technical?.largeVolumeDefense?.lowCheck;
  if (!check) return null;
  if (check.status === "breakdown") return 100 + Math.abs(check.distancePct || 0);
  if (check.status === "test") return 50 - Math.abs(check.distancePct || 0);
  return null;
}

function largeVolumeCheckRankLabel(check) {
  if (!check) return "-";
  const distance = check.distancePct !== null && check.distancePct !== undefined
    ? ` ${formatSignedMetric(check.distancePct, 2, "%")}`
    : "";
  return `${check.label}${distance}`;
}

function pocRecoveryRank(entry) {
  const check = entry?.technical?.decisionLayer?.pocCheck;
  if (!check?.available) return null;
  if (check.status === "above") return 100 + Math.max(0, check.distancePct || 0);
  if (check.status === "inside") return 50 - Math.abs(check.distancePct || 0);
  return null;
}

function atrRiskWarningRank(entry) {
  const risk = entry?.technical?.decisionLayer?.atrRisk;
  if (!risk?.available) return null;
  if (risk.status === "trailBreak") return 100 + Math.abs(risk.distanceToTrailingPct || 0);
  if (risk.status === "near") return 50 - Math.max(0, risk.distanceToTrailingPct || 0);
  return null;
}

function recoveryCandidateRank(entry) {
  const recovery = entry?.technical?.recoverySignal;
  if (!recovery?.available) return null;
  if (recovery.status === "reclaimedHigh") return 120 + Math.max(0, recovery.distanceToHalfPct || 0);
  if (recovery.status === "reclaimedHalf") return 100 + Math.max(0, recovery.distanceToHalfPct || 0);
  if (recovery.status === "reclaimedLow") return 70 + Math.max(0, recovery.distanceToLowPct || 0);
  return null;
}

function recoveryWarningRank(entry) {
  const recovery = entry?.technical?.recoverySignal;
  if (!recovery?.available) return null;
  if (recovery.status === "failedRetest") return 100 + Math.abs(recovery.distanceToLowPct || 0);
  if (recovery.status === "unrecovered") return 80 + Math.abs(recovery.distanceToLowPct || 0);
  return null;
}

function oscillatorBullRank(entry) {
  const osc = entry?.technical?.oscillatorChecklist;
  if (!osc?.available || osc.tone !== "up") return null;
  return 50 + (osc.score || 0) * 10;
}

function maBiasCompositeHeatRank(entry) {
  const profile = entry?.technical?.maBiasProfile;
  if (!profile?.available || !profile.heatScore) return null;
  return profile.heatScore + Math.max(0, profile.dominantEntry?.directionPercentile || 0) * 0.05;
}

function maBiasCompositeDeepRank(entry) {
  const profile = entry?.technical?.maBiasProfile;
  if (!profile?.available || !profile.deepScore) return null;
  return profile.deepScore + Math.max(0, profile.dominantEntry?.directionPercentile || 0) * 0.05;
}

function maBiasCompositeRankLabel(profile, direction = null) {
  if (!profile?.available) return "-";
  const target = direction || profile.dominant;
  const leader = (profile.availablePeriods || [])
    .filter((entry) => target === "heat" ? entry.currentBias > 0 : entry.currentBias < 0)
    .sort((left, right) => target === "heat" ? (right.heatPoints || 0) - (left.heatPoints || 0) : (right.deepPoints || 0) - (left.deepPoints || 0))[0] || profile.dominantEntry || null;
  const leadText = leader
    ? `${leader.shortLabel} ${formatSignedMetric(leader.currentBias, 1, "%")}${leader.directionPercentile !== null && leader.directionPercentile !== undefined ? ` / ${formatNumber(leader.directionPercentile, 0)}%ile` : ""}`
    : profile.summary;
  return `${leadText} · H${formatNumber(profile.heatScore, 0)} / D${formatNumber(profile.deepScore, 0)}`;
}

function tradingStatePriorityRank(entry) {
  const stateInfo = entry?.technical?.tradingState;
  if (!stateInfo?.available) return null;
  return (stateInfo.priority || 0) + (stateInfo.score || 0) * 0.5;
}

function tradingStateRankLabel(stateInfo) {
  if (!stateInfo) return "-";
  const scoreText = Number.isFinite(stateInfo.score) ? ` · ${stateInfo.score > 0 ? "+" : ""}${formatNumber(stateInfo.score, 0)}` : "";
  return `${stateInfo.label}${scoreText}`;
}

function technicalEventRiskRank(entry) {
  const events = Array.isArray(entry?.technical?.events) ? entry.technical.events : [];
  const riskEvents = events.filter((event) => event.tone === "down" || event.severity >= 8);
  if (!riskEvents.length) return null;
  const top = riskEvents.sort((left, right) => right.severity - left.severity || right.rank - left.rank)[0];
  return (top.severity || 0) * 20 + (top.rank || 0);
}

function technicalEventRankLabel(technical) {
  const events = Array.isArray(technical?.events) ? technical.events : [];
  const top = events.find((event) => event.tone === "down" || event.severity >= 8) || events[0];
  if (!top) return "-";
  return `${top.label}${top.level !== null && top.level !== undefined ? ` · ${formatNumber(top.level)}` : ""}`;
}

function freshRiskEventRank(entry, maxDays = 2) {
  const events = Array.isArray(entry?.technical?.eventTimeline?.riskEvents) ? entry.technical.eventTimeline.riskEvents : [];
  const top = events
    .filter((event) => event.daysAgo <= maxDays)
    .sort((left, right) => right.priority - left.priority || left.daysAgo - right.daysAgo)[0];
  return top ? top.priority : null;
}

function freshOpportunityEventRank(entry, maxDays = 2) {
  const events = Array.isArray(entry?.technical?.eventTimeline?.opportunityEvents) ? entry.technical.eventTimeline.opportunityEvents : [];
  const top = events
    .filter((event) => event.daysAgo <= maxDays)
    .sort((left, right) => right.priority - left.priority || left.daysAgo - right.daysAgo)[0];
  return top ? top.priority : null;
}

function eventTimelineRankLabel(timeline, tone = "any", maxDays = 2) {
  const events = Array.isArray(timeline?.events) ? timeline.events : [];
  const top = events
    .filter((event) => tone === "any" || event.tone === tone)
    .filter((event) => event.daysAgo <= maxDays)
    .sort((left, right) => right.priority - left.priority || left.daysAgo - right.daysAgo)[0];
  if (!top) return "-";
  return `${top.label} · ${technicalEventAgeText(top.daysAgo)}${top.active ? " / 有效" : " / 失效"}`;
}

function eventBacktestPrimaryHorizon(backtest) {
  if (!backtest?.available) return null;
  return (backtest.horizons || []).find((item) => item.horizon === 5) || (backtest.horizons || []).find((item) => item.n) || null;
}

function eventBacktestContinuationRank(entry) {
  const backtest = entry?.technical?.eventBacktest;
  const h5 = eventBacktestPrimaryHorizon(backtest);
  if (!backtest?.available || !h5 || h5.n < 3 || h5.continuationRate === null) return null;
  const direction = backtest.meta?.direction || 1;
  const directionalAvg = h5.avgReturnPct !== null && h5.avgReturnPct !== undefined ? h5.avgReturnPct * direction : 0;
  if (h5.continuationRate < 50 && directionalAvg <= 0) return null;
  return h5.continuationRate + Math.max(0, directionalAvg) * 6 + Math.min(12, h5.n);
}

function eventBacktestFailureRank(entry) {
  const backtest = entry?.technical?.eventBacktest;
  const h5 = eventBacktestPrimaryHorizon(backtest);
  if (!backtest?.available || !h5 || h5.n < 3 || h5.continuationRate === null) return null;
  const direction = backtest.meta?.direction || 1;
  const directionalAvg = h5.avgReturnPct !== null && h5.avgReturnPct !== undefined ? h5.avgReturnPct * direction : 0;
  if (h5.continuationRate > 50 && directionalAvg >= 0) return null;
  return (100 - h5.continuationRate) + Math.max(0, -directionalAvg) * 6 + Math.min(12, h5.n);
}

function eventBacktestRankLabel(backtest) {
  const h5 = eventBacktestPrimaryHorizon(backtest);
  if (!backtest?.available || !h5) return "-";
  return `${backtest.meta?.label || "-"} · 5日續航 ${h5.continuationRate !== null ? `${formatNumber(h5.continuationRate, 0)}%` : "-"} · 均 ${formatSignedMetric(h5.avgReturnPct, 2, "%")}`;
}

function technicalDecisionRankLabel(layer) {
  if (!layer) return "-";
  return `${layer.summary}${layer.score !== undefined ? ` · ${formatNumber(layer.score, 0)}分` : ""}`;
}

function renderMaMetricBadge(label, value, cssClass) {
  return `<span class="metric-ma ${escapeHtml(cssClass)}">${escapeHtml(label)} ${formatNumber(value)}</span>`;
}

function renderTechnicalMaBadges(technical, includeYear = true) {
  return [
    renderMaMetricBadge("MA5", technical.ma5, "metric-ma5"),
    renderMaMetricBadge("MA10", technical.ma10, "metric-ma10"),
    renderMaMetricBadge("MA20(月)", technical.ma20, "metric-ma20"),
    renderMaMetricBadge("MA60(季)", technical.ma60, "metric-ma60"),
    includeYear ? renderMaMetricBadge("MA240(年)", technical.ma240, "metric-ma240") : ""
  ].filter(Boolean).join("");
}

function renderChartLegendChip(cssClass, label, value) {
  return `<span class="chip legend-chip ${escapeHtml(cssClass)}"><span class="legend-dot ${escapeHtml(cssClass)}"></span>${escapeHtml(label)} ${formatNumber(value)}</span>`;
}

function renderRanks() {
  const scopedStocks = filteredStocks();
  const withQuotes = scopedStocks.filter((stock) => quoteFor(stock.code));
  const stocks = withQuotes.length ? withQuotes : scopedStocks;
  const updated = scopedStocks.filter((stock) => quoteFor(stock.code));
  const official = updated.filter((stock) => quoteFor(stock.code).sourceKind === "official").length;
  const technicalEntries = technicalReadyList(scopedStocks);
  const nearBuy = stocks
    .map((stock) => ({ stock, status: buyRangeStatus(stock, latestValue(stock)) }))
    .filter((entry) => Number.isFinite(entry.status.distance))
    .sort((a, b) => a.status.distance - b.status.distance)
    .slice(0, 5)
    .map((entry) => `
      <div class="rank-row">
        <span>${escapeHtml(entry.stock.name)} ${escapeHtml(entry.stock.code)}</span>
        <strong>${escapeHtml(entry.status.label)}</strong>
      </div>
    `).join("") || `<div class="empty">尚無買點區間資料。</div>`;

  // RS 排行（需要 TAIEX 資料）
  const hasTaiex = taiexKlines().length >= 20;
  const rsEntries = hasTaiex
    ? scopedStocks.map((stock) => ({ stock, rs: calculateRS(stock.code) })).filter((e) => e.rs !== null)
    : [];
  const rsTopHtml = rsEntries.length
    ? rsEntries.sort((a, b) => b.rs.excessReturn - a.rs.excessReturn).slice(0, 5).map((e) => `
        <div class="rank-row">
          <span>${escapeHtml(e.stock.name)} ${escapeHtml(e.stock.code)}</span>
          <strong class="${changeClass(e.rs.excessReturn)}">${e.rs.excessReturn > 0 ? "+" : ""}${e.rs.excessReturn.toFixed(1)}百分點</strong>
        </div>`).join("")
    : `<div class="empty">請先更新日線（含大盤指數）。</div>`;
  const rsBottomHtml = rsEntries.length
    ? rsEntries.sort((a, b) => a.rs.excessReturn - b.rs.excessReturn).slice(0, 5).map((e) => `
        <div class="rank-row">
          <span>${escapeHtml(e.stock.name)} ${escapeHtml(e.stock.code)}</span>
          <strong class="${changeClass(e.rs.excessReturn)}">${e.rs.excessReturn.toFixed(1)}百分點</strong>
        </div>`).join("")
    : "";

  // 量能異常排行
  const volEntries = scopedStocks
    .map((stock) => ({ stock, vol: volumeAnomalyInfo(stock.code) }))
    .filter((e) => e.vol !== null && e.vol.zScore > 1.0)
    .sort((a, b) => Math.abs(b.vol.zScore) - Math.abs(a.vol.zScore))
    .slice(0, 5);
  const volHtml = volEntries.length
    ? volEntries.map((e) => {
        const dir = e.vol.bullish ? "↑多" : "↓空";
        const cls = e.vol.bullish ? "up" : "down";
        return `<div class="rank-row">
          <span>${escapeHtml(e.stock.name)} ${escapeHtml(e.stock.code)} <span class="${cls}" style="font-size:0.78rem;">${dir}</span></span>
          <strong>${e.vol.zScore.toFixed(1)}σ &nbsp;×${e.vol.ratio.toFixed(1)}</strong>
        </div>`;
      }).join("")
    : `<div class="empty">無顯著量能異常（z &lt; 1，請先更新日線）。</div>`;

  $("rankGrid").innerHTML = `
    <article class="rank-card">
      <h3>漲幅 Top 5</h3>
      <div class="rank-list">${rankRows(stocks, (stock) => quoteFor(stock.code) ? quoteFor(stock.code).pct : null, (value) => formatPct(value))}</div>
    </article>
    <article class="rank-card">
      <h3>跌幅 Top 5</h3>
      <div class="rank-list">${rankRows(stocks, (stock) => quoteFor(stock.code) ? -quoteFor(stock.code).pct : null, (value) => formatPct(-value))}</div>
    </article>
    <article class="rank-card">
      <h3>RS 強勢 Top 5 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">超額報酬 vs TAIEX 65日</span></h3>
      <div class="rank-list">${rsTopHtml}</div>
    </article>
    ${rsEntries.length ? `<article class="rank-card">
      <h3>RS 弱勢 Top 5 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">落後大盤 65日</span></h3>
      <div class="rank-list">${rsBottomHtml}</div>
    </article>` : ""}
    <article class="rank-card">
      <h3>量能異常 <span style="font-size:0.72rem;font-weight:400;color:var(--muted);">今量 z-score &gt; 1σ</span></h3>
      <div class="rank-list">${volHtml}</div>
    </article>
    <article class="rank-card">
      <h3>接近買點</h3>
      <div class="rank-list">${nearBuy}</div>
    </article>
    <article class="rank-card">
      <h3>資料覆蓋</h3>
      <div class="rank-list">
        <div class="rank-row"><span>${escapeHtml(activeThemeLabel())}</span><strong>${scopedStocks.length} 檔</strong></div>
        <div class="rank-row"><span>已更新</span><strong>${updated.length}/${scopedStocks.length}</strong></div>
        <div class="rank-row"><span>官方來源</span><strong>${official}/${updated.length || 0}</strong></div>
        <div class="rank-row"><span>日線分析</span><strong>${technicalEntries.length}/${scopedStocks.length}</strong></div>
        <div class="rank-row"><span>大盤指數</span><strong>${hasTaiex ? `${taiexKlines().length} 筆` : "未抓取"}</strong></div>
      </div>
    </article>
    <article class="rank-card">
      <h3>朱家泓 × 林穎候選 Top 5</h3>
      <div class="rank-list">${technicalRankRows(technicalEntries, (entry) => playbookSortScore(entry.technical), (value, entry) => playbookRankLabel(entry.technical.playbook))}</div>
    </article>
  `;
}

function renderPlaybookChecklistBadges(playbook, limit = 6) {
  if (!playbook || !Array.isArray(playbook.checklist) || !playbook.checklist.length) return "";
  return playbook.checklist.slice(0, limit).map((item) => `
    <span>${item.pass ? "✓" : "○"} ${escapeHtml(item.label)}</span>
  `).join("");
}

function renderPlaybookMethodologyCard(mode = "full") {
  const isCompact = mode === "compact";
  const rows = isCompact
    ? PLAYBOOK_METHOD_SOURCE_ROWS.map((row) => `
      <tr>
        <td><strong>${escapeHtml(row.module)}</strong></td>
        <td>${escapeHtml(row.source)}</td>
        <td>${escapeHtml(row.codeRule)}</td>
      </tr>
    `).join("")
    : PLAYBOOK_METHOD_SOURCE_ROWS.map((row) => `
      <tr>
        <td><strong>${escapeHtml(row.module)}</strong></td>
        <td>${escapeHtml(row.source)}</td>
        <td>${escapeHtml(row.lectureRule)}</td>
        <td>${escapeHtml(row.codeRule)}</td>
        <td>${escapeHtml(row.limitation)}</td>
      </tr>
    `).join("");
  return `
    <div class="report-card" style="grid-column:1/-1;">
      <h3>方法學來源：朱家泓 × 林穎技術分析初階班</h3>
      <p class="snapshot-trend-note" style="margin-top:6px;">
        來源：${escapeHtml(PLAYBOOK_SOURCE_TITLE)}，${escapeHtml(PLAYBOOK_SOURCE_PDF)}；${escapeHtml(PLAYBOOK_SOURCE_PATH)}。
        ${escapeHtml(PLAYBOOK_SOURCE_NOTE)}
      </p>
      <div class="table-wrap" style="margin-top:12px;">
        <table>
          <thead>
            <tr>
              <th>講義模組</th>
              <th>講義依據</th>
              ${isCompact ? "" : "<th>方法摘要</th>"}
              <th>程式映射</th>
              ${isCompact ? "" : "<th>目前限制</th>"}
            </tr>
          </thead>
          <tbody>${rows}</tbody>
        </table>
      </div>
    </div>
  `;
}

function quoteVolumeLots(quote) {
  const volume = toNumber(quote?.volume);
  if (volume === null) return null;
  if (String(quote?.source || "").includes("Yahoo") || quote?.sourceKind === "fallback") {
    return volume / 1000;
  }
  return volume;
}

function klineVolumeLots(row) {
  const volume = toNumber(row?.volume);
  return volume === null ? null : volume / 1000;
}

function quoteKlineSameDate(quote, row) {
  const quoteDate = String(quote?.sourceDate || "").slice(0, 10);
  return Boolean(quoteDate && row?.date && quoteDate === row.date);
}

function rowAveragePrice(row) {
  const turnover = toNumber(row?.turnover);
  const volume = toNumber(row?.volume);
  if (turnover !== null && volume && volume > 0) return turnover / volume;
  const high = toNumber(row?.high);
  const low = toNumber(row?.low);
  const close = toNumber(row?.close);
  if (high !== null && low !== null && close !== null) return (high + low + close) / 3;
  return close;
}

function peerPeStats(stock) {
  const officialIndustry = String(stock?.officialIndustry || "").trim();
  const sector = String(stock?.sector || "").trim();
  let basis = officialIndustry ? `官方產業碼 ${officialIndustry}` : `產業 ${sector || "未分類"}`;
  let fallbackUsed = false;
  let peers = WATCHLIST.filter((peer) => {
    if (!peer || peer.code === stock.code) return false;
    if (officialIndustry) return String(peer.officialIndustry || "").trim() === officialIndustry;
    return sector && String(peer.sector || "").trim() === sector;
  });

  if (peers.length < 2 && stock.primaryTheme) {
    const theme = themeInfo(stock.primaryTheme);
    const themeCodes = new Set(theme?.codes || []);
    peers = WATCHLIST.filter((peer) => peer.code !== stock.code && themeCodes.has(peer.code));
    basis = `${THEME_LABELS[stock.primaryTheme] || stock.primaryTheme} 主題樣本`;
    fallbackUsed = true;
  }

  const values = peers
    .map((peer) => toNumber(valuationFor(peer.code)?.pe))
    .filter((value) => value !== null && value > 0 && value < 200);
  return {
    average: average(values),
    count: values.length,
    basis,
    fallbackUsed
  };
}

function latestMarketMetrics(stock, technical = null) {
  const quote = quoteFor(stock.code);
  const rows = Array.isArray(technical?.rows) && technical.rows.length
    ? technical.rows
    : latestKlines(stock.code);
  const latestRow = rows.at(-1) || null;
  const quoteMatchesLatestRow = quoteKlineSameDate(quote, latestRow);
  const currentRow = quote ? (quoteMatchesLatestRow ? latestRow : null) : latestRow;
  const previousRow = quote
    ? (quoteMatchesLatestRow ? rows.at(-2) : latestRow)
    : rows.at(-2);

  const close = toNumber(quote?.price) ?? toNumber(latestRow?.close);
  const previousClose = toNumber(quote?.previousClose) ?? toNumber(previousRow?.close);
  const open = toNumber(quote?.open) ?? toNumber(currentRow?.open) ?? toNumber(latestRow?.open);
  const high = toNumber(quote?.high) ?? toNumber(currentRow?.high) ?? toNumber(latestRow?.high);
  const low = toNumber(quote?.low) ?? toNumber(currentRow?.low) ?? toNumber(latestRow?.low);
  const change = toNumber(quote?.change) ?? (close !== null && previousClose !== null ? close - previousClose : null);
  const pct = toNumber(quote?.pct) ?? (change !== null && previousClose ? change / previousClose * 100 : null);
  const amplitude = high !== null && low !== null && previousClose ? (high - low) / previousClose * 100 : null;
  const quoteLots = quoteVolumeLots(quote);
  const latestLots = klineVolumeLots(currentRow || latestRow);
  const totalLots = quoteLots ?? latestLots;
  const previousLots = klineVolumeLots(previousRow);
  const exactTurnover = currentRow?.turnover !== null && currentRow?.turnover !== undefined
    ? toNumber(currentRow.turnover)
    : null;
  const quoteTurnover = toNumber(quote?.turnover);
  const quoteTurnoverLooksUsable = quoteTurnover !== null && totalLots !== null && close !== null
    ? quoteTurnover > totalLots * close * 100
    : false;
  const averagePrice = toNumber(quote?.averagePrice)
    ?? (quoteTurnoverLooksUsable && totalLots ? quoteTurnover / (totalLots * 1000) : null)
    ?? rowAveragePrice(currentRow || latestRow)
    ?? (high !== null && low !== null && close !== null ? (high + low + close) / 3 : null);
  const turnover = exactTurnover
    ?? (quoteTurnoverLooksUsable ? quoteTurnover : null)
    ?? (averagePrice !== null && totalLots !== null ? averagePrice * totalLots * 1000 : null);
  const valuation = valuationFor(stock.code);
  const peer = peerPeStats(stock);
  return {
    quote,
    date: quote?.sourceDate || latestRow?.date || "",
    time: quote?.sourceTime || "",
    source: quote?.source || latestRow?.source || "日線資料",
    close,
    previousClose,
    change,
    pct,
    open,
    high,
    low,
    averagePrice,
    averagePriceEstimated: !(toNumber(quote?.averagePrice) !== null || exactTurnover !== null || quoteTurnoverLooksUsable),
    totalLots,
    previousLots,
    amplitude,
    turnoverBillion: turnover !== null ? turnover / 100000000 : null,
    turnoverEstimated: exactTurnover === null && !quoteTurnoverLooksUsable,
    pe: toNumber(valuation?.pe),
    peerPeAverage: peer.average,
    peerPeCount: peer.count,
    peerPeBasis: peer.basis,
    peerPeFallbackUsed: peer.fallbackUsed
  };
}

function renderTechnicalMarketSnapshot(stock, technical = null) {
  if (!stock) return "";
  const metrics = latestMarketMetrics(stock, technical);
  const heatSignal = buildStockHeatSignal(stock.code, technical);
  const sourceLine = [
    metrics.date || "",
    metrics.time || "",
    metrics.source || "",
    metrics.averagePriceEstimated ? "均價為近似估算" : "",
    metrics.turnoverEstimated ? "成交金額為估算" : ""
  ].filter(Boolean).join(" · ");
  const peerText = metrics.peerPeAverage !== null
    ? `${formatNumber(metrics.peerPeAverage)}（n=${metrics.peerPeCount}）`
    : "樣本不足";
  return `
    <div class="report-card" style="grid-column:1/-1;">
      <h3>最近行情與同業 PE：${escapeHtml(stock.name)} ${escapeHtml(stock.code)}</h3>
      <p class="snapshot-trend-note" style="margin-top:6px;">${escapeHtml(sourceLine || "尚未更新報價；請先按更新選取個股或更新全部個股。")}</p>
      <div class="stock-price-heat-row">
        <div>
          <span>現價 / 收盤</span>
          <strong class="${changeClass(metrics.change)}">${formatNumber(metrics.close)}</strong>
          <em class="${changeClass(metrics.pct)}">${metrics.change !== null ? `${metrics.change > 0 ? "+" : ""}${formatNumber(metrics.change)} / ${formatPct(metrics.pct)}` : "-"}</em>
        </div>
        ${stockHeatChipHtml(heatSignal)}
        <small>${escapeHtml(heatSignal.available ? heatSignal.summary : "個股熱度資料不足")}</small>
      </div>
      <div class="table-wrap" style="margin-top:12px;">
        <table>
          <thead>
            <tr>
              <th>日期</th>
              <th class="num">開盤</th>
              <th class="num">收盤價</th>
              <th class="num">昨收</th>
              <th class="num">漲跌</th>
              <th class="num">漲跌幅</th>
              <th class="num">最高</th>
              <th class="num">最低</th>
              <th class="num">均價</th>
              <th class="num">總量(張)</th>
              <th class="num">昨量(張)</th>
              <th class="num">振幅</th>
              <th class="num">成交金額(億)</th>
              <th class="num">本益比</th>
              <th class="num">同業平均 PE</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td>${escapeHtml(metrics.date || "-")}</td>
              <td class="num">${formatNumber(metrics.open)}</td>
              <td class="num">${formatNumber(metrics.close)}</td>
              <td class="num">${formatNumber(metrics.previousClose)}</td>
              <td class="num"><span class="${changeClass(metrics.change)}">${formatNumber(metrics.change)}</span></td>
              <td class="num"><span class="${changeClass(metrics.pct)}">${formatPct(metrics.pct)}</span></td>
              <td class="num">${formatNumber(metrics.high)}</td>
              <td class="num">${formatNumber(metrics.low)}</td>
              <td class="num">${formatNumber(metrics.averagePrice)}${metrics.averagePriceEstimated ? " 估" : ""}</td>
              <td class="num">${formatNumber(metrics.totalLots, 0)}</td>
              <td class="num">${formatNumber(metrics.previousLots, 0)}</td>
              <td class="num">${formatPercentMetric(metrics.amplitude)}</td>
              <td class="num">${formatNumber(metrics.turnoverBillion, 2)}${metrics.turnoverEstimated ? " 估" : ""}</td>
              <td class="num">${formatNumber(metrics.pe)}</td>
              <td class="num">${escapeHtml(peerText)}</td>
            </tr>
          </tbody>
        </table>
      </div>
      <p class="snapshot-trend-note" style="margin-top:8px;">同業平均 PE 以本工具目前已更新的「${escapeHtml(metrics.peerPeBasis)}」交易所 PE 做簡單平均${metrics.peerPeFallbackUsed ? "；因同官方產業樣本不足，暫用主題樣本作備援" : ""}，需回財報狗 / Goodinfo / 交易所資料交叉核對。</p>
    </div>
  `;
}

function renderPlaybookPriceLevelRow(label, value, detail = "", tone = "") {
  const text = value || "-";
  return `
    <div class="kv-row">
      <span>${escapeHtml(label)}</span>
      <strong class="${escapeHtml(tone)}">${escapeHtml(text)}${detail ? `<br><small style="color:var(--muted);font-weight:700;">${escapeHtml(detail)}</small>` : ""}</strong>
    </div>
  `;
}

function renderPlaybookPriceLevels(levels) {
  if (!levels) return "";
  const primary = levels.primaryEntry
    ? `${levels.primaryEntry.label} ${playbookEntryText(levels.primaryEntry)}`
    : "-";
  const primaryDetail = levels.primaryEntry
    ? `${levels.primaryEntry.source}；${levels.primaryEntry.confirmation}`
    : "";
  const secondary = levels.secondaryEntry
    ? `${levels.secondaryEntry.label} ${playbookEntryText(levels.secondaryEntry)}`
    : "-";
  const secondaryDetail = levels.secondaryEntry
    ? `${levels.secondaryEntry.source}；${levels.secondaryEntry.confirmation}`
    : "";
  const stopText = levels.stop ? formatNumber(levels.stop.price) : "-";
  const stopDetail = levels.stop ? `${levels.stop.source}；${levels.stop.confirmation}` : "";
  const target1Text = levels.target1 ? formatNumber(levels.target1.price) : "-";
  const target1Detail = levels.target1 ? `${levels.target1.source}${levels.target1.note ? `；${levels.target1.note}` : ""}` : "";
  const target2Text = levels.target2 ? formatNumber(levels.target2.price) : "-";
  const target2Detail = levels.target2 ? `${levels.target2.source}${levels.target2.note ? `；${levels.target2.note}` : ""}` : "";
  const supportText = levels.mainSupport ? `${formatNumber(levels.mainSupport.price)} ${levels.mainSupport.label}` : "-";
  const pressureText = levels.mainPressure ? `${formatNumber(levels.mainPressure.price)} ${levels.mainPressure.label}` : "-";
  const candleText = [
    levels.largeBull ? `長紅 ${levels.largeBull.date} 半價 ${formatNumber(levels.largeBull.half)}` : "",
    levels.largeBear ? `長黑 ${levels.largeBear.date} 半價 ${formatNumber(levels.largeBear.half)}` : ""
  ].filter(Boolean).join(" / ") || "-";
  const atrPocText = [
    levels.atrRisk?.available ? `ATR追蹤 ${formatNumber(levels.atrRisk.trailingStop)}` : "",
    levels.pocCheck?.available ? `POC ${formatNumber(levels.pocCheck.low)}–${formatNumber(levels.pocCheck.high)}` : ""
  ].filter(Boolean).join(" / ") || "-";
  return `
    <div class="report-card">
      <h3>朱家泓 × 林穎講義價位框架</h3>
      ${renderPlaybookPriceLevelRow("動作傾向", `${levels.actionBias} · 信心${levels.confidence}`, levels.volumeContext)}
      ${renderPlaybookPriceLevelRow("進場 1", primary, primaryDetail, "up")}
      ${renderPlaybookPriceLevelRow("進場 2", secondary, secondaryDetail)}
      ${renderPlaybookPriceLevelRow("停損 / 失效", stopText, stopDetail, "down")}
      ${renderPlaybookPriceLevelRow("目標 1", target1Text, target1Detail, "up")}
      ${renderPlaybookPriceLevelRow("目標 2", target2Text, target2Detail)}
      ${renderPlaybookPriceLevelRow("支撐 / 壓力", `${supportText} / ${pressureText}`)}
      ${renderPlaybookPriceLevelRow("大量 K 半價", candleText)}
      ${renderPlaybookPriceLevelRow("ATR / POC", atrPocText)}
      ${renderPlaybookPriceLevelRow("規則來源", levels.basis.slice(0, 3).join("、"))}
    </div>
  `;
}

function largeVolumeAnchorText(anchor) {
  if (!anchor) return "-";
  const ratio = anchor.volumeRatio20 !== null && anchor.volumeRatio20 !== undefined ? `${formatNumber(anchor.volumeRatio20, 2)}x` : "最大量參考";
  const direction = anchor.direction === "up" ? "紅K" : anchor.direction === "down" ? "黑K" : "中性";
  return `${anchor.date} ${direction} H ${formatNumber(anchor.high)} / L ${formatNumber(anchor.low)} / 半 ${formatNumber(anchor.half)} / 量 ${ratio}`;
}

function renderLargeVolumeCheckRow(label, check, anchor) {
  if (!check || !anchor) {
    return renderPlaybookPriceLevelRow(label, "資料不足", "需先更新日線並累積大量 K。");
  }
  const detail = [
    check.detail,
    `錨點：${largeVolumeAnchorText(anchor)}`
  ].filter(Boolean).join("；");
  const tone = check.tone === "up" ? "up" : check.tone === "down" ? "down" : "flat";
  return renderPlaybookPriceLevelRow(label, `${check.label} · ${formatNumber(check.level)}`, detail, tone);
}

