function taiwanLimitBaseInfo(stock, technical = null) {
  if (!stock) return { base: null, source: "", note: "尚未選取個股" };
  const quote = quoteFor(stock.code);
  const technicalClose = technical?.ready ? toNumber(technical.latest?.close) : null;
  if (technicalClose !== null) {
    return {
      base: technicalClose,
      source: `本機日線 ${technical.latest?.date || ""}`.trim(),
      note: "以最近一根日線收盤價試算下一交易日普通交易範圍。"
    };
  }
  const quotePrice = toNumber(quote?.price);
  if (quotePrice !== null) {
    return {
      base: quotePrice,
      source: [quote?.source || "最新報價", quote?.sourceDate || "", quote?.sourceTime || ""].filter(Boolean).join(" "),
      note: "尚未有日線收盤資料，先用最新報價試算；盤中資料不等於正式次日參考價。"
    };
  }
  const previousClose = toNumber(quote?.previousClose);
  if (previousClose !== null) {
    return {
      base: previousClose,
      source: [quote?.source || "最新報價", quote?.sourceDate || ""].filter(Boolean).join(" "),
      note: "尚未有最新成交價，先用報價內昨收作試算。"
    };
  }
  const fallback = toNumber(latestValue(stock));
  return {
    base: fallback,
    source: stock.ref ? "watchlist 參考價" : "",
    note: "缺少日線 / 報價資料，僅以本機參考價示範。"
  };
}

