function activeEtfSnapshotTime(snapshot) {
  const raw = String(snapshot?.sourceDate || snapshot?.capturedAt || "").trim();
  if (!raw) return 0;
  const normalized = raw.replace(/[/.]/g, "-");
  const rocMatch = normalized.match(/^(\d{2,3})-(\d{1,2})-(\d{1,2})/);
  if (rocMatch && Number(rocMatch[1]) < 1911) {
    return Date.UTC(Number(rocMatch[1]) + 1911, Number(rocMatch[2]) - 1, Number(rocMatch[3]));
  }
  const ymdMatch = normalized.match(/^(\d{4})-(\d{1,2})-(\d{1,2})/);
  if (ymdMatch) {
    return Date.UTC(Number(ymdMatch[1]), Number(ymdMatch[2]) - 1, Number(ymdMatch[3]));
  }
  const compact = normalized.match(/^(\d{4})(\d{2})(\d{2})$/);
  if (compact) {
    return Date.UTC(Number(compact[1]), Number(compact[2]) - 1, Number(compact[3]));
  }
  const time = Date.parse(raw);
  return Number.isFinite(time) ? time : 0;
}

function activeEtfSnapshotDay(snapshot) {
  const time = activeEtfSnapshotTime(snapshot);
  return time ? new Date(time).toISOString().slice(0, 10) : "";
}

function activeEtfSourcePriority(snapshot) {
  const label = String(snapshot?.sourceLabel || "");
  const holdingsCount = Array.isArray(snapshot?.holdings) ? snapshot.holdings.length : 0;
  if (/投信|官方|e添富|PCF/i.test(label)) return 6;
  if (label.includes("MoneyDJ 全部持股")) return 5;
  if (label.includes("ETF資訊網") || label.includes("WantGoo")) return 4;
  if (label.includes("MoneyDJ 持股狀況")) return 2;
  if (label.includes("Investing")) return holdingsCount >= 20 ? 2 : 1;
  return 3;
}

function activeEtfSnapshotQuality(snapshot) {
  const holdings = Array.isArray(snapshot?.holdings) ? snapshot.holdings : [];
  const namedCount = holdings.filter((row) => row.name).length;
  return activeEtfSourcePriority(snapshot) * 10000 + holdings.length * 100 + namedCount;
}

function activeEtfSnapshotIsFullCoverage(snapshot) {
  const holdingsCount = Array.isArray(snapshot?.holdings) ? snapshot.holdings.length : 0;
  const label = String(snapshot?.sourceLabel || "");
  return holdingsCount >= 20 || label.includes("全部持股") || /投信|官方|e添富|PCF/i.test(label);
}

function activeEtfSnapshotsComparable(latest, candidate) {
  if (!latest || !candidate) return false;
  const latestCount = Array.isArray(latest.holdings) ? latest.holdings.length : 0;
  const candidateCount = Array.isArray(candidate.holdings) ? candidate.holdings.length : 0;
  if (!latestCount || !candidateCount) return false;
  if (activeEtfSnapshotIsFullCoverage(latest) && !activeEtfSnapshotIsFullCoverage(candidate)) return false;
  if (latestCount >= 20 && candidateCount < Math.max(15, latestCount * 0.55)) return false;
  return true;
}

function activeEtfSnapshotRows(code) {
  return Array.isArray((state.activeEtf?.snapshots || {})[code])
    ? [...state.activeEtf.snapshots[code]].sort((a, b) => (
        activeEtfSnapshotTime(b) - activeEtfSnapshotTime(a)
        || activeEtfSnapshotQuality(b) - activeEtfSnapshotQuality(a)
        || String(b.capturedAt || "").localeCompare(String(a.capturedAt || ""))
      ))
    : [];
}

function latestActiveEtfSnapshot(code) {
  return activeEtfSnapshotRows(code)[0] || null;
}

function isTaiwanActiveEtf(etfOrCode) {
  const code = typeof etfOrCode === "string" ? etfOrCode : etfOrCode?.code;
  return TW_ACTIVE_ETF_CODES.includes(code);
}

function isOverseasTrackedEtf(etfOrCode) {
  const code = typeof etfOrCode === "string" ? etfOrCode : etfOrCode?.code;
  return OVERSEAS_ACTIVE_ETF_CODES.includes(code)
    || US_STOCK_ETF_CODES.includes(code)
    || JAPAN_ETF_CODES.includes(code)
    || US_TREASURY_ETF_CODES.includes(code);
}

function activeEtfCategory(etf) {
  if (isTaiwanActiveEtf(etf)) return "台股主動 ETF";
  if (OVERSEAS_ACTIVE_ETF_CODES.includes(etf.code)) return "海外主動 ETF";
  if (US_STOCK_ETF_CODES.includes(etf.code)) return "美股 / 海外指數 ETF";
  if (JAPAN_ETF_CODES.includes(etf.code)) return "日股 ETF";
  if (US_TREASURY_ETF_CODES.includes(etf.code)) return "美債 ETF";
  return etf.group || "ETF";
}

function activeEtfRegistryForCurrentTheme() {
  if (state.filter === "activeetf") return ACTIVE_ETF_REGISTRY.filter(isTaiwanActiveEtf);
  if (state.filter === "usetf") return ACTIVE_ETF_REGISTRY.filter(isOverseasTrackedEtf);
  return ACTIVE_ETF_REGISTRY;
}

function activeEtfSummary(registry = ACTIVE_ETF_REGISTRY) {
  const rows = registry.map((etf) => ({ etf, snapshot: latestActiveEtfSnapshot(etf.code) }));
  const covered = rows.filter((row) => row.snapshot).length;
  const core = registry.filter(isTaiwanActiveEtf).length;
  const overseas = registry.filter(isOverseasTrackedEtf).length;
  const latestTimes = rows
    .map((row) => row.snapshot?.capturedAt)
    .filter(Boolean)
    .sort()
    .reverse();
  return { rows, covered, core, overseas, latestAt: latestTimes[0] || null };
}

function activeEtfConsensusRows(limit = 12, registry = ACTIVE_ETF_REGISTRY) {
  const byCode = new Map();
  for (const etf of registry) {
    const snapshot = latestActiveEtfSnapshot(etf.code);
    if (!snapshot) continue;
    for (const holding of snapshot.holdings || []) {
      if (!holding.code) continue;
      const entry = byCode.get(holding.code) || {
        code: holding.code,
        name: holding.name || "",
        holders: [],
        totalWeight: 0
      };
      entry.name = entry.name || holding.name || "";
      entry.totalWeight += holding.weight || 0;
      entry.holders.push({
        code: etf.code,
        shortName: etf.shortName,
        weight: holding.weight || 0
      });
      byCode.set(holding.code, entry);
    }
  }
  return Array.from(byCode.values())
    .sort((a, b) => b.holders.length - a.holders.length || b.totalWeight - a.totalWeight)
    .slice(0, limit);
}

function findActiveEtfReferenceSnapshot(rows, daysBack) {
  const latest = rows[0];
  const latestTime = activeEtfSnapshotTime(latest);
  if (!latestTime) return null;
  const targetTime = latestTime - daysBack * ONE_DAY_MS;
  const candidates = rows
    .slice(1)
    .map((snapshot) => ({ snapshot, time: activeEtfSnapshotTime(snapshot) }))
    .filter((item) => item.time && item.time <= targetTime)
    .filter((item) => activeEtfSnapshotsComparable(latest, item.snapshot))
    .sort((a, b) => b.time - a.time || activeEtfSnapshotQuality(b.snapshot) - activeEtfSnapshotQuality(a.snapshot));
  return candidates[0]?.snapshot || null;
}

function activeEtfHoldingMap(snapshot) {
  const map = new Map();
  for (const holding of snapshot?.holdings || []) {
    if (!holding.code) continue;
    map.set(holding.code, holding);
  }
  return map;
}

function activeEtfChangeRows(latest, previous) {
  const latestMap = activeEtfHoldingMap(latest);
  const previousMap = activeEtfHoldingMap(previous);
  const codes = new Set([...latestMap.keys(), ...previousMap.keys()]);
  return Array.from(codes).map((code) => {
    const now = latestMap.get(code);
    const before = previousMap.get(code);
    const weight = now?.weight || 0;
    const previousWeight = before?.weight || 0;
    const delta = weight - previousWeight;
    let action = "持平";
    if (!before && now) action = "新增";
    else if (before && !now) action = "移除";
    else if (Math.abs(delta) >= 0.005) action = delta > 0 ? "加碼" : "減碼";
    return {
      code,
      name: now?.name || before?.name || "",
      weight,
      previousWeight,
      delta,
      action
    };
  }).sort((a, b) => {
    const actionRank = { "新增": 0, "移除": 1, "加碼": 2, "減碼": 3, "持平": 4 };
    return (actionRank[a.action] ?? 9) - (actionRank[b.action] ?? 9)
      || Math.abs(b.delta) - Math.abs(a.delta)
      || b.weight - a.weight;
  });
}

function activeEtfChangeSummary(code, daysBack) {
  const rows = activeEtfSnapshotRows(code);
  const latest = rows[0];
  const previous = findActiveEtfReferenceSnapshot(rows, daysBack);
  if (!latest || !previous) {
    return {
      status: "insufficient",
      daysBack,
      label: rows.length ? "需累積可比快照" : "尚無快照",
      changes: []
    };
  }
  const changes = activeEtfChangeRows(latest, previous);
  const counts = {
    added: changes.filter((row) => row.action === "新增").length,
    removed: changes.filter((row) => row.action === "移除").length,
    increased: changes.filter((row) => row.action === "加碼").length,
    decreased: changes.filter((row) => row.action === "減碼").length
  };
  const material = changes.filter((row) => row.action !== "持平");
  const byAction = {
    added: changes.filter((r) => r.action === "新增"),
    removed: changes.filter((r) => r.action === "移除"),
    increased: changes.filter((r) => r.action === "加碼"),
    decreased: changes.filter((r) => r.action === "減碼")
  };
  return {
    status: "ok",
    daysBack,
    latestDay: activeEtfSnapshotDay(latest),
    previousDay: activeEtfSnapshotDay(previous),
    counts,
    byAction,
    changes: material.slice(0, 5),
    label: material.length ? `異動 ${material.length} 檔` : "持股未變"
  };
}

function activeEtfStockSignal(code) {
  const stockCode = activeEtfNormalizeHoldingCode(code);
  if (!stockCode) {
    return {
      hasData: false,
      score: 0,
      level: "flat",
      label: "無 ETF 訊號",
      detail: "",
      holders: [],
      totalWeight: 0,
      net1: null,
      net3: null,
      net7: null,
      windows: {}
    };
  }

  const holders = [];
  let totalWeight = 0;
  let maxWeight = 0;
  let latestSnapshotCount = 0;
  const signalRegistry = ACTIVE_ETF_REGISTRY.filter(isTaiwanActiveEtf);

  for (const etf of signalRegistry) {
    const snapshot = latestActiveEtfSnapshot(etf.code);
    if (!snapshot) continue;
    latestSnapshotCount += 1;
    const holding = activeEtfHoldingMap(snapshot).get(stockCode);
    if (!holding) continue;
    const weight = toNumber(holding.weight) || 0;
    totalWeight += weight;
    maxWeight = Math.max(maxWeight, weight);
    holders.push({
      code: etf.code,
      shortName: etf.shortName,
      weight
    });
  }

  const windowStats = {};
  for (const daysBack of [1, 3, 7]) {
    let net = 0;
    let hits = 0;
    let adds = 0;
    let cuts = 0;
    for (const etf of signalRegistry) {
      const summary = activeEtfChangeSummary(etf.code, daysBack);
      if (!summary || summary.status !== "ok") continue;
      const change = summary.changes.find((row) => row.code === stockCode);
      if (!change) continue;
      hits += 1;
      net += toNumber(change.delta) || 0;
      if (["新增", "加碼"].includes(change.action)) adds += 1;
      if (["移除", "減碼"].includes(change.action)) cuts += 1;
    }
    windowStats[daysBack] = hits ? { net, hits, adds, cuts } : null;
  }

  if (!latestSnapshotCount) {
    return {
      hasData: false,
      score: 0,
      level: "flat",
      label: "ETF 待更新",
      detail: "尚無主動式 ETF 快照",
      holders: [],
      totalWeight: 0,
      net1: null,
      net3: null,
      net7: null,
      windows: {}
    };
  }

  let score = 0;
  if (holders.length >= 4) score += 4;
  else if (holders.length >= 3) score += 3;
  else if (holders.length >= 2) score += 2;
  else if (holders.length === 1) score += 1;

  if (totalWeight >= 12) score += 2;
  else if (totalWeight >= 5) score += 1;

  const recent = windowStats[7] || windowStats[3] || windowStats[1];
  if (recent) {
    if (recent.net >= 1 || recent.adds >= 2) score += 2;
    else if (recent.net >= 0.3 || recent.adds >= 1) score += 1;
    if (recent.net <= -1 || recent.cuts >= 2) score -= 2;
    else if (recent.net <= -0.3 || recent.cuts >= 1) score -= 1;
  }

  score = clamp(score, -2, 6);
  const level = score >= 3 ? "good" : score < 0 ? "warn" : "flat";
  const recentText = recent
    ? `，近${recent === windowStats[7] ? 7 : recent === windowStats[3] ? 3 : 1}日 ${formatSignedMetric(recent.net, 2, "pp")}`
    : "";
  const label = holders.length
    ? `${holders.length} 檔持有 / ${formatNumber(totalWeight, 2)}% 權重${recentText}`
    : `未進最新持股${recentText}`;

  return {
    hasData: true,
    score,
    level,
    label,
    detail: holders.slice(0, 3).map((holder) => `${holder.shortName} ${formatNumber(holder.weight, 2)}%`).join("、"),
    holders,
    totalWeight,
    maxWeight,
    net1: windowStats[1]?.net ?? null,
    net3: windowStats[3]?.net ?? null,
    net7: windowStats[7]?.net ?? null,
    windows: windowStats
  };
}

function activeEtfChangeSummaryHtml(summary) {
  if (!summary || summary.status !== "ok") return `<span class="flat">${escapeHtml(summary?.label || "資料不足")}</span>`;
  const { added = [], removed = [], increased = [], decreased = [] } = summary.byAction || {};
  const hasChanges = added.length || removed.length || increased.length || decreased.length;
  if (!hasChanges) return `<span style="color:var(--muted);font-size:0.8rem;">持股未變</span>`;

  function changeRows(rows, tone, limit = 6) {
    if (!rows.length) return "";
    return rows.slice(0, limit).map((row) => {
      const delta = row.delta != null ? `<span style="font-size:0.7rem;color:var(--muted);margin-left:3px;">${row.delta > 0 ? "+" : ""}${row.delta.toFixed(2)}百分點</span>` : "";
      return `<span class="chip ${tone}" style="font-size:0.76rem;">${escapeHtml(row.code)} ${escapeHtml(row.name || "")}${delta}</span>`;
    }).join("") + (rows.length > limit ? `<span class="chip flat" style="font-size:0.72rem;">+${rows.length - limit}筆</span>` : "");
  }

  const sections = [
    added.length ? `<div style="margin-bottom:4px;"><span style="font-size:0.7rem;font-weight:800;color:var(--bad);">▲ 新增 ${added.length}</span><div class="chip-row chip-row-compact" style="margin-top:3px;">${changeRows(added, "up")}</div></div>` : "",
    increased.length ? `<div style="margin-bottom:4px;"><span style="font-size:0.7rem;font-weight:800;color:var(--bad);">↑ 加碼 ${increased.length}</span><div class="chip-row chip-row-compact" style="margin-top:3px;">${changeRows(increased, "up")}</div></div>` : "",
    decreased.length ? `<div style="margin-bottom:4px;"><span style="font-size:0.7rem;font-weight:800;color:var(--good);">↓ 減碼 ${decreased.length}</span><div class="chip-row chip-row-compact" style="margin-top:3px;">${changeRows(decreased, "down")}</div></div>` : "",
    removed.length ? `<div style="margin-bottom:4px;"><span style="font-size:0.7rem;font-weight:800;color:var(--good);">▼ 移除 ${removed.length}</span><div class="chip-row chip-row-compact" style="margin-top:3px;">${changeRows(removed, "down")}</div></div>` : ""
  ].filter(Boolean).join("");

  return `<div style="font-size:0.72rem;color:var(--muted);margin-bottom:4px;">${escapeHtml(summary.previousDay || "-")} → ${escapeHtml(summary.latestDay || "-")}</div>${sections}`;
}

function activeEtfTopHoldingsHtml(snapshot, limit = 5) {
  if (!snapshot || !Array.isArray(snapshot.holdings) || !snapshot.holdings.length) return `<span class="flat">尚無快照</span>`;
  return snapshot.holdings.slice(0, limit).map((holding) => `
    <span class="chip">${escapeHtml(holding.code)} ${escapeHtml(holding.name || "")} ${formatPercentMetric(holding.weight, 2)}</span>
  `).join("");
}

function activeEtfHoldingsHtml(snapshot) {
  if (!snapshot || !Array.isArray(snapshot.holdings) || !snapshot.holdings.length) return `<span class="flat">尚無快照</span>`;
  const holdings = [...snapshot.holdings].sort((a, b) => (b.weight || 0) - (a.weight || 0));
  return `
    <div class="chip-row chip-row-compact">${activeEtfTopHoldingsHtml({ ...snapshot, holdings }, 5)}</div>
    <details class="active-etf-holdings-details">
      <summary>完整持股 ${formatNumber(holdings.length, 0)} 檔</summary>
      <div class="active-etf-holding-list">
        ${holdings.map((holding) => `
          <div class="active-etf-holding-row">
            <span>${escapeHtml(holding.code)} ${escapeHtml(holding.name || "")}</span>
            <strong>${formatPercentMetric(holding.weight, 2)}</strong>
          </div>
        `).join("")}
      </div>
    </details>
  `;
}

function activeEtfDiagnosticRows() {
  const diagnostics = normalizeActiveEtfDiagnosticsMap(state.activeEtf?.diagnostics || {});
  return ACTIVE_ETF_REGISTRY
    .map((etf) => ({ etf, diagnostic: diagnostics[etf.code] || null }))
    .filter((row) => row.diagnostic)
    .sort((a, b) => String(b.diagnostic.finishedAt || "").localeCompare(String(a.diagnostic.finishedAt || "")));
}

function activeEtfDiagnosticChips(diagnostic) {
  if (!diagnostic) return `<span class="flat">尚無診斷</span>`;
  const successSources = (diagnostic.sources || []).filter((source) => source.status === "success");
  const failedSources = (diagnostic.sources || []).filter((source) => source.status === "error");
  const chips = [];
  if (successSources.length) chips.push(`<span class="chip good">成功 ${formatNumber(successSources.length, 0)}</span>`);
  if (failedSources.length) chips.push(`<span class="chip bad">失敗 ${formatNumber(failedSources.length, 0)}</span>`);
  chips.push(`<span class="chip">耗時 ${formatNumber((diagnostic.durationMs || 0) / 1000, 1)}s</span>`);
  return `<div class="chip-row chip-row-compact">${chips.join("")}</div>`;
}

function activeEtfSourceDiagnosticsHtml(diagnostic) {
  if (!diagnostic || !Array.isArray(diagnostic.sources) || !diagnostic.sources.length) return `<span class="flat">尚無來源紀錄</span>`;
  return `
    <details class="active-etf-holdings-details">
      <summary>來源 ${formatNumber(diagnostic.sources.length, 0)} 個</summary>
      <div class="active-etf-holding-list">
        ${diagnostic.sources.map((source) => `
          <div class="active-etf-holding-row">
            <span>
              <strong class="${source.status === "success" ? "status-good" : source.status === "duplicate" ? "status-flat" : "status-bad"}">${escapeHtml(source.label || "-")}</strong>
              <span style="color:var(--muted);font-size:0.72rem;">${escapeHtml(source.status)} · ${formatNumber((source.durationMs || 0) / 1000, 1)}s · ${formatNumber(source.bytes || 0, 0)} bytes</span>
              ${source.error ? `<br><span style="color:var(--muted);font-size:0.72rem;">${escapeHtml(source.error.slice(0, 140))}${source.error.length > 140 ? "..." : ""}</span>` : ""}
            </span>
            <strong>${source.holdingsCount ? `${formatNumber(source.holdingsCount, 0)} 檔` : "-"}</strong>
          </div>
        `).join("")}
      </div>
    </details>
  `;
}

function activeEtfDiagnosticsPanelHtml() {
  const rows = activeEtfDiagnosticRows();
  if (!rows.length) {
    return `<div class="note-box" style="margin-bottom:14px;">尚無 ETF 更新診斷。按左上角「更新ETF」後，這裡會列出每檔 ETF 成功來源、失敗來源、耗時與解析筆數。</div>`;
  }
  const successCount = rows.filter((row) => row.diagnostic.status === "success").length;
  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <h3 style="margin:0 0 10px;font-size:1rem;">ETF 更新診斷</h3>
      <div class="chip-row chip-row-compact" style="margin-bottom:10px;">
        <span class="chip good">成功 ${formatNumber(successCount, 0)}</span>
        <span class="chip bad">失敗 ${formatNumber(rows.length - successCount, 0)}</span>
        <span class="chip">已有診斷 ${formatNumber(rows.length, 0)} / ${formatNumber(ACTIVE_ETF_REGISTRY.length, 0)}</span>
      </div>
      <div class="table-wrap">
        <table>
          <thead>
            <tr>
              <th>ETF</th>
              <th>狀態</th>
              <th class="num">快照 / 持股</th>
              <th>成功來源</th>
              <th>來源細節</th>
            </tr>
          </thead>
          <tbody>
            ${rows.map(({ etf, diagnostic }) => {
              const successSources = (diagnostic.sources || []).filter((source) => source.status === "success");
              return `
                <tr>
                  <td><strong>${escapeHtml(etf.code)} ${escapeHtml(etf.shortName)}</strong><br><span style="color:var(--muted);font-size:0.78rem;">${escapeHtml(formatDateTime(diagnostic.finishedAt))}</span></td>
                  <td>${activeEtfDiagnosticChips(diagnostic)}</td>
                  <td class="num">${formatNumber(diagnostic.snapshotsCount, 0)} / ${formatNumber(diagnostic.latestHoldingsCount, 0)}</td>
                  <td>${successSources.length ? successSources.map((source) => `<span class="chip good">${escapeHtml(source.label)} ${formatNumber(source.holdingsCount, 0)}</span>`).join(" ") : `<span class="flat">尚無成功來源</span>`}</td>
                  <td>${activeEtfSourceDiagnosticsHtml(diagnostic)}</td>
                </tr>
              `;
            }).join("")}
          </tbody>
        </table>
        ${renderTableTermNotes(["sourceDiagnostics"])}
      </div>
    </div>
  `;
}

function usTreasuryEtfQuote(etf) {
  const quote = quoteFor(etf.code);
  if (quote && quote.price !== null && quote.price !== undefined) {
    return {
      price: toNumber(quote.price),
      change: toNumber(quote.change),
      pct: toNumber(quote.pct),
      high: toNumber(quote.high),
      low: toNumber(quote.low),
      volume: toNumber(quote.volume),
      time: [quote.sourceDate, quote.sourceTime].filter(Boolean).join(" "),
      sourceLabel: quote.source || "本機報價",
      isReference: false
    };
  }
  const reference = etf.referenceQuote || {};
  return {
    price: toNumber(reference.price),
    change: toNumber(reference.change),
    pct: toNumber(reference.pct),
    high: toNumber(reference.high),
    low: toNumber(reference.low),
    volume: toNumber(reference.volume),
    time: reference.time || "",
    sourceLabel: "使用者提供參考價",
    isReference: true
  };
}

function usTreasuryEtfSummary() {
  const rows = US_TREASURY_ETF_REGISTRY.map((etf) => ({ etf, quote: usTreasuryEtfQuote(etf) }));
  const updated = rows.filter((row) => !row.quote.isReference).length;
  const shortTerm = rows.filter((row) => row.etf.durationGroup === "短天期").length;
  const longTerm = rows.filter((row) => row.etf.durationGroup === "長天期").length;
  return { rows, updated, shortTerm, longTerm };
}

