function etfMiniQuoteRow(code) {
  const stock = STOCK_MAP.get(code) || STOCK_UNIVERSE[code] || { code, name: code, suffix: "TW" };
  const quote = quoteFor(code);
  const price = quote?.price ?? null;
  const pct = quote?.pct ?? null;
  const pd = etfPremiumDiscountInfo(code);
  const pdChip = pd ? ` <span class="chip ${pd.tone}" style="font-size:0.68rem;padding:1px 5px;">${escapeHtml(pd.label)}</span>` : "";
  return `<span class="chip ${pct > 0 ? "up" : pct < 0 ? "down" : ""}" title="${escapeHtml(quote?.source || "尚未更新報價")}">${escapeHtml(code)} ${escapeHtml(stock.name || "")}${price !== null ? ` ${formatNumber(price)} (${formatPct(pct)})` : ""}${pdChip}</span>`;
}

function renderEtfNavSummaryPanel(codes = null) {
  const allCodes = Array.isArray(codes) && codes.length
    ? uniqueList(codes)
    : [
      ...TW_PASSIVE_ETF_CODES,
      ...TW_ACTIVE_ETF_CODES.slice(0, 6),
      ...US_STOCK_ETF_CODES,
      ...JAPAN_ETF_CODES,
      ...US_TREASURY_ETF_CODES
    ];
  const rows = allCodes.map((code) => {
    const pd = etfPremiumDiscountInfo(code);
    const stock = STOCK_MAP.get(code) || STOCK_UNIVERSE[code] || { code, name: code };
    return { code, name: stock.name || "", pd };
  }).filter((r) => r.pd !== null);
  if (!rows.length) return "";
  const largePremium = rows.filter((r) => r.pd.pct > 1);
  const largeDiscount = rows.filter((r) => r.pd.pct < -1);
  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:10px;">
        <h3 style="margin:0;font-size:1rem;">ETF 折溢價總覽</h3>
        <span style="color:var(--muted);font-size:0.78rem;">共 ${rows.length} 檔有淨值資料</span>
      </div>
      ${largePremium.length ? `
        <div style="margin-bottom:8px;">
          <span style="font-size:0.8rem;font-weight:700;color:var(--warn);margin-right:6px;">溢價 &gt;1%（買貴注意）</span>
          ${largePremium.map((r) => `<span class="chip warn" title="${escapeHtml(r.name)}">${escapeHtml(r.code)} <strong>${r.pd.pct > 0 ? "+" : ""}${r.pd.pct.toFixed(2)}%</strong></span>`).join("")}
        </div>
      ` : ""}
      ${largeDiscount.length ? `
        <div style="margin-bottom:8px;">
          <span style="font-size:0.8rem;font-weight:700;color:var(--muted);margin-right:6px;">折價 &gt;1%（價格低於淨值）</span>
          ${largeDiscount.map((r) => `<span class="chip good" title="${escapeHtml(r.name)}">${escapeHtml(r.code)} <strong>${r.pd.pct.toFixed(2)}%</strong></span>`).join("")}
        </div>
      ` : ""}
      <div class="chip-row chip-row-compact">
        ${rows.map((r) => `<span class="chip ${r.pd.tone}" title="${escapeHtml(r.name)} 淨值 ${formatNumber(r.pd.nav)}">${escapeHtml(r.code)} ${r.pd.pct > 0 ? "+" : ""}${r.pd.pct.toFixed(2)}%</span>`).join("")}
      </div>
      <p style="color:var(--muted);font-size:0.73rem;margin:8px 0 0;">⚠️ 折溢價基於昨日收盤後公告淨值計算，非即時；正值溢價（市價 &gt; 淨值），負值折價（市價 &lt; 淨值）。</p>
    </div>
  `;
}

