// ─────────────────────────────────────────────────────────────────────────────
// 流動性評估方法學（含文獻 / 實務分水嶺）
// ─────────────────────────────────────────────────────────────────────────────
// ─────────────────────────────────────────────────────────────────────────────
// 海外所得最低稅負制（AMT）個人試算器
// 計算邏輯（⚠️ unverified — please cross-check）：
//   1. 海外所得免稅門檻：全戶全年 100 萬（低於不計入基本所得額）
//   2. 基本所得額 = 海外所得 + 其他加計項（員工認股選擇權等）
//   3. 基本稅額 = (基本所得額 - 670 萬) × 20%（670 萬為 2026 年免稅額，每年調整）
//   4. 最終需繳：max(基本稅額, 一般所得稅額)；兩者取較大者
//   5. 若已繳一般所得稅額 < 基本稅額 → 需補繳差額
// ─────────────────────────────────────────────────────────────────────────────
const AMT_PARAMS = {
  FOREIGN_INCOME_THRESHOLD: 100,  // 萬；全戶全年低於此不計入
  BASIC_EXEMPTION: 670,           // 萬；2026 年基本所得額免稅額（每年調整）
  AMT_RATE: 0.20,                 // 最低稅負制稅率 20%
  SUPPLEMENTARY_HEALTH_PREMIUM: 0.0211, // 二代健保補充保費 2.11%
  SUPPLEMENTARY_THRESHOLD: 2,     // 萬；單筆 2 萬以上才課補充保費
  SOURCE_URL: "https://www.mof.gov.tw/",
  YEAR: 2026
};

function calcAmtResult(params) {
  const { foreignIncome, otherBasicIncome, regularTax, supplementaryHealthItems } = params;
  const total = (foreignIncome || 0) + (otherBasicIncome || 0);
  const exceedsThreshold = foreignIncome >= AMT_PARAMS.FOREIGN_INCOME_THRESHOLD;
  if (!exceedsThreshold) {
    return {
      basicIncome: null,
      basicTax: 0,
      additionalTax: 0,
      trigger: false,
      note: `全年海外所得 ${foreignIncome} 萬 < ${AMT_PARAMS.FOREIGN_INCOME_THRESHOLD} 萬免稅門檻，不計入基本所得額。`,
      supplementaryTax: 0
    };
  }
  const basicIncome = total;
  const taxable = Math.max(0, basicIncome - AMT_PARAMS.BASIC_EXEMPTION);
  const basicTax = taxable * AMT_PARAMS.AMT_RATE;
  const trigger = basicTax > (regularTax || 0);
  const additionalTax = trigger ? basicTax - (regularTax || 0) : 0;

  // 補充保費估算（每筆配息 ≥ 2 萬才課）
  const totalSupplementary = (supplementaryHealthItems || []).reduce((sum, item) => {
    if (item.amount >= AMT_PARAMS.SUPPLEMENTARY_THRESHOLD) {
      return sum + item.amount * AMT_PARAMS.SUPPLEMENTARY_HEALTH_PREMIUM;
    }
    return sum;
  }, 0);

  return { basicIncome, basicTax, additionalTax, trigger, note: "", supplementaryTax: totalSupplementary };
}

