function renderLiquidityMethodologyPanel() {
  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap;margin-bottom:10px;">
        <div>
          <h3 style="margin:0 0 6px;font-size:1rem;">流動性評估方法學（張數 + 金額複合分級）</h3>
          <p style="margin:0;color:var(--muted);font-size:0.84rem;line-height:1.55;">分級採張數為主、金額為輔，<strong>取兩者較嚴格者</strong>；用最近 20 日 kline 計算。例如新鼎 5209 日均約 100 張 / 800 萬元 → 過小流動性；台積電 2330 日均 ~30,000 張 / ~400 億 → 巨型流動性。</p>
        </div>
        <span class="chip warn">⚠️ 分級門檻為實務參考</span>
      </div>
      <div class="report-grid">
        <article class="report-card">
          <h3>主要分級（依日均成交張數）</h3>
          <div class="kv-row"><span>巨型</span><strong class="up">≥ 5,000 張/日</strong></div>
          <div class="kv-row"><span>大型</span><strong class="up">1,000 - 5,000 張/日</strong></div>
          <div class="kv-row"><span>中型</span><strong>500 - 1,000 張/日（<strong style="color:var(--accent-2);">實務分水嶺</strong>）</strong></div>
          <div class="kv-row"><span>小型</span><strong style="color:var(--warn);">100 - 500 張/日</strong></div>
          <div class="kv-row"><span>過小</span><strong class="down">< 100 張/日（避開或小額）</strong></div>
        </article>
        <article class="report-card">
          <h3>輔助分級（依日均交易金額）</h3>
          <p style="color:var(--muted);font-size:0.78rem;line-height:1.5;margin:0 0 8px;">避免高價股因張數低被誤判（如 1,300 元的台積電）。</p>
          <div class="kv-row"><span>巨型</span><strong>≥ 5 億元/日</strong></div>
          <div class="kv-row"><span>大型</span><strong>1 - 5 億元/日</strong></div>
          <div class="kv-row"><span>中型</span><strong>3,000 萬 - 1 億/日</strong></div>
          <div class="kv-row"><span>小型</span><strong>1,000 萬 - 3,000 萬/日</strong></div>
          <div class="kv-row"><span>過小</span><strong>< 1,000 萬/日</strong></div>
        </article>
        <article class="report-card">
          <h3>文獻 / 實務來源 ⚠️ unverified</h3>
          <ul style="margin:0;padding-left:18px;color:var(--muted);font-size:0.8rem;line-height:1.65;">
            <li><strong>TWSE</strong>：注意交易資訊辦法 / 公布處置作業要點，列示「流動量偏低之有價證券」門檻（每月成交筆數低於約 200 筆）</li>
            <li><strong>實務分水嶺</strong>：個股投資者常以「日均 500 張」作為最低水位（MoneyDJ / 財報狗 / CMoney 實務分析常見門檻）</li>
            <li><strong>學術文獻</strong>：Amihud (2002) illiquidity ratio、Kyle (1985) market depth 提供金額面的衝擊成本理論</li>
            <li><strong>ETF 規模 (AUM)</strong>：證交所對 ETF 下市門檻為「規模低於 1 億 + 成交量過低」（投信投顧公會 / 證交所 ETF 公告）</li>
          </ul>
        </article>
      </div>
      <div class="link-row" style="margin-top:10px;">
        <a class="link-chip" href="https://www.twse.com.tw/zh/page/products/securities/list-low.html" target="_blank" rel="noopener">TWSE 流動量偏低有價證券</a>
        <a class="link-chip" href="https://twse-regulation.twse.com.tw/" target="_blank" rel="noopener">TWSE 規章資料庫</a>
        <a class="link-chip" href="https://www.sitca.org.tw/" target="_blank" rel="noopener">投信投顧公會 ETF 公告</a>
      </div>
    </div>
  `;
}

