function activeEtfTodayTopChanges(registry, topN = 5) {
  const buys = new Map();
  const sells = new Map();
  const twEtfs = registry.filter(isTaiwanActiveEtf);
  let coveredEtfs = 0;
  const latestDays = new Set();
  const previousDays = new Set();
  const addEntry = (map, row, etf) => {
    if (!row?.code) return;
    const delta = toNumber(row.delta) || 0;
    const e = map.get(row.code) || {
      code: row.code,
      name: row.name || "",
      count: 0,
      totalDelta: 0,
      etfs: []
    };
    e.name = e.name || row.name || "";
    e.count++;
    e.totalDelta += delta;
    e.etfs.push({
      code: etf.code,
      shortName: etf.shortName || "",
      action: row.action || "",
      delta,
      weight: row.weight,
      previousWeight: row.previousWeight
    });
    map.set(row.code, e);
  };
  for (const etf of twEtfs) {
    const summary = activeEtfChangeSummary(etf.code, 1);
    if (summary.status !== "ok") continue;
    coveredEtfs++;
    if (summary.latestDay) latestDays.add(summary.latestDay);
    if (summary.previousDay) previousDays.add(summary.previousDay);
    for (const row of [...(summary.byAction.added || []), ...(summary.byAction.increased || [])]) {
      addEntry(buys, row, etf);
    }
    for (const row of [...(summary.byAction.removed || []), ...(summary.byAction.decreased || [])]) {
      addEntry(sells, row, etf);
    }
  }
  const sortTop = (map, direction) => Array.from(map.values())
    .map((row) => ({
      ...row,
      etfs: row.etfs.sort((a, b) => Math.abs(b.delta) - Math.abs(a.delta) || a.code.localeCompare(b.code, undefined, { numeric: true }))
    }))
    .sort((a, b) => (
      b.count - a.count
      || (direction === "buy" ? b.totalDelta - a.totalDelta : Math.abs(b.totalDelta) - Math.abs(a.totalDelta))
      || a.code.localeCompare(b.code, undefined, { numeric: true })
    ))
    .slice(0, topN);
  const dayLabel = (set) => {
    const days = Array.from(set).filter(Boolean).sort();
    if (!days.length) return "";
    if (days.length === 1) return days[0];
    return `${days[0]}~${days.at(-1)}`;
  };
  return {
    buys: sortTop(buys, "buy"),
    sells: sortTop(sells, "sell"),
    coveredEtfs,
    total: twEtfs.length,
    latestDay: dayLabel(latestDays),
    previousDay: dayLabel(previousDays)
  };
}

function renderActiveEtfTodayPanel(registry) {
  const { buys, sells, coveredEtfs, total, latestDay, previousDay } = activeEtfTodayTopChanges(registry);
  if (!coveredEtfs) {
    return `<div class="note-box" style="margin-bottom:14px;">尚無可比快照（需兩次以上更新才能比對換股）；按「更新ETF」後隔日再查。</div>`;
  }
  const latestIsToday = latestDay === dateKeyInTaipei();
  const windowText = [latestDay || "最新快照", previousDay ? `vs ${previousDay}` : ""].filter(Boolean).join(" ");
  const etfDetailHtml = (row, tone) => row.etfs.slice(0, 5).map((item) => `
    <span class="chip ${tone}" title="${escapeHtml(item.shortName || item.code)} ${escapeHtml(item.action || "")}：${formatNumber(item.previousWeight, 2)}% → ${formatNumber(item.weight, 2)}%">
      ${escapeHtml(item.code)} ${escapeHtml(formatSignedMetric(item.delta, 2, "pp"))}
    </span>
  `).join("");
  const rowHtml = (rows, tone) => rows.length
    ? rows.map((r) => `
        <div class="rank-row" style="cursor:pointer;" data-search-jump="${escapeHtml(r.code)}">
          <span>
            <strong>${escapeHtml(r.code)}</strong> ${escapeHtml(r.name || STOCK_MAP.get(r.code)?.name || "")}
            <br><small style="color:var(--muted);">共同 ${formatNumber(r.count, 0)} 檔；合計 ${escapeHtml(formatSignedMetric(r.totalDelta, 2, "pp"))}</small>
            <span class="chip-row chip-row-compact" style="margin-top:4px;">${etfDetailHtml(r, tone)}</span>
          </span>
          <strong class="${tone}">${formatNumber(r.count, 0)} 檔</strong>
        </div>`).join("")
    : `<div class="rank-row"><span style="color:var(--muted);">無異動</span></div>`;
  return `
    <div class="panel-lite" style="margin-bottom:14px;">
      <div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:10px;">
        <h3 style="margin:0;font-size:1rem;">今日投信共同買賣 Top 5</h3>
        <span style="color:var(--muted);font-size:0.78rem;">${escapeHtml(windowText)}；快照 ${coveredEtfs}/${total} 檔</span>
      </div>
      <div class="report-grid">
        <article class="rank-card">
          <h3>共同買進 / 加碼 Top 5</h3>
          <div class="rank-list">${rowHtml(buys, "up")}</div>
        </article>
        <article class="rank-card">
          <h3>共同賣出 / 減碼 Top 5</h3>
          <div class="rank-list">${rowHtml(sells, "down")}</div>
        </article>
      </div>
      <p style="color:var(--muted);font-size:0.74rem;margin:6px 0 0;">⚠️ 依主動 ETF 最新持股快照 vs 前一可比快照彙總；${latestIsToday ? "快照日為今天。" : "若要看今天，請先按「更新ETF」取得今日快照。"} 交易判讀仍需回各投信公告 / ETF Edge 來源核對。</p>
    </div>
  `;
}

