// ── v16.6 營收儀表板：本機 MOPS 官方月營收歷史（最多 36 個月）一目瞭然 ─────────
function revenueMomentumStats(rows) {
  const yoyRows = (rows || []).filter((row) => toNumber(row.yoyPct) !== null);
  let streakPositive = 0;
  let streakNegative = 0;
  for (let index = yoyRows.length - 1; index >= 0; index -= 1) {
    const yoy = toNumber(yoyRows[index].yoyPct);
    if (yoy > 0 && streakNegative === 0) streakPositive += 1;
    else if (yoy <= 0 && streakPositive === 0) streakNegative += 1;
    else break;
  }
  const avg = (list) => (list.length ? list.reduce((sum, value) => sum + value, 0) / list.length : null);
  const last3 = yoyRows.slice(-3).map((row) => toNumber(row.yoyPct));
  const prev3 = yoyRows.slice(-6, -3).map((row) => toNumber(row.yoyPct));
  const avgLast3 = last3.length === 3 ? avg(last3) : null;
  const avgPrev3 = prev3.length === 3 ? avg(prev3) : null;
  return {
    latest: (rows || []).at(-1) || null,
    months: (rows || []).length,
    streakPositive,
    streakNegative,
    avgLast3,
    avgPrev3,
    momentumDelta: avgLast3 !== null && avgPrev3 !== null ? avgLast3 - avgPrev3 : null
  };
}

function revenueBarsSvgHtml(rows, maxBars = 24) {
  const list = (rows || []).filter((row) => toNumber(row.current) !== null).slice(-maxBars);
  if (list.length < 2) return "";
  const width = 560;
  const height = 96;
  const gap = 2;
  const barWidth = Math.max(2, Math.floor((width - gap * (list.length - 1)) / list.length));
  const max = Math.max(...list.map((row) => toNumber(row.current)));
  if (!(max > 0)) return "";
  const bars = list.map((row, index) => {
    const value = toNumber(row.current);
    const barHeight = Math.max(2, Math.round(value / max * (height - 4)));
    const x = index * (barWidth + gap);
    const yoy = toNumber(row.yoyPct);
    const fill = yoy === null ? "var(--line)" : yoy > 0 ? "var(--bad)" : "var(--good)";
    return `<rect x="${x}" y="${height - barHeight}" width="${barWidth}" height="${barHeight}" fill="${fill}"><title>${escapeHtml(row.yearMonth)}：${formatNumber(value / 1000, 0)} 百萬（YoY ${yoy !== null ? formatPct(yoy) : "-"}）</title></rect>`;
  }).join("");
  return `<svg viewBox="0 0 ${width} ${height}" preserveAspectRatio="none" role="img" aria-label="月營收長條圖" style="width:100%;height:96px;display:block;">${bars}</svg>`;
}

// ── v16.7 Yahoo 月營收 5 年回補（Tier 2；60 個月；與 MOPS 官方當月交叉核對）──
function parseYahooMonthlyRevenueHtml(html) {
  const source = String(html || "");
  const matches = [...source.matchAll(/>(\d{4}\/\d{2})</g)];
  const rows = [];
  for (let index = 0; index < matches.length; index += 1) {
    const start = matches[index].index;
    const end = index + 1 < matches.length ? matches[index + 1].index : Math.min(source.length, start + 4000);
    const spans = [...source.slice(start, end).matchAll(/<span[^>]*>([^<]*)<\/span>/g)].map((m) => m[1].trim());
    // 欄位順序（2026-07-04 實測 2330）：單月營收、月增率、去年同月、年增率、累計、去年累計、累計年增率
    if (spans.length < 4 || !String(spans[1]).includes("%")) continue;
    const current = toNumber(String(spans[0]).replace(/,/g, ""));
    if (current === null) continue;
    rows.push({
      yearMonth: matches[index][1].replace("/", "-"),
      current,
      momPct: toNumber(String(spans[1]).replace(/%/g, "")),
      yoyPct: toNumber(String(spans[3] || "").replace(/%/g, "")),
      cumulative: toNumber(String(spans[4] || "").replace(/,/g, "")),
      cumulativeYoyPct: toNumber(String(spans[6] || "").replace(/%/g, "")),
      source: "Yahoo 月營收頁",
      fetchedAt: new Date().toISOString()
    });
  }
  const byMonth = new Map();
  for (const row of rows) byMonth.set(row.yearMonth, row);
  return [...byMonth.values()].sort((a, b) => a.yearMonth.localeCompare(b.yearMonth));
}

async function backfillRevenueHistoryFromYahoo(code) {
  const stock = revenueLinksStockFor(code) || { code, suffix: "TW" };
  const suffixes = stock.suffix ? [stock.suffix] : ["TW", "TWO"];
  let parsed = [];
  let usedSuffix = "";
  const errors = [];
  for (const suffix of suffixes) {
    try {
      const html = await fetchText(`https://tw.stock.yahoo.com/quote/${stock.code}.${suffix}/revenue`, { timeoutMs: 15000 });
      parsed = parseYahooMonthlyRevenueHtml(html);
      usedSuffix = suffix;
      if (parsed.length >= 12) break;
    } catch (error) {
      errors.push(`${suffix}: ${error?.message || String(error)}`);
    }
  }
  if (!parsed.length) throw new Error(`Yahoo 月營收頁未解析到資料${errors.length ? `（${errors.join("；")}）` : ""}`);
  state.revenueHistory = state.revenueHistory || {};
  const existing = Array.isArray(state.revenueHistory[stock.code]) ? state.revenueHistory[stock.code] : [];
  const byMonth = new Map();
  for (const row of parsed) byMonth.set(row.yearMonth, row);
  let mismatches = 0;
  for (const row of existing) {
    const month = normalizeMonthKey(row.yearMonth);
    if (!month) continue;
    const yahooRow = byMonth.get(month);
    const mopsCurrent = toNumber(row.current);
    const yahooCurrent = toNumber(yahooRow?.current);
    if (yahooRow && mopsCurrent !== null && yahooCurrent !== null && yahooCurrent !== 0
      && Math.abs(mopsCurrent - yahooCurrent) / Math.abs(yahooCurrent) > 0.02) {
      mismatches += 1;
    }
    byMonth.set(month, { ...yahooRow, ...row, yearMonth: month }); // 既有（MOPS 官方）優先覆蓋 Yahoo
  }
  const merged = [...byMonth.values()]
    .sort((a, b) => String(a.yearMonth).localeCompare(String(b.yearMonth)))
    .slice(-REVENUE_HISTORY_MONTH_LIMIT);
  state.revenueHistory[stock.code] = merged;
  state.revenueBackfill = normalizeRecordMap(state.revenueBackfill);
  state.revenueBackfill[stock.code] = {
    fetchedAt: new Date().toISOString(),
    source: `Yahoo 月營收頁（${stock.code}.${usedSuffix}）`,
    sourceTier: "Tier 2 市場資料",
    months: parsed.length,
    firstMonth: merged[0]?.yearMonth || "",
    lastMonth: merged.at(-1)?.yearMonth || "",
    mismatches
  };
  persistStateSilently("營收 5 年回補");
  try { await persistResearchDataLayer("revenue-backfill"); } catch (_) {}
  return { months: parsed.length, merged: merged.length, mismatches, suffix: usedSuffix };
}

function revenueQuarterRows(hist, limit = 8) {
  const byQuarter = new Map();
  for (const row of hist || []) {
    const month = normalizeMonthKey(row.yearMonth);
    const current = toNumber(row.current);
    if (!month || current === null) continue;
    const quarter = `${month.slice(0, 4)}Q${Math.floor((Number(month.slice(5, 7)) - 1) / 3) + 1}`;
    if (!byQuarter.has(quarter)) byQuarter.set(quarter, { quarter, total: 0, months: 0 });
    const entry = byQuarter.get(quarter);
    entry.total += current;
    entry.months += 1;
  }
  const complete = [...byQuarter.values()].filter((entry) => entry.months === 3).sort((a, b) => a.quarter.localeCompare(b.quarter));
  return complete.map((entry, index) => {
    const previous = complete[index - 1] || null;
    const lastYear = complete.find((item) => item.quarter === `${Number(entry.quarter.slice(0, 4)) - 1}${entry.quarter.slice(4)}`) || null;
    return {
      quarter: entry.quarter,
      total: entry.total,
      qoqPct: previous && previous.total ? (entry.total - previous.total) / previous.total * 100 : null,
      yoyPct: lastYear && lastYear.total ? (entry.total - lastYear.total) / lastYear.total * 100 : null
    };
  }).slice(-limit);
}

function revenueYearRows(hist, limit = 5) {
  const byYear = new Map();
  for (const row of hist || []) {
    const month = normalizeMonthKey(row.yearMonth);
    const current = toNumber(row.current);
    if (!month || current === null) continue;
    const year = month.slice(0, 4);
    if (!byYear.has(year)) byYear.set(year, { year, total: 0, months: new Set() });
    const entry = byYear.get(year);
    entry.total += current;
    entry.months.add(month.slice(5, 7));
  }
  const years = [...byYear.values()].sort((a, b) => a.year.localeCompare(b.year));
  return years.map((entry) => {
    const previous = byYear.get(String(Number(entry.year) - 1)) || null;
    // YTD 口徑：與去年「同月份集合」比，避免年度未完把年增算歪
    const previousComparable = previous
      ? (hist || []).reduce((sum, row) => {
          const month = normalizeMonthKey(row.yearMonth);
          const current = toNumber(row.current);
          if (!month || current === null) return sum;
          return month.slice(0, 4) === previous.year && entry.months.has(month.slice(5, 7)) ? sum + current : sum;
        }, 0)
      : 0;
    return {
      year: entry.year,
      total: entry.total,
      monthCount: entry.months.size,
      isPartial: entry.months.size < 12,
      yoyPct: previousComparable ? (entry.total - previousComparable) / previousComparable * 100 : null
    };
  }).slice(-limit);
}

function revenueSameMonthRows(hist, limit = 5) {
  const latest = (hist || []).at(-1);
  const latestMonth = normalizeMonthKey(latest?.yearMonth);
  if (!latestMonth) return { monthLabel: "", rows: [] };
  const monthPart = latestMonth.slice(5, 7);
  const rows = (hist || [])
    .filter((row) => normalizeMonthKey(row.yearMonth)?.slice(5, 7) === monthPart)
    .map((row) => ({
      yearMonth: normalizeMonthKey(row.yearMonth),
      current: toNumber(row.current),
      yoyPct: toNumber(row.yoyPct)
    }))
    .filter((row) => row.current !== null)
    .sort((a, b) => a.yearMonth.localeCompare(b.yearMonth))
    .slice(-limit);
  return { monthLabel: `${Number(monthPart)} 月`, rows };
}

function revenueTrendVerdict(stats, quarters, years) {
  const latestQuarter = quarters.at(-1) || null;
  const latestYear = years.at(-1) || null;
  const latestYoy = toNumber(stats?.latest?.yoyPct);
  const pieces = [];
  if (stats.streakPositive >= 2) pieces.push(`月 YoY 連 ${stats.streakPositive} 月正成長`);
  else if (stats.streakNegative >= 2) pieces.push(`月 YoY 連 ${stats.streakNegative} 月衰退`);
  else if (latestYoy !== null) pieces.push(`最新月 YoY ${formatPct(latestYoy)}`);
  if (latestQuarter) pieces.push(`最新完整季 ${latestQuarter.quarter} QoQ ${latestQuarter.qoqPct !== null ? formatPct(latestQuarter.qoqPct) : "-"} / YoY ${latestQuarter.yoyPct !== null ? formatPct(latestQuarter.yoyPct) : "-"}`);
  if (latestYear && latestYear.yoyPct !== null) pieces.push(`${latestYear.year} 年${latestYear.isPartial ? `累計（${latestYear.monthCount} 個月）` : ""}年增 ${formatPct(latestYear.yoyPct)}`);
  const growing = latestYoy !== null && latestYoy > 0;
  const momentum = toNumber(stats.momentumDelta);
  const verdictState = growing
    ? momentum !== null && momentum > 1 ? "成長且動能上行" : momentum !== null && momentum < -1 ? "仍成長但動能放緩" : "穩定成長"
    : momentum !== null && momentum > 1 ? "衰退中但降幅收斂" : "營收衰退";
  const tone = growing ? (momentum !== null && momentum < -1 ? "warn" : "up") : "down";
  return { text: `${pieces.join("；")}——${verdictState}。`, tone };
}

// v17.1：30% 年增門檻（影片概念，台灣平均年增長基準）——營收年增與獲利(EPS)年增均須 ≥ 30%
const GROWTH_GATE_THRESHOLD = 30;
function thirtyPercentGrowthCheck(code) {
  const hist = revenueHistoryRowsForCode(code);
  const latest = hist.at(-1) || null;
  // 營收年增：累計年增優先（同影片「營收累計成長」欄），否則用最新單月 YoY
  const revYoY = toNumber(latest?.cumulativeYoyPct) ?? toNumber(latest?.yoyPct);
  const stock = STOCK_MAP.get(code) || null;
  const eps25 = toNumber(stock?.eps25);
  const eps26 = toNumber(stock?.eps26e);
  const epsYoY = eps25 !== null && eps25 > 0 && eps26 !== null ? (eps26 - eps25) / eps25 * 100 : null;
  const revPass = revYoY !== null && revYoY >= GROWTH_GATE_THRESHOLD;
  const epsPass = epsYoY !== null && epsYoY >= GROWTH_GATE_THRESHOLD;
  // 營收「有沒有成長」直答
  const revenueGrowthAnswer = revYoY === null
    ? "營收年增待補（回補 5 年或更新月營收）"
    : revYoY >= GROWTH_GATE_THRESHOLD
      ? `有成長：營收年增 ${formatPct(revYoY)} ≥ 30% 門檻`
      : revYoY > 0
        ? `成長但未達門檻：營收年增 ${formatPct(revYoY)} < 30%`
        : `沒有成長：營收年增 ${formatPct(revYoY)}（衰退）`;
  let verdict;
  let tone;
  if (revYoY === null && epsYoY === null) { verdict = "資料不足（缺營收 / EPS 年增）"; tone = "flat"; }
  else if (revPass && epsPass) { verdict = "雙軌達標：營收 + 獲利年增均 ≥ 30%（高成長）"; tone = "up"; }
  else if (revPass || epsPass) { verdict = `單軌達標：${revPass ? "營收" : "獲利"}年增 ≥ 30%，另一軌未達 / 待補`; tone = "warn"; }
  else if ((revYoY !== null && revYoY > 0) || (epsYoY !== null && epsYoY > 0)) { verdict = "成長但未達 30% 門檻"; tone = "warn"; }
  else { verdict = "未見成長 / 衰退"; tone = "down"; }
  return { revYoY, epsYoY, revPass, epsPass, revenueGrowthAnswer, verdict, tone };
}

function renderRevenueDashboardCard(code) {
  const hist = revenueHistoryRowsForCode(code);
  const revenue = revenueFor(code);
  const backfillMeta = state.revenueBackfill?.[code] || null;
  const backfillButton = `<button class="secondary-btn" type="button" data-revenue-backfill-code="${escapeHtml(code)}" style="font-size:0.8rem;min-height:32px;">回補 5 年營收（Yahoo）</button>`;
  if (!hist.length) {
    return `<div class="note-box" data-revenue-dashboard style="margin-top:12px;">本機尚無 ${escapeHtml(code)} 的月營收數字。追蹤股請在主題總覽執行「更新月營收」（MOPS 官方 CSV），或按 ${backfillButton} 直接抓近 5 年月營收（Tier 2、以 MOPS / 原站為準）。</div>`;
  }
  const stats = revenueMomentumStats(hist);
  const latest = stats.latest || {};
  const latestYoy = toNumber(latest.yoyPct);
  const latestMom = toNumber(latest.momPct);
  const streakChip = stats.streakPositive >= 2
    ? `<span class="chip up">YoY 連 ${formatNumber(stats.streakPositive, 0)} 月正成長</span>`
    : stats.streakNegative >= 2
      ? `<span class="chip down">YoY 連 ${formatNumber(stats.streakNegative, 0)} 月衰退</span>`
      : "";
  const momentumChip = stats.momentumDelta !== null
    ? `<span class="chip ${stats.momentumDelta > 0 ? "up" : stats.momentumDelta < 0 ? "down" : "flat"}">3月YoY動能 ${stats.momentumDelta > 0 ? "+" : ""}${formatNumber(stats.momentumDelta, 1)} pt</span>`
    : "";
  const tableRows = hist.slice(-12).reverse().map((row, index, list) => {
    const idxInHist = hist.length - 1 - index;
    const window3 = hist.slice(Math.max(0, idxInHist - 2), idxInHist + 1).map((item) => toNumber(item.yoyPct)).filter((value) => value !== null);
    const avg3 = window3.length === 3 ? window3.reduce((sum, value) => sum + value, 0) / 3 : null;
    return `
      <tr>
        <td><strong>${escapeHtml(row.yearMonth)}</strong></td>
        <td class="num">${toNumber(row.current) !== null ? formatNumber(toNumber(row.current) / 1000, 0) : "-"}</td>
        <td class="num ${changeClass(toNumber(row.momPct))}">${toNumber(row.momPct) !== null ? formatPct(toNumber(row.momPct)) : "-"}</td>
        <td class="num ${changeClass(toNumber(row.yoyPct))}">${toNumber(row.yoyPct) !== null ? formatPct(toNumber(row.yoyPct)) : "-"}</td>
        <td class="num ${changeClass(avg3)}">${avg3 !== null ? formatPct(avg3) : "-"}</td>
      </tr>
    `;
  }).join("");
  const quarters = revenueQuarterRows(hist);
  const years = revenueYearRows(hist);
  const sameMonth = revenueSameMonthRows(hist);
  const verdict = revenueTrendVerdict(stats, quarters, years);
  const quarterRowsHtml = quarters.slice().reverse().map((row) => `
    <tr>
      <td><strong>${escapeHtml(row.quarter)}</strong></td>
      <td class="num">${formatNumber(row.total / 1000, 0)}</td>
      <td class="num ${changeClass(row.qoqPct)}">${row.qoqPct !== null ? formatPct(row.qoqPct) : "-"}</td>
      <td class="num ${changeClass(row.yoyPct)}">${row.yoyPct !== null ? formatPct(row.yoyPct) : "-"}</td>
    </tr>
  `).join("");
  const yearRowsHtml = years.slice().reverse().map((row) => `
    <tr>
      <td><strong>${escapeHtml(row.year)}</strong>${row.isPartial ? `<span class="chip flat" style="margin-left:6px;">累計 ${formatNumber(row.monthCount, 0)} 個月</span>` : ""}</td>
      <td class="num">${formatNumber(row.total / 1000, 0)}</td>
      <td class="num ${changeClass(row.yoyPct)}">${row.yoyPct !== null ? formatPct(row.yoyPct) : "-"}</td>
    </tr>
  `).join("");
  const sameMonthRowsHtml = sameMonth.rows.slice().reverse().map((row) => `
    <tr>
      <td><strong>${escapeHtml(row.yearMonth)}</strong></td>
      <td class="num">${formatNumber(row.current / 1000, 0)}</td>
      <td class="num ${changeClass(row.yoyPct)}">${row.yoyPct !== null ? formatPct(row.yoyPct) : "-"}</td>
    </tr>
  `).join("");
  const backfillNote = backfillMeta
    ? `已回補 Yahoo 近 5 年（${escapeHtml(backfillMeta.firstMonth)} ~ ${escapeHtml(backfillMeta.lastMonth)}、${formatNumber(backfillMeta.months, 0)} 個月、${escapeHtml(formatDateTime(backfillMeta.fetchedAt))}）${backfillMeta.mismatches ? `；⚠️ ${formatNumber(backfillMeta.mismatches, 0)} 個月與 MOPS 差異 > 2%，以 MOPS 為準、標待複核` : ""}`
    : stats.months < 24 ? "歷史月數偏少：按「回補 5 年營收（Yahoo）」一次補齊近 60 個月（Tier 2，與 MOPS 官方交叉）。" : "";
  return `
    <div class="panel-lite" data-revenue-dashboard style="margin-top:12px;">
      <div class="section-head">
        <div>
          <h3>營收儀表板（月 / 季 / 年）</h3>
          <p>近 ${formatNumber(stats.months, 0)} 個月；紅柱 = 該月 YoY 正成長、綠柱 = 衰退。當月以 MOPS 官方為準，5 年歷史可由 Yahoo 回補（Tier 2）。歷史統計非預測、非買賣建議。</p>
        </div>
        <div class="chip-row chip-row-compact">
          <span class="chip">最新 ${escapeHtml(latest.yearMonth || "-")}</span>
          <span class="chip ${changeClass(latestYoy)}">YoY ${latestYoy !== null ? formatPct(latestYoy) : "-"}</span>
          <span class="chip ${changeClass(latestMom)}">MoM ${latestMom !== null ? formatPct(latestMom) : "-"}</span>
          ${streakChip}
          ${momentumChip}
          ${backfillButton}
        </div>
      </div>
      <div class="note-box" data-revenue-trend-verdict style="margin-bottom:10px;">
        <strong class="${escapeHtml(verdict.tone)}">趨勢判讀：</strong>${escapeHtml(verdict.text)}
      </div>
      ${(() => {
        const g = thirtyPercentGrowthCheck(code);
        return `<div class="note-box" data-revenue-growth-gate style="margin-bottom:10px;">
          <strong class="${escapeHtml(g.tone)}">30% 年增門檻（有沒有成長）：</strong>${escapeHtml(g.revenueGrowthAnswer)}
          <div style="margin-top:4px;font-size:0.74rem;color:var(--muted);">口徑：台灣上市櫃平均年增長約 30%，達標才算「贏過平均」。綜合（營收 + 獲利）：${escapeHtml(g.verdict)}${g.epsYoY !== null ? `（EPS 年增 ${formatPct(g.epsYoY)}）` : "；EPS 年增待補研究欄位"}。歷史統計非買賣建議。</div>
        </div>`;
      })()}
      ${revenueBarsSvgHtml(hist, 36)}
      <div class="table-wrap" style="margin-top:10px;">
        <table style="min-width:560px;">
          <thead><tr><th>月份</th><th class="num">營收（百萬）</th><th class="num">MoM 月增</th><th class="num">YoY 年增</th><th class="num">3月均YoY</th></tr></thead>
          <tbody>${tableRows}</tbody>
        </table>
      </div>
      <div class="report-grid" style="margin-top:12px;">
        <div class="report-card" data-revenue-quarter-table>
          <h3>季營收（近 ${formatNumber(quarters.length, 0)} 個完整季）</h3>
          ${quarters.length ? `
            <div class="table-wrap">
              <table>
                <thead><tr><th>季度</th><th class="num">營收（百萬）</th><th class="num">季增 QoQ</th><th class="num">年增 YoY</th></tr></thead>
                <tbody>${quarterRowsHtml}</tbody>
              </table>
            </div>
          ` : `<div class="empty" style="padding:10px;">月份資料不足一個完整季度；回補 5 年後即可比較。</div>`}
        </div>
        <div class="report-card" data-revenue-year-table>
          <h3>年營收（近 ${formatNumber(years.length, 0)} 年）</h3>
          ${years.length ? `
            <div class="table-wrap">
              <table>
                <thead><tr><th>年度</th><th class="num">營收（百萬）</th><th class="num">年增 YoY</th></tr></thead>
                <tbody>${yearRowsHtml}</tbody>
              </table>
            </div>
            <p style="color:var(--muted);font-size:0.7rem;margin:6px 0 0;">未滿 12 個月年度為累計口徑，年增以「去年同月份集合」比較，避免比到不完整年度。</p>
          ` : ""}
        </div>
        <div class="report-card" data-revenue-same-month-table>
          <h3>歷年同月比較（${escapeHtml(sameMonth.monthLabel || "-")}）</h3>
          ${sameMonth.rows.length >= 2 ? `
            <div class="table-wrap">
              <table>
                <thead><tr><th>月份</th><th class="num">營收（百萬）</th><th class="num">YoY</th></tr></thead>
                <tbody>${sameMonthRowsHtml}</tbody>
              </table>
            </div>
          ` : `<div class="empty" style="padding:10px;">同月樣本不足 2 年；回補 5 年後可看季節性。</div>`}
        </div>
      </div>
      <p style="color:var(--muted);font-size:0.72rem;margin:8px 0 0;">來源：${escapeHtml(revenue?.source || "MOPS t187ap05 官方 CSV")}（當月官方）＋ Yahoo 月營收頁（5 年歷史，Tier 2）；${escapeHtml(backfillNote || `歷史上限 ${REVENUE_HISTORY_MONTH_LIMIT} 個月`)}；深入請用外部連結（財報狗 / Goodinfo）核對。</p>
    </div>
  `;
}

// ── v16.9 公司體質快篩：全部用本機既有資料（官方估值 / 三率 / 法人 / RS / 股利），缺項標待補 ──
function renderCompanyQualityCard(code) {
  const stock = STOCK_MAP.get(code) || null;
  const valuation = valuationFor(code);
  const pe = valuation ? toNumber(valuation.pe) : null;
  const officialYield = valuation ? toNumber(valuation.dividendYield) : null;
  const ratiosRaw = state.financialRatios?.[code];
  const ratioRows = Array.isArray(ratiosRaw) ? ratiosRaw : Array.isArray(ratiosRaw?.rows) ? ratiosRaw.rows : [];
  const latestRatio = ratioRows.at(-1) || null;
  const prevRatio = ratioRows.at(-2) || null;
  const marginTrend = (key) => {
    const now = toNumber(latestRatio?.[key]);
    const prev = toNumber(prevRatio?.[key]);
    if (now === null) return "-";
    const arrow = prev === null ? "" : now > prev ? " ▲" : now < prev ? " ▼" : " —";
    return `${formatNumber(now, 2)}%${arrow}`;
  };
  const inst = institutionalFor(code);
  const history = Array.isArray(inst?.history) ? inst.history : [];
  const sumNet = (days) => {
    const rows = history.slice(-days);
    if (!rows.length) return null;
    return rows.reduce((sum, row) => sum + (toNumber(row.foreignNet) ?? 0) + (toNumber(row.trustNet) ?? 0) + (toNumber(row.dealerNet) ?? 0), 0);
  };
  const net5 = sumNet(5);
  const net10 = sumNet(10);
  const rs = typeof calculateRS === "function" ? calculateRS(code) : null;
  const behavior = typeof exDividendBehaviorFor === "function" ? exDividendBehaviorFor(code) : null;
  const hist = revenueHistoryRowsForCode(code);
  const latestRev = hist.at(-1) || null;
  const cumulativeYoy = toNumber(latestRev?.cumulativeYoyPct);
  const isEtf = isEtfCode(code);
  const isFinancial = (stock?.themes || []).includes("financials");
  if (isEtf) {
    return `<div class="note-box" data-company-quality style="margin-top:12px;">ETF 不適用公司體質快篩（無月營收 / 三率）；請看 NAV、折溢價、成分持股與費用率。</div>`;
  }
  // v16.10：合理本益比價位（EPS × PE 情境帶＝河流圖概念）＋風險報酬比，複用個股研究既有引擎
  const quote = stock ? quoteFor(code) : null;
  const technical = stock ? (() => { try { return calculateTechnical(code); } catch (_) { return null; } })() : null;
  const rsMulti = stock && typeof calculateRSMulti === "function" ? (() => { try { return calculateRSMulti(code); } catch (_) { return null; } })() : null;
  const tradePlan = stock ? buildTradePlan(stock, technical, quote?.price ?? latestValue(stock), quote, rsMulti, revenueFor(code)) : null;
  const priceModel = stock ? buildValuationPriceModel(stock, valuation, quote, technical, tradePlan) : null;
  const curPrice = toNumber(quote?.price) ?? (stock ? toNumber(latestValue(stock)) : null);
  const rrText = tradePlan && tradePlan.rr !== null && tradePlan.rr !== undefined
    ? `${formatNumber(tradePlan.rr, 2)}R`
    : "需日線 / 進出場資料";
  const rrTone = tradePlan && tradePlan.rr !== null ? (tradePlan.rr >= 2 ? "up" : tradePlan.rr >= 1 ? "flat" : "down") : "flat";
  const fairText = priceModel?.ready
    ? `${formatNumber(priceModel.fairLow, 1)} / ${formatNumber(priceModel.fairMid, 1)} / ${formatNumber(priceModel.fairHigh, 1)}`
    : (priceModel?.reason || "缺 EPS / PE");
  const valuationBandTone = priceModel?.ready && curPrice !== null
    ? (curPrice <= priceModel.buyHigh ? "up" : curPrice >= priceModel.sellLow ? "down" : "flat")
    : "flat";
  const valuationBandLabel = priceModel?.ready && curPrice !== null
    ? (curPrice <= priceModel.buyHigh ? "落在情境買進帶" : curPrice >= priceModel.sellLow ? "接近情境減碼帶" : "情境中性區")
    : "";
  return `
    <div class="panel-lite" data-company-quality style="margin-top:12px;">
      <div class="section-head">
        <div>
          <h3>公司體質快篩（本機資料）</h3>
          <p>估值與殖利率為交易所官方口徑；三率需匯入季報 CSV；法人與 RS 由本機快取計算。快篩是研究起點，不是買賣建議${isFinancial ? "；金融股三率不適用，請看資本適足 / 逾放比 / ROE 專屬框架" : ""}。</p>
        </div>
      </div>
      <div class="report-grid" style="grid-template-columns:repeat(auto-fit,minmax(210px,1fr));">
        <div class="report-card" data-company-growth-gate>
          <h3>30% 年增門檻</h3>
          ${(() => {
            const g = thirtyPercentGrowthCheck(code);
            return `
              <div class="kv-row"><span>營收年增 ≥ 30%</span><strong class="${g.revYoY === null ? "" : g.revPass ? "up" : g.revYoY > 0 ? "warn" : "down"}">${g.revYoY !== null ? `${formatPct(g.revYoY)} ${g.revPass ? "✓" : "✗"}` : "待補"}</strong></div>
              <div class="kv-row"><span>獲利 EPS 年增 ≥ 30%</span><strong class="${g.epsYoY === null ? "" : g.epsPass ? "up" : g.epsYoY > 0 ? "warn" : "down"}">${g.epsYoY !== null ? `${formatPct(g.epsYoY)} ${g.epsPass ? "✓" : "✗"}` : "待補 EPS"}</strong></div>
              <div class="kv-row"><span>綜合</span><strong class="${g.tone}">${escapeHtml(g.verdict.split("：")[0])}</strong></div>
              <div style="margin-top:4px;font-size:0.68rem;color:var(--muted);">台灣平均年增約 30%，雙軌達標才算贏過平均。</div>
            `;
          })()}
        </div>
        <div class="report-card">
          <h3>估值（官方）</h3>
          <div class="kv-row"><span>本益比 PE</span><strong>${pe !== null ? formatNumber(pe, 1) : "待更新估值"}</strong></div>
          <div class="kv-row"><span>殖利率（近四季）</span><strong class="${officialYield !== null && officialYield >= 5 ? "up" : ""}">${officialYield !== null ? formatPercentMetric(officialYield) : "-"}</strong></div>
          <div class="kv-row"><span>累計營收年增</span><strong class="${changeClass(cumulativeYoy)}">${cumulativeYoy !== null ? formatPct(cumulativeYoy) : "回補 5 年後顯示"}</strong></div>
        </div>
        <div class="report-card">
          <h3>獲利三率${isFinancial ? "（金融不適用）" : ""}</h3>
          <div class="kv-row"><span>毛利率</span><strong>${marginTrend("grossMargin")}</strong></div>
          <div class="kv-row"><span>營益率</span><strong>${marginTrend("operatingMargin")}</strong></div>
          <div class="kv-row"><span>淨利率</span><strong>${marginTrend("netMargin")}</strong></div>
          ${latestRatio ? `<div style="margin-top:4px;font-size:0.7rem;color:var(--muted);">${escapeHtml(latestRatio.period || "")}（▲▼ 為與前一季比較）</div>` : `<div style="margin-top:4px;font-size:0.7rem;color:var(--muted);">尚未匯入三率 CSV（主題總覽可匯入）</div>`}
        </div>
        <div class="report-card">
          <h3>籌碼 / 相對強度</h3>
          <div class="kv-row"><span>法人近 5 日</span><strong class="${changeClass(net5)}">${net5 !== null ? `${formatNumber(net5, 0)} 張` : "待更新籌碼"}</strong></div>
          <div class="kv-row"><span>法人近 10 日</span><strong class="${changeClass(net10)}">${net10 !== null ? `${formatNumber(net10, 0)} 張` : "-"}</strong></div>
          <div class="kv-row"><span>RS vs 加權（65日）</span><strong class="${changeClass(rs?.excessReturn)}">${rs ? `${formatNumber(rs.excessReturn, 1)} pp` : "需日線資料"}</strong></div>
        </div>
        <div class="report-card">
          <h3>股利體質</h3>
          <div class="kv-row"><span>連續配息</span><strong>${behavior?.consecutiveYears ? `${formatNumber(behavior.consecutiveYears, 0)}${behavior.consecutiveCapped ? "+" : ""} 年` : "除權息分頁分析後顯示"}</strong></div>
          <div class="kv-row"><span>近5年均現金殖利率</span><strong>${toNumber(behavior?.avgCashYield5y) !== null ? formatPercentMetric(toNumber(behavior.avgCashYield5y)) : "-"}</strong></div>
          <div class="kv-row"><span>業外檢查</span><strong>${typeof exDividendNonOperatingCheck === "function" ? escapeHtml(exDividendNonOperatingCheck(code)?.label || "-") : "-"}</strong></div>
        </div>
        <div class="report-card" data-company-valuation>
          <h3>合理價估算（EPS × PE 情境帶）</h3>
          <div class="kv-row"><span>估值基準</span><strong>${priceModel?.ready ? `EPS ${formatNumber(priceModel.epsBase, 2)} × PE ${formatNumber(priceModel.peBase, 1)}` : "-"}</strong></div>
          <div class="kv-row"><span>合理價 低 / 中 / 高</span><strong>${escapeHtml(fairText)}</strong></div>
          ${priceModel?.ready ? `<div class="kv-row"><span>情境買進帶</span><strong class="up">${formatNumber(priceModel.buyLow, 1)}–${formatNumber(priceModel.buyHigh, 1)}</strong></div>` : ""}
          ${priceModel?.ready ? `<div class="kv-row"><span>目前價位</span><strong class="${valuationBandTone}">${curPrice !== null ? formatNumber(curPrice, 1) : "-"}${valuationBandLabel ? ` · ${valuationBandLabel}` : ""}</strong></div>` : ""}
          <div style="margin-top:4px;font-size:0.7rem;color:var(--muted);line-height:1.5;">低 / 中 / 高 = PE × 0.75 / 1.00 / 1.25（同河流圖 PE band 概念）。${priceModel?.ready ? escapeHtml((priceModel.warnings || []).slice(0, 1).join("")) : "缺 EPS 或 PE：請按「更新估值」或在研究欄位補 EPS / PE。"}</div>
        </div>
        <div class="report-card" data-company-riskreward>
          <h3>風險報酬比 R:R</h3>
          <div class="kv-row"><span>R:R（獎酬 ÷ 風險）</span><strong class="${rrTone}">${escapeHtml(rrText)}</strong></div>
          <div class="kv-row"><span>進場參考</span><strong>${tradePlan?.entryRef !== null && tradePlan?.entryRef !== undefined ? formatNumber(tradePlan.entryRef, 1) : "-"}${tradePlan?.entrySource ? `（${escapeHtml(tradePlan.entrySource)}）` : ""}</strong></div>
          <div class="kv-row"><span>停損 / 目標</span><strong>${tradePlan?.stopPrice !== null && tradePlan?.stopPrice !== undefined ? formatNumber(tradePlan.stopPrice, 1) : "-"} / ${tradePlan?.targetPrice !== null && tradePlan?.targetPrice !== undefined ? formatNumber(tradePlan.targetPrice, 1) : "-"}</strong></div>
          <div style="margin-top:4px;font-size:0.7rem;color:var(--muted);line-height:1.5;">R:R = 潛在漲幅 ÷ 潛在跌幅；一般研究上 ≥ 2R 才值得參與。進出場價由技術面 playbook 推定，非買賣建議。</div>
        </div>
      </div>
      <div class="note-box" data-downside-framework style="margin-top:12px;">
        <strong>利空 / 回檔判斷框架：</strong>不能只看「營收成長」或「股價回檔」就決定買賣——遇到產業利空或股價回檔時，先判斷這個利空<strong>是否真的破壞未來獲利</strong>（改變成長假設），還是只是短線題材 / 情緒 / 一次性因素。
        <div style="margin-top:4px;font-size:0.74rem;color:var(--muted);line-height:1.6;">檢查點：① 利空是否讓上面「30% 年增門檻」的未來假設不成立（訂單 / 報價 / 產能被實質砍）？② 是產業結構性衰退，還是庫存 / 淡季 / 匯率等可回復因素？③ 回檔後估值（上方 PE 情境帶）是否已反映最壞情況？三點都指向「未來獲利未被破壞 + 估值回到買進帶」時，回檔才是研究上的機會而非陷阱。研究框架、非買賣建議。</div>
      </div>
    </div>
  `;
}

// ── v16.6 供應鏈拉貨動能 proxy：主題股池月營收 YoY 轉正比率 + 中位數 ───────────
const REVENUE_PULL_IN_THEME_KEYS = [
  "tsmc", "cpo", "pcb", "advancedPackaging", "network", "memory",
  "thermal", "grid", "icdesign", "ems", "robot", "passive"
];
const REVENUE_PULL_IN_MIN_SAMPLE = 4;

function themeRevenuePullInSeries(themeKey, monthLimit = 13) {
  const byMonth = new Map();
  for (const stock of WATCHLIST) {
    if (!(stock.themes || []).includes(themeKey)) continue;
    for (const row of revenueHistoryRowsForCode(stock.code)) {
      const yoy = toNumber(row.yoyPct);
      if (yoy === null || !row.yearMonth) continue;
      if (!byMonth.has(row.yearMonth)) byMonth.set(row.yearMonth, []);
      byMonth.get(row.yearMonth).push(yoy);
    }
  }
  const months = [...byMonth.keys()].sort().slice(-monthLimit);
  return months.map((month) => {
    const values = byMonth.get(month).slice().sort((a, b) => a - b);
    const mid = Math.floor(values.length / 2);
    return {
      month,
      sample: values.length,
      positiveRatio: values.filter((value) => value > 0).length / values.length * 100,
      medianYoy: values.length % 2 ? values[mid] : (values[mid - 1] + values[mid]) / 2
    };
  });
}

function pullInSparkHtml(series) {
  const rows = series.map((item) => ({ close: item.positiveRatio }));
  if (rows.length < 3) return `<span style="color:var(--muted);font-size:0.7rem;">趨勢累積中</span>`;
  const path = sparklinePath(rows, 120, 28);
  if (!path) return "";
  const latest = rows.at(-1)?.close ?? 0;
  return `<svg viewBox="0 0 120 28" preserveAspectRatio="none" style="width:96px;height:20px;vertical-align:middle;" aria-label="YoY 轉正比率趨勢"><path d="${path}" fill="none" stroke="${latest >= 50 ? "var(--bad)" : "var(--good)"}" stroke-width="1.5" /></svg>`;
}

function renderRevenuePullInPanel() {
  const rows = REVENUE_PULL_IN_THEME_KEYS
    .map((key) => {
      const series = themeRevenuePullInSeries(key);
      const latest = series.at(-1) || null;
      const previous = series.at(-2) || null;
      return { key, label: THEME_LABELS[key] || key, series, latest, previous };
    })
    .filter((row) => row.latest)
    .sort((a, b) => (b.latest.medianYoy ?? -Infinity) - (a.latest.medianYoy ?? -Infinity));
  const bodyHtml = rows.length ? rows.map((row) => {
    const lowSample = row.latest.sample < REVENUE_PULL_IN_MIN_SAMPLE;
    const direction = row.previous
      ? row.latest.positiveRatio > row.previous.positiveRatio ? "▲" : row.latest.positiveRatio < row.previous.positiveRatio ? "▼" : "—"
      : "—";
    return `
      <tr data-revenue-pull-in-row="${escapeHtml(row.key)}">
        <td><strong>${escapeHtml(row.label)}</strong></td>
        <td>${escapeHtml(row.latest.month)}</td>
        <td class="num ${row.latest.positiveRatio >= 50 ? "up" : "down"}"><strong>${formatNumber(row.latest.positiveRatio, 0)}%</strong> ${escapeHtml(direction)}</td>
        <td class="num ${changeClass(row.latest.medianYoy)}">${formatPct(row.latest.medianYoy)}</td>
        <td>${pullInSparkHtml(row.series)}</td>
        <td class="num">${formatNumber(row.latest.sample, 0)}${lowSample ? `<span class="chip warn" style="margin-left:6px;">樣本不足</span>` : ""}</td>
      </tr>
    `;
  }).join("") : "";
  return `
    <div class="panel-lite" data-revenue-pull-in style="margin-top:12px;">
      <div class="section-head">
        <div>
          <h3>供應鏈拉貨動能（主題月營收 proxy）</h3>
          <p>同一主題股池「當月 YoY 轉正家數比率 + YoY 中位數」的月度變化：多檔同月轉強是拉貨期啟動的研究 proxy，不是買賣訊號；實際拉貨與訂單能見度仍需以法說 / 官方公告核對。</p>
        </div>
      </div>
      ${rows.length ? `
        <div class="table-wrap">
          <table style="min-width:760px;">
            <thead><tr><th>主題</th><th>最新月份</th><th class="num">YoY 轉正比率</th><th class="num">YoY 中位數</th><th>近 13 月轉正比率趨勢</th><th class="num">樣本檔數</th></tr></thead>
            <tbody>${bodyHtml}</tbody>
          </table>
        </div>
      ` : `<div class="empty">本機月營收資料還不足以計算主題拉貨動能；請先在主題總覽執行「更新月營收」，每月累積後趨勢才會成形。</div>`}
      <p style="color:var(--muted);font-size:0.72rem;margin:8px 0 0;">樣本 = 該主題內本機已有 MOPS 月營收數字的追蹤股（樣本 &lt; ${REVENUE_PULL_IN_MIN_SAMPLE} 檔標示樣本不足）；月份覆蓋依本機累積（上限 ${REVENUE_HISTORY_MONTH_LIMIT} 個月）。</p>
    </div>
  `;
}

