let _macroRefreshPromise = null;
const _autoBackfillCooldown = new Map(); // code → timestamp of last auto-trigger
const AUTO_BACKFILL_COOLDOWN_MS = 3_600_000; // 1 hour per stock

function macroNumberCell(value) {
  return cellNumber(String(value || "").replace(/,/g, ""));
}

function twseIndexRowToMacroItem(row, label, sourceDate) {
  if (!row) return null;
  const pct = macroNumberCell(row[4]);
  const point = macroNumberCell(row[3]);
  const signText = stripHtml(row[2] || "");
  const signedPoint = signText.includes("-") && point !== null ? -Math.abs(point) : point;
  return {
    key: `twse-${label}`,
    label,
    value: macroNumberCell(row[1]),
    valueSuffix: "",
    change: signedPoint,
    pct,
    date: slashDateFromCompact(sourceDate || ""),
    source: "TWSE MI_INDEX",
    sourceTier: "官方",
    url: "https://www.twse.com.tw/zh/trading/historical/mi-index.html",
    note: "臺灣證券交易所每日收盤指數"
  };
}

async function fetchTwseMacroItems() {
  const text = await fetchText("https://www.twse.com.tw/rwd/zh/afterTrading/MI_INDEX?response=json&type=IND", { timeoutMs: 12000 });
  const data = JSON.parse(text);
  const rows = data?.tables?.flatMap((table) => Array.isArray(table?.data) ? table.data : []) || [];
  const findRow = (label) => rows.find((row) => String(row?.[0] || "").includes(label));
  return [
    twseIndexRowToMacroItem(findRow("發行量加權股價指數"), "加權指數", data.date),
    twseIndexRowToMacroItem(findRow("電子工業類指數"), "電子指數", data.date),
    twseIndexRowToMacroItem(findRow("半導體類指數"), "半導體指數", data.date)
  ].filter(Boolean);
}

async function fetchVixMacroItem() {
  const text = await fetchText("https://cdn.cboe.com/api/global/us_indices/daily_prices/VIX_History.csv", { timeoutMs: 15000 });
  const rows = text.split(/\r?\n/).map((line) => line.trim()).filter((line) => /^\d{2}\/\d{2}\/\d{4},/.test(line));
  const latest = rows.at(-1);
  const previous = rows.at(-2);
  if (!latest) throw new Error("Cboe VIX CSV 無資料");
  const latestCells = latest.split(",");
  const previousCells = previous ? previous.split(",") : [];
  const close = macroNumberCell(latestCells[4]);
  const prevClose = macroNumberCell(previousCells[4]);
  const change = close !== null && prevClose !== null ? close - prevClose : null;
  const pct = change !== null && prevClose ? change / prevClose * 100 : null;
  return {
    key: "vix",
    label: "VIX",
    value: close,
    valueSuffix: "",
    change,
    pct,
    date: latestCells[0] || "",
    source: "Cboe VIX History CSV",
    sourceTier: "官方",
    url: "https://www.cboe.com/tradable-products/vix/",
    note: "美股波動率，>20 通常代表風險情緒升溫",
    series: rows.slice(-120).map((line) => {
      const cells = line.split(",");
      return { date: cells[0] || "", value: macroNumberCell(cells[4]) };
    }).filter((point) => point.value !== null)
  };
}

function xmlTagValue(block, tag) {
  const match = String(block || "").match(new RegExp(`<d:${tag}[^>]*>([^<]*)<\\/d:${tag}>`));
  return match ? match[1] : "";
}

async function fetchTreasuryYieldCurveRows() {
  const year = new Date().getFullYear();
  const url = `https://home.treasury.gov/resource-center/data-chart-center/interest-rates/pages/xml?data=daily_treasury_yield_curve&field_tdr_date_value=${year}`;
  const text = await fetchText(url, { timeoutMs: 18000 });
  const entries = [...text.matchAll(/<m:properties>([\s\S]*?)<\/m:properties>/g)].map((match) => match[1]);
  const rows = entries.map((block) => ({
    date: xmlTagValue(block, "NEW_DATE").slice(0, 10),
    twoYear: macroNumberCell(xmlTagValue(block, "BC_2YEAR")),
    twentyYear: macroNumberCell(xmlTagValue(block, "BC_20YEAR")),
    tenYear: macroNumberCell(xmlTagValue(block, "BC_10YEAR")),
    thirtyYear: macroNumberCell(xmlTagValue(block, "BC_30YEAR"))
  })).filter((row) => row.date && row.tenYear !== null).sort((a, b) => a.date.localeCompare(b.date));
  if (!rows.length) throw new Error("Treasury yield XML 無資料");
  return rows;
}

async function fetchTreasuryMacroItems() {
  const rows = await fetchTreasuryYieldCurveRows();
  const latest = rows.at(-1);
  const curveSpread = latest.tenYear !== null && latest.twoYear !== null ? latest.tenYear - latest.twoYear : null;
  const tenYearSeries = rows.slice(-120).map((row) => ({ date: row.date, value: row.tenYear })).filter((point) => point.value !== null);
  const thirtyYearSeries = rows.slice(-120).map((row) => ({ date: row.date, value: row.thirtyYear })).filter((point) => point.value !== null);
  const spreadSeries = rows.slice(-120).map((row) => ({
    date: row.date,
    value: row.tenYear !== null && row.twoYear !== null ? row.tenYear - row.twoYear : null
  })).filter((point) => point.value !== null);
  return [
    {
      key: "ust10y",
      label: "美債 10Y",
      value: latest.tenYear,
      valueSuffix: "%",
      change: null,
      pct: null,
      date: latest.date,
      source: "U.S. Treasury Yield Curve",
      sourceTier: "官方",
      url: "https://home.treasury.gov/resource-center/data-chart-center/interest-rates/TextView?type=daily_treasury_yield_curve",
      note: "長天期利率，影響科技股估值與美債 ETF 久期",
      series: tenYearSeries
    },
    {
      key: "ust30y",
      label: "美債 30Y",
      value: latest.thirtyYear,
      valueSuffix: "%",
      change: null,
      pct: null,
      date: latest.date,
      source: "U.S. Treasury Yield Curve",
      sourceTier: "官方",
      url: "https://home.treasury.gov/resource-center/data-chart-center/interest-rates/TextView?type=daily_treasury_yield_curve",
      note: "長天期美債 ETF 的核心利率代理；工具燈號以此搭配 USD/TWD 與 Fed 狀態判讀",
      series: thirtyYearSeries
    },
    {
      key: "ust2y10y",
      label: "10Y-2Y 利差",
      value: curveSpread,
      valueSuffix: "百分點",
      change: null,
      pct: null,
      date: latest.date,
      source: "U.S. Treasury Yield Curve",
      sourceTier: "官方",
      url: "https://home.treasury.gov/resource-center/data-chart-center/interest-rates/TextView?type=daily_treasury_yield_curve",
      note: "殖利率曲線斜率；負值代表倒掛",
      series: spreadSeries
    }
  ];
}

function twseMarginRow(rows, keyword) {
  return (rows || []).find((row) => stripHtml(row?.[0] || "").includes(keyword)) || null;
}

function twseMarginSnapshotFromData(data) {
  const rows = Array.isArray(data?.data)
    ? data.data
    : data?.tables?.flatMap((table) => Array.isArray(table?.data) ? table.data : []) || [];
  const financeRow = twseMarginRow(rows, "融資(交易單位)");
  const shortRow = twseMarginRow(rows, "融券(交易單位)");
  const financeValueRow = twseMarginRow(rows, "融資金額");
  const financeBalance = macroNumberCell(financeRow?.[5]);
  const financePrevious = macroNumberCell(financeRow?.[4]);
  const shortBalance = macroNumberCell(shortRow?.[5]);
  const shortPrevious = macroNumberCell(shortRow?.[4]);
  const financeValueThousand = macroNumberCell(financeValueRow?.[5]);
  if (financeBalance === null && shortBalance === null && financeValueThousand === null) {
    throw new Error("TWSE MI_MARGN 無法解析融資融券統計列");
  }
  return {
    source: "TWSE MI_MARGN",
    sourceTier: "官方",
    date: slashDateFromCompact(data?.date || "") || stripHtml(data?.title || "").match(/\d{3,4}\/\d{1,2}\/\d{1,2}/)?.[0] || "",
    url: "https://www.twse.com.tw/zh/trading/margin/MI_MARGN.html",
    financeBalance,
    financeChange: financeBalance !== null && financePrevious !== null ? financeBalance - financePrevious : null,
    shortBalance,
    shortChange: shortBalance !== null && shortPrevious !== null ? shortBalance - shortPrevious : null,
    financeValue100m: financeValueThousand !== null ? financeValueThousand / 100000 : null,
    note: "目前圖表先接 TWSE 上市信用交易統計；上櫃 TPEx 入口列在交叉核對卡，未併入前不當作完整全市場結論。"
  };
}

async function fetchTwseMarketMarginSnapshot() {
  const text = await fetchText("https://www.twse.com.tw/exchangeReport/MI_MARGN?response=json&selectType=MS", { timeoutMs: 12000 });
  return twseMarginSnapshotFromData(JSON.parse(text));
}

function mergeMacroHistory(previousHistory, items, marketMargin, fetchedAt, fedPath = null) {
  const itemMap = {};
  (items || []).forEach((item) => {
    const value = toNumber(item.value);
    if (!item?.key || value === null) return;
    itemMap[item.key] = {
      label: item.label || item.key,
      value,
      valueSuffix: item.valueSuffix || "",
      date: item.date || "",
      source: item.source || ""
    };
  });
  const snapshot = {
    ts: Date.now(),
    fetchedAt,
    items: itemMap,
    marketMargin: marketMargin || null,
    fedPath: fedPathHistorySnapshot(fedPath)
  };
  const existing = Array.isArray(previousHistory) ? previousHistory : [];
  return [...existing, snapshot]
    .filter((row) => row && (row.ts || row.fetchedAt))
    .sort((left, right) => (left.ts || 0) - (right.ts || 0))
    .slice(-FED_PATH_HISTORY_LIMIT);
}

async function updateMacroSnapshot(silent = false) {
  if (_macroRefreshPromise) return _macroRefreshPromise;
  if (!silent) setStatus("正在更新總經即時快照...", "warn");
  _macroRefreshPromise = (async () => {
    const previousCache = normalizeMacroCache(state.macroCache);
    const results = await Promise.allSettled([
      fetchTwseMacroItems(),
      fetchVixMacroItem().then((item) => [item]),
      fetchTreasuryMacroItems(),
      fetchTwseMarketMarginSnapshot(),
      fetchCbcUsdTwdSignal(),
      fetchFedPolicyPath(previousCache)
    ]);
    const items = [];
    const errors = [];
    const sources = ["TWSE", "Cboe", "Treasury", "TWSE 融資券", "CBC USD/TWD", "Fed path"];
    results.forEach((result, index) => {
      if (result.status === "fulfilled") {
        if (index < 3) items.push(...result.value);
      } else {
        errors.push(`${sources[index]}: ${result.reason?.message || String(result.reason)}`);
      }
    });
    const marketMargin = results[3]?.status === "fulfilled" ? results[3].value : null;
    const usdTwd = results[4]?.status === "fulfilled" ? results[4].value : null;
    const fedPath = results[5]?.status === "fulfilled" ? results[5].value : null;
    const fetchedAt = new Date().toISOString();
    state.macroCache = {
      ts: Date.now(),
      fetchedAt,
      items,
      marketMargin,
      usdTwd,
      fedPath,
      history: mergeMacroHistory(previousCache.history, items, marketMargin, fetchedAt, fedPath),
      errors
    };
    persistStateSilently("總經快照");
    if (state.activeTab === "macro") renderMacroTab();
    if (state.activeTab === "market" && !_marketCrashRiskBatchUpdating) renderMarketDashboardTab();
    if (!silent) setStatus(`總經快照已更新：${items.length} 項直接數值${marketMargin ? "，含上市融資券水位" : ""}。`, errors.length ? "warn" : "good");
    return items;
  })().finally(() => {
    _macroRefreshPromise = null;
  });
  return _macroRefreshPromise;
}

function maybeRefreshMacroSnapshot() {
  const cache = normalizeMacroCache(state.macroCache);
  if (!cache.ts || Date.now() - cache.ts > MACRO_CACHE_TTL_MS) {
    const run = () => updateMacroSnapshot(true).catch((error) => console.warn("updateMacroSnapshot failed", error));
    if (deferStartupRefresh("macroSnapshot", "總經快照", run, 7500)) return;
    run();
  }
}

let _marketDashboardRefreshPromise = null;

function yahooChartApiUrl(symbol, range = "1d", interval = "5m") {
  return `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=${encodeURIComponent(interval)}&range=${encodeURIComponent(range)}`;
}

function timestampToMarketTime(ts, timeZone = TAIPEI_TIME_ZONE) {
  if (!Number.isFinite(ts)) return "";
  return new Intl.DateTimeFormat("zh-TW", {
    timeZone,
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  }).format(new Date(ts * 1000));
}

function marketSeriesFromYahooResult(result, timeZone) {
  const timestamps = Array.isArray(result?.timestamp) ? result.timestamp : [];
  const quote = result?.indicators?.quote?.[0] || {};
  const closes = Array.isArray(quote.close) ? quote.close : [];
  return timestamps
    .map((ts, index) => {
      const value = toNumber(closes[index]);
      if (value === null) return null;
      return {
        ts: Number(ts) || index,
        date: timestampToMarketTime(Number(ts), timeZone),
        time: timestampToMarketTime(Number(ts), timeZone),
        value
      };
    })
    .filter(Boolean)
    .slice(-96);
}

function yahooQuoteArrayValue(array, reducer) {
  const values = Array.isArray(array) ? array.map((value) => toNumber(value)).filter((value) => value !== null) : [];
  if (!values.length) return null;
  return reducer(values);
}

async function fetchYahooIndexSnapshot(config) {
  const text = await fetchText(yahooChartApiUrl(config.symbol), { timeoutMs: 12000 });
  const data = JSON.parse(text);
  const result = data?.chart?.result?.[0];
  if (!result) throw new Error(`Yahoo chart 無 ${config.symbol} 資料`);
  const meta = result.meta || {};
  const timeZone = meta.exchangeTimezoneName || config.timeZone || (config.symbol === "^TWII" ? TAIPEI_TIME_ZONE : US_EASTERN_TIME_ZONE);
  const quote = result.indicators?.quote?.[0] || {};
  const series = marketSeriesFromYahooResult(result, timeZone);
  const latestSeriesValue = series.at(-1)?.value ?? null;
  const previousClose = toNumber(meta.chartPreviousClose) ?? toNumber(meta.previousClose);
  const value = toNumber(meta.regularMarketPrice) ?? latestSeriesValue;
  const change = value !== null && previousClose !== null ? value - previousClose : toNumber(meta.regularMarketChange);
  const pct = value !== null && previousClose ? change / previousClose * 100 : toNumber(meta.regularMarketChangePercent);
  const open = toNumber(meta.regularMarketOpen)
    ?? yahooQuoteArrayValue(quote.open, (values) => values[0]);
  const high = toNumber(meta.regularMarketDayHigh)
    ?? yahooQuoteArrayValue(quote.high, (values) => Math.max(...values));
  const low = toNumber(meta.regularMarketDayLow)
    ?? yahooQuoteArrayValue(quote.low, (values) => Math.min(...values));
  return normalizeMarketIndexSnapshot({
    key: config.key,
    label: config.label,
    symbol: config.symbol,
    value,
    previousClose,
    change,
    pct,
    open,
    high,
    low,
    volume: toNumber(meta.regularMarketVolume),
    sourceDate: meta.regularMarketTime ? timestampToMarketTime(Number(meta.regularMarketTime), timeZone) : "",
    sourceTime: meta.regularMarketTime ? timestampToMarketTime(Number(meta.regularMarketTime), timeZone) : "",
    timeZone,
    fetchedAt: new Date().toISOString(),
    source: "Yahoo Finance chart API",
    sourceTier: "市場資料",
    fallbackUsed: true,
    confidence: "medium",
    url: config.yahooUrl,
    note: "盤中 / 盤後即時指數採 Yahoo chart API；交易結論需與官方收盤資料交叉核對。",
    series
  });
}

function twseOfficialAmountTo100m(value) {
  const amount = macroNumberCell(value);
  if (amount === null) return null;
  return amount > 1_000_000 ? amount / 100_000_000 : amount;
}

function parseTwseMarketOverviewData(data, sourceType) {
  const tables = Array.isArray(data?.tables) ? data.tables : [];
  const rows = tables.flatMap((table) => Array.isArray(table?.data) ? table.data : []);
  const fields = tables.flatMap((table) => Array.isArray(table?.fields) ? table.fields : []);
  const date = slashDateFromCompact(data?.date || "");
  const indexRow = rows.find((row) => stripHtml(row?.[0] || "").includes("發行量加權股價指數"));
  let turnover100m = null;
  for (const table of tables) {
    const tableFields = Array.isArray(table?.fields) ? table.fields.map(stripHtml) : [];
    const amountIndex = tableFields.findIndex((field) => /成交金額|成交值/.test(field));
    if (amountIndex < 0) continue;
    const dataRows = Array.isArray(table?.data) ? table.data : [];
    const totalRow = dataRows.find((row) => /總計|合計|集中市場|上市/.test(stripHtml(row?.[0] || ""))) || dataRows[0];
    const amount = twseOfficialAmountTo100m(totalRow?.[amountIndex]);
    if (amount !== null) {
      turnover100m = amount;
      break;
    }
  }
  if (turnover100m === null) {
    for (const row of rows) {
      const label = stripHtml(row?.[0] || "");
      if (!/成交金額|成交值|總成交/.test(label)) continue;
      const amount = row.map(twseOfficialAmountTo100m).find((value) => value !== null && value > 0);
      if (amount !== undefined) {
        turnover100m = amount;
        break;
      }
    }
  }
  const close = macroNumberCell(indexRow?.[1]);
  const point = macroNumberCell(indexRow?.[3]);
  const pct = macroNumberCell(indexRow?.[4]);
  const signText = stripHtml(indexRow?.[2] || "");
  const change = signText.includes("-") && point !== null ? -Math.abs(point) : point;
  return {
    date,
    close,
    change,
    pct,
    turnover100m,
    source: `TWSE MI_INDEX ${sourceType}`,
    sourceTier: "官方",
    url: "https://www.twse.com.tw/zh/trading/historical/mi-index.html"
  };
}

async function fetchTwseMarketOverviewOfficial() {
  const urls = [
    { type: "MS", url: "https://www.twse.com.tw/rwd/zh/afterTrading/MI_INDEX?response=json&type=MS" },
    { type: "IND", url: "https://www.twse.com.tw/rwd/zh/afterTrading/MI_INDEX?response=json&type=IND" }
  ];
  let lastError = null;
  for (const item of urls) {
    try {
      const text = await fetchText(item.url, { timeoutMs: 12000 });
      const parsed = parseTwseMarketOverviewData(JSON.parse(text), item.type);
      if (parsed.close !== null || parsed.turnover100m !== null) return parsed;
    } catch (error) {
      lastError = error;
    }
  }
  throw new Error(`TWSE 大盤官方資料解析失敗：${lastError?.message || "無資料"}`);
}

function mergeTaiwanMarketSnapshot(yahooSnapshot, officialSnapshot) {
  const yahoo = normalizeMarketIndexSnapshot(yahooSnapshot) || {};
  const official = officialSnapshot || {};
  const officialHasIndex = official.close !== null && official.close !== undefined;
  const officialHasTurnover = official.turnover100m !== null && official.turnover100m !== undefined;
  return normalizeMarketIndexSnapshot({
    ...yahoo,
    key: TAIWAN_MARKET_INDEX.key,
    label: TAIWAN_MARKET_INDEX.label,
    symbol: TAIWAN_MARKET_INDEX.symbol,
    value: yahoo.value ?? (officialHasIndex ? official.close : null),
    previousClose: yahoo.previousClose ?? (officialHasIndex && official.change !== null && official.change !== undefined ? official.close - official.change : null),
    change: yahoo.change ?? official.change,
    pct: yahoo.pct ?? official.pct,
    turnover100m: officialHasTurnover ? official.turnover100m : yahoo.turnover100m,
    sourceDate: yahoo.sourceDate || official.date || "",
    timeZone: yahoo.timeZone || TAIPEI_TIME_ZONE,
    source: officialHasTurnover || officialHasIndex
      ? "Yahoo Finance chart API + TWSE MI_INDEX"
      : (yahoo.source || "Yahoo Finance chart API"),
    sourceTier: officialHasTurnover || officialHasIndex ? "官方 + 市場資料" : "市場資料",
    confidence: officialHasTurnover ? "medium-high" : "medium",
    url: official.url || yahoo.url || TAIWAN_MARKET_INDEX.yahooUrl,
    note: officialHasTurnover
      ? "指數線圖與盤中價採 Yahoo；成交金額採 TWSE 官方收盤資料，盤中可能落後。"
      : "指數線圖採 Yahoo；TWSE 官方成交金額尚未解析或尚未發布，請收盤後更新核對。"
  });
}

function taifexNightSeries(quote) {
  const points = [
    { label: "昨收", value: quote.previousClose ?? quote.ref },
    { label: "開", value: quote.open },
    { label: "高", value: quote.high },
    { label: "低", value: quote.low },
    { label: "現", value: quote.value ?? quote.last }
  ].filter((point) => toNumber(point.value) !== null);
  return points.map((point, index) => ({
    ts: index,
    date: point.label,
    time: point.label,
    value: toNumber(point.value)
  }));
}

function jsonLdBlocksFromHtml(html) {
  const blocks = [];
  const pattern = /<script[^>]+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
  let match;
  while ((match = pattern.exec(String(html || "")))) {
    try {
      blocks.push(JSON.parse(match[1].trim()));
    } catch (_) {}
  }
  return blocks;
}

function findCmoneyFutureEntity(jsonLd) {
  const queue = Array.isArray(jsonLd) ? [...jsonLd] : [jsonLd];
  while (queue.length) {
    const item = queue.shift();
    if (!item || typeof item !== "object") continue;
    if (String(item.tickerSymbol || "").toUpperCase() === "TXF1" && Array.isArray(item.additionalProperty)) {
      return item;
    }
    if (Array.isArray(item["@graph"])) queue.push(...item["@graph"]);
    for (const value of Object.values(item)) {
      if (value && typeof value === "object") queue.push(value);
    }
  }
  return null;
}

function cmoneyFutureProp(entity, label) {
  const row = (entity?.additionalProperty || []).find((item) => item?.name === label);
  return row ? row.value : null;
}

async function fetchCmoneyTaifexNightSnapshot() {
  const url = "https://www.cmoney.tw/forum/futures/TXF1?s=p";
  const html = await fetchText(url, { timeoutMs: 12000 });
  const entity = jsonLdBlocksFromHtml(html).map(findCmoneyFutureEntity).find(Boolean);
  if (!entity) throw new Error("CMoney TXF1 JSON-LD 無期貨數值");
  const value = toNumber(cmoneyFutureProp(entity, "成交"));
  const previousClose = toNumber(cmoneyFutureProp(entity, "昨收"));
  const change = toNumber(cmoneyFutureProp(entity, "漲跌")) ?? (value !== null && previousClose !== null ? value - previousClose : null);
  const pct = toNumber(cmoneyFutureProp(entity, "漲跌幅")) ?? (change !== null && previousClose ? change / previousClose * 100 : null);
  const snapshot = normalizeMarketIndexSnapshot({
    key: "cmoney-taifex-night-txf",
    label: "台指期夜盤 TXF",
    symbol: "TXF1",
    value,
    previousClose,
    change,
    pct,
    open: cmoneyFutureProp(entity, "開盤"),
    high: cmoneyFutureProp(entity, "最高"),
    low: cmoneyFutureProp(entity, "最低"),
    volume: cmoneyFutureProp(entity, "總量"),
    turnover100m: cmoneyFutureProp(entity, "金額(億)"),
    sourceDate: "",
    timeZone: TAIPEI_TIME_ZONE,
    fetchedAt: new Date().toISOString(),
    source: "CMoney TXF1 JSON-LD",
    sourceTier: "市場資料",
    confidence: "medium",
    fallbackUsed: true,
    url,
    sourceLinks: TAIFEX_NIGHT_SOURCE_LINKS,
    note: "TAIFEX 官方夜盤未回可用資料時的自動備援；交易判讀仍以 TAIFEX 官方行情優先。",
    series: taifexNightSeries({ value, previousClose, open: cmoneyFutureProp(entity, "開盤"), high: cmoneyFutureProp(entity, "最高"), low: cmoneyFutureProp(entity, "最低") })
  });
  if (snapshot.value === null) throw new Error("CMoney TXF1 無成交價");
  return snapshot;
}

async function fetchTaifexNightFuturesSnapshot() {
  const product = FUTURES_PRODUCTS.find((item) => item.key === "txf") || FUTURES_PRODUCTS[0];
  const errors = [];
  let quote = null;
  try {
    quote = await fetchTaifexQuote(product, "1");
  } catch (error) {
    errors.push(`TAIFEX 夜盤：${error?.message || String(error)}`);
  }
  if (!quote) {
    try {
      return await fetchCmoneyTaifexNightSnapshot();
    } catch (error) {
      errors.push(`CMoney：${error?.message || String(error)}`);
    }
  }
  if (!quote) {
    try {
      quote = await fetchTaifexQuote(product, "0");
      if (quote) quote.fallbackDaySession = true;
    } catch (error) {
      errors.push(`TAIFEX 日盤備援：${error?.message || String(error)}`);
    }
  }
  if (!quote) throw new Error(`台指期夜盤自動來源皆無報價：${errors.join("；") || "無資料"}`);
  const value = toNumber(quote.last);
  const previousClose = toNumber(quote.ref);
  const change = toNumber(quote.change) ?? (value !== null && previousClose !== null ? value - previousClose : null);
  const pct = toNumber(quote.pct) ?? (change !== null && previousClose ? change / previousClose * 100 : null);
  const isDayFallback = quote.fallbackDaySession === true;
  return normalizeMarketIndexSnapshot({
    key: "taifex-night-txf",
    label: isDayFallback ? "台指期 TXF（日盤備援）" : "台指期夜盤 TXF",
    symbol: quote.symbolId || product.commodityId,
    value,
    previousClose,
    change,
    pct,
    open: quote.open,
    high: quote.high,
    low: quote.low,
    volume: quote.volume,
    sourceDate: [quote.sourceDate, quote.sourceTime].filter(Boolean).join(" "),
    sourceTime: quote.sourceTime || "",
    timeZone: TAIPEI_TIME_ZONE,
    fetchedAt: new Date().toISOString(),
    source: isDayFallback ? "TAIFEX 一般交易即時行情 API（日盤備援）" : (quote.source || "TAIFEX 盤後交易即時行情 API"),
    sourceTier: isDayFallback ? "官方備援" : "官方",
    confidence: isDayFallback ? "medium" : "medium-high",
    url: TAIFEX_NIGHT_SOURCE_LINKS[0].url,
    sourceLinks: TAIFEX_NIGHT_SOURCE_LINKS,
    note: isDayFallback
      ? "TAIFEX 夜盤與 CMoney 備援未回可用值，暫顯示日盤 TXF；請用 Yahoo / CMoney / WantGoo 人工核對夜盤。"
      : "TAIFEX 盤後交易 API 未提供完整分時序列；線圖以昨收 / 開 / 高 / 低 / 現作夜盤 OHLC proxy。",
    series: taifexNightSeries({ ...quote, value, previousClose })
  });
}

let _tideSectorRefreshPromise = null;

async function fetchTideSectorSnapshot() {
  const fetchedAt = new Date().toISOString();
  const [latestResult, briefResult, digestResult] = await Promise.allSettled([
    fetchText(TIDE_LATEST_JSON_URL, { timeoutMs: 12000 }).then((text) => JSON.parse(text)),
    fetchText(TIDE_DAILY_BRIEF_JSON_URL, { timeoutMs: 8000 }).then((text) => JSON.parse(text)),
    fetchText(TIDE_DAILY_DIGEST_JSON_URL, { timeoutMs: 8000 }).then((text) => JSON.parse(text))
  ]);
  if (latestResult.status !== "fulfilled") {
    throw new Error(`Tide latest.json 讀取失敗：${latestResult.reason?.message || String(latestResult.reason)}`);
  }
  const cache = buildTideSectorCacheFromPayload(
    latestResult.value,
    briefResult.status === "fulfilled" ? briefResult.value : null,
    digestResult.status === "fulfilled" ? digestResult.value : null,
    fetchedAt
  );
  if (briefResult.status === "rejected") {
    cache.errors.push(`daily_brief：${briefResult.reason?.message || String(briefResult.reason)}`);
  }
  if (digestResult.status === "rejected") {
    cache.errors.push(`daily_digest：${digestResult.reason?.message || String(digestResult.reason)}`);
  }
  return normalizeTideSectorCache(cache);
}

async function updateTideSectorCache(silent = false) {
  if (_tideSectorRefreshPromise) return _tideSectorRefreshPromise;
  if (!silent) setStatus("正在更新 Tide 板塊資金...", "warn");
  _tideSectorRefreshPromise = (async () => {
    try {
      state.tideSectorCache = await fetchTideSectorSnapshot();
      persistStateSilently("Tide 板塊資金");
      if (state.activeTab === "market") renderMarketDashboardTab();
      if (!silent) {
        setStatus(`Tide 板塊資金已更新：${state.tideSectorCache.asOf || "日期待補"}，板塊 ${formatNumber(state.tideSectorCache.sectorCount, 0)}。`, state.tideSectorCache.errors.length ? "warn" : "good");
      }
      return state.tideSectorCache;
    } catch (error) {
      const current = normalizeTideSectorCache(state.tideSectorCache);
      state.tideSectorCache = normalizeTideSectorCache({
        ...current,
        errors: [...current.errors.slice(-4), error && error.message ? error.message : String(error)]
      });
      if (state.activeTab === "market") renderMarketDashboardTab();
      if (!silent) setStatus(`Tide 板塊資金更新失敗：${error?.message || String(error)}`, "error");
      throw error;
    }
  })().finally(() => {
    _tideSectorRefreshPromise = null;
  });
  return _tideSectorRefreshPromise;
}

function maybeRefreshTideSectorCache() {
  const cache = normalizeTideSectorCache(state.tideSectorCache);
  if (!cache.ts || Date.now() - cache.ts > TIDE_SECTOR_CACHE_TTL_MS) {
    const run = () => updateTideSectorCache(true).catch((error) => console.warn("updateTideSectorCache failed", error));
    if (deferStartupRefresh("tideSector", "Tide 板塊資金", run, 4500)) return;
    run();
  }
}

async function updateMarketDashboard(silent = false) {
  if (_marketDashboardRefreshPromise) return _marketDashboardRefreshPromise;
  const webRuntime = isPublishedWebRuntime();
  if (!silent) setStatus(webRuntime ? "正在重新讀取 GitHub 延遲快照..." : "正在更新大盤總覽...", "warn");
  _marketDashboardRefreshPromise = (async () => {
    if (webRuntime) {
      try {
        state.marketDashboardCache = await loadPublishedMarketSnapshot();
        persistStateSilently("GitHub 大盤延遲快照");
        if (state.activeTab === "market" && !_marketCrashRiskBatchUpdating) renderMarketDashboardTab();
        const cache = state.marketDashboardCache;
        const sourceCount = [cache.taiwan, cache.taifexNight, ...(cache.global || [])].filter(Boolean).length;
        if (!silent) {
          setStatus(
            `GitHub 延遲快照已讀取：${sourceCount}/6 項可用；排程可能延遲，非逐筆即時行情。`,
            cache.errors.length || sourceCount < 3 ? "warn" : "good"
          );
        }
        return cache;
      } catch (error) {
        const current = normalizeMarketDashboardCache(state.marketDashboardCache);
        const detail = error?.message || String(error);
        state.marketDashboardCache = normalizeMarketDashboardCache({
          ...current,
          errors: [...current.errors, `GitHub 延遲快照讀取失敗：${detail}`]
        });
        persistStateSilently("GitHub 大盤延遲快照錯誤");
        if (state.activeTab === "market" && !_marketCrashRiskBatchUpdating) renderMarketDashboardTab();
        if (!silent) setStatus(`GitHub 延遲快照讀取失敗：${detail}`, "error");
        throw error;
      }
    }
    const errors = [];
    const taiwanResults = await Promise.allSettled([
      fetchYahooIndexSnapshot(TAIWAN_MARKET_INDEX),
      fetchTwseMarketOverviewOfficial()
    ]);
    const taiwanYahoo = taiwanResults[0].status === "fulfilled" ? taiwanResults[0].value : null;
    const taiwanOfficial = taiwanResults[1].status === "fulfilled" ? taiwanResults[1].value : null;
    taiwanResults.forEach((result, index) => {
      if (result.status === "rejected") errors.push(`${index === 0 ? "Yahoo TWII" : "TWSE MI_INDEX"}: ${result.reason?.message || String(result.reason)}`);
    });
    const globalResults = await Promise.allSettled(GLOBAL_MARKET_INDICES.map((item) => fetchYahooIndexSnapshot(item)));
    const global = [];
    globalResults.forEach((result, index) => {
      if (result.status === "fulfilled") global.push(result.value);
      else errors.push(`${GLOBAL_MARKET_INDICES[index].label}: ${result.reason?.message || String(result.reason)}`);
    });
    const nightResult = await Promise.allSettled([fetchTaifexNightFuturesSnapshot()]);
    const taifexNight = nightResult[0].status === "fulfilled" ? nightResult[0].value : null;
    if (nightResult[0].status === "rejected") errors.push(`TAIFEX 夜盤: ${nightResult[0].reason?.message || String(nightResult[0].reason)}`);
    const fetchedAt = new Date().toISOString();
    state.marketDashboardCache = normalizeMarketDashboardCache({
      ts: Date.now(),
      fetchedAt,
      taiwan: mergeTaiwanMarketSnapshot(taiwanYahoo, taiwanOfficial),
      taifexNight,
      global,
      errors
    });
    persistStateSilently("大盤總覽");
    if (state.activeTab === "market" && !_marketCrashRiskBatchUpdating) renderMarketDashboardTab();
    const taiwanOk = state.marketDashboardCache.taiwan?.value !== null && state.marketDashboardCache.taiwan?.value !== undefined;
    if (!silent) setStatus(`大盤總覽已更新：台股 ${taiwanOk ? "OK" : "缺"}，美股 ${global.length}/4，夜盤 ${taifexNight ? "OK" : "缺"}`, errors.length ? "warn" : "good");
    return state.marketDashboardCache;
  })().finally(() => {
    _marketDashboardRefreshPromise = null;
  });
  return _marketDashboardRefreshPromise;
}

function maybeRefreshMarketDashboard() {
  const cache = normalizeMarketDashboardCache(state.marketDashboardCache);
  const now = new Date();
  // 美股開盤期間縮短 TTL 至 5 分鐘；其他時段 30 分鐘才重新抓取
  const ttl = (isUsMarketOpen(now) || isTaiwanMarketOpen(now)) ? MARKET_DASHBOARD_CACHE_TTL_MS : 30 * 60 * 1000;
  if (!cache.ts || Date.now() - cache.ts > ttl) {
    const run = () => updateMarketDashboard(true).catch((error) => console.warn("updateMarketDashboard failed", error));
    if (deferStartupRefresh("marketDashboard", "大盤總覽", run, 4500)) return;
    run();
  }
}

function macroItemTone(item) {
  if (item.key === "vix") {
    if (item.value >= 25) return "down";
    if (item.value <= 16) return "up";
  }
  if (item.key === "ust2y10y") return item.value < 0 ? "down" : "flat";
  if (item.pct > 0) return "up";
  if (item.pct < 0) return "down";
  return "flat";
}

function macroSeriesFromHistory(cache, key) {
  return (cache.history || [])
    .map((row) => {
      const entry = row.items?.[key];
      const value = toNumber(entry?.value);
      if (value === null) return null;
      return {
        ts: row.ts || Date.parse(row.fetchedAt || "") || 0,
        date: entry.date || row.fetchedAt || "",
        value
      };
    })
    .filter(Boolean)
    .sort((left, right) => left.ts - right.ts);
}

function macroChartSeries(item, cache) {
  const direct = Array.isArray(item?.series)
    ? item.series
        .map((point, index) => ({
          ts: Date.parse(point.date || "") || index,
          date: point.date || "",
          value: toNumber(point.value)
        }))
        .filter((point) => point.value !== null)
        .sort((left, right) => left.ts - right.ts)
    : [];
  if (direct.length >= 2) return direct;
  const klinesFallbackKeys = {
    "twse-加權指數": "^TWII",
    "twse-電子指數": "^TWXT",
    "twse-半導體指數": "^TWTSC"
  };
  const klineKey = klinesFallbackKeys[item?.key];
  if (klineKey) {
    const klineRows = (Array.isArray(state.klines?.[klineKey]) ? state.klines[klineKey] : klineKey === "^TWII" ? taiexKlines() : [])
      .slice(-120)
      .map((row, index) => ({
        ts: Date.parse(row.date || "") || index,
        date: row.date || "",
        value: toNumber(row.close)
      }))
      .filter((point) => point.value !== null)
      .sort((left, right) => left.ts - right.ts);
    if (klineRows.length >= 2) return klineRows;
  }
  const histSeries = macroSeriesFromHistory(cache, item.key);
  if (histSeries.length >= 2) return histSeries;
  return [];
}

function macroMarginSeriesFromHistory(cache, key) {
  return (cache.history || [])
    .map((row) => {
      const margin = row.marketMargin || {};
      const value = toNumber(margin[key]);
      if (value === null) return null;
      return {
        ts: row.ts || Date.parse(row.fetchedAt || "") || 0,
        date: margin.date || row.fetchedAt || "",
        value
      };
    })
    .filter(Boolean)
    .sort((left, right) => left.ts - right.ts);
}

const MARKET_HEAT_GROUPS = [
  { key: "technical", label: "技術線型", max: 35 },
  { key: "breadth", label: "廣度 / 擴散", max: 20 },
  { key: "leverage", label: "槓桿 / 期權", max: 25 },
  { key: "macro", label: "總經 / 外部", max: 20 }
];

function marketHeatLevel(score, coverage) {
  if (coverage < 45) {
    return {
      label: "資料不足",
      tone: "flat",
      detail: "可用資料權重偏低，請先更新大盤、總經、期貨與日線後再判讀。"
    };
  }
  if (score >= 76) {
    return {
      label: "高度過熱",
      tone: "danger",
      detail: "多個面向同時顯示擁擠或風險升溫；研究上應降低追價、檢查停利與避險情境。"
    };
  }
  if (score >= 56) {
    return {
      label: "過熱",
      tone: "warn",
      detail: "技術位階或籌碼槓桿偏熱，若外部風險同步升溫，回檔風險需要提高權重。"
    };
  }
  if (score >= 34) {
    return {
      label: "偏熱",
      tone: "warn",
      detail: "部分指標偏熱，適合用分批、停損與資料交叉核對來控制追價風險。"
    };
  }
  return {
    label: "未見明顯過熱",
    tone: "good",
    detail: "目前可用指標未同時指向過熱；仍需持續更新官方與市場資料。"
  };
}

function marketHeatScoreFromPercentile(percentile, maxScore, warm = 65, hot = 85) {
  const value = toNumber(percentile);
  if (value === null) return null;
  if (value < warm) return 0;
  if (value >= hot) return maxScore;
  return (value - warm) / (hot - warm) * maxScore;
}

function marketHeatFactor({
  group,
  label,
  score,
  max,
  value = "",
  detail = "",
  source = "",
  asOf = "",
  tone = "flat",
  confidence = "medium"
}) {
  const numericScore = clamp(toNumber(score) ?? 0, 0, max || 0);
  return {
    group,
    label,
    score: numericScore,
    max: max || 0,
    value,
    detail,
    source,
    asOf,
    tone,
    confidence
  };
}

function marketHeatMissing(group, label, detail, source = "", max = 0) {
  return { group, label, detail, source, max };
}

function marketHeatMetricTone(score, max) {
  const ratio = max ? score / max : 0;
  if (ratio >= 0.75) return "danger";
  if (ratio >= 0.45) return "warn";
  return "flat";
}

function marketHeatConsecutiveUp(rows) {
  let count = 0;
  for (let index = rows.length - 1; index > 0; index -= 1) {
    const close = toNumber(rows[index]?.close);
    const prevClose = toNumber(rows[index - 1]?.close);
    if (close === null || prevClose === null || close <= prevClose) break;
    count += 1;
  }
  return count;
}

function marketHeatTechnicalFactors() {
  const rows = taiexKlines();
  const factors = [];
  const missing = [];
  if (!Array.isArray(rows) || rows.length < 20) {
    missing.push(marketHeatMissing("technical", "TAIEX 日線", "至少需要 20 根加權指數日線才能計算 RSI、均線乖離與布林位階。", "TWSE / Yahoo 日線", 35));
    return { factors, missing };
  }

  const technical = calculateTechnical(TAIEX_CODE, rows);
  const latest = technical.latest || rows.at(-1);
  const closes = rows.map((row) => toNumber(row.close)).filter((value) => value !== null);
  const ma20Series = smaSeries(closes, 20);
  const biasSeries = closes
    .map((close, index) => {
      const ma20 = ma20Series[index];
      return ma20 ? (close - ma20) / ma20 * 100 : null;
    })
    .filter((value) => value !== null);
  const currentBias = toNumber(technical.bias20);
  const biasPercentile = currentBias !== null ? percentileRank(biasSeries, currentBias) : null;
  const latestClose = toNumber(latest?.close);
  const rsi14 = toNumber(technical.rsi14);

  if (rsi14 !== null) {
    const rsiScore = rsi14 >= 82 ? 10 : rsi14 >= 78 ? 8 : rsi14 >= 70 ? 6 : rsi14 >= 65 ? 3 : 0;
    factors.push(marketHeatFactor({
      group: "technical",
      label: "RSI 動能",
      score: rsiScore,
      max: 10,
      value: formatNumber(rsi14, 1),
      detail: rsi14 >= 70
        ? "RSI 進入傳統過熱區；需搭配背離、量價與均線，不單獨作交易結論。"
        : "RSI 尚未進入常見過熱區。",
      source: latest?.source || "TAIEX 日線",
      asOf: latest?.date || "",
      tone: marketHeatMetricTone(rsiScore, 10),
      confidence: "medium"
    }));
  } else {
    missing.push(marketHeatMissing("technical", "RSI", "日線資料不足，無法計算 RSI。", "TAIEX 日線", 10));
  }

  if (currentBias !== null) {
    const fallbackScore = currentBias >= 8 ? 9 : currentBias >= 5 ? 6 : currentBias >= 3 ? 3 : 0;
    const pctScore = marketHeatScoreFromPercentile(biasPercentile, 9, 70, 90);
    const biasScore = Math.max(fallbackScore, pctScore ?? 0);
    factors.push(marketHeatFactor({
      group: "technical",
      label: "月線乖離",
      score: biasScore,
      max: 9,
      value: `${formatSignedMetric(currentBias, 1, "%")}${biasPercentile !== null ? ` / ${formatNumber(biasPercentile, 0)}%ile` : ""}`,
      detail: currentBias > 0
        ? "指數高於 20 日均線；乖離越高，追價的風險報酬越差。"
        : "指數未高於月線，未形成正乖離過熱。",
      source: latest?.source || "TAIEX 日線",
      asOf: latest?.date || "",
      tone: marketHeatMetricTone(biasScore, 9),
      confidence: biasPercentile !== null ? "medium-high" : "medium"
    }));
  } else {
    missing.push(marketHeatMissing("technical", "月線乖離", "需要 20 根以上 TAIEX 日線。", "TAIEX 日線", 9));
  }

  if (latestClose !== null && technical.bbUpper !== null) {
    const upperGap = (latestClose - technical.bbUpper) / technical.bbUpper * 100;
    const bbScore = upperGap > 1 ? 7 : upperGap >= 0 ? 5 : upperGap >= -1 ? 2 : 0;
    factors.push(marketHeatFactor({
      group: "technical",
      label: "布林上緣",
      score: bbScore,
      max: 7,
      value: `${formatSignedMetric(upperGap, 1, "%")}`,
      detail: upperGap >= 0
        ? "收盤在布林上緣附近或上方，短線波動放大與均值回歸風險提高。"
        : "尚未貼近布林上緣。",
      source: latest?.source || "TAIEX 日線",
      asOf: latest?.date || "",
      tone: marketHeatMetricTone(bbScore, 7)
    }));
  } else {
    missing.push(marketHeatMissing("technical", "布林上緣", "需要 20 根以上 TAIEX 日線與標準差。", "TAIEX 日線", 7));
  }

  const recent60 = closes.slice(-60);
  const recent20Rsi = rsiSeries(closes, 14).slice(-20).filter((value) => value !== null);
  const recentHist = macdFullSeries(closes).histograms.slice(-20).filter((value) => Number.isFinite(value));
  const recentHigh = recent60.length ? Math.max(...recent60) : null;
  const rsiPeak = recent20Rsi.length ? Math.max(...recent20Rsi) : null;
  const histPeak = recentHist.length ? Math.max(...recentHist) : null;
  const consecutiveUp = marketHeatConsecutiveUp(rows);
  let exhaustionScore = consecutiveUp >= 5 ? 5 : consecutiveUp >= 3 ? 3 : 0;
  const exhaustionNotes = [];
  if (consecutiveUp >= 3) exhaustionNotes.push(`連漲 ${consecutiveUp} 日`);
  if (latestClose !== null && recentHigh !== null && latestClose >= recentHigh * 0.995) {
    if (rsi14 !== null && rsiPeak !== null && rsi14 <= rsiPeak - 5) {
      exhaustionScore += 4;
      exhaustionNotes.push("接近 60 日高點但 RSI 未同步創高");
    }
    if (technical.macd?.histogram !== null && histPeak !== null && technical.macd.histogram <= histPeak * 0.65) {
      exhaustionScore += 3;
      exhaustionNotes.push("MACD 柱狀體低於近期高峰");
    }
  }
  factors.push(marketHeatFactor({
    group: "technical",
    label: "動能耗竭 proxy",
    score: clamp(exhaustionScore, 0, 9),
    max: 9,
    value: exhaustionNotes.length ? exhaustionNotes.join("；") : "未觸發",
    detail: "以連漲、接近高點但 RSI / MACD 未同步擴張作為頂部背離 proxy；仍需人工複核 K 線結構。",
    source: latest?.source || "TAIEX 日線",
    asOf: latest?.date || "",
    tone: marketHeatMetricTone(exhaustionScore, 9),
    confidence: "medium"
  }));

  return { factors, missing };
}

let _marketHeatBreadthSnapshotCache = null;

function marketHeatBreadthSnapshot() {
  const klineState = normalizeRecordMap(state.klines);
  const cacheKey = [
    Object.keys(klineState).length,
    state.klineStorage?.updatedAt || "",
    state.klineStorage?.lastHydratedAt || "",
    state.lastUpdated || ""
  ].join("|");
  if (_marketHeatBreadthSnapshotCache?.key === cacheKey) {
    return _marketHeatBreadthSnapshotCache.rows;
  }
  const stocks = quoteTrackableStocks(WATCHLIST).filter((stock) => !isEtfCode(stock.code));
  const rows = [];
  for (const stock of stocks) {
    const klines = Array.isArray(klineState[stock.code]) ? klineState[stock.code] : [];
    if (!Array.isArray(klines) || klines.length < 60) continue;
    const closes = klines.map((row) => toNumber(row.close));
    const latestClose = closes.at(-1);
    const ma20 = sma(closes.filter((value) => value !== null), 20);
    const ma60 = sma(closes.filter((value) => value !== null), 60);
    const rsi14 = rsi(closes.filter((value) => value !== null), 14);
    if (latestClose === null) continue;
    rows.push({
      code: stock.code,
      date: klines.at(-1)?.date || "",
      latestClose,
      aboveMa20: ma20 !== null ? latestClose > ma20 : false,
      aboveMa60: ma60 !== null ? latestClose > ma60 : false,
      rsi14
    });
  }
  _marketHeatBreadthSnapshotCache = { key: cacheKey, rows };
  return rows;
}

function marketHeatBreadthFactors() {
  const factors = [];
  const missing = [];
  const rows = marketHeatBreadthSnapshot();
  if (rows.length < 20) {
    missing.push(marketHeatMissing("breadth", "追蹤池廣度", `目前只有 ${rows.length} 檔具 60 根以上日線；廣度 proxy 需要至少 20 檔。`, "追蹤池日線", 20));
    return { factors, missing };
  }
  const pctAbove20 = rows.filter((row) => row.aboveMa20).length / rows.length * 100;
  const pctAbove60 = rows.filter((row) => row.aboveMa60).length / rows.length * 100;
  const rsiHotPct = rows.filter((row) => toNumber(row.rsi14) !== null && row.rsi14 >= 70).length / rows.length * 100;
  const latestDates = rows.map((row) => row.date).filter(Boolean);
  const asOf = latestDates.sort().at(-1) || "";
  const taiexRows = taiexKlines();
  const taiexCloses = taiexRows.map((row) => toNumber(row.close)).filter((value) => value !== null);
  const taiexClose = taiexCloses.at(-1);
  const taiexHigh60 = taiexCloses.length >= 60 ? Math.max(...taiexCloses.slice(-60)) : null;
  const nearHigh = taiexClose !== null && taiexHigh60 !== null && taiexClose >= taiexHigh60 * 0.985;

  const broadScore = pctAbove20 >= 85 && pctAbove60 >= 78 ? 9
    : pctAbove20 >= 78 && pctAbove60 >= 68 ? 7
    : pctAbove20 >= 68 ? 4
    : 0;
  factors.push(marketHeatFactor({
    group: "breadth",
    label: "多頭廣度",
    score: broadScore,
    max: 9,
    value: `月線上 ${formatNumber(pctAbove20, 0)}% / 季線上 ${formatNumber(pctAbove60, 0)}%`,
    detail: "追蹤池多數個股同時站上月線與季線時，代表行情擴散但也可能進入擁擠階段。",
    source: `追蹤池日線 ${rows.length} 檔`,
    asOf,
    tone: marketHeatMetricTone(broadScore, 9),
    confidence: rows.length >= 50 ? "medium-high" : "medium"
  }));

  const hotRsiScore = rsiHotPct >= 35 ? 6 : rsiHotPct >= 25 ? 4 : rsiHotPct >= 15 ? 2 : 0;
  factors.push(marketHeatFactor({
    group: "breadth",
    label: "個股 RSI 擁擠",
    score: hotRsiScore,
    max: 6,
    value: `${formatNumber(rsiHotPct, 0)}% 個股 RSI >= 70`,
    detail: "追蹤池內 RSI 過熱個股比例升高，代表短線追價風險擴散。",
    source: `追蹤池日線 ${rows.length} 檔`,
    asOf,
    tone: marketHeatMetricTone(hotRsiScore, 6)
  }));

  const divergenceScore = nearHigh && pctAbove20 < 52 ? 5 : nearHigh && pctAbove20 < 62 ? 3 : 0;
  factors.push(marketHeatFactor({
    group: "breadth",
    label: "高檔擴散轉弱",
    score: divergenceScore,
    max: 5,
    value: nearHigh ? `TAIEX 近高；月線上 ${formatNumber(pctAbove20, 0)}%` : "未觸發",
    detail: "指數接近 60 日高點但追蹤池月線上比例下滑時，可能是權值股撐盤、廣度轉弱的修正風險。",
    source: "TAIEX 日線 + 追蹤池日線",
    asOf,
    tone: marketHeatMetricTone(divergenceScore, 5),
    confidence: "medium"
  }));

  return { factors, missing };
}

function macroItemByKey(cache, key) {
  return (cache.items || []).find((item) => item?.key === key) || null;
}

function marketHeatLeverageFactors(cache) {
  const factors = [];
  const missing = [];
  const margin = cache.marketMargin || null;
  if (margin) {
    const financeSeries = macroMarginSeriesFromHistory(cache, "financeValue100m").map((point) => point.value);
    const financeValue = toNumber(margin.financeValue100m);
    const financePercentile = financeValue !== null && financeSeries.length >= 8 ? percentileRank(financeSeries, financeValue) : null;
    const financeScore = marketHeatScoreFromPercentile(financePercentile, 10, 65, 90) ?? 0;
    factors.push(marketHeatFactor({
      group: "leverage",
      label: "融資金額分位",
      score: financeScore,
      max: 10,
      value: `${formatNumber(financeValue, 0)} 億${financePercentile !== null ? ` / ${formatNumber(financePercentile, 0)}%ile` : ""}`,
      detail: "以上市 TWSE 信用交易統計作風險 proxy；上櫃尚未併入前，不解讀為完整全市場融資水位。",
      source: margin.source || "TWSE MI_MARGN",
      asOf: margin.date || "",
      tone: marketHeatMetricTone(financeScore, 10),
      confidence: financePercentile !== null ? "medium-high" : "medium"
    }));

    const changes = macroMarginSeriesFromHistory(cache, "financeBalance")
      .map((point, index, series) => index > 0 ? point.value - series[index - 1].value : null)
      .filter((value) => value !== null);
    const financeChange = toNumber(margin.financeChange);
    const changePercentile = financeChange !== null && changes.length >= 8 ? percentileRank(changes, financeChange) : null;
    const changeScore = financeChange !== null && financeChange > 0
      ? (marketHeatScoreFromPercentile(changePercentile, 5, 65, 90) ?? Math.min(5, financeChange > 0 ? 2 : 0))
      : 0;
    factors.push(marketHeatFactor({
      group: "leverage",
      label: "融資日增",
      score: changeScore,
      max: 5,
      value: formatSignedMetric(financeChange, 0, " 單位"),
      detail: "融資快速增加代表散戶槓桿升溫，需搭配價格位置與法人籌碼判讀。",
      source: margin.source || "TWSE MI_MARGN",
      asOf: margin.date || "",
      tone: marketHeatMetricTone(changeScore, 5),
      confidence: changePercentile !== null ? "medium" : "low"
    }));
  } else {
    missing.push(marketHeatMissing("leverage", "TWSE 融資券", "按「更新總經」後會抓 TWSE MI_MARGN 並累積本機歷史。", "TWSE MI_MARGN", 15));
  }

  const futures = futuresSentimentSummary(state.taifex);
  const foreignTxf = toNumber(futures.foreignTxf);
  const retailProxy = toNumber(futures.retailProxy);
  if (foreignTxf !== null || retailProxy !== null) {
    let futuresScore = 0;
    const notes = [];
    if (foreignTxf !== null && foreignTxf <= -10000) { futuresScore += 7; notes.push("外資大台淨空偏高"); }
    else if (foreignTxf !== null && foreignTxf <= -3000) { futuresScore += 5; notes.push("外資大台偏空"); }
    if (retailProxy !== null && retailProxy >= 8000) { futuresScore += 5; notes.push("小/微台非法人代理偏多"); }
    else if (retailProxy !== null && retailProxy >= 3000) { futuresScore += 3; notes.push("小/微台非法人代理偏多"); }
    factors.push(marketHeatFactor({
      group: "leverage",
      label: "期貨籌碼分歧",
      score: clamp(futuresScore, 0, 8),
      max: 8,
      value: notes.join("；") || "未觸發",
      detail: futures.conclusion || "期貨水位需搭配現貨籌碼與日線。",
      source: "TAIFEX 三大法人期貨未平倉",
      asOf: futures.sourceDate || "",
      tone: marketHeatMetricTone(futuresScore, 8),
      confidence: "medium"
    }));
  } else {
    missing.push(marketHeatMissing("leverage", "TAIFEX 期貨水位", "按「更新期貨」後取得大台 / 小台 / 微台法人與非法人 proxy。", "TAIFEX", 8));
  }

  const pcVol = toNumber(state.putCallRatio?.pcVol);
  const pcOi = toNumber(state.putCallRatio?.pcOI);
  if (pcVol !== null || pcOi !== null) {
    let pcScore = 0;
    const labels = [];
    if (pcVol !== null && pcVol <= 0.65) { pcScore += 5; labels.push("P/C 量低，偏多擁擠"); }
    else if (pcVol !== null && pcVol <= 0.8) { pcScore += 3; labels.push("P/C 量偏低"); }
    if (pcOi !== null && pcOi <= 0.75) { pcScore += 2; labels.push("P/C OI 偏低"); }
    if (pcVol !== null && pcVol >= 1.35) { pcScore += 3; labels.push("避險需求升溫"); }
    factors.push(marketHeatFactor({
      group: "leverage",
      label: "選擇權 P/C",
      score: clamp(pcScore, 0, 7),
      max: 7,
      value: `量 ${pcVol !== null ? pcVol.toFixed(3) : "-"} / OI ${pcOi !== null ? pcOi.toFixed(3) : "-"}`,
      detail: labels.join("；") || "P/C 未顯示明顯擁擠或避險升溫。",
      source: "TAIFEX 台指選擇權",
      asOf: state.putCallRatio?.date || "",
      tone: marketHeatMetricTone(pcScore, 7),
      confidence: "medium"
    }));
  } else {
    missing.push(marketHeatMissing("leverage", "選擇權 P/C", "按「更新期貨」會同步抓 TXO Put/Call Ratio。", "TAIFEX TXO", 7));
  }

  return { factors, missing };
}

function marketHeatMacroFactors(cache) {
  const factors = [];
  const missing = [];
  const vix = macroItemByKey(cache, "vix");
  if (vix && toNumber(vix.value) !== null) {
    const value = toNumber(vix.value);
    const vixScore = value <= 13 ? 6 : value <= 16 ? 4 : value >= 28 ? 6 : value >= 23 ? 4 : 0;
    const detail = value <= 16
      ? "VIX 低檔代表市場波動預期平靜；若台股技術過熱，需防過度樂觀。"
      : value >= 23
        ? "VIX 升高代表外部風險偏 risk-off，容易放大台股回檔。"
        : "VIX 未處於極端區。";
    factors.push(marketHeatFactor({
      group: "macro",
      label: "VIX 風險情緒",
      score: vixScore,
      max: 6,
      value: formatNumber(value, 2),
      detail,
      source: vix.source || "Cboe VIX",
      asOf: vix.date || "",
      tone: marketHeatMetricTone(vixScore, 6),
      confidence: "medium-high"
    }));
  } else {
    missing.push(marketHeatMissing("macro", "VIX", "按「更新總經」後會抓 Cboe VIX History CSV。", "Cboe", 6));
  }

  const ust10y = macroItemByKey(cache, "ust10y");
  if (ust10y && toNumber(ust10y.value) !== null) {
    const series = macroChartSeries(ust10y, cache).map((point) => point.value).filter((value) => value !== null);
    const latest = toNumber(ust10y.value);
    const prev20 = series.length >= 21 ? series.at(-21) : null;
    const change20 = latest !== null && prev20 !== null ? latest - prev20 : null;
    const rateScore = change20 !== null && change20 >= 0.35 ? 6
      : change20 !== null && change20 >= 0.2 ? 4
      : latest !== null && latest >= 4.8 ? 3
      : 0;
    factors.push(marketHeatFactor({
      group: "macro",
      label: "美債 10Y 壓力",
      score: rateScore,
      max: 6,
      value: `${formatNumber(latest, 2)}%${change20 !== null ? ` / 20日 ${formatSignedMetric(change20, 2, "pp")}` : ""}`,
      detail: "長端利率快速上行會壓縮科技與成長股估值，本模型僅作大環境風險加權。",
      source: ust10y.source || "U.S. Treasury",
      asOf: ust10y.date || "",
      tone: marketHeatMetricTone(rateScore, 6),
      confidence: change20 !== null ? "medium-high" : "medium"
    }));
  } else {
    missing.push(marketHeatMissing("macro", "美債 10Y", "按「更新總經」後會抓 U.S. Treasury Yield Curve。", "U.S. Treasury", 6));
  }

  const usdTwd = cache.usdTwd || null;
  if (usdTwd && toNumber(usdTwd.percentile) !== null) {
    const percentile = toNumber(usdTwd.percentile);
    const fxScore = percentile >= 85 ? 4 : percentile >= 75 ? 3 : percentile <= 10 ? 2 : 0;
    factors.push(marketHeatFactor({
      group: "macro",
      label: "USD/TWD 匯率壓力",
      score: fxScore,
      max: 4,
      value: `${formatNumber(usdTwd.latest, 3)} / ${formatNumber(percentile, 0)}%ile`,
      detail: usdTwd.detail || "USD/TWD 高分位代表台幣偏弱壓力，低分位則偏向外資匯率安全邊際較佳。",
      source: usdTwd.source || "CBC USD/TWD",
      asOf: usdTwd.date || "",
      tone: marketHeatMetricTone(fxScore, 4),
      confidence: "medium"
    }));
  } else {
    missing.push(marketHeatMissing("macro", "USD/TWD", "按「更新總經」後會抓中央銀行 USD/TWD 收盤匯率。", "中央銀行", 4));
  }

  const fedPath = cache.fedPath || null;
  const gap = fedPath?.gap || null;
  if (gap && toNumber(gap.diffBp) !== null) {
    const gapScore = toNumber(gap.score) || 0;
    factors.push(marketHeatFactor({
      group: "macro",
      label: "Fed 政策落差",
      score: gapScore,
      max: 5,
      value: `${gap.label} / ${formatSignedMetric(gap.diffBp, 0, "bp")}`,
      detail: gap.detail || "CME FedWatch 市場預期與 Fed SEP 點陣圖中位數的落差。",
      source: "CME FedWatch + Fed SEP",
      asOf: fedPath.asOf || fedPath.fetchedAt || "",
      tone: gapScore >= 4 ? "bad" : gapScore > 0 ? "warn" : "flat",
      confidence: gap.confidence || "low"
    }));
  } else {
    missing.push(marketHeatMissing("macro", "FedWatch / 點陣圖", "按「更新總經」後會嘗試抓 CME FedWatch 與 Fed SEP；CME 失敗時僅標示待複核，不把缺值視為低風險。", "CME / Federal Reserve", 5));
  }

  const valuations = quoteTrackableStocks(WATCHLIST)
    .map((stock) => ({ stock, valuation: valuationFor(stock.code) }))
    .filter((row) => row.valuation && toNumber(row.valuation.pe) !== null && toNumber(row.valuation.pe) > 0);
  if (valuations.length >= 20) {
    const peValues = valuations.map((row) => toNumber(row.valuation.pe)).filter((value) => value !== null && value > 0).sort((a, b) => a - b);
    const medianPe = peValues[Math.floor(peValues.length / 2)];
    const highPePct = peValues.filter((value) => value >= 35).length / peValues.length * 100;
    const valuationScore = highPePct >= 35 ? 4 : highPePct >= 25 ? 3 : highPePct >= 15 ? 1.5 : 0;
    const latestDates = valuations.map((row) => row.valuation.sourceDate || row.valuation.fetchedAt || "").filter(Boolean).sort();
    factors.push(marketHeatFactor({
      group: "macro",
      label: "追蹤池估值樣本",
      score: valuationScore,
      max: 4,
      value: `PE 中位 ${formatNumber(medianPe, 1)}；PE>=35 ${formatNumber(highPePct, 0)}%`,
      detail: "這是追蹤池樣本，不是全市場估值；官方市場 PE 尚未接入前僅作輔助。",
      source: topCountSummary(valuations.map((row) => row.valuation.sourceLabel || row.valuation.source || "交易所估值"), 2) || "交易所估值",
      asOf: latestDates.at(-1) || "",
      tone: marketHeatMetricTone(valuationScore, 4),
      confidence: "low"
    }));
  } else {
    missing.push(marketHeatMissing("macro", "估值樣本", `目前只有 ${valuations.length} 檔追蹤池估值可用；至少 20 檔才納入。`, "TWSE / TPEx 官方估值", 4));
  }

  return { factors, missing };
}

function buildMarketHeatScore() {
  const cache = normalizeMacroCache(state.macroCache);
  const sections = [
    marketHeatTechnicalFactors(),
    marketHeatBreadthFactors(),
    marketHeatLeverageFactors(cache),
    marketHeatMacroFactors(cache)
  ];
  const factors = sections.flatMap((section) => section.factors);
  const missing = sections.flatMap((section) => section.missing);
  const groupScores = MARKET_HEAT_GROUPS.map((group) => {
    const groupFactors = factors.filter((factor) => factor.group === group.key);
    const groupMissing = missing.filter((item) => item.group === group.key);
    const rawScore = groupFactors.reduce((sum, factor) => sum + factor.score, 0);
    const score = clamp(rawScore, 0, group.max);
    const availableMax = Math.min(group.max, groupFactors.reduce((sum, factor) => sum + (factor.max || 0), 0));
    return {
      ...group,
      score,
      availableMax,
      coverage: group.max ? availableMax / group.max * 100 : 0,
      factors: groupFactors,
      missing: groupMissing
    };
  });
  const score = Math.round(groupScores.reduce((sum, group) => sum + group.score, 0));
  const availableMax = groupScores.reduce((sum, group) => sum + group.availableMax, 0);
  const coverage = Math.round(availableMax);
  const level = marketHeatLevel(score, coverage);
  const drivers = [...factors]
    .filter((factor) => factor.score > 0)
    .sort((left, right) => (right.score / Math.max(1, right.max)) - (left.score / Math.max(1, left.max)) || right.score - left.score)
    .slice(0, 6);
  const fetchedAtCandidates = [
    normalizeMarketDashboardCache(state.marketDashboardCache).fetchedAt,
    cache.fetchedAt,
    state.taifex?.date,
    state.putCallRatio?.fetchedAt
  ].filter(Boolean).sort();
  return {
    score,
    level,
    coverage,
    availableMax,
    groupScores,
    factors,
    drivers,
    missing,
    fetchedAt: fetchedAtCandidates.at(-1) || null
  };
}

function renderMarketHeatFactor(factor) {
  return `
    <div class="market-heat-factor ${escapeHtml(factor.tone || "flat")}">
      <div>
        <span>${escapeHtml(factor.label)}</span>
        <strong>${formatNumber(factor.score, 1)} / ${formatNumber(factor.max, 0)}</strong>
      </div>
      <p>${escapeHtml(factor.value || factor.detail || "-")}</p>
      <small>${escapeHtml(factor.source || "")}${factor.asOf ? ` · ${escapeHtml(factor.asOf)}` : ""}${factor.confidence ? ` · 信心 ${escapeHtml(factor.confidence)}` : ""}</small>
    </div>
  `;
}

// v16.7 雷達重做：piecewise-linear 連續計分（取代粗階梯門檻，分數會隨輸入值微動）
function crashRiskRamp(value, from, to, max) {
  const numeric = toNumber(value);
  if (numeric === null) return 0;
  if (from === to) return numeric >= to ? max : 0;
  return clamp((numeric - from) / (to - from), 0, 1) * max;
}

// v16.7 雷達日誌：每日一筆分數 / 因子快照，供「與上一筆對照」與 30 日趨勢線
function normalizeCrashRiskHistory(rows) {
  const byDate = new Map();
  for (const row of Array.isArray(rows) ? rows : []) {
    if (!row || typeof row !== "object") continue;
    const dateKey = String(row.dateKey || "").slice(0, 10);
    if (!/^\d{4}-\d{2}-\d{2}$/.test(dateKey)) continue;
    byDate.set(dateKey, {
      dateKey,
      score: clamp(toNumber(row.score) ?? 0, 0, 100),
      baseScore: clamp(toNumber(row.baseScore) ?? 0, 0, 100),
      coverage: clamp(toNumber(row.coverage) ?? 0, 0, 100),
      overrideFloor: toNumber(row.overrideFloor),
      factors: normalizeRecordMap(row.factors),
      firstScore: toNumber(row.firstScore),
      firstFactors: normalizeRecordMap(row.firstFactors),
      updatedAt: row.updatedAt || ""
    });
  }
  return [...byDate.values()].sort((a, b) => a.dateKey.localeCompare(b.dateKey)).slice(-120);
}

function recordCrashRiskHistory(risk) {
  const history = normalizeCrashRiskHistory(state.crashRiskHistory);
  const today = dateKeyInTaipei();
  const existing = history.find((row) => row.dateKey === today) || null;
  const entry = {
    dateKey: today,
    score: Math.round((toNumber(risk?.score) ?? 0) * 10) / 10,
    baseScore: Math.round((toNumber(risk?.baseScore) ?? 0) * 10) / 10,
    coverage: toNumber(risk?.coverage) ?? 0,
    overrideFloor: toNumber(risk?.override?.floor),
    factors: Object.fromEntries((risk?.factors || []).map((factor) => [factor.label, Math.round(factor.score * 10) / 10])),
    // 今日首筆分數：跨日對照不存在時，退而跟今日第一筆比，畫面永遠有 Δ 可看
    firstScore: existing ? (toNumber(existing.firstScore) ?? existing.score) : Math.round((toNumber(risk?.score) ?? 0) * 10) / 10,
    firstFactors: existing ? (existing.firstFactors && Object.keys(existing.firstFactors).length ? existing.firstFactors : existing.factors) : Object.fromEntries((risk?.factors || []).map((factor) => [factor.label, Math.round(factor.score * 10) / 10])),
    updatedAt: new Date().toISOString()
  };
  const changed = !existing
    || existing.score !== entry.score
    || existing.coverage !== entry.coverage
    || JSON.stringify(existing.factors) !== JSON.stringify(entry.factors);
  const next = normalizeCrashRiskHistory([...history.filter((row) => row.dateKey !== today), entry]);
  if (changed) {
    state.crashRiskHistory = next;
    persistStateSilently("急殺雷達日誌");
  }
  const previousDay = [...next].reverse().find((row) => row.dateKey < today) || null;
  const buildDelta = (referenceScore, referenceFactors, previousDate, mode) => {
    const scoreDelta = Math.round((entry.score - referenceScore) * 10) / 10;
    const labels = new Set([...Object.keys(entry.factors), ...Object.keys(referenceFactors || {})]);
    const factorDeltas = [...labels]
      .map((label) => ({
        label,
        today: toNumber(entry.factors[label]) ?? 0,
        previous: toNumber(referenceFactors?.[label]) ?? 0,
        delta: Math.round(((toNumber(entry.factors[label]) ?? 0) - (toNumber(referenceFactors?.[label]) ?? 0)) * 10) / 10
      }))
      .filter((row) => Math.abs(row.delta) >= 0.1)
      .sort((a, b) => Math.abs(b.delta) - Math.abs(a.delta));
    return {
      previousDate,
      mode,
      scoreDelta,
      factorDeltas: factorDeltas.slice(0, 3),
      same: scoreDelta === 0 && factorDeltas.length === 0
    };
  };
  let delta = null;
  if (previousDay) {
    delta = buildDelta(previousDay.score, previousDay.factors, previousDay.dateKey, "previous-day");
  } else if (existing) {
    delta = buildDelta(toNumber(entry.firstScore) ?? entry.score, entry.firstFactors, today, "today-first");
  }
  return { history: next, previous: previousDay, delta };
}

function crashRiskTrendSparkHtml(history) {
  const rows = (history || []).slice(-60).map((row) => ({ close: row.score }));
  if (rows.length < 2) return "";
  const path = sparklinePath(rows, 220, 40);
  if (!path) return "";
  return `<svg viewBox="0 0 220 40" preserveAspectRatio="none" style="width:180px;height:34px;vertical-align:middle;" aria-label="市場風險雷達分數趨勢"><path d="${path}" fill="none" stroke="var(--accent)" stroke-width="1.5" /></svg>`;
}

// v16.7 歷史回推：雷達分數是即時輸入算出來的，不需要「等日誌累積」才有趨勢——
// 用本機已有的 TAIEX 日線（6 個月）、追蹤池日線與 VIX 120 天序列，重算過去每天的
// 「可回推因子子集」分數（技術乖離 + 廣度 + 加權跌幅 + VIX；法人 / 期貨 / 融資無歷史快照不可回推）。
// 打開第一天就有整條趨勢線；實錄全因子日誌逐日覆蓋其上，兩種口徑在 UI 明確標示。
const CRASH_RISK_FULL_FACTOR_MAX = 90; // 七因子滿分 16+18+10+14+14+12+6
let _crashRiskBackfillCache = null;

function crashRiskBackfillSeries(days = 90) {
  const taiexRows = taiexKlines().filter((row) => toNumber(row.close) !== null);
  if (taiexRows.length < 61) return [];
  const macroCache = normalizeMacroCache(state.macroCache);
  const vixItem = macroItemByKey(macroCache, "vix");
  const signature = [
    taiexRows.length,
    taiexRows.at(-1)?.date || "",
    vixItem?.date || "",
    Object.keys(normalizeRecordMap(state.klines)).length
  ].join("|");
  if (_crashRiskBackfillCache?.signature === signature) return _crashRiskBackfillCache.rows;
  const vixByDate = new Map();
  for (const point of vixItem?.series || []) {
    const match = String(point.date || "").match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if (match) vixByDate.set(`${match[3]}-${match[1]}-${match[2]}`, toNumber(point.value));
  }
  // 追蹤池廣度逐日回算（rolling MA20 / MA60，每檔一次掃過）
  const breadthByDate = new Map();
  const klineState = normalizeRecordMap(state.klines);
  const breadthStocks = quoteTrackableStocks(WATCHLIST).filter((stock) => !isEtfCode(stock.code));
  for (const stock of breadthStocks) {
    const rows = Array.isArray(klineState[stock.code])
      ? klineState[stock.code].filter((row) => toNumber(row.close) !== null)
      : [];
    if (rows.length < 60) continue;
    const closes = rows.map((row) => toNumber(row.close));
    let sum20 = 0;
    let sum60 = 0;
    for (let index = 0; index < closes.length; index += 1) {
      sum20 += closes[index];
      if (index >= 20) sum20 -= closes[index - 20];
      sum60 += closes[index];
      if (index >= 60) sum60 -= closes[index - 60];
      if (index < 59) continue;
      const dateKey = String(rows[index].date || "").slice(0, 10);
      if (!dateKey) continue;
      if (!breadthByDate.has(dateKey)) breadthByDate.set(dateKey, { above20: 0, above60: 0, total: 0 });
      const bucket = breadthByDate.get(dateKey);
      bucket.total += 1;
      if (closes[index] > sum20 / 20) bucket.above20 += 1;
      if (closes[index] > sum60 / 60) bucket.above60 += 1;
    }
  }
  const closes = taiexRows.map((row) => toNumber(row.close));
  const out = [];
  const start = Math.max(60, taiexRows.length - days);
  for (let index = start; index < taiexRows.length; index += 1) {
    const dateKey = String(taiexRows[index].date || "").slice(0, 10);
    if (!dateKey) continue;
    const window = closes.slice(0, index + 1);
    const close = closes[index];
    const ma20 = sma(window, 20);
    const ma60 = sma(window, 60);
    const bbStd = standardDeviation(window.slice(-20));
    const bias20 = ma20 ? (close - ma20) / ma20 * 100 : null;
    const bias60 = ma60 ? (close - ma60) / ma60 * 100 : null;
    const bbPosition = bbStd ? (close - ma20) / bbStd : null;
    const technical = crashRiskRamp(bias20, 2, 6, 6)
      + crashRiskRamp(rsi(window, 14), 62, 78, 5)
      + crashRiskRamp(bbPosition, 1.2, 2.2, 3)
      + crashRiskRamp(bias60, 5, 10, 2); // 子集滿分 16（不含 MACD 高檔柱縮事件分）
    const dayPct = index > 0 && closes[index - 1] ? (close - closes[index - 1]) / closes[index - 1] * 100 : null;
    const indexDrop = crashRiskRamp(dayPct !== null ? -dayPct : null, 0.3, 1.5, 4); // 僅加權現貨（無台指期夜盤歷史）
    const breadthBucket = breadthByDate.get(dateKey);
    let breadth = 0;
    let breadthMax = 0;
    if (breadthBucket && breadthBucket.total >= 20) {
      const pctAbove20 = breadthBucket.above20 / breadthBucket.total * 100;
      const pctAbove60 = breadthBucket.above60 / breadthBucket.total * 100;
      const nearHigh = close >= Math.max(...window.slice(-60)) * 0.985;
      breadth = (nearHigh ? crashRiskRamp(62 - pctAbove20, 0, 18, 7) : 0)
        + crashRiskRamp(50 - Math.max(pctAbove20, pctAbove60), 0, 12, 3);
      breadthMax = 10;
    }
    const vixValue = vixByDate.has(dateKey) ? vixByDate.get(dateKey) : null;
    const vixScore = vixValue !== null ? crashRiskRamp(vixValue, 16, 30, 6) : 0;
    const vixMax = vixValue !== null ? 6 : 0;
    const availableMax = 16 + 4 + breadthMax + vixMax;
    const raw = technical + indexDrop + breadth + vixScore;
    out.push({
      dateKey,
      score: Math.round(raw / availableMax * 1000) / 10,
      coverage: Math.round(availableMax / CRASH_RISK_FULL_FACTOR_MAX * 100),
      source: "backfill"
    });
  }
  _crashRiskBackfillCache = { signature, rows: out };
  return out;
}

// 回推線 + 實錄日誌合併：同日以實錄優先
function crashRiskCombinedTrend(history) {
  const byDate = new Map();
  for (const row of crashRiskBackfillSeries()) byDate.set(row.dateKey, row);
  for (const row of history || []) {
    byDate.set(row.dateKey, { dateKey: row.dateKey, score: row.score, coverage: row.coverage, source: "recorded" });
  }
  return [...byDate.values()].sort((a, b) => a.dateKey.localeCompare(b.dateKey));
}

function crashRiskLevel(score, coverage, override = null) {
  if (override?.floor >= 92) {
    return {
      label: "強警示",
      tone: "danger",
      headline: "急殺硬觸發：先保命，再談低接",
      action: "取消追價與攤平；先保護獲利、降槓桿、檢查隔日跳空與流動性。"
    };
  }
  if (override?.floor >= 82) {
    return {
      label: "高風險",
      tone: "danger",
      headline: "急殺硬觸發已啟動：部位先降風險",
      action: "避免滿倉與融資曝險；高乖離、高 beta、流動性弱的持股先檢查停利停損。"
    };
  }
  if (override?.floor >= 72) {
    return {
      label: "警戒",
      tone: "warn",
      headline: "急殺條件有硬觸發：新倉先暫停，舊倉先控回撤",
      action: "等期貨、法人與美股科技風險降溫後，再重新評估進場。"
    };
  }
  if (coverage < 45) {
    return {
      label: "資料不足",
      tone: "flat",
      headline: "急殺風險：資料不足，先更新大盤 / 期貨 / 總經 / 日線",
      action: "不要把缺資料解讀成低風險；先補 TAIFEX、TWSE、VIX 與 TAIEX 日線。"
    };
  }
  if (score >= 85) {
    return {
      label: "強警示",
      tone: "danger",
      headline: "急殺風險強警示：先保護獲利、降槓桿、停止攤平",
      action: "以回撤控制為第一優先；開盤劇烈波動時不急著接刀。"
    };
  }
  if (score >= 75) {
    return {
      label: "急殺風險高",
      tone: "danger",
      headline: "急殺風險高：先保護獲利、降槓桿、檢查停利停損",
      action: "避免追價與滿倉；優先檢查高乖離、融資熱門與法人轉賣標的。"
    };
  }
  if (score >= 60) {
    return {
      label: "警告",
      tone: "warn",
      headline: "急殺風險警告：不追價，先檢查槓桿與停損",
      action: "若台指期領跌或外資期貨淨空擴大，短線先降低獲利回吐風險。"
    };
  }
  if (score >= 40) {
    return {
      label: "注意",
      tone: "warn",
      headline: "急殺條件累積：57 這種分數是注意，不是大警報",
      action: "持股可保留，但新增部位要分批，並預先設定失守價位；等硬觸發出現才升級。"
    };
  }
  return {
    label: "未見共振",
    tone: "good",
    headline: "未見急殺共振：仍需持續追蹤台指期與法人籌碼",
    action: "目前可用 proxy 未同步轉弱；維持日常更新與交叉核對。"
  };
}

function crashRiskTrigger({
  label,
  floor,
  value = "",
  detail = "",
  source = "",
  asOf = "",
  theory = ""
}) {
  return {
    label,
    floor: clamp(toNumber(floor) ?? 0, 0, 100),
    value,
    detail,
    source,
    asOf,
    theory,
    tone: floor >= 82 ? "danger" : floor >= 72 ? "warn" : "flat"
  };
}

function marketCrashRiskGlobalSnapshot(cache, matcher) {
  const snapshots = [cache.taiwan, cache.taifexNight, ...(cache.global || [])].filter(Boolean);
  return snapshots.find((item) => {
    const haystack = [item.key, item.label, item.symbol].map((value) => String(value || "").toLowerCase()).join(" ");
    return matcher.some((token) => haystack.includes(String(token).toLowerCase()));
  }) || null;
}

function crashRiskFactor({
  label,
  score,
  max,
  value = "",
  detail = "",
  source = "",
  asOf = "",
  confidence = "medium"
}) {
  const numericScore = clamp(toNumber(score) ?? 0, 0, max || 0);
  return {
    label,
    score: numericScore,
    max: max || 0,
    value,
    detail,
    source,
    asOf,
    confidence,
    tone: marketHeatMetricTone(numericScore, max || 0)
  };
}

function marketCrashRiskTechnicalFactor() {
  const rows = taiexKlines()
    .filter((row) => toNumber(row.close) !== null)
    .slice(-120);
  if (rows.length < 60) {
    return {
      factor: null,
      missing: marketHeatMissing("crash", "TAIEX 日線乖離", `目前只有 ${rows.length} 根 TAIEX 日線；至少需要 60 根。`, "Yahoo ^TWII", 18)
    };
  }
  const closes = rows.map((row) => toNumber(row.close)).filter((value) => value !== null);
  const latest = rows.at(-1);
  const latestClose = toNumber(latest?.close);
  const ma20 = sma(closes, 20);
  const ma60 = sma(closes, 60);
  const rsi14 = rsi(closes, 14);
  const macdValue = macd(closes);
  const bbMid = sma(closes, 20);
  const bbStd = standardDeviation(closes.slice(-20));
  const bbUpper = bbMid !== null && bbStd !== null ? bbMid + bbStd * 2 : null;
  const high60 = Math.max(...closes.slice(-60));
  const bias20 = latestClose !== null && ma20 ? (latestClose - ma20) / ma20 * 100 : null;
  const bias60 = latestClose !== null && ma60 ? (latestClose - ma60) / ma60 * 100 : null;
  const nearHigh = latestClose !== null && high60 ? latestClose >= high60 * 0.985 : false;
  // 連續計分：乖離 / RSI / 布林位置線性給分；MACD 高檔柱縮維持事件式加分
  const bbPosition = bbStd ? (latestClose - bbMid) / bbStd : null; // 收盤在布林帶的標準差位置
  let score = crashRiskRamp(bias20, 2, 6, 6)
    + crashRiskRamp(rsi14, 62, 78, 5)
    + crashRiskRamp(bbPosition, 1.2, 2.2, 3)
    + crashRiskRamp(bias60, 5, 10, 2);
  const notes = [
    bias20 !== null ? `20日乖離 ${formatNumber(bias20, 1)}%` : "",
    rsi14 !== null ? `RSI ${formatNumber(rsi14, 1)}` : "",
    bbPosition !== null ? `布林位置 ${formatNumber(bbPosition, 1)}σ` : ""
  ].filter(Boolean);
  if (nearHigh && macdValue.histogram !== null && macdValue.previousHistogram !== null && macdValue.histogram < macdValue.previousHistogram) {
    score += 4;
    notes.push("近高檔但 MACD 柱縮");
  }
  if (bias60 !== null && bias60 >= 5) notes.push(`60日乖離 ${formatNumber(bias60, 1)}%`);
  return {
    factor: crashRiskFactor({
      label: "乖離過大 / 技術耗竭",
      score,
      max: 18,
      value: notes.join("；") || "未觸發",
      detail: "高乖離、RSI 過熱、貼近布林上緣且動能縮小時，容易被期貨或籌碼轉弱放大成急殺。",
      source: latest?.source || "Yahoo ^TWII 日線",
      asOf: latest?.date || "",
      confidence: "medium-high"
    }),
    missing: null
  };
}

function marketCrashRiskBreadthFactor() {
  const rows = marketHeatBreadthSnapshot();
  if (rows.length < 20) {
    return {
      factor: null,
      missing: marketHeatMissing("crash", "追蹤池廣度", `目前只有 ${rows.length} 檔具 60 根以上日線；至少需要 20 檔。`, "追蹤池日線", 10)
    };
  }
  const pctAbove20 = rows.filter((row) => row.aboveMa20).length / rows.length * 100;
  const pctAbove60 = rows.filter((row) => row.aboveMa60).length / rows.length * 100;
  const latestDates = rows.map((row) => row.date).filter(Boolean).sort();
  const taiexRows = taiexKlines();
  const taiexCloses = taiexRows.map((row) => toNumber(row.close)).filter((value) => value !== null);
  const taiexClose = taiexCloses.at(-1);
  const taiexHigh60 = taiexCloses.length >= 60 ? Math.max(...taiexCloses.slice(-60)) : null;
  const nearHigh = taiexClose !== null && taiexHigh60 !== null && taiexClose >= taiexHigh60 * 0.985;
  // 連續計分：近高檔時廣度越差分數越高；月 / 季線廣度同弱另計
  const divergence = nearHigh ? crashRiskRamp(62 - pctAbove20, 0, 18, 7) : 0;
  const weakBoth = crashRiskRamp(50 - Math.max(pctAbove20, pctAbove60), 0, 12, 3);
  const score = divergence + weakBoth;
  const notes = [];
  if (divergence > 0) notes.push("指數近高但廣度不足");
  if (weakBoth > 0) notes.push("月 / 季線廣度同步偏弱");
  return {
    factor: crashRiskFactor({
      label: "廣度轉弱 / 權值撐盤",
      score,
      max: 10,
      value: `月線上 ${formatNumber(pctAbove20, 0)}% / 季線上 ${formatNumber(pctAbove60, 0)}%`,
      detail: notes.join("；") || "追蹤池廣度未顯示明顯轉弱。",
      source: `追蹤池日線 ${rows.length} 檔`,
      asOf: latestDates.at(-1) || "",
      confidence: rows.length >= 50 ? "medium-high" : "medium"
    }),
    missing: null
  };
}

function marketCrashRiskInstitutionalFactor() {
  const cache = normalizeMarketInstitutionalRankings(state.marketInstitutionalRankings);
  const rows = cache.rows || [];
  if (!rows.length) {
    return {
      factor: null,
      missing: marketHeatMissing("crash", "大戶 / 法人前 10 籌碼", "按「法人前10」後取得 TWSE / TPEx 官方三大法人買賣超排行，作為大戶退場 proxy。", "TWSE / TPEx T86", 14)
    };
  }
  const sumMetric = (key) => rows.reduce((sum, row) => sum + (toNumber(row[key]) ?? 0), 0);
  const foreignNet = sumMetric("foreignNet");
  const trustNet = sumMetric("trustNet");
  const totalNet = sumMetric("totalNet");
  // 連續計分：賣壓張數在 ramp 區間內線性給分；數值一律顯示，方便日日對照
  const score = crashRiskRamp(-totalNet, 5000, 50000, 8)
    + crashRiskRamp(-foreignNet, 4000, 30000, 4)
    + crashRiskRamp(-trustNet, 2000, 8000, 2);
  const notes = [
    `前10合計 ${formatNumber(totalNet, 0)} 張`,
    `外資 ${formatNumber(foreignNet, 0)} 張`,
    `投信 ${formatNumber(trustNet, 0)} 張`
  ];
  return {
    factor: crashRiskFactor({
      label: "大戶 / 法人退場 proxy",
      score,
      max: 14,
      value: notes.join("；") || "前 10 法人排行未顯示明顯賣壓",
      detail: "此處是官方法人排行 proxy，不等於全市場淨買賣超；若與個股 TDCC 大戶週資料同向轉弱，權重更高。",
      source: cache.source || "TWSE / TPEx T86",
      asOf: cache.asOf || "",
      confidence: cache.fallbackUsed ? "medium" : "medium-high"
    }),
    missing: null
  };
}

