function pctTextToNumber(value) {
  const match = String(value || "").match(/-?\d+(?:\.\d+)?/);
  return match ? Number(match[0]) : null;
}

function renderRiskScatterHtml() {
  const points = RISKS.map((row) => {
    const probability = pctTextToNumber(row[4]);
    const impact = Math.abs(pctTextToNumber(row[5]) || 0);
    return { row, probability, impact };
  }).filter((item) => item.probability !== null);
  if (!points.length) return "";
  const width = 320;
  const height = 180;
  const pad = 28;
  const maxProb = Math.max(40, ...points.map((point) => point.probability));
  const maxImpact = Math.max(40, ...points.map((point) => point.impact));
  const marks = points.map((point, index) => {
    const x = pad + point.probability / maxProb * (width - pad * 2);
    const y = height - pad - point.impact / maxImpact * (height - pad * 2);
    const cls = riskClass(point.row[3]);
    const fill = point.row[3] === "高" ? "var(--bad)" : point.row[3] === "中" ? "var(--warn)" : "var(--good)";
    const label = `${point.row[1]}：機率 ${point.row[4]} / 幅度 ${point.row[5]}`;
    return `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="${point.row[3] === "高" ? 6 : 4.5}" class="${cls}" fill="${fill}" opacity="0.84"><title>${escapeHtml(label)}</title></circle>${index < 5 ? `<text x="${(x + 7).toFixed(1)}" y="${(y + 3).toFixed(1)}" font-size="9" fill="currentColor">${escapeHtml(point.row[1]).slice(0, 6)}</text>` : ""}`;
  }).join("");
  return `
    <svg viewBox="0 0 ${width} ${height}" style="width:100%;height:190px;display:block;" role="img" aria-label="風險機率與跌幅散點圖">
      <line x1="${pad}" y1="${height - pad}" x2="${width - pad}" y2="${height - pad}" stroke="var(--line-strong)" />
      <line x1="${pad}" y1="${height - pad}" x2="${pad}" y2="${pad}" stroke="var(--line-strong)" />
      <text x="${width - 86}" y="${height - 8}" font-size="10" fill="currentColor">機率 →</text>
      <text x="5" y="18" font-size="10" fill="currentColor">幅度 ↑</text>
      ${marks}
    </svg>
  `;
}

