function switchTab(target, options = {}) {
  const next = normalizeTabTarget(target);
  const persist = options.persist !== false;
  const shouldRender = options.render !== false;
  if (state.activeTab !== next) {
    // 切換分頁時重置「詳表按需」檢視，回到摘要優先初始畫面
    _discoveryDetailView = false;
    _catalystDetailView = false;
    _macroDetailView = false;
  }
  state.activeTab = next;
  ensureEtfTrackingFilterForTab();
  document.querySelectorAll(".tab-btn").forEach((button) => {
    button.classList.toggle("active", button.dataset.tabTarget === next);
  });
  document.querySelectorAll(".tab-panel").forEach((panel) => {
    panel.classList.toggle("active", panel.id === `tab-${next}`);
  });
  if (persist) persistStateSilently("目前分頁");
  if (shouldRender) renderActiveTab(next);
}

function jumpToSelectedTechnicalSection(section = "chart") {
  switchTab("technical");
  const targetId = section === "chips" ? "institutionContent" : "technicalChart";
  window.setTimeout(() => {
    const target = document.getElementById(targetId);
    if (target) target.scrollIntoView({ behavior: "smooth", block: "start" });
  }, 80);
}

function renderSection(name, fn, fallbackId = "") {
  const sectionStartedAt = performanceDiagnosticsNow();
  let ok = false;
  try {
    fn();
    ok = true;
    return true;
  } catch (error) {
    console.error(`renderSection failed: ${name}`, error);
    const fallback = fallbackId ? $(fallbackId) : null;
    if (fallback) {
      fallback.innerHTML = `<div class="empty">此區塊載入失敗：${escapeHtml(error && error.message ? error.message : String(error))}</div>`;
    }
    setStatus(`畫面區塊「${name}」載入失敗：${error && error.message ? error.message : String(error)}`, "error");
    return false;
  } finally {
    recordPerformanceRenderBlock(name, sectionStartedAt, {
      fallbackId,
      ok,
      tab: state.activeTab || ""
    });
  }
}

function performanceMsText(value) {
  const num = toNumber(value);
  if (num === null) return "-";
  return `${formatNumber(num, num >= 100 ? 0 : 1)} ms`;
}

function performanceHitRateText(value) {
  const num = toNumber(value);
  if (num === null) return "-";
  return `${formatNumber(num * 100, 1)}%`;
}

